import type { GolfCourse } from './types';

export const allCourses: Record<string, GolfCourse[]> = {
  'austin-texas': [
    { id: 'atx-1', name: 'Austin Country Club', slug: 'austin-country-club', city: 'Austin', state: 'Texas', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Pete Dye', yearBuilt: 1984, holes: 18, par: 72, yardage: 7171, description: 'Perched along the bluffs of Lake Austin, Austin Country Club is a Pete Dye masterpiece that has hosted the Dell Technologies Match Play. The course features dramatic elevation changes, strategic bunkering, and stunning Hill Country views that make every round memorable.', highlights: ['Host of Dell Technologies Match Play', 'Dramatic Lake Austin views', 'Pete Dye design with strategic risk-reward holes'], imageAlt: 'Austin Country Club overlooking Lake Austin with Hill Country backdrop', history: 'Austin Country Club is the oldest country club in Texas, established in 1899. The club has occupied three different locations over its long history. The current Pete Dye-designed course, the club\'s third home, opened in 1984 on a stunning property along the bluffs of Lake Austin and the Colorado River, near the iconic Pennybacker Bridge.\n\nPete Dye and his wife Alice Dye designed the course, which is most famously associated with Harvey Penick, the legendary golf instructor who taught at Austin Country Club for over 50 years. Penick\'s pupils included Ben Crenshaw and Tom Kite, both of whom became major champions.\n\nAustin Country Club hosted the WGC-Dell Technologies Match Play from 2016 through 2023, bringing the world\'s top players to the layout annually. The match play format proved ideal for Dye\'s risk-reward design, consistently producing dramatic finishes. The course underwent a renovation in 2015 to prepare for PGA Tour competition.', signatureHoles: [{ hole: 4, par: 4, yardage: 340, description: 'The shortest par 4 on the course, where Pete Dye tempts players leftward toward a green sitting on a cape jutting into a small lake. A classic risk-reward hole that regularly produced drama during the WGC Match Play.' }, { hole: 12, par: 4, yardage: 430, description: 'A demanding par 4 that favors long, accurate players. The tee shot should be aimed right-center to avoid the bunker left, setting up an approach to a well-defended green.' }, { hole: 14, par: 4, yardage: 400, description: 'One of the most strategic holes on the course with options off the tee and an approach that demands precision against Dye\'s characteristic bunkering.' }, { hole: 1, par: 4, yardage: 385, description: 'The opening hole plays along Lake Austin with water visible from tee to green. A dogleg left with bunkers guarding the turn, it serves as a dramatic introduction to Dye\'s lakeside design.' }], whatToExpect: 'Austin Country Club is a Pete Dye design perched on dramatic bluffs overlooking Lake Austin and the Texas Hill Country. The par-72 course plays to 7,171 yards from the tips with a rating of 75.2 and slope of 152. The opening holes play along the lake in a links-style setting before the course moves into the Hill Country with canyons, ravines, and significant elevation changes.\n\nThe Dye design features his trademark railroad ties, pot bunkers, and demanding green complexes. Conditioning is excellent year-round.', playingTips: 'Austin Country Club rewards strategic thinking over raw power. Many holes present tempting shortcuts that Dye has defended with deep bunkers, water, and severe slopes. Playing to the correct position off the tee is essential, particularly on the lakeside holes where wind is a factor.\n\nThe greens are firm and contoured. Missing on the wrong side leaves difficult up-and-down situations. Hole 4 is a prime example where the risk-reward equation must be carefully calculated.', faqs: [{ question: 'Can the public play Austin Country Club?', answer: 'No. Austin Country Club is a private club with no public access. It gained wide visibility during the WGC-Dell Technologies Match Play held from 2016 through 2023.' }, { question: 'What is Austin Country Club\'s connection to Harvey Penick?', answer: 'Harvey Penick was the legendary instructor who taught at Austin Country Club for over 50 years. His pupils included major champions Ben Crenshaw and Tom Kite.' }, { question: 'How old is Austin Country Club?', answer: 'Established in 1899, it is the oldest country club in Texas. The current Pete Dye course on Lake Austin is the club\'s third location, opening in 1984.' }, { question: 'What PGA Tour events has Austin CC hosted?', answer: 'Austin Country Club hosted the WGC-Dell Technologies Match Play from 2016 through 2023. The match play format proved ideal for Pete Dye\'s risk-reward design.' }] },
    { id: 'atx-2', name: 'Barton Creek Resort - Fazio Foothills', slug: 'barton-creek-fazio-foothills', city: 'Austin', state: 'Texas', type: 'resort', rating: 4.6, greensFee: '$150–$250', architect: 'Tom Fazio', yearBuilt: 1986, holes: 18, par: 72, yardage: 6956, description: 'The flagship course at Omni Barton Creek Resort, the Fazio Foothills layout winds through rugged Texas Hill Country terrain with dramatic elevation changes, natural limestone outcroppings, and lush fairways carved through ancient oaks.', highlights: ['Premier Hill Country resort course', 'Dramatic 100-foot elevation changes', 'Part of 4-course resort collection'], imageAlt: 'Fazio Foothills course at Barton Creek with limestone cliffs and oak trees', history: 'When Barton Creek Resort and Spa opened in 1986, the Fazio Foothills was the first Tom Fazio-designed golf course in the state of Texas. The layout was carved through rugged Hill Country terrain west of Austin, taking advantage of dramatic elevation changes, natural limestone outcroppings, and dense canopies of live oaks and cedars.\n\nOver the decades, the resort expanded to four championship 18-hole courses: the original Fazio Foothills, the Fazio Canyons added in 1999, the Coore-Crenshaw Cliffside, and the Palmer Lakeside. Together they made Barton Creek the undisputed golf capital of Texas. The resort is now operated by Omni Hotels and Resorts.\n\nThe Fazio Foothills underwent a comprehensive renovation that updated the playing surfaces while preserving Fazio\'s original routing. The course features Tifway 419 Hybrid Bermuda fairways and TifEagle Bermuda greens, providing excellent conditions year-round.', signatureHoles: [{ hole: 1, par: 4, yardage: 460, description: 'A demanding opening hole that plays as a tree-lined 460-yard par 4, setting the tone for the round with a requirement for both length and accuracy off the tee.' }, { hole: 9, par: 4, yardage: 422, description: 'A strategic par 4 with a green fiercely protected by a water penalty area. The tee shot must be placed precisely to set up an approach that avoids the hazard.' }, { hole: 14, par: 3, yardage: 165, description: 'A picturesque par 3 with dramatic limestone cliffs and Hill Country views as backdrop. Fazio\'s characteristic bunkering surrounds the green and the elevation change makes club selection critical.' }, { hole: 18, par: 5, yardage: 545, description: 'A sweeping finishing par 5 praised as one of the best closing holes in Texas resort golf. It demands three well-played shots through rolling terrain with the Omni clubhouse framing the backdrop.' }], whatToExpect: 'The Fazio Foothills is best described as a roller-coaster ride through the Texas Hill Country. The course features dramatic elevation changes of up to 100 feet, with tee shots launching from ridgelines and approaches playing to greens tucked into valleys or perched on plateaus. Waterfalls, natural limestone caves, and green-side mounds add visual drama.\n\nAt 7,085 yards from the back tees with a slope of 138, the course demands long and accurate drives down the Bermuda fairways. The small greens require precise iron play.', playingTips: 'Elevation changes significantly affect club selection. Downhill holes play shorter than the yardage while uphill approaches require at least one extra club. Pay attention to yardage books rather than trusting your eyes.\n\nThe greens are relatively small TifEagle Bermuda surfaces that can be firm and fast, especially in summer. Approach shots that land short and roll on are often more effective than flying the ball to the pin.', faqs: [{ question: 'Can the public play Fazio Foothills?', answer: 'Yes. The Fazio Foothills is a resort course open to guests of the Omni Barton Creek Resort and Spa. Green fees typically range from $150 to $250.' }, { question: 'How many courses are at Barton Creek?', answer: 'Omni Barton Creek features four 18-hole championship courses: Fazio Foothills (1986), Fazio Canyons (1999), Coore-Crenshaw Cliffside, and Palmer Lakeside.' }, { question: 'What makes Fazio Foothills special?', answer: 'It was the first Tom Fazio design in Texas when it opened in 1986, renowned for dramatic Hill Country elevation changes and natural limestone features.' }, { question: 'What is the best time to play?', answer: 'Spring and fall offer the most comfortable conditions. Summer temperatures can exceed 100 degrees, so early morning tee times are recommended from June through August.' }] },
    { id: 'atx-3', name: 'Wolfdancer Golf Club', slug: 'wolfdancer-golf-club', city: 'Austin', state: 'Texas', type: 'resort', rating: 4.5, greensFee: '$100–$180', architect: 'Arthur Hills & Mike Dasher', yearBuilt: 2007, holes: 18, par: 72, yardage: 7205, description: 'Located at the Hyatt Regency Lost Pines Resort, Wolfdancer delivers a uniquely Austin golf experience through Lost Pines forest, open meadows, and along the banks of the Colorado River. Wildlife sightings are common on this environmentally sensitive layout.', highlights: ['Colorado River frontage', 'Lost Pines forest setting', 'Audubon-certified sanctuary'], imageAlt: 'Wolfdancer Golf Club hole along the Colorado River in Lost Pines', history: 'Opened 2007 at Hyatt Regency Lost Pines Resort east of Austin. Arthur Hills/Steve Forrest design named after the Tonkawa wolf dance. Audubon Cooperative Sanctuary certified. Renovated and rebranded as Lost Pines Golf Club in 2023.', signatureHoles: [{ hole: 7, par: 3, yardage: 180, description: 'Par 3 with Colorado River views.' }, { hole: 12, par: 5, yardage: 565, description: 'Risk-reward par 5 through Lost Pines forest.' }, { hole: 15, par: 4, yardage: 420, description: 'Demanding par 4 along the Colorado River.' }, { hole: 18, par: 4, yardage: 435, description: 'Finishing hole through pine forest to clubhouse.' }], whatToExpect: 'Diverse golf through Lost Pines forest, meadows, and Colorado River frontage. Audubon-certified with wildlife. Hyatt resort has dining, spa, lodging.', playingTips: 'Forested sections demand accuracy; open meadows expose you to wind. Green complexes have collection areas and subtle contours.', faqs: [{ question: 'Public?', answer: 'Yes, resort. $100-$180.' }, { question: 'Designer?', answer: 'Arthur Hills/Steve Forrest, 2007.' }, { question: 'Wolfdancer meaning?', answer: 'Tonkawa Indian wolf dance.' }, { question: 'Audubon?', answer: 'Yes.' }] },
    { id: 'atx-4', name: 'Falconhead Golf Club', slug: 'falconhead-golf-club', city: 'Austin', state: 'Texas', type: 'public', rating: 4.3, greensFee: '$55–$95', architect: 'PB Dye', yearBuilt: 2003, holes: 18, par: 72, yardage: 7202, description: 'One of Austin\'s best public options, Falconhead offers a surprisingly challenging PB Dye design in the Lake Travis corridor. The course features bold bunkering, creative green complexes, and excellent conditioning that rivals many private clubs.', highlights: ['Top public course in Austin', 'PB Dye design pedigree', 'Excellent value in Lake Travis area'], imageAlt: 'Falconhead Golf Club fairway with Hill Country views', history: 'Opened 2003 as a PB Dye design in the Lake Travis corridor west of Austin. PB Dye, son of Pete Dye, created a 7,202-yard layout through rolling Hill Country terrain with bold bunkering and creative greens. The signature 8th hole features a green on a limestone ledge. Consistently ranked among Austin\'s top public courses.', signatureHoles: [{ hole: 4, par: 4, yardage: 420, description: 'Demanding par 4 with Dye-style bunkering guarding the approach.' }, { hole: 8, par: 3, yardage: 165, description: 'Signature hole with a green built on a limestone ledge. One of Austin\'s most unique par 3s.' }, { hole: 13, par: 5, yardage: 545, description: 'Risk-reward par 5 through rolling terrain with strategic bunkering.' }, { hole: 18, par: 4, yardage: 440, description: 'Demanding finishing hole with Hill Country views.' }], whatToExpect: 'Challenging public golf with PB Dye pedigree. Rolling Hill Country terrain, bold bunkering, conditioning rivaling private clubs. Green fees $55-$95. No hole is flat.', playingTips: 'Few flat lies on the rolling terrain. Running approaches are difficult due to slopes around greens. The limestone-ledge par-3 8th requires precise club selection.', faqs: [{ question: 'Public?', answer: 'Yes. $55-$95.' }, { question: 'Designer?', answer: 'PB Dye, son of Pete Dye, 2003.' }, { question: 'Signature hole?', answer: 'Par-3 8th with green on a limestone ledge.' }, { question: 'Difficulty?', answer: '7,202 yards with bold bunkering and rolling terrain.' }] },
    { id: 'atx-5', name: 'Avery Ranch Golf Club', slug: 'avery-ranch-golf-club', city: 'Austin', state: 'Texas', type: 'public', rating: 4.2, greensFee: '$45–$85', architect: 'Andy Raugust', yearBuilt: 2002, holes: 18, par: 72, yardage: 7121, description: 'A popular north Austin layout, Avery Ranch delivers solid public golf with well-maintained bermuda fairways, challenging water features, and panoramic views of the Texas Hill Country from several elevated tee boxes.', highlights: ['Convenient north Austin location', 'Panoramic Hill Country views', 'Well-maintained public course'], imageAlt: 'Avery Ranch Golf Club with panoramic Hill Country views', history: 'Avery Ranch Golf Club opened in 2002 on 226 acres of Texas Hill Country terrain in north Austin, designed by Andy Raugust — a former design associate with the Jack Nicklaus organization. Dynamite was used to blast through limestone during construction; rather than fighting the rocky terrain, Raugust incorporated the natural limestone formations, caverns, live oaks, and rolling hills into the design.\n\nThe 60-acre Lake Avery serves as the dramatic backdrop for the closing stretch. The course has earned a 4.5-star Golf Digest rating, "Top Luxury Course" in Central Texas recognition, and multiple Avid Golfer awards including "Best Course Conditions" in the Austin area. Avid Golfer Magazine named the 18th the best finishing hole in Central Texas.', signatureHoles: [{ hole: 18, par: 4, yardage: 477, description: 'Named the best finishing hole in Central Texas by Avid Golfer Magazine. This long par 4 runs along Lake Avery with a tight fairway, river hazard, and rock cliff features framing the approach. Panoramic Hill Country and lake views make it a dramatic closer. Playing it as a three-shot hole is a legitimate strategy for most golfers.' }, { hole: 7, par: 4, yardage: 396, description: 'The primary signature hole — a dogleg right-to-left featuring two scenic carries including one over a creek from an elevated tee. The approach is to a multi-tiered green protected by a rock wall in front and native cacti behind. Among the finest views on the property.' }, { hole: 13, par: 3, yardage: 161, description: 'The most visually striking short hole. The green sits adjacent to a water hazard with distinctive rock formations to the right. Anything pushed right is swallowed by the hazard — precise iron play is essential.' }], whatToExpect: 'Avery Ranch sits within a residential community 20 miles north of downtown Austin but feels surprisingly natural. Rock walls appear at tee areas and around greens, live oaks line fairways, and limestone outcroppings frame shots throughout.\n\nThe front nine is the more demanding half — tighter corridors, more elevation change, and several holes demanding accuracy off the tee. The back nine has an unusual structure of three par 3s, three par 4s, and three par 5s, favoring bolder play. The round builds to the climactic 18th along Lake Avery.\n\nWater affects 9 of 18 holes. TifEagle Bermuda greens are large and undulating; 60 soft sand bunkers guard landing zones and greens. Conditions are consistently praised — strong for a course handling 70,000+ rounds per year.', playingTips: 'Accuracy over distance off the tee. The oak-lined corridors punish wayward drives more than short ones. Keep the ball in the fairway.\n\nRespect the water on holes 4, 5, 13, 14, and 18. On hole 14, there is no water left — a useful bailout note.\n\nThe par 5s offer the best birdie chances but each features its own combination of water, trees, and bunkers. Assess risk carefully before going for the green in two.\n\nThe 477-yard 18th along Lake Avery is a brute. Consider playing it as a three-shot hole — the lake and river hazard punish anything right.\n\nExpect firm, fast Bermuda conditions. Factor in extra roll on approaches.', faqs: [{ question: 'Who designed Avery Ranch?', answer: 'Andy Raugust, a former Jack Nicklaus design associate. The course opened in 2002 on 226 acres in north Austin.' }, { question: 'What is the signature hole?', answer: 'The 18th — a 477-yard par 4 along Lake Avery, named the best finishing hole in Central Texas by Avid Golfer Magazine. The 7th (dogleg with rock wall green) is also a standout.' }, { question: 'How difficult is Avery Ranch?', answer: 'From the tips: 7,121 yards, rating 73.5, slope 134. Five tee sets ranging down to 4,924 yards make it accessible for all skill levels. Water affects 9 of 18 holes.' }, { question: 'What are the conditions like?', answer: 'Consistently rated best course conditions in the Austin area. TifEagle Bermuda greens, 419 Bermuda fairways — strong conditioning for a high-volume public course.' }]},
    { id: 'atx-6', name: 'The Golf Club at Star Ranch', slug: 'star-ranch-golf-club', city: 'Hutto', state: 'Texas', type: 'public', rating: 4.1, greensFee: '$75–$120', architect: 'Jay Morrish & Roy Bechtol', yearBuilt: 2001, holes: 18, par: 71, yardage: 7017, description: 'Carved through rolling Hill Country terrain northeast of Austin, Star Ranch is a championship par-71 layout stretching to 7,017 yards from the tips. The Morrish-Bechtol design weaves through natural creek corridors and mature oak canopies, rewarding precise shot-making over power.', highlights: ['Jay Morrish & Roy Bechtol championship design', 'Rolling Hill Country terrain with creek corridors', 'Among Austin\'s top-ranked public daily-fee layouts'], imageAlt: 'Championship fairway winding through Texas Hill Country oaks at Star Ranch Golf Club near Hutto', history: 'Star Ranch opened in 2001 on the former Timmerman Ranch in Hutto, Texas — a working cattle property on 1,000 acres northeast of Austin. The course was designed by a four-architect collaboration: Jay Morrish and his son Carter Morrish of Jay Morrish & Associates, together with Roy Bechtol and Randy Russell of the Austin-based Bechtol & Russell Golf Design firm. This multi-firm approach was unusual and reflects the ambition of the project, which served as the anchor for a master-planned residential community.\n\nStar Ranch became the first Austin-area course to market itself as an "All-Inclusive" daily-fee layout — including range balls with the green fee, a value proposition that has defined its reputation. In 2007 a new 55,000-square-foot practice facility debuted, featuring multiple teeing areas, six tiered target greens, and a full short game area — one of the largest public-access practice complexes in central Texas.', signatureHoles: [{ hole: 15, par: 3, yardage: 123, description: 'The course\'s signature hole — a par 3 featuring a pond with cascading waterfall that fronts and guards the green. A large bunker also protects the right side. The carry-over-water demand combined with the visual drama makes this the most talked-about shot at Star Ranch. Aim for the center of the green and commit fully — hesitation leads to the water.' }, { hole: 11, par: 4, yardage: 385, description: 'Considered one of the most memorable holes on the back nine and a defining test of the more strategic, tree-lined routing. The correct side of the fairway off the tee opens up a much cleaner angle into the green.' }, { hole: 1, par: 4, yardage: 425, description: 'The opening hole plays through a tree-lined corridor — a strong first impression that signals the course\'s serious intent. Length and accuracy are both needed from the first swing.' }], whatToExpect: 'Star Ranch divides naturally into two personalities. The front nine plays in links style — wide-open, gently rolling fairways with minimal tree cover, where wind becomes the primary defense. The back nine tightens considerably: more tree-lined corridors, more pronounced elevation changes, and more strategic demands.\n\nSixty-six white sand bunkers are strategically positioned at fairway landing zones and around greens. The architects placed them to reward players who think through their angles rather than just aim for the flag. Playing to the correct side of the fairway is more important than raw distance.\n\nRange balls are included with the green fee — a rarity among Austin-area daily-fee courses — and the 55,000-square-foot practice facility is one of the best in the region.', playingTips: 'Wind is the defining variable at Star Ranch. The open front nine can play dramatically differently depending on direction — factor wind before every tee shot and club selection.\n\nAngles off the tee matter more than pure distance. The 66 bunkers reward players who identify the correct side of the fairway before reaching for driver.\n\nHole 15 (the waterfall par 3): commit fully to your club selection and aim for the center of the green. Indecision leads to the water. Take one more club if uncertain.\n\nThe back nine holes 11–13 play with noticeable elevation change — the par-4 13th plays entirely uphill and feels significantly longer than its yardage. Add a club.\n\nArrive early and use the practice facility — precise distance control on the Bermuda greens rewards warm-up time.', faqs: [{ question: 'Does Star Ranch include range balls?', answer: 'Yes. Star Ranch markets itself as Austin\'s "All-Inclusive" course — range balls are included with the green fee, a notable value in the Austin market.' }, { question: 'Who designed Star Ranch?', answer: 'A four-architect team: Jay Morrish and Carter Morrish of Jay Morrish & Associates, and Roy Bechtol and Randy Russell of Bechtol & Russell Golf Design. The course opened in 2001.' }, { question: 'What makes Star Ranch distinctive?', answer: 'The contrast between the links-style open front nine and the tighter, tree-lined back nine gives the round two distinct personalities. The 55,000-square-foot practice facility is one of the largest public-access complexes in central Texas.' }, { question: 'What is the signature hole?', answer: 'Hole 15, a par 3 featuring a pond with cascading waterfall that fronts the green. It\'s the most photographed and talked-about hole on the course.' }]},
    { id: 'atx-7', name: 'Grey Rock Golf Club', slug: 'grey-rock-golf-club', city: 'Austin', state: 'Texas', type: 'semi-private', rating: 4.2, greensFee: '$80–$105', architect: 'Jay Morrish', yearBuilt: 1992, holes: 18, par: 72, yardage: 6909, description: 'Situated just south of downtown Austin on 160 acres of rolling Hill Country, Grey Rock is a Jay Morrish design that plays through stately live oaks and dramatic elevation shifts. The semi-private layout pairs public access with private-club conditions.', highlights: ['Jay Morrish design on 160 oak-studded acres near downtown', 'Recent comprehensive greens and tee-box renovation', 'Semi-private access with resort-quality conditioning'], imageAlt: 'Live oak-lined fairway at Grey Rock Golf Club with rolling Austin Hill Country elevation', history: 'Grey Rock Golf Club opened in 1992 as Circle C Golf Club, designed by Jay Morrish with Roy Bechtol as part of the Circle C Ranch master-planned community in southwest Austin. The 160-acre property was built on rolling terrain with towering live oaks that Morrish routed around to create the course\'s signature tree-lined corridors.\n\nIn March 2014, the Austin City Council voted 6-1 to purchase the course for $9.6 million using parkland and open space funds, preserving 160 acres of green space in a rapidly developing part of southwest Austin. The course was rebranded Grey Rock Golf Club and contracted to Touchstone Management. In 2023, the course closed for a five-month renovation that rebuilt all 18 greens (excavated to 6 inches and regrassed with TifDwarf Bermuda) and resurfaced all tee boxes — the most significant investment in the course since its 1992 opening. Grey Rock reopened in October 2023.', signatureHoles: [{ hole: 7, par: 5, yardage: 542, description: 'The hardest hole on the course (Handicap 1). At 542 yards, the hole plays through clusters of live oaks that demand precise shotmaking at multiple points. Three well-executed shots are required to have a realistic birdie chance — going for the green in two through the trees almost always leads to trouble. Par is a solid score here.' }, { hole: 5, par: 4, yardage: 380, description: 'A tricky mid-length par 4 where the challenge comes from the bunker complex surrounding the green. The green is set slightly right at the fairway\'s end — approaches from the left side open up the best angle and reduce bunker exposure.' }, { hole: 18, par: 4, yardage: 420, description: 'The closing hole plays toward a lake overlooked by the two-story clubhouse. The visual drama of finishing with a gallery from the clubhouse veranda, with water in play, makes this one of the most memorable finishers among Austin public courses.' }], whatToExpect: 'Grey Rock plays through 160 acres of southwest Austin terrain with towering live oaks as the defining visual and strategic feature throughout. The tree-lined corridors frame virtually every hole, creating a golf-in-the-forest atmosphere unusual for a city-owned course.\n\nThe layout is largely parkland-style with gently rolling terrain. The front nine is relatively straightforward; the back nine tightens with more doglegs and demanding angles. At 6,909 yards (slope 139, rating 74.6) it is one of the more demanding public layouts in Austin.\n\nThe 2023 green renovation means the putting surfaces are in their best condition since 1992. The Rock Grille restaurant and two-story clubhouse make it a full-service facility.', playingTips: 'Respect the live oaks — they are in play on virtually every hole and will deflect errant shots unpredictably. Keep the ball in the fairway corridors; recovery from deep under the oaks is very difficult.\n\nHole 7 (the hardest hole): treat it as a genuine three-shot par 5. Attempting to reach in two through the tree clusters almost always results in trouble. Lay up short of the trees on the second shot and hit a wedge to the green.\n\nOn Hole 5, attack from the left side of the fairway. The green is set right, so left-of-center approaches reduce bunker exposure and open up the best angle.\n\nThe Hole 18 lake is unforgiving. Do not force a heroic shot to a tight flag — two-putt par is a satisfying finish.', faqs: [{ question: 'What was Grey Rock Golf Club called before?', answer: 'Circle C Golf Club, the name it carried from its 1992 opening until the City of Austin purchased the property in 2014 for $9.6 million as open space preservation.' }, { question: 'Who designed Grey Rock?', answer: 'Jay Morrish with Roy Bechtol, the same team that later contributed to Star Ranch. The course opened in 1992 as Circle C Golf Club.' }, { question: 'Was Grey Rock recently renovated?', answer: 'Yes. A major renovation closed the course from May to October 2023. All 18 greens were rebuilt with new TifDwarf Bermuda and all tee boxes were resurfaced — the biggest investment since the course opened.' }, { question: 'Is Grey Rock public or private?', answer: 'It is city-owned and operates as a hybrid semi-private facility — open to daily-fee golfers and offering membership options. The City of Austin purchased it in 2014 to prevent residential development.' }]},
    { id: 'atx-8', name: 'Onion Creek Club', slug: 'onion-creek-club', city: 'Austin', state: 'Texas', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Jimmy Demaret', yearBuilt: 1974, holes: 18, par: 72, yardage: 6710, description: 'Founded in 1974 and designed by two-time Masters champion Jimmy Demaret, Onion Creek Club is the only golf course Demaret ever designed — a singular piece of Texas golf history. Ben Crenshaw and Bill Coore sensitively added nine holes in 1996, and the club hosted the Legends of Golf senior major for many years.', highlights: ['Only golf course ever designed by Jimmy Demaret', 'Ben Crenshaw & Bill Coore added nine holes in 1996', 'Historic host of the Legends of Golf senior major'], imageAlt: 'Spring-fed creek framing a cypress-lined fairway at Onion Creek Club in south Austin', history: 'Onion Creek Club was founded in 1974 by Austin businessman Jimmie Connolly and three-time Masters champion Jimmy Demaret, who designed the course and declared "Nature put it here, all I did was manicure it." It is the only golf course Demaret ever designed. The routing follows the namesake Onion Creek waterway through 225 acres of Texas Hill Country terrain.\n\nIn 1978, Demaret and television producer Fred Raphael launched the Legends of Golf at Onion Creek — a televised best-ball tournament featuring retired golf legends. The 1979 edition became a pivotal moment in golf history: Roberto De Vicenzo and Julius Boros birdied the final four holes to force a playoff on national NBC television, demonstrating overwhelming public appetite for senior golf competition. The PGA Senior Tour was formally established in 1980 directly as a result. Onion Creek is recognized as the birthplace of what is now the PGA Tour Champions.\n\nThe club added nine holes designed by Ben Crenshaw and Bill Coore in 1996 at higher elevation — creating a 27-hole facility with three 18-hole combinations. In October 2013 a catastrophic flood crested the creek at its highest level in 92 years; the $5–7 million in damage was restored under Coore and Crenshaw\'s oversight, with the original Demaret holes reopening in August 2014.', signatureHoles: [{ hole: 12, par: 4, yardage: 342, description: 'The signature hole — the tee sits approximately 50 feet above the fairway with dramatic downhill views. Onion Creek runs tight along the right side, guarding the approach. The elevation drop on the drive is exhilarating but demands precise distance control on the approach. Creek right punishes the bail-out.' }, { hole: 17, par: 3, yardage: 144, description: 'Deceptively difficult: short yardage but a severely elevated tee and a tri-level green create optical illusions and putting chaos. Wind swirls unpredictably from the elevated tee. Take more club than instinct suggests and target the correct tier — a putt from the wrong level is a likely three-putt.' }, { hole: 7, par: 5, yardage: 601, description: 'A dogleg-left at 601 yards with water running the entire right side. Three shots is virtually always the correct strategy — laying up short of the creek leaves a controlled wedge in. Almost no one reaches in two without flying directly over the water.' }], whatToExpect: 'Onion Creek plays as a classic Texas parkland course threading through mature live oaks and cedar elms, with the creek as the dominant strategic element. The original Demaret holes follow the creek bottom; the Crenshaw/Coore nine runs at higher elevation with more exposure and modern par-4s stretching to 450 and 461 yards.\n\nThe course rewards accuracy over power (par 70, under 6,500 yards from the tips) but the small, tightly guarded greens, penal rough, and six consecutive holes alongside the creek on the front nine make it genuinely challenging. Water affects play on 11–13 holes depending on the 18-hole combination.\n\nAccess is private, members and guests only.', playingTips: 'Accuracy over distance. The small greens and penal rough reward a 200-yard shot in the fairway over a 280-yard shot in the rough. Do not grip it and rip it.\n\nHoles 3–8 on the original course: Onion Creek runs continuously on the right side. Make the left side of the fairway your target throughout this stretch — errant shots right are rarely safe.\n\nHole 12: trust the elevation. The 50-foot drop makes the drive feel effortless but distance control on the approach is tricky. Commit to your line — the creek on the right punishes the bail-out.\n\nHole 17: one more club than the yardage suggests. Target the correct tier of the tri-level green — a putt from the wrong level can be a three-putt.\n\nBunker play must be clean. Some greenside bunkers have four-foot-tall front walls requiring a full, aggressive swing with complete follow-through.', faqs: [{ question: 'Why is Onion Creek historically significant?', answer: 'It is the birthplace of the PGA Tour Champions (formerly PGA Senior Tour). The Legends of Golf tournament, created at Onion Creek in 1978, directly inspired the founding of the Senior Tour in 1980. It is also the only golf course ever designed by three-time Masters champion Jimmy Demaret.' }, { question: 'Who designed Onion Creek Club?', answer: 'Jimmy Demaret designed the original 18 holes (1974), calling it his only course design. Ben Crenshaw and Bill Coore added nine holes in 1996, creating a 27-hole facility.' }, { question: 'Can the public play Onion Creek?', answer: 'No. Onion Creek is a private club — access is for members and their guests only.' }, { question: 'What happened to the course in 2013?', answer: 'A catastrophic Halloween flood crested the creek at its highest level in 92 years. The $5–7 million in damage was restored under Coore and Crenshaw\'s guidance, with the original Demaret holes reopening in August 2014.' }]},
    { id: 'atx-9', name: 'Crystal Falls Golf Club', slug: 'crystal-falls-golf-club', city: 'Leander', state: 'Texas', type: 'public', rating: 4.0, greensFee: '$55–$85', architect: 'Jack Miller', yearBuilt: 1990, holes: 18, par: 72, yardage: 6654, description: 'Perched on cedar- and oak-covered ridges in Leander, Crystal Falls is routinely cited as one of the most scenic public courses in Central Texas. Jack Miller\'s 1990 design threads through dramatic limestone bluffs and seasonal waterfalls, offering panoramic Hill Country views on nearly every hole.', highlights: ['Dramatic limestone bluffs and namesake seasonal waterfalls', 'Panoramic Hill Country views from nearly every hole', 'Accessible municipal pricing with above-average conditioning'], imageAlt: 'Limestone bluff and cedar-lined fairway at Crystal Falls Golf Club in Leander Texas', history: 'Crystal Falls Golf Club opened in 1990, designed by Jack Miller on 215 acres of rugged Hill Country terrain in Leander, Texas. The course was carved through dramatic limestone bluffs and canyon systems — the natural terrain so challenging that the course has zero sand bunkers, relying entirely on creeks, canyons, thick brush, and severe slopes as defense.\n\nOwned and operated by the City of Leander, Crystal Falls serves as one of the most scenic and affordable public golf experiences in Central Texas. The course hosted the 2024 and 2025 Texas Boys and Girls 1A State Golf Championships, establishing its credentials as a legitimate competitive venue despite municipal pricing.\n\nThe name references the crystal-clear waterfall features in the natural limestone terrain of the surrounding area.', signatureHoles: [{ hole: 11, par: 3, yardage: 192, description: 'The crown jewel — widely called one of the greatest par 3s in Texas. The tee sits atop a bluff with an enormous elevation drop of roughly 200 feet to the green below. The panoramic Hill Country view from the elevated tee is spectacular. Club down significantly — the ball carries much farther than the yardage suggests due to the dramatic downhill trajectory.' }, { hole: 2, par: 3, yardage: 165, description: 'Another dramatic elevated-tee par 3 with an approximately 80-foot drop from tee to green. Along with Hole 11, these two par 3s from high bluffs to greens far below define the Crystal Falls experience.' }], whatToExpect: 'Crystal Falls is target golf through dramatic Hill Country terrain. Narrow, sloping fairways funnel errant shots into creeks, brush, or canyons. There are zero sand bunkers on the entire course — instead, 12 of 18 holes bring water into play, and thick native vegetation penalizes every miss.\n\nThe elevation changes are significant and the course is very difficult to walk (carts are essentially mandatory). The two elevated par 3s — Holes 2 and 11 — play from bluffs high above the greens and offer some of the most dramatic tee shots in Central Texas.\n\nBring extra golf balls. Ball loss is nearly inevitable for first-time visitors. Plan for a 4.5 to 5-hour round — the difficulty and terrain slow pace of play. The scenic beauty of the canyon vistas and Hill Country panoramas makes it worth every minute.', playingTips: 'Favor accuracy over distance on every tee shot. This is target golf — a well-placed iron beats a wild driver on nearly every hole. The narrow fairways and canyons make recovery very difficult.\n\nOn holes 2 and 11 (the elevated par 3s), club down significantly. The extreme downhill drops mean the ball carries much farther than the yardage suggests. Trust the elevation.\n\nPlay the high side of sloping fairways. Many fairways tilt toward creeks or brush — aiming uphill gives the ball a chance to feed back to center.\n\nStay below the hole on approach shots. The undulating greens punish downhill putts severely.\n\nStudy the hole layout before swinging. Many holes feature blind or semi-blind landing areas due to elevation changes — use the cart GPS carefully.', faqs: [{ question: 'Does Crystal Falls have sand bunkers?', answer: 'No — zero sand bunkers on the entire course. The natural limestone terrain, creeks, canyons, and thick brush serve as the sole defense. This is one of very few courses anywhere with no traditional bunkers.' }, { question: 'What is the signature hole?', answer: 'Hole 11, a par 3 with a roughly 200-foot elevation drop from tee to green. It is regularly cited as one of the greatest par 3s in Texas for its dramatic bluff-top tee shot and panoramic Hill Country views.' }, { question: 'Is Crystal Falls walkable?', answer: 'Not recommended. The extreme elevation changes make it very difficult to walk. Carts (included in the green fee) are essentially mandatory.' }, { question: 'How affordable is it?', answer: 'As a City of Leander municipal course, green fees start around $31 with frequent deals. One of the best values in Central Texas given the dramatic setting and competitive-caliber layout.' }]},
  ],
  'dallas-texas': [
    { id: 'dal-1', name: 'Dallas National Golf Club', slug: 'dallas-national', city: 'Dallas', state: 'Texas', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 2002, holes: 18, par: 72, yardage: 7335, description: 'Widely regarded as the finest golf course in the Dallas–Fort Worth metroplex, Dallas National is a Tom Fazio design that sprawls across rolling terrain south of the city. The course features immaculate conditioning, bold shaping, and a series of dramatic par-3s.', highlights: ['#1 ranked course in DFW', 'Tom Fazio masterpiece', 'Exceptional conditioning year-round'], imageAlt: 'Dallas National Golf Club sweeping fairway with manicured landscaping', history: 'Dallas National Golf Club opened in 2002 as a Tom Fazio design on rolling terrain south of Dallas. Developer and owner David Graham envisioned creating the finest private golf experience in the Dallas-Fort Worth metroplex, and Fazio delivered a layout that immediately earned elite status. The course was built on a property with significant natural elevation change, unusual for North Texas, which Fazio enhanced with his signature bold shaping and immaculate attention to detail.\n\nThe club quickly rose to the top of Texas golf rankings and established itself as one of the premier private clubs in the entire Southwest. Every hole has been described as a signature hole, with Fazio\'s trademark sculpted bunkers defining the immaculate zoysia fairways. The natural appearance of the course belies the extensive earthmoving and shaping that went into its creation.\n\nDallas National has maintained its position at the top of DFW golf through relentless conditioning standards and an exclusive membership that values the quality of the golf experience above all else. The course is consistently ranked in the top 100 in America and remains the standard by which all other DFW private clubs are measured.', signatureHoles: [{ hole: 4, par: 4, yardage: 440, description: 'A demanding dogleg par 4 with one of the tightest fairways on the course. Unlike the generous corridors on most holes, the 4th requires precision off the tee through a narrow chute.' }, { hole: 8, par: 3, yardage: 175, description: 'A beautiful par 3 that plays slightly downhill to a green framed by Fazio\'s distinctive bunkering. One of the most visually striking holes on the front nine.' }, { hole: 14, par: 5, yardage: 565, description: 'A risk-reward par 5 that tempts long hitters to go for the green in two. The fairway sweeps through natural terrain with strategic bunkering that punishes indecision.' }, { hole: 17, par: 3, yardage: 225, description: 'A dramatic long par 3 that plays through blasted rock, showcasing Fazio\'s ability to create memorable short holes. The green is well-defended and the setting is among the most dramatic on the course.' }], whatToExpect: 'Dallas National is a pristine, immaculately conditioned Tom Fazio design that feels more like Augusta National than a typical Texas course. The zoysia fairways are emerald green year-round, the bunkers are perfectly maintained, and the overall presentation is exceptional. The rolling terrain provides elevation changes and sightlines unusual for the DFW area.\n\nAt 7,335 yards from the tips with a par of 72, the course is a serious test but plays fair from the appropriate tees. The generous fairways on most holes allow players to swing freely, but the green complexes demand precise approach play. The four par 3s are a particular strength of the design, each memorable and demanding.', playingTips: 'While the fairways are generally generous, approach shots require precision. Fazio\'s greens feature subtle contours and firm surfaces that reject shots missing on the wrong side. Hitting to the correct quadrant of the green is essential for birdie opportunities.\n\nThe par 3s are a highlight and collectively one of the best sets of short holes in Texas. Take enough club to reach the center of each green rather than short-siding yourself in Fazio\'s deep bunkers.', faqs: [{ question: 'Can the public play Dallas National?', answer: 'No. Dallas National is an exclusive private club requiring membership. There is no public access or resort play available.' }, { question: 'How does Dallas National compare to other DFW courses?', answer: 'Dallas National is widely regarded as the number one course in the DFW metroplex and consistently ranks among the top 100 courses in America. It is the benchmark private club in North Texas.' }, { question: 'What type of grass is on the fairways?', answer: 'Dallas National features zoysia fairways, which provide an exceptionally tight, firm playing surface that allows clean contact and maintains its green color well into the Texas fall and winter months.' }, { question: 'Who designed Dallas National?', answer: 'Tom Fazio designed the course, which opened in 2002. Fazio is one of the most prolific golf course architects in America, known for his bold shaping and immaculate attention to visual presentation.' }] },
    { id: 'dal-2', name: 'Trinity Forest Golf Club', slug: 'trinity-forest', city: 'Dallas', state: 'Texas', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Bill Coore & Ben Crenshaw', yearBuilt: 2016, holes: 18, par: 71, yardage: 7432, description: 'Built on a former landfill, Trinity Forest is a bold Coore & Crenshaw design that brought links-style golf to North Texas. The treeless, windswept layout rewards creativity and shotmaking, and previously hosted the AT&T Byron Nelson.', highlights: ['Former AT&T Byron Nelson host', 'Links-style design unique to Texas', 'Coore & Crenshaw craftsmanship'], imageAlt: 'Trinity Forest Golf Club open links-style landscape in Dallas', history: 'Trinity Forest Golf Club opened in 2016 on one of the most unlikely sites in American golf: a former landfill in the Great Trinity Forest south of downtown Dallas. The city of Dallas partnered with the Salesmanship Club to transform the reclaimed land into a world-class golf facility, hiring Bill Coore and Ben Crenshaw to design the course.\n\nCoore and Crenshaw created a treeless, windswept links-style layout that was revolutionary for North Texas. The course features no trees, relying instead on wind, native grasses, deep bunkers, and bold green contours to defend par. The design drew comparisons to great British and Irish links courses.\n\nTrinity Forest hosted the AT&T Byron Nelson from 2018 to 2019, bringing PGA Tour competition to the unconventional venue. The tournament moved to TPC Craig Ranch in 2021. The course remains one of the most distinctive private club experiences in the Southwest, celebrated by architecture enthusiasts for its bold vision.', signatureHoles: [{ hole: 3, par: 4, yardage: 488, description: 'A long par 4 that epitomizes the links character. The treeless expanse exposes the hole to wind from every direction, and the approach must navigate bunkers and firm green contours.' }, { hole: 10, par: 3, yardage: 215, description: 'A dramatic par 3 with a deep bunker complex protecting the green. Wind is a constant factor, making club selection critical on this long one-shotter.' }, { hole: 14, par: 5, yardage: 604, description: 'A reachable par 5 for long hitters with a fiercely defended green complex. The risk-reward equation is classic Coore-Crenshaw, offering multiple strategic options.' }, { hole: 18, par: 4, yardage: 466, description: 'A strong finishing hole demanding two quality shots. The green is well-bunkered and the wind often swirls, creating a demanding conclusion to the round.' }], whatToExpect: 'Trinity Forest is unlike any other course in Texas. The completely treeless landscape creates a wide-open, windswept environment that feels more like the British Isles than North Texas. Native grasses line the fairways, deep bunkers dot the landscape, and the Coore-Crenshaw green complexes feature bold contours.\n\nAt 7,432 yards from the tips with a par of 71, the course is a serious test, especially when the wind blows. The firm, fast conditions encourage a ground game approach.', playingTips: 'Wind management is the number one skill at Trinity Forest. With no trees for shelter, every hole is exposed. Learn to flight the ball low and use the ground to your advantage. Bump-and-run shots around the greens are often more effective than high pitches.\n\nThe greens have significant movement and firm surfaces. Leaving approach shots below the hole provides the best birdie chances. Do not underestimate the deep bunkers, which feature steep faces requiring lateral escapes.', faqs: [{ question: 'Can the public play Trinity Forest?', answer: 'No. Trinity Forest is a private club affiliated with the Salesmanship Club of Dallas. There is no public access.' }, { question: 'Why did the Byron Nelson leave Trinity Forest?', answer: 'The AT&T Byron Nelson was held at Trinity Forest in 2018 and 2019. The tournament moved to TPC Craig Ranch in 2021, partly due to infrastructure challenges at the Trinity Forest site.' }, { question: 'What was the site before the golf course?', answer: 'Trinity Forest was built on a former landfill in the Great Trinity Forest south of downtown Dallas. The reclamation project transformed the site into a world-class golf facility.' }, { question: 'What style of course is Trinity Forest?', answer: 'It is a links-style course with no trees, relying on wind, native grasses, deep bunkers, and bold green contours. Designed by Bill Coore and Ben Crenshaw to evoke British and Irish links character.' }] },
    { id: 'dal-3', name: 'TPC Craig Ranch', slug: 'tpc-craig-ranch', city: 'Dallas', state: 'Texas', type: 'semi-private', rating: 4.5, greensFee: '$130–$200', architect: 'Tom Weiskopf', yearBuilt: 2004, holes: 18, par: 72, yardage: 7438, description: 'Current home of the CJ Cup on the PGA Tour, TPC Craig Ranch offers tour-caliber golf accessible to the public. Tom Weiskopf\'s design balances playability with championship challenge across rolling North Texas terrain.', highlights: ['Current CJ Cup PGA Tour host', 'Tour-quality conditioning', 'Public access to championship golf'], imageAlt: 'TPC Craig Ranch championship hole with tournament-ready conditions', history: 'TPC Craig Ranch was designed by Tom Weiskopf with D.A. Weibring and opened in 2004 in McKinney, north of Dallas. Weiskopf preserved natural limestone features and an 1800s roadbed in the routing.\n\nThe course gained national prominence when the AT&T Byron Nelson moved here in 2021, rebranded as the CJ Cup Byron Nelson. It has proven to be an excellent PGA Tour venue.\n\nAs a certified Audubon Cooperative Sanctuary, TPC Craig Ranch demonstrates environmental stewardship alongside championship golf. At 7,438 yards, it is one of the longest par-72 layouts on Tour.', signatureHoles: [{ hole: 11, par: 4, yardage: 460, description: 'A demanding par 4 along the creek that plays as one of the toughest during the CJ Cup. Water threatens the entire right side.' }, { hole: 14, par: 5, yardage: 571, description: 'A risk-reward par 5 producing dramatic CJ Cup moments. Long hitters can reach in two, but water guards the green.' }, { hole: 16, par: 3, yardage: 200, description: 'A strong par 3 over water with a well-bunkered green. Wind can make club selection tricky.' }, { hole: 18, par: 5, yardage: 570, description: 'A reachable finishing par 5 that provides exciting finishes. Eagles and big numbers are both possible with water threatening aggressive plays.' }], whatToExpect: 'TPC Craig Ranch offers PGA Tour-quality conditioning accessible to the public. The Weiskopf design features wide fairways, strategic bunkering, and well-defended greens on rolling North Texas terrain.\n\nAt 7,438 yards from the tips, the course is long but very playable from forward tees. Conditioning is outstanding year-round.', playingTips: 'The par 5s offer the best birdie opportunities. Play aggressively on reachable par 5s but respect water hazards guarding several greens.\n\nWind is a factor on the exposed terrain. The Bermuda greens are firm and fast, rewarding shots that land on the correct portion.', faqs: [{ question: 'Can the public play TPC Craig Ranch?', answer: 'Yes. TPC Craig Ranch is semi-private with green fees typically ranging from $130 to $200.' }, { question: 'What PGA Tour event is held here?', answer: 'The CJ Cup Byron Nelson, held at TPC Craig Ranch since 2021.' }, { question: 'Who designed TPC Craig Ranch?', answer: 'Tom Weiskopf with D.A. Weibring. It opened in 2004.' }, { question: 'How long is TPC Craig Ranch?', answer: 'The course plays to 7,438 yards from the championship tees, one of the longest par-72 layouts on the PGA Tour.' }] },
    { id: 'dal-4', name: 'Maridoe Golf Club', slug: 'maridoe-golf-club', city: 'Dallas', state: 'Texas', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Steve Smyers', yearBuilt: 2019, holes: 18, par: 72, yardage: 7569, description: 'One of the most talked-about new courses in America, Maridoe is a brutally challenging Steve Smyers design built for serious golfers. The course features vast bunker complexes, bold green contours, and a no-tee-time walk-only philosophy.', highlights: ['Walking-only philosophy', 'One of America\'s toughest courses', 'Instant Top 100 ranking'], imageAlt: 'Maridoe Golf Club dramatic bunkering and rolling terrain', history: 'Maridoe Golf Club has a layered history beginning as the Columbian Country Club of Dallas in Carrollton, Texas. The club closed in 2008 and briefly became the Honors Golf Club Dallas before being completely reimagined by architect Steve Smyers. Smyers completed his dramatic redesign and the course reopened as Maridoe Golf Club in 2017.\n\nSmyers\'s design philosophy was to create a world-class experience reflecting the modern game\'s demands. The result is one of the most demanding courses in America, stretching to nearly 7,834 yards from the back tees with a slope of 155 and a course rating of 80.5.\n\nMaridoe quickly earned national Top 100 rankings. The club operates with a walking-only, no-tee-time philosophy, attracting serious players who relish the challenge. NorthBridge Bermuda fairways and Champion Bermuda greens provide tournament-caliber surfaces year-round.', signatureHoles: [{ hole: 3, par: 4, yardage: 490, description: 'A demanding long par 4 setting the tone for the challenge ahead. The approach must navigate bold green contours and strategic bunkering.' }, { hole: 7, par: 5, yardage: 618, description: 'The number one handicap hole at 618 yards. This monster par 5 requires three well-struck shots, with hazards threatening at every stage.' }, { hole: 14, par: 3, yardage: 182, description: 'The easiest hole by handicap offers a brief respite, though Smyers\'s green contours still demand a precise tee shot to the correct portion of the surface.' }, { hole: 18, par: 4, yardage: 475, description: 'A strong finishing hole with deep bunkers and bold contours guarding the final green.' }], whatToExpect: 'Maridoe is not for the faint of heart. The course stretches to nearly 7,900 yards from the tips, though forward tees offer more enjoyable yardages. Smyers\'s design features vast bunker complexes with shaved faces, bold undulating green contours, and shaved runoff areas demanding a sharp short game.\n\nThe walking-only philosophy and lack of tee times create a laid-back, player-focused atmosphere despite the intense difficulty. Caddies are available and recommended for first-time visitors.', playingTips: 'Play the right tees. Even from forward tees, green complexes and bunkering provide ample challenge. The greens are the primary defense — Smyers designed bold contours with shaved collection areas punishing wrong-side misses.\n\nLanding on the correct tier is essential. A ball on the wrong level leads to three-putts even for skilled players. Study the green slopes carefully before putting.', faqs: [{ question: 'Why is Maridoe walking only?', answer: 'The club operates a walking-only policy to preserve the pure golf experience and turf quality. Caddies are available.' }, { question: 'How difficult is Maridoe?', answer: 'From the back tees it measures nearly 7,900 yards with a slope of 155 and rating of 80.5. Forward tees make it playable for various skill levels.' }, { question: 'What was the course before Maridoe?', answer: 'Originally Columbian Country Club of Dallas. After closing in 2008, it briefly operated as the Honors Golf Club before Smyers completed his redesign in 2017.' }, { question: 'Can the public play Maridoe?', answer: 'No. Maridoe is a private club with no public access.' }] },
    { id: 'dal-5', name: 'Stevens Park Golf Course', slug: 'stevens-park', city: 'Dallas', state: 'Texas', type: 'public', rating: 4.3, greensFee: '$35–$65', architect: 'A.W. Tillinghast (restored)', yearBuilt: 1922, holes: 18, par: 71, yardage: 6545, description: 'A beautifully restored 1920s A.W. Tillinghast design in the heart of Oak Cliff, Stevens Park is a civic treasure and arguably the best municipal golf experience in Texas. The hilly layout offers charming character and downtown skyline views.', highlights: ['Historic Tillinghast design', 'Best municipal course in Texas', 'Dallas skyline views'], imageAlt: 'Stevens Park Golf Course historic layout with Dallas skyline views', history: 'Stevens Park Golf Course opened in 1924 as the second municipal course in Dallas, built in the hilly Oak Cliff neighborhood southwest of downtown. The original design is attributed to Jack Burke Sr., father of Masters champion Jackie Burke Jr., though A.W. Tillinghast reportedly consulted on the layout during one of his PGA-funded tours in the 1930s.\n\nBy the early 2000s, Stevens Park had fallen into disrepair. A passionate group of Oak Cliff residents organized to save the course, raising funds and pushing the city to invest in a comprehensive renovation that restored the classic character of the hilly routing with improved greens, bunkers, and drainage.\n\nToday Stevens Park is widely regarded as one of the finest municipal courses in the South. Its compact, walkable layout through rolling Kessler Park terrain, combined with views of the downtown Dallas skyline, make it a unique civic treasure.', signatureHoles: [{ hole: 1, par: 4, yardage: 383, description: 'A welcoming opener playing downhill from an elevated tee with views of the rolling terrain ahead and the Dallas skyline in the distance.' }, { hole: 7, par: 3, yardage: 180, description: 'A scenic par 3 playing slightly downhill to a green nestled in the hillside. The natural amphitheater setting and classic bunkering make it one of the most photogenic holes on the course.' }, { hole: 12, par: 4, yardage: 410, description: 'A demanding dogleg par 4 through the most dramatic elevation changes on the course. The approach shot is significantly uphill to a well-defended green.' }, { hole: 18, par: 4, yardage: 402, description: 'A strong finishing hole climbing back toward the clubhouse with an uphill approach to a green framed by mature trees.' }], whatToExpect: 'Stevens Park is a charming, walkable municipal course that punches well above its weight class. The hilly Oak Cliff terrain provides dramatic elevation changes, interesting lies, and excellent views of the downtown Dallas skyline.\n\nAt 6,545 yards with a par of 71, the yardage is modest, but elevation changes and small greens make the course play longer than it measures. Conditioning has improved dramatically since the renovation, rivaling many private clubs in presentation.', playingTips: 'The hilly terrain means many approach shots are significantly uphill or downhill. Take extra time to assess elevation changes and adjust club selection accordingly. The greens are relatively small, so accuracy on approach shots is more important than distance.\n\nStevens Park is a walker\'s course, and the hilly terrain provides a genuine workout. Early morning tee times are recommended in summer to beat the Texas heat.', faqs: [{ question: 'Can anyone play Stevens Park?', answer: 'Yes. Stevens Park is a public municipal course operated by the City of Dallas. Green fees typically range from $35 to $65.' }, { question: 'Who designed Stevens Park?', answer: 'The original 1924 design is attributed to Jack Burke Sr. A.W. Tillinghast reportedly consulted on the layout in the 1930s. A comprehensive restoration in the 2000s brought it back to its classic character.' }, { question: 'Is Stevens Park walkable?', answer: 'Yes, and walking is the best way to experience the course, though the hilly terrain provides a genuine workout.' }, { question: 'What makes Stevens Park special among Dallas courses?', answer: 'Its combination of Golden Age design heritage, dramatic hilly terrain, downtown skyline views, and accessible municipal pricing make it unique. It is widely considered the best municipal course in Texas.' }] },
    { id: 'dal-6', name: 'Preston Trail Golf Club', slug: 'preston-trail-golf-club', city: 'Dallas', state: 'Texas', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Ralph Plummer & Byron Nelson', yearBuilt: 1962, holes: 18, par: 72, yardage: 7091, description: 'Founded in 1962 and designed by Ralph Plummer with Byron Nelson, Preston Trail Golf Club is one of the most storied and exclusive private clubs in the Southwest. The course served as home of the Byron Nelson Golf Classic from 1968 to 1982. Tripp Davis completed a celebrated renovation in 2018.', highlights: ['Home of the Byron Nelson Golf Classic 1968–1982', 'Tripp Davis renovation completed in 2018', 'Adults-only private club with no-tee-time tradition'], imageAlt: 'Manicured fairway and deep flashed bunkering at Preston Trail Golf Club in north Dallas', history: 'Preston Trail Golf Club was organized in 1962 by four Dallas businessmen including Lamar Hunt (founder of the AFL and Kansas City Chiefs). Ralph Plummer — one of Texas\'s most prolific mid-century architects — designed the course, with Byron Nelson serving as design collaborator and contributing specific elements including crepe myrtle plantings and green features inspired by Augusta National.\n\nIn 1968, the Dallas Open was renamed the Byron Nelson Golf Classic and relocated to Preston Trail, beginning a 15-year PGA Tour tenure. Notable winners included Jack Nicklaus (back-to-back 1970–71), Tom Watson (four titles, the most dominant player at the venue), Raymond Floyd, and others. The tournament outgrew the site after 1982 and moved to Las Colinas.\n\nIn 2007, Tripp Davis was selected from a competitive process to oversee a complete reconstruction. Davis met with Byron Nelson at his ranch to gain firsthand insight into the original design intent — remarkable because Nelson recalled specific details from 45 years earlier. The full reconstruction was completed in 2008–2009 with follow-on renovation work in 2018, regrassing to Zoysia and rebuilding bunkers. Golf Digest has ranked Preston Trail in the Top 5 in Texas throughout the post-renovation era.', signatureHoles: [{ hole: 7, par: 4, yardage: 422, description: 'The signature hole and the hardest on the course (Handicap 1). A dogleg right running along White Rock Creek. The tee shot demands a long, precisely faded drive to reach the narrow throat of the fairway — short or straight tee shots leave no angle to the green. The green slopes severely back-to-front. Ben Hogan reportedly considered this his favorite hole at Preston Trail.' }, { hole: 16, par: 4, yardage: 428, description: 'The tee sits more than 100 feet above the landing area — a dramatic downhill drive with White Rock Creek crossing the fairway. Most players lay up short of the creek, leaving a demanding approach to a well-guarded green. One of the most visually dramatic tee shots on the property.' }, { hole: 3, par: 5, yardage: 591, description: 'A strong par 5 that plays dramatically downhill on the second shot after threading a narrow tee-shot corridor. The creek guards the green on the approach — precise distance control on the lay-up is critical to avoid rolling through into the hazard.' }], whatToExpect: 'Preston Trail is an adults-only, men-only private club (21+ required; no women, no exceptions) that produces fewer than 10,000 rounds per year. With those numbers, the course almost never feels crowded, and the lightning-fast bent-grass greens are maintained to a standard that rivals any club in Texas.\n\nRalph Plummer\'s parkland design winds through White Rock Creek with tree-lined fairways and large, contoured greens. The Tripp Davis renovation restored the original design intent while transitioning fairways to Zoysia for year-round playing conditions. Club dining is described by multiple sources as the best of any private club in Dallas.\n\nNotable current members include George W. Bush, Troy Aikman, and Lee Trevino. Mickey Mantle was a longtime member — a shrine to his memorabilia is in the locker room.', playingTips: 'The bent-grass greens run fast and break more than they appear to. Being below the pin is the top priority on every hole — uphill putts are manageable, but downhill putts on back-to-front slopes can be career-defining.\n\nHole 7 (Handicap 1): commit to the fade off the tee. A straight or pulled drive leaves no angle into the green. Don\'t bail left.\n\nHoles 16 and 17 both cross White Rock Creek. The visual drama of the elevated tee on 16 can tempt aggressive play — the correct play is a controlled drive to the lay-up zone.\n\nThe par 5s are collectively the strongest holes on the course — they play varied in length and shape, and all offer genuine risk-reward decisions. Know your distance to the creek on par-5 approach shots.', faqs: [{ question: 'Is Preston Trail Golf Club men-only?', answer: 'Yes. Preston Trail is one of approximately eight remaining all-male golf clubs in the United States. Men only, adults 21+ only. Byron Nelson himself was once asked to leave for bringing a 17-year-old (Scott Verplank) onto the property.' }, { question: 'Did the Byron Nelson Classic play at Preston Trail?', answer: 'Yes, from 1968 to 1982. Notable winners include Jack Nicklaus (back-to-back 1970–71), Tom Watson (four wins), and Raymond Floyd. The tournament moved to Las Colinas after 1982.' }, { question: 'Who designed Preston Trail?', answer: 'Ralph Plummer was the primary architect, with Byron Nelson as design collaborator. The course opened in 1962. Tripp Davis oversaw a full reconstruction completed in 2008–2009 with additional renovation work in 2018.' }, { question: 'What is the membership like?', answer: 'Invitation-only with a waiting list typically five or more years. Initiation fees have been reported at approximately $125,000–$250,000 with monthly dues around $2,250–$2,550. The club produces fewer than 10,000 rounds per year, ensuring exceptional conditioning and uncrowded conditions.' }]},
    { id: 'dal-7', name: 'Brook Hollow Golf Club', slug: 'brook-hollow-golf-club', city: 'Dallas', state: 'Texas', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'A.W. Tillinghast', yearBuilt: 1920, holes: 18, par: 71, yardage: 7011, description: 'One of the crown jewels of Golden Age American golf architecture, Brook Hollow was designed by A.W. Tillinghast in 1920. Bold flashed bunkers, undulating greens, and natural terrain movement create thrilling risk-reward decisions on every hole. A Coore & Crenshaw renovation restored the course\'s classic character.', highlights: ['A.W. Tillinghast Golden Age masterwork from 1920', 'Coore & Crenshaw renovation honoring original design', 'Consistently ranked among the top 5 courses in Texas'], imageAlt: 'Golden Age Tillinghast bunkering and tree-lined fairway at Brook Hollow Golf Club in Dallas', history: 'Designed by A.W. Tillinghast in 1920, one of the earliest Golden Age courses in Texas. Tillinghast, architect of Winged Foot and Baltusrol, created a strategic layout on rolling terrain. Coore & Crenshaw completed a restoration returning the bold flashed bunkers and undulating greens to their intended glory.\n\nConsistently ranked among the top five courses in Texas and one of the finest Tillinghast designs in the American South.', signatureHoles: [{ hole: 3, par: 4, yardage: 405, description: 'Strategic par 4 with Tillinghast flashed bunkers defining drive and approach.' }, { hole: 7, par: 3, yardage: 195, description: 'Demanding par 3 showcasing Tillinghast\'s short-hole mastery.' }, { hole: 13, par: 4, yardage: 430, description: 'One of the strongest par 4s with natural terrain creating risk-reward decisions.' }, { hole: 18, par: 4, yardage: 440, description: 'Fitting Tillinghast conclusion demanding two quality shots.' }], whatToExpect: 'World-class Golden Age experience. Bold flashed bunkers, undulating greens, and natural terrain movement on every hole. Par 71, 7,011 yards. Impeccable conditioning.', playingTips: 'Tillinghast greens are the primary defense. Understanding contours is essential. Bold bunkers are designed to be avoided, not easily escaped.', faqs: [{ question: 'Public?', answer: 'No. Private club.' }, { question: 'Designer?', answer: 'A.W. Tillinghast, 1920. Coore & Crenshaw restoration.' }, { question: 'Ranking?', answer: 'Consistently top 5 in Texas.' }, { question: 'Par/yardage?', answer: 'Par 71, 7,011 yards.' }] },
    { id: 'dal-8', name: 'Old American Golf Club', slug: 'old-american-golf-club', city: 'The Colony', state: 'Texas', type: 'semi-private', rating: 4.3, greensFee: '$150–$200', architect: 'Tripp Davis & Justin Leonard', yearBuilt: 2010, holes: 18, par: 71, yardage: 7084, description: 'Designed by Tripp Davis and PGA Tour champion Justin Leonard along the shores of Lake Lewisville, Old American evokes 1910s–1930s American golf architecture with a thoroughly modern playing experience. A slope of 145 from the tips makes it one of DFW\'s most demanding semi-private tracks.', highlights: ['Co-designed by PGA Tour champion Justin Leonard', 'Slope of 145 — among DFW\'s most demanding tests', 'Evokes Golden Age aesthetics along Lake Lewisville'], imageAlt: 'Wind-swept links-style fairway at Old American Golf Club along Lake Lewisville', history: 'Opened 2010, co-designed by Tripp Davis and 1997 Open champion Justin Leonard along Lake Lewisville in The Colony. Evokes 1910s-1930s Golden Age aesthetics with links-like wind exposure. Slope of 145 from tips makes it among DFW\'s most demanding semi-private courses.', signatureHoles: [{ hole: 3, par: 3, yardage: 200, description: 'Demanding lakeside par 3 with wind off Lake Lewisville.' }, { hole: 9, par: 4, yardage: 440, description: 'Strong lakefront par 4 closing the front nine.' }, { hole: 14, par: 4, yardage: 410, description: 'Strategic par 4 where tee angle determines approach quality.' }, { hole: 18, par: 4, yardage: 445, description: 'Demanding lakeside finisher with water and bunkers.' }], whatToExpect: 'Golden Age-inspired golf along Lake Lewisville. Windswept links-like setting with firm conditions and strategic bunkering. $150-$200 green fees.', playingTips: 'Wind off the lake is the primary defense. Play low shots when gusty. Firm conditions allow ground-game approaches. Golden Age bunkers are deep and penal.', faqs: [{ question: 'Can the public play?', answer: 'Semi-private with green fees $150-$200.' }, { question: 'Who designed it?', answer: 'Tripp Davis and Justin Leonard, 2010.' }, { question: 'How difficult?', answer: 'Slope 145 from tips, one of DFW\'s most demanding.' }, { question: 'What style?', answer: 'Golden Age aesthetics with links-like wind exposure.' }] },
    { id: 'dal-9', name: 'Waterchase Golf Club', slug: 'waterchase-golf-club', city: 'Fort Worth', state: 'Texas', type: 'public', rating: 4.2, greensFee: '$65–$110', architect: 'Steve Plummer', yearBuilt: 2000, holes: 18, par: 72, yardage: 7304, description: 'Consistently rated the top public golf course in Fort Worth, Waterchase stretches to 7,304 yards — one of the longest public tracks in the DFW metroplex. Six tee sets make the course playable for all abilities, while the championship configuration provides a genuine test for scratch players.', highlights: ['7,304 yards — among DFW\'s longest public courses', 'Six tee options accommodate all skill levels', 'Top-rated public course in Fort Worth'], imageAlt: 'Tree-lined dogleg fairway with water hazard at Waterchase Golf Club in Fort Worth', history: 'Waterchase Golf Club opened in 2000, designed by Steven D. Plummer on rolling hills in east Fort Worth near the Trinity River. The layout stretches to 7,304 yards from the championship tees — one of the longest public courses in the DFW metroplex — with an unusual configuration of five par 3s and five par 5s (rather than the standard four of each).\n\nThe course quickly established itself as the top-rated public course in Fort Worth, carrying a 4.6 out of 5 GolfPass rating with 95.6% of reviewers recommending it. It has hosted the USBGA (United States Blind Golf Association) Nationals, reflecting its championship-caliber layout. The on-site Jim McLean Golf Center provides one of the premier practice and instruction facilities in the DFW region.\n\nThe cascading waterfall between the 9th and 18th greens serves as the course\'s visual centerpiece — one of the most scenic finishes in DFW public golf.', signatureHoles: [{ hole: 9, par: 4, yardage: 433, description: 'The front nine closer plays to a green area framed by the course\'s cascading waterfall feature. Favor the left side off the tee for the best approach angle. Water behind the green punishes anything long — this is not the hole to be aggressive on the approach.' }, { hole: 10, par: 5, yardage: 633, description: 'A monster par 5 and the longest hole on the course. At 633 yards from the tips, this is a genuine three-shot hole. Course management is essential — forced heroics on the second shot rarely pay off.' }, { hole: 18, par: 5, yardage: 570, description: 'The finishing hole shares the cascading waterfall backdrop with the 9th, creating one of the most scenic finishing holes in DFW public golf. Lay up to approximately 120 yards for an ideal uphill approach rather than forcing a risky go-for-it second shot.' }, { hole: 17, par: 4, yardage: 484, description: 'A nearly 500-yard par 4 from the tips — one of the toughest two-shot holes in Fort Worth. Plays as a borderline par 5 for most amateurs. Two quality shots are mandatory to reach the green in regulation.' }], whatToExpect: 'Waterchase plays through rolling terrain unusual for the flat DFW area, mixing tree-lined doglegs with open exposed holes. Water comes into play on 11 of 18 holes, and over 50 soft sand bunkers guard landing zones and greens. Six tee sets span from 4,941 to 7,304 yards, making the course genuinely playable for all skill levels.\n\nThe five par 5s — including two over 600 yards (holes 10 and 13) — are the defining features. They demand careful course management but offer genuine birdie chances for those who plot their way intelligently. The Champions Bermuda greens are large, undulating, and roll true.\n\nGreen fees starting around $35 make this exceptional value for a championship-quality layout. The modest clubhouse is the only weak point — the course quality far exceeds the facility.', playingTips: 'Choose tees wisely. The 7,304-yard tips with 137 slope will test even low-handicap players. The blue tees at 6,661 yards offer a challenging but fair test for mid-handicappers.\n\nRespect the par 5s — all five are genuine three-shot holes from the back tees, including two over 600 yards. Play them conservatively rather than forcing heroic second shots into water.\n\nBring extra golf balls. Water on 11 holes burns through ammunition quickly.\n\nOn Hole 9, favor the left side off the tee. On Hole 18, lay up to 120 yards for the best uphill approach angle. Both holes share the waterfall — don\'t let the scenery distract from the strategy.\n\nHoles 15 and 18 share the same tee-shot landing area — be aware of other groups on the adjacent hole.', faqs: [{ question: 'Is Waterchase the best public course in Fort Worth?', answer: 'By most measures, yes. It carries a 4.6/5 GolfPass rating with 95.6% recommending it, and is consistently rated the top public course in Fort Worth by multiple publications.' }, { question: 'How long is Waterchase?', answer: 'At 7,304 yards from the tips, it is among the longest public courses in the DFW metroplex. Six tee sets ranging down to 4,941 yards make it playable for all abilities.' }, { question: 'What makes the finish special?', answer: 'The cascading waterfall between the 9th and 18th greens creates one of the most scenic finishes in DFW public golf. Both holes play toward the waterfall backdrop.' }, { question: 'What practice facilities are available?', answer: 'The Jim McLean Golf Center on-site features a grass driving range, chipping area, bunker practice, and putting greens — one of the premier practice facilities in the DFW region.' }]},
  ],
  'houston-texas': [
    { id: 'hou-1', name: 'Houston Oaks Golf Course', slug: 'houston-oaks', city: 'Houston', state: 'Texas', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Rees Jones', yearBuilt: 2005, holes: 18, par: 72, yardage: 7200, description: 'Set on a sprawling ranch property northwest of Houston, Houston Oaks is a Rees Jones design that offers an exclusive, rustic golf experience. The course winds through native oaks and open meadows with first-class conditioning.', highlights: ['Exclusive ranch-style setting', 'Rees Jones design', 'Premier Houston-area private club'], imageAlt: 'Houston Oaks Golf Course fairway through native oak trees', history: 'The Houston Oaks property spans nearly 1,000 acres in Hockley, Texas, roughly 40 miles northwest of downtown Houston. The land was originally owned by Tenneco Oil and Gas Company, which established Tennwood Golf Club on the site as an employee recreational facility in 1956, with the original course designed by Ralph Plummer.\n\nIn 2006, three Houston families — the Alvises, Havens, and Watsons — acquired the property with a vision for a family-oriented sporting retreat. A devastating clubhouse fire in 2008 destroyed the original structure, but the ownership group rebuilt and reimagined the entire facility. The golf course underwent a complete redesign by Chet Williams — the architect behind top-ranked Whispering Pines Golf Club — with construction beginning in 2015 and a formal grand opening in spring 2017. No holes from the original Plummer layout were retained.\n\nHouston Oaks was ranked the No. 2 private course in Texas in 2019–2020 rankings, behind only Whispering Pines (also a Williams design), making Williams the first architect to hold both top Texas spots simultaneously.', signatureHoles: [{ hole: 5, par: 3, yardage: 145, description: 'An island green par 3 reminiscent of TPC Sawgrass\'s 17th but with a Texas twist — a stone wall perimeter replaces railroad ties. This newly constructed hole did not exist on the original course and is the most photographed feature at Houston Oaks. Commit to your number and don\'t let the visual intimidation affect club selection.' }, { hole: 18, par: 4, yardage: 429, description: 'Water flanks the entire left side of this strong finishing hole. Two strategically placed fairway trees influence shot selection off the tee and approach, making accuracy critical for a dramatic risk-reward conclusion to the round.' }, { hole: 8, par: 5, yardage: 537, description: 'A reachable par 5 that rewards aggressive, well-placed shots. Strategic bunkering and water hazards guard the approach, creating genuine risk-reward decisions for players debating whether to go for the green in two.' }], whatToExpect: 'Houston Oaks is set on a sprawling ranch property with century-old oak trees, open meadows, and a "links lite" character — fairways feature intricate movement and undulation reminiscent of links golf despite the East Texas setting. The TifEagle Bermuda greens are maintained in pristine condition, and the bunkers contain real fluffy sand (unusual for Texas) though they are deceptively deep.\n\nBeyond the 18-hole championship course, the property includes a 9-hole Scrambler family short course, seven dining outlets, equestrian facilities, stocked fishing lakes, tennis courts, a spa, shooting range, and a 12-room boutique hotel. The club targets approximately 600 members. The pace expectation is 4 hours 15 minutes or less.\n\nAccess is private — members and guests only.', playingTips: 'Respect the bunkers. They look manageable but are deceptively deep — the fluffy sand plays differently than typical hard Texas sand. Use proper technique and take enough loft to clear the lip.\n\nOn the island green 5th, club selection is everything. Take the wind seriously, commit to your number, and aim for the center. Missing the green means a penalty stroke.\n\nThe fairways have links-style undulations — balls kick and bounce unpredictably. Each round reveals new subtleties in how the terrain influences the ball.\n\nOn the 18th, favor the right side off the tee. Water on the left and fairway trees make the finishing hole a genuine test of accuracy over aggression.', faqs: [{ question: 'Who designed Houston Oaks?', answer: 'Chet Williams, the architect behind Whispering Pines (Texas\'s top-ranked course). Williams completely redesigned the course — no holes from the original 1956 Ralph Plummer layout were retained. The new course opened in 2017.' }, { question: 'Can the public play Houston Oaks?', answer: 'No. Houston Oaks is a private club with approximately 600 members. Access is for members and their guests only.' }, { question: 'What else is on the property?', answer: 'Nearly 1,000 acres including a 9-hole Scrambler short course, seven dining outlets, equestrian facilities, fishing lakes, tennis courts, a spa, shooting range, disc golf, and a 12-room boutique hotel with cottages and cabins.' }, { question: 'How is it ranked?', answer: 'No. 2 private course in Texas (2019–2020 rankings), behind only Whispering Pines — also a Chet Williams design.' }]},
    { id: 'hou-2', name: 'Memorial Park Golf Course', slug: 'memorial-park', city: 'Houston', state: 'Texas', type: 'public', rating: 4.5, greensFee: '$40–$75', architect: 'Tom Doak (renovation)', yearBuilt: 1936, holes: 18, par: 72, yardage: 7412, description: 'Completely reimagined by Tom Doak in 2019, Memorial Park is a world-class municipal course and current host of the Houston Open. The renovation transformed this Depression-era layout into one of America\'s finest public courses.', highlights: ['Houston Open PGA Tour host', 'Tom Doak renovation', 'Best municipal course in America contender'], imageAlt: 'Memorial Park Golf Course renovated Tom Doak design in Houston', history: 'Memorial Park Golf Course dates to 1936 when it was built as a Works Progress Administration project during the Great Depression on the site of a former World War I military training camp. The course served Houston golfers for decades as one of the busiest municipal facilities in the country.\n\nIn 2019, Tom Doak completed a comprehensive renovation that transformed the course into a world-class public facility. PGA Tour champion Brooks Koepka consulted on the redesign, helping ensure it would test the best players in the world. The renovation reimagined every hole, adding strategic variety, new water features, and modern green complexes while respecting the property\'s mature tree-lined character.\n\nThe PGA Tour\'s Houston Open moved to Memorial Park in 2020, bringing professional golf back to a public course in Houston. Memorial Park is now widely considered one of the finest public courses in America.', signatureHoles: [{ hole: 1, par: 4, yardage: 522, description: 'A bold opening hole that functions as a mission statement for the course. The long par 4 demands a well-placed drive and precise approach to a green with characteristic Doak contours.' }, { hole: 15, par: 3, yardage: 165, description: 'A short par 3 with a creek along the left side. One of Brooks Koepka\'s favorites from the consultation process. Despite its brevity the green is well-defended.' }, { hole: 17, par: 4, yardage: 330, description: 'A drivable par 4 and one of the most unique holes at Memorial Park. Strategic options off the tee create compelling risk-reward decisions.' }, { hole: 18, par: 4, yardage: 475, description: 'A brutal finishing hole that regularly plays as one of the most difficult on the PGA Tour, demanding two strong shots to reach the well-defended green.' }], whatToExpect: 'Memorial Park is a mature, tree-lined parkland course set within Houston\'s iconic Memorial Park. The Doak renovation preserved the property\'s natural character while introducing modern strategic elements. The par-70 layout plays to 7,435 yards from championship tees with firm and fast conditions when weather permits.\n\nThe final six holes are particularly notable, including drivable par 4s, par 5s, a short par 3, and a demanding finishing hole. The course is walking-friendly and offers an experience rivaling many private clubs at municipal pricing.', playingTips: 'Memorial Park rewards thinking players. The drivable par 4s tempt aggressive play but are well-defended. The greens have more movement than they appear, so pay attention to slope and grain.\n\nHouston humidity can make the course play longer than the yardage suggests. Take an extra club on approaches, especially in summer. The closing stretch from 13 through 18 offers birdie chances but punishes greed.', faqs: [{ question: 'Can the public play Memorial Park?', answer: 'Yes. Memorial Park is a public municipal course operated by the City of Houston with green fees typically ranging from $40 to $75.' }, { question: 'When was the Tom Doak renovation completed?', answer: 'The renovation was completed in 2019, with the course reopening in time to host the 2020 Houston Open.' }, { question: 'Does the PGA Tour play at Memorial Park?', answer: 'Yes. The Texas Children\'s Houston Open is held annually, typically in late March. It is one of the few PGA Tour events on a municipal course.' }, { question: 'Who consulted on the renovation?', answer: 'Brooks Koepka consulted alongside architect Tom Doak, helping ensure the course would challenge the world\'s best players.' }] },
    { id: 'hou-3', name: 'The Club at Carlton Woods - Fazio Course', slug: 'carlton-woods-fazio', city: 'Houston', state: 'Texas', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 2001, holes: 18, par: 72, yardage: 7296, description: 'The crown jewel of The Woodlands, Carlton Woods\' Fazio Course is routinely ranked among the best private clubs in Texas. The layout carves through dense East Texas pines with bold shaping and pristine conditioning.', highlights: ['Top-ranked Texas private club', 'Dense pine forest setting', 'Immaculate Tom Fazio design'], imageAlt: 'Carlton Woods Fazio Course through dense pine forest', history: 'The Club at Carlton Woods opened its Jack Nicklaus Signature Course in 2001 as the centerpiece of a luxury residential community in The Woodlands, north of Houston. Five years later, in 2006, the Tom Fazio Championship Course debuted, giving the club two nationally ranked layouts. The Fazio Course was built through dense East Texas pine forest on gently rolling terrain, a rarity in the Houston area.\n\nTom Fazio crafted a design that emphasizes bold shaping and strategic variety. The 7,296-yard layout features dramatic mounding, well-placed water hazards, and challenging green complexes guarded by creeks, streams, and ponds. Water comes into play on more than half the holes, demanding careful course management.\n\nCarlton Woods has hosted the LPGA\'s Chevron Championship, bringing the world\'s top women\'s players to The Woodlands. The Fazio Course is consistently ranked among the best private clubs in Texas and has earned recognition on multiple national course ranking lists.', signatureHoles: [{ hole: 3, par: 4, yardage: 445, description: 'A demanding par 4 that doglegs through the pines with water threatening the approach shot. The green complex is well-guarded by Fazio\'s trademark bunkers and a creek running along the left side.' }, { hole: 8, par: 3, yardage: 195, description: 'A stunning par 3 playing over water to a green surrounded by pine trees. Club selection is critical as the penalty for missing is severe on all sides.' }, { hole: 14, par: 5, yardage: 565, description: 'A risk-reward par 5 that tempts long hitters to reach in two. A creek crosses the fairway at a strategic distance, and the green is protected by deep bunkers.' }, { hole: 18, par: 4, yardage: 455, description: 'A strong finishing hole that demands a long, accurate drive through the pine corridor followed by a precise approach to a well-defended green with water lurking.' }], whatToExpect: 'The Fazio Course at Carlton Woods is a pristine parkland layout carved through towering East Texas pines. At 7,296 yards from the tips, it presents a serious test with water hazards on more than half the holes. The rolling terrain provides unusual elevation changes for the Houston area, and Fazio\'s bold shaping creates visually dramatic holes throughout.\n\nConditioning is immaculate year-round, befitting one of the top private clubs in Texas. The fairways are generous enough to allow aggressive play off the tee, but the green complexes demand precision.', playingTips: 'Water is the primary defense on the Fazio Course. Identify which holes allow you to challenge hazards and which demand conservative play. The par 5s offer birdie opportunities for those who manage risk wisely.\n\nThe greens feature subtle Fazio contours that can be deceiving. Pay attention to the slope from back to front and avoid being above the hole whenever possible. The pine-sheltered holes can play differently than expected as trees block wind.', faqs: [{ question: 'Can the public play Carlton Woods Fazio Course?', answer: 'No. The Club at Carlton Woods is a private club requiring membership. There is no public or resort access.' }, { question: 'How many courses are at Carlton Woods?', answer: 'Carlton Woods features two championship 18-hole courses: the Jack Nicklaus Signature Course (2001) and the Tom Fazio Championship Course (2006).' }, { question: 'Has Carlton Woods hosted professional tournaments?', answer: 'Yes. Carlton Woods has hosted the LPGA\'s Chevron Championship, one of women\'s golf\'s five major championships.' }, { question: 'What makes the Fazio Course different from the Nicklaus Course?', answer: 'The Fazio Course is generally considered the more demanding of the two, with water hazards on more than half the holes and more aggressive green complexes. The Nicklaus Course offers a slightly more open layout.' }] },
    { id: 'hou-4', name: 'Golf Club of Houston', slug: 'golf-club-houston', city: 'Houston', state: 'Texas', type: 'public', rating: 4.3, greensFee: '$100–$225', architect: 'Rees Jones', yearBuilt: 2003, holes: 18, par: 72, yardage: 7441, description: 'Formerly known as Redstone Golf Club, the Golf Club of Houston in Humble hosted the PGA Tour\'s Shell Houston Open for 17 consecutive years. This Rees Jones and David Toms co-design in unincorporated Harris County delivers a championship-caliber public experience with wide fairways, aggressive bunkering, native wetlands, and a ferocious finishing hole widely considered one of the toughest in the Houston area.', highlights: ['Hosted the PGA Tour\'s Shell Houston Open 2003–2018', 'Co-designed by Rees Jones and PGA Tour champion David Toms', '18th hole ranked among Houston\'s most demanding par 4s', 'Native wetlands and water hazards on back nine', 'Slope rating of 148 from the tips', 'Former LIV Golf Houston venue (2024)', 'Walking-friendly with forecaddie option'], imageAlt: 'Golf Club of Houston Tournament Course championship layout in Humble Texas', history: 'The Golf Club of Houston was originally established as Redstone Golf Club in 2003. Its Tournament Course, a collaboration between renowned architect Rees Jones and PGA Tour champion David Toms, was purpose-built to serve as a premier competitive venue. The club also features a second 18-hole layout — the Member Course — designed by Jim Hardy and Peter Jacobsen.\n\nThe Shell Houston Open moved to Redstone in 2002 (playing the Member Course for its first three editions before transitioning fully to the Tournament Course). The tournament remained here through 2018, giving the club a 17-year run as a PGA Tour host site. Winners during that era include Vijay Singh (who won back-to-back titles in 2004 and 2005, defeating John Daly in a playoff in 2005), Phil Mickelson, Hunter Mahan, and Matt Jones. Vijay Singh also claimed the 2004 PGA Championship just months after his Houston victory, cementing the course\'s place in that season\'s narrative.\n\nIn 2013, Fort Worth-based Escalante Golf purchased Redstone and the facility was rebranded as the Golf Club of Houston. The Houston Open departed for Memorial Park in 2020, but the club\'s profile was revived when it hosted LIV Golf Houston in June 2024, won by Carlos Ortiz.\n\nToday the Tournament Course remains open to the public. Measuring 7,441 yards from the championship tees with a slope of 148 and course rating of 76.4, it stands as one of the most legitimate championship public tests in the greater Houston market.', signatureHoles: [{ hole: 5, par: 4, yardage: 478, description: 'One of the most demanding par 4s on the front nine, this 478-yard hole requires both distance and precision. The fairway narrows significantly around the 250-yard mark — just 12 yards wide at its pinch point — making aggressive play off the tee a genuine gamble. The miss is steep and often unplayable, so a well-placed iron or fairway wood sets up a long but manageable approach.' }, { hole: 8, par: 4, yardage: 391, description: 'A mid-length par 4 made famous in PGA Tour lore: J.B. Holmes hit a 391-yard drive on this hole, setting a PGA Tour record at the time. For the rest of us, the hole plays as a genuine two-shotter requiring a precise approach to a well-guarded green. The wide fairway rewards confident driving, but the green complex demands a clean strike.' }, { hole: 14, par: 3, yardage: 219, description: 'The longest and most demanding of the four par 3s, this 219-yard hole plays over native wetlands and demands a long, high carry. Wind across southeast Texas can shift club selection by two or three sticks. Missing left typically means a drop and a stiff bogey at best. Precision and confidence are required in equal measure.' }, { hole: 15, par: 5, yardage: 573, description: 'A lengthy par 5 that becomes a serious birdie hole for long hitters who avoid the wetlands guarding the left side. A disciplined layup leaves a wedge in, but the temptation to go for the green in two is real. The 2024 LIV Golf event saw Adrian Meronk bogey this hole, ultimately costing him the title.' }, { hole: 18, par: 4, yardage: 488, description: 'Widely described as one of the most punishing finishing holes in Houston golf, this 488-yard par 4 demands two full shots to a green defended by water along the entire left side. Houstonia Magazine called it "488 yards of unadulterated terror." There is no bail-out on the approach — the combination of length, water, and a firm green surface ensures that a birdie here is a genuine achievement for any player. This hole has decided multiple Shell Houston Open championships and remains the club\'s defining test.' }], whatToExpect: 'The Tournament Course at the Golf Club of Houston is a genuine championship track that pulls no punches. Playing to 7,441 yards from the back tees with a slope of 148, it is the most demanding publicly accessible round in the Houston area. Multiple forward tee options (including sets under 6,000 yards) make it playable for a wide range of handicaps, but the course is built to test the best.\n\nThe front nine plays through more open parkland with strategic bunkering as the primary defense. Wide fairways are a Rees Jones trademark — you can find them off the tee — but the green complexes are well-guarded and demand precise wedge play. The Mini-Verde bermudagrass greens are firm, fast, and fair, though they punish approaches from the wrong side of the hole.\n\nThe back nine is where the course flexes its teeth. Native wetlands and standing water come into play repeatedly from holes 10 through 16. Holes 10, 11, and 12 ease you in before the course opens up its full arsenal: a long par 5 (hole 13, 588 yards), the brutal 219-yard 14th over wetlands, and the 573-yard 15th with water left. The finishing hole — 488 yards with water all the way down the left — delivers a final test that is genuinely feared.\n\nCourse conditions are typically excellent. Fairways are well-maintained, and the greens are consistently fast. A forecaddie is included in the higher-tier tee times, which significantly enhances pace of play and on-course guidance.', playingTips: 'Course management is the key to scoring at the Golf Club of Houston. The wide fairways are inviting, but over-aggression with driver on several holes — particularly hole 5 — leads to big numbers. On holes where the fairway narrows, consider a 3-wood or long iron to stay below the pinch point.\n\nThe greens reward approaches from below the hole. Rees Jones\'s green complexes tend to slope back-to-front and side-to-side, and putts from above the hole are treacherously fast. If you have a choice between short of the green and over the back, take the front every time.\n\nOn the back nine, give the wetland hazards significant respect. The lines of penalty areas on holes 10 through 15 are not always obvious from the tee. When in doubt, lay back to a full approach yardage rather than trying to squeeze a career drive.\n\nThe 14th is the most underrated danger hole on the course. At 219 yards over water, recreational players should consider playing to the front of the green and taking the two-putt bogey as a win, rather than gambling on a long carry that leaves a drop zone and three putts.\n\nFor the 18th, aim for the center or right side of the fairway to open up the approach angle. The water is unforgiving on the entire left portion of the hole. A par on 18 after a solid round is something to be proud of.', faqs: [{ question: 'Is the Golf Club of Houston open to the public?', answer: 'Yes. The Tournament Course is open to the public. The Member Course is private and reserved for members. Green fees for the Tournament Course range from approximately $100 to $225 depending on season and tee time, with a forecaddie included in premium tee times.' }, { question: 'What years did the Shell Houston Open take place at the Golf Club of Houston?', answer: 'The Shell Houston Open was held at the Golf Club of Houston (then Redstone Golf Club) from 2002 through 2018, a span of 17 years. The first three editions (2002–2004) were played on the Member Course; the Tournament Course took over as the full-time host from 2006 onward. The event moved to Memorial Park beginning in 2020.' }, { question: 'Who designed the Tournament Course?', answer: 'The Tournament Course was co-designed by architect Rees Jones and PGA Tour champion David Toms. Jones provided the architectural framework while Toms contributed player-side strategic input. The course opened in 2003.' }, { question: 'What is the most difficult hole at the Golf Club of Houston?', answer: 'The 18th hole — a 488-yard par 4 with water running the entire left side of the approach — is widely considered the most difficult and most dramatic hole on the course. It has decided multiple Shell Houston Open championships and has been called one of the most challenging finishing holes in the Houston area.' }, { question: 'What is the course rating and slope from the tips?', answer: 'From the championship tees, the Tournament Course plays to 7,441 yards with a course rating of 76.4 and a slope of 148, making it one of the most demanding public tracks in Texas.' }, { question: 'Has the Golf Club of Houston hosted any events besides the PGA Tour?', answer: 'Yes. In addition to 17 years as a PGA Tour venue, the Golf Club of Houston hosted the 2024 LIV Golf Houston event, which was won by Carlos Ortiz. The club has also hosted various amateur and collegiate events throughout its history.' }] },
    { id: 'hou-5', name: 'Bluejack National', slug: 'bluejack-national', city: 'Houston', state: 'Texas', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Tiger Woods (TGR Design)', yearBuilt: 2016, holes: 18, par: 72, yardage: 7345, description: 'Tiger Woods\' first U.S. course design, Bluejack National is a family-oriented club with a world-class golf course routed through towering East Texas pines. The design emphasizes playability, fun, and a 10-hole short course called "The Playgrounds."', highlights: ['Tiger Woods\' first U.S. design', 'Family-oriented luxury club', '"The Playgrounds" short course'], imageAlt: 'Bluejack National golf course designed by Tiger Woods through pine trees', history: 'Bluejack National was announced in 2014 when Tiger Woods Design was chosen to redesign an existing 18-hole course on a 767-acre property of rolling hills in Montgomery, Texas, about an hour northwest of Houston. It became the first championship-level course Tiger Woods designed in the United States.\n\nThe course opened in late 2015 with all 18 holes fully operational by 2016. Woods was deeply involved in the design, shaping a layout that emphasizes playability and fun while providing a championship test from the back tees at 7,552 yards. The property\'s natural rolling terrain and towering East Texas pines provided an ideal canvas.\n\nBluejack quickly earned recognition as one of the top residential golf communities in the country. The club features the championship course, The Playgrounds -- a 10-hole lighted short course designed for families -- and extensive resort-style amenities.', signatureHoles: [{ hole: 1, par: 4, yardage: 428, description: 'A stunning opening hole that plays downhill from an elevated tee through a corridor of pines. The dogleg left sets the tone with dramatic elevation change and strategic bunkering.' }, { hole: 8, par: 4, yardage: 318, description: 'A driveable par 4 at just 318 yards from the tips. Players who keep their tee shot left while avoiding hazards can reach the green, but the risk-reward calculation makes this one of the most exciting holes on the course.' }, { hole: 12, par: 3, yardage: 178, description: 'Often cited as the signature hole, frequently compared to the iconic 12th at Augusta National. The hole plays over water to a green defended by bunkers with towering pines framing the backdrop.' }, { hole: 18, par: 4, yardage: 465, description: 'A strong finishing hole demanding two quality shots. The fairway narrows approaching the green, with strategic bunkering creating a demanding final test.' }], whatToExpect: 'Bluejack National is a luxury residential community and private club built around Tiger Woods\' first American course design. The par-72 layout plays to 7,552 yards from the tips but offers multiple tees for all skill levels. Zoysia fairways provide firm, fast playing conditions.\n\nThe atmosphere is family-friendly and laid-back with a Texas hospitality feel. The Playgrounds short course, with lights for evening play, reflects the club\'s emphasis on fun and accessibility.', playingTips: 'Bluejack rewards accuracy more than length. The rolling terrain creates uneven lies throughout, so solid ball-striking is essential. The zoysia fairways provide excellent conditions but firm turf that can challenge players unused to the surface.\n\nThe par-3 12th is the marquee hole -- check the wind carefully before committing to club selection over the water. The driveable 8th offers exciting risk-reward but punishes errant tee shots severely.', faqs: [{ question: 'Can the public play Bluejack National?', answer: 'No. Bluejack National is a private residential community and golf club. Access is limited to members, residents, and their guests.' }, { question: 'Did Tiger Woods actually design the course?', answer: 'Yes. Tiger Woods and his TGR Design firm designed Bluejack National. It was his first championship course in the United States, and he was heavily involved throughout the process.' }, { question: 'What is The Playgrounds?', answer: 'The Playgrounds is a 10-hole lighted short course designed for families and casual play, featuring holes ranging from 45 to 120 yards.' }, { question: 'Where is Bluejack National located?', answer: 'Bluejack National is in Montgomery, Texas, approximately 50 miles northwest of downtown Houston.' }] },
    { id: 'hou-6', name: 'Champions Golf Club – Cypress Creek', slug: 'champions-cypress-creek', city: 'Houston', state: 'Texas', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Ralph Plummer', yearBuilt: 1959, holes: 18, par: 71, yardage: 7018, description: 'Co-founded by Masters champions Jackie Burke Jr. and Jimmy Demaret, Champions Golf Club is one of America\'s most historically significant private clubs. The Cypress Creek course hosted the 1967 Ryder Cup, 1969 U.S. Open, and the 2020 U.S. Women\'s Open.', highlights: ['Host of the 1967 Ryder Cup and 1969 U.S. Open', 'Co-founded by Jackie Burke Jr. and Jimmy Demaret', 'Over 70,000 trees on one of Texas\'s most storied layouts'], imageAlt: 'Towering pines framing a championship fairway at Champions Golf Club Cypress Creek in Houston', history: 'Champions Golf Club was founded in 1957 by Jackie Burke Jr. and Jimmy Demaret, two legends with five major championships between them. Ralph Plummer designed the Cypress Creek course, which opened in 1959.\n\nCypress Creek hosted the 1967 Ryder Cup, the 1969 U.S. Open won by Orville Moody, the 1993 U.S. Amateur, and the 2020 U.S. Women\'s Open. The club has been awarded additional future USGA championships.\n\nWith over 70,000 trees on the property, Champions is one of Texas\'s most densely wooded and prestigious golf venues.', signatureHoles: [{ hole: 5, par: 4, yardage: 432, description: 'A demanding par 4 through towering pines requiring both length and accuracy.' }, { hole: 9, par: 4, yardage: 448, description: 'A strong front-nine finisher climbing through a tree-lined corridor.' }, { hole: 15, par: 3, yardage: 190, description: 'A beautiful par 3 that has tested the best players in multiple USGA championships.' }, { hole: 18, par: 4, yardage: 450, description: 'A historic finishing hole that has decided multiple major championships.' }], whatToExpect: 'Champions Cypress Creek is a classic tree-lined championship course with over 70,000 trees creating tight corridors and a cathedral-like atmosphere.\n\nAt 7,018 yards with a par of 71, the course demands accuracy above all else. Conditioning is excellent, befitting a regular USGA championship venue.', playingTips: 'Accuracy is paramount. Dense trees create narrow fairways where recovery is often impossible. Play to the wide side of fairways.\n\nThe greens are well-contoured and can be firm. Land approach shots on the correct portion to avoid three-putts.', faqs: [{ question: 'Can the public play Champions Cypress Creek?', answer: 'No. Champions Golf Club is a private club.' }, { question: 'What major championships has it hosted?', answer: 'The 1967 Ryder Cup, 1969 U.S. Open, 1993 U.S. Amateur, and 2020 U.S. Women\'s Open.' }, { question: 'Who founded Champions Golf Club?', answer: 'Jackie Burke Jr. and Jimmy Demaret in 1957.' }, { question: 'How many trees are on the property?', answer: 'Over 70,000, making it one of the most densely wooded golf venues in Texas.' }] },
    { id: 'hou-7', name: 'River Oaks Country Club', slug: 'river-oaks-country-club', city: 'Houston', state: 'Texas', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Donald Ross', yearBuilt: 1922, holes: 18, par: 72, yardage: 6600, description: 'Designed by the legendary Donald Ross in 1922, River Oaks Country Club is one of the oldest and most prestigious private clubs in Texas. Ross\'s trademark crowned greens and subtle bunkering demand precise short-game touch. Subsequent renovations by Joe Finger, Rees Jones, and Tom Fazio have maintained strategic integrity.', highlights: ['Donald Ross Golden Age design from 1922', 'Renovations by Joe Finger, Rees Jones, and Tom Fazio', 'One of Houston\'s oldest and most prestigious clubs'], imageAlt: 'Donald Ross crowned green at River Oaks Country Club surrounded by mature Houston oaks', history: 'River Oaks Country Club was founded in 1923 in one of Houston\'s most exclusive neighborhoods, with Donald Ross designing the original golf course. The club was integral to the development of the River Oaks residential community, one of America\'s wealthiest neighborhoods.\n\nRoss\'s original layout established River Oaks as Houston\'s premier club. Over the decades, Joe Finger, Rees Jones, and Tom Fazio have made renovations while respecting Ross\'s design intent.\n\nNow over 100 years old, River Oaks remains one of the most prestigious and exclusive clubs in Texas.', signatureHoles: [{ hole: 3, par: 4, yardage: 420, description: 'A classic Ross par 4 with a crowned green that sheds approach shots missing the center.' }, { hole: 8, par: 3, yardage: 185, description: 'A demanding par 3 showcasing Ross\'s crowned green design philosophy.' }, { hole: 13, par: 5, yardage: 520, description: 'A strategic par 5 with mature oaks lining both sides creating a demanding corridor.' }, { hole: 18, par: 4, yardage: 430, description: 'A strong finishing par 4 through mature oaks toward the historic clubhouse.' }], whatToExpect: 'River Oaks is a classic Donald Ross parkland course framed by mature live oaks in Houston\'s most prestigious neighborhood. At 6,600 yards, it rewards accuracy and finesse over power.\n\nThe setting is elegant and understated, befitting one of Houston\'s oldest and most exclusive clubs.', playingTips: 'Ross\'s crowned greens are the primary defense. Approach shots must be precise, as misses roll off into collection areas. A reliable short game is essential.\n\nMature oaks create tight corridors. Keep the ball in play off the tee.', faqs: [{ question: 'Can the public play River Oaks Country Club?', answer: 'No. River Oaks is one of Houston\'s most exclusive private clubs.' }, { question: 'Who designed River Oaks?', answer: 'Donald Ross designed the original course in 1922-1923. Joe Finger, Rees Jones, and Tom Fazio have made subsequent renovations.' }, { question: 'How old is River Oaks Country Club?', answer: 'Founded in 1923, it is over 100 years old.' }, { question: 'What neighborhood is it in?', answer: 'The club is in the River Oaks neighborhood, one of America\'s wealthiest residential communities.' }] },
    { id: 'hou-8', name: 'BraeBurn Country Club', slug: 'braeburn-country-club', city: 'Houston', state: 'Texas', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'John Bredemus', yearBuilt: 1926, holes: 18, par: 72, yardage: 6808, description: 'Founded in 1926 with ties to golf royalty — Jackie Burke Sr. was a founder and Jimmy Demaret served as head professional. Golden Age architect John Bredemus designed the original layout, and Tripp Davis completed a nationally recognized renovation in 2022.', highlights: ['John Bredemus Golden Age design with 2022 Tripp Davis renovation', 'Historic ties to Jackie Burke Sr. and Jimmy Demaret', 'Named among top course renovations upon completion'], imageAlt: 'Renovated Bermuda greens and bunkering at BraeBurn Country Club in Houston', history: 'BraeBurn Country Club was originally founded in 1926 as Colonial Country Club on the southwestern edge of downtown Houston. The course was designed by John Bredemus, often called the Father of Texas Golf, who was one of the most influential Golden Age architects in the state. The club was renamed BraeBurn Country Club in 1931.\n\nThe club boasts remarkable connections to golf royalty. Jackie Burke Sr., father of Masters and PGA Championship winner Jackie Burke Jr., was among the club\'s founders. The legendary Jimmy Demaret, a three-time Masters champion, served as head professional at BraeBurn early in his career before going on to co-found Champions Golf Club with Jackie Burke Jr.\n\nCarlton Gipson redesigned the layout in 1991 to address flooding and modernize the course. In 2022, Tripp Davis and Associates completed a comprehensive restoration and renovation that earned national recognition, returning the course to its Golden Age roots while incorporating modern turf and drainage improvements.', signatureHoles: [{ hole: 5, par: 4, yardage: 420, description: 'A strategic par 4 that showcases the Tripp Davis renovation with restored Golden Age bunkering and a green complex that rewards precise approach play.' }, { hole: 11, par: 3, yardage: 180, description: 'A demanding par 3 over water to a well-bunkered green. The hole exemplifies Bredemus\'s original vision restored through the 2022 renovation.' }, { hole: 14, par: 5, yardage: 540, description: 'A risk-reward par 5 with strategic options off the tee. Long hitters can reach in two, but water and bunkering punish aggressive misses.' }, { hole: 18, par: 4, yardage: 435, description: 'A strong finishing hole that demands accuracy off the tee and a precise approach to a well-defended green, providing a fitting conclusion to the round.' }], whatToExpect: 'BraeBurn is a classic Houston parkland course with mature trees lining the fairways and water features integrated throughout. The 2022 Tripp Davis renovation restored Golden Age character with authentic bunkering styles while modernizing drainage and playing surfaces. At 6,808 yards from the tips, the course rewards accuracy and course management over raw distance.\n\nThe club exudes Houston golf history at every turn, from the Bredemus routing to the legacy of Demaret and Burke. Conditioning is excellent following the renovation.', playingTips: 'BraeBurn rewards players who keep the ball in the fairway. The restored bunkering is both visually impressive and strategically demanding. Missing greens in the wrong bunker makes up-and-down challenging.\n\nThe Bermuda greens are firm and can be fast, especially in summer. Approach shots that land short and run onto the putting surface are often more effective than high shots that may release off the back.', faqs: [{ question: 'Can the public play BraeBurn Country Club?', answer: 'No. BraeBurn is a private club requiring membership. There is no public access.' }, { question: 'What is BraeBurn\'s connection to Jimmy Demaret?', answer: 'Three-time Masters champion Jimmy Demaret served as head professional at BraeBurn early in his career before co-founding Champions Golf Club with Jackie Burke Jr.' }, { question: 'When was BraeBurn renovated?', answer: 'Tripp Davis and Associates completed a comprehensive renovation in 2022 that restored Golden Age character while modernizing the playing surfaces and drainage.' }, { question: 'Who originally designed BraeBurn?', answer: 'John Bredemus, known as the Father of Texas Golf, designed the original layout when the club opened in 1926 as Colonial Country Club.' }] },
    { id: 'hou-9', name: 'Whispering Pines Golf Club', slug: 'whispering-pines-golf-club', city: 'Trinity', state: 'Texas', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Chet Williams (Nicklaus Design)', yearBuilt: 2000, holes: 18, par: 72, yardage: 7480, description: 'Carved from 660 acres of East Texas pine forest, Whispering Pines is regularly ranked the number-one course in Texas. The 7,480-yard layout features zoysia fairways and Bermuda greens with tournament-caliber conditioning, bounded by creeks and lakes that force dramatic carries.', highlights: ['Consistently ranked #1 golf course in Texas', 'Nicklaus Design on 660 acres of East Texas pine forest', '7,480-yard layout with zoysia fairways'], imageAlt: 'East Texas pine-framed championship fairway at Whispering Pines Golf Club', history: 'Whispering Pines Golf Club was the vision of Corby Robertson, who commissioned Chet Williams of the Nicklaus Design Group to build the best course in Texas on a 450-acre property along Lake Livingston in Trinity, Texas. The course opened in March 2000 and was ranked number one in Texas by Golf Digest for twelve consecutive years. In 2018 Williams oversaw an extensive reconstruction.', signatureHoles: [{ hole: 14, par: 4, yardage: 430, description: 'Often called the greatest hole in Texas. Caney Creek runs along the left side feeding into Lake Livingston.' }, { hole: 15, par: 3, yardage: 178, description: 'A par 3 to a green framed by pines and water, one of the most photographed holes in Texas.' }, { hole: 7, par: 5, yardage: 575, description: 'A strategic par 5 through towering pines with water threatening on the second and third shots.' }, { hole: 18, par: 4, yardage: 445, description: 'A demanding finisher requiring two strong shots through a pine corridor.' }], whatToExpect: 'An exclusive championship course in the serene piney woods of East Texas with zoysia fairways and Champion Bermuda greens. Also features The Needler, a celebrated 9-hole par-3 course.', playingTips: 'Accuracy off the tee is paramount. Pine-lined fairways punish errant drives. On holes 14 and 15 along the water, assess wind carefully before committing.', faqs: [{ question: 'Can the public play?', answer: 'No. Exclusively private with no public access.' }, { question: 'Why is it ranked so highly?', answer: 'Golf Digest ranked it number one in Texas for twelve consecutive years.' }, { question: 'Who designed it?', answer: 'Chet Williams of the Nicklaus Design Group, opening in March 2000.' }, { question: 'What is The Needler?', answer: 'A 9-hole par-3 short course praised as one of the best in America.' }] },
  ],
  'scottsdale-arizona': [
    { id: 'sco-1', name: 'TPC Scottsdale - Stadium Course', slug: 'tpc-scottsdale-stadium', city: 'Scottsdale', state: 'Arizona', type: 'resort', rating: 4.7, greensFee: '$175–$350', architect: 'Tom Weiskopf & Jay Morrish', yearBuilt: 1986, holes: 18, par: 71, yardage: 7261, description: 'Home of the WM Phoenix Open — the most attended event in golf — TPC Scottsdale\'s Stadium Course is a desert classic. The iconic 16th hole\'s natural amphitheater is legendary, and the course delivers championship golf against a stunning Sonoran Desert backdrop.', highlights: ['WM Phoenix Open host venue', 'Iconic 16th hole stadium', 'Premier Scottsdale resort golf'], imageAlt: 'TPC Scottsdale Stadium Course 16th hole with desert mountain backdrop', history: 'TPC Scottsdale\'s Stadium Course was designed by Tom Weiskopf and Jay Morrish and opened in January 1986, commissioned by the PGA Tour to create a purpose-built tournament venue in the Sonoran Desert. The course was constructed with spectator viewing in mind, featuring natural amphitheaters and mounding.\n\nThe Stadium Course has hosted what is now the WM Phoenix Open since 1987, and the event has grown into the most attended tournament in golf, regularly drawing over 700,000 spectators. The par-3 16th hole has become the most famous hole in tournament golf, with temporary grandstands creating a 20,000-seat coliseum that has witnessed 12 aces in tournament history, including Tiger Woods\'s iconic 1997 hole-in-one.\n\nWeiskopf returned to renovate the course in 2014, modernizing the layout while preserving the spectator-friendly design. The course features Bermuda and ryegrass surfaces, deep bunkers, and the dramatic desert mountain backdrop that defines Scottsdale golf.', signatureHoles: [{ hole: 3, par: 5, yardage: 558, description: 'A risk-reward par 5 tempting long hitters to reach in two. The desert landscape frames the hole beautifully with strategic bunkering guarding the approach.' }, { hole: 7, par: 3, yardage: 215, description: 'A challenging long par 3 to a well-defended green complex. One of the quieter but more demanding holes on the course.' }, { hole: 15, par: 5, yardage: 501, description: 'A reachable par 5 setting up the dramatic finish. Water and bunkers guard the approach for those going for the green in two.' }, { hole: 16, par: 3, yardage: 163, description: 'The most famous par 3 in golf. During the WM Phoenix Open, temporary grandstands create a 20,000-seat coliseum producing an atmosphere unlike anything in sport. The hole has witnessed 12 aces in tournament history.' }], whatToExpect: 'TPC Scottsdale plays through the Sonoran Desert with views of the McDowell Mountains. At 7,261 yards with a par of 71, the course features long par 4s, deep bunkers, spectator mounding, and fast undulating greens. The desert environment means dry conditions and firm fairways.\n\nDuring peak season (January through April), the course is in pristine condition with overseeded ryegrass. Summer months bring desert heat and Bermuda grass conditions.', playingTips: 'The par 4s are generally long, so expect plenty of mid-to-long irons into greens. Accuracy off the tee is important as desert rough and native areas bordering fairways will cost strokes. The greens are fast with more slope than they appear.\n\nThe closing stretch from 15 through 18 offers scoring opportunities but also significant risk. Play within yourself and take advantage of the reachable par 5s.', faqs: [{ question: 'Can the public play TPC Scottsdale?', answer: 'Yes. TPC Scottsdale is a resort course open to the public with green fees ranging from approximately $175 to $350 depending on season.' }, { question: 'What is the 16th hole like without the grandstands?', answer: 'Without the WM Phoenix Open grandstands, the 16th is a beautiful but straightforward par 3 of about 163 yards in a natural desert amphitheater. Grandstands are temporary structures for tournament week only.' }, { question: 'When is the WM Phoenix Open?', answer: 'The WM Phoenix Open is held annually in late January or early February. It is the most attended golf tournament in the world.' }, { question: 'Who designed the Stadium Course?', answer: 'Tom Weiskopf and Jay Morrish designed the original course opening in 1986. Weiskopf completed a renovation in 2014.' }] },
    { id: 'sco-2', name: 'Whisper Rock Golf Club - Upper', slug: 'whisper-rock-upper', city: 'Scottsdale', state: 'Arizona', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 2001, holes: 18, par: 72, yardage: 7508, description: 'A PGA Tour player hangout and one of America\'s most exclusive clubs, Whisper Rock Upper is a Tom Fazio design that flows through pristine Sonoran Desert terrain. Many touring professionals call this home, and the course demands precision off the tee.', highlights: ['PGA Tour player favorite', 'Pristine desert setting', 'Among America\'s most exclusive'], imageAlt: 'Whisper Rock Golf Club desert fairway with saguaro cacti and mountains', history: 'Whisper Rock Golf Club was founded by Gregg Tryhus, who envisioned creating the ultimate pure-golf experience in the Sonoran Desert north of Scottsdale. The Lower Course, designed by Tryhus and Gary Stephenson, opened in 2001 and quickly gained a following among serious players and PGA Tour professionals seeking a no-frills golf club focused entirely on the quality of the game.\n\nThe Upper Course, designed by Tom Fazio, opened in January 2005 as the centerpiece of the 36-hole facility. Fazio crafted wider fairways and larger greens than the Lower Course, but the layout\'s length -- stretching to 7,508 yards from the tips -- and its exposure to desert winds create a formidable test. The Upper Course has been called the Pine Valley of the Southwest for its demanding shot values and pristine conditioning.\n\nWhisper Rock operates with a no-tee-time policy and has become one of the most popular home clubs for PGA Tour professionals. The world-class practice facility, relaxed atmosphere, and exceptional men\'s grill have made it a gathering place for the game\'s best players during the Arizona swing and throughout the year.', signatureHoles: [{ hole: 1, par: 4, yardage: 456, description: 'A strong opening par 4 that sets the tone for the round. The tee shot must find the fairway to set up an approach into a well-defended green on this demanding opener.' }, { hole: 6, par: 4, yardage: 487, description: 'One of the longest and most challenging par 4s on the course at 487 yards. Accuracy off the tee is essential as the desert waste areas punish errant drives, and the lengthy approach demands precise distance control.' }, { hole: 13, par: 4, yardage: 340, description: 'The signature hole at Whisper Rock Upper. Despite its modest length of 340 yards, this par 4 requires a precise tee shot from an elevated tee to the fairway below, followed by a demanding approach to a well-guarded green.' }, { hole: 18, par: 4, yardage: 465, description: 'A fitting finishing hole that demands two quality shots. The tee shot must navigate desert terrain, and the approach plays to a green complex that provides a dramatic conclusion to the round.' }], whatToExpect: 'Whisper Rock Upper delivers a premium private club experience in a strikingly beautiful Sonoran Desert setting. The Fazio design features generous fairways compared to the tighter Lower Course, but the 7,508-yard length and frequent desert winds make it a serious test. Conditioning is immaculate year-round, with fast greens and firm fairways providing a tour-quality playing surface.\n\nThe no-tee-time policy means members simply show up and play, creating a relaxed atmosphere that appeals to serious golfers. The practice facility is widely regarded as one of the best in the country, and the men\'s grill is a popular gathering spot. Forecaddies are available and recommended for first-time guests.', playingTips: 'At over 7,500 yards the Upper Course plays long, but the generous fairways reward aggressive tee shots. Keeping the ball in play is paramount, as desert waste areas are unforgiving. The wider corridors off the tee are offset by demanding approach shots to greens that often feature firm surfaces and subtle contours.\n\nWind is a major factor, especially in the afternoon. Club selection on approach shots should account for gusts that can easily move the ball one to two clubs. The greens are typically fast, so approach shots that land below the hole leave the most manageable putts.', faqs: [{ question: 'Can the public play Whisper Rock Upper?', answer: 'No. Whisper Rock is an exclusive private club with no public access. Play is limited to members and their guests.' }, { question: 'Why do so many PGA Tour pros play at Whisper Rock?', answer: 'The club was designed as a pure golf experience with world-class practice facilities, no tee times, and a relaxed atmosphere. Many touring professionals who live in Scottsdale have made it their home club.' }, { question: 'What is the difference between the Upper and Lower courses?', answer: 'The Lower Course, designed by Gregg Tryhus and Gary Stephenson, opened in 2001 and features tighter, more target-style desert golf. The Upper Course, designed by Tom Fazio and opened in 2005, has wider fairways and larger greens but plays longer at 7,508 yards.' }, { question: 'Who designed the Upper Course?', answer: 'Tom Fazio designed the Upper Course, which opened in January 2005. Fazio is one of America\'s most celebrated golf course architects.' }] },
    { id: 'sco-3', name: 'Troon North - Monument Course', slug: 'troon-north-monument', city: 'Scottsdale', state: 'Arizona', type: 'public', rating: 4.6, greensFee: '$130–$290', architect: 'Tom Weiskopf & Jay Morrish', yearBuilt: 1990, holes: 18, par: 72, yardage: 7070, description: 'Set against Pinnacle Peak in North Scottsdale, Troon North\'s Monument Course is the definitive desert golf experience. The layout weaves through massive granite boulders, towering saguaros, and native desert washes.', highlights: ['Iconic Pinnacle Peak setting', 'Definitive desert golf', 'Dramatic boulder formations on course'], imageAlt: 'Troon North Monument Course with Pinnacle Peak and desert boulders', history: 'Troon North\'s Monument Course opened in 1990, designed by Tom Weiskopf and Jay Morrish at the base of Pinnacle Peak in North Scottsdale. It was the first of two courses (the Pinnacle followed in 1996) and helped establish the standard for upscale desert golf.\n\nThe course was built around massive granite boulder formations millions of years old. Weiskopf and Morrish routed the layout to incorporate these natural features, creating holes framed by ancient rock, towering saguaro cacti, and native desert washes.\n\nTroon North became one of the first courses managed by Troon Golf, which grew into the largest golf management firm in the world. The Monument Course ranks consistently among the top public courses in Arizona.', signatureHoles: [{ hole: 2, par: 3, yardage: 172, description: 'A visually stunning par 3 framed by desert boulders and saguaros. The tee shot carries native desert wash to a well-guarded putting surface.' }, { hole: 3, par: 5, yardage: 564, description: 'The signature hole featuring a massive granite boulder formation as its centerpiece — one of the most photographed holes in Arizona golf. The fairway bends around the monument offering strategic options.' }, { hole: 5, par: 4, yardage: 470, description: 'A long demanding par 4 through a natural desert corridor with mountain views and one of the most dramatic approaches on the course.' }, { hole: 17, par: 4, yardage: 410, description: 'A strategic par 4 demanding a well-placed drive to set up an approach defended by desert boulders and native vegetation.' }], whatToExpect: 'The Monument Course is the definitive desert golf experience, weaving through massive granite boulders, towering saguaros, and native desert washes beneath Pinnacle Peak. At 7,070 yards with a slope of 145, it is a serious test. Desert terrain means target golf — balls missing the fairway find hardpan, rocks, and cacti making recovery difficult.\n\nGreens are well-conditioned with subtle desert contours. The visual drama is extraordinary, with nearly every hole framed by the Sonoran Desert landscape.', playingTips: 'Stay on the fairway. Desert golf is target golf and balls in native areas are often unplayable. Take one less club off the tee if needed. Desert washes crossing several fairways require careful distance calculation.\n\nMorning tee times are recommended to avoid afternoon desert heat. Bring plenty of water and sunscreen.', faqs: [{ question: 'Can the public play Troon North?', answer: 'Yes. Green fees range from approximately $130 to $290 depending on season, peaking during winter months.' }, { question: 'Monument or Pinnacle — which is better?', answer: 'Monument (1990) features more dramatic boulder formations. Pinnacle (1996) is considered more secluded and cohesive and is ranked slightly higher by most publications. Both are excellent.' }, { question: 'When is the best time to play?', answer: 'January through April offers comfortable temperatures and peak conditions. Summer rates are lower but desert heat can exceed 110 degrees.' }, { question: 'How did Troon North get its name?', answer: 'Named after Troon in Scotland. Troon Golf, the management company born from this property, became the largest golf management firm in the world.' }] },
    { id: 'sco-4', name: 'Grayhawk Golf Club - Raptor Course', slug: 'grayhawk-raptor', city: 'Scottsdale', state: 'Arizona', type: 'public', rating: 4.5, greensFee: '$100–$250', architect: 'Tom Fazio', yearBuilt: 1994, holes: 18, par: 72, yardage: 7135, description: 'Host of the NCAA Championship, Grayhawk\'s Raptor Course is a Tom Fazio desert design with wide fairways, bold bunkering, and one of the best post-round scenes in golf at Phil\'s Grill.', highlights: ['NCAA Championship host', 'Tom Fazio desert design', 'Famous Phil\'s Grill 19th hole'], imageAlt: 'Grayhawk Raptor Course desert layout with mountain views', history: 'Grayhawk Golf Club opened its Raptor Course in 1995, designed by Tom Fazio on the northern edge of Scottsdale, Arizona. The Raptor joined the existing Talon Course (designed by David Graham and Gary Panks) to create one of the top public golf facilities in the American Southwest.\n\nThe Raptor has hosted the NCAA Division I Men\'s and Women\'s Golf Championships from 2021 to 2023, the PGA Junior League National Championship (2016-2022), and numerous AJGA events. Tom Fazio rerouted holes 15 and 16 and shortened the 17th in a 2015 update.\n\nGrayhawk is famous for its post-round scene at Phil\'s Grill, the outdoor restaurant named after Phil Mickelson where golfers gather on the expansive patio. The facility has become a must-play destination for visiting golfers in Scottsdale.', signatureHoles: [{ hole: 3, par: 5, yardage: 553, description: 'A risk-reward par 5 that tempts long hitters to reach in two. The desert terrain frames the hole and Fazio\'s bunkering creates strategic decisions.' }, { hole: 7, par: 3, yardage: 205, description: 'A demanding par 3 with a desert wash fronting the green. Club selection is critical as the green is well-defended by bunkers.' }, { hole: 14, par: 4, yardage: 450, description: 'One of the strongest par 4s on the course requiring two precise shots through the desert landscape to a well-protected green.' }, { hole: 18, par: 4, yardage: 438, description: 'A memorable finishing hole leading players back toward the clubhouse and Phil\'s Grill. The approach to the green demands accuracy under pressure.' }], whatToExpect: 'The Raptor is a desert design with wider fairways than typical target-desert courses, reflecting Fazio\'s player-friendly philosophy. At 7,135 yards from the tips the course is a serious test but plays fairly from forward tees. Desert washes and native vegetation frame the holes without creating excessive forced carries.\n\nThe post-round scene at Phil\'s Grill is a Scottsdale institution. The facility is consistently rated among the top public golf experiences in Arizona.', playingTips: 'The desert air allows the ball to fly further than at sea level, so adjust club selection accordingly. Morning rounds are preferred during peak season as afternoon winds can be challenging.\n\nKeep the ball on maintained turf. Balls that venture into the desert waste areas are often unplayable. The greens are typically fast and true, rewarding precise approach shots.', faqs: [{ question: 'Can the public play Grayhawk Raptor?', answer: 'Yes. Grayhawk is a public facility with green fees from $100 to $250 depending on season.' }, { question: 'What is Phil\'s Grill?', answer: 'Phil\'s Grill is the famous outdoor restaurant at Grayhawk named after Phil Mickelson, known as one of the best post-round gathering spots in golf.' }, { question: 'What tournaments has Raptor hosted?', answer: 'NCAA Division I Men\'s and Women\'s Golf Championships (2021-2023), PGA Junior League National Championship (2016-2022), and numerous AJGA events.' }, { question: 'How does Raptor compare to Talon?', answer: 'Raptor is a Tom Fazio design with wider fairways and more risk-reward options. Talon by Graham and Panks is a tighter target-desert layout.' }] },
    { id: 'sco-5', name: 'We-Ko-Pa Golf Club - Saguaro Course', slug: 'we-ko-pa-saguaro', city: 'Scottsdale', state: 'Arizona', type: 'public', rating: 4.7, greensFee: '$100–$225', architect: 'Bill Coore & Ben Crenshaw', yearBuilt: 2006, holes: 18, par: 72, yardage: 7225, description: 'Built on Fort McDowell Yavapai Nation land, We-Ko-Pa\'s Saguaro Course is a Coore & Crenshaw gem set against the Four Peaks and Red Mountain. The minimalist design celebrates the raw beauty of the Sonoran Desert with wide playing corridors and creative green complexes.', highlights: ['Coore & Crenshaw minimalist desert design', 'Four Peaks mountain backdrop', 'Top-rated public course in Arizona'], imageAlt: 'We-Ko-Pa Saguaro Course with Four Peaks mountain backdrop', history: 'We-Ko-Pa Golf Club is owned and operated by the Fort McDowell Yavapai Nation, whose reservation lies northeast of Scottsdale along the Verde River. The name We-Ko-Pa comes from the Yavapai word for Four Peaks, the distinctive mountain formation that serves as a dramatic backdrop to the golf courses. The first course, Cholla, was designed by Scott Miller and opened in 2001.\n\nThe Saguaro Course followed in 2006, designed by the acclaimed team of Bill Coore and Ben Crenshaw. True to their minimalist philosophy, Coore and Crenshaw routed the course through the natural desert terrain, finding holes in the landscape rather than imposing them. The design preserved thousands of native saguaro cacti, palo verde trees, and other desert vegetation, earning recognition from the ASGCA for its sensitive treatment of cultural resources and habitat.\n\nSaguaro quickly earned acclaim as one of the finest public-access courses in the American Southwest. It has been ranked the number one public course in Arizona by Golf Digest and consistently appears among the top casino courses in the country.', signatureHoles: [{ hole: 1, par: 4, yardage: 469, description: 'A strong opening par 4 that introduces the Coore and Crenshaw design philosophy. The wide fairway allows multiple angles off the tee, but the approach must be precise to find a green framed by desert terrain and mountain views.' }, { hole: 2, par: 4, yardage: 336, description: 'A short, drivable par 4 at just 336 yards from the back tees. The aggressive line off the tee is rewarded but well-defended, while the conservative play leaves a wedge to a receptive green.' }, { hole: 4, par: 5, yardage: 631, description: 'A massive par 5 stretching to 631 yards, making it one of the longest holes in Arizona public golf. Three well-struck shots are required to reach the green, with desert waste areas threatening offline shots throughout.' }, { hole: 17, par: 3, yardage: 178, description: 'A beautiful par 3 with the Four Peaks mountains providing a stunning backdrop. The green complex features the creative contours and natural surrounds that define the Coore and Crenshaw design.' }], whatToExpect: 'The Saguaro Course offers a minimalist desert golf experience that feels entirely natural. Coore and Crenshaw\'s routing flows through pristine Sonoran Desert terrain with wide playing corridors that allow multiple strategies off the tee. The Four Peaks and Red Mountain backdrops create some of the most photogenic golf settings in Arizona.\n\nThe course features meaningful elevation changes that create interesting stances and sightlines. While the wide fairways are forgiving off the tee, the green complexes are creative and demand precise approach shots.', playingTips: 'The wide fairways invite aggressive tee shots, but positioning matters more than distance. Many holes offer a safe side and a dangerous side, with the better angle into the green rewarding those who challenge the tighter line.\n\nThe desert rough is unforgiving -- once a ball leaves the maintained turf, it is often lost. Play conservatively when the desert encroaches on the fairway edges. The greens have more movement than they initially appear, so take time to read the subtle contours before putting.', faqs: [{ question: 'Can anyone play We-Ko-Pa Saguaro?', answer: 'Yes. We-Ko-Pa is a public-access facility open to all golfers. Green fees typically range from $100 to $225 depending on the season, with peak rates during the winter months.' }, { question: 'What is the difference between the Saguaro and Cholla courses?', answer: 'Saguaro, designed by Coore and Crenshaw, is a minimalist design with wider corridors and a more natural feel. Cholla, designed by Scott Miller, is a more traditional target-desert layout with more forced carries over desert terrain.' }, { question: 'Is the Saguaro Course walkable?', answer: 'The course was designed with the walking golfer in mind, and the routing moves naturally from green to tee. However, the elevation changes can make it a moderately strenuous walk, especially in warm weather.' }, { question: 'What does We-Ko-Pa mean?', answer: 'We-Ko-Pa comes from the Yavapai word for Four Peaks, the distinctive mountain formation visible throughout the course. The facility is owned by the Fort McDowell Yavapai Nation.' }] },
    { id: 'sco-6', name: 'Silverleaf Club', slug: 'silverleaf-club', city: 'Scottsdale', state: 'Arizona', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Tom Weiskopf', yearBuilt: 2002, holes: 18, par: 72, yardage: 7322, description: 'One of the most exclusive desert clubs in Arizona, Silverleaf is a Tom Weiskopf masterwork carved through pristine Sonoran Desert with dramatic saguaro-studded terrain. The 7,322-yard layout features dramatic elevation changes and impeccable conditioning year-round.', highlights: ['Ultra-exclusive Scottsdale private club', 'Tom Weiskopf desert masterwork', 'Pristine Sonoran Desert setting'], imageAlt: 'Silverleaf Club desert fairway with saguaro cacti and mountain views in Scottsdale', history: 'Silverleaf Club opened in 2002 as the centerpiece of the ultra-exclusive Silverleaf residential community at the base of the McDowell Mountains in north Scottsdale. The community was developed by DMB Associates, and 1973 Open Champion Tom Weiskopf was chosen to design a course worthy of the spectacular high-desert setting.\n\nWeiskopf crafted a par-72 layout stretching to 7,322 yards that flows naturally through the Sonoran Desert landscape, incorporating dramatic elevation changes, boulder outcroppings, and towering saguaro cacti into a design that feels both challenging and organic. The course earned immediate recognition and established Silverleaf as one of the premier private clubs in the American Southwest.\n\nWeiskopf passed away in August 2022 at age 79, but Silverleaf stands as one of his finest works. The club has maintained its position among the top-ranked courses in Arizona, known for impeccable conditioning, a modern clubhouse experience, and a membership that values privacy and exclusivity.', signatureHoles: [{ hole: 4, par: 4, yardage: 455, description: 'A challenging par 4 that plays through classic Sonoran Desert terrain. The elevated tee provides sweeping views, but the approach requires precision to find a green protected by desert wash and Weiskopf\'s strategic bunkering.' }, { hole: 11, par: 3, yardage: 205, description: 'One of only three par 3s on the course, this hole features the rotating tee concept that Weiskopf employed at Silverleaf. Multiple tee positions create different angles and yardages, keeping the hole fresh round after round.' }, { hole: 14, par: 5, yardage: 575, description: 'A dramatic par 5 on the back nine that traverses hilly terrain with desert and water hazards in play. The risk-reward second shot tempts long hitters but punishes aggression with desert waste areas.' }, { hole: 18, par: 4, yardage: 445, description: 'A strong finishing par 4 that demands two precise shots. The approach plays to a well-defended green with the McDowell Mountains providing a stunning backdrop to close the round.' }], whatToExpect: 'Silverleaf delivers one of the most refined private golf experiences in the Southwest. The Weiskopf design features wide, flowing fairways with elevated tees that provide panoramic desert views and clear sight lines. The back nine is particularly dramatic, traversing hills and incorporating water features alongside classic desert terrain.\n\nConditioning is exceptional year-round, and the experience extends beyond golf to a modern clubhouse with first-class dining and amenities. The club is known for its personalized locker room experience, with members finding their name and preferences ready upon arrival.', playingTips: 'The greens at Silverleaf are subtly contoured and can be difficult to read. Pay close attention to the slope of the surrounding terrain for clues on break direction. The fairways are wide and reward confident tee shots, but approach shots must be precise to avoid Weiskopf\'s strategic bunkers.\n\nThe back nine plays significantly hillier than the front, so be prepared for uneven lies and uphill approaches. Forced carries over desert wash are a factor on several holes. Wind can pick up in the afternoon, affecting club selection by one to two clubs.', faqs: [{ question: 'Can the public play Silverleaf Club?', answer: 'No. Silverleaf is an ultra-exclusive private club accessible only to members and their guests. There is no public play or resort access.' }, { question: 'Who designed Silverleaf Club?', answer: 'Tom Weiskopf, the 1973 Open Champion who became one of the most respected golf course architects of his era, designed the course. It opened in 2002.' }, { question: 'What makes Silverleaf unique among Scottsdale courses?', answer: 'Silverleaf features only three par 3s and three par 5s, with rotating tee positions on the short holes that create different playing angles each round. The course integrates seamlessly with the Sonoran Desert and McDowell Mountain landscape.' }, { question: 'What is the course rating from the back tees?', answer: 'From the Silver (back) tees at 7,267 yards, the course rating is 74.7 with a slope of 149, making it one of the more demanding layouts in the Scottsdale area.' }] },
    { id: 'sco-7', name: 'SunRidge Canyon Golf Club', slug: 'sunridge-canyon', city: 'Scottsdale', state: 'Arizona', type: 'public', rating: 4.3, greensFee: '$75–$180', architect: 'Keith Foster', yearBuilt: 1996, holes: 18, par: 71, yardage: 6823, description: 'A Keith Foster design in Fountain Hills, SunRidge Canyon is famous for its dramatic par-3 finishing stretch known as the "Wicked Six." The course features 200-foot elevation changes and panoramic views of the McDowell Mountains and Verde River Valley.', highlights: ['Famous "Wicked Six" finishing stretch', '200-foot elevation changes', 'McDowell Mountain and Verde River views'], imageAlt: 'SunRidge Canyon dramatic desert par 3 with McDowell Mountain backdrop', history: 'SunRidge Canyon Golf Club opened in 1996 in Fountain Hills, Arizona, designed by Keith Foster through rugged Sonoran Desert terrain with 200-foot elevation changes and the McDowell Mountains as backdrop.\n\nThe course is famous for its "Wicked Six" finishing stretch beginning at the 13th hole, featuring some of the most visually intimidating holes in Arizona desert golf.\n\nSunRidge Canyon has been consistently rated among the top public courses in the Phoenix-Scottsdale area.', signatureHoles: [{ hole: 13, par: 3, yardage: 170, description: 'The start of the Wicked Six, playing across a deep canyon to a green perched on the opposite ridge.' }, { hole: 15, par: 4, yardage: 395, description: 'A dramatic Wicked Six par 4 through a narrow canyon corridor with a carry over a wash.' }, { hole: 17, par: 3, yardage: 160, description: 'A stunning par 3 with a massive elevation drop to the green far below.' }, { hole: 18, par: 5, yardage: 520, description: 'A dramatic finishing par 5 concluding the Wicked Six with elevation change and risk-reward options.' }], whatToExpect: 'SunRidge Canyon offers dramatic desert golf with 200-foot elevation changes creating stunning vistas of the McDowell Mountains and Verde River Valley.\n\nAt 6,823 yards with a par of 71, the Wicked Six finishing stretch is one of the most memorable in Arizona golf.', playingTips: 'Elevation changes dramatically affect club selection. Downhill holes play shorter, uphill approaches need extra club. The thin desert air adds distance.\n\nAvoid natural desert hazards. Play conservatively on the Wicked Six until you learn the holes.', faqs: [{ question: 'Can the public play SunRidge Canyon?', answer: 'Yes. Green fees range from $75 to $180 depending on season.' }, { question: 'What is the Wicked Six?', answer: 'The final six holes (13-18), known for dramatic canyon settings and difficulty.' }, { question: 'When is the best time to play?', answer: 'October through April. Summer temperatures exceed 110 degrees but rates are much lower.' }] },
    { id: 'sco-8', name: 'Scottsdale National Golf Club', slug: 'scottsdale-national', city: 'Scottsdale', state: 'Arizona', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Tom Fazio / David McLay Kidd / Bobby Weed', yearBuilt: 2015, holes: 18, par: 72, yardage: 7301, description: 'A modern ultra-private club offering three distinct 12-hole courses designed by three different architects — including a David McLay Kidd links-style layout and a Tom Fazio desert parkland design. The innovative format keeps rounds to around 2.5 hours.', highlights: ['Three 12-hole courses by three architects', 'Innovative 12-hole round format', 'Modern ultra-private desert club'], imageAlt: 'Scottsdale National Golf Club desert links course at sunset', history: 'The land that became Scottsdale National has roots as a cattle ranch under the Brown family, who ran a 44,000-acre operation through the mid-20th century. In 1995, lightning ignited the Rio Fire on Fraesfield Mountain, scarring the landscape. GoDaddy founder Bob Parsons acquired the property in 2013 for $600,000 when it was called "The Golf Club of Scottsdale." Parsons has since invested approximately $250 million in redevelopment.\n\nThe Mine Shaft Course (original 18 holes) was designed by Jay Morrish and Dick Bailey and opened in 2003. After Parsons acquired the property, he commissioned Jackson Kahn Golf Course Design (Tim Jackson, David Kahn, Scott Hoffman) to build 27 additional holes. The Other Course and the all-par-3 Bad Little Nine opened in October 2016 after a 15-month construction timeline. Golf Club Atlas described the commission as a career-defining opportunity for an emerging firm — analogous to Mike Keiser commissioning an unknown David McLay Kidd for Bandon Dunes.\n\nThe 700-acre property is surrounded by public wilderness preserve on three sides, guaranteeing unobstructed Sonoran Desert and mountain views in perpetuity.', signatureHoles: [{ hole: 15, par: 0, yardage: 0, description: 'Mine Shaft Hole 15: features a 13-foot-deep bunker lined with reclaimed wood planks from the original Pabst Brewery in Milwaukee (1844–1996). Recovery from this bunker is described as nearly impossible. The surrounding hole plays as one of the most dramatic on the Mine Shaft routing.' }, { hole: 16, par: 3, yardage: 185, description: 'Mine Shaft Hole 16: elevated on Fraesfield Mountain with panoramic views of the McDowell Mountains and Four Peaks. One of the most spectacular tee shots in the desert Southwest.' }, { hole: 5, par: 5, yardage: 475, description: 'Other Course Hole 5: features a 21,287-square-foot green — large enough to fit the Bad Little Nine\'s 9th hole green 21 times, with nine feet of elevation change across its surface. Daily pin positions create an entirely different strategic picture.' }], whatToExpect: 'Scottsdale National offers three distinct courses: the Mine Shaft (18 holes, target-style desert, 7,579 yards, slope 148), the Other Course (18 holes, links-inspired with dormant Bermuda fairways, 7,165 yards), and the Bad Little Nine (all-par-3, 972 yards total). No tee times are ever required — the intentionally capped membership means the courses are almost always uncrowded.\n\nThe Other Course rewards patience and course management. Wide fairways invite aggression, but the massive contoured greens punish approach shots to the wrong quadrant. Study pin positions before each round — they fundamentally change the strategic play.\n\nThe Bad Little Nine is not a warm-up. The $1,000 "Challenge Day" prize (Fridays, most diabolical pins) has never been claimed since 2016. Walking with a caddie is the standard experience.', playingTips: 'The Mine Shaft demands accuracy from the tips (slope 148, rating 75.1). The 13-foot-deep Pabst Brewery bunker on hole 15 is effectively unplayable — stay out of it at all costs.\n\nThe Other Course: use your caddie. The green complexes are massive and highly variable. Caddie reads are essential, especially on holes 4 (punchbowl), 5 (21,287 sq ft), and 8 (gull-wing).\n\nThe Bad Little Nine: treat it as a serious test. Club selection on holes under 100 yards is a trap — the contoured greens and trench bunkers are unforgiving regardless of distance. On Challenge Fridays, the pin positions are specifically engineered to prevent par.\n\nPlay the Other Course in the morning — the dormant Bermuda fairways catch early light dramatically, and the ground game is most effective in cooler morning conditions.', faqs: [{ question: 'Who owns and designed Scottsdale National?', answer: 'Bob Parsons (GoDaddy founder) has owned the property since 2013, investing approximately $250 million. The Mine Shaft Course was designed by Jay Morrish and Dick Bailey (2003). The Other Course and Bad Little Nine were designed by Jackson Kahn Golf Course Design and opened in 2016.' }, { question: 'How do I get to play Scottsdale National?', answer: 'Three ways: as a member, as a guest of a member, or by applying for "The Xperience" — a 72-hour immersive program that includes unlimited play, villa accommodations, dining, a PXG fitting, and is the formal gateway to membership consideration.' }, { question: 'What is the Bad Little Nine?', answer: 'An all-par-3 nine-hole course (972 yards total) with extremely contoured greens and trench-style bunkers. A $1,000 prize is offered every Friday ("Challenge Day") to any golfer who breaks par — no one has claimed it since the course opened in 2016.' }, { question: 'Are tee times required?', answer: 'No. The capped membership ensures the courses are almost always uncrowded. Members and guests show up and play — no tee time booking is ever required.' }]},
    { id: 'sco-9', name: 'Boulders Resort - South Course', slug: 'boulders-south', city: 'Scottsdale', state: 'Arizona', type: 'resort', rating: 4.4, greensFee: '$100–$225', architect: 'Jay Morrish', yearBuilt: 1984, holes: 18, par: 71, yardage: 6726, description: 'Set among the iconic 12-million-year-old boulder formations of Black Mountain, the Boulders South Course is a Jay Morrish design that defines desert golf in Arizona. The dramatic rock outcroppings frame many holes, creating some of the most photographed shots in American golf.', highlights: ['Iconic ancient boulder formations', 'Jay Morrish desert design classic', 'Among the most photographed courses in Arizona'], imageAlt: 'Boulders South Course green framed by ancient desert boulder formations', history: 'The Boulders story began with a groundbreaking on September 8, 1982, in the Sonoran Desert foothills near Carefree, Arizona. The original 18 holes, designed by Jay Morrish (with Gary Panks), opened January 23, 1984. The resort opened in January 1985. Expansion through 1991 brought the facility to 36 holes (North and South courses). The property has passed through multiple luxury brands: Wyndham International (1998), Blackstone/LXR (2005), Waldorf Astoria (2009), and Hilton Curio under Crestview Management (2015). Troon Golf now manages both courses.\n\nIn January 2023, the North Course was converted to private members-only, making the South Course the only publicly accessible layout. Both courses received full bunker renovations in 2021; the South Course greens were renovated in 2022 and par-3 tee boxes leveled in 2023.\n\nThe ancient granite boulder formations that define the property are estimated at 12 million years old — the resort\'s tagline: "Twelve Million Years in the Making."', signatureHoles: [{ hole: 5, par: 5, yardage: 545, description: 'The signature hole of the entire Boulders resort. Players aim toward the massive "Boulder Pile" — a prehistoric granite formation rising approximately 200 feet (six stories) above the playing surface. The green is tucked among these towering formations. Features a split fairway and uphill approach; reachable in two for long hitters, but laying up to a comfortable wedge distance is smarter for most.' }, { hole: 7, par: 3, yardage: 187, description: 'Features "Rosie\'s Rock" — a distinctive boulder formation near the tee box named for resort founder Rusty Lyon. The elevated tee has a boulder curling directly around the teeing ground. The tiered green is protected by bunkers and cactus hazards. One of the most photogenic holes in Arizona desert golf.' }, { hole: 1, par: 4, yardage: 421, description: 'Sets the tone immediately with a 40-foot-tall boulder formation as backdrop. Boulders line the left side — errant pulls are penalized. The elevated tee gives a panoramic desert view ahead.' }], whatToExpect: 'The South Course threads through and around ancient granite boulder formations estimated at 12 million years old. Saguaro cacti, native desert vegetation, and the towering rock formations frame virtually every hole. Many reviewers consider it even more scenic than the North Course.\n\nThe course plays to par 71 at 6,726 yards from the blues (slope 140). Bentgrass greens (renovated 2022) are firm and fast. The desert rough — rocks, cacti, hard-packed sand — means a missed fairway is often a lost ball. Five tee sets spanning over 2,000 yards of difference make it accessible at all levels.\n\nWildlife encounters (bobcats, coyotes, javelinas, rabbits) are common. Peak-season (winter) rates reach approximately $285; summer rates drop to $55–75.', playingTips: 'Accuracy over distance on every hole. Desert rough is essentially a lost ball — keeping the ball on maintained turf is far more important than extra yards.\n\nFrom the back tees, several holes require forced carries over natural desert washes. Know your carry distances honestly and play forward tees if in doubt.\n\nHole 5 (signature par 5): the uphill approach into the Boulder Pile requires precise distance control. Laying up to a wedge distance is the percentage play.\n\nHole 12 (321 yards, par 4) is a legitimate birdie or eagle opportunity — consider a long iron or hybrid off the tee to find the green.\n\nDesert air and firm conditions make the ball fly farther and roll more. Adjust club selection accordingly, especially on the par 3s.\n\nPlay early morning or late afternoon for best light on the boulder formations and most comfortable temperatures.', faqs: [{ question: 'Can the public play the Boulders South Course?', answer: 'Yes. The South Course is open to resort guests and daily-fee players. The North Course was converted to private members-only in January 2023.' }, { question: 'What are the boulder formations?', answer: 'Ancient granite formations estimated at 12 million years old. They rise up to 200 feet (six stories) above the playing surface and frame many holes, particularly the signature 5th.' }, { question: 'Who designed the Boulders courses?', answer: 'Jay Morrish (with Gary Panks). The original 18 opened in 1984, with expansion to 36 holes completed by 1991. Morrish passed away in 2015.' }, { question: 'What does a round cost?', answer: 'Peak winter season rates reach approximately $285 including cart. Summer rates drop significantly to $55–75. Cart and GPS are included.' }]},
  ],
  'phoenix-arizona': [
    { id: 'phx-1', name: 'Papago Golf Course', slug: 'papago-golf-course', city: 'Phoenix', state: 'Arizona', type: 'public', rating: 4.3, greensFee: '$30–$70', architect: 'William F. Bell', yearBuilt: 1963, holes: 18, par: 72, yardage: 7068, description: 'Phoenix\'s beloved municipal gem, Papago sits at the base of the iconic Papago Buttes and has been a favorite of locals and touring professionals for decades. The mature desert layout offers outstanding value and an unforgettable setting.', highlights: ['Iconic Papago Buttes setting', 'Best municipal course in Arizona', 'Incredible value for the quality'], imageAlt: 'Papago Golf Course with Papago Buttes in Phoenix', history: 'Papago Golf Course opened in 1963, designed by William F. "Billy" Bell Jr. — the same architect who designed Torrey Pines South Course in San Diego. The City of Phoenix owns and operates the facility at the base of the iconic Papago Buttes in Papago Park, just two miles from Sky Harbor Airport.\n\nA $5.8 million renovation was completed in December 2008, led by Billy Fuller (a former Augusta National superintendent). The project removed 400 trees to restore original sightlines toward the Buttes, Camelback Mountain, and downtown Phoenix; rebuilt all greens to USGA specs with Mini-Verde bermuda; repositioned 12 fairway bunkers to challenge modern distances; and stretched championship tees to 7,333 yards.\n\nSince 2018, Papago has served as home course for Arizona State University golf — one of the most successful collegiate programs in NCAA history. The course hosted the 1971 U.S. Amateur Public Links Championship and handles roughly 100,000 rounds per year. Sports Illustrated rated it 9.5/10.', signatureHoles: [{ hole: 11, par: 3, yardage: 187, description: 'The signature hole — plays uphill and typically into the prevailing wind, with a water hazard guarding the green. Set against the red sandstone Papago Buttes (6–15 million years old), it is the most visually memorable shot on the course. Always take one extra club.' }, { hole: 18, par: 4, yardage: 464, description: 'A bruising uphill closer that demands both length off the tee and accuracy on the approach. Part of a punishing 16-17-18 finishing stretch that can turn a good round sour. Play for the center of the green and take your par.' }, { hole: 8, par: 3, yardage: 253, description: 'One of the toughest scoring holes — 253 yards from the tips. A deep bunker guards the right side; favor the left for a safer angle. One of the longest par 3s on any municipal course in Arizona.' }], whatToExpect: 'Unlike the target-style desert courses dominating Phoenix/Scottsdale, Papago is a parkland layout with tree-lined fairways and legitimate rough — misses stay recoverable rather than disappearing into desert waste. The gentle terrain through Papago Park makes it one of the most walkable courses in the area.\n\nViews of the red sandstone Papago Buttes, Camelback Mountain, and the Phoenix skyline surround the round. Five sets of tees range from 5,400 to 7,333 yards. Greens are Mini-Verde bermuda rebuilt to USGA specs — fast and true.\n\nThe course is honest and straightforward — everything is in front of you. Wide fairways and strategic bunkering reward course management over heroics. Pricing varies by season; peak winter rates can exceed $100, but a Phoenix City Golf Card offers significant discounts.', playingTips: 'The closing stretch (16-17-18) is brutal. Play conservatively through these holes — center of greens, take your pars.\n\nHole 11: always take one extra club. It plays uphill and into the wind.\n\nHole 8: favor the left side to avoid the deep right bunker. The 253-yard distance from the tips makes par a great score.\n\nThe course plays honestly — there are no hidden hazards or blind shots. Trust what you see and focus on course management.\n\nOff-fairway lies can be rocky. Carry extra balls and protect your club soles.\n\nBook early in winter — peak-season tee times at this beloved muni fill fast.', faqs: [{ question: 'Who designed Papago?', answer: 'William F. Bell Jr., the same architect behind Torrey Pines South Course. Billy Fuller (former Augusta National superintendent) led a $5.8 million renovation completed in 2008.' }, { question: 'Why is Papago so popular?', answer: 'Consistently ranked among the top 5 municipal courses in the US. The Papago Buttes setting, excellent conditioning for a high-volume muni, and outstanding value make it a Phoenix favorite.' }, { question: 'Is it the ASU home course?', answer: 'Yes. Arizona State University men\\\'s and women\\\'s golf teams have called Papago home since 2018, with The Thunderbirds Golf Complex practice facility on-site.' }, { question: 'How long can it play?', answer: 'Up to 7,333 yards from the championship tees after the 2008 renovation. Five tee sets range down to approximately 5,400 yards.' }]},
    { id: 'phx-2', name: 'Arizona Biltmore Golf Club - Links', slug: 'biltmore-links', city: 'Phoenix', state: 'Arizona', type: 'resort', rating: 4.4, greensFee: '$80–$180', architect: 'Bill Johnston', yearBuilt: 1928, holes: 18, par: 71, yardage: 6430, description: 'Adjacent to the legendary Arizona Biltmore resort, this historic layout has hosted presidents and celebrities for nearly a century. The classic design offers a resort golf experience steeped in Old Phoenix charm.', highlights: ['Historic resort dating to 1928', 'Presidential golf history', 'Classic Arizona resort golf'], imageAlt: 'Arizona Biltmore Golf Club Links course with historic resort', history: 'The Arizona Biltmore Golf Club traces to the legendary Arizona Biltmore Hotel, which opened February 23, 1929 — designed by Albert Chase McArthur with significant influence from Frank Lloyd Wright, who consulted for four months on the distinctive "Biltmore Block" textile-block construction.\n\nThe Links Course was designed by Bill Johnston and opened in 1979 as the second course at the resort. Every U.S. President from Eisenhower onward reportedly played the Biltmore courses. Ronald Reagan honeymooned here in 1952; Clark Gable and Carole Lombard were frequent guests; Marilyn Monroe sunbathed at the Catalina Pool; and the Wright Bar is where the Tequila Sunrise cocktail was invented in the late 1930s.\n\nThe sister Estates Course (formerly Adobe) underwent a complete Tom Lehman redesign reopening in 2023–2024. The resort sold for $705 million in 2024 to Henderson Park and Pyramid Global Hospitality.', signatureHoles: [{ hole: 15, par: 3, yardage: 170, description: 'The crown jewel — an 80-foot elevation drop from the tee to the green below, offering some of the finest views in all of Phoenix golf. Club down significantly; the dramatic drop makes it play much shorter than the card distance. One of the most photographed holes in Arizona.' }, { hole: 12, par: 4, yardage: 385, description: 'Features a large pond fronting a semi-island green. The approach shot must carry the water — bailing out short means a wet ball. One of the more nerve-wracking shots on the course.' }, { hole: 17, par: 4, yardage: 451, description: 'An elevated tee reveals a sweeping view of the Phoenix skyline. A long, demanding par 4 that tests both power and precision on the back nine.' }], whatToExpect: 'The Links Course plays through the Biltmore Estates neighborhood near the Phoenix Mountain Preserve. Despite its name, this is a lush resort-style layout with tree-lined fairways, lakes, arroyos, and significant elevation changes — especially on the back nine which climbs into the mountainside.\n\nThe front nine is tighter and more confined, weaving among estate homes and water features. The back nine opens up with dramatic elevation changes and panoramic views of the Phoenix skyline and desert mountains.\n\nAt 6,300 yards with a slope of only 124 from the tips, this is not a monster. But tight corridors, water hazards, and elevation changes provide the challenge. The resort ambiance and historical significance make this a must-play for golf history enthusiasts visiting Phoenix.', playingTips: 'Club selection on downhill holes is everything. The back nine elevation changes, especially the signature 15th, play 15–20 yards shorter than card distance. Take less club and trust the yardage adjustment.\n\nThe front nine is tight with homes and OB lining both sides. Accuracy matters more than distance — consider fairway wood or long iron on narrow holes.\n\nHole 12: commit to the approach over the water to the semi-island green. Indecision leads to a wet ball.\n\nMultiple holes feature sharp doglegs — study the cart GPS before each tee shot. Cutting corners without knowing the layout leads to trouble.\n\nBermuda greens in the afternoon can be grainy — factor that into your reads.', faqs: [{ question: 'What makes Arizona Biltmore historically significant?', answer: 'The resort opened in 1929 with Frank Lloyd Wright consultation and has hosted every US President since Eisenhower. Clark Gable, Marilyn Monroe, and Frank Sinatra were regulars. The Tequila Sunrise was invented at the Wright Bar.' }, { question: 'Who designed the Links Course?', answer: 'Bill Johnston, opening in 1979. The original Estates Course dates to 1928–29 and was completely redesigned by Tom Lehman in 2023.' }, { question: 'Can the public play?', answer: 'Yes. Both courses are open to resort guests and daily-fee players.' }, { question: 'What is the signature hole?', answer: 'Hole 15 — a par 3 with an 80-foot elevation drop offering panoramic Phoenix views. One of the most photographed holes in Arizona golf.' }]},
    { id: 'phx-3', name: 'Ak-Chin Southern Dunes', slug: 'ak-chin-southern-dunes', city: 'Phoenix', state: 'Arizona', type: 'public', rating: 4.6, greensFee: '$60–$150', architect: 'Brian Curley & Lee Schmidt', yearBuilt: 2002, holes: 18, par: 72, yardage: 7546, description: 'A links-style desert course south of Phoenix, Southern Dunes features dramatic dune formations, wide fairways, and a windswept feel that\'s unique in the Valley of the Sun. Consistently ranked among Arizona\'s top public courses.', highlights: ['Links-style desert layout', 'Dramatic dune formations', 'Top-ranked Arizona public course'], imageAlt: 'Ak-Chin Southern Dunes links-style desert course near Phoenix', history: 'Ak-Chin Southern Dunes opened in 2002, designed by the Schmidt-Curley Design firm (Lee Schmidt and Brian Curley) in collaboration with PGA Tour legend Fred Couples. Both Schmidt and Curley are former Pete Dye associates. The site was originally dead flat; massive earth-moving created the towering mounds, valleys, and deep sand-faced bunkers that give the course its character.\n\nThe land holds deep significance for the Ak-Chin Indian Community: it was part of their original reservation established in May 1912 but removed by Presidential Executive Order later that year. The community purchased the course in 2010, bringing the land back under tribal stewardship after nearly a century. Today it operates as a daily-fee public course managed by Troon, adjacent to Harrah\\\'s Ak-Chin Casino Resort.\n\nA 2014 renovation enhanced player-friendliness while preserving the championship challenge. The course has hosted U.S. Open qualifying, the Southwest Section PGA Championship, and Korn Ferry Tour Q-School. Golf Magazine has ranked it among its Top 100 Courses You Can Play.', signatureHoles: [{ hole: 10, par: 4, yardage: 412, description: 'The signature hole — "By the Pond." A dogleg right alongside a pond, leading to a bunker-laden approach. Each hole has its O\\\'odham (Ak-Chin) name carved into iron at the tee box. The tee shot demands a critical decision about how much of the dogleg to cut.' }, { hole: 14, par: 4, yardage: 323, description: 'The shortest par 4 but contains 16 bunkers with more sand visible than grass — an island of fairway amid the dunes. Despite the short yardage, scores here are often higher than expected. A classic Schmidt-Curley risk-reward design.' }, { hole: 13, par: 5, yardage: 606, description: 'A steady rightward bend with uphill terrain that makes this hole play significantly longer than its already considerable 606 yards. Reaching in two is a true challenge — course management is essential.' }], whatToExpect: 'Southern Dunes is an Australian Sand Belt-style course transplanted into the Sonoran Desert — links-inspired with firm, fast fairways that reward the ground game. The feel is more Melbourne Sand Belt than typical Arizona target golf. Fairways reach 70 yards wide in places, but the 129 bunkers (averaging 7 per hole) make sand avoidance the primary strategic concern.\n\nThe front nine eases in with a links-style open character; the back nine introduces more demanding challenges immediately. Wind is a significant factor on exposed sections. Walking is practical — unusual for Arizona resort courses.\n\nGreenside play is where the course bites hardest. Putting surfaces are consistent but tricky, and the bump-and-run is often smarter than a lofted chip on the firm turf.', playingTips: 'Stay out of the bunkers. With 129 of them, sand avoidance is the single most important strategic consideration. Find the beach and your scorecard explodes.\n\nPlay away from the pin on approach shots. The fat part of the green beats a greenside bunker shot every time.\n\nUse your putter off the green. The firm, links-style conditions make the putter viable well off the putting surface — chip shots often run unpredictably on tight lies.\n\nRespect the wind. The open terrain means wind is a significant factor. Club selection should always account for gusts.\n\nChoose the right tees. The tips (76.5/142) are a monster. The white tees at roughly 6,000 yards offer an excellent experience for mid-handicappers.', faqs: [{ question: 'Who designed Ak-Chin Southern Dunes?', answer: 'Schmidt-Curley Design (Lee Schmidt and Brian Curley) in collaboration with Fred Couples. Both Schmidt and Curley are former Pete Dye associates. The course opened in 2002.' }, { question: 'What is the playing style?', answer: 'Australian Sand Belt-inspired links golf in the Sonoran Desert. Firm, fast fairways reward the ground game. 129 bunkers (averaging 7 per hole) are the primary defense. It feels more like Melbourne\\\'s Sand Belt than typical Arizona target golf.' }, { question: 'What is the Ak-Chin connection?', answer: 'The Ak-Chin Indian Community purchased the course in 2010, recovering sacred ancestral land that was removed from their reservation by Presidential Executive Order in 1912. Each hole has its O\\\'odham name carved into iron at the tee box.' }, { question: 'How far is it from Scottsdale?', answer: 'About 30–35 miles south, near Maricopa. The drive keeps many visitors away, but those who make it consistently call it one of the best tracks in all of Arizona.' }]},
    { id: 'phx-4', name: 'Quintero Golf Club', slug: 'quintero-golf-club', city: 'Phoenix', state: 'Arizona', type: 'public', rating: 4.7, greensFee: '$80–$200', architect: 'Rees Jones', yearBuilt: 2000, holes: 18, par: 72, yardage: 7232, description: 'Set in a remote canyon northwest of Phoenix, Quintero is one of Arizona\'s hidden gems. The Rees Jones design navigates through rugged desert canyons with several jaw-dropping holes that emerge from the landscape.', highlights: ['Hidden canyon setting', 'Among Arizona\'s most scenic courses', 'Dramatic desert canyon holes'], imageAlt: 'Quintero Golf Club hole in dramatic desert canyon near Phoenix', history: 'Quintero Golf Club opened in 2000 in the foothills of the Hieroglyphic Mountains near Peoria, Arizona, designed by Rees Jones with associate Steve Weisser. Jones famously used helicopter flyovers to scout the routing through the desert canyon terrain. The original vision was a private club with two courses — Jones\\\'s "Founders Course" and a Greg Norman-designed "Charter Course" that was never built.\n\nThe remote location prevented the private model from succeeding, and by the early 2010s Quintero transitioned to public access — a gift to golfers, as a course intended for exclusive membership became one of the most celebrated public layouts in the Southwest. Troon now manages the facility.\n\nIn 2025, Jones and Weisser returned for the first major renovation in 25 years: greens resurfaced with 007XL creeping bentgrass, bunkers redesigned for public-access play, sightlines restored, and tees regrassed with Tifway 419 bermuda. Golf Digest ranks it No. 1 public course in Arizona; Golfweek alternates it at No. 1–2 with We-Ko-Pa Saguaro.', signatureHoles: [{ hole: 6, par: 3, yardage: 165, description: 'The most photographed hole — plays roughly 110 feet downhill with panoramic Sonoran Desert views stretching to the horizon. Club down significantly for the extreme elevation drop. Called one of the best par 3s found anywhere.' }, { hole: 8, par: 5, yardage: 530, description: 'A stunning three-shot par 5 requiring two shots threaded through mountain passages over desert wasteland. Three dramatically placed bunkers define the strategic challenge. Widely considered the signature par 5.' }, { hole: 16, par: 3, yardage: 165, description: 'A breathtaking downhill par 3 dropping 50+ feet to a deep green. Unplayable desert flanks the left side; sculpted bunkers frame the putting surface. The third of four dramatic par 3s.' }], whatToExpect: 'Quintero is routed through natural desert arroyos and canyons in the Hieroglyphic Mountains, roughly 45–60 minutes northwest of Scottsdale. Elevated tee boxes — sometimes dramatically so — present carries over raw desert. The isolation is part of the appeal: the setting feels untouched and removed from development.\n\nFairways are generous (often 60+ yards wide) but anything missing the short grass is essentially lost in the desert. The multi-level bentgrass greens are widely considered the finest putting surfaces in the Phoenix-Scottsdale area — fast, smooth, and recently resurfaced in 2025.\n\nAll four par 3s involve significant downhill elevation drops, creating the most dramatic collection of one-shot holes in Arizona. Mule deer and javelina roam the property.', playingTips: 'Play the right tees. Five options span 5,043 to 7,249 yards (slope 148 from the tips). The copper and jade tees remove many forced carries and are significantly more enjoyable for mid-to-high handicappers.\n\nAdjust for elevation on all par 3s (holes 6, 9, 13, 16). Take at least one club less than yardage suggests and trust the drop.\n\nKeep it in the fairway. The penalty for missing maintained turf is severe — desert waste, cacti, unplayable lies. A reliable tee shot shape matters more than carry distance.\n\nWind is constant and often stronger than it appears in the canyon terrain. Check wind direction before every shot.\n\nFavor the center of greens on your first visit. The multi-level surfaces are complex; chasing pins leads to three-putts.', faqs: [{ question: 'Is Quintero public?', answer: 'Yes. Originally designed as a private club, it transitioned to public access in the early 2010s. Peak-season green fees reach approximately $385 including cart. On-site lodging is available.' }, { question: 'Why is it ranked so highly?', answer: 'Golf Digest ranks it No. 1 public course in Arizona. The desert canyon setting, dramatic elevation changes, four spectacular downhill par 3s, and recently renovated bentgrass greens create an experience unlike anything else in the state.' }, { question: 'How far is it from Scottsdale?', answer: 'Roughly 45–60 minutes northwest. The remote location in the Hieroglyphic Mountains means the setting feels pristine and undeveloped — the drive is part of the experience.' }, { question: 'Was it recently renovated?', answer: 'Yes. In 2025, original architect Rees Jones returned for the first major renovation in 25 years — new greens, redesigned bunkers, restored sightlines, and regrassed tees.' }]},
    { id: 'phx-5', name: 'Wickenburg Ranch Golf Club', slug: 'wickenburg-ranch', city: 'Phoenix', state: 'Arizona', type: 'public', rating: 4.4, greensFee: '$50–$120', architect: 'Bill Brownlee', yearBuilt: 2015, holes: 18, par: 72, yardage: 6870, description: 'Northwest of Phoenix in the charming town of Wickenburg, this modern desert layout offers a relaxed pace and stunning high-desert scenery. The course features creative routing through mesquite-dotted terrain with Bradshaw Mountain views.', highlights: ['High-desert setting', 'Relaxed small-town atmosphere', 'Bradshaw Mountain views'], imageAlt: 'Wickenburg Ranch Golf Club high desert course with mountain views', history: 'Wickenburg Ranch opened in 2015, designed by Bill Brownlee and Wendell Pickett. Named among Golf Digest\'s Best New Courses upon opening, it sits in the Western town of Wickenburg, 60 miles northwest of Phoenix.\n\nThe course winds through high-desert terrain with mesquite, saguaro, and Bradshaw Mountain backdrop.\n\nIt offers relaxed, uncrowded desert golf away from the Scottsdale corridor.', signatureHoles: [{ hole: 4, par: 4, yardage: 405, description: 'A strategic par 4 with Bradshaw Mountain views framing the approach.' }, { hole: 8, par: 3, yardage: 175, description: 'A scenic desert par 3 with washes and bunkers defending the green.' }, { hole: 14, par: 5, yardage: 545, description: 'A risk-reward par 5 through a desert corridor.' }, { hole: 18, par: 4, yardage: 420, description: 'A strong finishing hole with mountain views.' }], whatToExpect: 'Relaxed, uncrowded desert golf with high-desert scenery and mountain views. At 6,870 yards, challenging but playable.\n\nThe small-town Wickenburg atmosphere is refreshingly different from resort golf.', playingTips: 'Desert hazards are unforgiving. Stay on maintained turf. High-desert elevation affects distance.\n\nMorning tee times recommended in summer.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Green fees $50 to $120.' }, { question: 'How far from Scottsdale?', answer: 'About 60 miles, roughly one hour.' }, { question: 'Who designed it?', answer: 'Bill Brownlee and Wendell Pickett. Best New Course 2015 by Golf Digest.' }] },
    { id: 'phx-6', name: 'Arizona Country Club', slug: 'arizona-country-club', city: 'Phoenix', state: 'Arizona', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Jack Snyder (restored by Forrest Richardson)', yearBuilt: 1932, holes: 18, par: 71, yardage: 6828, description: 'One of Phoenix\'s oldest and most prestigious private clubs, Arizona Country Club has been a cornerstone of Valley golf since 1932. A sensitive restoration modernized playing surfaces while honoring the Golden Age character of the original design.', highlights: ['One of Phoenix\'s oldest private clubs (1932)', 'Golden Age design with modern restoration', 'Central Phoenix location'], imageAlt: 'Arizona Country Club historic Phoenix fairway with mature desert landscaping', history: 'Arizona Country Club traces its roots to 1909, when William J. Murphy — the founder of Glendale, Arizona — established the Ingleside Golf Resort with oiled sand greens and a rudimentary six-hole layout. It was Phoenix\\\'s first winter golf resort. Murphy\\\'s son Ralph upgraded to a full 18-hole course with Bermuda grass in the 1920s but lost the property during the Great Depression in 1932.\n\nThe club was officially incorporated in 1946, and in 1949 purchased the original property. Jack Snyder — a Penn State-trained landscape architect who had served as superintendent at Oakmont Country Club — redesigned the course. Snyder\\\'s protege Forrest Richardson (who worked alongside Snyder for 33 years) has overseen restoration work honoring the original Golden Age character.\n\nArizona Country Club alternated with Phoenix Country Club as host of the Phoenix Open from 1955 to 1973. Arnold Palmer won the Phoenix Open here in 1961 and 1963 during his legendary three-peat (1961–63). Other champions who played the course include Jack Nicklaus, Gary Player, Gene Littler, and Lee Trevino.', signatureHoles: [{ hole: 5, par: 5, yardage: 520, description: 'One of five par 5s on this unusual layout. Strategic bunkering and trees narrow the landing area on the second shot, creating a genuine layup-or-go decision. The five par-5, five par-3, eight par-4 hole mix places a premium on versatility.' }, { hole: 15, par: 3, yardage: 185, description: 'A demanding par 3 to a push-up green guarded by strategic bunkering. One of five par 3s that test every iron in the bag.' }], whatToExpect: 'Arizona Country Club stands apart from the desert-target style dominating Phoenix/Scottsdale. Instead, it offers a lush, tree-lined, Midwestern-style parkland experience with mature trees framing virtually every hole. Push-up greens of medium size demand precise iron play.\n\nThe unusual hole mix — five par 5s, five par 3s, and eight par 4s (rather than the standard 4-10-4) — creates a distinctive scoring rhythm that rewards versatility across every club in the bag.\n\nViews of Camelback Mountain and Papago Buttes frame the course. The club holds 5-Star Platinum Club of America status and is consistently ranked the No. 1 family club in Arizona.', playingTips: 'Accuracy over distance. The tree-lined fairways punish wayward drives far more than most Arizona courses. Finding the short grass off the tee is the top priority.\n\nWith five par 5s, your strategy on these holes defines your score. Smart layups to preferred yardages often beat forcing shots through narrow tree corridors.\n\nBermuda greens are grainy — afternoon sun causes the grass to lean west. Downhill, downgrain putts can be very fast. Factor grain into every read.\n\nThe push-up greens shed offline approaches. Landing on the correct tier and staying below the hole are essential.', faqs: [{ question: 'Has Arizona Country Club hosted professional tournaments?', answer: 'Yes. It alternated with Phoenix Country Club as host of the Phoenix Open from 1955 to 1973. Arnold Palmer won here in 1961 and 1963 during his legendary three-peat. Nicklaus, Player, Littler, and Trevino also competed here.' }, { question: 'Who designed the course?', answer: 'Jack Snyder (a former Oakmont CC superintendent) designed the current layout. His protege Forrest Richardson has overseen restoration work preserving the Golden Age character.' }, { question: 'What makes the layout unusual?', answer: 'Five par 5s, five par 3s, and eight par 4s — rather than the standard 4-10-4 distribution. This places a premium on versatility and creates a distinctive scoring rhythm.' }, { question: 'Can the public play?', answer: 'No. Arizona Country Club is a private, invitation-only club. It holds 5-Star Platinum Club of America status.' }]},
    { id: 'phx-7', name: 'Verrado Golf Club - Victory Course', slug: 'verrado-victory', city: 'Phoenix', state: 'Arizona', type: 'public', rating: 4.2, greensFee: '$50–$120', architect: 'Tom Lehman & John Fought', yearBuilt: 2004, holes: 18, par: 72, yardage: 7258, description: 'Set against the White Tank Mountains west of Phoenix, Verrado\'s Victory Course is a Tom Lehman & John Fought collaboration that delivers championship desert golf at daily-fee prices. The 7,258-yard layout features wide fairways and dramatic desert carries.', highlights: ['Tom Lehman & John Fought design', 'White Tank Mountain backdrop', 'Championship length at public pricing'], imageAlt: 'Verrado Victory Course with White Tank Mountains backdrop in west Phoenix', history: 'Verrado Golf Club first opened with its Founders Course in 2004, co-designed by PGA Tour veteran Tom Lehman and architect John Fought. The Victory Course followed in 2016, designed by Tom Lehman as the second 18-hole championship layout within the master-planned Verrado community in Buckeye, west of Phoenix.\n\nThe Victory Course was designed to complement the Founders Course while offering a distinct playing experience. Lehman took advantage of the dramatic Sonoran Desert terrain in the foothills of the White Tank Mountains, creating a layout that blends desert target golf with more forgiving, links-inspired playing corridors.\n\nTogether, the two courses establish Verrado as one of the premier 36-hole public golf destinations in the greater Phoenix area, offering exceptional value compared to the high-end resort courses in Scottsdale.', signatureHoles: [{ hole: 3, par: 5, yardage: 560, description: 'A sweeping par 5 with dramatic mountain views that tempts long hitters to go for the green in two. The desert wash crossing the fairway demands a strategic layup decision for most players.' }, { hole: 8, par: 3, yardage: 200, description: 'A picturesque par 3 with the White Tank Mountains as a stunning backdrop. The elevated tee provides panoramic desert views while the green is well-defended by bunkers.' }, { hole: 15, par: 4, yardage: 440, description: 'A challenging par 4 that plays along the desert foothills. The approach requires careful club selection as desert carries and bunkering demand precision.' }, { hole: 18, par: 4, yardage: 450, description: 'A strong finishing hole with mountain views framing the final approach. The generous fairway gives way to a well-protected green that demands an accurate iron shot to close the round.' }], whatToExpect: 'The Victory Course offers a desert golf experience with wide, forgiving fairways framed by natural Sonoran Desert landscape and the White Tank Mountains. At 7,258 yards from the tips, it provides championship length but plays fairly from the forward tees. The Bermuda grass tees, fairways, and greens are well-maintained year-round.\n\nThe setting is quieter and less crowded than Scottsdale resort courses, and the value is significantly better. Expect dramatic desert carries on several holes but generous landing areas for accurate drives.', playingTips: 'Desert carries can be intimidating but most are shorter than they appear. Choose the appropriate tee box for your skill level and carry distance. The forward tees eliminate most forced carries.\n\nThe desert air and elevation near the White Tank Mountains can add distance to your shots. Club down on approaches, especially in the warm months. Wind can pick up in the afternoons, so morning tee times offer calmer conditions and cooler temperatures.', faqs: [{ question: 'Can the public play Verrado Victory Course?', answer: 'Yes. The Victory Course is a public daily-fee course with green fees typically ranging from $50 to $120 depending on season.' }, { question: 'What is the difference between the Founders and Victory courses?', answer: 'The Founders Course (2004) was co-designed by Lehman and Fought with a more traditional desert layout, while the Victory Course (2016) is a Lehman solo design with wider fairways and a links-inspired feel.' }, { question: 'When is the best time to play?', answer: 'October through April offers the most comfortable playing conditions. Summer temperatures regularly exceed 110 degrees, though twilight rates make afternoon rounds affordable.' }, { question: 'How far is Verrado from Scottsdale?', answer: 'Verrado is approximately 45 minutes west of Scottsdale in Buckeye, Arizona. The drive offers significantly lower green fees compared to Scottsdale resort courses.' }] },
    { id: 'phx-8', name: 'Troon Country Club', slug: 'troon-country-club', city: 'Phoenix', state: 'Arizona', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Tom Weiskopf & Jay Morrish', yearBuilt: 1986, holes: 18, par: 72, yardage: 7044, description: 'One of the early desert golf masterpieces, Troon Country Club sits at the base of Pinnacle Peak in north Scottsdale and helped pioneer the target-style desert golf concept that would define Arizona golf. The Weiskopf & Morrish design offers some of the most dramatic desert views in the Valley.', highlights: ['Pioneered desert target-style golf', 'Base of iconic Pinnacle Peak', 'Weiskopf & Morrish design classic'], imageAlt: 'Troon Country Club desert course at base of Pinnacle Peak', history: 'Troon Country Club opened in 1986, the very first collaboration between Tom Weiskopf and Jay Morrish — a partnership that would produce many of the Southwest\'s most acclaimed desert layouts. Named after Scotland\'s Royal Troon, the club helped pioneer the target-style desert golf concept that would come to define Arizona golf through the 1990s and beyond.\n\nThe course is routed around the base of Pinnacle Peak, a dramatic 3,000-foot granite formation visible from virtually every hole. As a Certified Audubon Cooperative Sanctuary, the course supports a thriving ecosystem of Sonoran Desert flora and fauna. Golf Magazine has recognized Troon among the top courses in the United States.\n\nThe Weiskopf-Morrish partnership that launched here went on to create dozens of celebrated courses, but Troon Country Club remains the foundational work — the design that proved desert golf could be both visually spectacular and strategically brilliant.', signatureHoles: [{ hole: 1, par: 4, yardage: 410, description: 'Named "Palo Verde" for the native trees with distinctive green bark and yellow spring blooms lining the fairway. A swale guards the front and right side of the green — favor the right side of the fairway off the tee for the best approach angle.' }], whatToExpect: 'Troon seamlessly integrates the Sonoran Desert environment — saguaro cacti, Palo Verde trees, natural desert washes, and native wildlife are constant companions. Desert washes bisect fairways, creating forced carries and strategic decisions off the tee. The McDowell Mountains provide a stunning backdrop that changes character throughout the day.\n\nAs one of the pioneering desert courses, the layout feels less contrived than some later imitators. The routing ensures Pinnacle Peak is visible from nearly every point, creating one of the most dramatic backdrops in Arizona golf. Conditioning is immaculate throughout.\n\nAccess is strictly private — members and guests only.', playingTips: 'Desert air can add 5-10% to carry distances. Factor this into every club selection.\n\nDesert washes that cross fairways demand a clear decision: lay up short or carry confidently. Do not leave the ball in the wash.\n\nAccuracy over length. The manicured fairways are the only safe landing zones — straying into native desert typically means a lost ball.\n\nGPS-equipped carts provide chilled water, fresh fruit, and scented towels. Hydrate aggressively in the desert heat.', faqs: [{ question: 'What makes Troon historically significant?', answer: 'It was the first-ever Tom Weiskopf and Jay Morrish collaboration (1986), launching one of golf architecture\'s most celebrated partnerships. The course helped pioneer the desert target-golf style that came to define Arizona golf.' }, { question: 'Can the public play Troon CC?', answer: 'No. Troon Country Club is a private club. It should not be confused with Troon North Golf Club (a public course also in Scottsdale).' }, { question: 'Is it Audubon certified?', answer: 'Yes. Troon is a Certified Audubon Cooperative Sanctuary, supporting Sonoran Desert flora and fauna throughout the property.' }, { question: 'What is Pinnacle Peak?', answer: 'A dramatic 3,000-foot granite formation at the base of which the course is routed. It is visible from virtually every hole and serves as the visual centerpiece of the experience.' }]},
    { id: 'phx-9', name: 'Lookout Mountain Golf Club', slug: 'lookout-mountain-golf', city: 'Phoenix', state: 'Arizona', type: 'resort', rating: 4.1, greensFee: '$75–$175', architect: 'Bill Johnston', yearBuilt: 1989, holes: 18, par: 72, yardage: 6518, description: 'Located at the Pointe Hilton Tapatio Cliffs Resort in north Phoenix, Lookout Mountain offers dramatic elevated tee shots, mountain-framed greens, and a resort-friendly layout that rewards accuracy over length. The shorter yardage makes it accessible while the terrain keeps it engaging.', highlights: ['Dramatic mountain terrain in north Phoenix', 'Resort-friendly but engaging layout', 'Tapatio Cliffs Resort on-site access'], imageAlt: 'Lookout Mountain Golf Club elevated desert tee shot in north Phoenix', history: 'Lookout Mountain Golf Club opened in 1989, designed by Bill Johnston (with later contributions from Forrest Richardson) as part of the Pointe Hilton Tapatio Cliffs Resort in north Phoenix. The course was built to complement the resort experience while offering dramatically more terrain character than typical resort layouts.\n\nOver the years, Lookout Mountain has hosted Champions Tour events and earned Golf Digest\'s Four Star Award for ten consecutive years. Zagat Survey named it one of "America\'s Top Golf Courses," and Arizona Business Magazine ranked it among the Top Ten resort courses in Arizona. Now managed by Troon Golf, it remains one of the most memorable resort plays in the Phoenix area.\n\nHole 10 was voted the No. 1 Golf Hole in Phoenix in 2010 — a dramatic distinction for a resort course competing against the Valley\'s many celebrated private and public layouts.', signatureHoles: [{ hole: 10, par: 4, yardage: 380, description: 'Voted the No. 1 Golf Hole in Phoenix (2010). Features a jaw-dropping 14-story drop from tee to green — the tee shot plays from a mountainside perch with sweeping valley views. The visual drama is extraordinary. Take significantly less club than the yardage suggests.' }, { hole: 13, par: 4, yardage: 395, description: '"The Lookout" — an elevated tee with panoramic mountain views that epitomize the course\'s character. The vista from the tee box is among the most photographed on the property.' }, { hole: 18, par: 5, yardage: 510, description: 'The finishing hole features a peninsula green surrounded by water on three sides, creating a nerve-testing conclusion. A reachable par 5 that rewards bold, accurate approach play.' }], whatToExpect: 'The round transforms dramatically as it progresses. Opening holes play in traditional resort fashion — relatively flat and welcoming. By holes 7-9, the course climbs into the North Phoenix Mountains with elevation changes rising as much as 175 feet above the valley floor. Views of Lookout Mountain and Piestewa Peak emerge as panoramic backdrops.\n\nAt 6,518 yards, the yardage is modest, but the creative layout, mountain terrain, and undulating Bermuda greens make it far more challenging than the scorecard suggests. Four tee sets accommodate all skill levels.\n\nThe resort setting includes the Pointe in Tyme restaurant as the 19th hole, with views of the finishing holes.', playingTips: 'On the famous 10th hole (14-story drop), take significantly less club than the yardage suggests. The elevation drop means the ball carries much farther than on flat ground.\n\nThe large, sloped greens require attention to pin position. Leaving yourself below the hole is critical for manageable putts.\n\nUphill holes on the front nine play longer than the card — club up. Downhill mountain holes play shorter — club down.\n\nHydrate aggressively. Phoenix heat combined with uphill climbs on the mountain holes depletes energy quickly.\n\nDon\'t let the modest yardage fool you into thinking this is easy. The terrain and green complexes provide the challenge.', faqs: [{ question: 'What is the famous hole at Lookout Mountain?', answer: 'Hole 10 — a par 4 with a 14-story elevation drop from tee to green. It was voted the No. 1 Golf Hole in Phoenix in 2010.' }, { question: 'Is it open to the public?', answer: 'Yes. As a resort course at the Pointe Hilton Tapatio Cliffs, it is open to resort guests and public daily-fee play. Managed by Troon Golf.' }, { question: 'How difficult is it?', answer: 'At 6,518 yards it is not long, but the mountain terrain, elevation changes, and undulating greens make it far more challenging than the scorecard suggests. Golf Digest gave it a Four Star Award for ten consecutive years.' }, { question: 'Has it hosted professional events?', answer: 'Yes — Champions Tour events have been held here, and it has been recognized by Zagat as one of America\'s Top Golf Courses.' }]},
  ],
  'orlando-florida': [
    { id: 'orl-1', name: 'Bay Hill Club & Lodge', slug: 'bay-hill', city: 'Orlando', state: 'Florida', type: 'resort', rating: 4.7, greensFee: '$200–$350', architect: 'Dick Wilson', yearBuilt: 1961, holes: 18, par: 72, yardage: 7381, description: 'Arnold Palmer\'s legendary home course and host of the Arnold Palmer Invitational, Bay Hill is one of the most storied venues in American golf. The lakeside layout demands precision and course management, with the finishing stretch among the toughest on Tour.', highlights: ['Arnold Palmer\'s home course', 'Arnold Palmer Invitational host', 'One of PGA Tour\'s toughest finishes'], imageAlt: 'Bay Hill Club signature hole along the lake in Orlando', history: 'Bay Hill opened in 1961 with the first 18 holes designed by Dick Wilson on rolling Florida terrain with natural sinkholes. Arnold Palmer first played Bay Hill in 1965 and purchased the club in 1970, making it his winter home. Since 1979 it has hosted a PGA Tour event now called the Arnold Palmer Invitational.', signatureHoles: [{ hole: 18, par: 4, yardage: 458, description: 'One of golf\'s most famous finishing holes. Water runs along the right and surrounds the green.' }, { hole: 6, par: 5, yardage: 558, description: 'A reachable par 5 offering birdie chances for those willing to take on the water.' }, { hole: 17, par: 3, yardage: 223, description: 'A demanding par 3 over water to a lakeside green where wind makes club selection critical.' }, { hole: 1, par: 4, yardage: 461, description: 'A strong opening par 4 that sets the tone for the demanding round ahead.' }], whatToExpect: 'A classic Florida course with more elevation change than most Central Florida layouts. Plays to 7,466 yards as a par 72 with a demanding lakeside finish. Resort guests can access the championship course.', playingTips: 'Course management is essential. Avoid the water on 17 and 18 at all costs. Accuracy with irons matters more than distance off the tee.', faqs: [{ question: 'Can the public play Bay Hill?', answer: 'Resort guests at the lodge can play with fees typically $200 to $350.' }, { question: 'What is the Arnold Palmer Invitational?', answer: 'An annual PGA Tour event held since 1979, one of Tour\'s most prestigious stops.' }, { question: 'Did Palmer design Bay Hill?', answer: 'Dick Wilson designed the original course in 1961. Palmer purchased it in 1970 and refined it over decades.' }, { question: 'What makes the 18th famous?', answer: 'Water surrounds the green on this par 4, creating one of golf\'s most dramatic finishers.' }] },
    { id: 'orl-2', name: 'Orange County National - Panther Lake', slug: 'ocn-panther-lake', city: 'Orlando', state: 'Florida', type: 'public', rating: 4.5, greensFee: '$60–$130', architect: 'Phil Ritson & David Harman', yearBuilt: 1988, holes: 18, par: 72, yardage: 7350, description: 'A PGA Tour Q-School staple, Panther Lake at Orange County National offers championship-caliber golf at public course prices. The rolling terrain is unusual for Central Florida, creating elevation changes that add visual and strategic interest.', highlights: ['PGA Tour Q-School venue', 'Unusual elevation changes for Florida', 'Outstanding public golf value'], imageAlt: 'Orange County National Panther Lake course with rolling terrain', history: 'Orange County National opened in 1988 near Winter Garden, Florida, designed by Phil Ritson and David Harman. Panther Lake gained national recognition as a longtime host of PGA Tour Q-School finals and the Korn Ferry Tour\'s Orange County National Championship.\n\nThe rolling terrain is unusual for Central Florida, providing elevation changes more reminiscent of the Carolinas than the Florida flatlands.\n\nOrange County National remains one of the best values in Orlando-area golf.', signatureHoles: [{ hole: 4, par: 4, yardage: 445, description: 'A demanding par 4 with significant elevation change that has challenged Q-School contenders.' }, { hole: 9, par: 4, yardage: 430, description: 'A strong front-nine finisher using rolling terrain with water threatening on approach.' }, { hole: 15, par: 3, yardage: 195, description: 'A challenging par 3 over water that has produced dramatic Q-School moments.' }, { hole: 18, par: 4, yardage: 455, description: 'A demanding finishing hole that has decided many Q-School fates.' }], whatToExpect: 'Championship-caliber golf at public course prices. Rolling terrain provides elevation changes unusual for Central Florida.\n\nAt 7,350 yards from the tips, it is a serious test. Forward tees make it playable for all levels.', playingTips: 'The rolling terrain affects club selection more than expected in Florida. Pay attention to elevation changes.\n\nLarge greens can be fast. Focus on correct portions to avoid long lag putts.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Green fees $60 to $130.' }, { question: 'What is the Q-School connection?', answer: 'Panther Lake was a longtime PGA Tour Q-School finals host.' }, { question: 'How many courses at Orange County National?', answer: 'Two: Panther Lake and Crooked Cat.' }] },
    { id: 'orl-3', name: 'Streamsong Resort - Red', slug: 'streamsong-red', city: 'Orlando', state: 'Florida', type: 'resort', rating: 4.8, greensFee: '$175–$300', architect: 'Bill Coore & Ben Crenshaw', yearBuilt: 2012, holes: 18, par: 72, yardage: 7148, description: 'While technically south of Orlando in Polk County, Streamsong Red is the must-play course for any Florida golf trip. Built on a former phosphate mine, this Coore & Crenshaw links-inspired layout features towering sand ridges, rolling fairways, and a sense of isolation unique in the Sunshine State.', highlights: ['Links-style Florida golf', 'Former phosphate mine terrain', 'Top 25 public course in America'], imageAlt: 'Streamsong Red links-style course with sand ridges in Central Florida', history: 'Streamsong Red was designed by Bill Coore and Ben Crenshaw and opened in 2012 on a former phosphate mining site in Polk County, Florida. The mining operations had inadvertently created dramatic sand ridges and rolling terrain unlike anything else in the flat Sunshine State, giving the architects raw material that resembled links land. Coore and Crenshaw routed 18 holes through the most dramatic dune formations on the property.\n\nThe course was an instant critical success, debuting in Golf Digest\'s Top 100 and ranking among the top public courses in America. Streamsong Red was the first of three courses at the resort — Tom Doak\'s Blue Course opened simultaneously in 2012, followed by Gil Hanse\'s Black Course in 2017. The Coore and Crenshaw design philosophy of minimalism is on full display, with the course feeling as though it has existed for decades rather than being carved from an industrial landscape.', signatureHoles: [{ hole: 16, par: 3, yardage: 208, description: 'A stunning Biarritz-style par 3 with a deep swale through the center of a long, narrow green. The visual from the tee is breathtaking, with sand ridges framing the hole. Hitting the correct tier is essential to avoid three-putts.' }, { hole: 7, par: 5, yardage: 527, description: 'A beautifully designed par 5 that sweeps left through rolling dune terrain. The fairway width rewards aggressive tee shots, and the green complex offers multiple pin positions that change the strategy for the approach.' }, { hole: 1, par: 4, yardage: 464, description: 'A strong opening par 4 that plays gently uphill through sand ridges. The wide fairway invites an aggressive drive, but the approach to an elevated green demands precision.' }, { hole: 12, par: 4, yardage: 472, description: 'One of the toughest holes on the course, this long par 4 often plays into the prevailing wind with a narrow fairway flanked by deep bunkers.' }], whatToExpect: 'Streamsong Red delivers a links-style experience unlike anything else in Florida. The former phosphate mine created towering sand ridges, rolling fairways, and a treeless landscape that feels more like the British Isles than Central Florida. Conditioning is excellent with firm, fast surfaces that encourage bump-and-run shots.\n\nThe greens are large, subtly contoured, and designed to accept running approaches. Wind is a significant factor on the exposed layout, adding an extra dimension to club selection and shot shaping.', playingTips: 'Embrace the ground game at Streamsong Red. The firm conditions reward bump-and-run approaches, and many greens are designed to funnel shots from specific angles. The wind is a constant factor on this exposed layout, so bring your knockdown shots and plan for extra clubs into the breeze.\n\nThe Biarritz green on the 16th is a must-experience moment. Play from the appropriate tees to maximize enjoyment; the course plays longer than the yardage suggests due to wind.', faqs: [{ question: 'Which Streamsong course should I play if I can only play one?', answer: 'Most golfers and critics give a slight edge to Streamsong Red as the best of the three, though all three are exceptional. If you can play two, pairing Red with either Blue or Black makes for an outstanding day.' }, { question: 'Is Streamsong Red walkable?', answer: 'Yes, and walking is encouraged. The terrain is gently rolling with reasonable distances between greens and tees. Caddies are available and recommended for first-time visitors.' }, { question: 'How far is Streamsong from Orlando or Tampa?', answer: 'Streamsong is approximately 90 minutes south of Orlando and about 75 minutes southeast of Tampa. The remote location is part of the appeal.' }, { question: 'What makes Streamsong Red different from the Blue and Black courses?', answer: 'Red features the most dramatic sand ridges with a Coore and Crenshaw minimalist approach. Blue (Tom Doak) offers wider fairways and more strategic options, while Black (Gil Hanse) is the most exposed and rugged of the three.' }] },
    { id: 'orl-4', name: 'Waldorf Astoria Golf Club', slug: 'waldorf-astoria-golf', city: 'Orlando', state: 'Florida', type: 'resort', rating: 4.4, greensFee: '$100–$200', architect: 'Rees Jones', yearBuilt: 2009, holes: 18, par: 72, yardage: 7108, description: 'A Rees Jones design nestled within the Bonnet Creek resort area near Disney, Waldorf Astoria Golf Club offers a surprisingly serene and challenging experience just minutes from the theme parks. Native wetlands and mature cypress trees line the fairways.', highlights: ['Minutes from Disney World', 'Rees Jones design', 'Luxury resort golf experience'], imageAlt: 'Waldorf Astoria Golf Club Orlando course with cypress trees', history: 'Waldorf Astoria Golf Club opened in 2009 as the first golf club bearing the Waldorf Astoria name, designed by Rees Jones in the Bonnet Creek area near Walt Disney World.\n\nJones created the layout through native wetlands and mature cypress trees, drawing design elements from classic courses worldwide.\n\nThe club is recognized as one of the finest resort courses in Orlando.', signatureHoles: [{ hole: 5, par: 4, yardage: 440, description: 'A demanding par 4 with water along the left side and a well-bunkered green.' }, { hole: 11, par: 3, yardage: 185, description: 'A scenic par 3 over water to a green surrounded by wetlands and cypress.' }, { hole: 16, par: 3, yardage: 195, description: 'A visually striking par 3 with water and bunkers creating a demanding target.' }, { hole: 18, par: 4, yardage: 445, description: 'A strong finishing hole through cypress trees alongside wetlands.' }], whatToExpect: 'A tranquil Rees Jones design through native wetlands and cypress, offering a serene contrast to nearby theme parks.\n\nAt 7,108 yards from the tips, it is a legitimate championship test with water on nearly every hole.', playingTips: 'Water is the primary hazard. Play conservatively on unfamiliar holes. Florida humidity makes the course play longer than yardage suggests.\n\nTake extra club on approaches, especially in summer.', faqs: [{ question: 'Can the public play here?', answer: 'Yes. Green fees range from $100 to $200.' }, { question: 'Who designed the course?', answer: 'Rees Jones. It opened in 2009.' }, { question: 'How close to Disney?', answer: 'In the Bonnet Creek resort area, just minutes from Walt Disney World.' }] },
    { id: 'orl-5', name: 'Shingle Creek Golf Club', slug: 'shingle-creek', city: 'Orlando', state: 'Florida', type: 'resort', rating: 4.2, greensFee: '$60–$120', architect: 'David Harman', yearBuilt: 2003, holes: 18, par: 72, yardage: 7228, description: 'Located along the headwaters of the Everglades at the Rosen Shingle Creek resort, this course offers a natural Florida golf experience in the heart of Orlando\'s Convention Center district. Wetlands, live oaks, and wildlife create a peaceful retreat.', highlights: ['Headwaters of the Everglades setting', 'Convention Center district location', 'Natural Florida golf experience'], imageAlt: 'Shingle Creek Golf Club natural wetland setting in Orlando', history: 'Shingle Creek Golf Club opened in 2003 at the Rosen Shingle Creek resort, designed by David Harman — a prominent Central Florida architect whose portfolio included Orange County National. Harman tragically passed away from cancer in December 2004 at just 51, making Shingle Creek one of his final designs.\n\nThe course sits along historic Shingle Creek, recognized as the headwaters of the Florida Everglades — a waterway historically important for Native Americans and early settlers. After Harman\'s original design, the Arnold Palmer Design Group refined the layout with knobs, swales, slopes, and closely mown runoff areas around elevated greens.\n\nThe Brad Brewer Golf Academy is based at the club, and Director of Golf Dave Scott previously worked for Arnold Palmer at Bay Hill, reinforcing the Palmer connection. The course is located just one mile from the Orange County Convention Center.', signatureHoles: [{ hole: 17, par: 3, yardage: 220, description: 'The signature hole — a demanding par 3 with water running the entire length of the right side. At 220 yards, it requires both distance and accuracy with zero margin for error right. Take enough club and aim left of center.' }], whatToExpect: 'Shingle Creek is an open, parkland-style layout through dense oaks, pines, and natural wetlands along the Everglades headwaters. Fairways sweep between tall trees and glistening wetland areas with interconnecting waterways throughout.\n\nWater comes into play on 16 of 18 holes — a significant strategic factor. However, the design generally provides bailout areas, and there are only three forced carries, keeping it playable across skill levels. Greens are elevated with slopes, knobs, and swales creating challenge.\n\nThe natural setting features abundant wildlife and mature trees, offering a welcome contrast to the nearby theme park corridor. The course plays longer than the scorecard suggests — one reviewer noted 6,600 yards felt more like 7,200 due to the open layout where wind is a factor.', playingTips: 'Water is on 16 of 18 holes — identify bailout areas on each hole rather than challenging the hazards directly.\n\nPrepare for the 220-yard par-3 17th with water right. Take enough club and aim left of center — there is no safe miss right.\n\nAccount for the wind. The open, flat Florida layout means wind adds significant effective yardage. The course plays longer than it looks on paper.\n\nGreens are elevated with Palmer Design Group refinements — don\'t go long. Short-sided misses are more recoverable than running off the back.', faqs: [{ question: 'Who designed Shingle Creek?', answer: 'David Harman (original 2003 design), later refined by the Arnold Palmer Design Group. Harman also designed Orange County National.' }, { question: 'What is the Everglades connection?', answer: 'The course sits along Shingle Creek, officially recognized as the headwaters of the Florida Everglades. The natural wetlands are integrated throughout the layout.' }, { question: 'Is it open to the public?', answer: 'Yes. While part of the Rosen Shingle Creek resort, it is fully open to public play, making it accessible to convention-goers, tourists, and locals.' }, { question: 'How much water is in play?', answer: 'Water affects 16 of 18 holes, though there are only three forced carries. The design provides bailout areas on most holes.' }]},
    { id: 'orl-6', name: 'Isleworth Golf & Country Club', slug: 'isleworth-golf-country-club', city: 'Windermere', state: 'Florida', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Arnold Palmer & Ed Seay', yearBuilt: 1986, holes: 18, par: 72, yardage: 7544, description: 'Nestled among the Butler Chain of Lakes in Windermere, Isleworth is one of the most exclusive and celebrity-studded private clubs in America. Originally designed by Arnold Palmer and Ed Seay, the course was later enhanced by Steve Smyers to produce a 7,544-yard par-72 layout with a slope of 142.', highlights: ['Arnold Palmer & Ed Seay design enhanced by Steve Smyers', 'Long-time private training home of Tiger Woods', 'Slope of 142 on one of Florida\'s most exclusive courses'], imageAlt: 'Lakeside fairway at Isleworth Golf and Country Club in Windermere Florida', history: 'Arnold Palmer purchased the land in 1984 with a vision for a luxury residential golf community on a former orange grove interwoven with the Butler Chain of Lakes. The original 18-hole course, designed by Palmer and Ed Seay, opened in 1986. The early years were financially rocky before the community rebounded into one of the most prestigious addresses in the country.\n\nIn 2003, architect Steve Smyers undertook a total reconstruction: every hole was regraded, yardage stretched from 7,179 to 7,544 yards (Florida\'s longest at the time), slope climbed from 135 to 142, greens converted from bent to TifEagle bermuda, and 65 high-flashed bunkers were cut into hillsides. Ten holes interact directly with the Butler Chain of Lakes.\n\nTiger Woods lived at Isleworth for years, in a home across from the practice facility. In the lead-up to the 1997 Masters — where he won by 12 strokes — Woods famously shot a practice-round 59 here. Other notable residents have included Shaquille O\'Neal, Mark O\'Meara, and Justin Rose. The Hero World Challenge (Tiger\'s foundation tournament) was previously held here.', signatureHoles: [{ hole: 2, par: 3, yardage: 210, description: 'The "Cypress Chute" — a par 3 over 200 yards through a tight corridor of cypress trees. Widely regarded as one of the hardest par 3s in Florida with minimal margin for error. One of three lowest-handicap holes that hit you early on the front nine.' }, { hole: 11, par: 4, yardage: 420, description: 'The visual highlight of the round, featuring flower beds and lake views on the Butler Chain. Described as the "Kodak moment of the day." Beautiful but demanding positioning off the tee.' }, { hole: 17, par: 4, yardage: 465, description: 'One of the two hardest handicap holes on the course. A diabolical green complex that can turn a good round sour in a hurry. Two precise shots are mandatory.' }], whatToExpect: 'Isleworth occupies 600 gated acres on the Butler Chain of Lakes in Windermere. The Smyers reconstruction created rolling terrain uncommon for Florida — extensive earthwork added swells, swales, mounds, and hollows throughout. Challenge comes through contour and angle rather than penal hazards.\n\nAt 7,544 yards with a 142 slope, this is a genuine championship test. Six tee options range down to 5,747 yards. TifEagle bermuda greens run fast, and 65 high-flashed bunkers demand precise approach play. Ten holes interact with the lakes.\n\nThe 89,000-square-foot Mediterranean clubhouse, two-acre short-game area, and 11,000-square-foot putting green reflect the exclusive standard. Access is strictly private — members and guests only.', playingTips: 'Choose tees wisely. At 6,400 yards the course is all most amateurs can handle. The 7,544-yard tips with 142 slope are a serious championship test.\n\nThe par 3s are course-defining holes — especially the 210-yard 2nd through the cypress chute. Club up and aim center.\n\nSmyers built strategic mounds and hollows into every hole. The TifEagle greens run fast. Leave approach shots below the hole.\n\nTen holes interact with the Butler Chain of Lakes. Bring extra golf balls and know your carry distances.\n\nThe two-acre short-game area is elite — warming up there before your round is essential given the difficulty.', faqs: [{ question: 'Did Tiger Woods really live at Isleworth?', answer: 'Yes. Tiger lived here for years, choosing a home across from the practice facility over a lakefront lot. He famously shot a 59 in a practice round before winning the 1997 Masters by 12 strokes.' }, { question: 'Who redesigned the course?', answer: 'Steve Smyers totally reconstructed it in 2003, regrading every hole, stretching it to 7,544 yards (Florida\'s longest at the time), and cutting 65 high-flashed bunkers into hillsides. Arnold Palmer and Ed Seay did the original 1986 design.' }, { question: 'Can the public play Isleworth?', answer: 'No. Isleworth is an extremely exclusive private club with 24/7 armed security. Access is for members and their guests only.' }, { question: 'How is it ranked?', answer: 'Golf Digest ranked it No. 22 among best courses in Florida (2019-2020). The 7,544-yard layout with 142 slope is among the most demanding in the state.' }]},
    { id: 'orl-7', name: 'Waldorf Astoria Golf Club', slug: 'waldorf-astoria-golf-club', city: 'Orlando', state: 'Florida', type: 'resort', rating: 4.2, greensFee: '$175–$299', architect: 'Rees Jones', yearBuilt: 2009, holes: 18, par: 72, yardage: 7108, description: 'Opened in 2009, the Waldorf Astoria Golf Club is Rees Jones\'s signature addition to the Orlando resort golf landscape, stretching across 482 acres of natural Florida terrain near Walt Disney World. Preserved wetlands, natural bunkering, and GEO Certified sustainability designation round out the experience.', highlights: ['Rees Jones design on 482 Florida acres', 'GEO Certified for environmental sustainability', 'Five-tee system with championship stretch of 7,108 yards'], imageAlt: 'Rees Jones-designed fairway at Waldorf Astoria Golf Club in Orlando with wetlands', history: 'The Waldorf Astoria Golf Club opened October 1, 2009, designed by Rees Jones — "The U.S. Open Doctor" known for preparing courses for seven U.S. Opens, five PGA Championships, and three Ryder Cups. Jones designed the layout to evoke a pre-Depression-era aesthetic on 482 acres of natural cypress-lined terrain near Walt Disney World.\n\nFrom 2018 to 2024, Jones and Steve Weisser led a phased renovation: back nine (2022), front nine (2023), and holes 16-17 (2024). The project enlarged greens that had shrunk from bermuda encroachment, replaced bunker liners with Better Billy Bunker technology, expanded tee areas, and cleared native growth for improved sightlines.\n\nThe resort was the first new-build Waldorf Astoria property. The course holds GEO (Golf Environment Organization) certification for environmental sustainability and has been named to Golf Magazine\'s "Top Courses You Can Play" list. Each hole is named after Waldorf Astoria New York landmarks: "Conrad" (Hole 12), "Sir Harry" (13), "The Presidential" (17), "Starlight" (18).', signatureHoles: [{ hole: 12, par: 5, yardage: 624, description: 'Named "Conrad" after Conrad Hilton. A demanding par 5 that can play over 700 yards into the prevailing wind. Identified by Orlando Magazine as one of the most challenging holes in Central Florida.' }, { hole: 17, par: 4, yardage: 482, description: '"The Presidential" — widely regarded as the hardest hole on the course. A demanding par 4 requiring two precise shots to reach in regulation. Named for the Waldorf Astoria\'s presidential suites.' }, { hole: 18, par: 5, yardage: 540, description: '"Starlight" — a reachable par 5 guarded by water with the most undulating green on the course. The green doubles as a fireworks-viewing area for the resort. A dramatic risk-reward closer.' }], whatToExpect: 'The layout is relatively straight with generous fairways that appear narrower from the tee than they actually are. Strategic bunkering (approximately 60 white sand bunkers) guards preferred landing areas, and raised multi-section greens generally slope back to front. Water comes into play on 14 of 18 holes.\n\nConditions are consistently praised as immaculate. TifEagle bermuda greens roll firm and true. GPS-equipped carts feature touchscreens with yardage information and food-ordering capability. The five-tee system ranges from 5,179 to 7,108 yards (slope 139 from tips).\n\nThe resort atmosphere provides a near-private-club experience accessible to the public, with valet parking, professional locker rooms, and a clubhouse grille.', playingTips: 'Do not go over the back of the greens. The back-to-front slope means missing long leaves very difficult recovery shots — err on the side of taking less club.\n\nFairways are wider than they look from the tee. Trust the visual corridors and swing freely.\n\nWith water on 14 holes and 60 bunkers, keeping the ball in play matters more than distance. Fairway bunkers guard preferred sides of landing areas.\n\nRespect the wind. Built on open wetlands, the course is susceptible to gusts, especially on the 624-yard 12th ("Conrad").\n\nThe renovation created interesting chipping zones around greens — the ground game is often smarter than a lofted pitch.', faqs: [{ question: 'Who designed the Waldorf Astoria Golf Club?', answer: 'Rees Jones ("The U.S. Open Doctor"), opening in 2009. Jones and Steve Weisser led a comprehensive phased renovation from 2018 to 2024.' }, { question: 'Why are the holes named after New York landmarks?', answer: 'Each hole references the Waldorf Astoria New York: "Conrad" (after Conrad Hilton), "Sir Harry" (the famous hotel bar), "The Presidential" (presidential suites), "Starlight" (the Starlight Roof ballroom).' }, { question: 'Is it open to the public?', answer: 'Yes. The course is accessible to both hotel guests (stay-and-play packages) and general public daily-fee play within the Walt Disney World resort corridor.' }, { question: 'What is GEO certification?', answer: 'The Golf Environment Organization certifies courses for environmental stewardship and sustainable practices. The Waldorf Astoria is one of relatively few GEO-certified courses in Florida.' }]},
    { id: 'orl-8', name: 'Disney\'s Magnolia Golf Course', slug: 'disney-magnolia-golf-course', city: 'Orlando', state: 'Florida', type: 'resort', rating: 4.3, greensFee: '$99–$199', architect: 'Joe Lee', yearBuilt: 1971, holes: 18, par: 72, yardage: 7560, description: 'The longest of Disney\'s golf courses, Magnolia opened in 1971 and hosted the PGA Tour\'s Disney event from 1971 to 2012. Famous for its iconic Mickey Mouse-shaped bunker on the sixth hole. A major Ken Kaufman redesign was completed in 2022.', highlights: ['Hosted PGA Tour Disney Classic from 1971 to 2012', 'Iconic Mickey Mouse-shaped bunker on hole 6', 'Joe Lee original design reimagined by Ken Kaufman in 2022'], imageAlt: 'Magnolia-tree-lined championship fairway at Disney Magnolia Golf Course Orlando', history: 'Disney\'s Magnolia Golf Course opened on October 1, 1971 — the same day Walt Disney World itself welcomed its first guests. Designed by Joe Lee in classic Florida championship style, the Magnolia was conceived as the resort\'s marquee course: the longest layout in the Disney golf portfolio at 7,516 yards from the championship tees, with 97 bunkers and water hazards on 11 of its 18 holes.\n\nThe course became the permanent home of the PGA Tour\'s Walt Disney World event, hosting the final round of the tournament for 42 consecutive years from 1971 to 2012. Prize money grew from $30,000 for the inaugural winner to $846,000 by the event\'s final year. Jack Nicklaus won three consecutive titles here (1971-1973), and Tiger Woods captured victories in 1996 and 1999. Other champions included Payne Stewart, Larry Nelson, Davis Love III, and Justin Leonard. The course also served as a PGA Tour Qualifying School finals venue into the early 1980s and hosted the Senior PGA Championship from 1975 to 1979, with winners including Charlie Sifford and Julius Boros.\n\nIn 2022, a major redesign led by Ken Baker of One Club Limited began the most extensive transformation in the course\'s history. Four holes — Nos. 14, 15, 16, and 17 — were completely reimagined with innovative layouts and landscaping in a stretch now branded "Grumpy\'s Gauntlet." The project also included new greens, renovated fairways and greenside bunkers, a new cart bridge connecting holes 16 and 17, and Disney-themed names for all 18 holes. The full renovation was completed in early 2025.', signatureHoles: [{ hole: 6, par: 3, yardage: 195, description: 'Known as "The Mouse Trap," this is the most iconic hole on the course and features the famous Mickey Mouse-shaped greenside bunker — a silhouette of Mickey\'s head and ears carved in sand. The bunker was rebuilt with Capillary Concrete technology in 2017 for superior drainage and durability. Disney plans similar themed bunkers on its other courses. A short to mid-iron to a well-defended green with the unmistakable Disney touch.' }, { hole: 15, par: 5, yardage: 597, description: 'The centerpiece of "Grumpy\'s Gauntlet," this 597-yard par 5 from the back tees presents a substantial challenge for distance and strategy. Part of the completely reimagined four-hole closing stretch (14-17) that represents the toughest finishing sequence in Central Florida.' }, { hole: 16, par: 4, yardage: 456, description: 'At 456 yards from championship tees, this Gauntlet hole demands precision with two bodies of water running along the left side. Reaching the green in regulation requires avoiding the water while finding a fairway that feeds toward the hazards.' }, { hole: 17, par: 3, yardage: 200, description: 'A stern closing par 3 in the Gauntlet sequence, with water flanking both sides of the hole and a green that slopes in multiple directions. Club selection and nerve are tested equally on this penultimate challenge.' }, { hole: 14, par: 4, yardage: 430, description: 'The opening hole of Grumpy\'s Gauntlet features a uniquely contoured green that slopes away from center on all four sides, making it extremely difficult to hold approach shots near the pin regardless of where it is located.' }], whatToExpect: 'Disney\'s Magnolia is a big, demanding Florida championship course that plays long at 7,516 yards from the tips with a slope of 141. Water comes into play on 11 of 18 holes, and the 97 bunkers — including the famous Mickey Mouse silhouette on the 6th — keep you honest throughout. The layout is lined with magnolia trees, pines, palms, and cypresses, and the flat Florida terrain is punctuated by enough shaping to create visual interest.\n\nThe recently completed renovation adds a modern dimension. The four reimagined holes of Grumpy\'s Gauntlet (14-17) bring waste bunkers, undulating greens, and strategic water into the closing stretch, creating one of the most demanding finishes in Central Florida. Each hole now carries a Disney-themed name, and golfers who survive the Gauntlet can download a personalized certificate celebrating their perseverance.\n\nThe resort atmosphere is family-friendly and welcoming. Arnold Palmer Golf Management operates the facility, and the experience includes GPS-equipped carts, a well-stocked pro shop, and the Champions Pavilion documenting four decades of PGA Tour history at the venue.', playingTips: 'Course management is paramount on the Magnolia. With water on 11 holes and 97 bunkers, keeping the ball in play matters far more than distance off the tee. Identify the dry side of every fairway and play to it.\n\nSave your concentration for Grumpy\'s Gauntlet (14-17). The four reimagined holes are the toughest stretch on the course. On the 14th, aim for the center of the green — the slopes shed balls off all four edges. On the 15th, do not try to reach the par 5 in two unless you are certain of your carry. The 16th demands accuracy with water left, and the 17th requires a confident swing with water on both sides.\n\nFlorida humidity makes the course play longer than the yardage suggests, particularly in summer. Take extra club on approaches. Morning tee times offer cooler temperatures and generally calmer winds.\n\nThe Mickey Mouse bunker on the 6th is a must-see, but it is also a legitimate hazard — aim away from it and enjoy the view from the fairway.', faqs: [{ question: 'What is the Mickey Mouse bunker at Disney Magnolia?', answer: 'The iconic Mickey Mouse-shaped bunker sits beside the green on the par-3 6th hole (now named "The Mouse Trap"). It is a sand bunker carved in the silhouette of Mickey\'s head and ears, rebuilt in 2017 with advanced Capillary Concrete drainage technology. It is one of the most photographed features in resort golf.' }, { question: 'Did the PGA Tour play at Disney Magnolia?', answer: 'Yes. The Magnolia hosted the final round of the PGA Tour\'s Walt Disney World event for 42 consecutive years, from 1971 to 2012. Jack Nicklaus won three straight titles (1971-1973) and Tiger Woods won in 1996 and 1999.' }, { question: 'What is Grumpy\'s Gauntlet?', answer: 'Grumpy\'s Gauntlet is the name for the four completely reimagined holes (14, 15, 16, and 17) created during the 2022-2025 renovation. These holes feature massive waste bunkers, strategic water hazards, and undulating greens that form the most challenging closing stretch in Central Florida. Golfers who complete the Gauntlet can download a personalized certificate.' }, { question: 'Who designed Disney\'s Magnolia Golf Course?', answer: 'Joe Lee designed the original course, which opened in 1971. Ken Baker of One Club Limited led the major redesign completed in 2025, which reimagined four holes and renovated the entire layout while preserving the course\'s championship character.' }, { question: 'Can the public play Disney Magnolia?', answer: 'Yes. As a resort course operated by Arnold Palmer Golf Management, it is open to Walt Disney World resort guests and outside visitors. Green fees typically range from $99 to $199 depending on season and time of day.' }] },
    { id: 'orl-9', name: 'Ritz-Carlton Golf Club, Grande Lakes', slug: 'ritz-carlton-grande-lakes', city: 'Orlando', state: 'Florida', type: 'resort', rating: 4.4, greensFee: '$299–$375', architect: 'Greg Norman', yearBuilt: 2003, holes: 18, par: 72, yardage: 7122, description: 'Designed by Greg Norman, the Ritz-Carlton Golf Club at Grande Lakes is widely regarded as one of America\'s most luxurious resort golf experiences. The 7,122-yard par-72 layout features native wetlands, dramatic water carries, and a full caddie program.', highlights: ['Greg Norman championship design', 'Full caddie program at this five-star resort', 'GEO Certified sustainability designation'], imageAlt: 'Greg Norman-designed water carry hole at Ritz-Carlton Golf Club Grande Lakes Orlando', history: 'The Ritz-Carlton Golf Club at Grande Lakes opened in 2003 as part of the Grande Lakes Orlando resort complex. Greg Norman — a two-time British Open Champion — designed the layout after extensive study of the Central Florida landscape, choosing to preserve the region\'s natural wetlands and pine hammocks.\n\nThe course earned Golf Course Management\'s National Resort Course designation for environmental excellence, and carries GEO Certification for its ongoing sustainability practices. Since 2012 the course has hosted the PNC Father Son Challenge, pairing major champions with their children and bringing Tiger and Charlie Woods and other legendary pairings to Orlando each December.', signatureHoles: [{ hole: 7, par: 4, yardage: 437, description: 'A demanding right-to-left dogleg with a lake hugging the entire left side. The tee shot must carry a corner of the hazard to set up the approach, which plays to an elevated green with steep falloffs.' }, { hole: 15, par: 3, yardage: 197, description: 'This long par 3 plays across a broad lake to a peninsula green. Club selection varies significantly with Central Florida\'s afternoon winds.' }], whatToExpect: 'Ritz-Carlton Golf Club at Grande Lakes delivers the rare combination of luxury amenity and genuine course quality. Greg Norman\'s layout blends seamlessly with Central Florida\'s natural wetlands, so players encounter native birds and lush vegetation throughout. The conditioning is maintained to five-star standards, with the PNC Championship broadcast nationally each December showcasing the pristine playing surfaces.', playingTips: 'Afternoon thunderstorms are most common in summer — book morning tee times. Water comes into play on over half the holes; err toward the dry side. The back nine is generally more demanding; arrive with a comfortable score going into hole 10.', faqs: [{ question: 'Does the Ritz-Carlton Golf Club host professional events?', answer: 'Yes, the course hosts the annual PNC Father Son Challenge each December, pairing major champions with their children in a holiday tradition watched by millions on TV.' }, { question: 'Is the Ritz-Carlton Golf Club open to non-hotel guests?', answer: 'The course is accessible to non-hotel guests on a daily-fee basis, subject to availability. Hotel guests receive preferred access and rates.' }]},
  ],
  'tampa-florida': [
    { id: 'tam-1', name: 'Streamsong Resort - Black', slug: 'streamsong-black', city: 'Tampa', state: 'Florida', type: 'resort', rating: 4.8, greensFee: '$175–$300', architect: 'Gil Hanse', yearBuilt: 2017, holes: 18, par: 73, yardage: 7311, description: 'The newest course at Streamsong Resort, Gil Hanse\'s Black routing is the most dramatic and photographed of the three courses. Built on the highest point of the property, it features vertigo-inducing elevation changes and bold, strategic design.', highlights: ['Gil Hanse\'s dramatic design', 'Highest elevation on property', 'Florida\'s most photographed course'], imageAlt: 'Streamsong Black dramatic elevated hole with sand ridges', history: 'Streamsong Black was designed by Gil Hanse and Jim Wagner and opened in 2017 as the third course at Streamsong Resort. Hanse, fresh off designing the 2016 Olympic Golf Course in Rio de Janeiro, was given the highest and most rugged terrain on the former phosphate mine property, creating dramatic elevation changes almost unheard of in Florida golf.\n\nThe Black Course features a unique par of 73 with five par 5s and four par 3s. Hanse designed wide fairways that narrow at key landing areas, massive bunker complexes, and greens that reward precise approach play. The course also offers flexible 6-hole, 9-hole, and 12-hole loops, plus a practice area called The Roundabout. Streamsong Black has earned a place among Golf Digest\'s Top 100 courses in America.', signatureHoles: [{ hole: 3, par: 4, yardage: 423, description: 'One of the most dramatic holes in Florida golf. The tee shot plays over a massive sand ridge to a hidden fairway, then the approach climbs steeply uphill to an elevated green.' }, { hole: 7, par: 3, yardage: 178, description: 'A stunning downhill par 3 from an elevated tee offering panoramic views. The green is ringed by deep bunkers and wind is always a factor.' }, { hole: 9, par: 4, yardage: 450, description: 'A fantastic finishing hole for the front nine with bunkers on both sides and a well-defended green.' }, { hole: 15, par: 3, yardage: 131, description: 'A deceptively short par 3 that plays dramatically downhill. The angled, well-bunkered green makes club selection critical.' }], whatToExpect: 'Streamsong Black is the most exposed and rugged of the three Streamsong courses with dramatic elevation changes and a par-73 layout featuring five par 5s and four par 3s.\n\nGreen complexes are large and boldly contoured with false edges and fallaway slopes. Conditions are firm and fast, consistent with the links-like ethos of the resort.', playingTips: 'Study pin positions carefully as the preferred side of the fairway changes based on flag location. On downhill holes like the 3rd and 15th, trust the yardage. The Roundabout practice area is excellent for warming up.\n\nFlexible 6-hole, 9-hole, and 12-hole loops are available for shorter rounds.', faqs: [{ question: 'What makes Streamsong Black different from the Red and Blue?', answer: 'Black sits on the highest terrain with the most dramatic elevation changes and a unique par of 73 with five par 5s. Gil Hanse\'s design is bolder and more exposed than the Coore-Crenshaw Red or Tom Doak Blue.' }, { question: 'Can I play a shorter loop on Streamsong Black?', answer: 'Yes. The course offers flexible 6-hole, 9-hole, and 12-hole routing options in addition to the full 18.' }, { question: 'What is The Roundabout?', answer: 'A free-flowing practice area where golfers hit shots to various targets in an open field, rather than a traditional driving range.' }, { question: 'Is Streamsong Black the hardest of the three courses?', answer: 'It is generally the most visually intimidating due to elevation changes, but the par-73 layout with five par 5s can be forgiving if you play smart.' }] },
    { id: 'tam-2', name: 'Innisbrook Resort - Copperhead', slug: 'innisbrook-copperhead', city: 'Tampa', state: 'Florida', type: 'resort', rating: 4.6, greensFee: '$100–$250', architect: 'Larry Packard', yearBuilt: 1972, holes: 18, par: 71, yardage: 7340, description: 'Host of the Valspar Championship, Copperhead at Innisbrook is a demanding layout that winds through dense Florida forest. The infamous "Snake Pit" finishing holes (16-18) are among the toughest closing stretches on the PGA Tour.', highlights: ['Valspar Championship host', 'Infamous "Snake Pit" finish', 'Dense forest corridor design'], imageAlt: 'Innisbrook Copperhead Course dense forest hole near Tampa', history: 'The Copperhead Course at Innisbrook Resort was designed by Larry Packard and opened in the early 1970s in Palm Harbor, Florida. Copperhead winds through dense corridors of pine, cypress, and oak on rolling terrain unusual for the Gulf Coast.\n\nCopperhead has hosted a PGA Tour event since 2000, currently the Valspar Championship. The final three holes -- the "Snake Pit" -- rank among the toughest closing stretches on Tour.\n\nSalamander Hotels & Resorts maintains PGA Tour standards while keeping it playable for resort guests.', signatureHoles: [{ hole: 5, par: 4, yardage: 455, description: 'A demanding par 4 through a tight forest corridor.' }, { hole: 14, par: 3, yardage: 210, description: 'A long par 3 over water to a green in the forest.' }, { hole: 16, par: 4, yardage: 465, description: 'Start of the Snake Pit. Tight trees and a long approach.' }, { hole: 17, par: 3, yardage: 190, description: 'Snake Pit centerpiece. Par 3 over water to a bunker-surrounded green.' }], whatToExpect: 'Copperhead feels more like a Carolina mountain course than typical Florida. At 7,340 yards with par 71, accuracy off the tee is essential.\n\nThe Snake Pit (holes 16-18) provides championship-level challenge even from forward tees.', playingTips: 'Leave the driver in the bag on several holes. Accuracy trumps distance here.\n\nOn the Snake Pit, par is a great score. Take enough club on 17 to clear the water.', faqs: [{ question: 'Can the public play Copperhead?', answer: 'Yes. Green fees range from $100 to $250.' }, { question: 'What is the Snake Pit?', answer: 'Holes 16-18: two par 4s sandwich a par 3, one of the PGA Tour\'s toughest closes.' }, { question: 'When is the Valspar Championship?', answer: 'Typically March at Copperhead.' }, { question: 'How does Copperhead differ from typical Florida courses?', answer: 'Rolling, tree-lined terrain rather than flat layouts.' }] },
    { id: 'tam-3', name: 'TPC Tampa Bay', slug: 'tpc-tampa-bay', city: 'Tampa', state: 'Florida', type: 'public', rating: 4.3, greensFee: '$60–$130', architect: 'Bobby Weed & Chi Chi Rodriguez', yearBuilt: 1991, holes: 18, par: 71, yardage: 6898, description: 'Home of the PGA Tour Champions Constellation Energy Classic, TPC Tampa Bay offers accessible championship golf in Lutz. The flat Florida layout is enhanced by strategic water features and well-placed bunkers.', highlights: ['PGA Tour Champions venue', 'Public access TPC facility', 'Bobby Weed & Chi Chi Rodriguez design'], imageAlt: 'TPC Tampa Bay championship course with water features', history: 'TPC Tampa Bay opened in 1991 in Lutz, Florida, designed by PGA TOUR Chief Architect Bobby Weed with PGA Tour legend Chi Chi Rodriguez as player consultant. Rodriguez\'s flair and Weed\'s technical expertise produced a course earning a rating of 73.9 and slope of 139 from the tips — among the toughest in the Tampa Bay region.\n\nThe layout winds through approximately 88 bunkers, extensive natural wetlands, cypress heads, and lagoons that define nearly every hole. TPC Tampa Bay has hosted multiple PGA Tour Champions events, and Chi Chi Rodriguez helped promote the course as a public-access showcase in the greater Tampa area.', signatureHoles: [{ hole: 18, par: 4, yardage: 432, description: 'The most memorable finishing hole at TPC Tampa Bay. Water guards the left side from tee to green, and the approach must carry to a shallow green with sand protecting the right.' }, { hole: 12, par: 3, yardage: 175, description: 'One of several excellent one-shotters on the course, the 12th plays to a green nearly surrounded by water, demanding precise carry and club selection.' }], whatToExpect: 'TPC Tampa Bay delivers a tournament-caliber experience in a public-access setting. Bobby Weed\'s routing through native Florida wetlands creates an authentic sense of place, with wildlife sightings common throughout. The 88-plus bunkers keep every approach honest, while the lagoons and cypress heads add both beauty and peril.', playingTips: 'From the tips this is one of Tampa\'s hardest courses — most recreational golfers will enjoy the round more from the middle tees. Water comes into play on nearly every hole; err toward the dry side. The greens are large and subtly contoured — lag putting is essential.', faqs: [{ question: 'Is TPC Tampa Bay open to the public?', answer: 'Yes, TPC Tampa Bay is a public-access TPC facility open to all golfers, maintaining the conditioning and design standards of PGA TOUR venues.' }, { question: 'Who designed TPC Tampa Bay?', answer: 'Bobby Weed, the PGA TOUR\'s Chief Architect, designed the course with Chi Chi Rodriguez as player consultant. It opened in 1991 in Lutz, north of Tampa.' }]},
    { id: 'tam-4', name: 'World Woods Golf Club - Pine Barrens', slug: 'world-woods-pine-barrens', city: 'Tampa', state: 'Florida', type: 'public', rating: 4.5, greensFee: '$45–$90', architect: 'Tom Fazio', yearBuilt: 1993, holes: 18, par: 71, yardage: 6902, description: 'Often called the "Pine Valley of Florida," World Woods\' Pine Barrens course is a Tom Fazio design that brings a Pine Barrens New Jersey aesthetic to Central Florida. Sandy waste areas, pine straw-covered ground, and strategic design make this a bucket-list public course.', highlights: ['"Pine Valley of Florida" reputation', 'Tom Fazio sandy waste areas', 'Among Florida\'s best public values'], imageAlt: 'World Woods Pine Barrens sandy waste area and pine trees', history: 'World Woods Golf Club opened in 1993 in Brooksville, Florida, north of Tampa. Developer Yoshiho Nishikawa commissioned Tom Fazio to design two distinct 18-hole courses on a 1,300-acre property with rolling sandy terrain, dense pine forests, and natural waste areas virtually unknown in the Florida flatlands.\n\nFazio modeled Pine Barrens after Pine Valley Golf Club, letting the sandy soil and natural topography dictate the routing. Golf Week ranked Pine Barrens No. 26 on its list of America\'s Best Modern Courses, and Golf Magazine placed it among the top 20 in America. Today the property operates as Cabot Citrus Farms, further enhancing the facility while honoring Fazio\'s original vision.', signatureHoles: [{ hole: 4, par: 4, yardage: 443, description: 'Considered one of the finest par 4s in the Southeast, the 4th plays through a dramatic corridor of sand waste and towering pines. The bold, contoured green is defended by deep waste bunkers on both sides.' }, { hole: 15, par: 4, yardage: 462, description: 'The other signature hole at Pine Barrens is a long, demanding par 4 among the most visually striking in Florida. Towering pines frame a sandy waste area left of the fairway.' }], whatToExpect: 'Pine Barrens at World Woods delivers a uniquely un-Florida experience. The sandy waste areas, rolling terrain, and dense pine corridors are reminiscent of Pine Valley and Pinehurst rather than the typical flat Florida track. Tom Fazio\'s artistic best is on full display and the course plays firm and fast, rewarding thoughtful shot-making over power.', playingTips: 'Resist the urge to lay up from the sandy waste areas — Fazio designed them to be played from. The firm, fast conditions mean bump-and-run shots often work better than high approach shots. The back nine builds dramatically in difficulty.', faqs: [{ question: 'Is World Woods still open?', answer: 'The property now operates as Cabot Citrus Farms, which has preserved and enhanced Fazio\'s original courses while adding resort accommodations.' }, { question: 'How does Pine Barrens compare to Rolling Oaks?', answer: 'Pine Barrens is the more celebrated layout, ranked among the top courses in America for its bold, waste-area-laden design. Rolling Oaks is a gentler Fazio design offering a contrasting style on the same property.' }]},
    { id: 'tam-5', name: 'Saddlebrook Resort - Palmer Course', slug: 'saddlebrook-palmer', city: 'Tampa', state: 'Florida', type: 'resort', rating: 4.2, greensFee: '$60–$120', architect: 'Arnold Palmer', yearBuilt: 1986, holes: 18, par: 71, yardage: 6469, description: 'The Arnold Palmer-designed course at Saddlebrook Resort offers a classic Florida resort golf experience in Wesley Chapel. The layout winds through cypress stands and around several lakes, with Palmer\'s signature aggressive bunkering throughout.', highlights: ['Arnold Palmer design', 'Classic Florida resort experience', 'Cypress and lake-lined layout'], imageAlt: 'Saddlebrook Palmer Course cypress-lined fairway near Tampa', history: 'Saddlebrook Resort formally opened in 1981 in Wesley Chapel, north of Tampa, developed by Thomas L. Dempsey with a vision of creating a unique car-free walking village resort amid Florida\'s natural landscape. The original Saddlebrook Course was designed by Ed Seay and Dean Refram and opened in 1976. Arnold Palmer was later hired to remodel that original course and subsequently designed the second layout, now known as the Palmer Course, which opened in 1986.\n\nThe Palmer Course became home to the Arnold Palmer Golf Academy, one of the premier golf instruction programs in the country. The resort\'s 480-acre property encompasses two championship courses, world-class tennis facilities, and a spa, making it a comprehensive sports resort.\n\nSaddlebrook has undergone a massive $92 million transformation in recent years, revitalizing both golf courses and the resort facilities. The renovation aims to modernize the playing experience while honoring the Palmer design legacy that has defined Saddlebrook golf for decades.', signatureHoles: [{ hole: 4, par: 4, yardage: 395, description: 'A dogleg par 4 that plays around a lake with cypress trees framing the approach. Palmer\'s aggressive bunkering guards the green, demanding a precise second shot.' }, { hole: 9, par: 4, yardage: 410, description: 'A strong finishing hole on the front nine with water along the left side. The approach must carry a bunker complex protecting the front of the green.' }, { hole: 13, par: 3, yardage: 175, description: 'A scenic par 3 over water to a green surrounded by cypress trees. The hole captures the essence of classic Florida golf with its natural beauty and strategic demand.' }, { hole: 18, par: 4, yardage: 420, description: 'A demanding finishing hole that requires a solid drive to set up an approach over water to the final green, providing a memorable conclusion to the round.' }], whatToExpect: 'The Palmer Course is a classic Florida resort layout winding through cypress stands and around numerous lakes on the 480-acre Saddlebrook property. At 6,469 yards from the tips with a par of 71, it is not overly long but demands accuracy around Palmer\'s trademark aggressive bunkering and water hazards.\n\nThe resort setting offers a relaxed, car-free walking village atmosphere. The course is walkable and provides a pleasant experience for golfers of all skill levels. Recent renovations have modernized the playing surfaces and facilities.', playingTips: 'Accuracy trumps distance on the Palmer Course. Many holes feature water hazards that come into play on approach shots, so knowing your carry distances is essential. When in doubt, favor the side away from water.\n\nThe Bermuda greens can be grainy, affecting both speed and break. Putts into the grain will be slower than expected, while downhill putts with the grain can be lightning fast. Read the grain by looking for the sheen on the putting surface.', faqs: [{ question: 'Can the public play the Saddlebrook Palmer Course?', answer: 'Yes. The Palmer Course is a resort course open to guests and outside play, with green fees typically ranging from $60 to $120.' }, { question: 'How many courses are at Saddlebrook?', answer: 'Saddlebrook features two 18-hole championship courses: the Saddlebrook Course (originally 1976) and the Palmer Course (1986), both designed or remodeled by Arnold Palmer.' }, { question: 'What is the Arnold Palmer Golf Academy?', answer: 'The Arnold Palmer Golf Academy at Saddlebrook is one of the premier golf instruction programs in the country, offering multi-day schools and individual lessons.' }, { question: 'Is Saddlebrook undergoing renovations?', answer: 'Yes. A $92 million resort transformation has been modernizing the golf courses and resort facilities, revitalizing the entire 480-acre property.' }] },
    { id: 'tam-7', name: 'Lake Jovita Golf & Country Club', slug: 'lake-jovita', city: 'Tampa', state: 'Florida', type: 'semi-private', rating: 4.3, greensFee: '$65–$120', architect: 'Tom Lehman & Kurt Sandness', yearBuilt: 2000, holes: 18, par: 72, yardage: 7154, description: 'North of Tampa in Dade City, Lake Jovita offers surprisingly hilly terrain for Florida golf. The Tom Lehman design winds through rolling sandhills and mature oaks, delivering an experience that feels more like the Carolina Sandhills than the Sunshine State.', highlights: ['Unusually hilly Florida terrain', 'Tom Lehman design', 'Carolina Sandhills feel in Florida'], imageAlt: 'Lake Jovita rolling hills and oak-lined fairway north of Tampa', history: 'Lake Jovita Golf and Country Club opened its South Course in 1999 in Dade City, Florida, approximately 35 miles north of Tampa. PGA Tour star and 1996 Player of the Year Tom Lehman co-designed the layout with architect Kurt Sandness, creating a 36-hole facility on terrain that stunned visitors accustomed to flat Florida courses.\n\nThe South Course features 140 feet of elevation change — extraordinary by Florida standards — with the 11th hole famously dropping 94 feet from tee box to landing area, the largest single-hole elevation change of any hole in Florida. Lake Jovita earned Golf Digest\'s 4.5-star rating and a Top 10 ranking among Florida places to play.', signatureHoles: [{ hole: 11, par: 5, yardage: 570, description: 'The most dramatic hole in Florida drops 94 feet from tee to landing area, creating a breathtaking roller-coaster ride down the hillside. The approach back uphill requires careful club selection to avoid running through the putting surface.' }, { hole: 18, par: 4, yardage: 448, description: 'A strong finisher that plays from an elevated tee down a tree-lined fairway to a demanding approach uphill to the clubhouse green. The sweeping views of the rolling property make this a memorable conclusion.' }], whatToExpect: 'Lake Jovita is Florida\'s great surprise — a hilly, tree-lined course that feels more like the Carolina Sandhills than the Sunshine State. Tom Lehman\'s design uses the natural topography to create distinct, memorable holes. Elevation changes affect both club selection and shot shape throughout the round.', playingTips: 'The dramatic elevation changes affect ball flight more than typical Florida courses — club up on uphill approaches and down on downhill shots. The 11th tee offers one of the best views in Florida golf. Morning tee times are preferred to beat afternoon heat. The South Course is the more acclaimed layout.', faqs: [{ question: 'What makes Lake Jovita unique in Florida?', answer: 'Lake Jovita has 140 feet of elevation change — virtually unheard of in Florida — including the 11th hole\'s 94-foot drop, the largest single-hole elevation change of any hole in the state.' }, { question: 'Who designed Lake Jovita?', answer: 'PGA Tour star Tom Lehman and architect Kurt Sandness co-designed both the South Course (1999) and North Course at Lake Jovita Golf and Country Club in Dade City, FL.' }]},
    { id: 'tam-8', name: 'Concession Golf Club', slug: 'concession-golf-club', city: 'Tampa', state: 'Florida', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 2006, holes: 18, par: 72, yardage: 7474, description: 'Named for Jack Nicklaus\'s famous 1969 Ryder Cup concession to Tony Lika, this Jack Nicklaus design in Bradenton hosted the 2021 WGC-Workday Championship. The 7,474-yard layout features some of the boldest bunkering and most dramatic elevation changes in Southwest Florida.', highlights: ['Hosted 2021 WGC-Workday Championship', 'Jack Nicklaus signature design', 'Named for Nicklaus\'s famous 1969 concession'], imageAlt: 'Concession Golf Club Jack Nicklaus championship layout near Tampa', history: 'Concession Golf Club takes its name from Jack Nicklaus\'s famous concession of a short putt to Tony Jacklin at the 1969 Ryder Cup at Royal Birkdale. Nicklaus designed the course in Bradenton, Florida, and it opened in 2006 on rolling terrain unusual for Southwest Florida.\n\nIn 2021, Concession hosted the WGC-Workday Championship, won by Collin Morikawa. The course will also host the 2026 Senior PGA Championship.', signatureHoles: [{ hole: 1, par: 4, yardage: 428, description: 'A slight dogleg left requiring a precise tee shot to set up the approach.' }, { hole: 7, par: 5, yardage: 606, description: 'A long risk-reward par 5. Viktor Hovland eagled this hole during the 2021 WGC.' }, { hole: 14, par: 3, yardage: 195, description: 'A par 3 over water to a green defended by bold bunkering.' }, { hole: 18, par: 4, yardage: 465, description: 'A demanding finishing hole requiring two strong shots.' }], whatToExpect: 'Concession delivers world-class private golf on rolling terrain unusual for Southwest Florida. Nicklaus\'s design features bold bunkering and dramatic elevation changes. At 7,474 yards it is a serious championship test.', playingTips: 'Elevation changes affect club selection significantly. Nicklaus\'s deep bunkers are the primary defense -- play away from them when possible.', faqs: [{ question: 'Can the public play Concession?', answer: 'No. It is an exclusive private club.' }, { question: 'What is the story behind the name?', answer: 'Named for Nicklaus\'s concession to Tony Jacklin at the 1969 Ryder Cup.' }, { question: 'What tournaments has it hosted?', answer: 'The 2021 WGC-Workday Championship and the upcoming 2026 Senior PGA Championship.' }] },
    { id: 'tam-9', name: 'Southern Hills Plantation Club', slug: 'southern-hills-plantation', city: 'Tampa', state: 'Florida', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Pete Dye', yearBuilt: 2005, holes: 18, par: 72, yardage: 7378, description: 'One of Pete Dye\'s final designs, Southern Hills Plantation in Brooksville features the architect\'s signature railroad ties, dramatic bunkering, and visual intimidation set amid rolling central Florida terrain. The challenging 7,378-yard layout is one of the longest in the Tampa Bay area.', highlights: ['One of Pete Dye\'s final designs', 'Signature railroad ties and bold bunkering', '7,378 yards — among Tampa Bay\'s longest'], imageAlt: 'Southern Hills Plantation Pete Dye bunkering in Brooksville near Tampa', history: 'Southern Hills Plantation Club opened in Brooksville, Florida, featuring a Pete Dye-designed course on rolling terrain unusual for the Florida Gulf Coast. The course stretches to over 7,300 yards, one of the longest Pete Dye designs in the state.\n\nDye took advantage of Brooksville\'s natural elevation changes to create dramatic ridge-top views with his trademark railroad ties, island-style greens, and demanding forced carries.\n\nIn 2026, Heritage Golf Group acquired the club, bringing additional resources and expanded access.', signatureHoles: [{ hole: 6, par: 3, yardage: 195, description: 'A demanding par 3 with a Dye island-style green surrounded by bunkers.' }, { hole: 11, par: 4, yardage: 440, description: 'A strong par 4 using the rolling terrain for dramatic elevation change.' }, { hole: 15, par: 5, yardage: 570, description: 'A risk-reward par 5 with Dye\'s characteristic railroad ties and bunkering.' }, { hole: 18, par: 4, yardage: 450, description: 'A demanding finishing hole with elevation change and a challenging Dye green complex.' }], whatToExpect: 'Pete Dye championship golf on rolling terrain that feels more like the Carolinas than typical Florida. Dramatic elevation changes and ridge-top views set it apart.\n\nAt 7,378 yards, it is one of the longest Pete Dye courses in Florida.', playingTips: 'Dye\'s greens are the primary defense. Study contours and bail-out areas before each approach.\n\nElevation changes affect club selection more than expected in Florida.', faqs: [{ question: 'Can the public play?', answer: 'Southern Hills Plantation is a private club.' }, { question: 'Who designed the course?', answer: 'Pete Dye, one of his final designs.' }, { question: 'What makes it unusual for Florida?', answer: 'Rolling Brooksville terrain provides dramatic elevation changes uncommon in Florida.' }] },
    { id: 'tam-10', name: 'Streamsong Resort - Red', slug: 'streamsong-red', city: 'Bowling Green', state: 'Florida', type: 'resort', rating: 4.8, greensFee: '$175–$325', architect: 'Bill Coore & Ben Crenshaw', yearBuilt: 2012, holes: 18, par: 72, yardage: 7050, description: 'Built on a former phosphate mine south of Tampa, Streamsong Red is a Coore & Crenshaw masterpiece that transformed industrial wasteland into one of America\'s most acclaimed golf courses. The rolling sand dunes, native grasses, and treeless landscape create a uniquely links-like experience in the heart of Florida.', highlights: ['Coore & Crenshaw links masterpiece on former mine', 'Top-50 ranked public course in America', 'Revolutionary Florida links landscape'], imageAlt: 'Streamsong Red links-style fairway through sand dunes in central Florida', history: 'Streamsong Red was designed by Bill Coore and Ben Crenshaw and opened in 2012 on a former phosphate mining site in Polk County, Florida. The mining operations created dramatic sand ridges and rolling terrain unlike anything else in the flat Sunshine State. Coore and Crenshaw routed 18 holes through the most dramatic dune formations on the property.\n\nThe course debuted in Golf Digest\'s Top 100 and ranks among the top public courses in America. Tom Doak\'s Blue Course opened simultaneously in 2012, followed by Gil Hanse\'s Black Course in 2017. The Coore and Crenshaw minimalist philosophy is on full display, with the course feeling as though it has existed for decades.', signatureHoles: [{ hole: 16, par: 3, yardage: 208, description: 'A stunning Biarritz-style par 3 with a deep swale through the center of a long, narrow green. Sand ridges frame the hole and hitting the correct tier is essential to avoid three-putts.' }, { hole: 7, par: 5, yardage: 527, description: 'A beautifully designed par 5 that sweeps left through rolling dune terrain. The green complex offers multiple pin positions that change the strategy for the approach.' }, { hole: 1, par: 4, yardage: 464, description: 'A strong opening par 4 that plays gently uphill through sand ridges with a wide fairway and elevated green.' }, { hole: 12, par: 4, yardage: 472, description: 'One of the toughest holes on the course, this long par 4 often plays into the prevailing wind with a narrow fairway flanked by deep bunkers.' }], whatToExpect: 'Streamsong Red delivers a links-style experience unlike anything else in Florida. The former phosphate mine created towering sand ridges, rolling fairways, and a treeless landscape. Conditioning is excellent with firm, fast surfaces that encourage bump-and-run shots. Wind is a significant factor on the exposed layout.', playingTips: 'Embrace the ground game at Streamsong Red. The firm conditions reward bump-and-run approaches. The wind is a constant factor, so bring knockdown shots and plan for extra clubs into the breeze. The Biarritz green on the 16th is a must-experience moment.', faqs: [{ question: 'Which Streamsong course should I play if I can only play one?', answer: 'Most golfers and critics give a slight edge to Streamsong Red as the best of the three, though all three are exceptional.' }, { question: 'Is Streamsong Red walkable?', answer: 'Yes, and walking is encouraged. Caddies are available and recommended for first-time visitors.' }, { question: 'How far is Streamsong from Orlando or Tampa?', answer: 'Streamsong is approximately 90 minutes south of Orlando and about 75 minutes southeast of Tampa.' }, { question: 'What makes Streamsong Red different from the Blue and Black courses?', answer: 'Red features the most dramatic sand ridges with a Coore and Crenshaw minimalist approach. Blue (Tom Doak) offers wider fairways, while Black (Gil Hanse) is the most exposed and rugged.' }] },
    { id: 'tam-11', name: 'Streamsong Resort - Blue', slug: 'streamsong-blue', city: 'Bowling Green', state: 'Florida', type: 'resort', rating: 4.7, greensFee: '$175–$325', architect: 'Tom Doak', yearBuilt: 2012, holes: 18, par: 72, yardage: 7077, description: 'Tom Doak\'s companion course to Streamsong Red, the Blue features equally stunning sand-dune terrain with Doak\'s signature minimalist approach. The wide fairways and creative green complexes reward strategic thinking and ground-game creativity in a setting that rivals the great links of the British Isles.', highlights: ['Tom Doak minimalist links design', 'Wide fairways and creative green complexes', 'Former phosphate mine sand-dune terrain'], imageAlt: 'Streamsong Blue Tom Doak minimalist fairway through Florida sand dunes', history: 'Streamsong Blue was designed by Tom Doak and opened alongside the Red Course in 2012 on a former phosphate mining site owned by The Mosaic Company in Polk County, Florida. The mining left behind massive sand ridges that Doak recognized as extraordinary golf terrain -- the central portion with the tallest formations was allocated to the Blue Course.\n\nDoak routed the course through the most dramatic landforms, creating a layout that feels more like Ireland than Central Florida. Bill Coore first visited the property and recognized its potential, leading to parallel development of both courses.\n\nStreamsong Blue has been consistently ranked among the top public courses in America. Together with Red (Coore and Crenshaw) and Black (Gil Hanse, opened 2017), the resort offers three world-class courses on transformed industrial land.', signatureHoles: [{ hole: 1, par: 4, yardage: 330, description: 'A short, drivable par 4 with stunning views across the sand-dune landscape. One of the most enjoyable openers in Florida golf.' }, { hole: 7, par: 3, yardage: 145, description: 'A short par 3 with one of the most fascinating green complexes on the course. Dramatic contours make pin position critical despite the modest yardage.' }, { hole: 12, par: 4, yardage: 408, description: 'One of the best holes on the course. A strategic tee shot sets up a unique approach through natural sand-dune terrain.' }, { hole: 16, par: 3, yardage: 237, description: 'A long, demanding par 3 that begins a challenging closing stretch. Demands a precise long iron to find the green.' }], whatToExpect: 'Streamsong Blue delivers a links-style experience on terrain that seems impossible for Florida. Doak\'s minimalist design lets the former phosphate mine sand ridges create natural drama, with wide fairways and bold green complexes.\n\nConditions are typically firm and fast, rewarding the ground game. Wind is a constant factor on this exposed, treeless layout. Caddies are available and recommended.', playingTips: 'Embrace the ground game. Doak designed the Blue to reward bump-and-run approaches. Firm conditions mean high-flying shots often bounce over greens, while low runners can use the contours to funnel toward pins.\n\nThe closing stretch from 16 through 18 is demanding. A caddie is invaluable for reading the creative green contours on a first visit.', faqs: [{ question: 'Which Streamsong course is the best?', answer: 'Opinions vary. Red often ranks slightly higher, but Blue is praised for creative green complexes and Black for its rugged character.' }, { question: 'How far is Streamsong from major airports?', answer: 'About 90 minutes south of Orlando and 75 minutes southeast of Tampa.' }, { question: 'Is Streamsong Blue walkable?', answer: 'Yes. Walking is encouraged and caddies are available.' }, { question: 'Was this really a phosphate mine?', answer: 'Yes. The Mosaic Company mined phosphate here for decades, creating the dramatic terrain.' }] },
    { id: 'tam-12', name: 'Westchase Golf Club', slug: 'westchase-golf-club', city: 'Tampa', state: 'Florida', type: 'public', rating: 4.1, greensFee: '$35–$70', architect: 'Lloyd Clifton', yearBuilt: 1992, holes: 18, par: 72, yardage: 6699, description: 'A solid public option in northwest Tampa, Westchase provides well-maintained golf at an accessible price point. The Lloyd Clifton design features water on 13 holes, mature landscaping, and a challenging but fair layout that keeps locals coming back for its consistent conditioning and friendly atmosphere.', highlights: ['Water features on 13 holes', 'Well-maintained public course in northwest Tampa', 'Accessible pricing with solid conditioning'], imageAlt: 'Westchase Golf Club water-lined fairway in northwest Tampa', history: 'Opened in 1992 as centerpiece of the Westchase community in northwest Tampa, designed by Lloyd Clifton with water on 13 holes.', signatureHoles: [{ hole: 6, par: 3, yardage: 175, description: 'Scenic par 3 over water.' }, { hole: 13, par: 4, yardage: 410, description: 'Demanding par 4 with water along one side.' }, { hole: 18, par: 4, yardage: 425, description: 'Strong finishing hole with water on approach.' }], whatToExpect: 'Well-maintained public golf with water on 13 holes. At 6,699 yards, it rewards accuracy over power.', playingTips: 'Water is the primary hazard. Play conservatively on unfamiliar holes.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Green fees $35 to $70.' }] },
  ],
  'miami-florida': [
    { id: 'mia-1', name: 'Trump National Doral - Blue Monster', slug: 'doral-blue-monster', city: 'Miami', state: 'Florida', type: 'resort', rating: 4.6, greensFee: '$150–$350', architect: 'Gil Hanse (renovation)', yearBuilt: 1962, holes: 18, par: 72, yardage: 7692, description: 'The iconic Blue Monster at Doral has been a South Florida landmark for over 60 years. Gil Hanse\'s comprehensive renovation modernized this classic layout while preserving its championship pedigree and the famous 18th hole.', highlights: ['Iconic Blue Monster layout', 'Gil Hanse renovation', 'Historic South Florida golf landmark'], imageAlt: 'Doral Blue Monster course iconic 18th hole in Miami', history: 'The Blue Monster at Doral was originally designed by Dick Wilson and Robert von Hagge and opened in 1962 as part of the Doral Resort in Miami. The course hosted PGA Tour events for decades, with the 18th hole becoming one of the most iconic finishes in professional golf.\n\nDonald Trump purchased the resort in 2012 and commissioned Gil Hanse to conduct a comprehensive renovation completed in 2014. Hanse extended the course to over 7,500 yards, created a new peninsula green on the 15th, and reimagined the 16th as a drivable par 4.\n\nThe Blue Monster remains one of the most famous courses in South Florida, attracting golfers seeking to test themselves on a storied championship layout.', signatureHoles: [{ hole: 1, par: 5, yardage: 600, description: 'Hanse extended the opener by 100 yards, making it a true three-shot par 5.' }, { hole: 15, par: 3, yardage: 170, description: 'Hanse created a peninsula green with water on three sides.' }, { hole: 16, par: 4, yardage: 325, description: 'Reimagined as a drivable par 4 with water left, creating exciting risk-reward.' }, { hole: 18, par: 4, yardage: 467, description: 'The iconic finishing hole. A dogleg-left with water guarding the entire left side.' }], whatToExpect: 'A long championship layout at over 7,500 yards from the tips. Hanse\'s renovation maintained trademark water hazards, deep bunkers, and Bermuda rough.\n\nSouth Florida wind makes the relatively flat course play much tougher than it appears.', playingTips: 'Wind management is crucial. Afternoon breezes can add two to three clubs. The Bermuda rough is thick, so keep it in the fairway.\n\nOn 18, avoid the water left at all costs -- bailout right is smarter unless confident in your draw.', faqs: [{ question: 'Can the public play the Blue Monster?', answer: 'Yes. Green fees range from $150 to $350.' }, { question: 'Does the PGA Tour still play at Doral?', answer: 'No. The Tour previously hosted events here for decades.' }, { question: 'Who originally designed the Blue Monster?', answer: 'Dick Wilson and Robert von Hagge in 1962. Gil Hanse renovated it in 2014.' }, { question: 'How long is the Blue Monster?', answer: 'Over 7,500 yards from the championship tees.' }] },
    { id: 'mia-2', name: 'Crandon Golf at Key Biscayne', slug: 'crandon-key-biscayne', city: 'Miami', state: 'Florida', type: 'public', rating: 4.4, greensFee: '$80–$180', architect: 'Robert von Hagge & Bruce Devlin', yearBuilt: 1972, holes: 18, par: 72, yardage: 7301, description: 'Set on the barrier island of Key Biscayne with Biscayne Bay and Atlantic Ocean views, Crandon is one of America\'s most scenic municipal courses. Saltwater lagoons, mangrove-lined fairways, and ocean breezes create a truly tropical golf experience.', highlights: ['Biscayne Bay and ocean views', 'Tropical barrier island setting', 'Among America\'s best municipal courses'], imageAlt: 'Crandon Golf Key Biscayne oceanside hole with bay views', history: 'Crandon Golf at Key Biscayne opened in 1972, designed by the celebrated architectural partnership of Robert von Hagge and Bruce Devlin. The course occupies a stunning barrier island setting within Crandon Park on Key Biscayne — just minutes from downtown Miami — surrounded by Biscayne Bay and the Atlantic Ocean.\n\nThe 7th hole earned the distinction of being named One of the Greatest Holes in Golf. The course hosted the Miccosukee Championship on the PGA Tour Champions circuit for over a decade. Golf Digest awarded the course four stars and recognized it among the Top 75 courses in the United States.', signatureHoles: [{ hole: 7, par: 4, yardage: 445, description: 'Named One of the Greatest Holes in Golf, the 7th is a sharp right-to-left dogleg where bold players can cut the corner over water for a short approach, while cautious players face a long second shot from the safe zone.' }, { hole: 18, par: 5, yardage: 548, description: 'The finishing hole has water along both sides of the fairway and a spectacular green complex open to Biscayne Bay. A risk-reward par 5 that invites aggressive play while punishing the errant shot.' }], whatToExpect: 'Crandon Golf at Key Biscayne offers a one-of-a-kind tropical golf experience. The barrier island setting surrounds the course with Biscayne Bay views, mangroves, and exotic wildlife, while the von Hagge/Devlin design provides a championship-caliber test. The trade winds off the Atlantic regularly affect club selection, adding a coastal element seldom found on public courses.', playingTips: 'The trade winds off Biscayne Bay affect club selection throughout — always check the wind direction before hitting. The 7th hole\'s aggressive corner carry is tempting but risky when wind is against you. Afternoon storms are frequent in summer — book a morning time.', faqs: [{ question: 'What famous hole is at Crandon Golf at Key Biscayne?', answer: 'The 7th hole, a 445-yard par 4 dogleg, has been named One of the Greatest Holes in Golf for its combination of scenic beauty, strategic challenge, and dramatic risk-reward decision.' }, { question: 'Has Crandon Golf hosted professional events?', answer: 'Yes, Crandon Golf at Key Biscayne hosted the PGA Tour Champions Miccosukee Championship for over a decade, earning national attention and Golf Digest\'s Top 75 ranking.' }]},
    { id: 'mia-3', name: 'The Biltmore Golf Course', slug: 'biltmore-miami', city: 'Miami', state: 'Florida', type: 'resort', rating: 4.3, greensFee: '$100–$200', architect: 'Donald Ross (restored)', yearBuilt: 1925, holes: 18, par: 71, yardage: 6803, description: 'A Donald Ross original at the legendary Biltmore Hotel in Coral Gables, this historic course has hosted presidents, celebrities, and the Miami Open. The 1925 design has been carefully restored to showcase Ross\'s strategic genius.', highlights: ['Historic 1925 Donald Ross design', 'Legendary Biltmore Hotel setting', 'Restored to original Ross specifications'], imageAlt: 'Biltmore Golf Course with iconic Biltmore Hotel tower in Coral Gables', history: 'The Biltmore Golf Course in Coral Gables is one of the oldest and most historically significant courses in South Florida. George Merrick, the visionary developer of Coral Gables, commissioned Donald Ross to design the No. 2 course as part of the grand Biltmore Hotel complex that opened in 1926. The course is part of Florida\'s Historic Golf Trail and associated with the hotel\'s National Historic Landmark designation.\n\nIn 2018-2019, architect Brian Silva led a restoration to return the course to the spirit of Ross\'s original 1925 design. The project reconstructed Ross-style bunkers, restored the green contours, and re-established the course\'s character as a classic early-century design.', signatureHoles: [{ hole: 3, par: 4, yardage: 390, description: 'A Ross classic with a gently bending fairway and a well-defended green featuring classic Ross bunkering — deep, sod-faced hazards positioned to catch pushed approach shots.' }, { hole: 16, par: 3, yardage: 165, description: 'One of Ross\'s finest one-shot holes at the Biltmore, with a well-contoured green that rewards the correctly shaped shot. The front-right false front is a classic Ross element.' }], whatToExpect: 'Playing The Biltmore Golf Course is a journey into early American golf history. Donald Ross\'s restored design challenges players with subtlety rather than length, emphasizing approach shot accuracy and precise putting on classic crowned and contoured greens. The backdrop of the historic Biltmore Hotel adds an atmosphere found nowhere else in South Florida.', playingTips: 'Ross designs reward the player who uses the ground game — bump-and-run approaches often work better than high-lofted shots. The crowned greens will reject approach shots that are even slightly off-line. Study the green contours before every putt — Ross built subtle undulations that cause the ball to curve on seemingly flat putts.', faqs: [{ question: 'Who designed The Biltmore Golf Course?', answer: 'Donald Ross designed the original course in 1925. Architect Brian Silva led a restoration in 2018-2019 to return it to Ross\'s original spirit.' }, { question: 'Is The Biltmore Golf Course on any historic registers?', answer: 'The Biltmore Hotel complex, including the golf course, is designated a National Historic Landmark. The course is also part of Florida\'s Historic Golf Trail.' }]},
    { id: 'mia-4', name: 'Jacaranda Golf Club - East', slug: 'jacaranda-east', city: 'Miami', state: 'Florida', type: 'public', rating: 4.1, greensFee: '$40–$80', architect: 'Mark Mahannah', yearBuilt: 1971, holes: 18, par: 72, yardage: 7175, description: 'A solid South Florida public option in Plantation, Jacaranda\'s East Course offers a well-maintained, tree-lined layout with enough challenge for competitive players. Water comes into play on 13 holes, demanding accurate approach shots.', highlights: ['Well-maintained public course', 'Water on 13 holes', 'Strong value in South Florida'], imageAlt: 'Jacaranda Golf Club East Course tree-lined fairway', history: 'Jacaranda Golf Club\'s East Course opened in 1971 in Plantation, Florida, in the Fort Lauderdale metro area, designed by Mark Mahannah. The 36-hole facility — East and West courses — quickly became one of the region\'s most popular daily-fee destinations.\n\nIn 2006, acclaimed architect Bobby Weed completed a comprehensive renovation of the East Course, introducing Paspalum tees and fairways — a salt-tolerant grass ideal for South Florida\'s conditions — paired with TifEagle Bermuda greens to produce a course that plays faster and firmer than in its original configuration. The renovation elevated Jacaranda East to first-class status in the South Florida market.', signatureHoles: [{ hole: 4, par: 4, yardage: 420, description: 'One of the East Course\'s strongest holes, the 4th requires a drive through a narrowed fairway corridor to set up a mid-iron approach to a green protected by Bobby Weed\'s renovated bunkering on both sides.' }, { hole: 12, par: 5, yardage: 545, description: 'A reachable par 5 that tempts players to go for the green in two, though water on the left side of the approach demands careful positioning off the tee.' }], whatToExpect: 'Jacaranda East offers a well-rounded South Florida golf experience on a course that benefits from Bobby Weed\'s 2006 renovation. The Paspalum fairways and TifEagle Bermuda greens provide excellent playing surfaces year-round. The wide variety of hole designs keeps the course interesting for all skill levels.', playingTips: 'The Paspalum fairways at Jacaranda play differently than standard Bermuda — the ball sits up nicely. Bobby Weed\'s renovated bunkers have steeper faces than the original design. Morning rounds avoid the afternoon winds that add difficulty to the finishing holes.', faqs: [{ question: 'What is the difference between Jacaranda East and West?', answer: 'The East Course (1971) was renovated by Bobby Weed in 2006, giving it Paspalum fairways and TifEagle greens with modernized bunkering. The West Course (1973) is the companion layout at this 36-hole Plantation, FL facility.' }, { question: 'Who designed Jacaranda Golf Club East Course?', answer: 'Mark Mahannah designed the original course in 1971. Bobby Weed completed a comprehensive renovation in 2006 that upgraded the turf, bunkers, and green complexes.' }]},
    { id: 'mia-5', name: 'The Surf Club Golf Course', slug: 'surf-club-golf', city: 'Miami', state: 'Florida', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Gil Hanse', yearBuilt: 2023, holes: 9, par: 36, yardage: 3200, description: 'The newest addition to Miami\'s elite golf scene, Gil Hanse designed this intimate 9-hole course at the Four Seasons Surf Club in Surfside. The seaside layout offers a refined, exclusive experience steps from the Atlantic.', highlights: ['Brand new Gil Hanse design', 'Four Seasons Surf Club location', 'Intimate 9-hole seaside layout'], imageAlt: 'Surf Club Golf Course seaside layout in Surfside Miami', history: 'The Surf Club Golf Course represents one of the most exclusive and intimate new golf experiences in South Florida. Gil Hanse, the acclaimed architect of the 2016 Rio Olympics course, was commissioned to create a 9-hole course at the iconic Four Seasons Hotel at The Surf Club in Surfside, Florida.\n\nThe Surf Club itself has a legendary history — opened in 1930, it was the social headquarters of Miami Beach\'s elite, hosting the Duke and Duchess of Windsor, Winston Churchill, and countless Hollywood celebrities. The hotel was redesigned by Pritzker Prize-winning architect Richard Meier and reopened in 2017. Hanse\'s 2023 golf addition brings championship design sensibility to an intimate format that complements the luxury property\'s storied heritage.', signatureHoles: [{ hole: 5, par: 4, yardage: 380, description: 'The mid-course challenge hole where Hanse\'s design philosophy is most evident: a strategic par 4 that rewards precise positioning over power, with the green complex featuring subtle contouring that characterizes his best work.' }, { hole: 9, par: 4, yardage: 355, description: 'The finishing hole plays toward the Atlantic with ocean views from the approach. Hanse designed the closing hole as a risk-reward opportunity — the bold line to the tight pin can be attempted, but a safe approach to the center of the green is always prudent.' }], whatToExpect: 'The Surf Club Golf Course is Miami\'s most exclusive golf experience — an intimate 9-hole sanctuary at one of the world\'s great luxury hotels. Gil Hanse\'s design brings architectural craft to a brief but memorable loop that captures the spirit of seaside golf. Ocean breezes, immaculate conditioning, and a historic setting combine to create something genuinely special.', playingTips: 'As a 9-hole course, The Surf Club is designed to be played twice through for a full 18-hole experience. The ocean breezes affect every shot — pay close attention to wind direction before club selection. Reserve tee times well in advance through the Four Seasons hotel as availability is extremely limited.', faqs: [{ question: 'Is The Surf Club Golf Course open to non-members?', answer: 'The Surf Club Golf Course is a private amenity for Four Seasons Hotel guests and members. Access is not available to the general public.' }, { question: 'Who designed The Surf Club Golf Course?', answer: 'Renowned architect Gil Hanse designed the 9-hole course, which opened in 2023 at the Four Seasons Hotel at The Surf Club in Surfside, Florida.' }]},
    { id: 'mia-6', name: 'Seminole Golf Club', slug: 'seminole-golf-club', city: 'Miami', state: 'Florida', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'Donald Ross', yearBuilt: 1929, holes: 18, par: 72, yardage: 7079, description: 'Widely regarded as the finest Donald Ross design in Florida and one of the top 10 courses in America, Seminole in Juno Beach is an oceanside masterpiece. The 2021 Walker Cup was the first competitive event held at the course in decades, bringing global attention to this ultra-exclusive layout.', highlights: ['Top 10 course in America', 'Donald Ross Florida masterpiece', 'Hosted 2021 Walker Cup'], imageAlt: 'Seminole Golf Club oceanside Donald Ross design in Juno Beach', history: 'Seminole Golf Club was incorporated in the spring of 1929, the brainchild of financier E.F. Hutton, who commissioned famed Scottish-born architect Donald Ross to design a course on a stunning dune-ridge property in Juno Beach, Florida. Ross started work immediately and the course officially opened on January 1, 1930. Ross routed 18 holes across two parallel dune ridges running north-south, making incredibly varied and efficient use of the natural terrain.\n\nThe club became a favorite winter retreat for America\'s golfing elite. Ben Hogan famously used Seminole as his pre-Masters tune-up course each spring, playing rounds alone in the wind-swept dunes to sharpen his game. Tom Doak has given the course his highest rating, underscoring its architectural significance.\n\nSeminole remained largely out of the competitive spotlight for decades until the 2021 Walker Cup brought global attention to the layout. The club has also undergone a major reconstruction project to restore Ross\'s original design intent, including rebuilding bunkers and greens to their original dimensions. Seminole is consistently ranked among the top 10 courses in America.', signatureHoles: [{ hole: 6, par: 4, yardage: 390, description: 'Famously known as Ben Hogan\'s favorite hole at Seminole. Hogan would prepare for tournaments by hitting approach shots to this green repeatedly. The hole demands a precise approach to a well-bunkered green.' }, { hole: 13, par: 3, yardage: 175, description: 'One of the most intimidating waterless par-3 tee shots on the course. Seven bunkers surround the green, and the coastal wind makes club selection a true test of judgment.' }, { hole: 17, par: 3, yardage: 197, description: 'Perhaps the most famous hole at Seminole and one of the most celebrated par 3s in world golf. The hole is brutally exposed to the ocean wind, and bunkers frame a green that demands an exacting tee shot.' }, { hole: 18, par: 4, yardage: 417, description: 'A strong finishing hole that plays hard against the Atlantic. The wind and strategic bunkering make par a satisfying score to close out a round at one of America\'s greatest courses.' }], whatToExpect: 'Seminole is a windswept, dune-lined masterpiece that feels unlike any other course in Florida. The layout moves through two prominent ridges, creating constant elevation change and visual drama. The par-72 course plays to approximately 7,079 yards from the tips with a coastal wind that is always a factor.\n\nThe experience is intimate and exclusive, with immaculate conditioning on Bermuda turf. Walking is the standard mode of play, and the club maintains an old-world atmosphere that emphasizes the quality of the golf above all else.', playingTips: 'Wind management is the single most important skill at Seminole. The prevailing ocean breeze affects every shot, and club selection must be adjusted constantly. The course plays dramatically different depending on wind direction.\n\nRoss\'s green complexes are the primary defense. Many greens are crowned and reject shots that miss the correct angle of approach. Hitting to the proper side of the fairway to set up the ideal approach angle is essential for scoring.', faqs: [{ question: 'Can the public play Seminole Golf Club?', answer: 'No. Seminole is an ultra-exclusive private club with no public access or resort play. It is one of the most difficult courses in America to access.' }, { question: 'What major events has Seminole hosted?', answer: 'Seminole hosted the 2021 Walker Cup, the first major competitive event held at the club in decades. It also hosted the 2021 Seminole Pro-Member, which was broadcast on television during the COVID-19 pandemic.' }, { question: 'Why did Ben Hogan love Seminole?', answer: 'Ben Hogan used Seminole as his annual pre-Masters preparation course. He valued the wind, the demanding shotmaking required, and the competitive conditions. Hole 6 was reportedly his favorite.' }, { question: 'Who designed Seminole Golf Club?', answer: 'Donald Ross designed Seminole, with the course opening on January 1, 1930. It is widely regarded as one of his finest works and among the greatest courses in America.' }] },
    { id: 'mia-7', name: 'PGA National Resort - Champion Course', slug: 'pga-national-champion', city: 'Miami', state: 'Florida', type: 'resort', rating: 4.5, greensFee: '$200–$375', architect: 'Tom Fazio & Jack Nicklaus', yearBuilt: 1981, holes: 18, par: 72, yardage: 7048, description: 'Home of The Honda Classic on the PGA Tour, PGA National\'s Champion Course features the infamous "Bear Trap" — three consecutive holes (15-17) considered among the most demanding stretches on Tour. The Fazio/Nicklaus design balances resort playability with championship teeth.', highlights: ['Honda Classic PGA Tour host', 'Infamous "Bear Trap" holes 15-17', 'Tom Fazio & Jack Nicklaus design'], imageAlt: 'PGA National Champion Course Bear Trap water hazard in Palm Beach Gardens', history: 'The Champion Course at PGA National was designed by George and Tom Fazio and opened November 17, 1981. It hosted the 1983 Ryder Cup and 1987 PGA Championship. Jack Nicklaus redesigned it in 1990, creating the infamous "Bear Trap" -- holes 15-17. Nicklaus refined the course again in 2002 and 2014.\n\nThe course has hosted the PGA Tour annually since 2007, currently the Cognizant Classic. The Bear Trap regularly decides tournament outcomes.\n\nAt just over 7,000 yards, it is a precision test rather than a brute-force challenge.', signatureHoles: [{ hole: 15, par: 3, yardage: 178, description: 'Start of the Bear Trap. Par 3 over water to a peninsula green.' }, { hole: 16, par: 4, yardage: 434, description: 'Bear Trap middle. Water on both tee shot and approach.' }, { hole: 17, par: 3, yardage: 178, description: 'Bear Trap closer. Another par 3 over water.' }, { hole: 18, par: 4, yardage: 440, description: 'Strong finish with water left after surviving the Bear Trap.' }], whatToExpect: 'A water-laden South Florida layout testing precision and nerve. Wind, water, and the Bear Trap make it demanding despite moderate yardage.\n\nFirst-class resort with excellent practice facilities and championship history.', playingTips: 'On both Bear Trap par 3s, take enough club and aim center. Pars win here.\n\nAfternoon wind dramatically affects club selection on the closing holes.', faqs: [{ question: 'What is the Bear Trap?', answer: 'Holes 15-17, named after Nicklaus. Two par 3s over water sandwich a par 4.' }, { question: 'Can the public play?', answer: 'Yes. Green fees $200-$375.' }, { question: 'What PGA Tour event is held here?', answer: 'The Cognizant Classic, typically late February.' }, { question: 'Who designed the Champion Course?', answer: 'George and Tom Fazio (1981), redesigned by Jack Nicklaus (1990, 2002, 2014).' }] },
    { id: 'mia-8', name: 'The Breakers Ocean Course', slug: 'breakers-ocean-course', city: 'Miami', state: 'Florida', type: 'resort', rating: 4.3, greensFee: '$175–$300', architect: 'Brian Silva', yearBuilt: 2000, holes: 18, par: 72, yardage: 6017, description: 'Part of the iconic Breakers Palm Beach resort, the Ocean Course was redesigned by Brian Silva in 2000 to create a playable yet strategic layout steps from the Atlantic. While shorter than most resort courses, the creative green complexes and coastal winds provide ample challenge.', highlights: ['Part of iconic Breakers Palm Beach', 'Steps from the Atlantic Ocean', 'Strategic Brian Silva design'], imageAlt: 'Breakers Ocean Course green with Atlantic Ocean visible in Palm Beach', history: 'The Ocean Course at The Breakers is recognized as Florida\'s oldest golf course, with origins dating to 1897 when Alexander H. Findlay laid out the original seaside links for Henry Morrison Flagler\'s Palm Beach resort. Flagler expanded the course to 18 holes in 1901, establishing continuous golf on the site for well over a century.\n\nOver the decades the course was updated several times, with notable work by Donald Ross in the 1920s and a redesign by Brian Silva in 2000 that reshaped the layout to create more strategic variety within the compact, oceanside footprint. Rees Jones completed a further renovation in 2018 that modernized the playing surfaces while honoring the historic coastal character.\n\nThe Breakers itself is one of America\'s most storied resorts, originally built by Flagler as a destination for America\'s elite. The Ocean Course remains a central part of the resort experience, offering guests the chance to play golf steps from the Atlantic on one of the most historic golf properties in the United States.', signatureHoles: [{ hole: 1, par: 4, yardage: 330, description: 'A short opening par 4 that eases players into the round with ocean breezes and views of the Atlantic. The green complex provides more challenge than the yardage suggests.' }, { hole: 5, par: 3, yardage: 155, description: 'A beautiful par 3 with ocean views and coastal winds that make club selection tricky. The well-bunkered green demands a precise tee shot despite the modest distance.' }, { hole: 10, par: 4, yardage: 385, description: 'A strategic par 4 where the ocean breeze typically affects ball flight. The approach to the green requires careful consideration of wind direction and pin position.' }, { hole: 18, par: 4, yardage: 350, description: 'A charming finishing hole that brings players back toward the iconic Breakers resort. The short par 4 rewards accuracy and provides a memorable visual conclusion to the round.' }], whatToExpect: 'The Ocean Course is a shorter layout at 6,017 yards but compensates with creative green complexes, strategic bunkering, and constant coastal winds off the Atlantic. The compact routing allows for a pleasant walking round within sight of one of America\'s most iconic resort hotels.\n\nDon\'t let the yardage fool you into thinking this is an easy course. Wind, firm greens, and Silva\'s creative design features create a genuine test of shotmaking and imagination. The resort atmosphere is elegant and the conditioning is excellent.', playingTips: 'Wind is the primary defense on the Ocean Course. Check conditions before teeing off and adjust your strategy accordingly. The prevailing ocean breeze can turn a short par 4 into a genuine challenge.\n\nThe greens feature creative contours that reward players who study the slopes. Lag putting is important as three-putts come quickly on these surfaces. Take advantage of the shorter holes to attack, but respect the wind on exposed holes near the ocean.', faqs: [{ question: 'Can the public play the Breakers Ocean Course?', answer: 'The Ocean Course is available to resort guests at The Breakers Palm Beach. Green fees typically range from $175 to $300 depending on season.' }, { question: 'How old is the Ocean Course?', answer: 'The course dates to 1897, making it Florida\'s oldest golf course. Alexander Findlay created the original layout for Henry Flagler\'s resort, and it has been in continuous operation since.' }, { question: 'Is the Ocean Course a walking course?', answer: 'Yes. The compact, flat layout is ideal for walking, and the resort encourages the walking experience along the oceanfront property.' }, { question: 'Does The Breakers have other golf courses?', answer: 'Yes. The Breakers also operates the Rees Jones Course, a par-72 layout located approximately 11 miles west of the resort, stretching to over 7,100 yards.' }] },
    { id: 'mia-9', name: 'Calusa Pines Golf Club', slug: 'calusa-pines', city: 'Miami', state: 'Florida', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Michael Hurdzan & Dana Fry', yearBuilt: 2001, holes: 18, par: 72, yardage: 7182, description: 'Hidden in Naples, Calusa Pines has quietly earned a reputation as one of Florida\'s finest private courses. The Hurdzan-Fry design routes through mature slash pines and wetlands, offering a surprisingly natural and strategic golf experience for Southwest Florida.', highlights: ['Top-rated private course in Southwest Florida', 'Natural pine and wetland setting', 'Hurdzan-Fry strategic design'], imageAlt: 'Calusa Pines slash pine-lined fairway in Naples Florida', history: 'Calusa Pines Golf Club opened in 2001 in Naples, Florida, designed by the acclaimed partnership of Michael Hurdzan and Dana Fry. The name references the ancient Calusa people who inhabited Southwest Florida for thousands of years. The course\'s construction involved carving through coral rock and cypress swamp, producing a landscape of dramatic undulation unique in flat South Florida.\n\nHurdzan and Fry\'s design was immediately celebrated for its extraordinary variety — no two consecutive holes play in the same direction. Links Magazine designated it a Modern Classic Course, and Golf Digest praised the course\'s incredible variety of holes with not one hole looking or feeling similar. It is consistently ranked among the best courses in Southwest Florida.', signatureHoles: [{ hole: 9, par: 4, yardage: 432, description: 'The most dramatic hole on the front nine is a cross-lake par 4 where the tee shot must clear the water hazard to find a narrow landing zone. The approach to the well-bunkered green demands precise distance control.' }, { hole: 18, par: 5, yardage: 512, description: 'The best finishing hole on the course is a reachable par 5 that builds excitement from tee to green, featuring great risk-reward architecture with a decision between laying up or attacking the green in two.' }], whatToExpect: 'Calusa Pines offers an exceptional private club experience that competes with any course in Florida for variety and design quality. Hurdzan and Fry\'s routing through ancient coral rock and cypress creates dramatic elevation changes genuinely surprising in flat Naples. Every hole is visually distinct and strategically different.', playingTips: 'The coral rock subsoil at Calusa Pines creates firm, fast conditions quite different from typical Florida courses — shots run out more than expected. The strategic short par 4s offer birdie opportunities for those who commit fully to the aggressive line. Green-reading is demanding throughout.', faqs: [{ question: 'How was Calusa Pines built on flat Florida terrain?', answer: 'Calusa Pines was literally blasted and carved from coral rock and cypress swamp, creating dramatic elevation changes that are unique in Southwest Florida.' }, { question: 'Is Calusa Pines Golf Club private?', answer: 'Yes, Calusa Pines is a private members-only club in Naples, Florida. Guest access is available only through member introduction.' }]},
  ],
  'atlanta-georgia': [
    { id: 'atl-1', name: 'East Lake Golf Club', slug: 'east-lake', city: 'Atlanta', state: 'Georgia', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Donald Ross / Rees Jones', yearBuilt: 1908, holes: 18, par: 72, yardage: 7346, description: 'The home of Bobby Jones and host of the PGA Tour Championship, East Lake is hallowed ground in American golf. The historic layout has been meticulously restored and enhanced, serving as the permanent home of the Tour Championship since 2004.', highlights: ['PGA Tour Championship host', 'Bobby Jones\' home course', 'Birthplace of the East Lake Foundation'], imageAlt: 'East Lake Golf Club historic course home of the Tour Championship in Atlanta', history: 'Established in 1904, East Lake Golf Club is Atlanta\'s oldest golf course and the historic home of Bobby Jones, who grew up playing the course as a boy. The original layout was designed by Tom Bendelow, then completely reworked by Donald Ross in 1913. Ross also designed a second course that opened in 1930.\n\nEast Lake hosted the 1963 Ryder Cup and the 1950 U.S. Women\'s Amateur, but by the 1980s the course and surrounding neighborhood had fallen into severe decline. In 1993, developer Tom Cousins purchased the club and launched a transformative revitalization. Rees Jones restored Donald Ross\'s original design in 1994, and the East Lake Foundation was created to uplift the surrounding community.\n\nSince 1998, East Lake has been the permanent home of the TOUR Championship, the season-ending event that crowns the FedExCup champion. The course has hosted legends from Tiger Woods to Rory McIlroy in dramatic finales.', signatureHoles: [{ hole: 2, par: 3, yardage: 205, description: 'A demanding par 3 over water that sets the tone early. The green is well-defended by bunkers and a fronting pond punishes anything short.' }, { hole: 6, par: 4, yardage: 525, description: 'A long, dogleg par 4 that plays as one of the most difficult holes during the Tour Championship. The drive must navigate a tight corridor before a lengthy approach.' }, { hole: 15, par: 3, yardage: 213, description: 'Home to what is believed to be the first island green in America, with a putting surface completely surrounded by water. One of the most dramatic shots on the PGA Tour.' }, { hole: 18, par: 5, yardage: 591, description: 'A reachable par 5 providing a thrilling finish. The hole doglegs around a lake with the green perched next to the water, creating birdie and eagle chances that have decided many FedExCup championships.' }], whatToExpect: 'East Lake is a classic Donald Ross parkland course set among rolling terrain and mature hardwoods in Atlanta. The layout stretches to 7,346 yards from championship tees and features Ross\'s trademark crowned greens, strategic bunkering, and natural terrain contours.\n\nThe course has a distinctly old-school feel with tree-lined fairways, gentle doglegs, and greens demanding precise iron play. Water comes into play on several holes, and the atmosphere is steeped in Bobby Jones history.', playingTips: 'Ross\'s crowned greens are the key defensive feature. Approach shots must be precise, as anything missing the green rolls off the convex surfaces into collection areas. Aim for green centers rather than chasing pins on edges.\n\nThe course rewards patience and course management. The par 4s are long and demanding, so making pars there and capitalizing on birdie opportunities at the par 5s is the formula for success.', faqs: [{ question: 'What is the connection between Bobby Jones and East Lake?', answer: 'Bobby Jones grew up at East Lake, learning the game on these fairways as a boy. He went on to win 13 major championships and complete the Grand Slam in 1930.' }, { question: 'Can the public play East Lake Golf Club?', answer: 'No. East Lake is private. The course is visible to the public during the annual TOUR Championship each September.' }, { question: 'What is the East Lake Foundation?', answer: 'Created alongside the golf club\'s restoration in the 1990s to revitalize the surrounding neighborhood through education, mixed-income housing, and community development. It has become a national model for community transformation.' }, { question: 'When is the Tour Championship held at East Lake?', answer: 'The TOUR Championship is held annually in late August or early September. It is the final event of the PGA Tour season and determines the FedExCup champion.' }] },
    { id: 'atl-2', name: 'Atlanta Athletic Club - Highlands', slug: 'aac-highlands', city: 'Atlanta', state: 'Georgia', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Robert Trent Jones Sr. / Rees Jones', yearBuilt: 1966, holes: 18, par: 72, yardage: 7527, description: 'Host of multiple major championships including the 2011 PGA Championship, Atlanta Athletic Club\'s Highlands Course is one of the Southeast\'s premier private clubs. The challenging layout through North Georgia pines has tested the game\'s best players.', highlights: ['Multiple major championship host', '2011 PGA Championship venue', 'Premier Southeast private club'], imageAlt: 'Atlanta Athletic Club Highlands Course through Georgia pines', history: 'Atlanta Athletic Club was founded in 1898 and moved to its current Johns Creek location in 1966, where Robert Trent Jones Sr. designed the Highlands and Riverside courses. Rees Jones later renovated the Highlands for championship play.\n\nThe Highlands has hosted the 1976 and 2011 PGA Championships, the 2001 PGA Championship, and the 2014 U.S. Amateur. Keegan Bradley won the 2011 PGA Championship here in dramatic fashion.\n\nAtlanta Athletic Club is one of the most historically significant private clubs in the Southeast.', signatureHoles: [{ hole: 7, par: 4, yardage: 470, description: 'A demanding par 4 through the pines requiring both length and accuracy.' }, { hole: 12, par: 3, yardage: 205, description: 'A challenging par 3 over water that has produced drama in major championships.' }, { hole: 15, par: 5, yardage: 555, description: 'A risk-reward par 5 with water guarding the green, pivotal in PGA Championship play.' }, { hole: 18, par: 4, yardage: 470, description: 'A demanding finishing hole that has decided multiple major championships.' }], whatToExpect: 'A championship-caliber course through North Georgia pines. At 7,527 yards, it is one of the longest championship venues in the Southeast.\n\nRees Jones\'s renovation created a stern test while maintaining strategic variety.', playingTips: 'Length matters on the Highlands. The long par 4s require consistent driving distance. However, accuracy in the pine corridors is equally important.\n\nThe greens are well-defended and require precise approach play.', faqs: [{ question: 'Can the public play?', answer: 'No. Atlanta Athletic Club is a private club.' }, { question: 'What championships has it hosted?', answer: 'The 1976 and 2011 PGA Championships, plus the 2014 U.S. Amateur, among others.' }, { question: 'Who designed the Highlands?', answer: 'Robert Trent Jones Sr. originally, with Rees Jones later renovating for championship play.' }] },
    { id: 'atl-3', name: 'TPC Sugarloaf', slug: 'tpc-sugarloaf', city: 'Atlanta', state: 'Georgia', type: 'semi-private', rating: 4.4, greensFee: '$80–$150', architect: 'Greg Norman', yearBuilt: 1999, holes: 18, par: 72, yardage: 7259, description: 'A Greg Norman Signature design in Duluth, TPC Sugarloaf offers accessible championship golf in Metro Atlanta. The rolling terrain and mature hardwoods create a peaceful setting for this former PGA Tour venue.', highlights: ['Greg Norman Signature design', 'Former PGA Tour venue', 'Accessible championship golf'], imageAlt: 'TPC Sugarloaf rolling fairway through hardwood forest near Atlanta', history: 'Opened in 1999 as a Greg Norman Signature design in Duluth, Georgia. Hosted the PGA Tour BellSouth Classic from 2000 to 2008.', signatureHoles: [{ hole: 7, par: 4, yardage: 455, description: 'A demanding par 4 through hardwoods.' }, { hole: 11, par: 3, yardage: 210, description: 'A challenging par 3 over water.' }, { hole: 15, par: 5, yardage: 540, description: 'A risk-reward par 5.' }, { hole: 18, par: 4, yardage: 450, description: 'Strong finisher climbing through hardwoods.' }], whatToExpect: 'Greg Norman design through rolling North Georgia hardwoods with TPC conditioning. At 7,259 yards, a serious test.', playingTips: 'Rolling terrain creates uneven lies. Greens can be fast.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Semi-private, $80-$150.' }, { question: 'PGA Tour history?', answer: 'BellSouth Classic 2000-2008.' }] },
    { id: 'atl-4', name: 'Echelon Golf Club', slug: 'echelon-golf', city: 'Atlanta', state: 'Georgia', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Rees Jones', yearBuilt: 2005, holes: 18, par: 72, yardage: 7379, description: 'One of Atlanta\'s newest premier private clubs, Echelon offers a Rees Jones design set on 340 acres of rolling North Georgia terrain. The course features dramatic elevation changes uncommon in Metro Atlanta and pristine conditioning.', highlights: ['Dramatic elevation changes', 'Rees Jones design on 340 acres', 'Premier new-generation Atlanta club'], imageAlt: 'Echelon Golf Club dramatic elevation change on North Georgia terrain', history: 'Echelon Golf Club opened in 2006 in Alpharetta, Georgia, designed by Rees Jones — the Open Doctor celebrated for his preparation of US Open venues including Bethpage Black. The course was originally conceived as the centerpiece of a luxury residential community and was branded as The Georgia Tech Golf Club in its early years.\n\nRees Jones built the layout on some of the steepest, most challenging terrain in metro Atlanta, creating dramatic elevation changes, powerful bunkering, and sweeping views unusual for metropolitan golf. At 7,558 yards from the tips with a par of 72, Echelon demands accurate, powerful golf throughout. The course is now accessible to non-members and has developed a reputation as one of Georgia\'s most difficult and visually impressive layouts.', signatureHoles: [{ hole: 13, par: 4, yardage: 462, description: 'One of Alpharetta\'s most dramatic golf holes, the 13th descends sharply from an elevated tee before climbing back to a plateau green with views of the surrounding Georgia hills.' }, { hole: 1, par: 4, yardage: 440, description: 'The opening hole signals the course\'s intention immediately — a demanding par 4 through a corridor of steep terrain requiring a drive that threads narrow landing areas to set up any realistic scoring opportunity.' }], whatToExpect: 'Echelon delivers an uncompromising championship experience in Atlanta\'s northern suburbs. Rees Jones\'s decision to build on demanding topography created a course that respects no handicap — powerful bunkering, bold elevation changes, and immense greens make this one of Georgia\'s most challenging tracks.', playingTips: 'Club selection is critical at Echelon — elevation changes affect carry distances significantly, especially on approach shots. The bentgrass greens tend to be firmer and faster than most Atlanta courses. Leave the ego at home and play a tee that lets you enjoy the course.', faqs: [{ question: 'Is Echelon Golf Club open to the public?', answer: 'Yes, Echelon Golf Club in Alpharetta, Georgia is accessible to non-members on a daily-fee basis, despite its origins as a luxury residential club.' }, { question: 'What is the difficulty of Echelon Golf Club?', answer: 'Echelon plays to 7,558 yards from the tips and is considered one of the most difficult courses in Georgia, with Rees Jones\'s design featuring demanding bunkering and large, contoured greens.' }]},
    { id: 'atl-5', name: 'Bobby Jones Golf Course', slug: 'bobby-jones-gc', city: 'Atlanta', state: 'Georgia', type: 'public', rating: 4.0, greensFee: '$25–$55', architect: 'Bob Cupp (redesign)', yearBuilt: 1932, holes: 9, par: 35, yardage: 3525, description: 'Named for Atlanta\'s most famous golfer, Bobby Jones GC is a lovingly redesigned 9-hole course and practice facility in Buckhead. The intimate layout offers a welcoming, walkable experience in the heart of the city.', highlights: ['Named for Bobby Jones', 'Heart of Buckhead location', 'Walkable 9-hole design'], imageAlt: 'Bobby Jones Golf Course in Buckhead Atlanta', history: 'Bobby Jones Golf Course has the longest legacy in Atlanta golf. The original course opened in 1932 in Buckhead, named for Atlanta\'s most celebrated golfer, Grand Slam champion Bobby Jones, who was born and raised in the city. For over 85 years the course served as Atlanta\'s primary public golf destination.\n\nIn 2017, Atlanta City Council approved a total renovation, commissioning Bob Cupp to create an entirely new golf experience on the historic site. Cupp\'s bold solution was a reversible nine-hole course: the same nine holes played in two different directions, creating two distinct 18-hole rounds from a single routing. The redesigned course opened on November 5, 2018, and is one of only four reversible golf courses in the United States. Seven sets of tees from approximately 3,200 to 7,300 yards make it accessible to all skill levels.', signatureHoles: [{ hole: 5, par: 4, yardage: 420, description: 'One of the strongest holes in the reversible configuration, the 5th plays to a well-positioned green using the natural Buckhead topography. In the reverse direction, the same corridor presents an entirely different strategic challenge.' }, { hole: 9, par: 3, yardage: 185, description: 'The finishing hole of the front nine plays over a natural depression to a demanding green. In the alternate routing, this hole becomes a short par 4 that opens the back nine with an inviting birdie opportunity.' }], whatToExpect: 'Bobby Jones Golf Course is Atlanta\'s most accessible and storied public golf experience. Bob Cupp\'s reversible design means regular visitors encounter a genuinely different course each time they play. The public pricing, wide range of tees, and historic Buckhead location make Bobby Jones a must-play for any Atlanta visitor.', playingTips: 'The reversible concept means that landmarks you used as aiming points on the front nine become misleading on the back nine — trust the yardage book. The seven tee options mean there is no excuse for playing from the wrong distance. The Buckhead location means parking can be limited on weekends — arrive early.', faqs: [{ question: 'What makes Bobby Jones Golf Course unique?', answer: 'Bobby Jones is one of only four reversible golf courses in the United States — the same nine holes are played in two different directions, creating two distinct 18-hole experiences.' }, { question: 'When was Bobby Jones Golf Course renovated?', answer: 'The course was completely redesigned by architect Bob Cupp and reopened in November 2018. The original course dated to 1932 and was Atlanta\'s first public golf facility.' }]},
    { id: 'atl-6', name: 'Peachtree Golf Club', slug: 'peachtree-golf-club', city: 'Atlanta', state: 'Georgia', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Robert Trent Jones Sr. & Bobby Jones', yearBuilt: 1948, holes: 18, par: 72, yardage: 7043, description: 'Co-designed by Bobby Jones and Robert Trent Jones Sr. in 1948, Peachtree is one of Atlanta\'s most prestigious private clubs and a shrine to the legacy of its co-founder. The rolling, tree-lined layout in Buckhead features bold bunkering and large, contoured greens.', highlights: ['Co-designed by Bobby Jones', 'One of Atlanta\'s most prestigious clubs', 'Robert Trent Jones Sr. collaboration'], imageAlt: 'Peachtree Golf Club tree-lined Buckhead fairway in Atlanta', history: 'Peachtree Golf Club was born from the collaboration of Bobby Jones, the legendary amateur who won the Grand Slam in 1930, and Robert Trent Jones Sr., who would become the most prolific golf course architect of the twentieth century. The course opened in 1948 in Atlanta\'s Buckhead neighborhood, with Jones envisioning a club that would recapture the magic of Augusta National, which he had co-founded in 1933.\n\nRobert Trent Jones had such deep respect for Bobby Jones that he began using his middle name professionally, reportedly saying there could only be one Bobby Jones in golf. The design reflects their shared philosophy of strategic golf, with wide fairways offering multiple routes but demanding precision on approach shots to the large, boldly contoured greens.\n\nPeachtree has maintained its intimate, exclusive character with approximately 225 members. The club remains one of the most respected private clubs in the American South, with rolling terrain, mature trees, and timeless design ensuring it ranks among the finest courses in Georgia.', signatureHoles: [{ hole: 2, par: 4, yardage: 445, description: 'A demanding par 4 showcasing the Jones and Jones design philosophy. Rolling terrain and strategic bunkering require two well-placed shots.' }, { hole: 10, par: 5, yardage: 519, description: 'A reachable par 5 opening the back nine with risk-reward. The rolling fairway leads to a well-defended green.' }, { hole: 12, par: 4, yardage: 486, description: 'Widely considered the best par 4 at Peachtree. The back tee sits just yards from Peachtree Road, and the hole reveals its character through a corridor of trees to a bold green.' }, { hole: 15, par: 3, yardage: 195, description: 'A beautiful par 3 defended by Robert Trent Jones\'s bold bunkering, with the mature tree canopy framing the hole.' }], whatToExpect: 'Peachtree is a classic, intimate private club in Buckhead. The Jones and Jones design emphasizes strategic play over brute length, with large, boldly contoured greens as the primary defense. With only about 225 members, the club maintains a quiet, unhurried atmosphere.\n\nThe course proves that great golf does not require extreme length -- thoughtful design and superb green complexes create a memorable test at any yardage.', playingTips: 'The greens are large and boldly contoured, making position more important than proximity. Hitting the correct portion of the green is essential to avoid three-putts.\n\nThe rolling terrain creates uneven lies throughout. Take time to assess your stance and adjust club selection. The course rewards thoughtful play over raw power.', faqs: [{ question: 'Can the public play Peachtree Golf Club?', answer: 'No. Peachtree is a very private club with approximately 225 members.' }, { question: 'What is the connection between the two Joneses?', answer: 'Bobby Jones the amateur champion and Robert Trent Jones Sr. the architect were not related. RTJ began using his middle name professionally out of respect for Bobby.' }, { question: 'How does Peachtree relate to Augusta National?', answer: 'Bobby Jones co-founded Augusta National in 1933 and later collaborated with RTJ Sr. on Peachtree in 1948, seeking to create another strategic masterpiece in Georgia.' }, { question: 'Who designed Peachtree?', answer: 'Bobby Jones and Robert Trent Jones Sr. collaborated on the design, which opened in 1948.' }] },
    { id: 'atl-7', name: 'Capital City Club - Crabapple', slug: 'capital-city-crabapple', city: 'Atlanta', state: 'Georgia', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 1993, holes: 18, par: 72, yardage: 7094, description: 'The suburban jewel of Capital City Club\'s multi-campus operation, Crabapple is a Jack Nicklaus design in Milton north of Atlanta. The course features rolling north Georgia terrain, strategic creek crossings, and Nicklaus\'s signature par-3 excellence.', highlights: ['Jack Nicklaus design', 'Rolling north Georgia terrain', 'Part of historic Capital City Club'], imageAlt: 'Capital City Club Crabapple Nicklaus-designed hole in north Atlanta', history: 'Capital City Club was founded in 1883, making it one of the oldest clubs in the South. The Crabapple campus opened in 1993 with a Jack Nicklaus-designed course in Milton, north of Atlanta.\n\nNicklaus routed the course through rolling North Georgia terrain with creek crossings and mature hardwoods, creating a course that rewards strategic play.', signatureHoles: [{ hole: 4, par: 3, yardage: 195, description: 'A demanding Nicklaus par 3 over water to a well-defended green.' }, { hole: 12, par: 4, yardage: 440, description: 'A strong par 4 with a creek crossing that tests driving accuracy.' }, { hole: 15, par: 5, yardage: 540, description: 'A risk-reward par 5 with water guarding the approach.' }, { hole: 18, par: 4, yardage: 445, description: 'A strong finishing hole through the North Georgia hardwoods.' }], whatToExpect: 'Jack Nicklaus championship design on rolling North Georgia terrain. At 7,094 yards, a serious test with creek crossings and strategic bunkering.\n\nPart of the historic Capital City Club, one of the oldest in the South.', playingTips: 'Creek crossings affect strategy on several holes. Play to the safe side of water hazards.\n\nNicklaus greens have significant contour. Reading the correct speed and break is essential.', faqs: [{ question: 'Can the public play?', answer: 'No. Capital City Club is private.' }, { question: 'How old is Capital City Club?', answer: 'Founded in 1883, one of the oldest clubs in the South. Crabapple campus opened 1993.' }, { question: 'Designer?', answer: 'Jack Nicklaus, opened 1993.' }] },
    { id: 'atl-8', name: 'Hawks Ridge Golf Club', slug: 'hawks-ridge-golf-club', city: 'Atlanta', state: 'Georgia', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Bob Cupp', yearBuilt: 2002, holes: 18, par: 72, yardage: 7207, description: 'A Bob Cupp design in Ball Ground north of Atlanta, Hawks Ridge occupies a stunning 500-acre property in the foothills of the Blue Ridge Mountains. The 7,207-yard layout features dramatic elevation changes through hardwood forest and mountain meadow, with panoramic north Georgia views from several elevated tees.', highlights: ['Bob Cupp design on 500 acres in Blue Ridge foothills', 'Dramatic elevation changes and mountain views', 'Exclusive north Georgia private club'], imageAlt: 'Hawks Ridge Golf Club mountain meadow fairway in Blue Ridge foothills near Atlanta', history: 'Hawks Ridge Golf Club in Ball Ground, Georgia, approximately 40 miles north of Atlanta, is widely considered the consummate achievement of golf course architect Bob Cupp\'s distinguished career. Cupp described the course as his best work, and Golf Digest ranked it among the Top 10 courses in Georgia within years of its opening.\n\nThe development vision for Hawks Ridge was to create an Augusta National for the 21st century — a private club of absolute quality in a spectacular natural setting. Cupp worked with the dramatic North Georgia hills and hardwood forests to produce a course of extraordinary visual beauty and strategic depth. The putting surfaces at Hawks Ridge earned widespread recognition as among the finest in Georgia.', signatureHoles: [{ hole: 15, par: 4, yardage: 333, description: 'The signature hole at Hawks Ridge is a dramatic short par 4 that presents one of golf\'s most compelling risk-reward decisions. A hero drive over the corner can leave a wedge to the green, but the bail-out area leaves a long, demanding second shot.' }, { hole: 7, par: 3, yardage: 215, description: 'From an elevated tee box with panoramic views of the North Georgia hills, the 7th demands a precise long iron or fairway wood to a well-bunkered green.' }], whatToExpect: 'Hawks Ridge is one of Georgia\'s finest private clubs — fulfilling its Augusta National for the 21st century ambition through extraordinary conditioning, architectural artistry, and a spectacular mountain setting. Bob Cupp\'s best work rewards thoughtful, creative golf.', playingTips: 'The dramatic terrain affects shots unfamiliar to flat-course players — uphill lies require extra club, downhill lies promote running shots. Note green complexes during the approach walk to understand undulations before putting. The 15th hole\'s aggressive line tempts every player.', faqs: [{ question: 'Is Hawks Ridge Golf Club accessible to non-members?', answer: 'Hawks Ridge is a private members-only club. Access is available only through member introduction or sponsored play.' }, { question: 'What is Hawks Ridge Golf Club\'s reputation?', answer: 'Hawks Ridge is considered Bob Cupp\'s consummate achievement. Golf Digest ranked it among the Top 10 courses in Georgia, celebrated for exceptional bentgrass greens and dramatic North Georgia setting.' }]},
    { id: 'atl-9', name: 'Château Élan Golf Club - Château Course', slug: 'chateau-elan-chateau', city: 'Atlanta', state: 'Georgia', type: 'resort', rating: 4.2, greensFee: '$70–$120', architect: 'Denis Griffiths', yearBuilt: 1989, holes: 18, par: 71, yardage: 7030, description: 'Part of the Château Élan Winery & Resort northeast of Atlanta, this Denis Griffiths design pairs north Georgia rolling terrain with a European winery atmosphere. The resort offers three courses total, making it one of the best multi-day golf destinations in the Atlanta area.', highlights: ['Winery resort setting', 'Three courses at one resort', 'Rolling north Georgia terrain'], imageAlt: 'Château Élan Golf Club with European winery backdrop near Atlanta', history: 'Château Élan is the creation of Donald and Nancy Panoz, who began developing the winery and resort property in Braselton, northeast of Atlanta, in the late 1980s. The Château Course, designed by Denis Griffiths, opened in 1989 as the resort\'s first golf offering. Griffiths crafted a championship layout that takes advantage of the rolling north Georgia terrain, with the European-style winery providing an elegant backdrop.\n\nThe resort expanded its golf offerings significantly over the years. The Woodlands Course, also designed by Denis Griffiths, opened in 1996. The Legends Course followed, featuring holes inspired by famous layouts worldwide, with input from golf legends Gene Sarazen, Kathy Whitworth, and Sam Snead alongside architect Griffiths.\n\nToday Château Élan encompasses a full winery, spa, and three distinct golf courses on a sprawling 3,500-acre property. The resort has hosted NFL Alumni events and numerous corporate tournaments, establishing itself as one of the premier golf resort destinations in the Southeast.', signatureHoles: [{ hole: 3, par: 4, yardage: 410, description: 'A dogleg par 4 that winds through mature hardwoods with the winery visible in the distance. The approach plays slightly downhill to a well-bunkered green.' }, { hole: 8, par: 3, yardage: 185, description: 'A scenic par 3 with a lake fronting the green. The north Georgia hills provide a picturesque backdrop while the water demands a confident tee shot.' }, { hole: 13, par: 5, yardage: 545, description: 'A risk-reward par 5 with rolling terrain that allows long hitters to reach in two. The green is defended by strategic bunkering and slopes.' }, { hole: 18, par: 4, yardage: 430, description: 'A demanding finishing hole that plays back toward the clubhouse with the winery estate framing the background. A solid drive is required to set up a mid-iron approach.' }], whatToExpect: 'The Château Course offers a unique combination of championship golf and European winery ambiance unlike anything else in the Atlanta area. The Denis Griffiths design stretches to 7,030 yards through rolling north Georgia terrain with mature hardwoods, lakes, and vineyard views.\n\nThe three courses at the resort provide enough variety for a multi-day golf getaway. Conditioning is solid for a resort course, and the pace of play is generally reasonable. After your round, the winery tasting room and spa are major draws.', playingTips: 'The rolling terrain creates uneven lies throughout the Château Course. Practice hitting from uphill, downhill, and sidehill positions before your round. The elevation changes also affect club selection significantly.\n\nThe greens are moderately paced but slope more than they appear. Read putts carefully, especially on the holes where the green sits on a hillside. Morning tee times are recommended in summer as north Georgia humidity can be intense.', faqs: [{ question: 'Can the public play the Château Course?', answer: 'Yes. The Château Course is a resort course open to guests and outside play, with green fees typically ranging from $70 to $120.' }, { question: 'How many courses are at Château Élan?', answer: 'The resort features three courses: the Château Course (1989), the Woodlands Course (1996), and the Legends Course, all designed by Denis Griffiths.' }, { question: 'Is there a winery at the resort?', answer: 'Yes. Château Élan is built around a working winery with tasting rooms, making it a unique golf-and-wine destination in the Southeast.' }, { question: 'How far is Château Élan from Atlanta?', answer: 'The resort is located in Braselton, approximately 50 miles northeast of downtown Atlanta, about a one-hour drive.' }] },
  ],
  'charlotte-north-carolina': [
    { id: 'clt-1', name: 'Quail Hollow Club', slug: 'quail-hollow', city: 'Charlotte', state: 'North Carolina', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'George Cobb / Tom Fazio', yearBuilt: 1961, holes: 18, par: 72, yardage: 7554, description: 'One of the PGA Tour\'s premier venues, Quail Hollow hosted the 2017 PGA Championship and the Presidents Cup. The "Green Mile" finishing stretch (holes 16-18) is one of the most demanding closes in championship golf.', highlights: ['2017 PGA Championship host', 'Presidents Cup venue', 'Infamous "Green Mile" finish'], imageAlt: 'Quail Hollow Club Green Mile holes in Charlotte', history: 'Quail Hollow Club was originally designed by George Cobb and opened in 1961 on what had been dairy farmland in south Charlotte, North Carolina. Cobb\'s vision included tree-lined fairways, strategically placed bunkering, and elevated putting surfaces. Arnold Palmer altered four holes in 1985, beginning the course\'s evolution toward championship status.\n\nTom Fazio became the club\'s architect starting in 1995 and carried out a major renovation in 1996 that fundamentally transformed the layout. Fazio\'s redesign gave Quail Hollow its contemporary character, including the creation of the famous Green Mile finishing stretch. Fazio Design has guided master planning at the club for over two decades, with additional renovation work completed ahead of the 2017 and 2025 PGA Championships.\n\nQuail Hollow has become one of the premier venues in championship golf. The club hosted the Wells Fargo Championship annually starting in 2003, the 2017 PGA Championship won by Justin Thomas, the 2022 Presidents Cup, and the 2025 PGA Championship. The Green Mile -- holes 16, 17, and 18 -- has been statistically the toughest three-hole finishing stretch on the PGA Tour.', signatureHoles: [{ hole: 16, par: 4, yardage: 529, description: 'The beginning of the infamous Green Mile. At 529 yards, this par 4 is one of the longest on the PGA Tour. Water guards the left side, and the green is perched above a creek.' }, { hole: 17, par: 3, yardage: 223, description: 'The middle of the Green Mile, a demanding par 3 over water to a green angled away from the tee. Club selection and nerve are tested in equal measure.' }, { hole: 18, par: 4, yardage: 494, description: 'The closing hole of the Green Mile. Water runs along the entire left side, and the approach must navigate bunkers and the creek to find a well-guarded green.' }, { hole: 1, par: 4, yardage: 367, description: 'A short, strategic opening par 4 that sets the tone. Despite modest yardage, the green is well-defended and demands a precise approach.' }], whatToExpect: 'Quail Hollow is a championship-caliber private club that plays through mature hardwood forests in south Charlotte. The Cobb/Fazio design stretches to 7,554 yards from the championship tees with a par of 72. The front nine is generally more scoreable, while the back nine ratchets up the difficulty dramatically.\n\nConditioning is exceptional, befitting a course that regularly hosts PGA Tour and major championship events. The green complexes are firm and fast, demanding precision on approach shots.', playingTips: 'The Green Mile demands respect. Playing holes 16-18 in even par is an excellent result. On 16, position off the tee is paramount given the extreme length. On 17, take enough club to reach the middle of the green. On 18, avoid the water left at all costs.\n\nThe front nine offers more birdie chances, so building a score early is essential. Approach shots must be hit to the correct tier of Fazio\'s multi-level greens throughout.', faqs: [{ question: 'Can the public play Quail Hollow?', answer: 'No. Quail Hollow is a private club with no public access. It is visible during PGA Tour telecasts of the Wells Fargo Championship.' }, { question: 'What is the Green Mile?', answer: 'The Green Mile refers to holes 16, 17, and 18 at Quail Hollow -- a brutally demanding finishing stretch that has been statistically the toughest three-hole close on the PGA Tour.' }, { question: 'What major championships has Quail Hollow hosted?', answer: 'Quail Hollow hosted the 2017 PGA Championship won by Justin Thomas, the 2022 Presidents Cup, and the 2025 PGA Championship. It also annually hosts the Wells Fargo Championship.' }, { question: 'Who designed Quail Hollow?', answer: 'George Cobb designed the original course in 1961. Arnold Palmer altered four holes in 1985. Tom Fazio became the club\'s architect in 1995 and has guided all major renovations since.' }] },
    { id: 'clt-2', name: 'The Peninsula Club', slug: 'peninsula-club', city: 'Charlotte', state: 'North Carolina', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Rees Jones', yearBuilt: 2000, holes: 18, par: 72, yardage: 7106, description: 'Set on a peninsula on Lake Norman north of Charlotte, this Rees Jones design offers one of the most scenic private golf experiences in the Carolinas. Lakeside holes and hardwood forests create a serene retreat from the Queen City.', highlights: ['Lake Norman peninsula setting', 'Scenic Rees Jones design', 'Premier Lake Norman private club'], imageAlt: 'The Peninsula Club on Lake Norman near Charlotte', history: 'Opened in 2000 on a Lake Norman peninsula north of Charlotte, designed by Rees Jones with multiple lakeside holes and hardwood forest corridors.', signatureHoles: [{ hole: 5, par: 4, yardage: 430, description: 'A lakeside par 4 with Lake Norman views.' }, { hole: 12, par: 3, yardage: 190, description: 'Scenic par 3 along the lake.' }, { hole: 16, par: 5, yardage: 545, description: 'Dramatic par 5 along Lake Norman.' }, { hole: 18, par: 4, yardage: 440, description: 'Strong lakeside finishing hole.' }], whatToExpect: 'One of the most scenic private courses in the Carolinas with Lake Norman backdrop. At 7,106 yards, a serious test.', playingTips: 'Wind off Lake Norman affects lakeside holes. Forest holes demand accuracy through tight corridors.', faqs: [{ question: 'Can the public play?', answer: 'No. Private club.' }, { question: 'Designer?', answer: 'Rees Jones, 2000.' }] },
    { id: 'clt-3', name: 'Trump National Golf Club Charlotte', slug: 'trump-charlotte', city: 'Charlotte', state: 'North Carolina', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Greg Norman', yearBuilt: 2012, holes: 18, par: 72, yardage: 7267, description: 'A Greg Norman design built on Lake Norman\'s shoreline, this club features 23 holes (18-hole championship + 5-hole short course) with dramatic lakefront views and premium conditioning.', highlights: ['Greg Norman lakefront design', '23 total holes', 'Lake Norman shoreline setting'], imageAlt: 'Trump National Charlotte lakefront hole on Lake Norman', history: 'The property that became Trump National Golf Club Charlotte was originally developed as The Point Golf Club, with a Greg Norman-designed course opening in 1999 in Mooresville, North Carolina, along the shores of Lake Norman. The layout was built within a luxury residential community north of Charlotte.\n\nIn 2012, the Trump Organization acquired the property and renamed it Trump National Golf Club Charlotte. Significant renovations and enhancements followed, expanding the facility to 23 total holes including the 18-hole championship course and a 5-hole short course. The championship layout was stretched to 7,495 yards from the back tees.\n\nThe club sits on prime Lake Norman waterfront with over a mile of shoreline, providing dramatic views and several holes that play along or near the lake. The Greg Norman design emphasizes wide fairways with strategic bunkering and challenging green complexes.', signatureHoles: [{ hole: 4, par: 3, yardage: 210, description: 'A stunning par 3 that plays directly toward Lake Norman. The water backdrop creates one of the most scenic tee shots in the Charlotte area.' }, { hole: 10, par: 4, yardage: 445, description: 'A demanding par 4 along the lakefront with water visible throughout. The approach requires precision to avoid strategic bunkering.' }, { hole: 15, par: 5, yardage: 570, description: 'A risk-reward par 5 with Lake Norman views. Long hitters can reach in two but must navigate bunkers and slopes protecting the green complex.' }, { hole: 18, par: 4, yardage: 460, description: 'A strong finishing hole that plays back toward the clubhouse with lake views. The demanding par 4 requires two quality shots to reach the well-defended green.' }], whatToExpect: 'Trump National Charlotte is a meticulously maintained private club with premium conditioning throughout. The Greg Norman design features wide Bermuda fairways and challenging green complexes across rolling terrain along Lake Norman. Multiple tee options accommodate all skill levels.\n\nThe 5-hole short course provides a unique practice and casual play option. The lakefront clubhouse and facilities are upscale.', playingTips: 'Norman\'s design rewards strategic thinking over raw power. The wide fairways invite aggressive tee shots, but position matters for approach angles into the greens. Several holes feature false fronts and runoff areas that punish short approaches.\n\nLake Norman can create breezy conditions, especially on the lakefront holes. Factor in wind when selecting clubs on exposed holes. The Bermuda greens can be grainy, so pay attention to grain direction when putting.', faqs: [{ question: 'Can the public play Trump National Charlotte?', answer: 'No. Trump National Golf Club Charlotte is a private club requiring membership.' }, { question: 'Who designed the golf course?', answer: 'Greg Norman designed the original course, which opened in 1999 as The Point Golf Club. The Trump Organization acquired and enhanced the property in 2012.' }, { question: 'How many holes are there?', answer: 'The club features 23 total holes: an 18-hole championship course and a 5-hole short course.' }, { question: 'Where is the club located?', answer: 'The club is in Mooresville, North Carolina, on the shores of Lake Norman, approximately one hour north of Charlotte.' }] },
    { id: 'clt-4', name: 'Rocky River Golf Club', slug: 'rocky-river', city: 'Charlotte', state: 'North Carolina', type: 'public', rating: 4.2, greensFee: '$35–$65', architect: 'Dan Maples', yearBuilt: 2000, holes: 18, par: 72, yardage: 6900, description: 'A Dan Maples design in Concord, Rocky River is a strong public option for Charlotte-area golfers. The course features a varied routing through meadows, hardwoods, and along Rocky River, offering diversity and value.', highlights: ['Strong Charlotte public option', 'Dan Maples design', 'Varied terrain and routing'], imageAlt: 'Rocky River Golf Club fairway near Charlotte North Carolina', history: 'Rocky River Golf Club opened in 1997 in Concord, North Carolina, designed by Dan Maples — one of the Carolinas\' most prolific and respected golf course architects, known for designs including Pinehurst No. 9. The course is routed through rocky hills and natural wetlands adjacent to Charlotte Motor Speedway.\n\nMaples utilized the rolling, rocky terrain to create a course of genuine character with diverse hole types flowing through forests, wetlands, and open meadows. At 6,970 yards from the tips (rating 73.5, slope 137), Rocky River offers a genuine championship challenge. Sports Illustrated gave it an 8.5 review score, praising the design\'s use of natural features.', signatureHoles: [{ hole: 3, par: 5, yardage: 555, description: 'The signature hole at Rocky River winds through the rocky terrain with a demanding two-shot corridor. Natural rock outcroppings and diverse hazards make it one of the most memorable par 5s in North Carolina.' }, { hole: 14, par: 4, yardage: 430, description: 'A strong mid-round test that plays through a narrow tree-lined corridor to a well-protected green. The back nine is more demanding, and the 14th exemplifies Maples\'s ability to create difficulty through strategic placement.' }], whatToExpect: 'Rocky River is one of the better values in the Charlotte golf market — a genuine championship test by a respected Carolina architect at public-access pricing. Dan Maples\'s routing through rocky terrain, wetlands, and hardwood forest creates a course that feels completely different from the typical suburban track.', playingTips: 'Rocky River\'s rocky terrain creates some uneven lies uncommon in Charlotte. The back nine is considered more demanding; build a cushion on the more forgiving front nine. Wide fairways are deceptively generous off the tee — approach shot placement and accuracy matter more than driving distance.', faqs: [{ question: 'Where is Rocky River Golf Club located?', answer: 'Rocky River Golf Club is located in Concord, North Carolina, adjacent to Charlotte Motor Speedway — approximately 15 miles northeast of downtown Charlotte.' }, { question: 'Who designed Rocky River Golf Club?', answer: 'Dan Maples, one of the Carolinas\' most accomplished golf course architects, designed Rocky River Golf Club, which opened in 1997. Maples also designed Pinehurst No. 9.' }]},
    { id: 'clt-5', name: 'The Tradition Golf Club', slug: 'tradition-charlotte', city: 'Charlotte', state: 'North Carolina', type: 'public', rating: 4.1, greensFee: '$30–$60', architect: 'John Cassell', yearBuilt: 1996, holes: 18, par: 72, yardage: 6803, description: 'A well-regarded public course in south Charlotte, The Tradition offers a mature, tree-lined layout with good conditioning and fair pricing. It\'s become a reliable staple for Charlotte\'s public golf scene.', highlights: ['Reliable south Charlotte public course', 'Mature tree-lined fairways', 'Good value and conditioning'], imageAlt: 'The Tradition Golf Club tree-lined hole in south Charlotte', history: 'The Tradition Golf Club in Charlotte, North Carolina opened in 1996, offering a tree-lined layout with water features on 15 of 18 holes. The course was developed to provide a premium daily-fee experience in the rapidly growing south Charlotte market, where the Ballantyne corridor created demand for quality golf facilities.\n\nThe 6,597-yard, par-72 layout on Ultradwarf Bermuda greens challenged area golfers with a combination of water hazards and tight tree-lined corridors that demand precision. The Tradition\'s finishing hole — a risk-reward par 5 — became a signature of the course, offering birdie opportunities for those willing to challenge the water.', signatureHoles: [{ hole: 18, par: 5, yardage: 530, description: 'The Tradition\'s most celebrated hole is the risk-reward finishing par 5, where water guards the aggressive second-shot route to the green. Players can lay up safely and attack with a wedge, or challenge the water for a potential eagle opportunity.' }, { hole: 10, par: 3, yardage: 175, description: 'The back nine opener sets the tone for the more demanding second half. Water guards the front and right of the green, demanding a precise carry.' }], whatToExpect: 'The Tradition is a reliable and entertaining daily-fee experience in south Charlotte, featuring water on 15 of 18 holes and tight tree-lined corridors. The Ultradwarf Bermuda greens are fast and true throughout the year. Competitive pricing keeps The Tradition accessible to a wide range of Charlotte-area golfers.', playingTips: 'With water on 15 holes, The Tradition rewards accurate iron play over distance. The Ultradwarf greens are faster than they appear — start lag putts well short of the hole. The 18th hole risk-reward decision should be made conservatively if the round has gone well.', faqs: [{ question: 'How many holes have water at The Tradition Golf Club?', answer: 'Water comes into play on 15 of the 18 holes at The Tradition Golf Club in Charlotte, making accurate iron play and conservative tee shots important throughout.' }, { question: 'Is The Tradition Golf Club public or private?', answer: 'The Tradition Golf Club is a daily-fee public course open to all golfers in the Charlotte, NC area.' }]},
    { id: 'clt-6', name: 'The Club at Irish Creek', slug: 'irish-creek', city: 'Charlotte', state: 'North Carolina', type: 'semi-private', rating: 4.2, greensFee: '$65–$110', architect: 'Davis Love III', yearBuilt: 2005, holes: 18, par: 72, yardage: 7145, description: 'A Davis Love III design in Kannapolis north of Charlotte, Irish Creek offers championship-caliber golf with excellent accessibility. The layout features rolling Piedmont terrain, mature hardwoods, and Love\'s signature risk-reward par 5s.', highlights: ['Davis Love III design', 'Rolling Piedmont terrain', 'Championship caliber at semi-private pricing'], imageAlt: 'Irish Creek rolling Piedmont fairway with hardwoods near Charlotte', history: 'The Club at Irish Creek in Kannapolis, North Carolina occupies a stunning site built around an enormous 400-acre lake that defines the course\'s character. Davis Love III — a major champion, Ryder Cup captain, and one of America\'s most respected course designers — created an 18-hole signature design on what was originally the site of Kannapolis Country Club, a nine-hole layout built around the city\'s water supply reservoir.\n\nLove\'s 2005 renovation/expansion added four entirely new holes set amid mature hardwood forest while incorporating the best elements of the existing lakeside routing. The result is a 7,099-yard, par-71 course of dramatic variety. The finishing three holes — a 479-yard par 4, a 468-yard par 4, and a 242-yard par 3 — are considered among the strongest closing sequences in North Carolina.', signatureHoles: [{ hole: 16, par: 4, yardage: 479, description: 'The first of Irish Creek\'s celebrated three-hole finish, the 16th plays along the lake shore with water threatening both tee and approach shots. Davis Love III designed this demanding hole to require the best shot of the round from both tee and fairway.' }, { hole: 9, par: 4, yardage: 445, description: 'The ninth hole plays directly toward Kannapolis Lake, with the approach requiring a carry over a corner of the water to a well-guarded green. Lake views and precise shot demands make this the most photographed hole on the front nine.' }], whatToExpect: 'Irish Creek is Kannapolis\'s finest golf achievement — a Davis Love III signature design built around a breathtaking 400-acre lake that makes every lakeside hole a visual spectacle. Love\'s routing blends dramatic lake holes with wooded interior holes for a varied, memorable experience.', playingTips: 'The lake at Irish Creek changes the visual perspective on many approach shots — the water appears closer or farther than it actually is. Trust your yardage book over your eyes. The closing three holes (16-18) are physically and mentally demanding — arrive there with reserves of both.', faqs: [{ question: 'Who designed The Club at Irish Creek?', answer: 'PGA Tour champion and Ryder Cup captain Davis Love III designed the Club at Irish Creek, which opened in its current 18-hole form in 2005 in Kannapolis, NC.' }, { question: 'What makes Irish Creek distinctive?', answer: 'Irish Creek is built around a 400-acre lake that comes into play on multiple holes, with Davis Love III\'s routing maximizing the lake\'s visual and strategic presence throughout the round.' }]},
    { id: 'clt-7', name: 'TPC Piper Glen', slug: 'tpc-piper-glen', city: 'Charlotte', state: 'North Carolina', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Arnold Palmer', yearBuilt: 1989, holes: 18, par: 72, yardage: 7074, description: 'A former PGA Tour venue, TPC Piper Glen is an Arnold Palmer design in south Charlotte. The course hosted the Wachovia Championship and combines classic Carolina Piedmont terrain with TPC-standard conditioning and strategic interest.', highlights: ['Former PGA Tour venue', 'Arnold Palmer design', 'TPC-standard conditioning'], imageAlt: 'TPC Piper Glen championship fairway in south Charlotte', history: 'TPC Piper Glen opened in 1987 in Charlotte, North Carolina, designed by Arnold Palmer and his longtime design partner Ed Seay. The course was built as part of the Piper Glen development in south Charlotte and earned TPC designation as a Tournament Players Club facility.\n\nPalmer\'s design was recognized for its challenging but accessible character — 6,883 yards (rating 73.2, slope 130) with multiple tee positions. The course hosted the PGA Tour Champions Home Depot Invitational for multiple years, with Palmer himself serving as the tournament\'s host and ambassador. The 16th, 17th, and 18th holes form a celebrated finishing sequence.', signatureHoles: [{ hole: 18, par: 4, yardage: 445, description: 'TPC Piper Glen\'s finishing hole is a demanding par 4 where precision off the tee is paramount. The approach plays to a well-bunkered green that reflects Arnold Palmer\'s philosophy of making the final hole both challenging and exciting.' }, { hole: 16, par: 3, yardage: 190, description: 'The first of Piper Glen\'s celebrated closing stretch, the 16th is a long par 3 to a well-guarded green. Palmer\'s design makes the tee shot feel exposed and demanding, with bunkers positioned to catch anything short or right.' }], whatToExpect: 'TPC Piper Glen is one of Charlotte\'s most prestigious private clubs — an Arnold Palmer signature design with TPC conditioning standards and a history of PGA Tour Champions events. The Arnold Palmer design philosophy emphasizes exciting, risk-reward architecture over pure difficulty.', playingTips: 'TPC Piper Glen\'s cart paths between some holes are long — budget extra time. The greens at TPC facilities tend to be faster than typical Bermuda courses. The 16-17-18 finishing stretch determines many rounds; arrive there with a clear head and a conservative game plan.', faqs: [{ question: 'Has TPC Piper Glen hosted professional events?', answer: 'Yes, TPC Piper Glen hosted the PGA Tour Champions Home Depot Invitational for multiple years, with Arnold Palmer serving as the tournament\'s host. The event brought the world\'s best senior players to Charlotte annually.' }, { question: 'Is TPC Piper Glen open to the public?', answer: 'TPC Piper Glen is a private members-only club in south Charlotte, North Carolina. Access is available through member sponsorship.' }]},
    { id: 'clt-8', name: 'Ballantyne Golf Club', slug: 'ballantyne-golf-club', city: 'Charlotte', state: 'North Carolina', type: 'resort', rating: 4.1, greensFee: '$80–$140', architect: 'Rees Jones', yearBuilt: 1998, holes: 18, par: 71, yardage: 7015, description: 'Part of The Ballantyne Hotel & Lodge in south Charlotte, this Rees Jones design offers resort-quality golf through rolling Piedmont terrain. The well-conditioned layout provides an engaging test with multiple water features and strategic bunkering.', highlights: ['Ballantyne Hotel resort golf', 'Rees Jones Piedmont design', 'Convenient south Charlotte location'], imageAlt: 'Ballantyne Golf Club resort course through Carolina Piedmont terrain', history: 'Ballantyne Golf Club is the golf amenity of The Ballantyne Hotel and Lodge in south Charlotte\'s prestigious Ballantyne development. Rees Jones — widely known as the Open Doctor for his work preparing US Open venues including Bethpage Black, Torrey Pines, and Pinehurst No. 2 — designed the 18-hole, par-71 layout on rolling Piedmont terrain, opening in 1998.\n\nAt 7,015 yards, Ballantyne stretches to genuine championship length while offering an inviting experience from forward tees. The course underwent an extensive renovation in the 2010s that introduced TifEagle Bermuda greens and refreshed the bunkering, maintaining its status as one of Charlotte\'s finest resort golf experiences.', signatureHoles: [{ hole: 11, par: 4, yardage: 440, description: 'The strongest hole at Ballantyne Golf Club plays from an elevated tee down a rolling fairway with bunkers positioned to catch pushed and pulled drives. The approach must carry a run-off slope to a well-protected green.' }, { hole: 17, par: 3, yardage: 185, description: 'A classic one-shotter from Rees Jones that plays over a water hazard to a green with no bail-out zone. Club selection is critical — carry the water and reach the proper quadrant of the green.' }], whatToExpect: 'Ballantyne Golf Club provides the quintessential hotel golf experience — a Rees Jones design in excellent condition integrated with five-star resort amenities. The rolling Piedmont terrain gives the course a natural character that distinguishes it from flat suburban tracks.', playingTips: 'Ballantyne\'s TifEagle Bermuda greens are among the fastest in the Charlotte resort market — lag putting is essential. Jones designed several holes with a specific bail-out zone for approach shots — learn these preferred miss spots before your round.', faqs: [{ question: 'Is Ballantyne Golf Club open to non-hotel guests?', answer: 'Ballantyne Golf Club is a resort course primarily serving Ballantyne Hotel guests, but non-hotel guests can play on a daily-fee basis subject to availability.' }, { question: 'Who designed Ballantyne Golf Club?', answer: 'Rees Jones, the Open Doctor, designed Ballantyne Golf Club, which opened in 1998 as the golf amenity for The Ballantyne Hotel and Lodge in south Charlotte, North Carolina.' }]},
    { id: 'clt-9', name: 'Firethorne Country Club', slug: 'firethorne-country-club', city: 'Charlotte', state: 'North Carolina', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Hale Irwin', yearBuilt: 2000, holes: 18, par: 72, yardage: 7100, description: 'A Hale Irwin design in Weddington south of Charlotte, Firethorne is one of the most respected newer private clubs in the Charlotte market. The layout features rolling terrain, mature hardwood groves, and Irwin\'s emphasis on strategic bunkering and green defense.', highlights: ['Hale Irwin private club design', 'Rolling Weddington terrain', 'Among Charlotte\'s top-rated newer clubs'], imageAlt: 'Firethorne Country Club rolling terrain with hardwoods in south Charlotte', history: 'Firethorne Country Club opened in 2000 in Weddington, North Carolina, just south of Charlotte, designed by three-time US Open Champion Hale Irwin. Irwin founded Hale Irwin Golf Design in 1986 and has produced numerous award-winning courses; Firethorne is considered one of his most successful Carolinas designs.\n\nThe course is built on rolling Piedmont terrain with mature hardwood groves, creating a setting that feels more like a classic parkland course than contemporary development golf. Irwin\'s design emphasis on strategic bunkering and green defense produces a layout that demands precision on approach shots — a hallmark of his design philosophy rooted in his own playing career on difficult US Open venues. At 7,100 yards from the tips, Firethorne is one of the most respected newer private clubs in the greater Charlotte market.', signatureHoles: [{ hole: 10, par: 4, yardage: 448, description: 'The opening hole of the back nine is Firethorne\'s most demanding par 4 — a long, tree-lined corridor requiring a precise drive to set up any realistic scoring opportunity. Irwin\'s deep, strategically placed bunkers guard the green on both sides.' }, { hole: 7, par: 3, yardage: 220, description: 'One of Hale Irwin\'s signature design elements: a long, demanding par 3 that offers no mercy for slightly mis-hit shots. The green complex reflects Irwin\'s appreciation for US Open-style challenge.' }], whatToExpect: 'Firethorne Country Club is one of Charlotte\'s most respected private clubs — a genuine championship test by a Hall of Fame player-architect demanding the same precision Irwin applied in his own playing career. The rolling Weddington terrain, mature hardwood groves, and meticulous conditioning create an atmosphere that serious golfers appreciate.', playingTips: 'Firethorne\'s bunkering is more severe than it appears in photos — Irwin positioned hazards to catch approach shots that are merely imprecise. The mature hardwoods create windbreaks that can make distance difficult to judge. The back nine is generally more demanding; arrive at the 10th tee with a comfortable cushion if possible.', faqs: [{ question: 'Who designed Firethorne Country Club?', answer: 'Three-time US Open Champion Hale Irwin designed Firethorne Country Club, which opened in 2000 in Weddington, NC.' }, { question: 'Is Firethorne Country Club private?', answer: 'Yes, Firethorne Country Club is a private members-only club in Weddington, North Carolina, south of Charlotte. Guest access is available only through member introduction.' }]},
  ],
  'pinehurst-north-carolina': [
    { id: 'pin-1', name: 'Pinehurst No. 2', slug: 'pinehurst-no-2', city: 'Pinehurst', state: 'North Carolina', type: 'resort', rating: 5.0, greensFee: '$350–$550', architect: 'Donald Ross', yearBuilt: 1907, holes: 18, par: 72, yardage: 7588, description: 'The crown jewel of American golf, Pinehurst No. 2 is Donald Ross\'s masterpiece and has hosted more single championships than any course in America — including U.S. Opens, PGA Championships, and Ryder Cups. The restored wiregrass-and-sand landscape and legendary turtle-back greens define the Pinehurst experience.', highlights: ['Most championship-tested course in America', 'Donald Ross\'s crowning achievement', 'Restored to original sand-and-wiregrass aesthetic'], imageAlt: 'Pinehurst No. 2 iconic clubhouse and wiregrass landscape', history: 'Pinehurst No. 2 opened in 1907, designed by Donald Ross, the Scottish-born architect who made Pinehurst his home. Ross continuously refined the course over four decades, calling it the fairest test of championship golf he ever designed. The course is the centerpiece of Pinehurst Resort, founded by James Walker Tufts in the North Carolina Sandhills in 1895.\n\nNo. 2 has hosted more single championships than any course in America, including three U.S. Opens (1999, 2005, 2014), the 1936 PGA Championship, and multiple U.S. Amateurs. Payne Stewart\'s iconic 15-foot par putt on the 18th to win the 1999 U.S. Open is one of golf\'s most celebrated moments.\n\nIn 2011, Bill Coore and Ben Crenshaw led a landmark restoration that removed all rough and replaced it with native sand and wiregrass, returning the course to its original sandy aesthetic. The restoration reduced water usage by 40 percent while dramatically improving strategic interest and visual beauty.', signatureHoles: [{ hole: 4, par: 4, yardage: 528, description: 'Converted from a par 5 for U.S. Open play, this is the longest par 4 on the front nine. The turtleback green rejects anything not perfectly struck.' }, { hole: 5, par: 5, yardage: 576, description: 'A beautiful par 5 with risk-reward options and one of Ross\'s most dramatic green complexes. Many consider it the best hole on the course.' }, { hole: 17, par: 3, yardage: 190, description: 'A demanding par 3 with one of the most severe green complexes on the course. The hourglass-shaped putting surface falls away on all sides.' }], whatToExpect: 'Pinehurst No. 2 plays through sandy, rolling terrain of the North Carolina Sandhills. Since the 2011 restoration, native sand and wiregrass border the fairways instead of traditional rough. The famous turtleback greens, crowned and sloping on all edges, are the primary defense.\n\nPar 72 at approximately 7,588 yards from the championship tees. Walking with a caddie is recommended. Sandy soil provides excellent drainage and firm conditions year-round.', playingTips: 'The key to scoring is positioning approaches below the hole. The crowned turtleback greens reject shots landing on the wrong side. Short-game creativity is essential since areas around greens offer multiple recovery options.\n\nOff the tee, sandy waste areas are preferable to wiregrass. Fairways are wide but approach angles matter enormously. Some pin positions are simply not attackable.', faqs: [{ question: 'Can the public play Pinehurst No. 2?', answer: 'Yes. It is a resort course open to Pinehurst Resort guests. Green fees range from approximately $350-$550 depending on season.' }, { question: 'What are turtleback greens?', answer: 'Donald Ross\'s signature crowned greens where putting surfaces slope away on all sides. Shots missing the green roll off into collection areas.' }, { question: 'What was the 2011 restoration?', answer: 'Coore and Crenshaw removed all rough, replacing it with native sand and wiregrass, returning the course to its original aesthetic while reducing water usage by 40 percent.' }, { question: 'When is the best time to play?', answer: 'Spring (March-May) and fall (September-November) offer the best weather. Summer can be very hot and humid.' }] },
    { id: 'pin-2', name: 'Pinehurst No. 4', slug: 'pinehurst-no-4', city: 'Pinehurst', state: 'North Carolina', type: 'resort', rating: 4.7, greensFee: '$200–$375', architect: 'Gil Hanse', yearBuilt: 2018, holes: 18, par: 72, yardage: 7361, description: 'Completely rebuilt by Gil Hanse in 2018, Pinehurst No. 4 has earned rave reviews as the best "other" course at the resort. The design features bold contours, sandy waste areas, and a strategic quality that some say rivals No. 2 for pure fun.', highlights: ['Gil Hanse complete rebuild', 'Rivals No. 2 for enjoyment', 'Bold contours and waste areas'], imageAlt: 'Pinehurst No. 4 Gil Hanse design with sandy waste areas', history: 'Pinehurst No. 4 was originally designed by Donald Ross in 1919 as one of the early courses at Pinehurst Resort. Over the decades it went through several iterations by different architects, including a Fazio redesign, that moved it further from its Sandhills roots. In 2018, Gil Hanse completed what he called a "retrovation" -- a complete reimagining that honored the minimalist, sandy character of the Carolina Sandhills while creating an entirely new routing.\n\nHanse stripped away heavy-handed design elements of previous renovations, restoring native sandy waste areas, removing unnecessary trees, and creating low-profile greens with bold contours that blend into the landscape. The result was named Golf Digest\'s Best New Course You Can Play in 2018 and immediately earned comparisons to the resort\'s crown jewel, No. 2.\n\nAt 7,361 yards and par 72, No. 4 is a strong test from the back tees, but wide fairways with kick-slopes that direct shots toward the greens make it supremely playable from forward tees. Many resort guests now consider No. 4 their favorite Pinehurst course.', signatureHoles: [{ hole: 5, par: 4, yardage: 440, description: 'A strong par 4 showcasing Hanse\'s strategic design. The wide fairway offers multiple angles of approach, but finding the correct position is essential for attacking the boldly contoured green.' }, { hole: 6, par: 3, yardage: 180, description: 'A beautiful par 3 with a green complex that blends into the surrounding sandy landscape. Dramatic contours make pin position critical to club selection.' }, { hole: 13, par: 5, yardage: 555, description: 'A reachable par 5 offering genuine risk-reward for long hitters. The green is accessible in two but well-defended by waste areas and bold contours.' }, { hole: 18, par: 4, yardage: 408, description: 'A demanding finishing hole with deep bunkers guarding the green. The hole requires two precise shots to close out the round.' }], whatToExpect: 'Pinehurst No. 4 is visually stunning and feels timeless despite being completely rebuilt in 2018. Hanse created the design in the tradition of Carolina Sandhills golf with wide fairways, native sandy waste areas, low-profile greens, and minimal artificiality.\n\nThe experience complements rather than duplicates No. 2. Where No. 2 can be stern and exacting, No. 4 is more fun and accessible while still providing strategic depth for skilled players.', playingTips: 'Use the kick-slopes to your advantage. Hanse designed many approach areas to funnel shots toward the greens, so playing ground shots can be highly effective. The greens have significant contour, so landing on the correct tier is more important than simply hitting the green.\n\nMost resort guests will enjoy No. 4 more from the middle or forward tees where the strategic options are most apparent. Take time to study each green before putting -- the bold contours can produce surprising breaks.', faqs: [{ question: 'Is Pinehurst No. 4 as good as No. 2?', answer: 'Many guests consider No. 4 more fun than No. 2, while No. 2 retains its status as the iconic championship test. The two courses complement each other beautifully.' }, { question: 'Who designed the current version of No. 4?', answer: 'Gil Hanse completed a full "retrovation" in 2018, creating an entirely new routing. It was named Golf Digest\'s Best New Course You Can Play in 2018.' }, { question: 'Is No. 4 walking only?', answer: 'Pinehurst Resort generally encourages walking on its courses. No. 4 is very walkable with gentle Sandhills terrain.' }, { question: 'What was on the No. 4 property before Hanse?', answer: 'Donald Ross originally designed the course in 1919. It went through several redesigns before Hanse\'s 2018 retrovation created the current layout.' }] },
    { id: 'pin-3', name: 'Mid Pines Inn & Golf Club', slug: 'mid-pines', city: 'Pinehurst', state: 'North Carolina', type: 'resort', rating: 4.6, greensFee: '$100–$200', architect: 'Donald Ross', yearBuilt: 1921, holes: 18, par: 72, yardage: 6515, description: 'A lovingly restored Donald Ross gem across the street from Pine Needles, Mid Pines offers an intimate, classic Sandhills experience. The cozy inn and walkable course feel like stepping back to golf\'s golden age.', highlights: ['Intimate Donald Ross gem', 'Classic Sandhills inn experience', 'Beautifully restored'], imageAlt: 'Mid Pines Inn and Golf Club classic Donald Ross Sandhills course', history: 'Mid Pines was established in 1921 with Donald Ross as founding member and course designer. In 2013, Kyle Franz completed a restoration winning Golf Digest\'s Best Restored Course award.\n\nNow widely regarded as one of the finest Ross courses in the Sandhills, offering an authentic Golden Age experience.', signatureHoles: [{ hole: 4, par: 4, yardage: 410, description: 'A demanding par 4 with a classic Ross crowned green.' }, { hole: 7, par: 3, yardage: 165, description: 'A beautiful par 3 surrounded by sandy waste areas and longleaf pines.' }, { hole: 13, par: 4, yardage: 400, description: 'A strategic par 4 with restored bunkering creating compelling options.' }, { hole: 18, par: 4, yardage: 420, description: 'A strong finishing hole playing back toward the historic inn.' }], whatToExpect: 'A lovingly restored Donald Ross gem with crowned greens, strategic bunkering, and sandy waste areas. The inn-style lodging and walkable course create a timeless experience.\n\nSandy Sandhills soil provides ideal firm, fast conditions.', playingTips: 'Ross\'s crowned greens shed shots missing the center. Aim for the middle first.\n\nBump-and-run shots work well on the firm Sandhills turf.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Resort course with lodging packages and excellent value.' }, { question: 'What was the Franz restoration?', answer: 'A 2013 restoration returning the course to Ross\'s 1921 design, winning Golf Digest\'s Best Restored Course.' }, { question: 'How does it compare to Pinehurst No. 2?', answer: 'Authentic Ross architecture at a fraction of the price in a more intimate setting.' }] },
    { id: 'pin-4', name: 'Pine Needles Lodge & Golf Club', slug: 'pine-needles', city: 'Pinehurst', state: 'North Carolina', type: 'resort', rating: 4.7, greensFee: '$150–$275', architect: 'Donald Ross', yearBuilt: 1928, holes: 18, par: 72, yardage: 7015, description: 'Host of three U.S. Women\'s Opens and the 2022 U.S. Open, Pine Needles is a Donald Ross masterwork that winds through longleaf pines. The walkable layout features Ross\'s signature crowned greens and strategic bunkering.', highlights: ['Multiple U.S. Open host', 'Quintessential Donald Ross design', 'Longleaf pine-lined fairways'], imageAlt: 'Pine Needles Golf Club longleaf pine fairway in Southern Pines', history: 'Pine Needles Lodge & Golf Club was designed by Donald Ross and opened in 1928 in Southern Pines, North Carolina. Ross routed the course through towering longleaf pines on gently rolling terrain, creating one of his most celebrated designs. The lodge and course were developed as a golf retreat and have maintained that intimate character for nearly a century.\n\nPine Needles is the first golf resort to host four U.S. Women\'s Opens (1996, 2001, 2007, and 2022), cementing its place among the most important championship venues in American golf. The late Peggy Kirk Bell, a pioneering figure in women\'s golf, owned and operated the resort for decades and her family continues the tradition.\n\nA comprehensive restoration by Kyle Franz returned the course to Ross\'s original design intent, removing trees that had encroached on playing corridors and restoring the sandy, open character Ross intended. The result is a pure, walkable Donald Ross experience that ranks among the finest resort courses in the Southeast.', signatureHoles: [{ hole: 3, par: 4, yardage: 395, description: 'The hole that remains closest to Ross\'s original design. A classic mid-length par 4 through the pines demanding precise placement and a thoughtful approach to a crowned Ross green.' }, { hole: 5, par: 3, yardage: 195, description: 'A long, uphill par 3 that is one of Ross\'s finest short holes. The elevated green is defended by deep bunkers and the uphill nature demands an extra club.' }, { hole: 13, par: 3, yardage: 165, description: 'A downhill par 3 that complements the uphill 5th. The tee shot plays to a Ross green with subtle crowning that rejects shots missing the center.' }, { hole: 18, par: 4, yardage: 420, description: 'A demanding finishing hole that plays uphill to a crowned green defended by strategic bunkering. A fitting conclusion to one of the master architect\'s finest courses.' }], whatToExpect: 'Pine Needles is the quintessential Donald Ross experience -- a walkable, strategic course through longleaf pines with crowned greens, thoughtful bunkering, and timeless character. At 7,015 yards from the medal tees, it tests length, but the genius is in the green complexes that demand precise iron play from every skill level.\n\nThe lodge atmosphere is warm and welcoming, with a focus on the golf experience. The recent restoration has returned the course to its original sandy, open character, enhancing both the playing experience and visual beauty.', playingTips: 'The crowned greens are Pine Needles\' primary defense. Approach shots that miss the center will roll off the edges into collection areas or bunkers. Aim for the center of each green rather than firing at pins, especially on first visit.\n\nWalking is the best way to experience Pine Needles. The gently rolling terrain is very manageable on foot. The short par 4s on the 8th and 11th holes offer birdie chances for those who play smart.', faqs: [{ question: 'How many U.S. Women\'s Opens has Pine Needles hosted?', answer: 'Pine Needles has hosted four U.S. Women\'s Opens (1996, 2001, 2007, and 2022), making it the first resort to host the championship four times.' }, { question: 'Can the public play Pine Needles?', answer: 'Yes. Pine Needles is a resort course open to lodge guests and the public. Green fees typically range from $150 to $275 depending on season.' }, { question: 'Who was Peggy Kirk Bell?', answer: 'Peggy Kirk Bell was a pioneering figure in women\'s golf who owned and operated Pine Needles for decades. She was an LPGA Tour player, renowned instructor, and passionate advocate for growing the game.' }, { question: 'Is Pine Needles walkable?', answer: 'Absolutely. Pine Needles is one of the most walkable courses in the Sandhills, with gentle terrain that Donald Ross designed with walking in mind.' }] },
    { id: 'pin-5', name: 'Tobacco Road Golf Club', slug: 'tobacco-road', city: 'Pinehurst', state: 'North Carolina', type: 'public', rating: 4.5, greensFee: '$75–$150', architect: 'Mike Strantz', yearBuilt: 1998, holes: 18, par: 71, yardage: 6554, description: 'The most polarizing course in the Sandhills, Tobacco Road is a Mike Strantz creation that defies convention. Massive dunes, blind shots, and creative green complexes create a golf experience unlike anything else in America.', highlights: ['Most polarizing course in America', 'Mike Strantz\'s bold vision', 'Massive sand dunes and blind shots'], imageAlt: 'Tobacco Road massive sand dunes and dramatic landscape', history: 'Tobacco Road Golf Club opened in 1998 on the site of an old sand quarry near Sanford, North Carolina, about 30 minutes from Pinehurst. Architect Mike Strantz embraced the raw, scarred terrain rather than trying to tame it, creating what many consider the most unconventional and polarizing golf course in America. The massive sand dunes, some reaching 50 feet high, and blind shots challenged every assumption about traditional golf course design.\n\nStrantz was known as "The Maverick" of golf architecture, and Tobacco Road is the course most often mentioned when discussing his legacy. Built on a shoestring budget, Strantz used the natural sand quarry topography to create dramatic elevation changes and visual spectacles that divide golfers into passionate fans and vocal critics.\n\nMore than 25 years after its opening, Tobacco Road has only grown in stature and influence. Many credit it as a precursor to modern bold designs at places like Streamsong and Sand Valley. The course continues to attract golfers from around the world seeking a truly unique experience in the North Carolina Sandhills.', signatureHoles: [{ hole: 1, par: 5, yardage: 547, description: 'The opening hole immediately announces that Tobacco Road is unlike anything you have played before. A par 5 that plunges from an elevated tee into a valley between massive sand dunes.' }, { hole: 3, par: 3, yardage: 147, description: 'A short par 3 that plays to a green perched atop a sand dune. The carry is visually intimidating and the green has dramatic contours typical of Strantz\'s creative philosophy.' }, { hole: 8, par: 3, yardage: 175, description: 'A stunning par 3 playing downhill to a green surrounded by towering sand dunes. The visual drama and demand for precise club selection make it one of the most memorable short holes in the Sandhills.' }, { hole: 18, par: 4, yardage: 423, description: 'A dramatic finishing hole featuring a blind tee shot over a massive dune, followed by a demanding approach. It encapsulates everything Tobacco Road represents -- bold, unconventional, and unforgettable.' }], whatToExpect: 'Tobacco Road is a completely unique golf experience. At 6,554 yards and par 71, it is not long, but the challenge comes from the creativity and unconventionality of the design. Expect blind shots, massive sand dunes, wildly creative green complexes, and a visual experience unlike any other course in America. A yardage book is highly recommended.\n\nThe course is built on a former sand quarry, so the terrain is sandy and dramatic with significant elevation changes. Come with an open mind and a sense of adventure.', playingTips: 'A yardage book is essential for first-time players. Many holes feature blind shots, and without knowledge of the landing areas, the course can feel random rather than strategic. The more you play Tobacco Road, the more the genius of the design reveals itself.\n\nDo not fight the course -- embrace it. Missing in the wrong spot can lead to big numbers, so study the green complexes carefully and play to the safe sides when in doubt. The par 3s are a particular strength and offer some of the most visually dramatic shots in Sandhills golf.', faqs: [{ question: 'Is Tobacco Road really that unusual?', answer: 'Yes. Tobacco Road features more blind shots, bigger dunes, and more unconventional hole designs than virtually any course in America. It is a love-it-or-hate-it experience.' }, { question: 'Do I need a yardage book?', answer: 'Strongly recommended for first-time players. The course has many blind shots and unusual features that are much more enjoyable when you understand the layout.' }, { question: 'How far is Tobacco Road from Pinehurst?', answer: 'Tobacco Road is located in Sanford, NC, approximately 30 minutes northeast of Pinehurst. It makes an excellent addition to a Sandhills golf trip.' }, { question: 'Is Tobacco Road walkable?', answer: 'Yes, walking is encouraged. The sandy terrain and dramatic elevation changes make for an invigorating walk. Carts are also available.' }] },
    { id: 'pin-6', name: 'Pinehurst No. 8', slug: 'pinehurst-no-8', city: 'Pinehurst', state: 'North Carolina', type: 'resort', rating: 4.5, greensFee: '$150–$300', architect: 'Tom Fazio', yearBuilt: 1996, holes: 18, par: 72, yardage: 7092, description: 'Known as the "Centennial Course" for its opening during Pinehurst\'s 100th anniversary, No. 8 is a Tom Fazio design that offers a more modern, dramatic style compared to the classic Ross and Hanse courses at the resort. Bold shaping, dramatic bunkering, and excellent conditioning make it a favorite among resort guests.', highlights: ['Tom Fazio Centennial design', 'Bold modern style at historic resort', 'Among Pinehurst Resort\'s most popular courses'], imageAlt: 'Pinehurst No. 8 Tom Fazio bold bunkering and shaping', history: 'Pinehurst No. 8 was designed by Tom Fazio to commemorate the 100th anniversary of Pinehurst Resort and opened in 1996. Often called the Centennial Course, Fazio built crowned greens with greenside swales as a deliberate salute to Donald Ross and Pinehurst No. 2.\n\nNo. 8 is the most secluded of the Pinehurst resort courses, routed through dense longleaf pines with no residential development visible from any hole. The course features dramatic waste areas, bold shaping, and water hazards absent from the more minimalist Ross courses.\n\nThe course received agronomic enhancements in 2022, refreshing playing surfaces while maintaining Fazio\'s original design intent. No. 8 regularly ranks among the best resort courses in America.', signatureHoles: [{ hole: 2, par: 4, yardage: 420, description: 'A par 4 through towering longleaf pines with a crowned green paying homage to Donald Ross.' }, { hole: 9, par: 4, yardage: 440, description: 'A strong front-nine closer with a large waste area along the right side and Fazio\'s trademark bunkering.' }, { hole: 13, par: 3, yardage: 195, description: 'A demanding par 3 over water to a green flanked by sand and pines. One of the most stunning holes at Pinehurst.' }, { hole: 18, par: 5, yardage: 545, description: 'A risk-reward par 5 finish where long hitters can reach in two, but water and bunkers guard the green.' }], whatToExpect: 'No. 8 offers a distinctly different experience from the classic Ross courses. Fazio\'s bold style features dramatic shaping, waste areas, and water hazards creating visual excitement. The routing through secluded longleaf pines means no houses or distractions.\n\nAt 7,092 yards from the tips, the course is a serious test but plays fairly from forward tees. The crowned greens demand thoughtful approach play.', playingTips: 'The crowned greens are the defining challenge. Balls missing the center roll into collection areas. Aim for green centers and work toward pins only when confident in distance control.\n\nWaste areas are played as through-the-green so you can ground your club. Course management through the pines is essential as wayward drives leave difficult recoveries.', faqs: [{ question: 'Can the public play Pinehurst No. 8?', answer: 'Yes. No. 8 is available to Pinehurst Resort guests with green fees typically from $150 to $300 depending on season.' }, { question: 'Why is it called the Centennial Course?', answer: 'No. 8 opened in 1996 to celebrate Pinehurst Resort\'s 100th anniversary.' }, { question: 'How does No. 8 compare to No. 2?', answer: 'No. 8 is a more modern design with water and bold shaping, while No. 2 is a minimalist Donald Ross classic. Many find No. 8 more visually exciting for casual play.' }, { question: 'Are there houses on the course?', answer: 'No. No. 8 is the most secluded course at Pinehurst with no residential development visible from any hole.' }] },
    { id: 'pin-7', name: 'Forest Creek Golf Club', slug: 'forest-creek', city: 'Pinehurst', state: 'North Carolina', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 1996, holes: 18, par: 72, yardage: 7023, description: 'A highly regarded Tom Fazio private club in the Sandhills, Forest Creek features two 18-hole courses with the South Course consistently ranked among the best in North Carolina. Fazio routed the layout through longleaf pines with his trademark bold shaping and strategic bunkering.', highlights: ['Two Fazio courses — South ranked top 10 in NC', 'Longleaf pine Sandhills setting', 'Exclusive alternative to resort golf'], imageAlt: 'Forest Creek longleaf pine fairway in the NC Sandhills', history: 'Forest Creek Golf Club is a private club in the Sandhills of North Carolina featuring two Tom Fazio-designed 18-hole courses. The South Course opened first and quickly earned recognition as one of the finest private courses in the state, routed through towering longleaf pines on gently rolling Sandhills terrain.\n\nThe club is notable for Fazio\'s personal connection. Forest Creek is reportedly the only golf club where Fazio himself holds a membership, underscoring his regard for the property. The North Course underwent an extensive Fazio-led restoration, reopening in 2021 with modernized playing surfaces.\n\nThe South Course has also been undergoing restoration combining Fazio\'s original vision with advanced agronomic science. Forest Creek offers an exclusive alternative to nearby Pinehurst Resort, attracting members who value privacy and premier Fazio design.', signatureHoles: [{ hole: 4, par: 4, yardage: 435, description: 'A demanding par 4 through a corridor of longleaf pines. Fazio\'s bold bunkering frames the approach to a well-contoured green.' }, { hole: 8, par: 3, yardage: 190, description: 'A scenic par 3 with waste areas and native grasses framing the green amid towering longleaf pines.' }, { hole: 14, par: 5, yardage: 550, description: 'A strategic par 5 offering risk-reward options. The fairway bends through the pines with Fazio\'s characteristic shaping creating multiple routes to the green.' }, { hole: 17, par: 4, yardage: 425, description: 'A challenging late-round par 4 with bold bunkering and a demanding approach to a well-defended green complex.' }], whatToExpect: 'Forest Creek offers two distinct Tom Fazio experiences in a secluded Sandhills setting. The South Course is consistently ranked among the best private courses in North Carolina. Both courses are routed through longleaf pines with no outside distractions.\n\nConditioning is exceptional. The courses are walkable and the private club atmosphere is relaxed and understated compared to the busier resort environment at nearby Pinehurst.', playingTips: 'The Sandhills terrain creates firm and fast conditions that reward a ground game. Running approach shots onto greens is often more effective than aerial attacks. Waste areas can be played with grounded clubs.\n\nFazio\'s greens feature subtle contours more complex than they appear. Avoid being above the hole, as downhill putts on these surfaces can be treacherously fast.', faqs: [{ question: 'Can the public play Forest Creek?', answer: 'No. Forest Creek is a private club with no public or resort access.' }, { question: 'How many courses are at Forest Creek?', answer: 'Forest Creek features two 18-hole Tom Fazio designs: the South Course and the North Course.' }, { question: 'Is Tom Fazio a member?', answer: 'Yes. Forest Creek is reportedly the only golf club where Fazio himself holds a membership.' }, { question: 'How close is Forest Creek to Pinehurst Resort?', answer: 'Forest Creek is in the Sandhills region just minutes from Pinehurst Resort, offering a private alternative to the resort courses.' }] },
    { id: 'pin-8', name: 'The Cradle at Pinehurst', slug: 'the-cradle-pinehurst', city: 'Pinehurst', state: 'North Carolina', type: 'resort', rating: 4.4, greensFee: '$50–$75', architect: 'Gil Hanse', yearBuilt: 2017, holes: 9, par: 27, yardage: 789, description: 'A Gil Hanse 9-hole short course that has become one of the most talked-about golf experiences in America. The Cradle offers sub-100-yard holes with full-sized Sandhills greens, and the walking-only, family-friendly atmosphere captures the pure joy of golf. It\'s become the must-play addition to any Pinehurst trip.', highlights: ['Gil Hanse 9-hole short course', 'Most talked-about new experience in American golf', 'Walking-only, family-friendly atmosphere'], imageAlt: 'The Cradle at Pinehurst short course with Sandhills greens and walking paths', history: 'The Cradle opened in 2017, designed by Gil Hanse — the architect behind the 2016 Olympic Course in Rio de Janeiro and the restoration of Pinehurst No. 4. This 9-hole, par-27 short course spans just 789 yards with no hole longer than 127 yards, but it has become one of the most talked-about golf experiences in America.\n\nBuilt on Pinehurst resort land between the practice facility and the Pinehurst Brewing Company, The Cradle was conceived as a way to grow the game and create a pure, joyful golf experience accessible to everyone. Walking only, no tee times required — just show up, grab a wedge and putter, and play.\n\nDespite being a short course, The Cradle incorporates genuine Sandhills green complexes with the same wire grass, native sand, and rolling terrain that define Pinehurst No. 2. It has become the must-play addition to any Pinehurst trip and a model for short-course design nationwide.', signatureHoles: [{ hole: 9, par: 3, yardage: 127, description: 'The longest hole at 127 yards and the dramatic finisher. A full-sized Sandhills green complex with genuine Donald Ross-style contours. The elevated green demands precise distance control — anything long rolls off the back.' }], whatToExpect: 'The Cradle is pure, joyful golf distilled to its essence. Nine par-3 holes under 127 yards each, played walking-only with just a wedge and putter. No tee times needed — show up and play. Multiple loops in a session are common and encouraged.\n\nDon\'t mistake "short" for "simple." The greens are full-sized Sandhills putting surfaces with the same wire grass, native sand waste areas, and contours found on Pinehurst No. 2. The chipping and putting challenge is legitimate. Hanse designed the course to be fun for beginners while rewarding skilled short-game players.\n\nThe atmosphere is unlike anywhere else in golf — families, juniors, seasoned players, and first-timers all sharing the same holes. The adjacent Pinehurst Brewing Company and Thistle Dhu putting course complete the experience.', playingTips: 'Bring only a wedge (or two) and a putter. That\'s all you need.\n\nThe greens play like real Pinehurst greens — firm, fast, and contoured. Treat every approach like a precision short-game shot, not a casual flip.\n\nPlay multiple loops. The experience changes with different pin positions and wind conditions. Many visitors play 2-3 loops in a session.\n\nThis is a walking-only course. Embrace the pace and the atmosphere — it\'s designed to be relaxed and social.', faqs: [{ question: 'How long is The Cradle?', answer: 'Nine par-3 holes totaling 789 yards. No hole exceeds 127 yards. Par is 27 for the full loop.' }, { question: 'Do I need a tee time?', answer: 'No. The Cradle operates on a walk-up, first-come basis. No reservations needed — just show up and play.' }, { question: 'Who designed it?', answer: 'Gil Hanse, the architect of the 2016 Olympic Course in Rio and the restoration of Pinehurst No. 4. The Cradle opened in 2017.' }, { question: 'Is it just for beginners?', answer: 'No. While accessible to beginners and families, the full-sized Sandhills green complexes challenge skilled players too. The short-game test is legitimate.' }]},
    { id: 'pin-9', name: 'Tot Hill Farm Golf Club', slug: 'tot-hill-farm', city: 'Pinehurst', state: 'North Carolina', type: 'public', rating: 4.3, greensFee: '$50–$95', architect: 'Mike Strantz', yearBuilt: 2000, holes: 18, par: 72, yardage: 6614, description: 'The second of Mike Strantz\'s two legendary Sandhills designs (alongside Tobacco Road), Tot Hill Farm is a dramatic, artistic golf experience through extreme elevation changes. The course features quarry holes, 200-foot elevation drops, and Strantz\'s signature visual drama.', highlights: ['Mike Strantz\'s second Sandhills masterwork', 'Extreme elevation changes and quarry holes', '200-foot elevation drops'], imageAlt: 'Tot Hill Farm dramatic quarry hole with extreme elevation change in NC Sandhills', history: 'Tot Hill Farm Golf Club opened in 2000 on a 400-acre family farm in Asheboro, NC, designed by Mike Strantz — who moved into the on-site farmhouse during design to fully inhabit the land. The course name honors the three Yates family children: Tucker, Ogburn, and Toler.\n\nStrantz called it his finest work. He used a small horse nicknamed "Little Man" to survey the steep, rocky terrain (a local brewery later honored the horse with "Little Man Lager"). His original pencil sketches hang in the 1851 farmhouse clubhouse.\n\nAfter flood damage in 2003–04 and years of deferred maintenance, new owner Pat Barber launched a $3 million restoration in 2023. The renovation converted all greens to Prizm Zoysia (only the second course in the US to use it), removed 1,200+ trees, restored the 15th waterfall, and reinstated Strantz\'s original three-tier 13th green. The course reopened Labor Day 2023 and earned a spot on Golf Magazine\'s Top 100 Courses You Can Play 2024–25.', signatureHoles: [{ hole: 15, par: 3, yardage: 145, description: 'The "Waterfall Hole" — a downhill par 3 with a restored waterfall cascading behind the green. The course\'s most photographed hole. Aim center; birdie is very gettable from the middle of the green.' }, { hole: 12, par: 4, yardage: 392, description: 'Elevated dogleg left around a pond, with a peninsula green inches above the water. Every swing is exciting. A bolder tee line shortens the approach but brings water fully into play.' }, { hole: 5, par: 5, yardage: 543, description: 'Atop the property\'s highest point with views into Uwharrie National Forest. The T-shaped green is surrounded by rocks, pot bunkers, and a fronting stream — one of the most dramatic putting surfaces in the Carolinas.' }, { hole: 3, par: 3, yardage: 180, description: '"The Rock" — a downhill par 3 to a boomerang-shaped green surrounded by creek on three sides with rocky outcroppings throughout. Aim center to avoid the right bunker and the surrounding water.' }], whatToExpect: 'Tot Hill Farm sits at the foot of the Uwharrie Mountains in central NC and delivers a mountain-course experience with extreme elevation changes on nearly every hole. Betty McGee Creek winds through the property, affecting strategy on all five par 3s.\n\nStrantz built wide fairways — the course looks far more penalizing from the tee than it plays. Trust the width. The Prizm Zoysia greens are firm and fast, requiring precise approach shots to the correct tier. Being on the wrong level can turn a 2-putt into a 4-putt.\n\nThe 1851 farmhouse clubhouse displays Strantz\'s original pencil sketches. Five par 3s (unusual for an 18-hole layout) and four par 5s make for a varied, memorable round.', playingTips: 'Trust the width — fairways are wider than they appear. As Strantz himself said: "Take what the golf course gives you."\n\nGreen tier management is everything. Always identify which tier the pin is on and land on that tier or below — never above. False fronts (especially No. 17) punish short approaches.\n\nUphill holes (4, 9, 18) play significantly longer than the scorecard. Club up by one or two clubs.\n\nKnow Betty McGee Creek. Favor the side of the fairway that gives the best angle away from water on approach.\n\nHole 15: aim center of the green — the waterfall backdrop is beautiful but the surrounding stream penalizes greed. Birdie is very makeable from the middle.', faqs: [{ question: 'Who designed Tot Hill Farm?', answer: 'Mike Strantz, who called it his finest work. He lived on-site during design and construction, opening in 2000.' }, { question: 'What makes Tot Hill Farm unique?', answer: 'Five par 3s, extreme elevation changes, Betty McGee Creek throughout, and Prizm Zoysia greens (only the 2nd US course to use them). The 1851 farmhouse clubhouse displays Strantz\'s original pencil sketches.' }, { question: 'Was Tot Hill Farm recently renovated?', answer: 'Yes. A $3 million restoration in 2023 restored Strantz\'s original vision — 1,200+ trees removed, greens converted to Prizm Zoysia, the waterfall at No. 15 restored, and the original 3-tier 13th green reinstated.' }, { question: 'How far is Tot Hill Farm from Pinehurst?', answer: 'About 50 minutes from Pinehurst. It pairs well with Tobacco Road (Strantz\'s other NC masterwork) for a Sandhills-area golf trip.' }]},
  ],
  'san-diego-california': [
    { id: 'sd-1', name: 'Torrey Pines - South Course', slug: 'torrey-pines-south', city: 'San Diego', state: 'California', type: 'public', rating: 4.7, greensFee: '$80–$230', architect: 'William F. Bell / Rees Jones', yearBuilt: 1957, holes: 18, par: 72, yardage: 7698, description: 'Perched on the cliffs above the Pacific Ocean, Torrey Pines South is one of America\'s most famous municipal courses and host of the Farmers Insurance Open. Tiger Woods\' legendary 2008 U.S. Open victory here cemented its place in golf history.', highlights: ['U.S. Open and PGA Tour venue', 'Pacific Ocean cliffside setting', 'Tiger Woods\' 2008 U.S. Open on one leg'], imageAlt: 'Torrey Pines South Course clifftop hole overlooking Pacific Ocean', history: 'Torrey Pines South was designed by William F. Bell in 1957 as a San Diego municipal facility on dramatic coastal bluffs in La Jolla. Rees Jones renovated the layout in 2001, stretching it to nearly 7,700 yards for U.S. Open standards. The 2008 U.S. Open saw Tiger Woods defeat Rocco Mediate in a Monday playoff on a broken left leg for his 14th major. Jon Rahm won the 2021 U.S. Open here. The South Course also hosts the annual Farmers Insurance Open.', signatureHoles: [{ hole: 3, par: 3, yardage: 201, description: 'One of the most scenic par 3s in American golf, playing from an elevated tee with the Pacific Ocean as backdrop.' }, { hole: 4, par: 4, yardage: 490, description: 'A brutally long par 4 along the cliff edge that ranks among the most difficult holes on the PGA Tour.' }, { hole: 7, par: 4, yardage: 462, description: 'A dogleg right with a ravine crossing the fairway and an uphill approach to a well-defended green.' }, { hole: 12, par: 4, yardage: 504, description: 'A massive par 4 over 500 yards from the tips, running along the canyon with a downhill approach to a bunker-guarded green.' }], whatToExpect: 'Torrey Pines South stretches to nearly 7,700 yards along Pacific Ocean bluffs and through native Torrey pine canyons. Morning marine fog can make the course play longer, while afternoon winds add challenge. As a municipal course, it offers remarkable value for a two-time U.S. Open venue with excellent conditioning.', playingTips: 'Play from appropriate tees — the back tees are for championship-caliber players. Morning tee times offer cooler, calmer conditions and smoother poa annua greens. San Diego residents receive significantly discounted green fees.', faqs: [{ question: 'How much does it cost to play Torrey Pines South?', answer: 'San Diego residents pay approximately $55-$80, while non-residents pay $150-$230 depending on the day.' }, { question: 'Is it hard to get a tee time?', answer: 'Tee times are competitive, especially on weekends. Book as early as possible online.' }, { question: 'Should I play the North or South Course?', answer: 'The South is the championship layout and more famous but harder and more expensive. The North shares the same stunning clifftop setting at a lower price.' }, { question: 'What is the best time of year to play?', answer: 'San Diego enjoys mild temperatures year-round. Summer mornings are ideal before afternoon wind arrives.' }] },
    { id: 'sd-2', name: 'Maderas Golf Club', slug: 'maderas', city: 'San Diego', state: 'California', type: 'public', rating: 4.5, greensFee: '$100–$180', architect: 'Johnny Miller & Robert Muir Graves', yearBuilt: 1999, holes: 18, par: 72, yardage: 7167, description: 'Carved through rugged North County San Diego terrain, Maderas is consistently rated the top daily-fee course in the region. The dramatic layout features waterfall-backed greens, canyon carries, and elevation changes that create a memorable experience.', highlights: ['Top-rated daily-fee course in San Diego', 'Dramatic canyon and waterfall features', 'Johnny Miller design'], imageAlt: 'Maderas Golf Club dramatic canyon hole in north San Diego County', history: 'Maderas Golf Club opened in 1999 in Poway, north of San Diego. Designed by Johnny Miller and Robert Muir Graves on dramatic canyon terrain. Since opening it has been consistently rated the top daily-fee course in San Diego.\n\nThe name means wood in Spanish. Miller utilized every aspect of the hilly landscape to create a course both visually stunning and strategically demanding.', signatureHoles: [{ hole: 8, par: 4, yardage: 415, description: 'Dramatic par 4 in the canyons with significant elevation change.' }, { hole: 9, par: 3, yardage: 175, description: 'Stunning downhill par 3 with canyon views. Most photographed hole.' }, { hole: 14, par: 5, yardage: 555, description: 'Signature hole. Picturesque par 5 requiring strategy as a true three-shot hole.' }, { hole: 18, par: 4, yardage: 445, description: 'Strong finishing par 4 with waterfall behind the green.' }], whatToExpect: 'Dramatic round through hilly terrain. Wide fairways but canyon carries demand thoughtful management. Waterfall-backed greens create stunning visuals.\n\nAt 7,167 yards from the tips with multiple tees for all skill levels.', playingTips: 'Elevation changes affect club selection. Downhill holes play shorter, uphill approaches need extra club.\n\nGreens are firm. Play to centers rather than tucked pins near canyon edges.', faqs: [{ question: 'Is Maderas public?', answer: 'Yes. Daily-fee, $100-$180.' }, { question: 'Designer?', answer: 'Johnny Miller and Robert Muir Graves, opened 1999.' }, { question: 'Location?', answer: 'Poway, about 25 miles north of downtown San Diego.' }, { question: 'Signature hole?', answer: 'Par-5 14th, a three-shot hole through canyon terrain.' }] },
    { id: 'sd-3', name: 'Aviara Golf Club', slug: 'aviara', city: 'San Diego', state: 'California', type: 'resort', rating: 4.4, greensFee: '$150–$275', architect: 'Arnold Palmer', yearBuilt: 1991, holes: 18, par: 72, yardage: 7007, description: 'An Arnold Palmer design at the Park Hyatt Aviara in Carlsbad, this beautifully conditioned course offers ocean views, native landscaping, and a resort golf experience among the finest in Southern California.', highlights: ['Arnold Palmer design', 'Park Hyatt luxury resort', 'Pacific Ocean and lagoon views'], imageAlt: 'Aviara Golf Club Carlsbad ocean view hole', history: 'Aviara Golf Club opened in 1991 as the only Arnold Palmer-designed course in San Diego County. Located at the Park Hyatt Aviara in Carlsbad, it overlooks the Batiquitos Lagoon with Pacific Ocean views.\n\nThe course hosted the LPGA Tour\'s Kia Classic and JTBC Classic from 2010 through 2022. In 2016, a walking bridge at hole 3 was dedicated to Palmer during the 25th anniversary celebration.\n\nAviara has been named the top golf resort in Southern California and draws golfers who appreciate Palmer\'s integration of natural landscape into the playing experience.', signatureHoles: [{ hole: 3, par: 4, yardage: 395, description: 'A scenic par 4 with the Arnold Palmer Memorial Bridge. Views of the Batiquitos Lagoon and a well-bunkered green.' }, { hole: 7, par: 3, yardage: 170, description: 'A beautiful downhill par 3 with ocean views and Palmer\'s bunkering amid native landscaping.' }, { hole: 11, par: 5, yardage: 540, description: 'A risk-reward par 5 with lagoon views where long hitters can reach in two.' }, { hole: 18, par: 5, yardage: 545, description: 'A sweeping finishing par 5 back toward the resort with birdie chances for those navigating the final water hazard.' }], whatToExpect: 'Aviara feels like playing through a botanical garden. Palmer integrated native wildflowers, tropical landscaping, and natural habitats throughout. Lagoon and ocean views appear on multiple holes.\n\nAt 7,007 yards, the course rewards accuracy. The Park Hyatt provides luxury amenities and Carlsbad\'s climate allows year-round play.', playingTips: 'Coastal breezes are common in afternoons. Morning tee times offer calmer conditions.\n\nPalmer\'s greens are well-defended by bunkers and slopes. Keep the ball below the hole on these subtly contoured putting surfaces.', faqs: [{ question: 'Can the public play Aviara?', answer: 'Yes. It is a resort course at the Park Hyatt Aviara with fees typically from $150 to $275.' }, { question: 'Has Aviara hosted pro tournaments?', answer: 'Yes. The LPGA Kia Classic and JTBC Classic were held here from 2010 through 2022.' }, { question: 'Is it an Arnold Palmer design?', answer: 'Yes. The only Palmer-designed course in San Diego County, co-designed with Ed Seay, opened 1991.' }, { question: 'Best time to play?', answer: 'Carlsbad\'s mild climate allows year-round play. Mornings offer calmer winds.' }] },
    { id: 'sd-4', name: 'Steele Canyon Golf Club', slug: 'steele-canyon', city: 'San Diego', state: 'California', type: 'public', rating: 4.2, greensFee: '$50–$100', architect: 'Gary Player', yearBuilt: 1991, holes: 27, par: 72, yardage: 6741, description: 'A Gary Player design with 27 holes offering three distinct nines through the canyons of eastern San Diego County. The course provides excellent value with varied terrain and dramatic elevation changes.', highlights: ['Gary Player design', '27 holes with three nines', 'Canyon and mountain setting'], imageAlt: 'Steele Canyon Golf Club canyon hole in eastern San Diego', history: 'Steele Canyon Golf Club opened in 1991 as a Gary Player Signature design carved through the rugged foothills of San Diego\'s East County, 20 miles east of downtown San Diego. Player personally designed all 27 holes, routing three distinct nines — Canyon, Ranch, and Vineyard — through dramatically varied terrain.\n\nThe Gary Player design philosophy centered on respecting natural terrain rather than reshaping it, which is why the Canyon nine in particular feels wild and organically routed through rocky hillsides. Golf Digest awarded the course a 4.5-star rating, making it one of San Diego County\'s highest-rated public facilities.\n\nThe course has hosted multiple championship events and remains one of Southern California\'s top-value public tracks, offering three different 18-hole experiences from a single visit.', signatureHoles: [{ hole: 3, par: 4, yardage: 446, description: 'Ranch Hole 3, "Parachute" — the tee box sits 175 feet above the fairway. Standing on the tee feels like stepping out of a plane. Plays into prevailing headwinds; the hole is rated Handicap 1 on the Ranch nine. Take significantly less club than the yardage suggests for the drop, then account for wind.' }, { hole: 1, par: 4, yardage: 409, description: 'Canyon Hole 1, "Boomerang" — a dogleg left with a blind bunker lurking on the right. Favor the left side of the fairway and the left side of the green on approach to avoid the hidden hazard.' }, { hole: 4, par: 3, yardage: 204, description: 'Ranch Hole 4, "Echo" — a mid-length par 3 in the heart of the canyon terrain with panoramic East County views.' }], whatToExpect: 'Steele Canyon offers three distinct 18-hole experiences through 27 holes: Canyon (most dramatic, tightest), Ranch (longest, features the signature Parachute hole), and Vineyard (most accessible). The Canyon/Ranch combination is recommended for first-time visitors.\n\nThe defining characteristic is dramatic, unrelenting elevation change. The Canyon nine is genuinely disorienting — the rocky terrain makes it difficult to judge shot direction and carry distances. First-time players are almost always caught off-guard. Greens are fast and smooth.\n\nPace of play can stretch to 5+ hours. The panoramic views of San Diego foothills are exceptional throughout.', playingTips: 'Book the Canyon/Ranch combination for the full Steele Canyon experience — it includes both the wild Canyon terrain and the signature Parachute tee shot.\n\nRanch Hole 3 ("Parachute"): the 175-foot drop means taking 2–3 clubs less than the yardage. However, the prevailing headwind partially counteracts the elevation advantage — balance both factors.\n\nCanyon Hole 1 ("Boomerang"): favor the left side of the fairway to avoid the blind right bunker.\n\nGreens are fast — putt conservatively below the hole. Use a GPS or rangefinder throughout; visual distance estimation is unreliable on these dramatic elevation changes.\n\nCome prepared for a long round — budget 4.5–5 hours.', faqs: [{ question: 'How many holes does Steele Canyon have?', answer: '27 holes across three nines: Canyon, Ranch, and Vineyard. You play two nines for an 18-hole round, giving you three possible combinations.' }, { question: 'What is the signature hole at Steele Canyon?', answer: 'Ranch Hole 3, "Parachute" — the tee box sits 175 feet above the fairway and plays into prevailing headwinds. One of the most dramatic tee shots in Southern California.' }, { question: 'Which 18-hole combination is best?', answer: 'Canyon/Ranch is the most recommended. It pairs the dramatic Canyon terrain (slope 136) with the Ranch\'s signature Parachute hole.' }, { question: 'Who designed Steele Canyon?', answer: 'Gary Player personally designed all 27 holes as a Gary Player Signature Course, opening in 1991.' }]},
    { id: 'sd-5', name: 'Coronado Municipal Golf Course', slug: 'coronado-muni', city: 'San Diego', state: 'California', type: 'public', rating: 4.0, greensFee: '$30–$55', architect: 'Jack Daray', yearBuilt: 1957, holes: 18, par: 72, yardage: 6633, description: 'With views of downtown San Diego, the Coronado Bridge, and the Pacific, this bayside municipal course may be the most scenic affordable golf in America. While the layout is straightforward, the setting is world-class.', highlights: ['Downtown San Diego skyline views', 'Coronado Bridge backdrop', 'Most scenic municipal course in America'], imageAlt: 'Coronado Municipal Golf Course with San Diego skyline and bay views', history: 'Golf on Coronado Island dates to 1897–1898, when a 9-hole private course near the Hotel Del Coronado became one of the first golf sites in California. The current municipal course was designed by Jack Daray Sr. and opened December 19, 1957 — the same year as Torrey Pines — with an inaugural foursome that included Billy Casper and Gene Littler, two Hall of Fame PGA Tour champions who were San Diego-area locals at the time.\n\nConstruction of the Coronado Bridge (1966–1969) required acquisition of part of the original course. Jack Daray Jr. redesigned the front nine into its current routing around the bridge construction; the bridge opened August 3, 1969. The redesign created the unique and dramatic relationship between the course and bridge that defines the experience today. A new clubhouse was built in 1997.', signatureHoles: [{ hole: 16, par: 4, yardage: 370, description: 'The most celebrated back-nine hole, running alongside Glorietta Bay. A slight dogleg right with seven bunkers including three greenside. The bay runs left — conservative right-side play removes water from the equation. Golf Digest singled this hole out for having the best views on the course.' }, { hole: 5, par: 3, yardage: 163, description: 'The front nine\'s visual showpiece, with the Coronado Bridge looming dramatically in the background — one of the most photographed tee shots on the course. A missed green here makes scrambling difficult.' }, { hole: 3, par: 4, yardage: 406, description: 'The only front-nine hole directly bordering San Diego Bay. A demanding par 4 requiring a strong tee shot and precise approach with the bay as both backdrop and hazard.' }], whatToExpect: 'Coronado Municipal may be the most scenic affordable golf in America. Views change throughout the round: San Diego skyline and Coronado Bridge on the front nine; Hotel Del Coronado and Glorietta Bay on the back. Holes 15, 16, 17, and 18 all play at or along the waterfront.\n\nThe layout is a classic old-school parkland/coastal hybrid — flat enough to walk comfortably. Fairways are wide, greens are well-maintained and can be quick. Note that nearly every hole features a significant dogleg — golfers who rely on a left-to-right ball flight will find most doglegs going the wrong direction.\n\nCourse marshals actively enforce pace of play. Morning rounds are ideal for calmer wind conditions and the best light on the bridge and bay.', playingTips: 'This is a dogleg course — study hole diagrams before each tee shot. Hitting driver straight is often the wrong play; identify the landing zone that opens the proper approach angle.\n\nOn water holes 16, 17, and 18, the bay is on the left. Taking the right side off the tee removes water from play.\n\nHole 8: placing your tee shot near (not in) the right-side fairway bunker opens the best angle into a slightly elevated green.\n\nWind off the bay affects club selection on par 3s by one to three clubs — mornings are calmer. Morning tee times are recommended in summer when afternoon sea breezes pick up.', faqs: [{ question: 'Why is Coronado Municipal famous?', answer: 'For its extraordinary views — San Diego skyline, Coronado Bridge, Glorietta Bay, and Hotel Del Coronado. Holes 15–18 all play alongside the waterfront. It may be the most scenic affordable municipal golf in America.' }, { question: 'How did the Coronado Bridge affect the course?', answer: 'Bridge construction (1966–69) required redesigning the front nine. Jack Daray Jr. rerouted the holes around the construction, creating the famous bridge backdrop that now defines the course experience.' }, { question: 'Who played in the inaugural round?', answer: 'Billy Casper and Gene Littler — two Hall of Fame PGA Tour champions who were local San Diego golfers — along with first head pro Don Collette, on December 19, 1957.' }, { question: 'Is it walkable?', answer: 'Yes. The terrain is gently undulating and very walkable. Walking the course allows you to fully appreciate the bay views and the course\'s vintage character.' }]},
    { id: 'sd-6', name: 'Torrey Pines North Course', slug: 'torrey-pines-north', city: 'San Diego', state: 'California', type: 'public', rating: 4.3, greensFee: '$80–$175', architect: 'William F. Bell (redesigned Tom Weiskopf)', yearBuilt: 1957, holes: 18, par: 72, yardage: 6874, description: 'The more accessible sibling to the famous South Course, Torrey Pines North was redesigned by Tom Weiskopf in 2016 to bring more strategic interest and championship character. The clifftop location overlooking the Pacific Ocean is equally stunning, with more forgiving fairways and approachable greens.', highlights: ['Tom Weiskopf 2016 redesign', 'Same stunning Pacific clifftop setting', 'More accessible than the South Course'], imageAlt: 'Torrey Pines North Course Pacific Ocean clifftop view in La Jolla', history: 'Torrey Pines Golf Course was built on land that served as Camp Callan, a WWII U.S. Army anti-aircraft training center housing up to 40,000 soldiers (1941–1945). After the war, the City of San Diego claimed the mesa and commissioned architect William P. Bell Sr. to design a golf facility. Bell Sr. passed away in 1953 before completion; his son William F. Bell Jr. finished the project. Both the North and South courses opened in 1957.\n\nIn 2016, the North Course underwent a $12.6 million renovation by legendary architect Tom Weiskopf. He enlarged greens by 20–30%, reduced bunkers from 60 to 42, and most notably swapped the front and back nines — placing the dramatic ocean clifftop holes as the finishing stretch. The renovation is now widely credited with transforming a beloved but modest public layout into a championship-caliber test. The North Course is part of the same City of San Diego municipal facility that hosts the Farmers Insurance Open (PGA Tour) and has staged two U.S. Opens.', signatureHoles: [{ hole: 15, par: 3, yardage: 202, description: 'The undisputed signature hole — a downhill par 3 of 202 yards with panoramic Pacific Ocean views. The tee box overlooks the La Jolla coastline and ocean cove. Play 1–2 clubs less than the raw yardage suggests due to the downhill elevation. GolfPass calls it one of the most beautiful par 3s in California.' }, { hole: 16, par: 4, yardage: 393, description: 'The "most thrilling tee shot at Torrey Pines North" per Golf Digest. Runs along the Pacific Ocean cliffs with the ocean immediately to one side. At ~393 yards it is not overly long, but visual intimidation is high. A controlled fade down the right-center is the preferred play.' }, { hole: 6, par: 3, yardage: 168, description: 'The front nine\'s lone clifftop par 3, playing downhill with sweeping ocean views. An early preview of the dramatic back nine scenery. Wind off the Pacific is the primary club-selection factor.' }], whatToExpect: 'Torrey Pines North divides into two distinct experiences. The front nine (holes 1–9) is an inland mesa layout — solid and strategic but relatively unremarkable visually, apart from the par-3 6th. The back nine (holes 13–18) delivers the full Torrey Pines experience along Pacific Ocean cliffs, culminating in the spectacular 14–15–16 stretch.\n\nThe North is more accessible than the famous South Course — wider fairways, shorter rough, and enlarged greens (post-Weiskopf). PGA Tour pros regularly shoot 8–10 under par on the North; the South is one of the ten most difficult layouts on Tour.\n\nWind is a constant factor on the back nine. Morning tee times offer calmer conditions and better photography light on the clifftop holes. Non-residents pay ~$258–$322 plus a non-refundable $50 booking fee; San Diego residents pay ~$51 on weekdays.', playingTips: 'Book from the Green tees (~6,400 yards, slope 125) unless you are a scratch golfer. The Black tees (7,258 yards, slope 134, rating 75.8) are severe and will grind down mid-to-high handicappers.\n\nHole 15 (signature par 3, 202 yards): play 1–2 clubs less than normal — the downhill grade is significant. Many golfers hit a 5 or 6-iron here.\n\nHole 16: aim center-to-right on the tee shot. A pull or draw toward the cliff side is the danger. The hole is only ~393 yards — precision, not power, is what matters.\n\nHole 13 (back nine opener): there is out-of-bounds left off the tee. Aim center-to-right for safety.\n\nMorning tee times avoid both afternoon wind and the marine layer that can obscure ocean views in summer months.', faqs: [{ question: 'How does the North Course differ from the South?', answer: 'The South Course is the U.S. Open/Farmers Insurance venue — longer, tighter, with penalizing rough. The North was redesigned by Tom Weiskopf in 2016 and is more accessible, with wider fairways and larger greens, while offering the same iconic Pacific Ocean clifftop setting.' }, { question: 'What is the signature hole?', answer: 'Hole 15, a downhill 202-yard par 3 overlooking the Pacific Ocean and La Jolla coastline. Take 1–2 clubs less than normal due to the elevation drop.' }, { question: 'Who designed the North Course?', answer: 'Originally designed by William F. Bell Jr. (completing his late father\'s work) and opened in 1957. Tom Weiskopf led a $12.6 million renovation in 2016 that included swapping the front and back nines.' }, { question: 'Does the North Course host PGA Tour events?', answer: 'Yes. During the annual Farmers Insurance Open, players play one round on the North Course and one on the South. The North typically produces much lower scores — Justin Rose shot a course-record 10-under 62 in January 2026.' }]},
    { id: 'sd-8', name: 'Aviara Golf Club', slug: 'aviara-golf-club', city: 'San Diego', state: 'California', type: 'resort', rating: 4.5, greensFee: '$175–$295', architect: 'Arnold Palmer', yearBuilt: 1991, holes: 18, par: 72, yardage: 7007, description: 'Part of the Park Hyatt Aviara resort in Carlsbad, this Arnold Palmer design hosts the LPGA\'s Kia Classic and features stunning Pacific Ocean views, lush tropical landscaping, and some of the best-conditioned playing surfaces in Southern California.', highlights: ['LPGA Kia Classic host', 'Arnold Palmer coastal design', 'Park Hyatt Aviara resort'], imageAlt: 'Aviara Golf Club Arnold Palmer design with Pacific Ocean views in Carlsbad', history: 'Aviara Golf Club opened in 1991, designed by Arnold Palmer — the only Palmer signature course on the Southern California coast and the only one in San Diego. The resort hotel opened seven years later in 1998, initially as the Four Seasons Resort Aviara before transitioning to the Park Hyatt Aviara brand.\n\nThe course borders the Batiquitos Lagoon Nature Preserve, a protected coastal wetland that frames multiple holes and provides Pacific Ocean views from elevated points. Managed by Troon Golf since 2014, Aviara has hosted the LPGA Kia Classic (later JTBC Classic) annually since 2013 — winners include Inbee Park (2021) and Cristie Kerr (2015).\n\nAwards include Golf Magazine\'s 2004 Gold Medal Resort Award and Golf Digest readers\' vote as the No. 1 Golf Resort in Southern California. The course celebrated its 30th anniversary in 2021.', signatureHoles: [{ hole: 3, par: 3, yardage: 149, description: 'The most photographed hole — water flanks both left and right sides of one of the smallest greens on the course, leaving virtually no bailout room. Despite a handicap rating of 17 (second-easiest on the card), it is deceptively penal. Take one club more and aim center-green.' }, { hole: 14, par: 3, yardage: 201, description: 'The other marquee par 3 — plays downhill over a scenic pond connected to the Batiquitos Lagoon Nature Preserve. Wind off the lagoon almost always pushes left to right. The downhill grade reduces effective yardage, but at handicap 9 it is the hardest-ranked par 3 on the course.' }, { hole: 10, par: 5, yardage: 530, description: 'The most strategically demanding hole — a sharp 60-degree dogleg left that punishes players who try to cut the corner. A conservative iron or hybrid to the right-center of the fairway sets up a much better angle than a driver that drifts left.' }], whatToExpect: 'Aviara is sculpted through rolling hillsides, canyon terrain, and lush tropical landscaping — often described as "playing in a botanical garden." The greens are the defining challenge: large, heavily undulating, and fast (approximately stimpmeter 11). Multiple tiers create significant break, and lip-outs are common on second-guessed strokes.\n\nFrom the Palmer tees (7,007 yards, slope 144), this is a legitimately demanding layout. The course is fair from middle and forward tees (slope 133 and 132). Views of the Batiquitos Lagoon and Pacific Ocean are visible from multiple elevated points. Herons, egrets, and osprey are commonly seen during a round.\n\nPace of play can be slow on weekends. Book early morning tee times for faster rounds.', playingTips: 'Club selection is everything — the terrain changes elevation constantly. Many approaches play uphill or downhill, altering effective yardage significantly.\n\nDo not overpower the course. Several holes punish drivers and reward strategic irons or hybrids off the tee. The 60-degree dogleg on Hole 10 is the prime example.\n\nAll four par 3s carry water or severe penalty. On holes 3 and 14, water is immediately adjacent to the green. Aim center-green and take enough club.\n\nSpend time on the putting green before your round. The greens roll fast with significant slope — speed catches unprepared players.\n\nCoastal wind off Batiquitos Lagoon is a constant factor, particularly on the back nine.', faqs: [{ question: 'Is Aviara the only Arnold Palmer course in San Diego?', answer: 'Yes — and the only coastal Palmer signature course in all of California. It opened in 1991 at what is now the Park Hyatt Aviara resort in Carlsbad.' }, { question: 'Does it host professional tournaments?', answer: 'Yes. The LPGA Kia Classic (later JTBC Classic) has been held here annually since 2013. Past winners include Inbee Park and Cristie Kerr.' }, { question: 'How fast are the greens?', answer: 'Approximately stimpmeter 11 — fast with significant undulation. Spending time on the practice green before your round is strongly recommended.' }, { question: 'What is the Batiquitos Lagoon?', answer: 'A protected coastal wetland preserve bordering the course — one of the few remaining tidal wetlands on the Southern California coast. Herons, egrets, and osprey are commonly spotted during play.' }]},
    { id: 'sd-9', name: 'Mount Woodson Golf Club', slug: 'mount-woodson', city: 'San Diego', state: 'California', type: 'public', rating: 4.0, greensFee: '$50–$95', architect: 'unknown', yearBuilt: 1971, holes: 18, par: 70, yardage: 5740, description: 'A hidden gem in Ramona northeast of San Diego, Mount Woodson offers one of the most dramatically scenic golf experiences in the county. The short but challenging mountain layout features boulder-framed holes, dramatic elevation changes, and panoramic views that rival any course in the state for sheer visual drama.', highlights: ['Most scenic course in San Diego County', 'Boulder-framed mountain holes', 'Short but dramatically challenging'], imageAlt: 'Mount Woodson boulder-framed mountain hole with panoramic San Diego County views', history: 'Mount Woodson Golf Club was designed by architects Brian Curley and Lee Schmidt, who carved a layout through rocky, mountainous terrain in Ramona northeast of San Diego. The par-70 course earned a reputation as one of the most scenic golf experiences in the county.\n\nAlliance GCP LLC purchased the club in 2016 and has worked to maintain the unique playing experience. Despite being shorter at approximately 6,000 yards, the dramatic terrain creates genuinely challenging golf.\n\nMount Woodson sits surrounded by massive granite boulders and native chaparral, offering a mountain golf experience just 45 minutes from the coast.', signatureHoles: [{ hole: 3, par: 4, yardage: 345, description: 'A short par 4 framed by massive granite boulders with a green tucked among the rocks.' }, { hole: 7, par: 3, yardage: 165, description: 'A scenic par 3 with panoramic mountain and valley views from an elevated tee.' }, { hole: 12, par: 4, yardage: 380, description: 'A challenging par 4 with significant elevation change demanding careful club selection.' }, { hole: 16, par: 3, yardage: 155, description: 'A dramatic par 3 with boulders framing the green.' }], whatToExpect: 'A one-of-a-kind mountain golf experience. At roughly 6,000 yards par 70, dramatic elevation changes, narrow fairways, and boulder-lined holes create genuine challenge. Every hole offers stunning views.\n\nThe hilly terrain makes the course play harder than the scorecard suggests.', playingTips: 'Elevation changes dramatically affect club selection. Trust yardage markers rather than your eyes.\n\nAccuracy trumps distance. Walking is challenging due to terrain so consider a cart.', faqs: [{ question: 'Can the public play Mount Woodson?', answer: 'Yes. Green fees typically range from $50 to $95.' }, { question: 'How far from San Diego?', answer: 'About 45 minutes northeast of downtown in Ramona.' }, { question: 'Is it walkable?', answer: 'Very hilly. Walking is possible but demanding. Most players take a cart.' }, { question: 'Who designed it?', answer: 'Brian Curley and Lee Schmidt.' }] },
  ],
  'los-angeles-california': [
    { id: 'la-1', name: 'Riviera Country Club', slug: 'riviera', city: 'Los Angeles', state: 'California', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'George C. Thomas Jr.', yearBuilt: 1927, holes: 18, par: 71, yardage: 7322, description: 'Known as "Hogan\'s Alley," Riviera is one of the most celebrated courses in the world and host of the Genesis Invitational. George C. Thomas Jr.\'s genius routing through Temescal Canyon features the iconic 10th hole and a par-3 6th with a bunker in the middle of the green.', highlights: ['Genesis Invitational PGA Tour host', '"Hogan\'s Alley" historic legacy', 'George C. Thomas Jr. masterpiece'], imageAlt: 'Riviera Country Club iconic barranca and canyon setting in Pacific Palisades', history: 'Riviera Country Club opened in 1927 in Pacific Palisades, California, designed by George C. Thomas Jr. with construction overseen by Billy Bell. Thomas, a Philadelphia blue-blood who moved west for his health, initially resisted designing the course but ultimately created what many consider his masterpiece. The original plan called for an 18-hole championship layout, a shorter course, and a pitch-and-putt, though only the championship course survives today.\n\nThe club quickly became a fixture of Hollywood glamour and championship golf. It hosted the 1929 and 1995 PGA Championships, the 1948 U.S. Open won by Ben Hogan (earning the course its famous nickname "Hogan\'s Alley"), and has been the permanent home of the Genesis Invitational (formerly the LA Open) on the PGA Tour.\n\nRiviera celebrated its centennial in 2026, having undergone careful renovations over the decades that preserved Thomas\'s original strategic genius. The course is consistently ranked in the top 15 in America and top 25 in the world, revered by architecture aficionados for its creative green complexes, bold bunkering, and brilliant routing through Temescal Canyon.', signatureHoles: [{ hole: 4, par: 3, yardage: 236, description: 'Thomas\'s take on the famous Redan hole at North Berwick, recently lengthened by nearly 40 yards to over 230 yards. This long par 3 plays slightly uphill with a green angled from front-right to back-left, demanding a precise long iron.' }, { hole: 6, par: 3, yardage: 199, description: 'One of the most famous par 3s in the world, featuring a pot bunker placed directly in the center of the green. Players must choose whether to attack the pin or play safe to the side, creating endless strategic debate.' }, { hole: 10, par: 4, yardage: 315, description: 'Frequently called the greatest short par 4 in the world. At just 315 yards, the green is theoretically drivable but fiercely protected by a front bunker, a barranca, and a severely contoured green that rejects anything less than perfect.' }, { hole: 18, par: 4, yardage: 476, description: 'A demanding finishing hole that plays uphill through a natural amphitheater toward the iconic clubhouse. The approach must carry a massive barranca to reach a green tucked against the hillside.' }], whatToExpect: 'Riviera plays through a stunning natural canyon setting in Pacific Palisades, with eucalyptus-lined fairways, dramatic barrancas (dry creek beds), and gentle elevation changes throughout. The marine layer and coastal breezes from the nearby Pacific frequently come into play, particularly on morning rounds. The kikuyu grass rough is notoriously thick and grabby, making accuracy off the tee essential.\n\nDespite playing at just 7,322 yards with a par of 71, Riviera is a stern test of golf. The course features only two par 5s (both on the front nine) and four par 3s, with the remaining twelve par 4s ranging from the drivable 10th to the brutish 476-yard 18th. Green complexes are among the most creative and demanding in championship golf.', playingTips: 'Course management is everything at Riviera. The kikuyu rough punishes wayward tee shots severely, so keeping the ball in play is more important than distance. On the par 3s, pay careful attention to pin positions — the green complexes reward precision and punish anything that misses on the wrong side.\n\nThe greens are generally fast and feature subtle breaks influenced by the canyon terrain. Approach shots that land below the hole will leave manageable putts, while those above the hole face slippery downhill putts. On the iconic 10th hole, laying up to a comfortable wedge distance is often the smarter play than going for the green.', faqs: [{ question: 'Can the public play Riviera Country Club?', answer: 'Riviera is a private club and public play is not available. Access requires an invitation from a member. The course is visible to fans during the annual Genesis Invitational PGA Tour event each February.' }, { question: 'Why is Riviera called Hogan\'s Alley?', answer: 'Ben Hogan won the 1947 and 1948 Los Angeles Opens and the 1948 U.S. Open at Riviera, dominating the course so thoroughly that it earned the nickname "Hogan\'s Alley" in his honor.' }, { question: 'What makes the 6th hole at Riviera so famous?', answer: 'The par-3 6th features a pot bunker placed in the middle of the green, creating one of the most unique and strategic holes in golf. George Thomas designed it to offer multiple angles of attack depending on the pin position.' }, { question: 'Has Riviera hosted major championships?', answer: 'Yes. Riviera has hosted the 1948 U.S. Open, the 1929 and 1995 PGA Championships, and the annual PGA Tour Genesis Invitational.' }] },
    { id: 'la-2', name: 'Los Angeles Country Club - North', slug: 'lacc-north', city: 'Los Angeles', state: 'California', type: 'private', rating: 5.0, greensFee: 'Members Only', architect: 'George C. Thomas Jr. / Gil Hanse', yearBuilt: 1921, holes: 18, par: 72, yardage: 7556, description: 'Host of the 2023 U.S. Open, Los Angeles Country Club is one of America\'s most exclusive and highly ranked courses. The Gil Hanse restoration brought this George C. Thomas Jr. gem back to its original strategic brilliance, set incongruously amid Beverly Hills and Century City.', highlights: ['2023 U.S. Open host', 'Top 5 course in America', 'Stunning Beverly Hills setting'], imageAlt: 'Los Angeles Country Club North Course with Century City skyline', history: 'The Los Angeles Country Club was founded in 1897, making it one of the oldest clubs in Southern California. The North Course was originally designed by George C. Thomas Jr. and William Bell in 1927, routed through a remarkable 312-acre property in the heart of Beverly Hills and Century City. For decades the club shunned the spotlight, declining to host major events despite having one of the finest courses in America.\n\nIn 2010, architect Gil Hanse, along with Jim Wagner and golf historian Geoff Shackelford, completed a masterful restoration of the North Course that returned the layout to Thomas\'s original strategic vision. The restoration uncovered lost features, removed decades of tree encroachment, and rebuilt green complexes to their original bold contours. Hanse even recreated a lost replica of the famous "Little 17th" hole as a hidden 19th hole on the property.\n\nThe club finally stepped into the spotlight by hosting the 2023 U.S. Open, where Wyndham Clark won the championship. The event was widely praised, and the course received universal acclaim from players and media. The North Course is now consistently ranked among the top five courses in America.', signatureHoles: [{ hole: 3, par: 4, yardage: 400, description: 'A short par 4 that mixes together all of the North Course\'s best ingredients. The fairway angles from left to right with multiple strategic options off the tee, and the green complex rewards creative approach play from various angles.' }, { hole: 11, par: 3, yardage: 232, description: 'A dramatic long par 3 that played as one of the most difficult holes during the 2023 U.S. Open. The green is perched on a ridge with severe falloffs on all sides, demanding an accurate long iron under pressure.' }, { hole: 15, par: 3, yardage: 205, description: 'A gorgeous par 3 with the Century City skyline towering beyond the green, creating one of the most surreal backdrops in all of golf. The green features Thomas\'s characteristic bold contours.' }, { hole: 18, par: 4, yardage: 420, description: 'A strong finishing hole that plays uphill to a well-defended green. During the 2023 U.S. Open, this hole provided a demanding final test with its narrow fairway and challenging approach.' }], whatToExpect: 'LACC North occupies one of the most valuable and unlikely pieces of real estate in golf — 312 acres bordered by Beverly Hills, Century City, and Bel-Air. The juxtaposition of a sprawling, golden-hued links-style landscape against a backdrop of gleaming skyscrapers is unlike anything else in the sport. The course features wide fairways with strategic bunkering, firm and fast playing conditions, and Thomas\'s characteristically bold green complexes.\n\nThe terrain rolls gently through native grasses and open ground, with the restoration having removed many trees to reveal the original wide-open character. At 7,556 yards from the championship tees, the course is a serious test, but the multiple angles of approach mean it rewards thoughtful play at every skill level.', playingTips: 'The key to scoring at LACC North is understanding the angles. Thomas designed greens that are most receptive from specific positions in the fairway, so positioning off the tee is more important than distance. The firm, fast conditions mean you can use the ground game effectively — running approach shots onto greens is often the smarter play.\n\nAfternoon winds from the Pacific can significantly affect play, particularly on the exposed holes. Club selection on the par 3s should account for the firm greens and the tendency for balls to release toward the edges of the putting surfaces.', faqs: [{ question: 'Can the public play Los Angeles Country Club?', answer: 'No. LACC is one of the most exclusive private clubs in America and does not offer public access. The 2023 U.S. Open provided a rare public glimpse of the course.' }, { question: 'Who designed the LACC North Course?', answer: 'The course was originally designed by George C. Thomas Jr. and William Bell in 1927. Gil Hanse, Jim Wagner, and Geoff Shackelford completed a celebrated restoration in 2010 that returned the course to Thomas\'s original design intent.' }, { question: 'What happened at the 2023 U.S. Open at LACC?', answer: 'Wyndham Clark won the 2023 U.S. Open at LACC North, finishing at 10-under par. The event was the first major championship held at the club and was widely praised for the quality of the course.' }, { question: 'Why are there skyscrapers visible from the course?', answer: 'LACC sits on 312 acres in the heart of west Los Angeles, bordered by Beverly Hills and Century City. The contrast of the natural, links-style landscape against the glittering skyline creates one of the most unique settings in world golf.' }] },
    { id: 'la-3', name: 'Rustic Canyon Golf Course', slug: 'rustic-canyon', city: 'Los Angeles', state: 'California', type: 'public', rating: 4.5, greensFee: '$35–$75', architect: 'Gil Hanse & Geoff Shackelford', yearBuilt: 2002, holes: 18, par: 72, yardage: 6900, description: 'A Gil Hanse/Geoff Shackelford design in Moorpark, Rustic Canyon is a links-inspired layout that stands as one of the best public golf values in America. The no-frills, walk-friendly course lets the architecture speak for itself.', highlights: ['Gil Hanse public course gem', 'Links-inspired Southern California design', 'Among America\'s best public values'], imageAlt: 'Rustic Canyon Golf Course links-style layout in Moorpark', history: 'Rustic Canyon Golf Course opened in 2002 on a former sheep ranch in Moorpark, California. It was a collaboration between Gil Hanse, Jim Wagner, and golf writer Geoff Shackelford, who set out to prove Golden Age design virtues could work on a value-priced public course.\n\nBuilt without detailed blueprints, Hanse Golf shaped contoured green complexes and sculpted bunkers from natural terrain in a minimalist approach inspired by early 20th-century architects. The course opened to rave reviews.\n\nRustic Canyon is consistently ranked among the best public courses in the United States and has become a pilgrimage site for architecture enthusiasts.', signatureHoles: [{ hole: 2, par: 4, yardage: 457, description: 'One of the toughest holes on the front nine, this long par 4 demands a powerful accurate drive and a precise approach to a well-defended green complex.' }, { hole: 13, par: 4, yardage: 315, description: 'A short drivable par 4 embodying the strategic nature of the design with multiple options off the tee.' }, { hole: 15, par: 3, yardage: 147, description: 'A short par 3 with a deceptive green complex featuring significant contour. Accuracy matters more than distance.' }, { hole: 16, par: 4, yardage: 479, description: 'The toughest hole on the course. The tee shot plays downhill but the approach plays uphill to a demanding green.' }], whatToExpect: 'Rustic Canyon is a minimalist links-inspired design that strips golf to its essentials. The natural terrain and creative architecture speak for themselves.\n\nThe layout plays firm and fast with wide fairways encouraging ground-game shots and large undulating greens accepting running approaches. Walking is strongly encouraged.', playingTips: 'Rustic Canyon rewards creativity and ground-game skills. Running the ball onto greens is often the smartest play.\n\nThe large green complexes offer many pin positions so pay attention to flag locations. Wind can be significant in the afternoon.', faqs: [{ question: 'How much does it cost to play Rustic Canyon?', answer: 'Green fees range from $35 to $75, making it one of the best values in American golf.' }, { question: 'Who designed Rustic Canyon?', answer: 'Gil Hanse, Jim Wagner, and Geoff Shackelford collaborated on the 2002 design on a former sheep ranch in Moorpark.' }, { question: 'Is Rustic Canyon walking friendly?', answer: 'Yes. It is one of the most walkable courses in Southern California.' }, { question: 'Why is Rustic Canyon so highly rated?', answer: 'The minimalist links-inspired design brings Golden Age principles to an affordable public course, consistently ranking among the best in America.' }] },
    { id: 'la-4', name: 'Pelican Hill Golf Club - Ocean South', slug: 'pelican-hill-south', city: 'Los Angeles', state: 'California', type: 'resort', rating: 4.6, greensFee: '$200–$350', architect: 'Tom Fazio', yearBuilt: 1991, holes: 18, par: 70, yardage: 6580, description: 'Overlooking the Pacific from Newport Coast, Pelican Hill\'s Ocean South Course delivers one of the most spectacular resort golf experiences in California. Tom Fazio sculpted 18 holes with sweeping ocean panoramas and immaculate conditioning.', highlights: ['Sweeping Pacific Ocean panoramas', 'Tom Fazio coastal design', 'Resort at Pelican Hill luxury setting'], imageAlt: 'Pelican Hill Ocean South Course overlooking Pacific Ocean', history: 'The Ocean South opened in 1991 as the first of two Tom Fazio designs at Pelican Hill in Newport Coast. Perched 300 feet above the Pacific with 270-degree views, it became one of Fazio\'s most celebrated coastal works. The Ocean North followed in 1993. The Resort at Pelican Hill opened in 2008.\n\nThe course is undergoing a restoration to refresh Fazio\'s original design while maintaining the coastal character.', signatureHoles: [{ hole: 4, par: 3, yardage: 142, description: 'Short par 3 with panoramic Pacific views to Catalina Island and deep bunkers.' }, { hole: 7, par: 3, yardage: 193, description: 'Scenic hole with pond fronting the green and sweeping coastal views.' }, { hole: 8, par: 5, yardage: 562, description: 'Sweeping par 5 with risk-reward options. Long hitters can reach in two.' }, { hole: 10, par: 4, yardage: 475, description: 'Number one handicap hole. Wind and length make par a good score.' }], whatToExpect: 'Every hole provides Pacific panoramas to Catalina Island. Par-70 at 6,580 yards through sage and eucalyptus. First-class resort with immaculate conditions year-round.', playingTips: 'Ocean breezes are the primary defense. Morning tee times offer calmer conditions. Fazio\'s deep bunkers are penal. Greens roll true.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Open to resort guests and outside players, $200-$350.' }, { question: 'South vs North?', answer: 'Both Fazio. South par 70 (1991). North par 71 (1993).' }, { question: 'Distance from LA?', answer: 'About 50 miles south in Newport Coast.' }, { question: 'Best season?', answer: 'Year-round. Mornings avoid afternoon breezes.' }] },
    { id: 'la-5', name: 'Angeles National Golf Club', slug: 'angeles-national', city: 'Los Angeles', state: 'California', type: 'public', rating: 4.3, greensFee: '$80–$150', architect: 'Jack Nicklaus', yearBuilt: 2004, holes: 18, par: 72, yardage: 7016, description: 'A Jack Nicklaus design in the San Fernando Valley foothills, Angeles National offers a challenging, well-conditioned public golf experience with dramatic views of the Angeles National Forest and San Gabriel Mountains.', highlights: ['Jack Nicklaus design', 'Angeles National Forest views', 'Challenging valley foothill routing'], imageAlt: 'Angeles National Golf Club with San Gabriel Mountains backdrop', history: 'Angeles National Golf Club opened in 2004, designed by Jack Nicklaus in the San Fernando Valley foothills of Sunland, California. It was Nicklaus\'s first public-access course in the greater Los Angeles area, built on former movie ranch land surrounded by the Angeles National Forest and San Gabriel Mountains.\n\nThe course was originally envisioned as a high-end daily-fee facility to bring Nicklaus-caliber design to public golfers in LA. At 7,016 yards from the tips with dramatic canyon crossings and mountain views, it quickly established itself as one of the most challenging and scenic public courses in Southern California.\n\nThe layout takes full advantage of the foothill terrain, routing holes through natural canyons with significant elevation changes. The Angeles National Forest provides an unspoiled backdrop that feels miles removed from urban Los Angeles despite being just 30 minutes from downtown.', signatureHoles: [{ hole: 15, par: 3, yardage: 195, description: 'A dramatic downhill par 3 with a forced carry over a canyon to a well-bunkered green. The San Gabriel Mountains provide a stunning backdrop. One of the most photographed holes on the course — take less club due to the elevation drop.' }, { hole: 18, par: 5, yardage: 555, description: 'A risk-reward finishing par 5 with water guarding the approach to the green. Reachable in two for long hitters willing to carry the hazard, but a smart layup leaves a manageable wedge to close the round.' }], whatToExpect: 'Angeles National plays through dramatic foothill terrain with canyon crossings, significant elevation changes, and mountain views throughout. The Angeles National Forest surrounds the course, creating an unspoiled natural setting that feels far from LA despite being 30 minutes from downtown.\n\nNicklaus designed the course with his trademark strategic choices off the tee — multiple routes on most holes that reward smart course management. The fairways are generous but the approaches demand precision, particularly on the canyon holes with forced carries.\n\nConditions are consistently strong for a high-volume public course. The mountain setting means temperatures can be 5-10 degrees cooler than the valley floor — welcome relief in summer.', playingTips: 'Canyon holes require confident forced carries. Know your distances honestly and don\'t get caught between clubs — commit to the shot.\n\nThe mountain elevation and dry air can add distance to shots. Factor this in, especially on the downhill par 3s.\n\nNicklaus provides multiple routes on most holes. On first visits, play the conservative line until you learn where the fairway bunkers and canyon edges are.\n\nThe back nine is significantly more demanding than the front. Save some energy and concentration for the stretch run.\n\nMorning tee times offer the best conditions — afternoon winds can pick up in the foothill canyons.', faqs: [{ question: 'Who designed Angeles National?', answer: 'Jack Nicklaus — his first public-access course in the greater Los Angeles area. The course opened in 2004 on former movie ranch land in the San Fernando Valley foothills.' }, { question: 'How challenging is it?', answer: 'At 7,016 yards with canyon forced carries and significant elevation changes, it is one of the more demanding public courses in Southern California. The back nine is particularly challenging.' }, { question: 'What are the views like?', answer: 'The Angeles National Forest and San Gabriel Mountains provide a spectacular natural backdrop throughout the round. The setting feels far from urban LA despite being 30 minutes from downtown.' }, { question: 'Is it walkable?', answer: 'The significant elevation changes and canyon crossings make it difficult to walk. Cart play is standard.' }]},
    { id: 'la-7', name: 'Bel-Air Country Club', slug: 'bel-air-country-club', city: 'Los Angeles', state: 'California', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'George C. Thomas Jr. / Jack Neville', yearBuilt: 1926, holes: 18, par: 71, yardage: 6619, description: 'One of LA\'s most iconic private clubs, Bel-Air features a suspension bridge, dramatic canyon routing, and the Golden Age genius of George C. Thomas. The compact, rolling layout rewards precise shot-making and creative recovery skills over raw power.', highlights: ['Iconic suspension bridge', 'George C. Thomas canyon routing', 'Celebrity-studded private club'], imageAlt: 'Bel-Air Country Club canyon routing with famous suspension bridge in Los Angeles', history: 'Bel-Air Country Club was founded in the mid-1920s by oil magnate Alphonzo Bell as the centerpiece of his upscale Bel Air Estates residential community, intended to attract Hollywood\'s elite to the rolling canyons above Los Angeles. George C. Thomas Jr. designed the course in 1925-1926 with assistance from Jack Neville and Billy Bell handling construction and bunkering. It was the first of Thomas\'s legendary Los Angeles trilogy, followed by Riviera (1927) and the renovation of the North Course at Los Angeles Country Club.\n\nThe site presented extraordinary challenges. Thomas originally planned to route the course across relatively flat land to the south, but UCLA\'s acquisition of that property forced him into the steep canyons — a constraint that sparked genius. The resulting layout required remarkable engineering: multiple tunnels cut through canyon walls to connect separated sections, a swinging suspension bridge spanning a deep gorge, and an elevator transporting players between different elevations. No other classic course in the world features such infrastructure.\n\nOver the decades, the club attracted a membership roster of politicians, entertainers, and power brokers including Richard Nixon, Ronald Reagan, and Howard Hughes. Hughes famously landed his Sikorsky airplane on the 8th fairway in 1936 to impress actress Katharine Hepburn. Successive renovations by Dick Wilson (1962), Robert Trent Jones Sr. (1974), and Tom Fazio altered Thomas\'s original design.\n\nIn 2018, Tom Doak\'s Renaissance Golf Design completed a comprehensive restoration that returned the course to Thomas\'s original vision. Doak\'s team discovered original bunker dimensions by excavating buried sand layers from previous construction, removed ponds that had been added in later renovations, reduced the overall bunker count, and rebuilt green complexes to match Thomas\'s design philosophy. The restoration recovered three bunkerless holes and stripped away features that obscured the original landscape character.\n\nBel-Air hosted the 2023 U.S. Women\'s Amateur and is set to host the 2026 Curtis Cup Match (June 12-14), showcasing the restored layout on the international stage. The suspension bridge, now 100 years old, remains the most recognizable feature of one of America\'s most architecturally significant golf courses.', signatureHoles: [{ hole: 10, par: 3, yardage: 205, description: 'The most dramatic hole at Bel-Air and one of the most famous par 3s in American golf. Players ride an elevator up from the 9th green, cross the iconic swinging suspension bridge high above a canyon, and then face an uphill shot over the gorge to a punchbowl green. The engineering and scenery are unmatched anywhere in golf.' }, { hole: 12, par: 4, yardage: 395, description: 'Known as the "Mae West" hole for its distinctively shaped green complex, this world-class par 4 concludes an impressive stretch of bunkerless holes. Thomas demonstrated his ability to create strategic intrigue through landform alone — the green is benched into a canyon wall with natural contours that reject anything less than a precise approach.' }, { hole: 9, par: 4, yardage: 370, description: 'A short par 4 that demonstrates Thomas\'s strategic brilliance in a confined space. Players choose between aggressive and conservative routes around a restored barranca, with multiple options off the tee. The hole concludes with a walk through a tunnel and an elevator ride up to the 10th tee — a transition unlike anything else in golf.' }, { hole: 1, par: 5, yardage: 495, description: 'A sweeping opening par 5 that immediately introduces the dramatic canyon terrain and strategic bunkering that define the round. The hole descends into the landscape, setting the tone for the routing adventure ahead.' }, { hole: 8, par: 5, yardage: 515, description: 'A rolling par 5 with a serpentine fairway through the canyon bottom. This is the fairway where Howard Hughes famously landed his airplane in 1936 to impress Katharine Hepburn, adding Hollywood lore to an already memorable hole.' }], whatToExpect: 'Bel-Air is unlike any other golf course in the world. The routing winds through steep canyons above UCLA\'s campus, connected by tunnels, an elevator, and the famous century-old suspension bridge. The infrastructure alone makes this an unforgettable experience, but Thomas\'s architecture elevates it further — bold bunkering in a distinctive Southern California style, serpentine fairways through canyon bottoms, and green complexes that mix deep bunkers with natural landforms.\n\nAt 6,619 yards and par 71, the course does not overwhelm with length. The challenge comes from the terrain: elevation changes, blind and semi-blind shots, sidehill lies, and canyon crossings that demand confident ball-striking. The par 3s serve as creative connectors between separated terrain pockets, each with unique character. The compact routing means holes occasionally run close together, with staggered landing zones managing safety across parallel fairways.\n\nThe Tom Doak restoration stripped away decades of accumulated alterations and returned the course to Thomas\'s original strategic intent. Ponds were removed, bunker counts reduced, and several holes regained their bunkerless character, letting the natural terrain provide the defense. The result is a course that rewards creative shotmaking, ground-game approaches, and precise positioning over raw power.', playingTips: 'Leave the driver in the bag on most holes. Bel-Air rewards accuracy and positioning over distance, and the canyons punish wayward shots severely. A well-placed iron off the tee sets up better angles into Thomas\'s demanding green complexes.\n\nThe elevation changes affect club selection dramatically. Uphill shots to canyon-top greens play longer than yardage suggests, while downhill shots into canyon bottoms may need less club. Trust your caddie\'s advice on the first visit.\n\nOn the par 3s, especially the iconic 10th, commit fully to the shot. The canyons create wind channels that can shift direction between the tee and the green. The punchbowl green on 10 is more receptive than it appears — aim for the center and let the contours work.\n\nThe restored bunkerless holes (including the 12th "Mae West") require a different mindset. Without sand to frame the target, reading the landform and understanding the natural slopes is essential. Shots that miss on the low side of these greens are far easier to recover than those that go high.\n\nTake a moment on the suspension bridge to appreciate the view — downtown Los Angeles is visible on clear days, and the bridge itself is a century-old landmark worth savoring.', faqs: [{ question: 'Can the public play Bel-Air Country Club?', answer: 'No. Bel-Air is a private club and access requires an invitation from a member. The course is occasionally visible during USGA events such as the 2023 U.S. Women\'s Amateur and the upcoming 2026 Curtis Cup.' }, { question: 'What is the suspension bridge at Bel-Air?', answer: 'The swinging suspension bridge spans a deep canyon connecting the 9th green area to the back nine. Built in 1925, it is 100 years old and has become an icon of both the club and the Los Angeles landscape. Players cross it after riding an elevator up from the 9th green before teeing off on the par-3 10th hole.' }, { question: 'Who designed Bel-Air Country Club?', answer: 'George C. Thomas Jr. designed the course in 1925-1926 with assistance from Jack Neville and Billy Bell. Thomas also designed Riviera and renovated LA Country Club North. Tom Doak completed a comprehensive restoration in 2018 that returned the course to Thomas\'s original design intent.' }, { question: 'Did Howard Hughes really land a plane on the golf course?', answer: 'Yes. In 1936, the eccentric aviator and club member landed his Sikorsky airplane on the 8th fairway to impress actress Katharine Hepburn, adding to the club\'s Hollywood legend.' }, { question: 'What major events has Bel-Air hosted?', answer: 'Bel-Air hosted the 2023 U.S. Women\'s Amateur and is set to host the 2026 Curtis Cup Match (June 12-14), a biennial competition between the top women amateurs of the United States and Great Britain & Ireland.' }] },
    { id: 'la-9', name: 'Monarch Beach Golf Links', slug: 'monarch-beach', city: 'Los Angeles', state: 'California', type: 'resort', rating: 4.3, greensFee: '$175–$275', architect: 'Robert Trent Jones Jr.', yearBuilt: 1983, holes: 18, par: 70, yardage: 6601, description: 'Perched on the bluffs above Dana Point with sweeping Pacific Ocean views, Monarch Beach is a Robert Trent Jones Jr. links-style design at the Waldorf Astoria Monarch Beach resort. The coastal layout features ocean-view holes, sea breezes, and Catalina Island on the horizon.', highlights: ['Pacific Ocean blufftop setting', 'Waldorf Astoria Monarch Beach resort', 'Catalina Island views'], imageAlt: 'Monarch Beach Golf Links Pacific blufftop hole with ocean and Catalina views', history: 'Opened in 1983 on the bluffs above Dana Point, designed by Robert Trent Jones Jr. at the Waldorf Astoria Monarch Beach resort. Ocean views and Catalina Island on the horizon.', signatureHoles: [{ hole: 3, par: 4, yardage: 370, description: 'A scenic blufftop par 4 with Pacific views and Catalina in the distance.' }, { hole: 8, par: 3, yardage: 165, description: 'A coastal par 3 with ocean breezes affecting every shot.' }, { hole: 14, par: 4, yardage: 400, description: 'A dramatic par 4 along the blufftop.' }, { hole: 18, par: 4, yardage: 410, description: 'A strong finisher with ocean views.' }], whatToExpect: 'Dramatic blufftop golf with Pacific Ocean views and Catalina Island on the horizon. At 6,601 yards par 70, ocean breezes make it play longer.\n\nWaldorf Astoria resort setting adds luxury.', playingTips: 'Ocean breezes are constant. Factor wind into every shot on exposed holes.\n\nThe links-style design rewards ground game shots.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Resort course, $175-$275.' }, { question: 'Where?', answer: 'Dana Point bluffs at Waldorf Astoria Monarch Beach, Orange County.' }] },
  ],
  'new-york-new-york': [
    { id: 'ny-1', name: 'Bethpage State Park - Black Course', slug: 'bethpage-black', city: 'New York', state: 'New York', type: 'public', rating: 4.8, greensFee: '$65–$150', architect: 'A.W. Tillinghast', yearBuilt: 1936, holes: 18, par: 71, yardage: 7468, description: 'The most famous public course in America, Bethpage Black is a brute of a Tillinghast design that has hosted two U.S. Opens and a PGA Championship. The first tee famously warns: "The Black Course is an extremely difficult course which we recommend only for highly skilled golfers."', highlights: ['Multiple U.S. Open host', 'America\'s most famous public course', 'Legendary difficulty warning sign'], imageAlt: 'Bethpage Black Course challenging fairway on Long Island', history: 'Bethpage Black opened in 1936 as part of a New Deal-era public works project spearheaded by Robert Moses. A.W. Tillinghast designed the Black, Red, and Blue courses at the park. The Black was built during the Great Depression by WPA workers on Long Island\'s glacial moraine.\n\nFor decades it was a secret among New York public golfers. In 2002, it became the first public course to host the U.S. Open, won by Tiger Woods. The 2009 U.S. Open followed (Lucas Glover), and the 2019 PGA Championship was won by Brooks Koepka. The 2025 Ryder Cup brought international team competition to Bethpage.\n\nRees Jones renovated the course before the 2002 U.S. Open, adding length and restoring Tillinghast-era bunkering. It remains a New York State public facility offering championship golf at municipal prices.', signatureHoles: [{ hole: 4, par: 5, yardage: 517, description: 'Often called Tillinghast\'s greatest par 5. A sweeping double dogleg with gorgeous cross-bunkering forcing strategic decisions on every shot.' }, { hole: 5, par: 4, yardage: 478, description: 'Where the real grind begins. This demanding par 4 requires a long, accurate drive followed by a mid-iron to a well-bunkered green.' }, { hole: 12, par: 4, yardage: 501, description: 'A brute of a par 4 that doglegs left with a long iron approach to a sloping green. Finishes a fearsome three-hole stretch.' }, { hole: 15, par: 4, yardage: 478, description: 'A demanding uphill par 4 beginning the brutal finishing stretch. The elevated green is guarded by deep bunkers.' }], whatToExpect: 'Bethpage Black is a relentless test on rolling Long Island terrain. Thick rough, deep bunkers, and forced carries define the experience. Par 71 at nearly 7,500 yards. Walking only, no carts permitted. The terrain is hilly and physically demanding.\n\nPace of play can be slow on busy days. Tee times are highly sought after, with resident golfers sometimes camping overnight for morning spots.', playingTips: 'Accuracy matters more than length. The rough is genuinely penal and missing fairways leads to bogey or worse. Play to the wide parts of fairways and accept par as a good score on longer holes.\n\nGreens are large but heavily contoured. Approach shots must reach the correct quadrant or three-putts become common. Take advantage of the reachable par-5 4th for scoring.', faqs: [{ question: 'How do I get a tee time at Bethpage Black?', answer: 'NY State residents can book online two days in advance. Non-residents book one day ahead or try for same-day availability. Many golfers arrive before dawn to queue.' }, { question: 'What does it cost to play?', answer: 'Approximately $65-$75 for NY residents, $130-$150 for non-residents. Remarkable value for a championship venue.' }, { question: 'Is it really that hard?', answer: 'Yes. The famous sign warns the course is recommended only for highly skilled golfers. Slope rating exceeds 150 from the back tees.' }, { question: 'Are carts available?', answer: 'No. Bethpage Black is walking only. No riding carts are permitted.' }] },
    { id: 'ny-2', name: 'Shinnecock Hills Golf Club', slug: 'shinnecock-hills', city: 'New York', state: 'New York', type: 'private', rating: 5.0, greensFee: 'Members Only', architect: 'William Flynn', yearBuilt: 1931, holes: 18, par: 70, yardage: 7445, description: 'One of the five founding member clubs of the USGA, Shinnecock Hills is among the most revered courses on the planet. The windswept links-inspired layout on the eastern end of Long Island has hosted five U.S. Opens and embodies the essence of American championship golf.', highlights: ['Five-time U.S. Open host', 'Founding USGA member club', 'Links-inspired Long Island masterpiece'], imageAlt: 'Shinnecock Hills windswept fairway overlooking Peconic Bay', history: 'Founded in 1891, Shinnecock Hills is one of America\'s oldest clubs. Willie Davis laid out the original 12-hole course with help from the Shinnecock Indian Nation. In 1895 it became one of five founding USGA member clubs and hosted the second U.S. Open.\n\nWilliam Flynn designed the current course in 1931 on a windswept site overlooking Peconic Bay with rolling hills, native fescue, and constant ocean winds. The Stanford White clubhouse (1892) is the iconic centerpiece.\n\nShinnecock has hosted five U.S. Opens (1896, 1986, 1995, 2004, 2018) and is set for 2026.', signatureHoles: [{ hole: 7, par: 3, yardage: 189, description: 'The Redan hole with a green sloping front-right to back-left, guarded by three deep bunkers. One of the finest Redan-style holes in America.' }, { hole: 9, par: 4, yardage: 443, description: 'Ben Nevis, an exceptional uphill par 4 playing toward the Stanford White clubhouse with a demanding approach.' }, { hole: 14, par: 4, yardage: 519, description: 'One of the longest par 4s in championship golf, demanding two powerful and accurate shots.' }], whatToExpect: 'Links-inspired course on eastern Long Island with views of Peconic Bay. Treeless windswept terrain in native fescue. Par 70 at 7,445 yards. Walking with caddies is standard.', playingTips: 'Wind awareness is critical as holes face prevailing wind from different angles. Take extra club into wind. Keep the ball below the hole on fast greens.', faqs: [{ question: 'Can the public play Shinnecock?', answer: 'No. Private club, member invitation only.' }, { question: 'How many U.S. Opens?', answer: 'Five: 1896, 1986, 1995, 2004, 2018. Scheduled for 2026.' }, { question: 'What is the Stanford White clubhouse?', answer: 'Designed in 1892, one of the most beautiful clubhouses in American golf.' }] },
    { id: 'ny-3', name: 'Winged Foot Golf Club - West', slug: 'winged-foot-west', city: 'New York', state: 'New York', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'A.W. Tillinghast', yearBuilt: 1923, holes: 18, par: 72, yardage: 7477, description: 'Host of six U.S. Opens including the 2020 championship, Winged Foot West is one of Tillinghast\'s greatest achievements. The demanding par-72 in Mamaroneck features some of the most complex green surfaces in the game.', highlights: ['Six-time U.S. Open host', 'Tillinghast\'s finest work', 'Legendary green complexes'], imageAlt: 'Winged Foot West Course clubhouse and 18th green', history: 'Winged Foot Golf Club was founded in 1921 by members of the New York Athletic Club. A.W. Tillinghast designed both the East and West courses on 280 acres in Mamaroneck, opening in 1923. Tillinghast famously said he gave the members a man-sized course.\n\nThe West Course has hosted six U.S. Opens (1929, 1959, 1974, 1984, 2006, 2020), a PGA Championship (1997), and multiple U.S. Amateurs. The 1974 Open is remembered as the Massacre at Winged Foot when Hale Irwin won at 7-over par. Bryson DeChambeau won the 2020 championship as the only player under par.\n\nGil Hanse led a restoration in 2017 removing over 7,000 trees and rebuilding bunkers to honor Tillinghast\'s original vision. The West Course is consistently ranked among the top 10 in America.', signatureHoles: [{ hole: 10, par: 3, yardage: 183, description: 'A signature Tillinghast par 3 with a heavily contoured green surrounded by deep bunkers demanding a precise tee shot.' }, { hole: 12, par: 5, yardage: 561, description: 'A strategic par 5 offering risk-reward decisions with deep bunkers guarding the approach and severe green contours.' }, { hole: 18, par: 4, yardage: 448, description: 'One of the great finishing holes in championship golf. This demanding uphill par 4 plays to a severely contoured green fronted by deep bunkers.' }], whatToExpect: 'Classic Tillinghast parkland with tree-lined fairways, deep bunkers, and complex green surfaces. 7,477 yards, par 72. The final five holes are all par 4s over 400 yards. Walking with a caddie is standard.', playingTips: 'The greens are the defense. Study approach angles and play to the correct section of the green. Missing on the wrong side leads to impossible recoveries from deep bunkers.\n\nThe par-4 6th at 321 yards is one of the few breathers. On the closing stretch, fairway accuracy matters more than distance.', faqs: [{ question: 'Can the public play Winged Foot?', answer: 'No. Private club requiring member invitation.' }, { question: 'How many U.S. Opens has Winged Foot hosted?', answer: 'Six on the West Course: 1929, 1959, 1974, 1984, 2006, 2020.' }, { question: 'What is the Massacre at Winged Foot?', answer: 'The 1974 U.S. Open when Hale Irwin won at 7-over par 287.' }, { question: 'Does Winged Foot have two courses?', answer: 'Yes. East and West both opened in 1923 by Tillinghast.' }] },
    { id: 'ny-4', name: 'Ballyowen Golf Club', slug: 'ballyowen', city: 'New York', state: 'New York', type: 'public', rating: 4.3, greensFee: '$70–$140', architect: 'Roger Rulewich', yearBuilt: 1998, holes: 18, par: 72, yardage: 7094, description: 'Set in the rolling hills of northern New Jersey (an easy drive from NYC), Ballyowen brings Scottish links-style golf to the Tri-State area. The treeless, windswept layout at Crystal Springs Resort is a unique experience for metro New York golfers.', highlights: ['Scottish links style near NYC', 'Crystal Springs Resort setting', 'Treeless windswept design'], imageAlt: 'Ballyowen Golf Club links-style course near New York City', history: 'Ballyowen Golf Club opened in 1998 as the crown jewel of Crystal Springs Resort in the Kittatinny Mountains of northern New Jersey, roughly 50 miles from midtown Manhattan. Designed by Roger Rulewich, the longtime lead design associate for Robert Trent Jones Sr., the course occupies a 250-acre treeless plateau with natural links-like conditions.\n\nRulewich designed Ballyowen to evoke the links courses of Ireland and Scotland. The exposed, windswept terrain is rarely found in the northeastern United States, and the course earned immediate critical acclaim as one of the best new public courses in America.\n\nBallyowen is part of Crystal Springs Resort\'s six-course collection, but stands apart as the most celebrated, offering a style of golf unavailable anywhere else in the New York metro area.', signatureHoles: [{ hole: 5, par: 4, yardage: 418, description: 'A sweeping dogleg par 4 across the windswept plateau with panoramic mountain views and a green well-defended by deep bunkers.' }, { hole: 11, par: 3, yardage: 197, description: 'A long, exposed par 3 into the prevailing wind. The raised green is framed by fescue mounds and bunkers, demanding a well-struck iron.' }, { hole: 14, par: 5, yardage: 546, description: 'A strategic par 5 offering risk-reward options. Deep bunkers and a false front punish anything less than perfect execution on the approach.' }, { hole: 18, par: 4, yardage: 432, description: 'A demanding finishing hole playing back toward the clubhouse, often into the wind, requiring precise club selection.' }], whatToExpect: 'Ballyowen delivers a genuine links experience without crossing the Atlantic. The treeless plateau sits high in the Kittatinny Mountains, creating an exposed, windswept environment. Fescue grasses, deep pot bunkers, and firm running fairways encourage a ground-game approach.\n\nAt 7,094 yards from the tips, the course is a serious test when the wind blows. Mountain views are spectacular, particularly in autumn.', playingTips: 'Wind is the primary defense. The exposed hilltop location means conditions can shift dramatically during a round. Keep the ball low and embrace bump-and-run shots around the greens.\n\nFirm fairways provide generous roll, so consider less club off the tee on shorter holes. Avoid the deep pot bunkers at all costs, as many require a lateral escape.', faqs: [{ question: 'Can the public play Ballyowen?', answer: 'Yes. Green fees range from $70 to $140, with stay-and-play packages available through Crystal Springs Resort.' }, { question: 'Is Ballyowen really a links course?', answer: 'While not on the coast, Ballyowen authentically replicates links conditions with its treeless, windswept hilltop setting, fescue grasses, firm fairways, and pot bunkers.' }, { question: 'How many courses are at Crystal Springs Resort?', answer: 'Crystal Springs Resort features six golf courses. Ballyowen is the most acclaimed.' }, { question: 'Who designed Ballyowen?', answer: 'Roger Rulewich, the longtime lead design associate for Robert Trent Jones Sr. It is considered one of Rulewich\'s finest independent works.' }] },
    { id: 'ny-5', name: 'Trump Golf Links at Ferry Point', slug: 'ferry-point', city: 'New York', state: 'New York', type: 'public', rating: 4.4, greensFee: '$100–$200', architect: 'Jack Nicklaus', yearBuilt: 2015, holes: 18, par: 72, yardage: 7400, description: 'A Jack Nicklaus links-style design in the Bronx with sweeping views of the Manhattan skyline, Whitestone Bridge, and Long Island Sound, Ferry Point is one of the most dramatic settings for a public golf course in the world.', highlights: ['Manhattan skyline views', 'Links-style course in the Bronx', 'Jack Nicklaus design'], imageAlt: 'Ferry Point golf course with Manhattan skyline and Whitestone Bridge', history: 'Ferry Point opened in 2015 as New York City\\\'s first championship-caliber municipal golf course, designed by Jack Nicklaus on a 222-acre former landfill in the Bronx. The project took approximately 31 years from concept to completion at a cost of roughly $97 million in city funds. Construction incorporated recycled schist rock from the 2nd Avenue Subway and East Side Access tunnel projects.\n\nThe course was originally operated under the Trump Organization before Bally\\\'s Corporation assumed operations in 2023. Despite the naming controversy, the Nicklaus links-style design has been widely praised — ranked No. 3 Best Public Course in New York by Golfweek (2025).\n\nThe closing stretch (holes 13-18) runs along the waterfront with sweeping views of the Manhattan skyline, Whitestone Bridge, Throgs Neck Bridge, and East River — arguably the most dramatic setting for public golf in the world.', signatureHoles: [{ hole: 7, par: 4, yardage: 279, description: 'A tempting driveable short par 4 requiring a carry over water to a narrow, well-defended green. Pure risk-reward — the birdie chance is real but so is the double bogey.' }, { hole: 13, par: 4, yardage: 420, description: 'The signature skyline hole with the full Manhattan panorama as backdrop. Part of the celebrated closing stretch (13-18) that runs along the waterfront.' }, { hole: 18, par: 5, yardage: 555, description: 'A dramatic par 5 finisher played beneath the Whitestone Bridge. The bridge towers above as you approach the green — an unforgettable closing image for a round of golf.' }], whatToExpect: 'Ferry Point is a true links-style layout built atop a capped landfill with firm-and-fast fairways, deep Nicklaus-style pot bunkers, and dense penal fescue rough lining wide fairways. Wind off the East River is a constant factor, particularly on the exposed closing stretch.\n\nConditioning is exceptional — frequently rated 9/10 by reviewers. The course is very difficult: narrow corridors defined by thick fescue, deep bunkers, and firm greens combine with persistent wind to create a stern championship test at 7,400 yards.\n\nThe Manhattan skyline, Whitestone Bridge, and East River views — especially on holes 13-18 — are unmatched in public golf anywhere.', playingTips: 'Wind off the East River affects every shot on the closing holes. Check wind direction before each swing and adjust club selection accordingly.\n\nMissing fairways into the fescue is severely punishing. Accuracy off the tee matters far more than distance on this links-style layout.\n\nThe deep Nicklaus-style bunkers demand confident sand play. Avoid them when possible — getting out can cost multiple strokes.\n\nOn the driveable 7th (279 yards), assess wind carefully before deciding to go for the green. A smart layup leaves a simple pitch.\n\nThe closing stretch (13-18) is the most scenic but also the most exposed. Stay patient and play within yourself.', faqs: [{ question: 'Is Ferry Point a public course?', answer: 'Yes. It is a New York City municipal course open to the public. It was NYC\\\'s first championship-caliber public course when it opened in 2015.' }, { question: 'Who designed it?', answer: 'Jack Nicklaus. The links-style layout was built on a 222-acre former landfill in the Bronx at a cost of roughly $97 million.' }, { question: 'What happened to the Trump name?', answer: 'Bally\\\'s Corporation assumed operations from the Trump Organization in 2023. The course itself remains a Nicklaus design regardless of the operator.' }, { question: 'What are the views like?', answer: 'The closing stretch (holes 13-18) offers sweeping views of the Manhattan skyline, Whitestone Bridge, Throgs Neck Bridge, and East River — arguably the most dramatic setting for public golf in the world.' }]},
    { id: 'ny-6', name: 'National Golf Links of America', slug: 'national-golf-links', city: 'New York', state: 'New York', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'Charles Blair Macdonald', yearBuilt: 1911, holes: 18, par: 72, yardage: 6779, description: 'Founded by C.B. Macdonald, the father of American golf architecture, National Golf Links is a template course that inspired generations of designers. The links-style layout on the Peconic Bay in Southampton features Macdonald\'s famous renditions of classic British holes including the Redan, Alps, and Cape.', highlights: ['C.B. Macdonald\'s template masterpiece', 'Peconic Bay links setting', 'Inspired generations of American golf architecture'], imageAlt: 'National Golf Links of America links landscape overlooking Peconic Bay', history: 'National Golf Links of America was the creation of Charles Blair Macdonald, widely regarded as the father of American golf architecture. Macdonald, who learned the game at the University of St. Andrews in Scotland, set out to build his vision of an ideal American golf course. He spent years studying the great holes of the British Isles before breaking ground in Southampton, New York, with the course opening in 1911.\n\nMacdonald enlisted the help of Seth Raynor, a local surveyor who would go on to become one of America\'s greatest golf architects himself. Together they created a links-style layout on the shores of Peconic Bay that featured Macdonald\'s famous template holes -- renditions of the best holes he had studied abroad, including the Redan from North Berwick, the Alps from Prestwick, the Eden and Road Hole from St. Andrews, the Sahara from Royal St George\'s, and the Cape.\n\nMacdonald continued to refine National Golf Links well into his 70s before passing away in Southampton in 1939. The course has been consistently ranked among the top 10-15 courses in America for over a century and remains the seminal template course in American golf architecture.', signatureHoles: [{ hole: 2, par: 4, yardage: 340, description: 'The Sahara hole, named after the famous hole at Royal St George\'s. A dramatic carry over a vast waste area from the tee sets up a short but strategic approach.' }, { hole: 4, par: 3, yardage: 195, description: 'The Redan, modeled after the famous 15th at North Berwick in Scotland. Widely considered the finest Redan in American golf, the green slopes away from front-right to back-left, demanding a precise tee shot.' }, { hole: 6, par: 3, yardage: 135, description: 'Called Short, this diminutive par 3 is a Ben Crenshaw favorite. Despite its modest yardage, the eccentric green is a thoroughly original creation and one of the most discussed short holes in architecture.' }, { hole: 18, par: 5, yardage: 502, description: 'The Home hole, the only hole that plays directly alongside Peconic Bay. A reachable par 5 that provides a memorable closing experience with expansive bay views.' }], whatToExpect: 'National Golf Links is a strategic, links-style experience on one of the most beautiful properties in American golf. The course plays along rolling terrain with views of Peconic Bay and Shinnecock Hills across the road. At approximately 6,779 yards, the course plays far more demanding than its modest length suggests due to wind, green complexity, and strategic demands.\n\nThe template holes provide a living museum of golf architecture. Each hole tells a story rooted in the great courses of the British Isles, adapted brilliantly to the Long Island landscape.', playingTips: 'National Golf Links rewards strategic thinking over raw power. Many holes present multiple paths from tee to green, and understanding the template origins of each hole provides insight into the best approach.\n\nThe greens are the heart of the design, featuring bold contours that demand the ball arrive from a specific angle. Position off the tee is far more important than distance. Wind off Peconic Bay is a constant factor.', faqs: [{ question: 'Can the public play National Golf Links of America?', answer: 'No. National Golf Links is an ultra-exclusive private club with very limited membership. There is no public access.' }, { question: 'What are template holes?', answer: 'Template holes are golf holes modeled after famous holes from the great courses of the British Isles. C.B. Macdonald pioneered this concept, bringing designs like the Redan, Alps, Cape, and Eden to America at National Golf Links.' }, { question: 'What is the par at National Golf Links?', answer: 'The course plays as a par 72 at approximately 6,779 yards. Despite its relatively modest length, the strategic demands and wind make it a rigorous test.' }, { question: 'Who was Seth Raynor?', answer: 'Seth Raynor was a local surveyor hired by C.B. Macdonald to help build National Golf Links. Through this apprenticeship, Raynor learned Macdonald\'s template philosophy and went on to become one of America\'s greatest golf architects.' }] },
    { id: 'ny-7', name: 'Garden City Golf Club', slug: 'garden-city-golf-club', city: 'New York', state: 'New York', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Devereux Emmet / Walter Travis', yearBuilt: 1899, holes: 18, par: 73, yardage: 6840, description: 'One of the finest Golden Age courses on Long Island, Garden City Golf Club features flat, windswept terrain reminiscent of British links golf. The Emmet/Travis design rewards ground-game creativity and has hosted numerous USGA amateur championships.', highlights: ['Golden Age links-style design', 'Hosted multiple USGA championships', 'Flat windswept terrain rewards ground game'], imageAlt: 'Garden City Golf Club windswept links-style fairway on Long Island', history: 'Garden City Golf Club was founded in 1899 on the Hempstead Plains of Long Island, one of the few naturally flat, treeless grassland areas in the northeastern United States. Devereux Emmet laid out the original course on terrain that closely resembled the linksland of the British Isles. In 1902, Walter J. Travis, one of America\'s greatest amateur golfers and a three-time U.S. Amateur champion, undertook a major redesign that gave the course its enduring character.\n\nTravis\'s redesign was revolutionary for its era. He introduced bold, deep bunkers, dramatic green contours, and strategic principles that were ahead of their time. His work at Garden City, particularly the famous 12th hole with its inverted stack bunkers and wild green contours, remains some of the most daring architecture from the early 1900s. The club has hosted the Walter J. Travis Invitational for over 110 years in his honor.\n\nTom Doak completed a restoration in 2015 that recovered Travis\'s original design intent, removing decades of incremental changes. The course has hosted numerous USGA amateur championships and is consistently ranked among the top 50 courses in America.', signatureHoles: [{ hole: 3, par: 4, yardage: 395, description: 'A demanding par 4 that exemplifies the strategic nature of the course. The flat terrain requires precise positioning off the tee to set up the best angle into a well-defended green complex.' }, { hole: 12, par: 4, yardage: 413, description: 'The most famous hole at Garden City, featuring Walter Travis\'s signature inverted stack bunkers and dramatic in-green mounding. The green complex is one of the most unique and daring in American golf, restored by Tom Doak in 2012.' }, { hole: 14, par: 3, yardage: 180, description: 'A strong par 3 that plays into the prevailing wind. The green is defended by Travis\'s deep bunkers and requires a well-struck long iron or hybrid to find the putting surface.' }, { hole: 18, par: 5, yardage: 535, description: 'A fitting par-5 closer that offers risk-reward options for players willing to challenge the bunkers guarding the approach. The flat terrain makes wind a significant factor on this finishing hole.' }], whatToExpect: 'Garden City Golf Club is a minimalist, windswept experience on the flat Hempstead Plains of Long Island. The course plays to 6,840 yards at par 73 with virtually no trees and minimal elevation change, placing the emphasis squarely on strategic architecture, firm turf, and wind. The experience has been compared to playing inland links golf in the British Isles.\n\nWalter Travis\'s bunkers are the primary defense, featuring deep faces and strategic placement that demand careful thought on every shot. The greens are boldly contoured, particularly the famous 12th, and reward approach shots from the correct angle. Tom Doak\'s 2015 restoration brought the course closer to its original character than at any point in decades.', playingTips: 'Garden City rewards the ground game more than almost any course in America. The firm, fast turf and flat terrain encourage running the ball onto greens rather than flying it directly to the pin. Bump-and-run shots and low trajectory approaches are valuable weapons here.\n\nWind is the invisible defense at Garden City. The exposed, treeless terrain means every hole is affected by whatever breeze is blowing. Pay close attention to flag behavior and cloud movement to gauge wind strength and direction throughout your round.', faqs: [{ question: 'Can the public play Garden City Golf Club?', answer: 'No. Garden City Golf Club is a private club with no public access. The club hosts the annual Walter J. Travis Invitational for invited amateurs.' }, { question: 'Who was Walter Travis?', answer: 'Walter J. Travis was a three-time U.S. Amateur champion and pioneering golf architect. He redesigned Garden City in 1902, introducing bold bunkering and green contours that were revolutionary for the era. The club\'s annual invitational is named in his honor.' }, { question: 'What USGA events has Garden City hosted?', answer: 'Garden City has hosted numerous USGA amateur championships over its long history, taking advantage of its championship-caliber layout and proximity to New York City.' }, { question: 'What makes the 12th hole famous?', answer: 'The 12th hole features Walter Travis\'s inverted stack bunkers and wild in-green mounding, creating one of the most unique and daring green complexes in American golf. Tom Doak restored the green to its original design in 2012.' }] },
    { id: 'ny-8', name: 'Bethpage Red Course', slug: 'bethpage-red', city: 'New York', state: 'New York', type: 'public', rating: 4.3, greensFee: '$45–$85', architect: 'A.W. Tillinghast', yearBuilt: 1935, holes: 18, par: 68, yardage: 6776, description: 'Often overshadowed by its famous Black sibling, Bethpage Red is a fine A.W. Tillinghast design in its own right. The par-68 layout offers a challenging test with excellent conditioning at state-park pricing, making it one of the best value rounds in the New York metropolitan area.', highlights: ['A.W. Tillinghast design', 'Excellent value at state-park pricing', 'Challenging par-68 layout'], imageAlt: 'Bethpage Red Course Tillinghast design at Bethpage State Park', history: 'Bethpage Red Course was designed by A.W. Tillinghast and opened in 1935 as a WPA (Works Progress Administration) project during the Great Depression — one of Roosevelt\\\'s New Deal public works. Along with the Blue Course, Red was the first to open at Bethpage State Park, preceding even the famous Black Course by a year.\n\nThe Red hosted the U.S. Amateur Public Links Championship in 1936 — its very first year of operation. Tillinghast designed it with his trademark strategic variety: subtle angles, protective cross-bunkers, and elevated green sites that reward thoughtful play over raw power.\n\nBethpage State Park now hosts approximately 300,000 rounds annually across five courses. While the Black Course draws headlines (2002 and 2009 U.S. Opens, 2019 PGA Championship, 2025 Ryder Cup), the Red is widely considered the consensus second-best course at the park. Golfweek ranked it No. 6 Best Public Course in New York (2025).', signatureHoles: [{ hole: 1, par: 4, yardage: 459, description: 'The longest par 4 on the course and likely the hardest hole. An elevated tee leads to a generous fairway, but the uphill approach to a green sloping back to front is a brutal opening test.' }, { hole: 4, par: 3, yardage: 158, description: 'The "Red Redan" — plays over a valley to a perched green sloping back to front, defended by a deep bunker short. Deceptively demanding despite modest yardage.' }, { hole: 13, par: 4, yardage: 385, description: 'Widely regarded as the best-designed hole on the course. Eight bunkers split the fairway down the center, creating a genuine risk-reward decision off the tee comparable to the Black Course\\\'s famous bunker features.' }], whatToExpect: 'The Red embodies Tillinghast\\\'s philosophy of strategic variety over pure punishment. While the Black is brutally penal, the Red prioritizes interesting green complexes and more recovery options. The front nine features hillier, rolling terrain; the back nine is flatter with a linksier feel.\n\nAt par 68 with multiple long par 4s and only two par 5s, the Red is a stern test. Conditioning is strong (rated 8/10) with quick, true greens and lush fairways. The course rewards thoughtful shot-making and course management.\n\nAt $45-85 depending on residency, this is one of the best values in New York metropolitan golf — a genuine Tillinghast championship design at state-park pricing.', playingTips: 'Don\\\'t be rattled by the brutal 459-yard opening hole. The course eases through holes 2-7 to let you build a score.\n\nOn the par-3 4th ("Red Redan"), favor the left side. The back-to-front slope rejects anything short and right into the deep bunker.\n\nOn the 13th, decide your strategy before teeing off: play safe to one side of the central bunker complex, or carry it for a shorter approach.\n\nThe front nine\\\'s hillier terrain means uneven lies — adjust stance and club selection. The back nine plays flatter and more exposed to wind.\n\nGreens have subtle Tillinghast undulations. Read them carefully, especially the back-to-front slopes.', faqs: [{ question: 'How does Bethpage Red compare to the Black?', answer: 'The Red is widely considered the second-best course at Bethpage. It emphasizes strategic variety over the Black\\\'s pure punishment, with more interesting green complexes and more recovery options.' }, { question: 'Why is it par 68?', answer: 'The layout features multiple long par 4s and only two par 5s, creating a stern test where pars are hard-earned despite the lower par number.' }, { question: 'Who designed it?', answer: 'A.W. Tillinghast, one of golf\\\'s greatest architects. The Red opened in 1935 as a Depression-era WPA project — one year before the famous Black Course.' }, { question: 'What does it cost to play?', answer: 'Approximately $45-85 depending on NY state residency. One of the best values in metropolitan New York for a genuine championship-caliber Tillinghast design.' }]},
    { id: 'ny-9', name: 'Maidstone Club', slug: 'maidstone-club', city: 'New York', state: 'New York', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Willie Park Jr. / Jack Nicklaus (restored)', yearBuilt: 1891, holes: 18, par: 72, yardage: 6621, description: 'One of the oldest clubs in America, Maidstone occupies a spectacular oceanfront setting in East Hampton with Atlantic dunes, ocean views, and Hook Pond. The Willie Park Jr. design has been sensitively updated while maintaining its raw, natural character that makes it feel closer to Scotland than the Hamptons.', highlights: ['Spectacular East Hampton oceanfront', 'Among the oldest clubs in America', 'Scottish-style dunes and ocean setting'], imageAlt: 'Maidstone Club oceanfront dunes hole in East Hampton with Atlantic views', history: 'The Maidstone Club was founded in 1891 in East Hampton, New York, making it one of the oldest clubs in the United States. The club initially operated a modest 7-hole course before expanding. In 1922, Willie Park Jr., the two-time Open Championship winner turned celebrated golf architect, designed the 18-hole West Course on the Gardiner Peninsula along with his brother Jack. Park\'s design took advantage of the spectacular oceanfront dunes, Hook Pond, and Atlantic Ocean views.\n\nThe course occupies a remarkable stretch of land between the Atlantic Ocean and Hook Pond, creating a setting that feels more like the Scottish coastline than the fashionable Hamptons. Seth Raynor also contributed redesign plans in 1921, and elements of his work influenced the layout. Over the decades, the course has been sensitively maintained to preserve its raw, natural character.\n\nBill Coore and Ben Crenshaw completed a restoration in 2012 that further refined the course while honoring Willie Park Jr.\'s original vision. Maidstone is consistently ranked among the top 50 courses in America and is widely considered one of the finest oceanfront golf experiences in the world.', signatureHoles: [{ hole: 7, par: 4, yardage: 432, description: 'A superb Cape-style par 4 that bends around Hook Pond. Players must decide how much of the pond to carry off the tee, with a more aggressive line significantly shortening the approach to the green.' }, { hole: 8, par: 3, yardage: 151, description: 'A beloved short par 3 with a blind tee shot over dunes to a green nestled in the dunescape. Despite its modest yardage, the wind and hidden green make club selection a genuine challenge.' }, { hole: 9, par: 4, yardage: 402, description: 'Often cited as one of the finest two-shot holes in American golf, the 9th plays along the Atlantic coast with ocean views and dunes framing the hole. The approach to the seaside green is unforgettable.' }, { hole: 14, par: 5, yardage: 527, description: 'A strategic par 5 that offers multiple routes to the green. The hole winds through the property\'s natural terrain with bunkers and contours rewarding careful course management.' }], whatToExpect: 'Maidstone offers one of the most spectacular golf settings in America. The front nine plays through rolling oceanfront dunes with Atlantic Ocean views and the constant sound of crashing waves, while the back nine moves through more sheltered terrain near Hook Pond. The course measures 6,621 yards from the back tees as a par 72.\n\nThe natural, raw character of the course is its greatest asset. The turf plays firm and fast, the bunkers are rugged and natural, and the wind is a constant companion. The stretch from holes 7 through 10 along the ocean is widely regarded as one of the finest four-hole sequences on Long Island.', playingTips: 'Wind management is essential at Maidstone. The oceanfront holes on the front nine are fully exposed to Atlantic breezes, and club selection can vary by two or three clubs depending on conditions. The blind shots, particularly on the par-3 8th, require trust in your yardage and commitment to your target.\n\nThe ground game is rewarded here as on Scottish links courses. Running approach shots onto the firm greens is often a smarter play than flying the ball to the pin, especially in wind.', faqs: [{ question: 'Can the public play Maidstone Club?', answer: 'No. Maidstone is an exclusive private club in East Hampton with no public access. Guest play requires a member invitation.' }, { question: 'Who designed Maidstone?', answer: 'Willie Park Jr., the two-time Open Championship winner and renowned golf architect, designed the 18-hole West Course in 1922. Bill Coore and Ben Crenshaw completed a restoration in 2012.' }, { question: 'What makes the setting special?', answer: 'Maidstone occupies a stunning stretch of land between the Atlantic Ocean and Hook Pond on the Gardiner Peninsula in East Hampton. The oceanfront dunes and constant sea breezes create a setting more reminiscent of Scotland than the Hamptons.' }, { question: 'How does Maidstone rank among American courses?', answer: 'Maidstone is consistently ranked among the top 50 courses in America and is widely considered one of the finest oceanfront golf experiences in the world.' }] },
  ],
  'chicago-illinois': [
    { id: 'chi-1', name: 'Chicago Golf Club', slug: 'chicago-golf-club', city: 'Chicago', state: 'Illinois', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'Charles Blair Macdonald / Seth Raynor', yearBuilt: 1895, holes: 18, par: 70, yardage: 6597, description: 'The first 18-hole course in the United States and a founding member of the USGA, Chicago Golf Club is an American treasure. C.B. Macdonald\'s template holes, refined by Seth Raynor, offer a master class in strategic golf architecture.', highlights: ['First 18-hole course in America', 'Founding USGA member', 'Historic Macdonald/Raynor design'], imageAlt: 'Chicago Golf Club historic first 18-hole course in America', history: 'Chicago Golf Club was founded in 1892 by Charles Blair Macdonald and other prominent Chicagoans who wanted to play the game they had experienced during visits to Scotland. The club initially operated on a 9-hole course in Belmont before moving to Wheaton, Illinois, where Macdonald laid out the first 18-hole golf course in North America in 1895. Chicago Golf Club was one of the five founding member clubs of the USGA in 1894.\n\nMacdonald, who won the inaugural U.S. Amateur in 1895, designed the original layout incorporating template holes inspired by the great courses of the British Isles. Seth Raynor later supervised construction and refined the template concepts including the Redan, Biarritz, Eden, and Road holes. The club hosted the U.S. Open in 1897, 1900, and 1911, the U.S. Amateur in 1897 and 1905, and the Walker Cup in 1928 and 2005.\n\nThe course remains remarkably true to its original character. It hosted the 2018 U.S. Senior Women\'s Open, demonstrating its continued relevance. Chicago Golf Club is consistently ranked among the top 20 courses in America.', signatureHoles: [{ hole: 2, par: 4, yardage: 481, description: 'The Road hole, modeled after the famous 17th at St. Andrews. At 481 yards it is often the most difficult hole on the course, requiring two precise shots to navigate strategic hazards guarding the green.' }, { hole: 7, par: 3, yardage: 195, description: 'The Redan hole, inspired by the 15th at North Berwick. The green angles from front-right to back-left with a deep bunker guarding the front left, rewarding a fade that uses the contours.' }, { hole: 14, par: 4, yardage: 380, description: 'A strategic par 4 exemplifying Macdonald\'s design philosophy. The short yardage belies a demanding approach to a well-defended green requiring careful club selection.' }, { hole: 17, par: 3, yardage: 210, description: 'The Biarritz hole with Macdonald\'s signature long narrow green featuring a dramatic swale through its center. Players must land on the correct tier for any birdie chance.' }], whatToExpect: 'Chicago Golf Club is a flat, windswept course through open prairie terrain west of Chicago. At just 6,597 yards with a par of 70, the course relies on strategic architecture rather than length. The template holes represent a master class in design principles that have influenced architects for over a century.\n\nThe course has a distinctly minimalist, links-like character with firm turf, subtle ground contours, and a premium on the ground game. Wind is a constant factor on the exposed terrain, and small, well-defended greens demand precise iron play.', playingTips: 'Study the template holes before playing — understanding the strategic concepts will help you make better decisions. The Redan requires a specific shot shape to use the green contours. The Biarritz demands landing on the correct tier. The Road hole punishes anything long or right.\n\nBecause the course is relatively short, resist the temptation to overpower it. Positioning and angle of approach matter far more than distance. Pay close attention to wind direction, as it can shift club selection significantly on exposed holes.', faqs: [{ question: 'Is Chicago Golf Club really the first 18-hole course in America?', answer: 'Yes. While earlier 9-hole courses existed, Chicago Golf Club became the first 18-hole course in North America when C.B. Macdonald designed the layout at Wheaton in 1895.' }, { question: 'What are template holes?', answer: 'Template holes are designs inspired by famous holes on great Scottish and English courses. C.B. Macdonald pioneered the concept in America with templates like the Redan, Biarritz, Eden, and Road holes.' }, { question: 'Can the public play Chicago Golf Club?', answer: 'No. Chicago Golf Club is a very private club with no public access. It occasionally hosts USGA and international amateur events.' }, { question: 'What championships has Chicago Golf Club hosted?', answer: 'Three U.S. Opens (1897, 1900, 1911), two U.S. Amateurs, two Walker Cups (1928, 2005), and the 2018 U.S. Senior Women\'s Open.' }] },
    { id: 'chi-2', name: 'Cog Hill Golf & Country Club - Dubsdread', slug: 'cog-hill-dubsdread', city: 'Chicago', state: 'Illinois', type: 'public', rating: 4.5, greensFee: '$65–$125', architect: 'Dick Wilson / Rees Jones', yearBuilt: 1964, holes: 18, par: 72, yardage: 7547, description: 'Long the Chicago-area\'s premier public championship course, Cog Hill No. 4 "Dubsdread" hosted the BMW Championship and Western Open for decades. The Rees Jones renovation maintained the course\'s fearsome reputation while modernizing it for championship play.', highlights: ['Former BMW Championship host', '"Dubsdread" championship legacy', 'Premier Chicago public course'], imageAlt: 'Cog Hill Dubsdread championship course south of Chicago', history: 'Cog Hill was founded in Lemont, Illinois in 1927. Course No. 4 Dubsdread, designed by Dick Wilson and Joe Lee, opened in 1964. The name means dreaded by dubs reflecting its championship difficulty.\n\nDubsdread hosted the Western Open from 1962 to 2006, the BMW Championship, and the 1997 U.S. Amateur. Tiger Woods won the 2009 BMW Championship here. Rees Jones completed a $5 million renovation in 2008. Another Jones renovation finished in 2025.', signatureHoles: [{ hole: 2, par: 3, yardage: 224, description: 'Demanding long par 3 surrounded by deep bunkers requiring a precise long iron.' }, { hole: 5, par: 5, yardage: 507, description: 'Reachable par 5 with risk-reward. Heavy bunkering and water threaten the greedy.' }, { hole: 15, par: 5, yardage: 592, description: 'One of the longest holes requiring three precise shots through tight landing areas.' }, { hole: 18, par: 5, yardage: 559, description: 'Memorable finishing par 5 where championships have been decided.' }], whatToExpect: 'Classic Midwest parkland design at 7,547 yards with tight landing areas and heavily bunkered greens. Bent grass throughout with excellent conditioning. One of four courses at Cog Hill, all open to the public.', playingTips: 'Accuracy off the tee is paramount. Fairways are pinched by deep bunkers. Greens are large but contoured with steep-faced bunkers requiring confident sand play.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Green fees $65-$125.' }, { question: 'Tournaments hosted?', answer: 'Western Open (1962-2006), BMW Championship, 1997 U.S. Amateur. Tiger Woods won 2009 BMW here.' }, { question: 'Designers?', answer: 'Dick Wilson/Joe Lee (1964). Rees Jones renovations 2008 and 2025.' }, { question: 'Why Dubsdread?', answer: 'Means dreaded by dubs (poor golfers), reflecting the difficulty.' }] },
    { id: 'chi-3', name: 'Olympia Fields Country Club - North', slug: 'olympia-fields-north', city: 'Chicago', state: 'Illinois', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Willie Park Jr.', yearBuilt: 1922, holes: 18, par: 70, yardage: 7366, description: 'Host of the 2003 U.S. Open and 2023 BMW Championship, Olympia Fields North is a classic parkland championship course south of Chicago. The tight, tree-lined layout demands precision and patience through 18 demanding holes.', highlights: ['U.S. Open and BMW Championship host', 'Classic parkland championship design', 'Demanding tree-lined layout'], imageAlt: 'Olympia Fields North Course tree-lined championship hole', history: 'Olympia Fields Country Club was founded in 1915 and at its peak was one of the largest country clubs in the world, spanning over 700 acres with four 18-hole courses. The North Course -- originally designated as Course No. 4 -- was designed in 1923 by Willie Park Jr., a two-time Open Champion (1887 and 1889) from Musselburgh, Scotland. Park called his creation the equal of any course he had ever seen.\n\nThe North Course has hosted an extraordinary roster of major championships: two U.S. Opens (1928 and 2003), two PGA Championships (1925 and 1961), the U.S. Senior Open (1997), the U.S. Amateur (2015), the KPMG Women\'s PGA Championship (2017), and multiple BMW Championships (2020 and 2023).\n\nOver the decades, the club scaled back from four courses to two (North and South), but the North Course has remained a premier championship venue. Its naturally rolling terrain, mature tree canopy, and demanding par of 70 continue to test the world\'s best players.', signatureHoles: [{ hole: 1, par: 5, yardage: 627, description: 'A massive opening par 5 at 627 yards that immediately establishes the demanding character of the North Course. The tree-lined fairway requires two precise shots to set up a reachable third into the green.' }, { hole: 3, par: 4, yardage: 463, description: 'One of the most impressive par 4s on the course, playing 463 yards through a tree-lined corridor. The approach to the elevated green is one of the most demanding on the front nine.' }, { hole: 14, par: 4, yardage: 452, description: 'A long, demanding par 4 that pairs with the 3rd as one of the finest par-4 duos on any championship course. The tee shot must navigate a tight tree-lined fairway before a lengthy approach to a well-defended green.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finishing par 4 that has decided championships. The tree-lined fairway demands an accurate drive, and the approach must find a green that slopes away from incoming shots.' }], whatToExpect: 'Olympia Fields North is a classic Midwest parkland championship course that rewards precision and patience. At 7,366 yards with a par of just 70, the course carries a rating of 76.6 and slope of 150 from the back tees, making it one of the most demanding layouts in the Chicago area.\n\nThe course is routed over naturally rolling terrain south of Chicago, providing subtle elevation changes that add complexity to club selection. Conditioning is always championship-caliber, with firm, fast greens that reward precise iron play.', playingTips: 'With a par of 70 and only two par 5s, Olympia Fields North does not give away many birdie opportunities. Patience and course management are essential. Focus on hitting fairways -- the tree-lined corridors punish errant tee shots.\n\nThe greens are well-defended and feature subtle movement. Approach shots that find the correct portion of the green leave manageable putts, while missing to the wrong side often results in a challenging up-and-down.', faqs: [{ question: 'Can the public play Olympia Fields North?', answer: 'No. Olympia Fields is a private country club. Access is limited to members and their guests.' }, { question: 'What major championships has Olympia Fields hosted?', answer: 'Two U.S. Opens (1928, 2003), two PGA Championships (1925, 1961), the U.S. Senior Open (1997), the U.S. Amateur (2015), the KPMG Women\'s PGA Championship (2017), and multiple BMW Championships.' }, { question: 'Who designed the North Course?', answer: 'Willie Park Jr., a two-time Open Champion from Musselburgh, Scotland, designed the course in 1923.' }, { question: 'Why is the par only 70?', answer: 'The North Course features just two par 5s and four par 3s, resulting in a par of 70 that combined with the 7,366-yard length makes it one of the toughest tests in championship golf.' }] },
    { id: 'chi-4', name: 'Medinah Country Club - Course No. 3', slug: 'medinah-no-3', city: 'Chicago', state: 'Illinois', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Tom Bendelow / Roger Rulewich', yearBuilt: 1928, holes: 18, par: 72, yardage: 7658, description: 'Known for its iconic Byzantine-inspired clubhouse, Medinah No. 3 has hosted three U.S. Opens, two PGA Championships, and the 2012 Ryder Cup. The Lake Kadijah centerpiece and dramatic tree-lined holes make this one of golf\'s most recognizable venues.', highlights: ['Three-time U.S. Open host', '2012 Ryder Cup "Miracle at Medinah"', 'Iconic clubhouse and Lake Kadijah'], imageAlt: 'Medinah Country Club No. 3 with Byzantine clubhouse and Lake Kadijah', history: 'Medinah Country Club was founded in 1924 by members of the Shriners organization, and Course No. 3 was completed in 1928, designed by Scottish-born architect Tom Bendelow. The course was built on rolling terrain west of Chicago, with Lake Kadijah -- a man-made lake created during construction -- becoming its defining feature. The Byzantine-inspired clubhouse, with its distinctive dome, remains one of the most recognizable structures in American golf.\n\nCourse No. 3 rose to major championship prominence hosting the 1949 U.S. Open won by Cary Middlecoff, the 1975 U.S. Open won by Lou Graham, and the 1990 U.S. Open won by Hale Irwin. It also hosted PGA Championships in 1999 and 2006, both won by Tiger Woods. The 2012 Ryder Cup produced one of the most dramatic moments in the event\'s history when Europe mounted a historic final-day comeback from 10-6 down, forever known as the Miracle at Medinah. The 2019 BMW Championship saw Justin Thomas fire a course-record 61.\n\nIn 2024, the firm of Ogilvy, Cocking, and Mead (OCM) completed an extensive renovation and redesign of Course No. 3. The project involved major routing changes particularly on the final six holes, transforming the layout from a narrow, heavily wooded course into a more broad and dynamic design.', signatureHoles: [{ hole: 2, par: 3, yardage: 211, description: 'A demanding par 3 that plays over a portion of Lake Kadijah to a well-defended green. This is one of several holes where the lake comes dramatically into play, requiring a precise tee shot to find the putting surface.' }, { hole: 7, par: 5, yardage: 582, description: 'The longest par 5 on the front nine at 582 yards. This three-shot hole winds through mature trees and demands strategic positioning on each shot to set up a reasonable approach to the green.' }, { hole: 13, par: 3, yardage: 153, description: 'A shorter par 3 but one of the most scenic on the course, playing across Lake Kadijah to a green framed by the water and towering trees. Club selection is critical as the penalty for missing the green is severe.' }, { hole: 17, par: 3, yardage: 193, description: 'One of the new signature holes following the 2024 OCM redesign. This par 3 features a dramatic setting with Lake Kadijah in play, creating one of the most visually striking and pressure-packed shots on the course.' }], whatToExpect: 'Medinah No. 3 is a major championship venue with the presence and conditioning to match. Following the 2024 OCM redesign, the course has been transformed from a narrow, heavily wooded layout into a more open, strategically demanding design while retaining its core character. Lake Kadijah remains the dramatic centerpiece, coming into play on several holes.\n\nAt over 7,600 yards from the championship tees with a par of 72, this is a long and demanding course. The rolling terrain provides natural elevation changes, and the mature trees that remain frame the holes beautifully. The iconic Byzantine clubhouse provides a stunning backdrop throughout the round.', playingTips: 'Course management is essential at Medinah No. 3. The par 3s are a particular strength of the design, with Lake Kadijah creating dramatic forced carries on several short holes. Take enough club to clear the water comfortably rather than aiming for the pin.\n\nThe 2024 redesign opened up the course significantly, but the remaining tree-lined holes still demand accuracy off the tee. The greens feature creative contours, so read putts carefully and focus on leaving approach shots below the hole.', faqs: [{ question: 'Can the public play Medinah No. 3?', answer: 'No. Medinah is a private country club with three courses. Access to Course No. 3 is limited to members and their guests.' }, { question: 'What major championships has Medinah No. 3 hosted?', answer: 'Three U.S. Opens (1949, 1975, 1990), two PGA Championships (1999, 2006), the 2012 Ryder Cup, and the 2019 BMW Championship, among other significant events.' }, { question: 'What was the Miracle at Medinah?', answer: 'The 2012 Ryder Cup saw Europe trail 10-6 entering the final-day singles matches but mount a historic comeback to win 14.5 to 13.5, one of the greatest comebacks in team golf history.' }, { question: 'What is the OCM redesign?', answer: 'In 2024, Ogilvy, Cocking, and Mead completed an extensive renovation that reimagined the final six holes and opened up the previously narrow, wooded layout into a more dynamic and strategic design.' }] },
    { id: 'chi-5', name: 'Harborside International - Port Course', slug: 'harborside-port', city: 'Chicago', state: 'Illinois', type: 'public', rating: 4.2, greensFee: '$45–$85', architect: 'Dick Nugent', yearBuilt: 1995, holes: 18, par: 72, yardage: 7164, description: 'Built on a former landfill on Lake Michigan\'s south shore, Harborside\'s Port Course offers links-style golf with Chicago skyline views. The windswept layout is a unique public golf experience just minutes from downtown.', highlights: ['Chicago skyline views', 'Links-style lakefront design', 'Former landfill transformation'], imageAlt: 'Harborside International Port Course with Chicago skyline views', history: 'Harborside International opened in 1995 on a former landfill site on Lake Michigan\'s south shore, designed by Dick Nugent. The transformation from landfill to links-style golf was one of the most ambitious reclamation projects in American golf.\n\nThe Port and Starboard courses provide links-style golf with Chicago skyline views, offering a unique public experience minutes from downtown.', signatureHoles: [{ hole: 7, par: 4, yardage: 430, description: 'A windswept par 4 with Chicago skyline views framing the approach.' }, { hole: 13, par: 3, yardage: 195, description: 'A demanding par 3 exposed to Lake Michigan winds.' }, { hole: 16, par: 5, yardage: 555, description: 'A risk-reward par 5 along the lakefront.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finishing hole with skyline backdrop.' }], whatToExpect: 'Links-style golf on a former landfill with Chicago skyline views and Lake Michigan winds. At 7,164 yards, the wind makes it play significantly longer.\n\nThe open, treeless layout is exposed to constant winds off the lake.', playingTips: 'Wind off Lake Michigan is the primary defense. Club selection can vary by 3-4 clubs depending on wind direction.\n\nKeep the ball low in windy conditions. Bump-and-run shots work well.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Green fees $45 to $85.' }, { question: 'How many courses?', answer: 'Two: Port and Starboard, both links-style.' }, { question: 'What was the site before?', answer: 'A former landfill on Lake Michigan\'s south shore.' }] },
    { id: 'chi-6', name: 'Shoreacres', slug: 'shoreacres', city: 'Chicago', state: 'Illinois', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Seth Raynor', yearBuilt: 1921, holes: 18, par: 70, yardage: 6310, description: 'A Seth Raynor masterpiece on the North Shore overlooking Lake Michigan, Shoreacres is consistently ranked among the best courses in Illinois and the top 50 in America. The compact 6,310-yard layout features Raynor\'s template holes adapted brilliantly to dramatic lakeside ravine terrain.', highlights: ['Seth Raynor masterpiece', 'Lake Michigan bluff setting', 'Top 50 in America'], imageAlt: 'Shoreacres Seth Raynor ravine hole overlooking Lake Michigan on Chicago North Shore', history: 'Shoreacres was founded in 1916 in Lake Bluff on Chicago\'s North Shore. Seth Raynor designed the course, which opened in 1921 on spectacular ravine terrain near Lake Michigan. Raynor brilliantly chose the interior ravine land over the steep lakefront bluffs, creating one of his most celebrated routings.\n\nAfter decades of play, a restoration brought back Raynor\'s original template holes and bunkering. Shoreacres is widely regarded as one of Raynor\'s finest courses and consistently ranks among the top 50 in America. At just 6,310 yards, it is the shortest course on most top-100 lists, proving great architecture transcends length.', signatureHoles: [{ hole: 12, par: 3, yardage: 133, description: 'A beautiful short par 3 playing downhill to a green in the most attractive setting on the course.' }, { hole: 1, par: 4, yardage: 478, description: 'A demanding opener traversing the ravine terrain, one of the most challenging opening holes in Chicago golf.' }, { hole: 15, par: 5, yardage: 478, description: 'A short par 5 through the ravines offering birdie chances for those who navigate the dramatic terrain.' }, { hole: 7, par: 3, yardage: 165, description: 'A Raynor Redan hole adapted to the North Shore terrain with the green sloping front-right to back-left in classic fashion.' }], whatToExpect: 'An intimate, walkable masterpiece set in deep ravines on Chicago\'s North Shore. At 6,310 yards and par 70 it is compact but endlessly strategic. Raynor\'s template holes are adapted brilliantly to the dramatic topography.', playingTips: 'Do not let the short yardage fool you. Ravine terrain creates awkward stances and uneven lies. Raynor\'s green complexes are the primary defense with bold contours punishing wrong-side misses. A strong short game is essential.', faqs: [{ question: 'Can the public play Shoreacres?', answer: 'No. It is a private club with no public access.' }, { question: 'Is it really only 6,310 yards?', answer: 'Yes. It is the shortest course on most top-100 lists, proving great architecture transcends length.' }, { question: 'Who designed it?', answer: 'Seth Raynor designed the course, opening in 1921. It is widely regarded as one of his finest works.' }, { question: 'What are template holes?', answer: 'Designs based on famous British holes. Raynor learned this from C.B. Macdonald and adapted templates like the Redan to the North Shore terrain.' }] },
    { id: 'chi-7', name: 'Conway Farms Golf Club', slug: 'conway-farms', city: 'Chicago', state: 'Illinois', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 1991, holes: 18, par: 70, yardage: 7139, description: 'A Tom Fazio design in Lake Forest that hosted the 2013 BMW Championship, Conway Farms proves that compelling championship golf doesn\'t require 7,400+ yards. The walking-only, caddie-program club emphasizes strategic variety and firm, fast conditions.', highlights: ['Hosted 2013 BMW Championship', 'Walking-only with caddie program', 'Tom Fazio strategic design'], imageAlt: 'Conway Farms championship fairway in Lake Forest Illinois', history: 'Conway Farms Golf Club opened in 1991 in Lake Forest on Chicago\'s North Shore. Tom Fazio designed the course with Scottish links influences. The club adopted a walking-only policy with a full caddie program from inception.\n\nConway Farms hosted the BMW Championship in 2013, 2015, and 2017. Zach Johnson won the inaugural 2013 edition. The club also hosted the 2009 Western Amateur and regularly ranks among the top 10 courses in Illinois.', signatureHoles: [{ hole: 1, par: 4, yardage: 360, description: 'A short opening par 4 that demands precision despite modest yardage.' }, { hole: 4, par: 4, yardage: 497, description: 'The longest par 4 on the course, requiring two strong shots.' }, { hole: 10, par: 4, yardage: 453, description: 'A strong par 4 beginning the back nine with a demanding approach.' }, { hole: 18, par: 4, yardage: 467, description: 'A challenging finishing par 4 that has provided drama in BMW Championship finishes.' }], whatToExpect: 'Conway Farms is a walking-only experience with a mandatory caddie program. The Fazio design plays to 7,139 yards at par 70 with strategic variety.\n\nFirm, fast conditions and Scottish links influence are hallmarks of the design.', playingTips: 'At par 70, birdie chances are limited. Wind off Lake Michigan is a significant factor. Lean on your caddie for local knowledge.', faqs: [{ question: 'Can the public play Conway Farms?', answer: 'No. It is a private club with no public access.' }, { question: 'Is it walking only?', answer: 'Yes, with a full caddie program.' }, { question: 'What Tour events has it hosted?', answer: 'The BMW Championship in 2013, 2015, and 2017.' }, { question: 'Who designed it?', answer: 'Tom Fazio, opening in 1991.' }] },
    { id: 'chi-8', name: 'Cantigny Golf Club', slug: 'cantigny-golf', city: 'Chicago', state: 'Illinois', type: 'public', rating: 4.2, greensFee: '$55–$110', architect: 'Roger Packard', yearBuilt: 1989, holes: 27, par: 72, yardage: 6719, description: 'Located on the former estate of Chicago Tribune publisher Robert R. McCormick, Cantigny offers 27 holes of well-maintained public golf in Wheaton. The Roger Packard design features beautiful parkland terrain, a dedicated golf academy, and one of the best practice facilities in the Midwest.', highlights: ['Historic McCormick estate setting', '27 holes with top practice facility', 'Best-maintained public course in western suburbs'], imageAlt: 'Cantigny Golf Club parkland fairway on McCormick estate in Wheaton', history: 'Cantigny Golf Club opened in 1989, designed by Roger Packard on 250 acres of the former estate of Colonel Robert R. McCormick — longtime publisher of the Chicago Tribune and a decorated World War I officer. McCormick named his Wheaton farm "Cantigny" after the Battle of Cantigny (May 28, 1918), America\\\'s first major offensive victory in the Great War.\n\nThe course was dedicated on June 5, 1989, with two-time U.S. Open champion Andy North. A Jacobson Golf Course Design renovation updated the layout in 2003. The 500-acre Cantigny Park is operated by the Robert R. McCormick Foundation, which has invested over $1.5 billion in journalism, education, and veteran programs.\n\nGolf Digest named Cantigny "Best New Public Course in America" shortly after opening. It has maintained its reputation as the premier public course in Chicago\\\'s western suburbs, with a 4.7/5 rating and 93.7% recommendation rate from over 450 reviews.', signatureHoles: [{ hole: 6, par: 3, yardage: 165, description: 'On the Hillside nine — "The Chase." The most difficult hole (handicap 1) with a green completely surrounded by water. Precision is mandatory; there is no safe miss.' }, { hole: 3, par: 4, yardage: 390, description: 'On the Hillside nine — "Packard\\\'s Peak," named after architect Roger Packard. Features dramatic elevation changes on the course\\\'s most architecturally interesting hole.' }], whatToExpect: 'Cantigny offers 27 holes across three distinct nines — Woodside, Lakeside, and Hillside — each with its own character. Woodside demands accuracy through dense tree corridors. Lakeside features water on six of nine holes. Hillside is the shortest but arguably toughest nine.\n\nWith over 70 bunkers and a dozen lakes plus two creeks, the course rewards accurate tee shots and smart course management. Conditioning is consistently praised — reviewers compare it to a Northern Michigan resort despite being in the Chicago suburbs. The atmosphere is described as "a public course with a private feel."\n\nThe Cantigny Golf Academy features 10 covered heated bays with TrackMan technology — one of the finest practice facilities in the Midwest. The adjacent First Division Museum and McCormick House museum add cultural depth to the visit.', playingTips: 'Accuracy over distance on all three nines. Tree-lined fairways (Woodside), water hazards (Lakeside), and tight corridors (Hillside) all punish wayward shots more than short ones.\n\nWith over 70 bunkers, solid sand play is essential. Practice in the short-game area before your round.\n\nOn the Lakeside nine, water affects six of nine holes. Know where the hazards are and play away from them — conservative club selection saves strokes.\n\nThe Hillside nine is shortest but toughest. Hole 6 ("The Chase") with its water-surrounded green is the hardest hole across all 27 — accept par as a great score.\n\nTake advantage of the heated TrackMan bays at the Golf Academy for a year-round warm-up, especially in winter.', faqs: [{ question: 'Why is it called Cantigny?', answer: 'Named after the Battle of Cantigny (May 28, 1918), America\\\'s first major offensive victory in World War I. Colonel Robert R. McCormick, who fought in the battle, named his Wheaton estate "Cantigny" in its honor.' }, { question: 'How many holes does Cantigny have?', answer: '27 holes across three nines: Woodside (tree-lined), Lakeside (water features), and Hillside (elevation changes). Any two nines combine for an 18-hole round.' }, { question: 'What makes the practice facility special?', answer: 'The Cantigny Golf Academy features 10 covered, heated bays with TrackMan radar technology (same as PGA Tour broadcasts), indoor simulators, and a year-round operation. One of the finest practice facilities in the Midwest.' }, { question: 'Is it connected to the Chicago Tribune?', answer: 'Yes. The estate belonged to Robert R. McCormick, publisher of the Chicago Tribune for over four decades. The Robert R. McCormick Foundation now operates the entire 500-acre Cantigny Park.' }]},
    { id: 'chi-9', name: 'Rich Harvest Farms', slug: 'rich-harvest-farms', city: 'Chicago', state: 'Illinois', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Jerry Rich', yearBuilt: 1999, holes: 18, par: 72, yardage: 7531, description: 'One of the most exclusive and unique private courses in America, Rich Harvest Farms was designed by owner Jerry Rich on his 455-acre farm in Sugar Grove. The 7,531-yard layout features dramatic elevation changes, water on 13 holes, and hosted the 2009 Solheim Cup.', highlights: ['Hosted 2009 Solheim Cup', 'Owner-designed on 455-acre farm', '7,531 yards with water on 13 holes'], imageAlt: 'Rich Harvest Farms dramatic farmland course in Sugar Grove near Chicago', history: 'Rich Harvest Farms is one of the most unique stories in American golf. In 1987, Jerry Rich began developing a golf course on his 1,820-acre property in Sugar Grove, Illinois, about 50 miles west of Chicago. With no formal training in golf architecture, Rich designed and built the course himself over more than a decade. It opened in 1999.\n\nThe layout features massive elevation changes unusual for the Chicago area, water hazards on 13 of 18 holes, and a distinctive covered bridge on the 9th hole. From the championship tees it stretches to 7,531 yards with a slope of 155 and a course rating of 79.1.\n\nRich Harvest Farms gained international attention as host of the 2009 Solheim Cup. The club has also hosted the 2015 Western Amateur and the Arnold Palmer Cup.', signatureHoles: [{ hole: 3, par: 3, yardage: 235, description: 'A long par 3 over water to a well-defended green. One of the most challenging short holes in the Chicago area.' }, { hole: 9, par: 5, yardage: 545, description: 'The signature hole features the property\'s iconic covered bridge. This par 5 offers risk-reward options and a memorable walk through the bridge.' }, { hole: 14, par: 4, yardage: 461, description: 'A demanding par 4 with a dramatic elevated tee and water threatening the approach.' }, { hole: 17, par: 4, yardage: 489, description: 'Often considered the toughest hole, this long par 4 demands two precise shots to find the green.' }], whatToExpect: 'Rich Harvest Farms features more elevation change than almost any course in the Chicago area, with water on 13 of 18 holes. At 7,531 yards with a slope of 155, this is one of the most demanding courses in Illinois.\n\nThe remote farm setting creates an atmosphere of privacy and exclusivity unlike typical suburban clubs.', playingTips: 'Water management is essential. With water on 13 holes, knowing when to lay up is critical. The par 3s are particularly demanding.\n\nDramatic elevation changes affect club selection significantly. Trust your caddie for local knowledge.', faqs: [{ question: 'Can the public play Rich Harvest Farms?', answer: 'No. It is an extremely private club with no public access.' }, { question: 'Who designed it?', answer: 'Owner Jerry Rich designed and built the course himself with no formal architectural training.' }, { question: 'What championships has it hosted?', answer: 'The 2009 Solheim Cup, 2015 Western Amateur, and Arnold Palmer Cup.' }, { question: 'Why is the slope so high?', answer: 'At 155, the slope reflects 7,531 yards, water on 13 holes, dramatic elevation changes, and demanding greens.' }] },
  ],
  'nashville-tennessee': [
    { id: 'nas-1', name: 'The Golf Club of Tennessee', slug: 'golf-club-tennessee', city: 'Nashville', state: 'Tennessee', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 2000, holes: 18, par: 72, yardage: 7334, description: 'Nashville\'s most exclusive golf address, The Golf Club of Tennessee is a Tom Fazio design that winds through the rolling hills of Williamson County. The course features dramatic elevation changes, pristine conditioning, and panoramic views of the Tennessee countryside.', highlights: ['Nashville\'s most exclusive club', 'Tom Fazio design', 'Rolling Tennessee hill country'], imageAlt: 'Golf Club of Tennessee rolling hills south of Nashville', history: 'The Golf Club of Tennessee was formed in 1988 by Nashville businessman Bronson Ingram along with Toby S. Wilt and George Gillette, who envisioned building a fine golf-only club west of Nashville. Tom Fazio, assisted by longtime associate Tom Marzolf, designed the sprawling layout on 317 acres in Kingston Springs.\n\nThe course opened for member play in 1991 and quickly established itself as the premier private golf club in the Nashville area. The design features A1 bent grass greens and lush fairways winding through the rolling Tennessee countryside with dramatic elevation changes and panoramic views.\n\nThe Golf Club of Tennessee maintains an exclusive membership focused purely on the golf experience without the social programming typical of traditional country clubs. It consistently ranks among the top private courses in the state.', signatureHoles: [{ hole: 5, par: 4, yardage: 445, description: 'A demanding par 4 with a sweeping view of the Tennessee hills. The elevated tee provides a panoramic vista before the challenge of the approach to a well-defended green.' }, { hole: 12, par: 3, yardage: 195, description: 'A scenic par 3 playing slightly downhill with the rolling countryside as backdrop. The green is surrounded by Fazio\'s characteristic bunkering.' }, { hole: 15, par: 5, yardage: 560, description: 'A risk-reward par 5 that tempts long hitters to go for the green in two while punishing those who miss. The hole winds through mature trees with elevation change.' }, { hole: 18, par: 4, yardage: 450, description: 'A strong finishing par 4 that demands two precise shots to reach the green. The elevated setting provides a fitting conclusion to the round.' }], whatToExpect: 'A sprawling Tom Fazio design on 317 acres of rolling Tennessee countryside. The course features dramatic elevation changes and panoramic views with pristine conditioning throughout. The golf-only club atmosphere means the focus is entirely on the playing experience.\n\nAt 7,334 yards from the tips the course is a serious test. A1 bent grass greens are fast and true.', playingTips: 'The rolling terrain means many lies are uneven. Practice hitting from sidehill and uphill/downhill lies before your round. The elevation changes also affect club selection significantly.\n\nThe bent grass greens are fast and true but feature subtle breaks influenced by the surrounding terrain. Reading greens carefully is essential for scoring.', faqs: [{ question: 'Can the public play?', answer: 'No. The Golf Club of Tennessee is a private club with no public access.' }, { question: 'Who designed it?', answer: 'Tom Fazio with associate Tom Marzolf. The course opened in 1991.' }, { question: 'Where is it located?', answer: 'In Kingston Springs, about 25 miles west of downtown Nashville on 317 acres.' }, { question: 'What type of club is it?', answer: 'A golf-only private club focused purely on the playing experience, formed in 1988 by Bronson Ingram and Toby Wilt.' }] },
    { id: 'nas-2', name: 'Hermitage Golf Course - Presidents Reserve', slug: 'hermitage-presidents-reserve', city: 'Nashville', state: 'Tennessee', type: 'public', rating: 4.5, greensFee: '$45–$85', architect: 'Denis Griffiths', yearBuilt: 2000, holes: 18, par: 72, yardage: 7157, description: 'Host of the Simmons Bank Open on the Korn Ferry Tour, Presidents Reserve at Hermitage is Nashville\'s premier public course. The layout along the Cumberland River features dramatic bluff-top views and a challenging finishing stretch.', highlights: ['Korn Ferry Tour venue', 'Cumberland River bluff-top holes', 'Nashville\'s best public course'], imageAlt: 'Hermitage Golf Course Presidents Reserve along the Cumberland River', history: 'Opened in 2000 along the Cumberland River near Andrew Jackson\'s Hermitage estate, designed by Denis Griffiths. Hosts the Korn Ferry Tour\'s Simmons Bank Open.', signatureHoles: [{ hole: 14, par: 4, yardage: 440, description: 'Dramatic par 4 along Cumberland River bluffs.' }, { hole: 16, par: 3, yardage: 195, description: 'Demanding par 3 overlooking the river.' }, { hole: 17, par: 5, yardage: 560, description: 'Risk-reward par 5 along the river.' }, { hole: 18, par: 4, yardage: 445, description: 'Strong finishing hole, decisive in Korn Ferry events.' }], whatToExpect: 'Nashville\'s premier public course along the Cumberland River with bluff-top views. At 7,157 yards, a serious test.', playingTips: 'River bluff holes are exposed to wind. Greens can be fast during tournament season.', faqs: [{ question: 'Can the public play?', answer: 'Yes. $45 to $85.' }, { question: 'Professional events?', answer: 'Simmons Bank Open on the Korn Ferry Tour.' }] },
    { id: 'nas-3', name: 'Gaylord Springs Golf Links', slug: 'gaylord-springs', city: 'Nashville', state: 'Tennessee', type: 'public', rating: 4.3, greensFee: '$50–$90', architect: 'Larry Nelson', yearBuilt: 1990, holes: 18, par: 72, yardage: 7120, description: 'Adjacent to the Gaylord Opryland Resort, this Larry Nelson design follows the Cumberland River with a links-influenced feel. The course offers a convenient, quality golf experience for Nashville visitors and Music City locals alike.', highlights: ['Gaylord Opryland Resort adjacent', 'Cumberland River setting', 'Larry Nelson links-influenced design'], imageAlt: 'Gaylord Springs Golf Links along the Cumberland River near Opryland', history: 'Gaylord Springs Golf Links was designed by three-time major champion Larry Nelson and opened in the early 1990s along the Cumberland River in Nashville. Nelson brought his competitive experience to a links-inspired layout that demands strategic thinking.\n\nThe course is adjacent to the Gaylord Opryland Resort. Nearly every hole runs north-south along the river, with limestone bluffs and wetlands providing natural hazards and scenic beauty.\n\nGaylord Springs has established itself as one of Nashville\'s top public golf experiences, offering championship golf at accessible pricing with wide corridors, strategic bunkering, and firm approaches.', signatureHoles: [{ hole: 5, par: 4, yardage: 415, description: 'A par 4 along the Cumberland River with links-style bunkering demanding a precise approach.' }, { hole: 9, par: 3, yardage: 195, description: 'A demanding par 3 with the Cumberland as backdrop. Wind off the river affects club selection.' }, { hole: 14, par: 5, yardage: 550, description: 'A risk-reward par 5 with limestone bluffs and river wetlands framing the hole.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finisher back toward the clubhouse with the Opryland Resort visible beyond.' }], whatToExpect: 'A links-inspired layout along the Cumberland River with wide corridors and strategic bunkering. Limestone bluffs and wetlands provide natural beauty and hazards.\n\nAt 7,120 yards from the tips, it is a legitimate championship test. The location adjacent to Opryland Resort makes it ideal for visitors.', playingTips: 'The links design rewards low, running shots. Firm surfaces allow ball release, so plan for roll-out on approaches.\n\nWind off the Cumberland is a constant factor on exposed holes.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Green fees typically from $50 to $90.' }, { question: 'Who designed it?', answer: 'Three-time major champion Larry Nelson.' }, { question: 'Is it connected to Opryland Resort?', answer: 'Yes. The course is adjacent, making it convenient for hotel guests.' }, { question: 'Is it a true links?', answer: 'Links-inspired with wide corridors, strategic bunkering, and firm conditions along the Cumberland River.' }] },
    { id: 'nas-4', name: 'Nashville Golf & Athletic Club', slug: 'nashville-golf-athletic', city: 'Nashville', state: 'Tennessee', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Bob Cupp', yearBuilt: 1988, holes: 18, par: 72, yardage: 7116, description: 'A Bob Cupp design in Brentwood, Nashville Golf & Athletic Club is a well-regarded private club with a demanding layout through Middle Tennessee hills. The course rewards precision and course management.', highlights: ['Respected Brentwood private club', 'Bob Cupp design', 'Middle Tennessee hills setting'], imageAlt: 'Nashville Golf & Athletic Club hilly fairway in Brentwood', history: 'Nashville Golf & Athletic Club opened in 1988, designed by Bob Cupp — a former senior designer for Jack Nicklaus (1972-1986) who went on to design over 150 courses worldwide and served as ASGCA President in 2012-13. The club sits in Brentwood on dramatic Middle Tennessee terrain at 1703 Crockett Springs Trail.\n\nThe course plays up to 7,525 yards from the tips with a 137 slope and 76.8 rating, making it one of the most difficult layouts in Tennessee. The dramatic elevation changes throughout create memorable and challenging tee shots on nearly every hole.\n\nCupp passed away in 2016 at age 76, making Nashville Golf & Athletic Club one of his enduring Tennessee designs.', signatureHoles: [{ hole: 1, par: 4, yardage: 430, description: 'A notably punishing opener that has been featured in "Design Disasters" discussions for its difficulty. Sets an immediate tone that this is not a casual round — the course demands respect from the first swing.' }], whatToExpect: 'A classic Bob Cupp design with fast greens, thick rough, and abundant bunkers set across dramatic Middle Tennessee elevation changes. The course rewards precision and course management — you will hit every club in your bag.\n\nDespite its metro location in Brentwood, the course feels removed and rural. The greens are a particular highlight, kept in excellent condition with significant undulation. Reviewers describe it as "tough but fair" with more great holes than most private clubs in the region.\n\nAccess is strictly private — members and guests only.', playingTips: 'Play from the right tees. At 7,525 yards from the tips with a 137 slope, this course is long and demanding. The middle tees offer a more enjoyable experience for most golfers.\n\nThe elevation changes are deceptive — trust your yardage device over your eyes. Uphill and downhill shots require careful club adjustment.\n\nThick rough penalizes errant shots heavily. Accuracy off the tee is paramount.\n\nThe fast, undulating greens demand precise distance control on approach shots. Favor below-the-hole positions for manageable putts.', faqs: [{ question: 'Who designed Nashville Golf & Athletic Club?', answer: 'Bob Cupp, a former senior designer for Jack Nicklaus who designed over 150 courses worldwide. The course opened in 1988.' }, { question: 'How difficult is it?', answer: 'Very. At 7,525 yards from the tips with a 137 slope and 76.8 rating, it is one of the most difficult layouts in Tennessee.' }, { question: 'Can the public play?', answer: 'No. Nashville Golf & Athletic Club is a private club in Brentwood. Access requires membership or a member invitation.' }]},
    { id: 'nas-5', name: 'Greystone Golf Club', slug: 'greystone-nashville', city: 'Nashville', state: 'Tennessee', type: 'public', rating: 4.1, greensFee: '$35–$65', architect: 'Mark McCumber', yearBuilt: 1999, holes: 18, par: 72, yardage: 6971, description: 'A Mark McCumber design in Dickson west of Nashville, Greystone offers a solid public golf experience through Middle Tennessee terrain. The well-maintained layout features wooded hills, creeks, and good variety.', highlights: ['Mark McCumber design', 'Well-maintained Middle Tennessee course', 'Good value west of Nashville'], imageAlt: 'Greystone Golf Club wooded fairway in Dickson near Nashville', history: 'Greystone Golf Club opened in 1998, designed by 10-time PGA Tour winner Mark McCumber with Mike Nuzzo. McCumber\\\'s firm has designed over 40 courses globally. Located about 40 miles west of Nashville in Dickson, the course has served as a PGA Tour Q-School (Qualifying School) host site and hosted numerous Tennessee state golf events.\n\nNamed to "Top 10 Tennessee Courses You Can Play" lists, Greystone offers genuine championship caliber at public-access pricing — a combination that makes it a standout value in the Nashville region.', signatureHoles: [{ hole: 9, par: 4, yardage: 420, description: 'Renowned for its beauty and difficulty — described by players as "beautifully hard." The fairway is one of the most visually striking on the course, demanding both an accurate tee shot and a precise approach.' }, { hole: 2, par: 5, yardage: 520, description: 'A mid-length par 5 with a spacious fairway guarded by a tree line and creek, setting the tone for the course. Risk-reward decisions start early.' }], whatToExpect: 'Dramatic Middle Tennessee elevation changes give Greystone strong visual appeal. The terrain features wooded areas, creeks, and rolling hills throughout. The back nine (holes 10-18) is particularly praised for variety and challenge.\n\nA good mix of hole variety — some genuinely challenging, some more forgiving — creates a fair test across skill levels. When well-maintained, it plays as a top-notch public offering with PGA Tour Q-School pedigree.\n\nAt $35-65, this represents excellent value for the caliber of Mark McCumber design work.', playingTips: 'Respect the elevation changes. Uphill and downhill shots require careful club adjustments throughout the round.\n\nSome holes feature forced carries, so know your distances honestly before committing to aggressive lines.\n\nFairway placement is critical on the tighter holes, especially on the back nine where the challenge increases.\n\nThe course has been tested by aspiring PGA Tour professionals during Q-School — play smart and take your medicine when out of position.', faqs: [{ question: 'Who designed Greystone?', answer: 'Mark McCumber, a 10-time PGA Tour winner, with Mike Nuzzo. The course opened in 1998 about 40 miles west of Nashville in Dickson.' }, { question: 'Has it hosted professional events?', answer: 'Yes — PGA Tour Qualifying School (Q-School) has been held here, meaning aspiring tour professionals have tested the layout under tournament pressure.' }, { question: 'What is the value proposition?', answer: 'At $35-65, Greystone offers championship-caliber Mark McCumber design at public-access pricing. Named to "Top 10 Tennessee Courses You Can Play" lists.' }]},
    { id: 'nas-6', name: 'Honors Course', slug: 'honors-course', city: 'Nashville', state: 'Tennessee', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Pete Dye', yearBuilt: 1983, holes: 18, par: 72, yardage: 7064, description: 'Located in Ooltewah near Chattanooga, The Honors Course is a Pete Dye design that has hosted the U.S. Amateur, the NCAA Championship, and numerous USGA events. The course is widely regarded as the finest in Tennessee and one of Pete Dye\'s most complete designs.', highlights: ['Hosted U.S. Amateur and NCAA Championship', 'Finest course in Tennessee', 'One of Pete Dye\'s most complete designs'], imageAlt: 'Honors Course Pete Dye championship layout in Ooltewah Tennessee', history: 'The Honors Course was created by Jack Lupton, the Chattanooga Coca-Cola bottling magnate, who envisioned a course dedicated to honoring amateur golf. Pete Dye began construction at the base of White Mountain in Ooltewah on July 23, 1981, and the course opened in 1983.\n\nThe club has hosted the U.S. Amateur, U.S. Mid-Amateur, U.S. Senior Amateur, Curtis Cup, NCAA Championship, and numerous state amateur events. Ranked number one in Tennessee and among America\'s top 50, it is regarded as one of Pete Dye\'s greatest creations.', signatureHoles: [{ hole: 15, par: 4, yardage: 475, description: 'A demanding par 4 with forced water carry. The fairway is flanked by water requiring an accurate drive and courageous approach.' }, { hole: 3, par: 3, yardage: 180, description: 'An early par 3 with Dye\'s characteristic green contours and well-placed bunkers setting the strategic tone.' }, { hole: 18, par: 4, yardage: 420, description: 'A strong finisher with creek tributaries exposed in front of the green, a fitting conclusion to a great championship course.' }, { hole: 6, par: 5, yardage: 520, description: 'A reachable par 5 marking the transition from woodland to more open terrain. Risk-reward decisions define the experience.' }], whatToExpect: 'A Pete Dye masterpiece in the tranquil woods of the Ooltewah foothills near Chattanooga. The par-72 layout plays to approximately 7,500 yards from back tees. The championship pedigree is evident throughout, with exceptional conditioning and a serene wooded setting.', playingTips: 'Dye challenges the eye before challenging the swing. Many holes present optical illusions making distances deceiving. Trust your yardage. Water comes into play on multiple back-nine holes, so course management and avoiding big numbers are key.', faqs: [{ question: 'Can the public play?', answer: 'No. The Honors Course is private with no public access.' }, { question: 'What events has it hosted?', answer: 'The U.S. Amateur, U.S. Mid-Amateur, U.S. Senior Amateur, Curtis Cup, NCAA Championship, and numerous state events.' }, { question: 'Who created it?', answer: 'Jack Lupton created the club; Pete Dye designed the course, opening in 1983.' }, { question: 'Is it in Nashville?', answer: 'No. It is in Ooltewah near Chattanooga, about 130 miles southeast of Nashville.' }] },
    { id: 'nas-7', name: 'The Governors Club', slug: 'governors-club', city: 'Nashville', state: 'Tennessee', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Arnold Palmer', yearBuilt: 1999, holes: 36, par: 72, yardage: 7089, description: 'Arnold Palmer\'s signature Nashville area design, The Governors Club in Brentwood offers 36 holes of golf through the rolling hills of southern Williamson County. The two courses feature Palmer\'s trademark risk-reward par 5s and dramatic Tennessee terrain.', highlights: ['36 holes — Arnold Palmer design', 'Rolling Williamson County terrain', 'Nashville\'s premier multi-course club'], imageAlt: 'Governors Club rolling Tennessee hills Arnold Palmer fairway in Brentwood', history: 'The Governors Club opened in 1999 in Brentwood, Tennessee, designed by Arnold Palmer. The 36-hole facility features Palmer\'s trademark risk-reward par 5s on rolling Williamson County terrain.\n\nThe club quickly became Nashville\'s premier multi-course private club, attracting the area\'s business and civic leaders.', signatureHoles: [{ hole: 5, par: 5, yardage: 550, description: 'A classic Arnold Palmer risk-reward par 5 through rolling Tennessee terrain.' }, { hole: 9, par: 4, yardage: 445, description: 'A demanding par 4 with elevation change and strategic bunkering.' }, { hole: 14, par: 3, yardage: 190, description: 'A scenic par 3 framed by Tennessee hardwoods.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finishing hole climbing through the rolling hills.' }], whatToExpect: 'Arnold Palmer\'s 36-hole design through rolling Williamson County terrain. At 7,089 yards, the course features Palmer\'s signature risk-reward holes.\n\nThe rolling Tennessee hills create varied elevation changes on every hole.', playingTips: 'Palmer\'s risk-reward par 5s offer birdie chances but punish aggression. Calculate risk carefully.\n\nThe rolling terrain creates uneven lies. Solid ball-striking from slopes is essential.', faqs: [{ question: 'Can the public play?', answer: 'No. Private club.' }, { question: 'How many holes?', answer: '36 holes across two courses.' }, { question: 'Designer?', answer: 'Arnold Palmer, opened 1999.' }] },
    { id: 'nas-8', name: 'Vanderbilt Legends Club', slug: 'vanderbilt-legends', city: 'Nashville', state: 'Tennessee', type: 'semi-private', rating: 4.2, greensFee: '$50–$90', architect: 'Tom Kite & Bob Cupp', yearBuilt: 2004, holes: 36, par: 72, yardage: 7181, description: 'Named in honor of Vanderbilt University, Legends Club in Franklin offers 36 holes designed by Tom Kite and Bob Cupp. The two courses — Irish and Scottish themed — wind through Middle Tennessee horse country with excellent conditioning at accessible prices.', highlights: ['36 holes with Irish and Scottish themes', 'Tom Kite & Bob Cupp design', 'Middle Tennessee horse country setting'], imageAlt: 'Vanderbilt Legends Club links-themed fairway in Franklin Tennessee', history: 'Vanderbilt Legends Club opened its North Course in 1992 and added the South Course later, designed by Bob Cupp and 19-time PGA Tour winner/U.S. Open champion Tom Kite. The 36-hole facility in Franklin serves as the home course for Vanderbilt University\\\'s men\\\'s and women\\\'s golf teams.\n\nThe North Course carries an "Irish" theme while the South Course reflects a "Scottish" character, each with distinct design personalities. The club has hosted LPGA Tour events, U.S. Senior Open Qualifying, and Korn Ferry Tour events — establishing serious competitive credentials.\n\nAt 1500 Legends Club Lane in the heart of Middle Tennessee horse country, the facility is one of the premier 36-hole complexes in the Nashville/Franklin area.', signatureHoles: [{ hole: 2, par: 4, yardage: 420, description: 'On the North Course — one of three defining holes (along with 16 and 18) that most impact a player\\\'s final score. Execute well here and you can elevate your round; stumble and the card suffers.' }, { hole: 18, par: 4, yardage: 440, description: 'The North Course closer — another swing hole where the outcome often determines whether a good round finishes strong or falls apart. A demanding par 4 to close.' }], whatToExpect: 'Two distinct 18-hole courses with Irish and Scottish themes wind through Middle Tennessee horse country in Franklin. The North Course (par 72, approximately 7,190 yards, slope 132) features a mix of open and wooded terrain. The South Course (par 71, approximately 7,100 yards, slope 132) has more elevation changes.\n\nBoth courses are kept in excellent condition. As home to Vanderbilt Commodores golf and host of professional tour events, the facility maintains championship standards. Tom Kite\\\'s Tour-caliber design sensibility is evident throughout.\n\nThe semi-private format provides broader access than a fully private club.', playingTips: 'The South Course has more hidden trouble — play conservatively until you know the layout.\n\nElevation changes on both courses affect club selection significantly. Don\\\'t trust your eyes; use a rangefinder.\n\nOn the North Course, holes 2, 16, and 18 are the swing holes that define your score. Execute well on these and you can post a strong number.\n\nThe horse country setting means morning fog can affect early tee times in spring and fall.', faqs: [{ question: 'What are the two courses?', answer: 'The North Course (Irish-themed, par 72, ~7,190 yards) and South Course (Scottish-themed, par 71, ~7,100 yards). Each has a distinct character.' }, { question: 'Is it connected to Vanderbilt University?', answer: 'Yes — Legends Club serves as the home course for Vanderbilt\\\'s men\\\'s and women\\\'s golf teams.' }, { question: 'Has it hosted professional events?', answer: 'Yes — LPGA Tour events, U.S. Senior Open Qualifying, and Korn Ferry Tour events have all been held here.' }, { question: 'Is it open to the public?', answer: 'Semi-private. Access is available to members and through public tee times at $50-90.' }]},
    { id: 'nas-9', name: 'Temple Hills Country Club', slug: 'temple-hills-cc', city: 'Nashville', state: 'Tennessee', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Denis Griffiths', yearBuilt: 2001, holes: 18, par: 72, yardage: 7038, description: 'A Denis Griffiths design in Franklin south of Nashville, Temple Hills occupies some of the most beautiful rolling terrain in Middle Tennessee. The course features dramatic elevation changes, creek crossings, and pastoral views of the surrounding horse farms.', highlights: ['Denis Griffiths rolling Tennessee design', 'Dramatic elevation changes', 'Pastoral horse farm views in Franklin'], imageAlt: 'Temple Hills Country Club rolling terrain and horse farm views in Franklin Tennessee', history: 'Temple Hills Country Club opened in 2001, designed by Denis Griffiths — an architect who has worked since 1970 with Gary Player and Ron Kirby before establishing his own firm. Griffiths is one of the few American architects to complete course designs in St. Andrews, Scotland, and his international portfolio includes the Thai Country Club.\n\nThe club occupies some of the most beautiful rolling terrain in Middle Tennessee, with dramatic elevation changes and pastoral views of surrounding horse farms in Franklin south of Nashville. Now managed by Invited (formerly ClubCorp), the facility offers 27 holes arranged in three nines: Deercrest, Quail Run, and Foxchase.\n\nTemple Hills is notable for being one of the few courses in Middle Tennessee with bent grass greens, creating a different putting experience from the region\\\'s typical bermuda surfaces.', signatureHoles: [{ hole: 6, par: 3, yardage: 175, description: 'On the Foxchase nine — features creative, unconventional design elements that showcase Griffiths\\\'s international experience. The third nine has the most unusual and memorable holes.' }], whatToExpect: 'Three nines — Deercrest, Quail Run, and Foxchase — provide variety across 27 holes of championship golf on rolling Franklin terrain. Any two nines combine for an 18-hole round at approximately par 72 and 7,038 yards.\n\nThe bent grass greens are a distinguishing feature — ultra-soft in summer, they play differently from the bermuda greens found at most Middle Tennessee courses. Tree-lined fairways and rolling hills create defined corridors throughout.\n\nThe pastoral horse farm views and dramatic elevation changes make this one of the most visually appealing private clubs in the Nashville area. Managed by Invited (ClubCorp).', playingTips: 'The bent grass greens play differently in summer (soft, receptive) versus cooler months (firmer, faster). Adjust your approach strategy accordingly.\n\nPay attention to green contours — some greens have significant banking that redirects approach shots away from the pin. Read the slopes carefully.\n\nThe Foxchase nine has the most unusual layout. If it\\\'s your first time, expect some creative holes that require strategic thinking.\n\nThe course plays shorter than yardage suggests due to elevation changes — downhill holes are common.', faqs: [{ question: 'How many holes does Temple Hills have?', answer: '27 holes across three nines: Deercrest, Quail Run, and Foxchase. Any two nines combine for an 18-hole round.' }, { question: 'Who designed it?', answer: 'Denis Griffiths, an architect with international experience including courses at St. Andrews and Thai Country Club. The course opened in 2001.' }, { question: 'What makes the greens special?', answer: 'Temple Hills is one of the few Middle Tennessee courses with bent grass greens rather than bermuda, creating a distinctly different putting experience.' }, { question: 'Is it open to the public?', answer: 'No. Temple Hills is a private club managed by Invited (formerly ClubCorp). Membership or a member invitation is required.' }]},
  ],
  'myrtle-beach-south-carolina': [
    { id: 'mb-1', name: 'Caledonia Golf & Fish Club', slug: 'caledonia-golf-fish-club', city: 'Myrtle Beach', state: 'South Carolina', type: 'public', rating: 4.8, greensFee: '$125–$225', architect: 'Mike Strantz', yearBuilt: 1994, holes: 18, par: 70, yardage: 6526, description: 'Widely regarded as the crown jewel of Myrtle Beach golf, Caledonia is a Mike Strantz masterpiece routed through a former rice plantation along the Waccamaw River. The avenue of live oaks leading to the antebellum-style clubhouse sets the tone for one of America\'s most beautiful golf experiences.', highlights: ['Mike Strantz plantation masterpiece', 'Avenue of live oaks and antebellum clubhouse', 'Consistently ranked #1 in Myrtle Beach'], imageAlt: 'Caledonia Golf & Fish Club live oak avenue and plantation clubhouse in Pawleys Island', history: 'Caledonia Golf & Fish Club opened on January 1, 1994, as the first solo design of architect Mike Strantz, who had previously worked as a shaper for Tom Fazio. Built on a former rice plantation along the Waccamaw River in Pawleys Island, South Carolina, the property\'s centuries-old live oaks, colorful azaleas, and antebellum-style clubhouse immediately distinguished it from other Myrtle Beach area courses.\n\nStrantz was just 37 years old when Caledonia opened, and few people had heard of him. But his artistic approach to design -- he hand-sketched each of the 18 holes before construction began -- put him on the national map overnight. Caledonia was one of only nine courses Strantz completed before his tragic death from cancer in 2005 at the age of 50.\n\nThe course has been consistently ranked among the top public courses in America and the number one course in the Myrtle Beach area. Its intimate, garden-like atmosphere and Strantz\'s creative routing through marshland, moss-draped oaks, and rice plantation remnants create a golf experience unlike anything else on the Grand Strand.', signatureHoles: [{ hole: 2, par: 5, yardage: 568, description: 'A long par 5 that winds through towering oaks and demands three well-placed shots. The hole reveals Strantz\'s ability to create strategic challenge within the natural beauty of the plantation landscape.' }, { hole: 11, par: 3, yardage: 167, description: 'A scenic par 3 playing over water to a green surrounded by live oaks and Spanish moss. One of the most photographed holes on the course, it demands a precise mid-iron to a well-defended putting surface.' }, { hole: 14, par: 4, yardage: 390, description: 'A dogleg par 4 that plays through classic Lowcountry terrain. Marsh and water flank the hole, requiring accurate driving and a thoughtful approach to the green.' }, { hole: 18, par: 4, yardage: 390, description: 'Caledonia\'s most famous hole and one of the most celebrated finishing holes in the Southeast. The approach plays over marsh water to a green framed by the iconic plantation clubhouse and ancient oaks, creating a postcard finish.' }], whatToExpect: 'Caledonia is an intimate, garden-like golf experience that feels worlds apart from the typical Myrtle Beach resort course. At just 6,526 yards and par 70, it is not a brute, but Strantz\'s creative green complexes and strategic bunkering provide ample challenge for all skill levels. The course is immaculately conditioned and the Lowcountry setting -- with marsh views, live oaks, and abundant wildlife -- creates a serene atmosphere.\n\nThe arrival through the avenue of live oaks to the antebellum-style clubhouse sets the tone. Every hole has been described as a signature hole, and the pace of play tends to be relaxed, allowing golfers to savor the beauty of the property.', playingTips: 'Caledonia rewards accuracy over power. The course is short by modern standards, so leave the driver in the bag on many holes and focus on positioning. Strantz\'s greens have subtle contours that are more complex than they first appear, so reading the grain and slope carefully is essential.\n\nThe par-3 9th hole plays just 118 yards but is deceptively tricky with an elevated green. On the 18th, take a moment to enjoy the view before committing to your approach over the marsh -- club selection is critical on this signature finishing hole.', faqs: [{ question: 'Can anyone play Caledonia Golf & Fish Club?', answer: 'Yes. Caledonia is a public-access course, though tee times should be booked well in advance, especially during peak spring and fall seasons. Green fees typically range from $125 to $225.' }, { question: 'How does Caledonia compare to its sister course True Blue?', answer: 'Caledonia is the more refined and intimate of the two Strantz designs. True Blue is bolder and longer with massive waste bunkers, while Caledonia offers a gentler, more scenic experience routed through the plantation landscape.' }, { question: 'What is the best time of year to play Caledonia?', answer: 'Spring (March through May) and fall (September through November) offer the best combination of weather and course conditions. Summer can be hot and humid, while winter offers lower rates but dormant turf.' }, { question: 'Is Caledonia walkable?', answer: 'Caledonia is relatively flat and walkable, though most rounds are played with carts. The course layout follows a traditional routing that returns to the clubhouse after nine holes.' }] },
    { id: 'mb-2', name: 'True Blue Golf Club', slug: 'true-blue-golf-club', city: 'Myrtle Beach', state: 'South Carolina', type: 'public', rating: 4.6, greensFee: '$80–$165', architect: 'Mike Strantz', yearBuilt: 1998, holes: 18, par: 72, yardage: 7126, description: 'The bold, dramatic sibling of neighboring Caledonia, True Blue is another Mike Strantz creation that plays through marshland and maritime forest. Massive waste bunkers, forced carries, and wildly creative green complexes make every hole an adventure.', highlights: ['Mike Strantz bold, dramatic design', 'Massive waste bunkers and marsh carries', 'Sister course to Caledonia'], imageAlt: 'True Blue Golf Club dramatic waste bunker and marsh carry in Pawleys Island', history: 'True Blue Golf Club opened in February 1998 as Mike Strantz\'s fourth course design and the bold sibling to his acclaimed Caledonia Golf & Fish Club located just across the road in Pawleys Island. Where Caledonia was refined and intimate, True Blue was designed to be bigger, bolder, and more dramatic -- a full expression of Strantz\'s maverick design philosophy.\n\nStrantz built the course on a former indigo and rice plantation, using the sandy Lowcountry terrain to create massive waste bunkers, heroic forced carries over marsh, and fairways stretching 60 to 90 yards wide. The greens erupt out of sand barrens in dramatic fashion. Golf Digest praised the course for its heroic scale, noting that everything at True Blue is bigger and more adventurous than conventional designs.\n\nTrue Blue and Caledonia together represent perhaps the finest pair of public-access courses by a single architect anywhere in the country. Like Caledonia, True Blue stands as a lasting tribute to Strantz\'s artistic genius, attracting golfers from around the world to the Pawleys Island area.', signatureHoles: [{ hole: 1, par: 5, yardage: 571, description: 'True Blue throws you into the fire immediately. The opening hole is rated the hardest on the course -- a par 5 that demands three strong shots through sand barrens and marsh to reach the green.' }, { hole: 10, par: 5, yardage: 599, description: 'A massive 599-yard par 5 that horseshoes around a lake. Long hitters are tempted to cut the corner, but the water and sprawling waste bunkers punish miscalculations severely.' }, { hole: 14, par: 3, yardage: 186, description: 'A stunning par 3 playing over a vast sandy waste area to a green perched above the hazards. The visual intimidation is classic Strantz, demanding commitment and precise club selection.' }, { hole: 18, par: 4, yardage: 438, description: 'A strong finishing par 4 that requires a well-placed drive to set up an approach over water to the final green. The clubhouse looms behind, creating a dramatic stage for the closing hole.' }], whatToExpect: 'True Blue is big, bold, and visually dramatic. At 7,126 yards from the championship tees with massive waste bunkers and forced marsh carries, it looks intimidating, but the 60-to-90-yard-wide fairways provide generous landing areas off the tee. The challenge is primarily visual and in the approach shots, where Strantz\'s creative green complexes demand precision.\n\nThe course plays through a mix of marshland, maritime forest, and sandy terrain. Multiple tee options make it playable for all skill levels, and the experience is unlike anything else on the Grand Strand. Conditioning is typically excellent.', playingTips: 'Do not let the visual intimidation get into your head. The fairways are wider than they appear from the tee. Focus on the landing areas rather than the hazards. On approach shots, pay close attention to which side of the green the pin is located -- many greens have dramatic falloffs that make recovery difficult from the wrong side.\n\nPlay the correct tees for your ability. True Blue from the tips is a serious test, but the forward tees offer a much more enjoyable experience for mid-to-high handicappers. The waste bunkers are generally playable, so do not treat them like penalty areas.', faqs: [{ question: 'Is True Blue harder than Caledonia?', answer: 'True Blue is longer and more visually intimidating, but the wide fairways are forgiving off the tee. Caledonia is shorter but tighter. Most golfers find True Blue the bigger challenge from the back tees, but it plays fair from the forward tees.' }, { question: 'Can the public play True Blue?', answer: 'Yes. True Blue is a public-access course with green fees typically ranging from $80 to $165 depending on season and time of day.' }, { question: 'What are the waste bunkers like at True Blue?', answer: 'The waste bunkers are massive sandy expanses that define the visual character of the course. They are generally firm and playable, more like sandy ground than traditional sand traps.' }, { question: 'Can I play both True Blue and Caledonia in one day?', answer: 'Yes. The courses are directly across the road from each other and many golfers play both in a single day. Combo packages are often available through Caledonia Golf Vacations.' }] },
    { id: 'mb-3', name: 'TPC Myrtle Beach', slug: 'tpc-myrtle-beach', city: 'Myrtle Beach', state: 'South Carolina', type: 'public', rating: 4.4, greensFee: '$80–$150', architect: 'Tom Fazio', yearBuilt: 1999, holes: 18, par: 72, yardage: 6950, description: 'A Tom Fazio design built to TPC standards, this layout in Murrells Inlet delivers championship golf through Lowcountry wetlands and maritime forest. The polished conditioning and strategic layout offer a premium Myrtle Beach experience.', highlights: ['Tom Fazio TPC-standard design', 'Lowcountry wetland setting', 'Championship conditioning'], imageAlt: 'TPC Myrtle Beach Fazio fairway through maritime forest and wetlands', history: 'TPC Myrtle Beach opened in 1999, designed by Tom Fazio as part of the PGA Tour\\\'s Tournament Players Club network — the only TPC-branded course in the Myrtle Beach area. The course hosted the Senior PGA Tour Championship in 2000, won by Tom Watson.\n\nNow a member of Founders Group International and part of the Hammock Coast Golf Trail, TPC Myrtle Beach delivers championship conditioning and Fazio\\\'s masterful integration of Lowcountry wetlands, maritime forest, and native grasses. The course carries a formidable 144 slope from the tips.\n\nFairways are described as "plush as carpet" — Tour-caliber conditioning that feels private despite being open to the public.', signatureHoles: [{ hole: 17, par: 3, yardage: 193, description: 'The standout hole — a peninsula green that presents a formidable challenge and is considered the course\\\'s best. Accuracy is mandatory; anything missing the green faces a difficult recovery. Take enough club and commit to the shot.' }, { hole: 18, par: 5, yardage: 530, description: 'A risk-reward closer with water guarding the approach for those going for the green in two. The hole has decided many matches — weigh risk versus reward carefully on the second shot.' }, { hole: 5, par: 3, yardage: 158, description: 'The shortest hole but one of the most challenging. A deceptive par 3 with a difficult green complex that demands precise distance control despite the modest yardage.' }], whatToExpect: 'TPC Myrtle Beach weaves through forests of red oak and pine, around Lowcountry marshes and picturesque wetlands. Tom Fazio masterfully incorporated the natural landscape into every hole. The course feels private despite being open to the public.\n\nAt 6,950 yards with a 144 slope from the tips, this is a genuine championship test. MiniVerde bermuda greens are fast and challenging. The par 3s are the course\\\'s teeth — all four demand respect.\n\nConditioning is consistently praised as among the best on the Grand Strand. The TPC pedigree ensures professional-level maintenance standards.', playingTips: 'Choose tees carefully. The 144 slope from the tips is formidable. The white tees at 6,133 yards (138 slope) provide a strong but more enjoyable challenge for most golfers.\n\nThe par 3s are the course\\\'s defining holes. Respect all four — the 17th\\\'s peninsula green especially demands accuracy.\n\nOn the par-5 18th, water guards the green for those going for it in two. Unless you have a reliable long approach, lay up to a comfortable wedge distance.\n\nLowcountry afternoon winds can be a factor. Morning tee times typically offer calmer conditions.\n\nFairways are generous but the approach shots demand precision. Fast MiniVerde greens punish anything above the hole.', faqs: [{ question: 'Is TPC Myrtle Beach open to the public?', answer: 'Yes. Despite the TPC branding and private-club feel, it is open to daily-fee public play at $80-150. It is the only TPC-branded course in the Myrtle Beach area.' }, { question: 'Has it hosted professional events?', answer: 'Yes. The Senior PGA Tour Championship was held here in 2000, won by Tom Watson.' }, { question: 'Who designed it?', answer: 'Tom Fazio, one of America\\\'s most celebrated golf architects. The course was built to TPC Tour standards and opened in 1999.' }, { question: 'How tough is it?', answer: 'Very. The 144 slope from the tips ranks it among the most difficult public courses on the Grand Strand. The par 3s are particularly demanding.' }]},
    { id: 'mb-4', name: 'Barefoot Resort - Love Course', slug: 'barefoot-love-course', city: 'Myrtle Beach', state: 'South Carolina', type: 'resort', rating: 4.3, greensFee: '$65–$130', architect: 'Davis Love III', yearBuilt: 2000, holes: 18, par: 72, yardage: 7047, description: 'Part of the four-course Barefoot Resort complex, the Love Course is a Davis Love III design that brings a natural Lowcountry feel with live oak corridors, salt marsh edges, and classic Southern charm. It\'s one of four distinct architect designs at the resort.', highlights: ['Davis Love III Lowcountry design', 'Part of 4-course Barefoot Resort', 'Live oak and salt marsh setting'], imageAlt: 'Barefoot Resort Love Course through Lowcountry live oaks and marsh', history: 'The Love Course opened around 2000 as one of four championship layouts at Barefoot Resort, alongside courses by Greg Norman, Tom Fazio, and Pete Dye. Designed by Davis Love III — a Carolina native and active PGA Tour star — the course draws on Lowcountry golfing traditions with Pinehurst No. 2-inspired green complexes.\n\nGolf Digest ranked it No. 1 among the Top 50 Courses of Myrtle Beach in 2005, and it reached No. 53 on Golf Digest\\\'s America\\\'s 100 Greatest Public Courses in 2007. Barefoot Resort was named North America Golf Resort of the Year by IAGTO in 2017.\n\nThe Love Course is considered the most balanced of Barefoot\\\'s four layouts — generous off the tee but demanding on approaches.', signatureHoles: [{ hole: 5, par: 4, yardage: 400, description: 'Part of the spectacular holes 3-7 stretch that incorporates recreated ruins of an old plantation home, giving the sequence an atmospheric Lowcountry character unique on the Grand Strand.' }], whatToExpect: 'Wide, generous GN-1 hybrid fairways give confidence off the tee, but the real test comes on approaches to Champion UltraDwarf greens with subtle, Pinehurst-style runoffs. Rolling fairways, live oak corridors, salt marsh edges, and lush Lowcountry landscaping throughout.\n\nThe holes 3-7 stretch through recreated plantation ruins is the centerpiece. The course emphasizes approach-shot accuracy over raw distance — missing greens leaves difficult up-and-down situations with the crowned putting surfaces.\n\nPlays 5,249 to 7,006 yards across four tee sets, slope up to 141 from the tips.', playingTips: 'Focus on approach-shot accuracy rather than bombing drives. The generous landing areas forgive tee shots, but missing greens leaves difficult recovery situations.\n\nThe Pinehurst-style crowned greens shed anything that misses the surface. Favor the center of greens rather than chasing pins, especially on first visits.\n\nThe Love Course is considered the most fair and playable of Barefoot\\\'s four layouts — ideal for groups with mixed skill levels.', faqs: [{ question: 'How does the Love Course compare to Barefoot\\\'s other courses?', answer: 'It is considered the most balanced and playable of the four (Norman, Fazio, Dye, Love). Golf Digest ranked it No. 1 among Top 50 Myrtle Beach courses in 2005.' }, { question: 'Who designed it?', answer: 'Davis Love III, a Carolina native and PGA Tour star who cited Pinehurst No. 2 as inspiration for the challenging green complexes.' }, { question: 'What is the plantation ruins feature?', answer: 'Holes 3-7 incorporate recreated ruins of an old plantation home, giving the stretch an atmospheric Lowcountry character unique on the Grand Strand.' }]},
    { id: 'mb-5', name: 'Tidewater Golf Club', slug: 'tidewater-golf-club', city: 'Myrtle Beach', state: 'South Carolina', type: 'public', rating: 4.5, greensFee: '$70–$140', architect: 'Ken Tomlinson', yearBuilt: 1990, holes: 18, par: 72, yardage: 7044, description: 'Set on a peninsula between the Intracoastal Waterway and Cherry Grove inlet, Tidewater offers some of the most spectacular water views on the Grand Strand. Several holes play along bluffs overlooking the waterway, creating a coastal golf experience uncommon for Myrtle Beach.', highlights: ['Peninsula setting on Intracoastal Waterway', 'Bluff-top holes with panoramic water views', 'Top 5 public course on the Grand Strand'], imageAlt: 'Tidewater Golf Club bluff-top hole overlooking Intracoastal Waterway', history: 'Tidewater was designed by Ken Tomlinson — a Columbia, SC attorney with no formal architecture training — and built on a dramatic 600-acre peninsula along the Intracoastal Waterway. The course was nearly ready in fall 1989 when Hurricane Hugo struck, delaying the opening to 1990.\n\nUpon debut, both Golf Digest and Golf Magazine named it the best new public course in America. It remains Tomlinson\\\'s only publicly known course design, making his achievement remarkably unique in the history of golf architecture. A 2014 renovation rebuilt and resurfaced all greens with MiniVerde bermuda, restoring original contours.\n\nGolfweek rates it No. 7 among top public courses in South Carolina. The dramatic bluff-top and waterside holes have earned it the nickname "The Pebble Beach of the East."', signatureHoles: [{ hole: 4, par: 4, yardage: 410, description: '"Futch\\\'s Site" — considered perhaps the best par 4 in the Myrtle Beach area. A gentle dogleg left along Cherry Grove with beach views across the inlet. Beautiful and demanding in equal measure.' }, { hole: 3, par: 3, yardage: 175, description: '"Stranded" — a par 3 with deep bunkers and marsh threats along the left. One of eight holes that play along either Cherry Grove or the Intracoastal Waterway.' }, { hole: 13, par: 5, yardage: 540, description: 'The only par 5 in the Myrtle Beach area offering Atlantic Ocean views. A memorable three-shot hole where the scenery can distract from the strategic challenge.' }], whatToExpect: 'Eight holes play along either Cherry Grove or the Intracoastal Waterway, creating visuals often compared to Pebble Beach. Dramatic elevation changes and sweeping marsh views throughout. Water affects 15 of 18 holes.\n\nThe peninsula setting means wind is a constant factor — the exposed waterside holes can play very differently from day to day. The inland holes offer some relief but maintain strategic interest with tree-lined corridors.\n\nThe 2014 greens renovation with MiniVerde bermuda restored the course to top condition.', playingTips: 'Wind is the primary challenge given the exposed waterside setting. Check wind direction before every shot, especially on the bluff-top and marsh holes.\n\nClub selection on the par 3s is critical — the 12th ("Wishing Well") requires a carry over marshland where wind makes distance judgment very difficult.\n\nThe inland holes offer scoring opportunities between the dramatic waterside stretches. Take advantage of them.\n\nWater affects 15 of 18 holes. Know where the hazards are and play away from them.', faqs: [{ question: 'Why is Tidewater called the Pebble Beach of the East?', answer: 'Eight holes play along the Intracoastal Waterway and Cherry Grove inlet with dramatic bluff-top views comparable to coastal California golf. The peninsula setting creates one of the most scenic public courses in the Southeast.' }, { question: 'Who designed it?', answer: 'Ken Tomlinson, a Columbia SC attorney with no formal architecture training. Both Golf Digest and Golf Magazine named it best new public course in America when it opened in 1990. It remains his only known design.' }, { question: 'Was it affected by Hurricane Hugo?', answer: 'Yes. The course was nearly ready to open in fall 1989 when Hugo struck, delaying the opening to 1990.' }]},
    { id: 'mb-6', name: 'Dunes Golf & Beach Club', slug: 'dunes-golf-beach-club', city: 'Myrtle Beach', state: 'South Carolina', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Robert Trent Jones Sr.', yearBuilt: 1948, holes: 18, par: 72, yardage: 7165, description: 'The oldest and most prestigious club on the Grand Strand, Dunes Golf & Beach Club is a Robert Trent Jones Sr. design that hosted PGA Tour events for decades. The famous "Waterloo" par-5 13th — a dramatic dogleg around Lake Singleton — is one of the most iconic holes on the East Coast.', highlights: ['Robert Trent Jones Sr. classic design', 'Famous "Waterloo" 13th hole', 'Most prestigious club on the Grand Strand'], imageAlt: 'Dunes Golf & Beach Club iconic Waterloo hole at Lake Singleton in Myrtle Beach', history: 'The Dunes Golf and Beach Club was incorporated in May 1948, making it the oldest and most prestigious golf club on the Grand Strand. A then little-known architect named Robert Trent Jones Sr. was commissioned to design the layout on sandy, rolling terrain perfectly suited for golf. The Dunes became one of Jones\'s first nationally acclaimed solo designs and helped launch his legendary career.\n\nThe club hosted PGA Tour events for decades and returned to the national stage as the venue for the Myrtle Beach Classic beginning in 2024. Rees Jones, Robert Trent Jones Sr.\'s son, completed a renovation in 2013 that modernized the greens and bunkers while honoring his father\'s original design intent.\n\nThe Dunes is best known for its par-5 13th hole, nicknamed "Waterloo," a dramatic dogleg around Lake Singleton that has been selected as one of the most memorable holes in American golf.', signatureHoles: [{ hole: 9, par: 4, yardage: 410, description: 'A challenging par 4 along the dunes with an elevated, well-protected green and Jones\'s trademark bunkering.' }, { hole: 13, par: 5, yardage: 590, description: 'The legendary "Waterloo" hole. This dramatic dogleg wraps around Lake Singleton, tempting long hitters to cut the corner over water.' }, { hole: 16, par: 3, yardage: 175, description: 'A demanding par 3 to a well-guarded green. The tee shot must carry bunkers to find the putting surface.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finishing hole that demands two quality shots, with the clubhouse gallery watching.' }], whatToExpect: 'The Dunes is a classic Robert Trent Jones Sr. design on sandy, rolling terrain providing a championship-caliber test. At over 7,100 yards from the tips with a slope of 148, it is one of the most demanding courses in the area. Each hole has unique character, with Jones\'s deep bunkers and strategic water hazards creating compelling risk-reward decisions.\n\nThe Rees Jones renovation features modern green complexes honoring the original design. The facility includes beach and social amenities befitting the Grand Strand\'s most prestigious club.', playingTips: 'Course management is critical. Jones designed the course to reward strategic thinking over raw power. On the 13th "Waterloo" hole, resist cutting too much corner over Lake Singleton -- the safe play still leaves a manageable approach.\n\nThe greens are large and undulating, so landing on the correct portion is essential. The deep bunkers are the primary defense -- keeping the ball out of them should be a priority.', faqs: [{ question: 'Can the public play Dunes Golf & Beach Club?', answer: 'The Dunes is a private club, but limited public access is available through certain Myrtle Beach golf packages and resort partnerships.' }, { question: 'What makes the 13th hole "Waterloo" so famous?', answer: 'The par-5 13th dramatically doglegs around Lake Singleton, creating one of golf\'s great risk-reward decisions. It is ranked among the most memorable holes in American golf.' }, { question: 'Has the PGA Tour played at The Dunes?', answer: 'Yes. The Dunes hosted PGA Tour events for decades and returned to the schedule as the venue for the Myrtle Beach Classic beginning in 2024.' }, { question: 'Who renovated The Dunes?', answer: 'Rees Jones, son of original designer Robert Trent Jones Sr., completed a renovation in 2013 honoring the original design.' }] },
    { id: 'mb-7', name: 'Grande Dunes Resort Club', slug: 'grande-dunes-resort', city: 'Myrtle Beach', state: 'South Carolina', type: 'resort', rating: 4.3, greensFee: '$75–$140', architect: 'Roger Rulewich', yearBuilt: 2001, holes: 18, par: 72, yardage: 7018, description: 'A Roger Rulewich design along the Intracoastal Waterway, Grande Dunes offers upscale resort golf with waterway views from several elevated tees. The layout features well-conditioned Bermuda fairways, bold bunkering, and one of the best practice facilities on the Grand Strand.', highlights: ['Intracoastal Waterway setting', 'Roger Rulewich strategic design', 'Upscale resort experience'], imageAlt: 'Grande Dunes Resort fairway with Intracoastal Waterway views in Myrtle Beach', history: 'Grande Dunes Resort Club opened in 2001, designed by Roger Rulewich — a longtime associate of Robert Trent Jones Sr. The course sits on elevated terrain with a high bluff overlooking the Intracoastal Waterway, providing dramatic views from seven holes along the waterway.\n\nNamed "National Golf Course of the Year" by the National Golf Course Owners Association in 2009, and voted Myrtle Beach\\\'s second-best course by area PGA professionals. The course underwent a greens and bunker renovation in summer 2022, installing Champion bermuda greens.\n\nRanked among Golf Digest\\\'s America\\\'s 100 Greatest Public Courses. PGA Magazine called it one of the great golf clubs in the world. Grande Dunes serves as the home course for Coastal Carolina University athletics.', signatureHoles: [{ hole: 4, par: 5, yardage: 566, description: 'A dogleg right with water running tee to green. Long hitters can go for the green in two with little margin for error — the water punishes any miss. The quintessential risk-reward hole.' }, { hole: 16, par: 4, yardage: 420, description: 'Features one of the most daunting tee shots on the course plus a diagonally angled, two-tiered green stretching 57 yards deep. Being on the wrong tier leaves an extremely difficult two-putt.' }], whatToExpect: 'Seven holes play along the Intracoastal Waterway on elevated bluffs, forming the course\\\'s most dramatic stretch. Expansive bermuda fairways with subtle undulations lead to large, modestly contoured Champion bermuda greens (renovated 2022).\n\nThe waterway holes provide stunning visual drama, but the inland holes are equally strategic and challenging. A 10,000-square-foot Mediterranean-styled clubhouse overlooks the 9th and 18th greens.\n\nAt 7,018 yards with bold Rulewich bunkering and waterway exposure, this is an upscale resort experience that plays like a private club.', playingTips: 'On Hole 4, an aggressive tee shot opens a two-shot opportunity, but water from tee to green punishes any miss severely. Know your carry distance before going for it.\n\nHole 16\\\'s two-tiered green stretches 57 yards deep. Landing on the wrong tier virtually guarantees a three-putt. Check the pin sheet and aim for the correct level.\n\nSeveral greens are deeper than they are wide — precise distance control matters more than direction on many approaches.\n\nThe waterway holes are exposed to wind. Factor it into every club selection along the bluff.', faqs: [{ question: 'Who designed Grande Dunes?', answer: 'Roger Rulewich, a longtime associate of Robert Trent Jones Sr. The course opened in 2001 and was renovated (greens and bunkers) in 2022.' }, { question: 'How is it ranked?', answer: 'Named National Golf Course of the Year (2009). Ranked among Golf Digest\\\'s 100 Greatest Public Courses. PGA Magazine called it one of the great golf clubs in the world.' }, { question: 'Is it a public course?', answer: 'Yes — resort/public access at $75-140. Despite the upscale feel, tee times are available to the public.' }]},
    { id: 'mb-8', name: 'Pawleys Plantation Golf & Country Club', slug: 'pawleys-plantation', city: 'Myrtle Beach', state: 'South Carolina', type: 'public', rating: 4.2, greensFee: '$55–$110', architect: 'Jack Nicklaus', yearBuilt: 1988, holes: 18, par: 72, yardage: 7026, description: 'A Jack Nicklaus Signature design in Pawleys Island, this course plays through centuries-old live oaks, salt marshes, and along historic rice plantation canals. Several holes border the marsh with expansive Lowcountry views.', highlights: ['Jack Nicklaus Signature design', 'Historic rice plantation setting', 'Lowcountry marsh and live oak corridors'], imageAlt: 'Pawleys Plantation Nicklaus fairway through live oaks and salt marsh', history: 'Pawleys Plantation opened in 1988 as Jack Nicklaus\\\'s first signature design in the greater Myrtle Beach area, built on the grounds of a former rice plantation. Nicklaus returned in fall 2018 to celebrate the course\\\'s 30th anniversary.\n\nThe layout winds through centuries-old marshlands, live oaks draped in Spanish moss, tidal creeks, and historic rice plantation canals — authentic Lowcountry terrain that predates the golf course by centuries. Part of both the Waccamaw Golf Trail and Hammock Coast Golf Trail.\n\nNicklaus designed each of the 18 holes with a distinct strategy, using green placement, water, tree lines, traps, mounds, and split fairways to create variety throughout.', signatureHoles: [{ hole: 13, par: 3, yardage: 149, description: 'Shares a spectacular 12,800-square-foot double green with the 16th hole — one of only two holes on the course sharing a putting surface. A rare Nicklaus design feature that creates a memorable strategic element.' }, { hole: 14, par: 5, yardage: 528, description: 'Features a peninsula cut across marsh for aggressive players attempting to reach in two. The marsh carry on the second shot is genuinely intimidating — consider your ability honestly before attempting it.' }, { hole: 2, par: 4, yardage: 452, description: 'The No. 1 handicap hole — a long, demanding par 4 early in the round with an undulating green. Sets the tone for the challenge ahead.' }], whatToExpect: 'Quintessential Lowcountry golf through centuries-old live oaks, salt marshes, and tidal creeks on authentic rice plantation grounds. Each hole has a distinct Nicklaus-designed strategy with varying shot shapes, hazard placement, and green complexes.\n\nThe smallest green (Hole 9) sits atop a ridge; the largest (Hole 8) is surrounded by hollows. The rare double green shared by holes 13 and 16 adds a unique strategic element. Moss-draped oaks and salt marsh views throughout.\n\nAt 7,026 yards from the tips, the course provides a genuine championship test while remaining very playable from the forward tees.', playingTips: 'Hole 5 demands precise tee shot placement — water crosses the fairway, and missing the landing area forces a layup.\n\nOn the par-5 14th, honestly assess your ability before attempting the marsh carry on the second shot. A smart layup leaves a comfortable approach.\n\nWind on the marsh holes (especially 13 and 16 around the double green) dictates club selection significantly.\n\nHole 9\\\'s tiny ridgetop green demands a precise short iron. An oak tree in the fairway also complicates the tee shot — plan your line carefully.', faqs: [{ question: 'What is the double green?', answer: 'Holes 13 (par 3) and 16 (par 4) share a spectacular 12,800-square-foot putting surface — a rare design feature even for Nicklaus courses.' }, { question: 'Is it built on an actual plantation?', answer: 'Yes. The course sits on authentic former rice plantation grounds with centuries-old landscape features — marshlands, live oaks, tidal creeks, and historic canals — still intact.' }, { question: 'Who designed Pawleys Plantation?', answer: 'Jack Nicklaus — his first signature design in the greater Myrtle Beach area, opened in 1988. Nicklaus returned for the 30th anniversary celebration in 2018.' }]},
  ],
  'hilton-head-south-carolina': [
    { id: 'hh-1', name: 'Harbour Town Golf Links', slug: 'harbour-town-golf-links-hh', city: 'Hilton Head', state: 'South Carolina', type: 'resort', rating: 4.8, greensFee: '$200–$375', architect: 'Pete Dye & Jack Nicklaus', yearBuilt: 1969, holes: 18, par: 71, yardage: 7099, description: 'Home of the RBC Heritage on the PGA Tour, Harbour Town is one of the most iconic courses in America. Pete Dye\'s tight, tree-lined layout demands precision over power, and the lighthouse finish at the 18th green on Calibogue Sound is one of golf\'s most recognizable images.', highlights: ['RBC Heritage PGA Tour host', 'Iconic lighthouse at 18th green', 'Pete Dye & Jack Nicklaus collaboration'], imageAlt: 'Harbour Town Golf Links iconic lighthouse and 18th green on Calibogue Sound', history: 'Harbour Town Golf Links was designed by Pete Dye with consultation from a young Jack Nicklaus and opened in 1969 at Sea Pines Resort on Hilton Head Island. The first Heritage Classic was held that same year, won by Arnold Palmer, establishing the tournament that continues today as the RBC Heritage.\n\nThe course challenged conventional wisdom that Tour courses needed to be over 7,000 yards. Harbour Town remains one of the shortest on the PGA Tour schedule, yet its tight live-oak corridors, small greens, and Calibogue Sound winds make it one of the most demanding. The iconic red-and-white lighthouse behind the 18th green is one of the most recognizable landmarks in golf.', signatureHoles: [{ hole: 18, par: 4, yardage: 472, description: 'One of the most iconic finishing holes in golf. The fairway runs along Calibogue Sound with the approach playing to a green at the base of the famous striped lighthouse.' }, { hole: 17, par: 3, yardage: 192, description: 'A beautiful par 3 over a marshy waste area to a green guarded by Calibogue Sound on the left. Wind off the water makes club selection tricky.' }, { hole: 9, par: 4, yardage: 338, description: 'A short but devious par 4 with a narrow fairway pinched by towering live oaks and a tiny, heavily bunkered green.' }, { hole: 15, par: 5, yardage: 541, description: 'The longest and most difficult hole on the course. A tight, tree-lined par 5 with a well-defended green that makes birdie hard-earned.' }], whatToExpect: 'Harbour Town is a shotmaker\'s course where accuracy trumps distance. The fairways are narrow corridors through ancient live oaks draped in Spanish moss, with overhanging branches that restrict trajectory. The greens are among the smallest on the PGA Tour.\n\nThe final holes along Calibogue Sound bring wind and water into play, and the iconic lighthouse at 18 provides a memorable finish.', playingTips: 'Leave the driver in the bag on many holes. Accuracy off the tee is far more important than distance. A 3-wood or hybrid will keep you in play and set up better angles into the small greens.\n\nWind off Calibogue Sound intensifies on the back nine, particularly on holes 17 and 18. Take extra club and aim for green centers.', faqs: [{ question: 'Can non-resort guests play Harbour Town?', answer: 'Yes, though Sea Pines Resort guests receive preferred tee times. Green fees range from $200 to $400 depending on season.' }, { question: 'Why is Harbour Town so short compared to other Tour courses?', answer: 'At approximately 7,200 yards for Tour events, it is one of the shortest on the schedule. But tight fairways, small greens, overhanging trees, and coastal winds make it play much harder than the yardage suggests.' }, { question: 'When is the RBC Heritage played?', answer: 'The RBC Heritage is typically held in April, the week after the Masters.' }, { question: 'Can I see the lighthouse up close?', answer: 'Yes. The Harbour Town Lighthouse is open to the public with panoramic views of Calibogue Sound and the 18th hole.' }] },
    { id: 'hh-2', name: 'Atlantic Dunes by Davis Love III', slug: 'atlantic-dunes-hilton-head', city: 'Hilton Head', state: 'South Carolina', type: 'resort', rating: 4.5, greensFee: '$100–$200', architect: 'Davis Love III', yearBuilt: 2015, holes: 18, par: 72, yardage: 6781, description: 'A complete Davis Love III reimagining of the old Ocean Course at Sea Pines, Atlantic Dunes embraces a natural, links-inspired aesthetic with sandy waste areas, dune ridges, and ocean breezes. The redesign was acclaimed as one of the best renovations in the country.', highlights: ['Davis Love III acclaimed renovation', 'Links-inspired dune and sand aesthetic', 'Sea Pines resort setting'], imageAlt: 'Atlantic Dunes links-style fairway through dune ridges at Sea Pines Hilton Head', history: 'Opened in 2015 as Davis Love III\'s reimagining of Sea Pines\' former Ocean Course. The links-inspired redesign with sandy waste areas and dune ridges was acclaimed nationally.', signatureHoles: [{ hole: 3, par: 4, yardage: 390, description: 'Strategic par 4 through natural dune ridges.' }, { hole: 10, par: 3, yardage: 175, description: 'Beautiful links-inspired par 3.' }, { hole: 15, par: 5, yardage: 535, description: 'Risk-reward par 5 through the dunes.' }, { hole: 18, par: 4, yardage: 420, description: 'Strong finisher with dune ridges framing the approach.' }], whatToExpect: 'Links-inspired resort course with sandy waste areas, dune ridges, and ocean breezes. At 6,781 yards, a unique Lowcountry experience.', playingTips: 'Sandy waste areas are playable but tricky. Ocean breezes affect every shot. Bump-and-run approaches work well.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Resort course at Sea Pines, $100-$200.' }, { question: 'Previous course?', answer: 'The Ocean Course at Sea Pines, reimagined by Love III in 2015.' }] },
    { id: 'hh-3', name: 'Haig Point Club', slug: 'haig-point-club', city: 'Hilton Head', state: 'South Carolina', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Rees Jones', yearBuilt: 1986, holes: 18, par: 72, yardage: 7016, description: 'Located on Daufuskie Island accessible only by ferry, Haig Point offers one of the most secluded private golf experiences on the East Coast. The Rees Jones design plays through maritime forest and along the Intracoastal Waterway with views toward Savannah.', highlights: ['Ferry-access island course on Daufuskie', 'Rees Jones maritime forest design', 'Secluded Lowcountry private club'], imageAlt: 'Haig Point Club Daufuskie Island hole through maritime forest and waterway', history: 'Haig Point Club occupies 1,050 acres on Daufuskie Island, South Carolina, accessible only by ferry. International Paper developed the property in the mid-1980s and hired Rees Jones to build the course, which opened in 1987. Jones had free rein routing what he called one of the most spectacular pieces of ground in the Lowcountry.\n\nJones returned in 2007 to restore greens and sharpen the course. The renovation modernized playing surfaces while preserving the routing through maritime forest and along the waterways.\n\nThe island setting makes Haig Point one of the most secluded golf experiences on the East Coast, combining Rees Jones golf with a beach club, tennis, equestrian center, and fine dining.', signatureHoles: [{ hole: 3, par: 4, yardage: 410, description: 'A par 4 through maritime forest with Intracoastal Waterway views.' }, { hole: 9, par: 4, yardage: 430, description: 'A strong front-nine closer with waterway views and strategic bunkering.' }, { hole: 15, par: 3, yardage: 185, description: 'A scenic par 3 with views toward Savannah. Coastal breeze makes club selection critical.' }, { hole: 18, par: 4, yardage: 445, description: 'A demanding finisher through maritime forest to a well-defended green.' }], whatToExpect: 'The ferry ride to Daufuskie Island separates you from the mainland, and the maritime forest routing provides complete seclusion. Views of the Intracoastal Waterway and toward Savannah appear throughout.\n\nThe Rees Jones design at over 7,000 yards is a serious test with Lowcountry breezes adding an extra dimension.', playingTips: 'Coastal breezes are constant. Waterway holes are exposed and play differently depending on wind direction.\n\nBermuda greens are firm and grainy. Read the grain carefully as it affects both speed and break.', faqs: [{ question: 'Can the public play?', answer: 'No. Haig Point is private, accessible only to members and guests.' }, { question: 'How do you get there?', answer: 'By ferry only. There are no bridges to Daufuskie Island.' }, { question: 'Who designed it?', answer: 'Rees Jones in 1987, with a renovation in 2007.' }, { question: 'Where is Daufuskie Island?', answer: 'Between Hilton Head, SC and Savannah, GA in the Intracoastal Waterway.' }] },
    { id: 'hh-4', name: 'Palmetto Dunes - Robert Trent Jones Course', slug: 'palmetto-dunes-rtj', city: 'Hilton Head', state: 'South Carolina', type: 'resort', rating: 4.4, greensFee: '$80–$170', architect: 'Robert Trent Jones Sr.', yearBuilt: 1969, holes: 18, par: 72, yardage: 6710, description: 'The flagship course at Palmetto Dunes Resort, this Robert Trent Jones Sr. design features oceanfront holes, lagoon carries, and classic Jones strategic bunkering. The ocean-side 10th hole is one of the most scenic on Hilton Head.', highlights: ['Robert Trent Jones Sr. oceanfront design', 'Iconic ocean-side 10th hole', 'Part of 3-course Palmetto Dunes resort'], imageAlt: 'Palmetto Dunes RTJ oceanfront hole on Hilton Head Island', history: 'The Robert Trent Jones Course at Palmetto Dunes opened in 1969 as one of the earliest resort courses on Hilton Head Island, designed by Robert Trent Jones Sr. with Roger Rulewich assisting. It is a Certified Audubon Cooperative Sanctuary and part of the three-course Palmetto Dunes Oceanfront Resort (alongside Arthur Hills and George Fazio designs).\n\nThe course is home to one of only two oceanfront holes on all of Hilton Head Island — the iconic 10th hole with panoramic Atlantic Ocean views from its elevated green. Recognized among Golfweek\\\'s Best Courses You Can Play in South Carolina (2024).\n\nAs one of Jones Sr.\\\'s resort designs, the layout emphasizes wide fairways, strategic bunkering, and engaging lagoon carries rather than raw difficulty.', signatureHoles: [{ hole: 10, par: 5, yardage: 550, description: 'The crown jewel — one of only two oceanfront holes on all of Hilton Head Island. A straightaway par 5 typically playing into prevailing winds, with panoramic Atlantic Ocean views from the elevated green. Three solid shots are required. The ocean vistas from this green are among the most memorable in Southeast golf.' }], whatToExpect: 'Wide fairways, expansive greens, strategic Jones bunkering, and subtle mounding throughout. The shifting ocean winds make every hole play differently from day to day, adding a links-like element to the resort experience.\n\nThe course plays 6,710 yards from the tips with a slope up to 141. GPS-equipped carts with Visage systems help with distance management. The oceanfront 10th hole is the undisputed highlight — plan to pause and enjoy the view.\n\nPalmetto Dunes offers free Monday golf exhibitions at 4 p.m. — a nice bonus for resort guests.', playingTips: 'The 10th hole typically plays into prevailing wind. Club up and plan for three solid shots rather than forcing a heroic second shot to the oceanfront green.\n\nWind management is the primary challenge across the entire course. The ocean exposure means conditions shift constantly — check wind direction before every shot.\n\nThe wide fairways are forgiving off the tee. Focus on managing approach distances in the wind rather than worrying about finding the fairway.\n\nThe Jones bunkering is strategic rather than penal. Avoid the fairway bunkers in the landing zones and you\\\'ll have clean approaches.', faqs: [{ question: 'What makes the 10th hole special?', answer: 'It is one of only two oceanfront holes on all of Hilton Head Island. The par 5 features panoramic Atlantic Ocean views from its elevated green — one of the most memorable holes in Southeast golf.' }, { question: 'Who designed the course?', answer: 'Robert Trent Jones Sr. with Roger Rulewich assisting. It opened in 1969 as one of the earliest resort courses on Hilton Head Island.' }, { question: 'How many courses does Palmetto Dunes have?', answer: 'Three — Robert Trent Jones, Arthur Hills, and George Fazio designs. The RTJ course is the only one that does not offer a 9-hole rate, as the signature oceanfront 10th is on the back nine.' }, { question: 'Is it environmentally certified?', answer: 'Yes. The course is a Certified Audubon Cooperative Sanctuary.' }]},
    { id: 'hh-5', name: 'Colleton River Club - Nicklaus Course', slug: 'colleton-river-nicklaus', city: 'Hilton Head', state: 'South Carolina', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 1999, holes: 18, par: 72, yardage: 7168, description: 'One of the finest private courses in the Lowcountry, Colleton River\'s Nicklaus Course winds through stunning marsh and river settings on the mainland adjacent to Hilton Head. Jack Nicklaus routed the layout to maximize views of the Colleton River and surrounding wetlands.', highlights: ['Jack Nicklaus Lowcountry masterwork', 'Colleton River and marsh setting', 'Top-rated Hilton Head private club'], imageAlt: 'Colleton River Club Nicklaus Course marsh hole with river views', history: 'Colleton River Club\\\'s Nicklaus Course was named Golf Digest\\\'s "Best New Private Course in America" in 1993. The 36-hole private community features both a Nicklaus course and a Pete Dye course, plus a six-hole par-3 course, on the banks of the Colleton River amid Lowcountry marsh and maritime forest.\n\nThe Nicklaus course underwent a significant renovation in Fall 2017. It has been recognized as a Top 100 residential course and is consistently ranked among the finest private courses in the Lowcountry. Water comes into play on 12 of 18 holes, with the back nine\\\'s marsh and river views especially dramatic.', signatureHoles: [{ hole: 16, par: 4, yardage: 420, description: 'The acknowledged signature hole — plays directly toward the Colleton River with dramatic marsh and water views framing the approach. The setting is quintessential Lowcountry golf at its finest.' }, { hole: 18, par: 4, yardage: 440, description: 'Part of a celebrated finishing stretch along the Colleton River. The closing holes are consistently praised as among the finest in the Lowcountry — a dramatic conclusion with river views throughout.' }], whatToExpect: 'Tree-lined fairways with large, firm, fast greens through Lowcountry marsh and maritime forest. Water on 12 of 18 holes. The back nine runs along the Colleton River with constant marsh and river views.\n\nThe tidal marshland creates both visual drama and strategic challenge — wind off the river and marsh can shift significantly throughout a round.\n\nAccess is strictly private. The community also features a Pete Dye course, giving members two elite options on the same property.', playingTips: 'Greens are hard and fast — precise club selection on approaches is critical. Favor below-the-hole positions.\n\nPosition off the tee matters more than distance given the 12 water holes. Play away from the marsh.\n\nWind off the river shifts throughout the day. Factor it into every club choice on the riverside holes.\n\nThe back nine is where the drama and difficulty peak. Build your score on the front nine.', faqs: [{ question: 'How was the Nicklaus Course received?', answer: 'Golf Digest named it Best New Private Course in America (1993). It remains a Top 100 residential course.' }, { question: 'How many courses does Colleton River have?', answer: 'Two full 18-hole courses (Nicklaus and Pete Dye) plus a six-hole par-3 course — 42 holes total on the property.' }, { question: 'Can the public play?', answer: 'No. Colleton River is a private community. Access requires membership or a member invitation.' }]},
    { id: 'hh-6', name: 'Palmetto Hall - Arthur Hills Course', slug: 'palmetto-hall-hills', city: 'Hilton Head', state: 'South Carolina', type: 'semi-private', rating: 4.2, greensFee: '$65–$120', architect: 'Arthur Hills', yearBuilt: 1991, holes: 18, par: 72, yardage: 6918, description: 'An Arthur Hills design in the gated Palmetto Hall Plantation, this course features dramatic elevation changes uncommon for the Lowcountry, with rolling fairways through towering pines and hardwoods. The semi-private format makes it one of the best accessible courses on the island.', highlights: ['Unusual Lowcountry elevation changes', 'Arthur Hills pine and hardwood design', 'Best semi-private value on Hilton Head'], imageAlt: 'Palmetto Hall Arthur Hills rolling pine-lined fairway on Hilton Head Island', history: 'Opened in 1991 within the gated Palmetto Hall Plantation on Hilton Head Island, designed by Arthur Hills. The course features unusual elevation changes for the Lowcountry through towering pines and hardwoods.', signatureHoles: [{ hole: 5, par: 4, yardage: 420, description: 'A demanding par 4 using the unusual elevation changes.' }, { hole: 11, par: 3, yardage: 185, description: 'A scenic par 3 through the pines.' }, { hole: 15, par: 5, yardage: 540, description: 'A risk-reward par 5 with rolling terrain.' }, { hole: 18, par: 4, yardage: 430, description: 'A strong finisher through the tree-lined corridor.' }], whatToExpect: 'Unusual Lowcountry elevation changes through towering pines. At 6,918 yards, a solid test with semi-private accessibility.\n\nOne of the best values on Hilton Head Island.', playingTips: 'The elevation changes affect club selection more than typical Lowcountry courses.\n\nPine corridors demand accuracy off the tee.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Semi-private, $65-$120.' }, { question: 'What makes it unusual for Hilton Head?', answer: 'Dramatic elevation changes uncommon for the flat Lowcountry.' }] },
    { id: 'hh-7', name: 'May River Golf Club', slug: 'may-river-golf-club-hh', city: 'Hilton Head', state: 'South Carolina', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 2004, holes: 18, par: 72, yardage: 7171, description: 'Part of the Montage Palmetto Bluff resort, May River is a Jack Nicklaus design that plays through ancient live oaks, Spanish moss, and along the May River in Bluffton. The course is considered one of the finest in the Lowcountry, with an intimate, secluded atmosphere.', highlights: ['Jack Nicklaus at Montage Palmetto Bluff', 'May River and live oak setting', 'Among the finest courses in the Lowcountry'], imageAlt: 'May River Golf Club live oak-draped fairway along the May River in Bluffton', history: 'May River Golf Club opened in 2004 within the 20,000-acre Palmetto Bluff community in Bluffton, designed by Jack Nicklaus as a Signature Course (meaning Nicklaus personally oversaw every design aspect). Named South Carolina\\\'s "Best New Course" the year it opened.\n\nThe course winds through centuries-old live oaks and along the banks of the May River, routing through four distinct forest types: upland pine, maritime, live oaks, and hardwood — each stretch has a unique character. The setting is serene and feels immersed in nature rather than carved from it.\n\nPalmetto Bluff is expanding its golf offerings with a Coore & Crenshaw course (expected to open in late 2025/early 2026). Access is available to guests staying at Montage Palmetto Bluff.', signatureHoles: [{ hole: 14, par: 4, yardage: 420, description: 'One of several holes that brush directly along the May River banks, with ancient 300-year-old live oaks framing the fairway and creating cathedral-like corridors. The river views and natural beauty make this stretch unforgettable.' }], whatToExpect: 'Wide, inviting fairways wind past 300-year-old live oaks and gently undulating Lowcountry terrain. The course uses Eco turf and feels immersed in nature. Despite the generous fairways, the greens provide the real defense — more complex than they first appear.\n\nThe routing through four forest types means each stretch of the course has a distinct character and visual identity. Wind off the May River affects exposed holes.\n\nAccess is available to Montage Palmetto Bluff resort guests, making it one of the few ultra-premium Nicklaus Signature courses accessible without a membership.', playingTips: 'The generous fairways reward accuracy over power. Keep the ball in position for the best approach angles to the greens.\n\nThe greens are the real defense — they look simple but the undulations are more complex than they first appear. Read carefully.\n\nWind off the May River affects the river-adjacent holes. Factor it into every club choice on exposed holes.\n\nEnjoy the setting. The 300-year-old live oaks and river views are why people travel here — don\\\'t rush the experience.', faqs: [{ question: 'Can non-members play May River?', answer: 'Yes — guests staying at Montage Palmetto Bluff have access. It is one of the few ultra-premium Nicklaus Signature courses available through a resort stay.' }, { question: 'Who designed it?', answer: 'Jack Nicklaus as a Signature Course (personally overseeing every aspect). It opened in 2004 and was named South Carolina\\\'s Best New Course.' }, { question: 'What is Palmetto Bluff?', answer: 'A 20,000-acre private community in Bluffton featuring the Montage resort, centuries-old live oaks, and soon three golf courses (Nicklaus, Coore-Crenshaw, and Anson).' }]},
    { id: 'hh-8', name: 'Oldfield Golf Club', slug: 'oldfield-golf-club', city: 'Hilton Head', state: 'South Carolina', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Greg Norman', yearBuilt: 2002, holes: 18, par: 72, yardage: 7019, description: 'A Greg Norman design on the Okatie River in Okatie near Hilton Head, Oldfield occupies a stunning riverfront setting with expansive marsh views. The layout weaves through live oaks and along the river, offering a peaceful, naturalistic Lowcountry golf experience.', highlights: ['Greg Norman riverfront design', 'Okatie River and marsh views', 'Peaceful Lowcountry private club'], imageAlt: 'Oldfield Golf Club marsh and river setting near Hilton Head', history: 'Opened in 2002 on the Okatie River near Hilton Head, designed by Greg Norman. The riverfront setting with expansive marsh views creates a naturalistic Lowcountry experience through live oaks and along the river.', signatureHoles: [{ hole: 6, par: 4, yardage: 415, description: 'A scenic par 4 along the Okatie River with marsh views.' }, { hole: 11, par: 3, yardage: 180, description: 'A beautiful par 3 with river and marsh backdrop.' }, { hole: 15, par: 5, yardage: 535, description: 'A river-side par 5 with risk-reward options.' }, { hole: 18, par: 4, yardage: 430, description: 'A strong finishing hole with marsh views.' }], whatToExpect: 'Greg Norman design on the Okatie River with expansive marsh views through live oaks. At 7,019 yards, peaceful and naturalistic.\n\nA serene Lowcountry private club experience.', playingTips: 'River breezes affect shots on exposed holes. The marsh and river are out of bounds on several holes.', faqs: [{ question: 'Can the public play?', answer: 'No. Private club.' }, { question: 'Designer?', answer: 'Greg Norman, opened 2002.' }] },
  ],
  'las-vegas-nevada': [
    { id: 'lv-1', name: 'Shadow Creek', slug: 'shadow-creek', city: 'Las Vegas', state: 'Nevada', type: 'resort', rating: 4.9, greensFee: '$600–$750', architect: 'Tom Fazio', yearBuilt: 1989, holes: 18, par: 72, yardage: 7560, description: 'The most exclusive and expensive resort course in Las Vegas, Shadow Creek is a Tom Fazio creation built in the desert for Steve Wynn at a rumored cost of $60 million. The lush, parkland-style layout — complete with transplanted trees, creeks, and waterfalls — feels impossibly out of place in the Mojave Desert and is universally ranked as the best course in Nevada.', highlights: ['Best course in Nevada — $60M construction cost', 'Lush parkland oasis in the Mojave Desert', 'Exclusive MGM Resorts guests-only access'], imageAlt: 'Shadow Creek lush parkland fairway and waterfall in the Las Vegas desert', history: 'Shadow Creek was built by casino mogul Steve Wynn in 1989-1990, with Tom Fazio designing a lush parkland course in the flat Mojave Desert north of the Las Vegas Strip at an estimated cost of $60 million. Over 21,000 mature trees were transplanted and an elaborate system of creeks, waterfalls, and elevation changes was sculpted from barren desert floor.\n\nNow operated by MGM Resorts, Fazio completed a renovation in 2008 stretching the layout to 7,560 yards. Shadow Creek hosted the 2020 CJ Cup on the PGA Tour and the 2018 Tiger vs. Phil pay-per-view match. It is consistently ranked the best course in Nevada.', signatureHoles: [{ hole: 17, par: 3, yardage: 130, description: 'A short but spectacular par 3 to an island-like green surrounded by a creek and framed by waterfalls and transplanted pines.' }, { hole: 3, par: 4, yardage: 449, description: 'The longest par 4, featuring an uphill tee shot and demanding approach through a corridor of pines with a creek guarding the green.' }, { hole: 15, par: 4, yardage: 433, description: 'A beautiful dogleg with water in play on the approach. The green is framed by a waterfall creating one of the most photographed settings on the course.' }, { hole: 18, par: 4, yardage: 440, description: 'A dramatic finishing hole with water down the left and a green backed by a waterfall and the clubhouse. The approach must carry the creek.' }], whatToExpect: 'Shadow Creek is a surreal experience — a lush, Carolina-style parkland course in the Mojave Desert. The 21,000 transplanted trees, man-made creeks, and waterfalls create a completely isolated, fantasy-like setting minutes from the Strip.\n\nEvery aspect is first-class, from limousine transportation to caddie service. The course plays 7,560 yards from the tips with a slope of 145, but multiple tees make it accessible. Conditioning is always immaculate.', playingTips: 'Enjoy the experience and do not rush — every hole offers a different visual experience. The course rewards accurate iron play more than length. A caddie is included and provides valuable reads. Many holes feature creeks on approach shots, so take extra club and aim for the safe side.', faqs: [{ question: 'How do I get to play Shadow Creek?', answer: 'Shadow Creek is available to guests of MGM Resorts properties. Green fees of $600-$750 include caddie service and limousine transportation from your hotel.' }, { question: 'Is Shadow Creek worth the price?', answer: 'For golfers who appreciate course design and a once-in-a-lifetime experience, Shadow Creek delivers an unmatched combination of Tom Fazio design, surreal desert-to-parkland transformation, and first-class service.' }, { question: 'How was Shadow Creek built in the desert?', answer: 'Steve Wynn invested an estimated $60 million to transform flat desert into lush parkland with over 21,000 transplanted trees, rolling terrain, creeks, waterfalls, and ponds.' }, { question: 'What PGA Tour events has Shadow Creek hosted?', answer: 'The 2020 CJ Cup (won by Jason Kokrak) and the 2018 Capital One\'s The Match between Tiger Woods and Phil Mickelson.' }] },
    { id: 'lv-2', name: 'Wynn Golf Club', slug: 'wynn-golf-club', city: 'Las Vegas', state: 'Nevada', type: 'resort', rating: 4.7, greensFee: '$500–$650', architect: 'Tom Fazio / Bobby Weed', yearBuilt: 2018, holes: 18, par: 70, yardage: 6722, description: 'Located on the Las Vegas Strip behind the Wynn resort, this is the only golf course on the Strip. Originally designed by Tom Fazio and reimagined by Bobby Weed in 2018, the compact par-70 layout offers a luxurious, ultra-private golf experience steps from the casino floor.', highlights: ['Only golf course on the Las Vegas Strip', 'Ultra-exclusive Wynn resort amenity', 'Reimagined by Bobby Weed in 2018'], imageAlt: 'Wynn Golf Club fairway on the Las Vegas Strip with resort towers', history: 'Wynn Golf Club originally opened in 2005 when Wynn Las Vegas debuted, with Tom Fazio designing the 129-acre championship course on the Las Vegas Strip. It was the only golf course on the Strip and quickly became one of the most exclusive golf experiences in the world.\n\nIn 2017, the course was slated for demolition for the Wynn Paradise Park development, but those plans were shelved. Tom Fazio returned to reimagine the course, which reopened in October 2019 with eight new holes and ten refurbished ones, including a dramatic new finishing sequence.\n\nThe par-70 layout features six par 3s, creatively dealing with the compact acreage. The course is maintained to extraordinary standards with lush fairways contrasting dramatically with the desert landscape and Strip skyline.', signatureHoles: [{ hole: 7, par: 3, yardage: 165, description: 'One of six par 3s, showcasing how Fazio created memorable variety within the compact footprint.' }, { hole: 11, par: 4, yardage: 420, description: 'A demanding par 4 proving the course can bare its teeth despite modest total yardage.' }, { hole: 17, par: 4, yardage: 380, description: 'One of the new holes from 2019. Fazio was especially excited about the new finishing sequence.' }, { hole: 18, par: 4, yardage: 410, description: 'The most over-the-top finisher in Las Vegas golf, playing back toward the Wynn towers with a waterfall backdrop.' }], whatToExpect: 'An ultra-premium golf experience on the Strip. Immaculately maintained lush fairways contrast with desert surroundings. At 6,722 yards and par 70 with six par 3s, it rewards accuracy over power.\n\nEvery amenity is top-shelf, from caddies to on-course dining. Limited tee times ensure uncrowded conditions.', playingTips: 'The six par 3s are the backbone. Play for green centers where scoring opportunities and bogey risks coexist.\n\nThe course plays shorter than most resorts, so accuracy matters more than distance. Savor the unique Strip setting.', faqs: [{ question: 'How much does it cost to play?', answer: 'Green fees range from $500 to $650, including caddie, practice balls, and premium amenities.' }, { question: 'Is Wynn Golf Club open to the public?', answer: 'Primarily for Wynn and Encore hotel guests, though non-guests can sometimes book at a premium.' }, { question: 'Is it really the only course on the Strip?', answer: 'Yes, the only golf course located directly on the Las Vegas Strip.' }, { question: 'Who redesigned it in 2019?', answer: 'Tom Fazio, the original 2005 designer, returned with eight new and ten refurbished holes. Reopened October 2019.' }] },
    { id: 'lv-3', name: 'TPC Las Vegas', slug: 'tpc-las-vegas', city: 'Las Vegas', state: 'Nevada', type: 'public', rating: 4.4, greensFee: '$100–$200', architect: 'Bobby Weed & Raymond Floyd', yearBuilt: 1996, holes: 18, par: 71, yardage: 7104, description: 'Host of the Shriners Children\'s Open on the PGA Tour, TPC Las Vegas offers accessible championship golf in Summerlin. The desert layout features mountain views, dramatic canyon holes, and the prestige of playing a current PGA Tour venue.', highlights: ['PGA Tour Shriners Open host venue', 'Bobby Weed & Raymond Floyd design', 'Accessible championship golf in Summerlin'], imageAlt: 'TPC Las Vegas desert championship hole with mountain backdrop', history: 'Opened 1996 in Summerlin by Bobby Weed and Raymond Floyd. Hosts the PGA Tour Shriners Children\'s Open.', signatureHoles: [{ hole: 9, par: 4, yardage: 450, description: 'Demanding par 4 with canyon views.' }, { hole: 13, par: 5, yardage: 555, description: 'Risk-reward par 5.' }, { hole: 16, par: 3, yardage: 195, description: 'Scenic mountain-backdrop par 3.' }, { hole: 18, par: 4, yardage: 445, description: 'Strong finisher.' }], whatToExpect: 'PGA Tour venue accessible to the public. Mountain views and canyon holes. At 7,104 yards in thin desert air.', playingTips: 'Thin air adds 5-10% distance. Stay on maintained turf.', faqs: [{ question: 'Public?', answer: 'Yes. $100-$200.' }, { question: 'PGA Tour event?', answer: 'Shriners Children\'s Open.' }] },
    { id: 'lv-4', name: 'Cascata', slug: 'cascata-golf', city: 'Las Vegas', state: 'Nevada', type: 'resort', rating: 4.7, greensFee: '$250–$400', architect: 'Rees Jones', yearBuilt: 2000, holes: 18, par: 72, yardage: 7137, description: 'Set in a dramatic desert canyon 30 minutes south of the Strip, Cascata (Italian for "waterfall") features a 418-foot man-made waterfall at the clubhouse and a Rees Jones design that plays through towering rock canyon walls. It\'s one of the most visually dramatic golf experiences in the world.', highlights: ['418-foot waterfall at clubhouse', 'Dramatic desert canyon setting', 'Rees Jones visual masterpiece'], imageAlt: 'Cascata golf course dramatic canyon walls and waterfall near Las Vegas', history: 'Cascata, Italian for "waterfall," opened in 2000 as an ultra-exclusive playground for MGM high rollers. Designed by Rees Jones and Keith Evans on a dramatic site in the foothills of the River Mountain Range near Boulder City, Nevada, the course was originally accessible only to VIP casino guests. Sports Illustrated dubbed it "Golf\'s Hidden Treasure" at its debut, while Rees Jones himself called it "The Eighth Wonder of the golf world."\n\nThe property changed hands over the years, passing from MGM to Caesars Entertainment and then to Harrah\'s Entertainment. Today it is owned by VICI Properties. Through each transition, Cascata has maintained its reputation as one of the most visually spectacular golf courses on the planet, rivaling the famous Shadow Creek as Las Vegas\'s premier golf destination.\n\nSoaring 3,200 feet above the Las Vegas Desert Valley, the course climbs 800 feet in elevation through towering canyon walls. The Tuscan-inspired clubhouse features a roaring river running through it, fed by the iconic 418-foot man-made waterfall that cascades down the mountainside. Every element of the experience, from the private gates to the forecaddie service, is designed to feel like a world apart from the Las Vegas Strip.', signatureHoles: [{ hole: 7, par: 3, yardage: 139, description: 'One of the most photographed holes at Cascata, this short par 3 plays from an elevated tee down into a canyon with towering rock walls framing the green. Despite its brevity, the heavily protected green demands a precise carry over rugged terrain.' }, { hole: 12, par: 3, yardage: 165, description: 'A beautiful par 3 highlighted by a running waterfall cascading down the mountainside overlooking the green. The easiest hole by handicap, but the dramatic visual setting and the water feature left of the green can be distracting.' }, { hole: 14, par: 4, yardage: 434, description: 'A stunning downhill par 4 with a creek cutting in front of the tee boxes and running down the right side before pooling near the green. Tiger Woods was photographed near this green for a Golf Digest cover, cementing its iconic status.' }, { hole: 17, par: 4, yardage: 489, description: 'The number two handicap hole, this demanding par 4 plays nearly 490 yards through the canyon. It requires two precise, powerful shots to reach a well-defended green, making it one of the toughest holes on the course.' }], whatToExpect: 'Cascata is a bucket-list golf experience from start to finish. The round begins with a drive through private gates into a landscape that feels worlds removed from the desert. A Tuscan-inspired clubhouse with a river flowing through it sets the tone before you even reach the first tee. Forecaddies accompany every group, and tee times are spaced 12 minutes apart to ensure a peaceful, unhurried round.\n\nThe par-72 layout plays to 7,137 yards from the tips with a slope of 143 and a course rating of 74.6. Expect dramatic elevation changes on nearly every hole, with the course climbing 800 feet in either direction near the peak of Red Mountain. The greens are fast and the conditions are immaculate. Big horn sheep sightings are common among the towering canyon walls.', playingTips: 'Listen to your forecaddie. The extreme elevation changes at Cascata make club selection tricky, and distances can be deceiving. Uphill holes play significantly longer than the yardage suggests, while downhill tee shots can fly much further than expected. Take the caddie\'s recommendations on club selection seriously.\n\nThe greens are fast and undulating, so getting the ball below the hole is critical. The holes are spread out enough that errant shots are rarely in danger of reaching other fairways, so swing freely off the tee and focus your precision on approaches.', faqs: [{ question: 'Can the public play Cascata?', answer: 'Yes. While Cascata was originally exclusive to MGM casino VIPs, it is now open to the public with advance tee time reservations. Green fees typically range from $250 to $400 depending on the season.' }, { question: 'How far is Cascata from the Las Vegas Strip?', answer: 'Cascata is located in Boulder City, approximately 25 to 30 miles southeast of the Las Vegas Strip, roughly a 30-minute drive.' }, { question: 'Is a forecaddie included?', answer: 'Yes. Forecaddie service is included with every round at Cascata. Tee times are spaced 12 minutes apart to ensure an unhurried experience. A gratuity for the forecaddie is customary.' }, { question: 'What is the 418-foot waterfall at Cascata?', answer: 'The man-made waterfall cascades down the steep mountainside above the driving range, flows through the practice facilities, and runs as a river through the Tuscan-inspired clubhouse. It is the defining visual feature of the property.' }] },
    { id: 'lv-5', name: 'Paiute Golf Resort - Wolf Course', slug: 'paiute-wolf', city: 'Las Vegas', state: 'Nevada', type: 'public', rating: 4.4, greensFee: '$75–$175', architect: 'Pete Dye', yearBuilt: 2001, holes: 18, par: 72, yardage: 7604, description: 'The most challenging of three Pete Dye courses at Paiute Resort, the Wolf stretches to 7,604 yards through the desert northwest of the Strip. It\'s widely considered the best public value in Las Vegas, with dramatic island greens and Dye\'s signature railroad-tie bunkering.', highlights: ['Pete Dye desert design at 7,604 yards', 'Best public value in Las Vegas', 'Part of 3-course Paiute Resort'], imageAlt: 'Paiute Wolf Course desert Pete Dye fairway with Spring Mountain views', history: 'Las Vegas Paiute Golf Resort is owned and operated by the Las Vegas Paiute Tribe on tribal land northwest of the Las Vegas Strip. The resort was the first master-planned, multi-course facility of its kind in Nevada, with the Snow Mountain course opening in 1995, Sun Mountain following in 1997, and the Wolf Course completing the trio in 2001. All three layouts were designed by legendary architect Pete Dye.\n\nThe Wolf Course was Dye\'s final addition and his most ambitious at Paiute, stretching to 7,604 yards to become one of the longest courses in Nevada. Dye incorporated his trademark design elements including railroad-tie bunkering, split fairways, and an island green, while taking full advantage of the dramatic desert terrain and sweeping views of the Spring Mountains and Mount Charleston.\n\nDespite its championship length and difficulty, the Wolf Course has consistently been recognized as one of the best public-access values in Las Vegas. The course won the Best of Las Vegas award and has been featured in Golf Digest\'s rankings of top public courses.', signatureHoles: [{ hole: 15, par: 3, yardage: 172, description: 'The signature hole at the Wolf Course features a dramatic island green surrounded by desert waste areas. This memorable par 3 demands a precise tee shot with no bailout, making it one of the most photographed holes in Las Vegas.' }, { hole: 6, par: 5, yardage: 578, description: 'A strategic par 5 with a split fairway that epitomizes Pete Dye\'s risk-reward philosophy. Players must choose between a safer wide route or a tighter line that shortens the hole significantly for a chance at eagle.' }, { hole: 17, par: 4, yardage: 428, description: 'Another split-fairway hole where Dye presents two distinct paths to the green. The aggressive line brings danger into play but leaves a shorter approach, while the conservative route demands a longer second shot.' }, { hole: 18, par: 4, yardage: 445, description: 'A demanding finishing hole that plays back toward the massive clubhouse. Railroad-tie bunkering guards the approach to a well-defended green, providing a fitting conclusion to the most challenging course at Paiute.' }], whatToExpect: 'The Wolf Course offers a true desert golf experience on pristine Paiute tribal land about 30 minutes northwest of the Las Vegas Strip. At 7,604 yards from the tips, it is one of the longest courses in Nevada, but five sets of tees make it playable for all skill levels. The wide-open desert setting features sweeping views of the Spring Mountains and Mount Charleston with virtually no housing or development in sight.\n\nConditions are excellent year-round, and the pace of play is well-managed. The massive clubhouse serves all three Paiute courses and features one of the largest golf shops in the Southwest.', playingTips: 'Do not let the 7,604-yard length intimidate you. Choose the appropriate tee box for your game and the Wolf becomes very enjoyable. The desert air and elevation help the ball carry further than at sea level. Wind can be a significant factor on the exposed desert layout, so check conditions before your round and adjust club selection accordingly.\n\nThe island green at the 15th is the marquee moment. Take one extra club and aim for the center of the green. On the split-fairway holes at 6 and 17, assess your confidence level honestly before choosing the aggressive line.', faqs: [{ question: 'Which is the best of the three Paiute courses?', answer: 'The Wolf Course is generally considered the most challenging and highest-rated of the three Pete Dye layouts, though Snow Mountain and Sun Mountain are also excellent. Many golfers play all three during a Las Vegas trip.' }, { question: 'How far is Paiute from the Las Vegas Strip?', answer: 'The resort is approximately 25-30 minutes northwest of the Strip, located on Las Vegas Paiute tribal land in a pristine desert setting.' }, { question: 'Is the Wolf Course too difficult for average golfers?', answer: 'Not from the right tees. While the championship tees stretch to 7,604 yards, the course offers five tee positions. The forward tees bring the course to a very manageable length while still providing the full Pete Dye experience.' }, { question: 'What is the island green hole at the Wolf?', answer: 'The par-3 15th hole features a dramatic island green surrounded by desert waste areas. It is the most famous and photographed hole on the course.' }] },
    { id: 'lv-6', name: 'Rio Secco Golf Club', slug: 'rio-secco', city: 'Las Vegas', state: 'Nevada', type: 'public', rating: 4.3, greensFee: '$100–$200', architect: 'Rees Jones', yearBuilt: 1997, holes: 18, par: 72, yardage: 7332, description: 'A Rees Jones design in Henderson with six holes playing through a dramatic desert canyon and 12 holes on the surrounding desert plateau. Rio Secco is also home to the Butch Harmon School of Golf, adding a premium instruction component.', highlights: ['Butch Harmon School of Golf on-site', 'Six dramatic desert canyon holes', 'Rees Jones championship design'], imageAlt: 'Rio Secco desert canyon hole in Henderson near Las Vegas', history: 'Rio Secco Golf Club (recently rebranded as Serket Golf Club but still widely known as Rio Secco) opened in 1997, designed by Rees Jones in the foothills of Henderson southeast of the Las Vegas Strip. The layout features three distinct six-hole segments: six holes through dramatic desert canyons and arroyos, six on a plateau with panoramic valley views, and six along a ridgeline.\n\nThe course is home to the famous Butch Harmon School of Golf, where countless tour professionals have trained — one of the most renowned instruction facilities in the world. The combination of championship golf and world-class instruction makes Rio Secco unique in the Las Vegas market.', signatureHoles: [{ hole: 18, par: 5, yardage: 634, description: 'A massive finishing hole with panoramic views of the Las Vegas Strip in the distance. At 634 yards, it is one of the longest and most memorable closers in the Vegas market — a three-shot challenge with a dramatic backdrop.' }, { hole: 16, par: 4, yardage: 440, description: 'Plays beneath what was Butch Harmon\\\'s home with sweeping canyon views. A demanding tee shot sets up an approach with one of the most dramatic backdrops on the course.' }], whatToExpect: 'Three distinct six-hole segments each with a completely different feel: canyon holes are visually stunning with forced carries over arroyos; plateau holes offer sweeping valley and Strip views; ridgeline holes provide elevated drama.\n\nElevation changes are significant throughout. The canyon holes demand target golf — pick conservative lines and accept par. The plateau and ridge holes reward aggressive play with proper wind management.\n\nThe Butch Harmon School of Golf on-site is one of the most famous instruction facilities in the world. Consider booking a lesson as a complement to your round.', playingTips: 'The canyon holes (typically 7-12) demand target golf. Pick conservative lines off the tee and accept par on these dramatic holes.\n\nElevation changes affect club selection dramatically. Downhill holes play shorter; uphill holes play much longer than the card suggests.\n\nWind at the higher elevations can be a significant factor, especially in afternoon rounds.\n\nDesert air and elevation mean the ball flies farther. Factor this into club selection, particularly on the par 3s.', faqs: [{ question: 'What is the Butch Harmon School of Golf?', answer: 'One of the most famous golf instruction facilities in the world, located on-site at Rio Secco. Countless tour professionals have trained here. Lessons can be booked as a complement to your round.' }, { question: 'What are the three course segments?', answer: 'Six canyon holes (dramatic arroyos and forced carries), six plateau holes (panoramic valley views), and six ridgeline holes (elevated terrain). Each segment has a completely different character.' }, { question: 'Who designed it?', answer: 'Rees Jones ("The Open Doctor"), opening in 1997. The course was recently rebranded as Serket Golf Club but is still widely known as Rio Secco.' }]},
    { id: 'lv-7', name: 'Southern Highlands Golf Club', slug: 'southern-highlands', city: 'Las Vegas', state: 'Nevada', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Robert Trent Jones Jr.', yearBuilt: 2000, holes: 18, par: 72, yardage: 7381, description: 'One of Las Vegas\'s most prestigious private clubs, Southern Highlands is an RTJ Jr. design with dramatic desert elevation changes and panoramic views of the Las Vegas Strip and surrounding mountains. The course has hosted the Las Vegas Invitational.', highlights: ['Panoramic Las Vegas Strip views', 'Robert Trent Jones Jr. desert design', 'Elite Las Vegas private club'], imageAlt: 'Southern Highlands elevated tee with Las Vegas Strip and mountain views', history: 'Southern Highlands Golf Club opened on April 1, 2000, as the centerpiece of the master-planned Southern Highlands community in southwest Las Vegas. The course was co-designed by Robert Trent Jones Sr. and his son Robert Trent Jones Jr., making it one of the final works of the elder Jones, who passed away in 2000. It stands as one of only four courses the father-son duo collaborated on together.\n\nThe design descends into canyons created by an aggressive grading plan, providing a sense of separation from the surrounding residential community. The lush layout features Bermuda tees and fairways with bent grass greens, multiple waterfalls, and dramatic elevation changes at 2,200 feet above sea level. The elevation makes the course play shorter than its listed yardage.\n\nSouthern Highlands serves as the home course for the UNLV Rebels men\'s and women\'s golf teams and has hosted numerous collegiate and amateur events. The club has attracted a notable membership and remains one of the most prestigious private clubs in the Las Vegas valley.', signatureHoles: [{ hole: 3, par: 4, yardage: 420, description: 'One of the most wooded holes on the property, this par 4 plays through a narrow tree-lined corridor that challenges players of all skill levels. Precision off the tee is essential to set up a birdie opportunity.' }, { hole: 9, par: 4, yardage: 465, description: 'A demanding par 4 that plays uphill with panoramic views of the Las Vegas Strip in the background. The elevated green rewards accurate approach play and offers one of the best vistas on the course.' }, { hole: 15, par: 3, yardage: 195, description: 'A beautiful par 3 with a waterfall feature beside the green. The hole plays slightly downhill but demands a precise tee shot to a well-bunkered putting surface with the sound of cascading water as a backdrop.' }, { hole: 18, par: 5, yardage: 622, description: 'The longest and most memorable hole on the course, this massive 622-yard par 5 plays uphill with a stream bisecting the fairway. The finishing hole demands three strong shots and provides a dramatic conclusion to the round.' }], whatToExpect: 'Southern Highlands is a lush, meticulously conditioned private club that feels like an oasis in the desert. The course features dramatic elevation changes, multiple waterfalls, and panoramic views of both the Las Vegas Strip and the surrounding mountain ranges. At 2,200 feet of elevation, the ball flies further than at sea level, so the 7,381-yard layout plays shorter than its listed yardage.\n\nThe 18 holes are distinctly different from one another, winding through canyons and across ridgelines. Conditions are consistently immaculate, and the Bermuda fairways and bent grass greens provide excellent playing surfaces year-round.', playingTips: 'Account for the 2,200-foot elevation when selecting clubs. The ball will carry 5-10 percent further than at sea level, which is significant on approach shots. The course features many downhill holes that play even shorter, so adjust accordingly.\n\nThe greens are bent grass and tend to be slick, especially in the afternoon desert heat. Several holes feature waterfalls and water features that come into play, so conservative targets away from hazards are wise, particularly on the par 3s.', faqs: [{ question: 'Can the public play Southern Highlands?', answer: 'No. Southern Highlands is a private club with no public access. Play is restricted to members and their guests.' }, { question: 'Who designed Southern Highlands?', answer: 'The course was co-designed by Robert Trent Jones Sr. and Robert Trent Jones Jr. It is one of the elder Jones\'s final designs before his passing in 2000, and one of only four courses the father-son team designed together.' }, { question: 'Is Southern Highlands the home course for UNLV golf?', answer: 'Yes. Southern Highlands serves as the home course for both the UNLV Rebels men\'s and women\'s golf teams and regularly hosts collegiate competitions.' }, { question: 'What is the most difficult hole at Southern Highlands?', answer: 'The 622-yard par-5 18th is the longest and most demanding hole, playing uphill with a stream cutting through the fairway. Several par 4s over 450 yards also present significant challenges.' }] },
    { id: 'lv-8', name: 'Bear\'s Best Las Vegas', slug: 'bears-best-vegas', city: 'Las Vegas', state: 'Nevada', type: 'public', rating: 4.2, greensFee: '$75–$150', architect: 'Jack Nicklaus', yearBuilt: 2002, holes: 18, par: 72, yardage: 7194, description: 'Jack Nicklaus re-created 18 of his favorite holes from courses around the world in this unique "greatest hits" concept in northwest Las Vegas. Each hole is modeled after a specific Nicklaus design, making it a fun survey of the Golden Bear\'s career.', highlights: ['18 replica Nicklaus "greatest hits" holes', 'Unique concept in golf', 'Fun desert layout with mountain views'], imageAlt: 'Bear\'s Best Las Vegas Nicklaus replica hole with desert mountain setting', history: 'Bear\\\'s Best Las Vegas opened in 2002 as a completely unique concept in golf: Jack Nicklaus hand-picked 18 of his favorite holes from the 270+ courses he designed worldwide and recreated them on a single property in the Las Vegas desert. Each hole is a faithful replica of a specific Nicklaus design, giving players a "greatest hits" experience.\n\nThe course sold in 2024 for $30.5 million. It is one of only two Bear\\\'s Best facilities (the other is in Atlanta). The concept lets public golfers experience holes from exclusive private courses they would otherwise never play.\n\nEach hole includes signage explaining which original course it replicates and the design philosophy behind it, making the round both a golf experience and an architecture tour.', signatureHoles: [{ hole: 1, par: 4, yardage: 410, description: 'A replica of the 6th hole at PGA West (private course), with water running the entire left side. A stunning opener that sets the tone for the "greatest hits" concept — you\\\'re playing famous holes from your first swing.' }, { hole: 4, par: 3, yardage: 175, description: 'Features distinctive black-sand bunkers (actually black slag), replicating the design at Old Works in Anaconda, Montana, where Nicklaus used copper-smelting slag as bunker material. Visually disorienting but plays identically to regular sand.' }], whatToExpect: 'Each hole replicates a specific famous Nicklaus design from around the world, with signage explaining the original course and design intent. Holes draw from PGA West, Castle Pines, Cabo del Sol, Old Works, and other iconic venues.\n\nThe routing flows surprisingly well for a compilation course. Desert landscaping frames each hole, and conditioning is typically very good for a public facility. It plays as a cohesive round rather than a disconnected collection.\n\nThe concept makes every hole an adventure — you\\\'re essentially touring the highlights of Nicklaus\\\'s career in a single round.', playingTips: 'Study the tee markers and signage. Understanding which famous hole you\\\'re playing and its original strategic intent helps with course management.\n\nThe black-sand bunkers on holes 4 and 11 play identically to regular sand but are visually disorienting. Don\\\'t let the color affect your technique.\n\nDesert target golf principles apply throughout: stay in the short grass and avoid the waste areas.\n\nThe desert elevation and dry air mean the ball flies farther. Adjust club selection accordingly.', faqs: [{ question: 'What is the Bear\\\'s Best concept?', answer: 'Nicklaus hand-picked 18 favorite holes from his 270+ designs worldwide and recreated them on one property. Each hole replicates a specific famous course, with signage explaining the original design.' }, { question: 'Which courses are represented?', answer: 'Holes draw from PGA West, Castle Pines, Cabo del Sol, Old Works (black slag bunkers), and other iconic Nicklaus venues around the world.' }, { question: 'Are the replicas accurate?', answer: 'Yes — each hole includes unique design elements faithful to the original. The routing flows cohesively despite drawing from different courses.' }]},
    { id: 'lv-9', name: 'Paiute Golf Resort - Wolf Course', slug: 'paiute-wolf', city: 'Las Vegas', state: 'Nevada', type: 'public', rating: 4.3, greensFee: '$75–$175', architect: 'Pete Dye', yearBuilt: 1998, holes: 18, par: 72, yardage: 7604, description: 'The most challenging of Pete Dye\'s three courses at the Las Vegas Paiute resort, the Wolf features an island green, dramatic desert carries, and sweeping mountain views. At 7,604 yards, it tests the best players while offering multiple tee positions for all abilities in a pristine desert setting northwest of the Strip.', highlights: ['Pete Dye\'s most challenging Paiute layout at 7,604 yards', 'Island green and dramatic desert forced carries', 'Pristine desert setting with mountain views'], imageAlt: 'Paiute Wolf Course Pete Dye desert fairway with mountain views Las Vegas', history: 'The Wolf Course opened in 1998 as the third and final Pete Dye design at the Las Vegas Paiute Golf Resort, joining the Snow and Sun courses on tribal land about 25 miles northwest of the Strip. At 7,604 yards from the tips, the Wolf is the longest and most demanding of the three Paiute courses.\n\nThe resort offers 54 holes of Dye-designed desert golf against the backdrop of the Spring Mountains and surrounded by raw Mojave Desert. The Wolf features Dye\\\'s famous island green (reminiscent of TPC Sawgrass\\\'s 17th) and severe green undulations that are the course\\\'s primary defense.\n\nThe Paiute resort sits on Paiute tribal land, giving it a distinctive setting and character separate from the commercial Vegas golf scene.', signatureHoles: [{ hole: 15, par: 3, yardage: 182, description: 'The famous island green — completely surrounded by water, reminiscent of TPC Sawgrass\\\'s 17th but larger and playing longer. The defining visual of the course. Take one extra club — the hole plays longer than its yardage due to the psychological pressure.' }], whatToExpect: 'Pete Dye at his most strategic and punishing in a desert setting. Severe green undulations are the primary defense — players consistently describe the greens as the toughest feature. Tight fairways, small greens, and the sheer 7,604-yard length from the tips create a genuine championship test.\n\nThe barren desert setting with jagged Spring Mountain peaks creates a stark, beautiful backdrop with zero distractions. The course feels completely isolated despite being less than 30 minutes from the Strip.\n\nThe three Paiute courses together represent one of the best public golf values in the Las Vegas market.', playingTips: 'Play the appropriate tees. At 7,604 yards from the tips, this course can overwhelm most golfers. Choose tees that match your game honestly.\n\nThe greens are the real challenge. Focus on getting the ball on the correct tier — landing on the wrong level leaves treacherous putts.\n\nDesert elevation and dry air mean the ball flies farther, partially offsetting the length. Factor this into every club selection.\n\nWind in the open desert can be fierce, especially in the afternoon. Morning tee times typically offer calmer conditions.\n\nOn the island green 15th, take one extra club. The psychological pressure makes most golfers come up short.', faqs: [{ question: 'What is the island green hole?', answer: 'No. 15 — a par 3 completely surrounded by water, reminiscent of TPC Sawgrass\\\'s 17th but larger. It is the defining visual of the Wolf Course.' }, { question: 'How does the Wolf compare to the other Paiute courses?', answer: 'It is the longest (7,604 yards) and most demanding of the three Pete Dye designs. The Sun and Snow courses are slightly more forgiving.' }, { question: 'How far is it from the Strip?', answer: 'About 25 miles northwest — less than 30 minutes. Despite the proximity, the course feels completely isolated in the Mojave Desert.' }, { question: 'Is it walkable?', answer: 'Not recommended. The desert terrain and distances between holes make cart play standard.' }]},
    { id: 'lv-10', name: 'Reflection Bay Golf Club', slug: 'reflection-bay-golf-club', city: 'Henderson', state: 'Nevada', type: 'public', rating: 4.3, greensFee: '$80–$175', architect: 'Jack Nicklaus', yearBuilt: 1998, holes: 18, par: 72, yardage: 7261, description: 'A Jack Nicklaus design at Lake Las Vegas in Henderson, Reflection Bay offers a resort golf experience with water features and mountain views east of the Strip. The 7,261-yard layout wraps around the lake with dramatic desert terrain, bold Nicklaus bunkering, and a memorable par-3 over the lake to an island green.', highlights: ['Jack Nicklaus lakeside design at Lake Las Vegas', 'Memorable island-green par 3 over the lake', 'Desert resort experience east of the Strip'], imageAlt: 'Reflection Bay Golf Club lakeside fairway at Lake Las Vegas in Henderson', history: 'Reflection Bay opened in 1998 as the only Jack Nicklaus Signature Design course in Nevada, built as the centerpiece of the Lake Las Vegas resort community — a 320-acre private lake about 20 miles east of the Strip. The course hosted the Wendy\\\'s 3-Tour Challenge from 1998 to 2007, bringing together PGA Tour, LPGA, and Champions Tour players.\n\nFive holes run along a mile and a half of Lake Las Vegas shoreline, with the par-3 17th featuring a near-island green jutting into the lake. Nicklaus reportedly birdied a hole during the ceremonial first round in 1998.', signatureHoles: [{ hole: 17, par: 3, yardage: 185, description: 'The marquee hole — a near-island green jutting into Lake Las Vegas, often compared to TPC Sawgrass\\\'s 17th. Wind off the lake makes club selection critical. One of the most dramatic par 3s in the Las Vegas market.' }, { hole: 6, par: 5, yardage: 540, description: 'A daring risk-reward hole with a desert-framed tee shot followed by an aggressive second over a ravine to a beautifully positioned green. The classic Nicklaus two-shot decision.' }], whatToExpect: 'Five holes along the Lake Las Vegas shoreline create a unique water-and-desert combination unlike anything else near Vegas. The routing uses natural elevation changes well, balancing uphill and downhill shots. Desert terrain frames the holes while the lake provides a dramatic backdrop.\n\nNicklaus\\\'s signature bunkering guards greens throughout. The lakeside holes are visually stunning but wind off the water adds a challenge not found on most desert courses.', playingTips: 'Wind off the lake is a constant factor on the shoreline holes. Club up or down accordingly — don\\\'t trust your usual distances.\n\nNicklaus bunkering punishes misses. Favor the center of greens, especially on the lakeside par 3s.\n\nDesert elevation and dry air add distance. Factor this into every club selection.', faqs: [{ question: 'Is this the only Nicklaus course in Nevada?', answer: 'Yes — the only Jack Nicklaus Signature Design in the state. It opened in 1998 at Lake Las Vegas.' }, { question: 'What is the island green hole?', answer: 'No. 17 — a near-island green jutting into Lake Las Vegas, reminiscent of TPC Sawgrass\\\'s famous 17th.' }, { question: 'Has it hosted professional events?', answer: 'Yes — the Wendy\\\'s 3-Tour Challenge (1998-2007) brought PGA Tour, LPGA, and Champions Tour players together here.' }]},
    { id: 'lv-11', name: 'Southern Highlands Golf Club', slug: 'southern-highlands-gc', city: 'Las Vegas', state: 'Nevada', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Robert Trent Jones Jr. / Jack Nicklaus / Steve Wynn (renovations)', yearBuilt: 2000, holes: 18, par: 72, yardage: 7381, description: 'An RTJ Jr. design in the master-planned Southern Highlands community south of the Strip, this private club has been enhanced by Jack Nicklaus and Steve Wynn. The 7,381-yard layout through desert terrain features dramatic elevation changes, pristine conditioning, and panoramic Las Vegas skyline and mountain views.', highlights: ['RTJ Jr. design with Nicklaus and Wynn enhancements', 'Panoramic Las Vegas skyline views', 'Dramatic elevation changes and pristine conditioning'], imageAlt: 'Southern Highlands Golf Club fairway with Las Vegas skyline views', history: 'Southern Highlands opened in 2000, co-designed by Robert Trent Jones Sr. and his son Robert Trent Jones Jr. — one of only four courses the father-son duo ever designed together, and the elder Jones\\\'s final work before his death in June 2000 at age 93.\n\nThe strictly private club has served as home to the UNLV men\\\'s golf team and has hosted PGA Tour events. The canyon-style routing provides remarkable seclusion despite being minutes south of the Strip. The course plays up to 7,510 yards from the tips.\n\nJack Nicklaus and Steve Wynn have enhanced the layout over the years, adding to the already distinguished design pedigree.', signatureHoles: [{ hole: 14, par: 4, yardage: 440, description: 'One of several holes descending into manufactured desert canyons, creating a sense of isolation. Dramatic elevation changes provide sweeping views of the Las Vegas valley below. Precise carries over desert washes are mandatory.' }], whatToExpect: 'Immaculately conditioned with lightning-fast greens that roll true. The canyon-style routing creates remarkable seclusion — each hole feels isolated despite the proximity to the Strip. Wide enough to be fair but strategically bunkered throughout.\n\nThe layout descends into canyons created by aggressive grading, with dramatic elevation changes and Las Vegas skyline/mountain views. Desert elevation and dry air make the ball fly farther than expected.\n\nStrictly private — one of the most exclusive clubs in Las Vegas.', playingTips: 'The greens are the primary defense — extremely fast with significant undulation. Every approach should land below the hole.\n\nDesert elevation and dry air mean extra distance on every shot. Adjust club selection accordingly.\n\nCaddies are available and highly recommended for first-time players given the canyon routing and fast greens.\n\nThe manufactured canyons create wind channels that can affect shots unexpectedly.', faqs: [{ question: 'What makes the design historically significant?', answer: 'It is one of only four father-son RTJ collaborations and was Robert Trent Jones Sr.\\\'s final course design before his death in June 2000 at age 93.' }, { question: 'Can the public play?', answer: 'No. Southern Highlands is a strictly private club. It is home to UNLV men\\\'s golf and has hosted PGA Tour events.' }, { question: 'Who else contributed to the design?', answer: 'Jack Nicklaus and Steve Wynn have enhanced the layout over the years, adding to the RTJ father-son foundation.' }]},
  ],
  'denver-colorado': [
    { id: 'den-1', name: 'Cherry Hills Country Club', slug: 'cherry-hills', city: 'Denver', state: 'Colorado', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'William Flynn', yearBuilt: 1922, holes: 18, par: 72, yardage: 7160, description: 'One of the most historic courses in America, Cherry Hills hosted Arnold Palmer\'s legendary 1960 U.S. Open charge, the 1985 PGA Championship, and multiple other majors. The William Flynn design south of Denver features dramatic mountain views and the unique physics of mile-high golf.', highlights: ['Arnold Palmer\'s legendary 1960 U.S. Open', 'Multiple major championship host', 'William Flynn design with mountain views'], imageAlt: 'Cherry Hills Country Club with Rocky Mountain backdrop in Denver', history: 'Cherry Hills Country Club was founded in 1922 in Cherry Hills Village, Colorado, south of Denver. William Flynn, one of the most revered architects of the Golden Age, designed the course on a property graced with mature cottonwood trees, Little Dry Creek, and panoramic Rocky Mountain views. The course opened to immediate acclaim and quickly became Colorado\'s premier private club.\n\nCherry Hills is the site of one of the most famous moments in golf history. At the 1960 U.S. Open, Arnold Palmer trailed by seven strokes entering the final round. He famously drove the green on the 346-yard 1st hole, shot a final-round 65, and won the championship in dramatic fashion. The 1960 Open also marked a passing of the torch, as 47-year-old Ben Hogan faded on the back nine and a young Jack Nicklaus finished as the low amateur.\n\nCherry Hills has hosted the U.S. Open three times (1938, 1960, 1978), the PGA Championship in 1985 won by Hubert Green, the U.S. Amateur in 1990 won by Phil Mickelson, and the BMW Championship in 2014. Tom Doak completed a decade-long restoration of the William Flynn design in 2022, recovering original green contours and bunker positions that had been altered over the decades.', signatureHoles: [{ hole: 1, par: 4, yardage: 397, description: 'The most famous opening hole in championship golf. Arnold Palmer drove this green in the final round of the 1960 U.S. Open, igniting his charge to victory. Today it plays 397 yards with a slight dogleg left, and the green remains reachable for long hitters at altitude.' }, { hole: 5, par: 5, yardage: 538, description: 'A strategic par 5 that plays along Little Dry Creek. The creek threatens the second shot for players attempting to reach the green in two, creating a classic risk-reward decision enhanced by the mountain backdrop.' }, { hole: 11, par: 4, yardage: 442, description: 'A demanding par 4 with water guarding the left side of the fairway and approach. The hole requires two precise shots and is consistently one of the most difficult on the course during major championships.' }, { hole: 18, par: 4, yardage: 478, description: 'A strong finishing hole that plays uphill toward the clubhouse with Rocky Mountain views behind the green. The long approach to an elevated green makes par a satisfying conclusion to any round.' }], whatToExpect: 'Cherry Hills is a classic William Flynn parkland course set against the dramatic backdrop of the Rocky Mountains at approximately 5,300 feet elevation. The mile-high altitude adds 10-15 percent to shot distances, making the 7,160-yard layout play somewhat shorter than its yardage suggests. Little Dry Creek winds through the property, coming into play on several holes.\n\nThe Tom Doak restoration completed in 2022 returned the course to its Flynn-era character, with recovered green contours, restored bunker positions, and cleared sightlines. The mature cottonwood trees, mountain panoramas, and historic character combine to create one of the most special golf experiences in America.', playingTips: 'Factor altitude into every club selection at Cherry Hills. The ball flies 10-15 percent farther at mile-high elevation, so a shot that normally travels 150 yards will carry approximately 165-170 yards here. The thin air also reduces spin, so the ball will release more on landing.\n\nLittle Dry Creek is the primary hazard and comes into play on several key holes. Position off the tee is critical on holes where the creek threatens, particularly on the risk-reward par 5s. The recently restored Flynn greens feature more contour and firmness than longtime members may remember.', faqs: [{ question: 'Can the public play Cherry Hills?', answer: 'No. Cherry Hills Country Club is a private club with no public access. It occasionally hosts major championships and professional events open to spectators.' }, { question: 'What happened at the 1960 U.S. Open?', answer: 'Arnold Palmer trailed by seven strokes entering the final round, drove the green on the 346-yard 1st hole, shot a final-round 65, and won the championship. It is widely considered one of the greatest rounds in golf history.' }, { question: 'What major championships has Cherry Hills hosted?', answer: 'Cherry Hills has hosted three U.S. Opens (1938, 1960, 1978), the 1985 PGA Championship, the 1990 U.S. Amateur, and the 2014 BMW Championship, among other significant events.' }, { question: 'What is the elevation at Cherry Hills?', answer: 'Cherry Hills sits at approximately 5,300 feet elevation south of Denver, which adds roughly 10-15 percent to shot distances due to the thinner air.' }] },
    { id: 'den-2', name: 'Castle Pines Golf Club', slug: 'castle-pines', city: 'Denver', state: 'Colorado', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 1981, holes: 18, par: 72, yardage: 7559, description: 'A Jack Nicklaus design at 6,300 feet elevation in the foothills south of Denver, Castle Pines hosted The International on the PGA Tour for over 20 years. The dramatic mountain-and-pine setting, combined with thin mile-high air that adds 10-15% distance, creates a unique championship experience.', highlights: ['Former PGA Tour International host', 'Jack Nicklaus mountain foothills design', '6,300 feet elevation — 10-15% extra distance'], imageAlt: 'Castle Pines dramatic mountain pine fairway south of Denver', history: 'Castle Pines Golf Club was the vision of Jack Vickers, a Denver oil executive who acquired thousands of acres of rugged foothill terrain in Castle Rock, Colorado. Vickers enlisted Jack Nicklaus to design a championship course that would rival Augusta National in scenery and drama. The course opened in 1981 at an elevation of approximately 6,300 feet, carved through ponderosa pine forests with dramatic elevation changes.\n\nThe International, a PGA Tour event using a unique modified Stableford scoring format, called Castle Pines home from 1986 to 2006 for 21 consecutive years. At the time of its inaugural event, The International featured a $1 million purse, the largest in PGA Tour history. The tournament became one of the most distinctive stops on Tour, with the Stableford format encouraging aggressive play on the mountain course.\n\nCastle Pines returned to championship prominence when it hosted the 2024 BMW Championship, a FedEx Cup Playoffs event. At 8,130 yards from the championship tees, it was the longest course setup in PGA Tour history. Jack Vickers passed away in 2018, but his legacy endures through one of the most dramatic and demanding courses in American golf.', signatureHoles: [{ hole: 1, par: 4, yardage: 444, description: 'A dramatic opening hole that plunges downhill through a chute of ponderosa pines. The significant elevation drop makes the hole play shorter than its yardage, setting the tone for the mountain golf experience ahead.' }, { hole: 11, par: 3, yardage: 197, description: 'The signature par 3 drops approximately 75 feet from tee to green with the Rocky Mountains as a backdrop. The dramatic downhill shot to a well-bunkered green is one of the most photographed holes in Colorado.' }, { hole: 17, par: 4, yardage: 483, description: 'A demanding par 4 that plays along a ridge with panoramic mountain views. The length and elevation make this one of the most challenging holes on the course, particularly into the prevailing wind.' }, { hole: 18, par: 4, yardage: 474, description: 'A strong finishing hole that requires two precise shots. The approach plays slightly uphill to a well-guarded green near the clubhouse, providing a demanding conclusion to the round.' }], whatToExpect: 'Castle Pines is a mountain golf experience unlike any other. The course sits at approximately 6,300 feet elevation amid towering ponderosa pines with dramatic elevation changes on nearly every hole. At 7,559 yards from the back tees, the course is long on paper but the altitude adds 10-15 percent to shot distances.\n\nThe Nicklaus design takes full advantage of the rugged terrain, routing holes through natural corridors in the pine forests with panoramic Rocky Mountain views. The conditioning is immaculate, and the remote mountain setting creates a sense of isolation and grandeur that few courses can match.', playingTips: 'Altitude adjustment is critical at Castle Pines. The 6,300-foot elevation adds roughly 10-15 percent to all distances, and many holes feature significant elevation changes that further affect club selection. A shot that travels 150 yards at sea level may carry over 170 yards here, especially on downhill holes.\n\nThe ponderosa pines create narrow corridors that demand accuracy off the tee. Wayward drives will find trouble in the trees, thick rough, or natural mountain terrain. Focus on keeping the ball in the fairway rather than maximizing distance.', faqs: [{ question: 'Can the public play Castle Pines?', answer: 'No. Castle Pines Golf Club is an exclusive private club. The nearby Country Club at Castle Pines is a separate facility.' }, { question: 'What was The International?', answer: 'The International was a PGA Tour event held at Castle Pines from 1986 to 2006. It used a unique modified Stableford scoring format that encouraged aggressive play.' }, { question: 'What is the elevation at Castle Pines?', answer: 'The course sits at approximately 6,300 feet elevation in the foothills south of Denver. The thin air adds 10-15 percent to shot distances.' }, { question: 'Has Castle Pines hosted recent PGA Tour events?', answer: 'Yes. Castle Pines hosted the 2024 BMW Championship, a FedEx Cup Playoffs event. At 8,130 yards from the tips, it was the longest course setup in PGA Tour history.' }] },
    { id: 'den-3', name: 'Colorado Golf Club', slug: 'colorado-golf-club', city: 'Denver', state: 'Colorado', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Bill Coore & Ben Crenshaw', yearBuilt: 2007, holes: 18, par: 72, yardage: 7600, description: 'A Coore & Crenshaw design in Parker that hosted the 2013 Solheim Cup and 2019 U.S. Mid-Amateur, Colorado Golf Club occupies wide-open prairie terrain with expansive Front Range views. The minimalist design allows the natural terrain and mountain panoramas to dominate.', highlights: ['Hosted 2013 Solheim Cup', 'Coore & Crenshaw minimalist prairie design', 'Expansive Rocky Mountain panoramas'], imageAlt: 'Colorado Golf Club open prairie fairway with Rocky Mountain Front Range views', history: 'Colorado Golf Club opened in 2007 in Parker, Colorado, southeast of Denver. Bill Coore and Ben Crenshaw designed the course on rolling prairie terrain at approximately 6,200 feet elevation, using their minimalist philosophy to let the natural landscape and panoramic Front Range views define the experience.\n\nIn 2013, Colorado Golf Club hosted the Solheim Cup. The U.S. team recaptured the Cup in a closely fought match, showcasing the course to a worldwide audience.\n\nIn 2019, the club hosted the U.S. Mid-Amateur Championship. The course is consistently ranked among the top courses in Colorado and the top 100 in America.', signatureHoles: [{ hole: 1, par: 4, yardage: 430, description: 'Considered one of the great opening holes in American golf, playing through a natural meadow that conceals subtle strategic options.' }, { hole: 11, par: 3, yardage: 214, description: 'A beautiful par 3 to a green fronted by the course\'s largest pond with expansive Front Range views behind.' }, { hole: 15, par: 5, yardage: 602, description: 'A long par 5 following the natural ridge terrain. The fescue rough flanking the fairway punishes errant shots severely.' }, { hole: 18, par: 4, yardage: 468, description: 'A strong finishing par 4 along a dramatic ridgeline with panoramic mountain views.' }], whatToExpect: 'Colorado Golf Club is a wide-open prairie golf experience with expansive Rocky Mountain Front Range views. At 7,600 yards from the championship tees at approximately 6,200 feet elevation, the course is a serious test even with altitude-enhanced distances.\n\nNative fescue rough punishes wayward shots severely. The greens feature Coore and Crenshaw\'s subtle contours that reward precise approach play.', playingTips: 'The native fescue rough is severe. Keeping the ball in the fairway is paramount. Accuracy should take priority over distance.\n\nWind is a major factor on the exposed prairie terrain. Factor altitude into all club selections, as the 6,200-foot elevation adds roughly 10 percent to distances.', faqs: [{ question: 'Can the public play Colorado Golf Club?', answer: 'No. Colorado Golf Club is a private club in Parker with no public access.' }, { question: 'What championships has it hosted?', answer: 'The 2013 Solheim Cup and the 2019 U.S. Mid-Amateur Championship.' }, { question: 'Who designed Colorado Golf Club?', answer: 'Bill Coore and Ben Crenshaw, opening in 2007.' }, { question: 'How does altitude affect play?', answer: 'At approximately 6,200 feet, the thin air adds roughly 10 percent to distances. Wind on the exposed terrain is also a constant factor.' }] },
    { id: 'den-4', name: 'Arrowhead Golf Club', slug: 'arrowhead-golf-club', city: 'Denver', state: 'Colorado', type: 'public', rating: 4.5, greensFee: '$75–$175', architect: 'Robert Trent Jones Jr.', yearBuilt: 1972, holes: 18, par: 70, yardage: 6682, description: 'Set among the same dramatic 300-million-year-old red rock formations as nearby Red Rocks Amphitheatre, Arrowhead is one of the most visually stunning public courses in the world. RTJ Jr.\'s layout winds through towering sandstone spires with panoramic mountain views.', highlights: ['Dramatic red rock formations like Red Rocks', 'Among the most scenic courses in the world', 'Robert Trent Jones Jr. mountain design'], imageAlt: 'Arrowhead Golf Club fairway through towering red rock formations near Denver', history: 'Arrowhead opened in 1972 in Littleton, Colorado, co-designed by Robert Trent Jones Sr. and Jr. Set among the same 300-million-year-old red sandstone formations as Red Rocks Amphitheatre. Now managed by Arcis Golf, consistently ranked among the most scenic courses in America.\n\nThe course sits at approximately 6,200 feet elevation in the Rocky Mountain foothills. Jones incorporated the massive formations into the design using boulders as natural hazards.', signatureHoles: [{ hole: 5, par: 4, yardage: 390, description: 'Massive red rock boulder defends the green, creating one of the most photographed holes.' }, { hole: 13, par: 3, yardage: 173, description: 'Signature hole. Steep downhill par 3 framed by towering red rock formations with panoramic views.' }, { hole: 15, par: 4, yardage: 380, description: 'Another hole defined by a massive boulder defending the green.' }, { hole: 18, par: 4, yardage: 420, description: 'Demanding finishing par 4 with mountain views.' }], whatToExpect: 'Bucket-list visual experience with 300-million-year-old formations towering over fairways. At 6,200 feet the ball flies about 10 percent further. Par-70 at 6,682 yards.', playingTips: 'Club down for altitude. Afternoon thunderstorms common in summer. Course plays firm and fast.', faqs: [{ question: 'Public?', answer: 'Yes. $75-$175.' }, { question: 'Near Red Rocks?', answer: 'Same geological formations, a few miles away.' }, { question: 'Designer?', answer: 'RTJ Sr. and Jr., opened 1972.' }, { question: 'Altitude?', answer: 'At 6,200 feet ball flies 10 percent further.' }] },
    { id: 'den-5', name: 'CommonGround Golf Course', slug: 'commonground-golf', city: 'Denver', state: 'Colorado', type: 'public', rating: 4.3, greensFee: '$40–$70', architect: 'Tom Doak', yearBuilt: 2009, holes: 18, par: 72, yardage: 7336, description: 'A Tom Doak municipal design in Aurora, CommonGround proves that world-class golf architecture and public accessibility are not mutually exclusive. The links-influenced layout features firm, fast conditions, creative green complexes, and Front Range mountain views — all at municipal pricing.', highlights: ['Tom Doak municipal design', 'Links-influenced firm and fast conditions', 'World-class architecture at public pricing'], imageAlt: 'CommonGround Golf Course Tom Doak links fairway with Denver mountain views', history: 'CommonGround was designed by Tom Doak and Renaissance Golf Design, opening in 2009 in Aurora. Doak transformed a former Air Force base course into a model public facility that serves as home of the Colorado Golf Association.\n\nThe USGA hosted the 2012 U.S. Amateur Public Links Championship here. Doak was given an uninspiring flat site and created what many consider the model for metropolitan public golf architecture.\n\nCommonGround handles about 40,000 rounds annually at municipal pricing, proving world-class design and public accessibility are compatible.', signatureHoles: [{ hole: 5, par: 4, yardage: 430, description: 'A strategic par 4 with multiple tee options. Doak\'s creative green complex rewards precise approaches.' }, { hole: 11, par: 3, yardage: 200, description: 'A challenging par 3 with firm conditions demanding a well-struck tee shot and Doak\'s characteristic contours.' }, { hole: 14, par: 5, yardage: 560, description: 'A risk-reward par 5 with strategic bunkering. Firm conditions allow long hitters to reach in two.' }, { hole: 18, par: 4, yardage: 445, description: 'A strong finisher with Front Range mountain views framing the approach.' }], whatToExpect: 'A links-influenced layout with firm, fast conditions unlike typical Colorado courses. Doak\'s green complexes reward imaginative shot-making. Front Range views provide a scenic backdrop.\n\nAt 7,336 yards at altitude the ball flies far. Walking is easy on the flat terrain.', playingTips: 'Use the ground game. Run approach shots onto greens rather than flying them. Firm surfaces bounce aerial attacks through.\n\nDenver altitude adds 10-15 percent to carry distances. Adjust club selection on par 3s especially.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Municipal course with fees from $40 to $70.' }, { question: 'Who designed it?', answer: 'Tom Doak and Renaissance Golf Design, 2009.' }, { question: 'Has it hosted championships?', answer: 'Yes. The 2012 U.S. Amateur Public Links Championship.' }, { question: 'Is it the CGA home course?', answer: 'Yes. Home of the Colorado Golf Association.' }] },
    { id: 'den-6', name: 'Bear Dance Golf Club', slug: 'bear-dance-golf', city: 'Denver', state: 'Colorado', type: 'public', rating: 4.4, greensFee: '$55–$120', architect: 'Keith Foster', yearBuilt: 2003, holes: 18, par: 72, yardage: 7750, description: 'At 7,750 yards from the tips (playing shorter at altitude), Bear Dance in Larkspur is one of the longest courses in Colorado. Keith Foster\'s design uses dramatic elevation changes through scrub oak and ponderosa pine with panoramic Front Range views on nearly every hole.', highlights: ['7,750 yards — one of Colorado\'s longest courses', 'Dramatic Front Range elevation changes', 'Keith Foster design in Larkspur'], imageAlt: 'Bear Dance Golf Club elevated tee with Rocky Mountain Front Range panorama', history: 'Bear Dance opened in 2003, designed by Keith Foster and carved through the timber of the Colorado Front Range south of Denver near Castle Rock/Larkspur. At approximately 7,750 yards from the tips, it is one of the longest courses in Colorado. The PGA Colorado Section is headquartered at Bear Dance.\n\nThe course consistently ranks among Colorado\\\'s best public courses. The front nine has a more open, links-style feel while the back nine plays through dense timber with dramatic mountain-style elevation swings — essentially two courses in one.', signatureHoles: [{ hole: 16, par: 4, yardage: 430, description: 'Widely cited as one of the best holes in Colorado. Plays from a severely elevated tee down to a valley fairway with a pond guarding the front of the green. The elevation drop is dramatic and the views are stunning.' }], whatToExpect: 'The front nine is open and links-style with less elevation change. The back nine transforms into mountain/forest golf through dense timber with significant elevation swings and stunning Front Range views. Greens run fast (stimping at 11-12).\n\nAt 7,750 yards from the tips (playing shorter at ~6,500 feet altitude where the ball carries roughly 10% farther), this is a genuine monster. Multiple tee sets make it playable for all levels, but tee selection is critical.\n\nExpect 4.5-5 hour rounds given the length and terrain.', playingTips: 'The altitude (~6,500 feet) adds roughly 10% to carry distances. Factor this into every club selection.\n\nPlay conservative on the back nine where trees tighten landing areas significantly compared to the open front.\n\nGreens are fast — respect the slopes and lag putt on unfamiliar surfaces.\n\nBring extra golf balls. The length and tight back nine demand them.\n\nTee selection is critical given the extreme yardage range. Don\\\'t play the tips unless you\\\'re a strong player.', faqs: [{ question: 'Is Bear Dance really 7,750 yards?', answer: 'Yes — one of the longest courses in Colorado. However, at 6,500 feet altitude the ball carries roughly 10% farther, so it plays somewhat shorter than the number suggests.' }, { question: 'What is the front nine vs back nine like?', answer: 'The front nine is open and links-style. The back nine transforms into mountain/forest golf through dense timber with dramatic elevation changes — essentially two courses in one.' }, { question: 'Who designed it?', answer: 'Keith Foster, opening in 2003. The PGA Colorado Section is headquartered at Bear Dance.' }]},
    { id: 'den-7', name: 'Fossil Trace Golf Club', slug: 'fossil-trace', city: 'Denver', state: 'Colorado', type: 'public', rating: 4.3, greensFee: '$55–$100', architect: 'Jim Engh', yearBuilt: 2003, holes: 18, par: 72, yardage: 6831, description: 'Built on a former clay mine in Golden, Fossil Trace features exposed 65-million-year-old fossils, dinosaur tracks, and leaf imprints throughout the layout. Jim Engh\'s creative design incorporates the geological features while delivering a quality golf experience with Table Mountain views.', highlights: ['65-million-year-old fossils visible on course', 'Jim Engh design in former clay mine', 'Unique geological features and Table Mountain views'], imageAlt: 'Fossil Trace Golf Club exposed fossil formations and Table Mountain in Golden Colorado', history: 'Fossil Trace opened in 2003, designed by Jim Engh on the site of a former clay mine and quarry in Golden, just west of Denver at the base of the Front Range foothills. The land contains trace fossils dating back approximately 64 million years — triceratops footprints, prehistoric palm frond impressions, and other fossils are visible adjacent to the playing surfaces, particularly around holes 11-15.\n\nThe name "Fossil Trace" is a reversal of "trace fossil," the paleontological term for the footprint impressions found on site. It is the only golf course in the world with visible dinosaur fossils integrated into the playing field.\n\nMunicipally owned by the City of Golden, Fossil Trace has been included among Golf Digest\\\'s most fun courses to play.', signatureHoles: [{ hole: 12, par: 5, yardage: 585, description: 'The undisputed signature hole and one of the most photographed in the United States. Sandstone monoliths rise from the center of the fairway, forcing players to choose a route over or around them. The back of the sandstone wall displays trace fossils of palm fronds and triceratops footprints.' }], whatToExpect: 'The front nine is more open and forgiving. The back nine (built within the old quarry) plays significantly tougher, with deep bunkers (some 12 feet deep), exposed rock walls, and old quarrying equipment scattered as decoration.\n\nThe fossil viewing areas around holes 11-15 are unique to golf anywhere in the world. Table Mountain provides a dramatic backdrop throughout. At 6,831 yards, accuracy matters more than distance.\n\nAs a City of Golden municipal course, it offers excellent value for a truly one-of-a-kind experience.', playingTips: 'On No. 12, know your carry distances precisely before deciding whether to challenge the sandstone monoliths. The conservative route is longer but safer.\n\nThe quarry-influenced back nine requires more target golf than the open front nine. Adjust your strategy at the turn.\n\nWinds funnel through the foothills unpredictably. Check conditions before exposed shots.\n\nThe course is shorter than many championship layouts — position and accuracy matter more than power.', faqs: [{ question: 'Are the dinosaur fossils real?', answer: 'Yes — 64-million-year-old trace fossils including triceratops footprints and palm frond impressions are visible adjacent to playing surfaces, particularly around holes 11-15. It is the only golf course in the world with this feature.' }, { question: 'What is the signature hole?', answer: 'No. 12 — sandstone monoliths rise from the center of the fairway, with trace fossils visible on the rock walls. One of the most photographed holes in the US.' }, { question: 'Who owns the course?', answer: 'The City of Golden — it is a municipally owned public course offering excellent value for a unique experience.' }]},
    { id: 'den-8', name: 'The Club at Pradera', slug: 'club-at-pradera', city: 'Denver', state: 'Colorado', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Jim Engh', yearBuilt: 2004, holes: 18, par: 72, yardage: 7437, description: 'A Jim Engh design in Parker south of Denver, Pradera is one of Colorado\'s most acclaimed newer private clubs. The layout occupies dramatic bluff terrain overlooking expansive prairie with Pikes Peak visible on clear days. Engh\'s bold, creative routing maximizes the natural drama.', highlights: ['Jim Engh bluff-top private design', 'Pikes Peak visible on clear days', 'Dramatic prairie overlook terrain'], imageAlt: 'Club at Pradera bluff-top fairway with Pikes Peak in the distance', history: 'The Club at Pradera opened in 2004, designed by Jim Engh as a private club in the rolling hills of Parker, Colorado, south of Denver. Engh drew on Irish links influences, blending them with the natural Colorado high-plains landscape of bluffs, native grasses, and open vistas.\n\nThe course plays approximately 7,200-7,260 yards from the tips with a 143 slope. Managed by Arcis Golf, the club shares a community with The Pinery Country Club, giving members access to 45 combined holes.\n\nViews of Pikes Peak and the Front Range are visible from multiple holes on clear days. The Irish links-style adaptation to the Colorado high plains creates a playing experience unlike anything else in the Denver metro.', signatureHoles: [{ hole: 7, par: 5, yardage: 550, description: 'A prime risk-reward hole cited as one of Engh\\\'s best designs. The aggressive line offers a chance to reach in two, but the penalty for missing is severe. The classic risk-reward decision that defines Engh\\\'s creative style.' }, { hole: 15, par: 3, yardage: 185, description: 'Features elevated tee boxes with dramatic views of the surrounding landscape. A confident downhill shot to the green with panoramic Front Range views.' }], whatToExpect: 'An Irish links-style layout adapted to the Colorado high plains. Many areas are left completely natural with wispy native grasses framing the holes. Picturesque ponds and rugged terrain add variety.\n\nGreens feature significant undulation and run very fast — lag putting is essential. The course feels adventurous and strategic, playable multiple ways depending on risk tolerance.\n\nAt approximately 6,000 feet elevation, the ball carries extra distance. The exposed hilltop holes are subject to regular wind.', playingTips: 'The greens are the biggest challenge — super fast with large undulations. Lag putting is essential. Don\\\'t leave yourself above the hole.\n\nThe Irish links influence means the ball can be played along the ground on many approaches. Don\\\'t automatically reach for the lob wedge.\n\nAt elevation (~6,000 feet), add roughly 10% to carry distances.\n\nWind is a regular factor on exposed hilltop holes. Check conditions before every shot on the open stretches.', faqs: [{ question: 'What is the design style?', answer: 'Irish links-style adapted to the Colorado high plains — wispy native grasses, bluffs, and open vistas. Unique for the Denver area.' }, { question: 'Who designed it?', answer: 'Jim Engh (who also designed nearby Fossil Trace), opening in 2004. Managed by Arcis Golf.' }, { question: 'Can the public play?', answer: 'No. Pradera is a private club. Members also have access to The Pinery Country Club\\\'s 27 holes (45 holes total).' }, { question: 'Are Pikes Peak views real?', answer: 'Yes — on clear days, Pikes Peak and the Front Range are visible from multiple holes.' }]},
    { id: 'den-9', name: 'Bear Dance Golf Club', slug: 'bear-dance-golf-club', city: 'Larkspur', state: 'Colorado', type: 'public', rating: 4.4, greensFee: '$55–$100', architect: 'Keith Foster', yearBuilt: 2003, holes: 18, par: 72, yardage: 7516, description: 'A Keith Foster design south of Denver in Larkspur, Bear Dance is consistently ranked the top public course in Colorado. The dramatic 7,516-yard layout through scrub oak foothills features significant elevation changes, spectacular Front Range views, and a rugged mountain character that evokes Colorado golf at its finest.', highlights: ['Consistently ranked #1 public course in Colorado', '7,516-yard layout through scrub oak foothills', 'Spectacular Front Range mountain views'], imageAlt: 'Bear Dance Golf Club foothill fairway with Front Range views south of Denver', history: 'The Golf Club at Bear Dance opened in 2002, designed by a group of four PGA of America members headed by Brian Whitcomb, who later served as PGA of America president from 2007 to 2008. The course was built in the scrub oak foothills of Larkspur, south of Denver, on dramatic terrain with significant elevation changes.\n\nBear Dance quickly established itself as Colorado\'s top daily-fee course, a ranking it has held for over eight consecutive years. The course serves as the home of the Colorado Section of the PGA of America. Heritage Golf Group acquired the property, bringing additional resources to maintain the championship-caliber conditions.\n\nThe 7,516-yard layout features generous tree-lined fairways framed by distinctive white sand bunkers, with the Front Range providing a spectacular backdrop. GOLF Magazine has recognized Bear Dance as one of the best courses in Colorado.', signatureHoles: [{ hole: 5, par: 5, yardage: 575, description: 'A sweeping par 5 with dramatic elevation change and Front Range views. Risk-reward decisions abound with the green reachable in two for long hitters.' }, { hole: 10, par: 4, yardage: 450, description: 'A challenging par 4 with a dramatic downhill tee shot through the scrub oak foothills. The views from the tee are among the best on the course.' }, { hole: 15, par: 3, yardage: 210, description: 'A demanding par 3 with significant elevation change affecting club selection. The white sand bunkers frame the green beautifully.' }, { hole: 18, par: 4, yardage: 460, description: 'A strong finishing hole that demands two quality shots to reach the green, with mountain views providing a dramatic conclusion.' }], whatToExpect: 'Bear Dance is a rugged mountain golf experience through scrub oak foothills with spectacular Front Range views. At 7,516 yards from the tips, it is one of the longest public courses in Colorado, though altitude compensates significantly. Five sets of tees accommodate all skill levels.\n\nThe white sand bunkers against the green foothills create striking visual contrast. Conditioning is excellent and the mountain setting provides a memorable experience beyond the golf itself.', playingTips: 'Altitude at Bear Dance adds significant distance to every shot. Club down from your normal selections, especially on the par 3s. The thin air also reduces spin, so shots may not hold greens as expected.\n\nElevation changes are dramatic. Pay attention to whether holes play uphill or downhill and adjust accordingly. The closing stretch is particularly demanding.', faqs: [{ question: 'Can the public play Bear Dance?', answer: 'Yes. It is a public daily-fee course with green fees from $55 to $100.' }, { question: 'Is it really the top public course in Colorado?', answer: 'Yes. Bear Dance has been ranked the top daily-fee course in the Denver area for over eight consecutive years.' }, { question: 'Who designed it?', answer: 'A team of four PGA of America members led by Brian Whitcomb, who later became PGA of America president.' }, { question: 'How far from Denver?', answer: 'Bear Dance is in Larkspur, approximately 45 minutes south of Denver.' }] },
    { id: 'den-10', name: 'Fossil Trace Golf Club', slug: 'fossil-trace-golf-club', city: 'Golden', state: 'Colorado', type: 'public', rating: 4.3, greensFee: '$55–$95', architect: 'Jim Engh', yearBuilt: 2003, holes: 18, par: 72, yardage: 6831, description: 'A Jim Engh design in Golden where real dinosaur footprints and leaf fossils are embedded in exposed rock formations on several holes, Fossil Trace is one of the most unique golf courses in America. The creative layout against the Front Range foothills blends geological wonder with challenging golf and stunning mountain views.', highlights: ['Real dinosaur fossils embedded in rock on course', 'Jim Engh creative design against Front Range', 'One of the most unique courses in America'], imageAlt: 'Fossil Trace Golf Club fairway with fossil formations and Front Range views in Golden', history: 'Fossil Trace opened in 2003, designed by Jim Engh on a former clay mine in Golden at the base of the Front Range foothills. The land contains 64-million-year-old trace fossils — triceratops footprints and prehistoric palm frond impressions are visible adjacent to playing surfaces, particularly holes 11-15. The only golf course in the world with visible dinosaur fossils integrated into the playing field.\n\nMunicipally owned by the City of Golden, the course name reverses "trace fossil," the paleontological term for the footprint impressions found on site. Golf Digest has included it among its most fun courses to play.', signatureHoles: [{ hole: 12, par: 5, yardage: 585, description: 'Sandstone monoliths rise from the center of the fairway, forcing players to choose a route over or around them. The back of the sandstone wall displays trace fossils of palm fronds and triceratops footprints — one of the most photographed holes in the US.' }], whatToExpect: 'The front nine is open and forgiving. The back nine (built within the old quarry) plays significantly tougher with deep bunkers (some 12 feet deep), exposed rock walls, and old quarrying equipment as decoration. Table Mountain provides a dramatic backdrop.\n\nAt 6,831 yards, accuracy matters more than distance. The fossil viewing areas around holes 11-15 are unique to golf anywhere in the world.', playingTips: 'On No. 12, know your carry distances before challenging the monoliths. The quarry back nine requires target golf. Winds funnel unpredictably through the foothills.', faqs: [{ question: 'Are the fossils real?', answer: 'Yes — 64-million-year-old trace fossils including triceratops footprints are visible on the course. The only golf course in the world with this feature.' }]},
    { id: 'den-11', name: 'Colorado Golf Club', slug: 'colorado-golf-club', city: 'Parker', state: 'Colorado', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Bill Coore & Ben Crenshaw', yearBuilt: 2007, holes: 18, par: 72, yardage: 7683, description: 'A Coore & Crenshaw design south of Denver that hosted the 2019 U.S. Mid-Amateur and the Solheim Cup, Colorado Golf Club features a treeless, links-style layout through rolling prairie at 6,200 feet elevation. The wide fairways, deep bunkers, and firm playing conditions create a strategic experience with panoramic Rocky Mountain views.', highlights: ['2019 U.S. Mid-Amateur and Solheim Cup host', 'Coore & Crenshaw prairie links design at 6,200 feet', 'Panoramic Rocky Mountain views from treeless terrain'], imageAlt: 'Colorado Golf Club Coore Crenshaw prairie fairway with Rocky Mountain views', history: 'Colorado Golf Club opened in 2007, designed by Bill Coore and Ben Crenshaw on rolling prairie terrain southeast of Denver at approximately 6,200 feet elevation. The minimalist design lets the natural landscape and panoramic Front Range views define the experience.\n\nDespite being under 20 years old, it has already hosted the 2010 Senior PGA Championship, the 2013 Solheim Cup (U.S. team recaptured the Cup), the 2019 U.S. Mid-Amateur, and the stroke play portion of the 2023 U.S. Amateur. Consistently ranked among the top courses in Colorado and top 100 in America. Course rating 75.5, slope 149.', signatureHoles: [{ hole: 1, par: 4, yardage: 430, description: 'Considered one of the great opening holes in American golf. Plays through a natural meadow that conceals subtle strategic options — the hole reveals little from the tee, forcing thoughtful decision-making from the first swing.' }, { hole: 11, par: 3, yardage: 214, description: 'A beautiful par 3 to a green fronted by the course\\\'s largest pond with expansive Rocky Mountain views behind. The combination of water, wind, and mountain backdrop makes it unforgettable.' }], whatToExpect: 'Wide-open, treeless prairie golf with panoramic Rocky Mountain views. Feels like Scottish links transplanted to the Colorado high plains. Native fescue rough is severe and punishes wayward shots harshly. Coore & Crenshaw greens feature subtle contours that reveal themselves over multiple rounds.\n\nWind is a constant factor on the exposed terrain. The 6,200-foot altitude adds roughly 10% to all distances. The firm, fast conditions reward a ground game.\n\nStrictly private — one of the most prestigious clubs in Colorado.', playingTips: 'Keep the ball in the fairway. Native fescue rough is nearly unplayable — accuracy over distance always.\n\nThe 6,200-foot altitude adds ~10% to all distances. Adjust every club selection.\n\nWind management is essential on the exposed prairie terrain. Check direction before every shot.\n\nThe firm conditions favor a ground game. Bump-and-run approaches are often more effective than lofted shots.', faqs: [{ question: 'What major events has it hosted?', answer: '2010 Senior PGA Championship, 2013 Solheim Cup, 2019 U.S. Mid-Amateur, and 2023 U.S. Amateur stroke play. Remarkable for a course opened in 2007.' }, { question: 'Who designed it?', answer: 'Bill Coore and Ben Crenshaw — the minimalist design duo behind Sand Hills, Streamsong, and many other top-ranked courses.' }, { question: 'Can the public play?', answer: 'No. Colorado Golf Club is strictly private.' }]},
  ],
  'san-francisco-california': [
    { id: 'sf-1', name: 'The Olympic Club - Lake Course', slug: 'olympic-club-lake', city: 'San Francisco', state: 'California', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Sam Whiting / Willie Watson', yearBuilt: 1924, holes: 18, par: 72, yardage: 6815, description: 'Host of five U.S. Opens, The Olympic Club\'s Lake Course is one of America\'s most demanding championship layouts. Set along the Pacific coast in the Daly City fog belt, the tight, tree-lined parkland course has famously produced upset champions and is considered one of the toughest courses in the country.', highlights: ['Five-time U.S. Open host', 'Legendary Pacific coast fog belt setting', 'One of America\'s toughest championship courses'], imageAlt: 'Olympic Club Lake Course tree-lined fairway in San Francisco fog', history: 'The Olympic Club was founded in 1860 as an athletic club, making it one of the oldest athletic organizations in the United States. The Lake Course was designed by Sam Whiting and Willie Watson and opened in 1924, carved through dense eucalyptus and cypress forest along the Pacific coast south of San Francisco.\n\nThe Lake Course has hosted five U.S. Opens in 1955, 1966, 1987, 1998, and 2012 and is famous for producing upset champions. Jack Fleck stunned Ben Hogan in a playoff in 1955, Billy Casper overcame Arnold Palmer in 1966, Scott Simpson edged Tom Watson in 1987, Lee Janzen won in 1998, and Webb Simpson took the 2012 title. The course also hosted the 1958 U.S. Amateur and the 2021 U.S. Women\'s Open.\n\nPrior to the 2012 U.S. Open, the club redesigned the par-3 eighth hole and converted the 16th from a par 5 to a par 4. Despite measuring under 7,200 yards, the Lake Course remains one of the most demanding tests in championship golf.', signatureHoles: [{ hole: 1, par: 5, yardage: 528, description: 'A classic opener sweeping downhill through a eucalyptus-lined corridor. The fairway narrows near the green, demanding an accurate lay-up or bold carry to reach in two.' }, { hole: 3, par: 3, yardage: 196, description: 'A demanding par 3 to a well-defended green surrounded by mature trees with subtle breaks difficult to read in the fog.' }, { hole: 16, par: 4, yardage: 670, description: 'Converted from a par 5 to a brutally long par 4 for championship play, one of the most talked-about holes in U.S. Open history requiring two enormous shots.' }, { hole: 18, par: 4, yardage: 347, description: 'A short but treacherous finisher with a fairway only 21 paces wide at its narrowest. The tiny target demands a precise tee shot and the well-guarded green can make or break a round.' }], whatToExpect: 'The Olympic Club Lake Course is a tight, tree-lined parkland course wrapped in coastal fog and eucalyptus. Fairways are narrow with punishing rough, and greens are small and well-defended. Despite measuring under 7,000 yards, the combination of fog, wind, tight corridors, and difficult green complexes makes this one of the hardest courses in the country.\n\nThe Pacific marine layer frequently rolls in, reducing visibility and making club selection challenging. Dense stands of Monterey cypress and eucalyptus create a cathedral-like atmosphere unlike any other championship venue.', playingTips: 'Accuracy off the tee is paramount. The fairways are narrow and the rough deep, so keeping the ball in the short grass is essential. Take one less club off the tee if needed to find the fairway.\n\nThe greens slope more than they appear, particularly in the fog. Trust your yardage numbers rather than your eyes. The closing stretch from 16 through 18 is one of the most demanding finishes in championship golf.', faqs: [{ question: 'Why does the Olympic Club produce so many upsets?', answer: 'Tight fairways, heavy rough, and challenging conditions neutralize length advantages, letting skilled ball-strikers compete with longer hitters. The fog and closing-hole pressure have historically produced dramatic finishes.' }, { question: 'Can the public play the Olympic Club?', answer: 'No. The Olympic Club is private and requires a member invitation. The course is visible to the public during USGA championship events.' }, { question: 'How many U.S. Opens has the Olympic Club hosted?', answer: 'Five: 1955 (Jack Fleck), 1966 (Billy Casper), 1987 (Scott Simpson), 1998 (Lee Janzen), and 2012 (Webb Simpson).' }, { question: 'Is the course really under 7,000 yards?', answer: 'Yes, typically around 6,815 yards. Its difficulty comes from tight fairways, dense rough, small greens, and challenging weather rather than length.' }] },
    { id: 'sf-2', name: 'San Francisco Golf Club', slug: 'san-francisco-golf-club', city: 'San Francisco', state: 'California', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'A.W. Tillinghast', yearBuilt: 1915, holes: 18, par: 71, yardage: 6726, description: 'An A.W. Tillinghast masterpiece hidden in the residential hills of San Francisco, SFGC is widely considered one of the 20 best courses in America. The compact layout features dramatic cypress-framed views, wildflower-dotted roughs, and some of Tillinghast\'s most creative green complexes.', highlights: ['A.W. Tillinghast masterpiece — top 20 in America', 'Cypress-framed Pacific views', 'Hidden residential San Francisco setting'], imageAlt: 'San Francisco Golf Club Tillinghast green with cypress trees and Pacific views', history: 'The San Francisco Golf Club was founded in 1895, making it one of the oldest golf clubs west of the Mississippi. The club initially played on a rudimentary course before settling at its current location near Lake Merced. In 1915, the legendary A.W. Tillinghast was commissioned to redesign the course, creating what many consider one of his finest and most underappreciated works.\n\nThe course occupies a remarkably private and secluded setting within the residential neighborhoods of San Francisco\'s west side. Tillinghast crafted a compact but brilliant routing that maximizes the natural terrain, featuring his trademark bold bunkering and inventive green complexes. The famous 7th hole, known as the "Duel Hole," overlooks the site where the last legal duel in California took place in September 1859.\n\nIn 2001, Tom Doak was brought in to restore the greens, and in 2006 he completed a restoration of the original 13th, 14th, and 15th holes, bringing the course back to Tillinghast\'s original vision. San Francisco Golf Club remains one of the most exclusive and least-photographed top courses in America, fiercely guarding its privacy while maintaining its place among the nation\'s elite.', signatureHoles: [{ hole: 7, par: 3, yardage: 190, description: 'Known as the "Duel Hole," this iconic par 3 overlooks the site of the last legal duel in California. The downhill tee shot plays to a narrow, kidney-shaped green surrounded by Tillinghast\'s dramatic bunkering with sweeping views beyond.' }, { hole: 2, par: 4, yardage: 435, description: 'A massive-scale par 4 that sets the tone for the round. The expansive fairway gives way to one of Tillinghast\'s boldest green complexes, perched above deep bunkers.' }, { hole: 18, par: 4, yardage: 410, description: 'A strong finishing hole that demands a well-placed drive and precise approach to a green protected by Tillinghast\'s artful bunkering, providing a dramatic conclusion to the round.' }, { hole: 4, par: 4, yardage: 430, description: 'A demanding par 4 that plays through a corridor of mature cypress trees to a green with complex contours, requiring both power and precision.' }], whatToExpect: 'San Francisco Golf Club offers an intimate and exclusive golf experience on one of the finest Tillinghast designs in existence. The compact layout is packed with strategic interest, featuring bold bunkering, inventive green complexes, and the natural beauty of mature cypress trees and wildflower-dotted roughs.\n\nThe course plays firm and fast, with the coastal climate keeping conditions cool year-round. The setting feels remarkably secluded despite being in the heart of San Francisco, and the lack of real estate development along the course boundaries preserves the timeless character of the design.', playingTips: 'Course management is essential at San Francisco Golf Club. Tillinghast designed the holes to reward strategic thinking over raw power, with many greens offering clear advantages for approaches from specific angles. Study the pin positions carefully and plan your tee shots accordingly.\n\nThe firm, fast conditions favor a ground game approach, particularly around the greens where bump-and-run shots are often more reliable than high-spinning wedges. The marine layer and ocean breezes add an extra dimension of challenge, so take an extra club when the wind is up.', faqs: [{ question: 'Can the public play San Francisco Golf Club?', answer: 'No, San Francisco Golf Club is an extremely private club. Access is limited to members and their invited guests.' }, { question: 'What is the Duel Hole?', answer: 'The famous 7th hole is known as the "Duel Hole" because it overlooks the site where the last legal duel in California was fought in September 1859 between U.S. Senator David Broderick and Judge David Terry.' }, { question: 'Who restored San Francisco Golf Club?', answer: 'Tom Doak completed a green restoration in 2001 and a broader restoration of holes 13, 14, and 15 in 2006, bringing the course back to Tillinghast\'s original design intent.' }] },
    { id: 'sf-3', name: 'TPC Harding Park', slug: 'tpc-harding-park', city: 'San Francisco', state: 'California', type: 'public', rating: 4.5, greensFee: '$80–$175', architect: 'Willie Watson / Tom Doak (renovation)', yearBuilt: 1925, holes: 18, par: 72, yardage: 7169, description: 'Host of the 2020 PGA Championship and Presidents Cup, Harding Park is one of America\'s finest municipal courses. Set along Lake Merced with eucalyptus and Monterey pine corridors, the renovated layout punches well above its municipal weight class.', highlights: ['2020 PGA Championship host', 'Presidents Cup venue', 'Premier municipal course on the West Coast'], imageAlt: 'TPC Harding Park championship fairway along Lake Merced in San Francisco', history: 'TPC Harding Park opened on July 18, 1925, named after President Warren G. Harding, an avid golfer who had died in San Francisco two years earlier. The original 18-hole course was designed by Sam Whiting and Willie Watson, the same duo responsible for the nearby Olympic Club Lake Course. Set along the shores of Lake Merced on the west side of San Francisco, Harding Park quickly became one of the most popular public courses in the city.\n\nThe course fell into disrepair during the 1990s but was dramatically restored in 2003 with help from architect Sandy Tatum and PGA Tour Design Services. This renovation returned championship caliber to the layout and attracted major professional events. The 2005 WGC-American Express Championship marked Harding Park\'s arrival on the world stage, followed by the 2009 Presidents Cup, the 2015 WGC-Match Play, and most notably the 2020 PGA Championship, won by Collin Morikawa.\n\nIn 2025, TPC Harding Park celebrated its centennial, cementing its status as one of the most storied municipal courses in America. The course joined the TPC network and continues to host PGA Tour events while remaining accessible to public golfers.', signatureHoles: [{ hole: 18, par: 4, yardage: 446, description: 'A demanding finishing hole that plays along Lake Merced with water guarding the left side. This hole has produced dramatic moments in PGA Championship and Presidents Cup history.' }, { hole: 16, par: 4, yardage: 453, description: 'A long par 4 with a narrow, tree-lined fairway that requires precision off the tee. The approach plays to a well-guarded green surrounded by mature cypress trees.' }, { hole: 7, par: 3, yardage: 185, description: 'A beautiful par 3 playing through a corridor of Monterey cypress to a green protected by deep bunkers. One of the most picturesque short holes in Bay Area golf.' }, { hole: 10, par: 4, yardage: 423, description: 'The opening hole of the back nine plays from an elevated tee down to a fairway framed by Lake Merced on the left and towering eucalyptus on the right.' }], whatToExpect: 'TPC Harding Park delivers a championship-caliber experience at municipal pricing. The course is beautifully conditioned and stretches to over 7,100 yards from the back tees, testing every club in the bag. Expect firm, well-maintained fairways lined with mature Monterey cypress and eucalyptus trees, with Lake Merced providing a scenic backdrop on several holes.\n\nThe marine layer and fog common to this part of San Francisco create cool, often breezy conditions that add challenge. Green fees are tiered, with San Francisco residents receiving discounted rates. Walking is permitted and the relatively flat terrain makes it manageable.', playingTips: 'Accuracy is paramount at TPC Harding Park. The tree-lined fairways punish wayward drives, and the firm, well-bunkered greens demand precise iron play. Take one extra club on approach shots when the wind is blowing in off the Pacific, which is most afternoons.\n\nBook your tee time well in advance, especially on weekends, as demand is high. San Francisco residents can access reduced rates by showing valid ID. Dress in layers, as morning fog often burns off by midday, and the temperature can swing significantly during a round.', faqs: [{ question: 'Is TPC Harding Park open to the public?', answer: 'Yes, TPC Harding Park is a public municipal course. San Francisco residents receive preferred rates, but anyone can book a tee time.' }, { question: 'What major tournaments has Harding Park hosted?', answer: 'TPC Harding Park hosted the 2020 PGA Championship, 2009 Presidents Cup, 2015 WGC-Match Play, and 2005 WGC-American Express Championship, among other notable events.' }, { question: 'How do I get the SF resident rate?', answer: 'San Francisco residents can access discounted green fees by presenting valid identification showing a San Francisco address when checking in.' }, { question: 'Is there a driving range at TPC Harding Park?', answer: 'Yes, TPC Harding Park has a full practice facility including a driving range, short game area, and putting greens.' }] },
    { id: 'sf-4', name: 'Pasatiempo Golf Club', slug: 'pasatiempo-golf-club', city: 'San Francisco', state: 'California', type: 'semi-private', rating: 4.7, greensFee: '$150–$300', architect: 'Alister MacKenzie', yearBuilt: 1929, holes: 18, par: 70, yardage: 6476, description: 'Alister MacKenzie\'s personal favorite among his designs (he built a home on the 6th fairway), Pasatiempo in Santa Cruz is a bucket-list course for architecture aficionados. The rolling layout features MacKenzie\'s trademark contoured greens, strategic bunkering, and a dramatic barranca crossing.', highlights: ['Alister MacKenzie\'s personal favorite design', 'MacKenzie built his home on the 6th fairway', 'Bucket-list course for architecture lovers'], imageAlt: 'Pasatiempo Golf Club MacKenzie barranca crossing in Santa Cruz', history: 'Pasatiempo opened in 1929, designed by Dr. Alister MacKenzie for Marion Hollins. MacKenzie built his home on the sixth fairway. Bobby Jones played the opening round and praised hole 16. Tom Doak restored original features in 2007.', signatureHoles: [{ hole: 6, par: 4, yardage: 395, description: 'Adjacent to MacKenzie\'s former home overlooking the fairway.' }, { hole: 11, par: 3, yardage: 170, description: 'Deep barranca fronts the green in a celebrated MacKenzie short hole.' }, { hole: 16, par: 4, yardage: 395, description: 'MacKenzie\'s self-proclaimed favorite hole in all of golf.' }, { hole: 18, par: 5, yardage: 520, description: 'Dramatic finisher with barranca crossing.' }], whatToExpect: 'A bucket-list experience with MacKenzie\'s rolling terrain, barrancas, and contoured greens. Cool Santa Cruz coastal weather.\n\nAt 6,476 yards par 70, green complexes are among the most challenging anywhere.', playingTips: 'Greens are the primary defense. Being on the correct tier is essential. Barrancas require confident carries.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Semi-private with fees from $150 to $300.' }, { question: 'Did MacKenzie live here?', answer: 'Yes, on the 6th fairway until 1934.' }, { question: 'What else did MacKenzie design?', answer: 'Augusta National, Cypress Point, Royal Melbourne.' }, { question: 'Has it been restored?', answer: 'Tom Doak led a 2007 restoration.' }] },
    { id: 'sf-5', name: 'Presidio Golf Course', slug: 'presidio-golf-course', city: 'San Francisco', state: 'California', type: 'public', rating: 4.2, greensFee: '$50–$120', architect: 'Robert Johnstone', yearBuilt: 1895, holes: 18, par: 72, yardage: 6477, description: 'Set within the Presidio National Park with views of the Golden Gate Bridge, this historic course is one of the most scenically located public courses in America. The eucalyptus and cypress-lined fairways offer a peaceful retreat from the city.', highlights: ['Golden Gate Bridge views from the course', 'Located within Presidio National Park', 'Historic public course dating to 1895'], imageAlt: 'Presidio Golf Course with Golden Gate Bridge visible in background', history: 'The Presidio Golf Course is one of the oldest golf courses west of the Mississippi, dating back to 1895 when it was established as a modest nine-hole layout within the active military post of the Presidio of San Francisco. The original course was designed by a group of San Francisco businessmen, with Robert Wood Johnstone credited as the primary architect. In those early days, green fees were just fifty cents.\n\nThe course was expanded to 18 holes in 1910 through a collaboration between Johnstone and William McEwan. For decades, the Presidio served as both a military recreation facility and a public golf course, hosting troop reviews for Theodore Roosevelt and serving as a gathering place for officers and civilians alike. The course was renovated and updated over the years, including work by Arnold Palmer Management Group after the Presidio was transferred from military to National Park Service control in 1994.\n\nToday, the Presidio Golf Course operates as a public facility within the Presidio National Park, offering one of the most unique golf experiences in America. The towering eucalyptus and Monterey cypress trees create cathedral-like corridors, and several holes offer stunning views of the Golden Gate Bridge, San Francisco Bay, and the Pacific Ocean.', signatureHoles: [{ hole: 1, par: 4, yardage: 380, description: 'An inviting opening hole that plays through a corridor of towering eucalyptus trees. A birdie opportunity that sets a welcoming tone for the round ahead.' }, { hole: 12, par: 3, yardage: 175, description: 'A scenic par 3 with views of the Golden Gate Bridge and San Francisco Bay. The elevated tee offers one of the most photogenic tee shots in Bay Area golf.' }, { hole: 8, par: 4, yardage: 420, description: 'A challenging dogleg par 4 through dense forest that demands a well-shaped tee shot and accurate approach to a green tucked among ancient trees.' }, { hole: 18, par: 4, yardage: 370, description: 'A reachable finishing hole that offers birdie opportunities to close the round on a high note, playing back toward the historic clubhouse.' }], whatToExpect: 'The Presidio Golf Course provides a uniquely peaceful golf experience within a national park in the heart of San Francisco. The course is sheltered by towering eucalyptus and Monterey cypress trees that create a serene, almost forest-like atmosphere just minutes from downtown. On clear days, several holes offer breathtaking views of the Golden Gate Bridge.\n\nThe layout is not overly long but demands accuracy through its tree-lined corridors. Conditions can be cool and foggy, particularly in the summer months when the marine layer settles over the western part of the city. The course is well-maintained and offers a great value for the quality and setting.', playingTips: 'Keeping the ball in the fairway is the primary challenge at the Presidio. The mature trees that line most holes will severely penalize errant drives, so leave the driver in the bag on tighter holes and prioritize position over distance.\n\nThe course is hilly in places, so be prepared for uneven lies. Club selection on approach shots should account for the cool, dense air that can reduce carry distance. Afternoon tee times often benefit from the fog burning off, providing clearer skies and warmer temperatures.', faqs: [{ question: 'Is the Presidio Golf Course open to the public?', answer: 'Yes, the Presidio Golf Course is a fully public course. Tee times can be booked online and are available to all golfers.' }, { question: 'Can you see the Golden Gate Bridge from the course?', answer: 'Yes, several holes offer views of the Golden Gate Bridge, particularly holes on the northern side of the course. Clear morning conditions provide the best views.' }, { question: 'Is the Presidio Golf Course walkable?', answer: 'The course has some significant elevation changes that can make walking challenging. Carts are available, but the tree-lined fairways make for a beautiful walk for those who are up for it.' }, { question: 'What is the best time to play the Presidio?', answer: 'Fall months (September through November) typically offer the warmest and clearest weather in San Francisco, providing the best playing conditions and views.' }] },
    { id: 'sf-6', name: 'California Golf Club of San Francisco', slug: 'california-golf-club-sf', city: 'San Francisco', state: 'California', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Alister MacKenzie / Kyle Phillips (restoration)', yearBuilt: 1926, holes: 18, par: 72, yardage: 6789, description: 'A recently restored Alister MacKenzie gem in South San Francisco, Cal Club has surged in rankings after Kyle Phillips\'s meticulous restoration of MacKenzie\'s original design intent. The rolling coastal terrain and creative green complexes now shine as the master architect intended.', highlights: ['Alister MacKenzie design restored by Kyle Phillips', 'Surging in national rankings post-restoration', 'Rolling coastal terrain south of San Francisco'], imageAlt: 'California Golf Club restored MacKenzie green complexes in South San Francisco', history: 'California Golf Club was founded in 1926 with Alister MacKenzie reworking a layout by A. Vernon Macan on rolling coastal terrain in South San Francisco. Over decades, trees encroached and alterations obscured MacKenzie\\\'s original vision.\n\nIn 2005, Kyle Phillips was brought in for what became one of the greatest golf course restorations in history. Phillips cleared trees, created five new holes (including a new par-4 2nd in the old practice range), restored MacKenzie\\\'s greens and bunkering using 1927 as the benchmark, and reimagined the routing. The course reopened in 2008.\n\nThe result was immediate: Cal Club surged from obscurity to No. 45 in GOLF\\\'s 2025-26 Top 100 World list, No. 36 Golfweek Classic, and No. 19 in North America. Now considered the third gem in the Bay Area golf trinity alongside Cypress Point and San Francisco Golf Club.', signatureHoles: [{ hole: 16, par: 3, yardage: 133, description: 'A short but devious par 3 in a back-to-back par-3 sequence — an under-utilized design feature found at great courses like Sand Hills and Cypress Point. Tests touch and creativity over pure power.' }, { hole: 7, par: 4, yardage: 395, description: 'A terrific match play hole with a tucked green that rewards a specific angle of attack. Demonstrates the strategic width that sets Cal Club apart from lesser designs.' }], whatToExpect: 'A course that feels simultaneously retro and modern after the Phillips restoration. Broad fairways, flamboyant MacKenzie-style bunkers, and expansive undulating greens. Plays firm and fast with treacherous green sites and very little punitive rough. Tumbling coastal terrain creates a varied routing.\n\nThe restoration is widely considered one of the greatest in golf history — returning Cal Club from a forgettable layout to a world-ranked masterpiece.\n\nStrictly private — one of the most exclusive clubs in the Bay Area.', playingTips: 'Firm, fast conditions favor a ground game. Bump-and-run approaches are often more effective than lofted shots to these MacKenzie greens.\n\nThe dramatic bunkering frames holes strategically — they are more visual than penal, but avoid them when possible.\n\nBeing on the correct portion of the large greens is essential. Wrong-side misses can leave 60+ foot putts.', faqs: [{ question: 'What makes the restoration so significant?', answer: 'Kyle Phillips\\\'s 2007-2008 restoration is considered one of the greatest in golf history. Cal Club surged from obscurity to a top-50 world ranking — now the third gem in the Bay Area trinity with Cypress Point and San Francisco GC.' }, { question: 'Who originally designed it?', answer: 'Alister MacKenzie (the architect of Augusta National, Cypress Point, and Royal Melbourne) reworked an A. Vernon Macan layout in 1926.' }, { question: 'Can the public play?', answer: 'No. California Golf Club is strictly private.' }]},
    { id: 'sf-7', name: 'Half Moon Bay Golf Links - Ocean Course', slug: 'half-moon-bay-ocean', city: 'San Francisco', state: 'California', type: 'resort', rating: 4.5, greensFee: '$150–$275', architect: 'Arthur Hills', yearBuilt: 1997, holes: 18, par: 72, yardage: 6732, description: 'Perched on bluffs overlooking the Pacific Ocean at the Ritz-Carlton Half Moon Bay, this Arthur Hills design offers some of the most dramatic ocean views in California golf. The closing holes along the cliff edge rival Pebble Beach for sheer visual drama.', highlights: ['Pacific Ocean cliff-edge closing holes', 'Ritz-Carlton resort setting', 'Rivals Pebble Beach for ocean drama'], imageAlt: 'Half Moon Bay Ocean Course cliff-edge hole overlooking the Pacific', history: 'The Ocean Course at Half Moon Bay Golf Links opened in 1997 at the Ritz-Carlton Half Moon Bay, designed by Arthur Hills. The cliff-edge closing holes along the Pacific Ocean instantly became some of the most photographed in California golf.\n\nHills created a layout that saves its most dramatic moments for the finish, with the final holes perched on bluffs high above the Pacific.', signatureHoles: [{ hole: 16, par: 4, yardage: 410, description: 'A dramatic cliff-edge par 4 along the Pacific bluffs with ocean on both sides.' }, { hole: 17, par: 3, yardage: 175, description: 'A stunning par 3 on the cliff edge with the Pacific crashing below. One of the most photographed holes in California.' }, { hole: 18, par: 4, yardage: 435, description: 'A spectacular finishing hole along the ocean cliffs with the Ritz-Carlton as a backdrop.' }, { hole: 5, par: 5, yardage: 530, description: 'A strategic par 5 that begins the course\'s transition toward the coast.' }], whatToExpect: 'Dramatic ocean-cliff golf at a Ritz-Carlton resort. The closing holes along the Pacific bluffs rival Pebble Beach for visual drama.\n\nAt 6,732 yards, ocean winds make it play longer. The inland holes are pleasant, but the oceanside stretch is the highlight.', playingTips: 'Ocean winds are fierce on the cliff-edge holes. Take extra club and keep the ball low.\n\nThe closing stretch is visually intimidating. Focus on your targets rather than the scenery.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Resort course at Ritz-Carlton Half Moon Bay, $150-$275.' }, { question: 'How does it compare to Pebble Beach?', answer: 'The cliff-edge closing holes rival Pebble Beach for visual drama, at a lower price point.' }, { question: 'Designer?', answer: 'Arthur Hills, opened 1997.' }] },
    { id: 'sf-8', name: 'Poppy Hills Golf Course', slug: 'poppy-hills', city: 'San Francisco', state: 'California', type: 'public', rating: 4.3, greensFee: '$100–$200', architect: 'Robert Trent Jones Jr. / Dye Designs (renovation)', yearBuilt: 1986, holes: 18, par: 71, yardage: 7002, description: 'Located on the Monterey Peninsula alongside Pebble Beach and Spyglass Hill, Poppy Hills is the NCGA\'s home course and part of the AT&T Pebble Beach Pro-Am rotation. The 2014 renovation by Dye Designs dramatically improved playability and aesthetics through the Del Monte Forest.', highlights: ['AT&T Pebble Beach Pro-Am venue', 'NCGA home course on the Monterey Peninsula', 'Renovated 2014 through Del Monte Forest'], imageAlt: 'Poppy Hills pine-lined fairway on the Monterey Peninsula', history: 'Poppy Hills opened in 1986, the first U.S. course owned by an amateur golf association (NCGA). Designed by Robert Trent Jones Jr. through the Del Monte Forest. Co-hosted the AT&T Pebble Beach Pro-Am 1991-2009. Jones Jr. renovated it in 2014.', signatureHoles: [{ hole: 6, par: 4, yardage: 395, description: 'A dogleg through Del Monte pines.' }, { hole: 10, par: 4, yardage: 420, description: 'Demanding par 4 showcasing the 2014 renovation.' }, { hole: 14, par: 3, yardage: 175, description: 'Scenic par 3 in a forest amphitheater.' }, { hole: 18, par: 5, yardage: 540, description: 'Reachable par 5 finisher through forest-lined fairway.' }], whatToExpect: 'Routed through towering Monterey pines with an intimate feel. The 2014 renovation created a more natural experience at 7,002 yards par 71.\n\nMore accessible and affordable than Pebble Beach neighbors.', playingTips: 'Keep the ball in fairways. Recovery from pines is difficult. Morning fog is common but clears by mid-morning.', faqs: [{ question: 'Can the public play?', answer: 'Yes. $100-$200. NCGA members get preferred rates.' }, { question: 'Pro-Am history?', answer: 'Co-hosted AT&T Pro-Am 1991-2009.' }, { question: 'Who owns it?', answer: 'The NCGA.' }, { question: 'Renovation?', answer: 'Jones Jr. renovated in 2014.' }] },
    { id: 'sf-9', name: 'Sharp Park Golf Course', slug: 'sharp-park-golf-course', city: 'Pacifica', state: 'California', type: 'public', rating: 4.0, greensFee: '$35–$55', architect: 'Alister MacKenzie', yearBuilt: 1932, holes: 18, par: 72, yardage: 6275, description: 'The only Alister MacKenzie-designed municipal course on the West Coast, Sharp Park in Pacifica sits between the Pacific Ocean and a coastal lagoon along the dramatic San Mateo County coast. The affordable layout offers classic MacKenzie strategic bunkering and green complexes in an unforgettable oceanside setting.', highlights: ['Only Alister MacKenzie municipal course on West Coast', 'Pacific Ocean and coastal lagoon setting', 'Affordable MacKenzie golf in Pacifica'], imageAlt: 'Sharp Park Golf Course MacKenzie oceanside fairway in Pacifica', history: 'Sharp Park was designed by Alister MacKenzie in 1931 and opened in 1932 on a former artichoke farm between the Pacific Ocean and Laguna Salada, a coastal lagoon. It is MacKenzie\\\'s only American seaside municipal course — the same architect who designed Augusta National, Cypress Point, and Royal Melbourne created this affordable public course.\n\nNicknamed "The Poor Man\\\'s Pebble Beach," Sharp Park has endured decades of controversy: environmentalists have pushed to close it due to habitat concerns for the San Francisco garter snake and California red-legged frog, while public golf advocates have fought to preserve this MacKenzie treasure. Owned by the City of San Francisco but located in Pacifica, about 10 miles south.', signatureHoles: [{ hole: 14, par: 4, yardage: 363, description: 'Plays alongside the Pacific Ocean with the coastal lagoon in view. One of the holes that best captures MacKenzie\\\'s seaside links intent — wind, ocean, and strategic bunkering create a classic experience.' }], whatToExpect: 'A semi-links layout set between the Pacific Ocean and Laguna Salada lagoon. Wind and weather dictate play as on any true seaside course. MacKenzie\\\'s characteristic rolling green contours provide the strategic defense.\n\nConditions can be inconsistent due to municipal budget constraints — manage expectations. But at $35-55 for an oceanside MacKenzie design, this is one of the great values in American golf.\n\nThe hillside stretch (holes 4-7) climbs up with challenging terrain and views, showcasing MacKenzie\\\'s ability to route through varied topography.', playingTips: 'Wind is the primary defense. The ocean exposure makes club selection critical on every hole.\n\nThe greens have more slope than they appear — MacKenzie\\\'s subtle contours reward careful reading.\n\nThe lagoon comes into play on several holes. Know your carry distances.\n\nThe course plays dramatically different calm vs. windy. Afternoon winds are typically stronger.', faqs: [{ question: 'Is this really designed by the Augusta National architect?', answer: 'Yes. Alister MacKenzie — designer of Augusta National, Cypress Point, and Royal Melbourne — created Sharp Park in 1932. It is his only seaside municipal course in America.' }, { question: 'Why is it called the Poor Man\\\'s Pebble Beach?', answer: 'An oceanside course by a legendary architect at municipal pricing ($35-55). Few courses anywhere offer this combination of design pedigree, ocean setting, and affordability.' }, { question: 'Is there controversy about the course?', answer: 'Yes — ongoing environmental debate about habitat for endangered species in the coastal lagoon. Public golf advocates have successfully fought to keep it open.' }]},
    { id: 'sf-10', name: 'San Francisco Golf Club', slug: 'san-francisco-golf-club', city: 'San Francisco', state: 'California', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'A.W. Tillinghast', yearBuilt: 1915, holes: 18, par: 71, yardage: 6799, description: 'An A.W. Tillinghast masterwork in the Harding Park area of San Francisco, the San Francisco Golf Club is one of the most exclusive and least-photographed top-50 courses in America. The Golden Age layout through coastal cypress and eucalyptus features Tillinghast\'s boldest bunkering and most dramatic green complexes.', highlights: ['A.W. Tillinghast top-50 ranked masterwork', 'One of America\'s most exclusive private clubs', 'Golden Age design through coastal cypress'], imageAlt: 'San Francisco Golf Club Tillinghast fairway through coastal cypress forest', history: 'The San Francisco Golf Club was founded in 1895, making it one of the oldest golf clubs west of the Mississippi. The club initially played on a rudimentary course before settling at its current location near Lake Merced. In 1915, the legendary A.W. Tillinghast was commissioned to redesign the course, creating what many consider one of his finest and most underappreciated works.\n\nThe course occupies a remarkably private and secluded setting within the residential neighborhoods of San Francisco\'s west side. Tillinghast crafted a compact but brilliant routing that maximizes the natural terrain, featuring his trademark bold bunkering and inventive green complexes. The famous 7th hole, known as the "Duel Hole," overlooks the site where the last legal duel in California took place in September 1859.\n\nIn 2001, Tom Doak was brought in to restore the greens, and in 2006 he completed a restoration of the original 13th, 14th, and 15th holes, bringing the course back to Tillinghast\'s original vision. San Francisco Golf Club remains one of the most exclusive and least-photographed top courses in America, fiercely guarding its privacy while maintaining its place among the nation\'s elite.', signatureHoles: [{ hole: 7, par: 3, yardage: 190, description: 'Known as the "Duel Hole," this iconic par 3 overlooks the site of the last legal duel in California. The downhill tee shot plays to a narrow, kidney-shaped green surrounded by Tillinghast\'s dramatic bunkering with sweeping views beyond.' }, { hole: 2, par: 4, yardage: 435, description: 'A massive-scale par 4 that sets the tone for the round. The expansive fairway gives way to one of Tillinghast\'s boldest green complexes, perched above deep bunkers.' }, { hole: 18, par: 4, yardage: 410, description: 'A strong finishing hole that demands a well-placed drive and precise approach to a green protected by Tillinghast\'s artful bunkering, providing a dramatic conclusion to the round.' }, { hole: 4, par: 4, yardage: 430, description: 'A demanding par 4 that plays through a corridor of mature cypress trees to a green with complex contours, requiring both power and precision.' }], whatToExpect: 'San Francisco Golf Club offers an intimate and exclusive golf experience on one of the finest Tillinghast designs in existence. The compact layout is packed with strategic interest, featuring bold bunkering, inventive green complexes, and the natural beauty of mature cypress trees and wildflower-dotted roughs.\n\nThe course plays firm and fast, with the coastal climate keeping conditions cool year-round. The setting feels remarkably secluded despite being in the heart of San Francisco, and the lack of real estate development along the course boundaries preserves the timeless character of the design.', playingTips: 'Course management is essential at San Francisco Golf Club. Tillinghast designed the holes to reward strategic thinking over raw power, with many greens offering clear advantages for approaches from specific angles. Study the pin positions carefully and plan your tee shots accordingly.\n\nThe firm, fast conditions favor a ground game approach, particularly around the greens where bump-and-run shots are often more reliable than high-spinning wedges. The marine layer and ocean breezes add an extra dimension of challenge, so take an extra club when the wind is up.', faqs: [{ question: 'Can the public play San Francisco Golf Club?', answer: 'No, San Francisco Golf Club is an extremely private club. Access is limited to members and their invited guests.' }, { question: 'What is the Duel Hole?', answer: 'The famous 7th hole is known as the "Duel Hole" because it overlooks the site where the last legal duel in California was fought in September 1859 between U.S. Senator David Broderick and Judge David Terry.' }, { question: 'Who restored San Francisco Golf Club?', answer: 'Tom Doak completed a green restoration in 2001 and a broader restoration of holes 13, 14, and 15 in 2006, bringing the course back to Tillinghast\'s original design intent.' }] },
    { id: 'sf-11', name: 'Presidio Golf Course', slug: 'presidio-golf-course', city: 'San Francisco', state: 'California', type: 'public', rating: 4.1, greensFee: '$40–$100', architect: 'Robert Johnstone', yearBuilt: 1895, holes: 18, par: 72, yardage: 6477, description: 'Nestled in the Presidio national park lands in San Francisco, this historic municipal course offers golf among towering eucalyptus and Monterey cypress with Golden Gate Bridge views. The Arnold Palmer Management-operated facility provides a unique urban golf experience within a national park at the gateway to one of the world\'s most beautiful cities.', highlights: ['Golf in Presidio national park with Golden Gate views', 'Towering eucalyptus and Monterey cypress forest', 'Historic municipal course dating to 1895'], imageAlt: 'Presidio Golf Course fairway through eucalyptus forest with Golden Gate Bridge views', history: 'The Presidio Golf Course is one of the oldest golf courses west of the Mississippi, dating back to 1895 when it was established as a modest nine-hole layout within the active military post of the Presidio of San Francisco. The original course was designed by a group of San Francisco businessmen, with Robert Wood Johnstone credited as the primary architect. In those early days, green fees were just fifty cents.\n\nThe course was expanded to 18 holes in 1910 through a collaboration between Johnstone and William McEwan. For decades, the Presidio served as both a military recreation facility and a public golf course, hosting troop reviews for Theodore Roosevelt and serving as a gathering place for officers and civilians alike. The course was renovated and updated over the years, including work by Arnold Palmer Management Group after the Presidio was transferred from military to National Park Service control in 1994.\n\nToday, the Presidio Golf Course operates as a public facility within the Presidio National Park, offering one of the most unique golf experiences in America. The towering eucalyptus and Monterey cypress trees create cathedral-like corridors, and several holes offer stunning views of the Golden Gate Bridge, San Francisco Bay, and the Pacific Ocean.', signatureHoles: [{ hole: 1, par: 4, yardage: 380, description: 'An inviting opening hole that plays through a corridor of towering eucalyptus trees. A birdie opportunity that sets a welcoming tone for the round ahead.' }, { hole: 12, par: 3, yardage: 175, description: 'A scenic par 3 with views of the Golden Gate Bridge and San Francisco Bay. The elevated tee offers one of the most photogenic tee shots in Bay Area golf.' }, { hole: 8, par: 4, yardage: 420, description: 'A challenging dogleg par 4 through dense forest that demands a well-shaped tee shot and accurate approach to a green tucked among ancient trees.' }, { hole: 18, par: 4, yardage: 370, description: 'A reachable finishing hole that offers birdie opportunities to close the round on a high note, playing back toward the historic clubhouse.' }], whatToExpect: 'The Presidio Golf Course provides a uniquely peaceful golf experience within a national park in the heart of San Francisco. The course is sheltered by towering eucalyptus and Monterey cypress trees that create a serene, almost forest-like atmosphere just minutes from downtown. On clear days, several holes offer breathtaking views of the Golden Gate Bridge.\n\nThe layout is not overly long but demands accuracy through its tree-lined corridors. Conditions can be cool and foggy, particularly in the summer months when the marine layer settles over the western part of the city. The course is well-maintained and offers a great value for the quality and setting.', playingTips: 'Keeping the ball in the fairway is the primary challenge at the Presidio. The mature trees that line most holes will severely penalize errant drives, so leave the driver in the bag on tighter holes and prioritize position over distance.\n\nThe course is hilly in places, so be prepared for uneven lies. Club selection on approach shots should account for the cool, dense air that can reduce carry distance. Afternoon tee times often benefit from the fog burning off, providing clearer skies and warmer temperatures.', faqs: [{ question: 'Is the Presidio Golf Course open to the public?', answer: 'Yes, the Presidio Golf Course is a fully public course. Tee times can be booked online and are available to all golfers.' }, { question: 'Can you see the Golden Gate Bridge from the course?', answer: 'Yes, several holes offer views of the Golden Gate Bridge, particularly holes on the northern side of the course. Clear morning conditions provide the best views.' }, { question: 'Is the Presidio Golf Course walkable?', answer: 'The course has some significant elevation changes that can make walking challenging. Carts are available, but the tree-lined fairways make for a beautiful walk for those who are up for it.' }, { question: 'What is the best time to play the Presidio?', answer: 'Fall months (September through November) typically offer the warmest and clearest weather in San Francisco, providing the best playing conditions and views.' }] },
  ],
  'tucson-arizona': [
    { id: 'tuc-1', name: 'Ventana Canyon Golf & Racquet Club - Mountain Course', slug: 'ventana-canyon-mountain', city: 'Tucson', state: 'Arizona', type: 'resort', rating: 4.6, greensFee: '$100–$200', architect: 'Tom Fazio', yearBuilt: 1987, holes: 18, par: 72, yardage: 6948, description: 'Set in the foothills of the Santa Catalina Mountains, Ventana Canyon\'s Mountain Course is a Tom Fazio desert masterpiece with the iconic island tee on the par-3 3rd hole — a shot from a rocky ledge to a green surrounded by saguaro-studded desert. The course offers dramatic elevation changes and mountain views on every hole.', highlights: ['Iconic island tee par-3 3rd hole', 'Tom Fazio desert foothills design', 'Santa Catalina Mountain views'], imageAlt: 'Ventana Canyon Mountain Course island tee with Santa Catalina Mountains', history: 'Ventana Canyon\\\'s Mountain Course opened in 1987, designed by Tom Fazio in the foothills of the Santa Catalina Mountains north of Tucson. It is one of two Fazio courses at the resort (alongside the Canyon Course), connected to the Loews Ventana Canyon Resort.\n\nThe course has been a fixture in Arizona golf tourism for nearly four decades, known primarily for the iconic par-3 3rd hole — a shot from a rocky ledge across a saguaro-studded desert canyon. LINKS Magazine consistently lists the 3rd among the best short par 3s in North America.', signatureHoles: [{ hole: 3, par: 3, yardage: 107, description: 'The most famous hole on the course and one of the most photographed in the American Southwest. At the course\\\'s highest point, the tee shot plays across a desert canyon studded with saguaro cactus to a seemingly impossibly small green. The distance is deceptively short (only a wedge) but the visual intimidation, canyon drop, and swirling wind make it unforgettable.' }], whatToExpect: 'Classic Fazio desert target golf through pristine Sonoran Desert in the Santa Catalina Mountain foothills. Dramatic elevation changes throughout — more holes play downhill than uphill. Depending on tee selection, forced carries over desert terrain range from minimal to demanding.\n\nThe par-3 3rd is the undisputed highlight, but the entire routing offers mountain views and desert beauty on every hole. Conditioning is consistently strong.\n\nSummer value rates can drop below $100 — excellent for a Fazio resort design of this quality.', playingTips: 'On the famous 3rd hole, the short distance is misleading. Wind swirls in the canyon and visual intimidation causes over-thinking. Pick a wedge and commit.\n\nDesert conditions: hydrate aggressively, use sunscreen, and consider summer tee times for significant savings.\n\nFirm greens require planning for rollout. Being below the hole is essential throughout.\n\nDesert air means the ball flies farther. Adjust club selection, especially on the par 3s.', faqs: [{ question: 'What is the famous hole?', answer: 'No. 3 — a par 3 of only ~107 yards playing across a saguaro-studded desert canyon from a rocky ledge. Despite the short distance, it is one of the most photographed and talked-about holes in the Southwest.' }, { question: 'Is it open to the public?', answer: 'Yes — as a resort course connected to Loews Ventana Canyon. Green fees range from under $100 (summer) to $200 (peak winter season).' }, { question: 'Who designed it?', answer: 'Tom Fazio, opening in 1987. One of two Fazio courses at Ventana Canyon (the other is the Canyon Course).' }]},
    { id: 'tuc-2', name: 'Arizona National Golf Club', slug: 'arizona-national', city: 'Tucson', state: 'Arizona', type: 'public', rating: 4.4, greensFee: '$50–$120', architect: 'Robert Trent Jones Jr.', yearBuilt: 1995, holes: 18, par: 71, yardage: 6785, description: 'A Robert Trent Jones Jr. design adjacent to the Saguaro National Park, Arizona National delivers desert golf with panoramic mountain views and close encounters with native wildlife. The course features dramatic elevation changes through saguaro-studded Sonoran terrain.', highlights: ['Adjacent to Saguaro National Park', 'RTJ Jr. desert design with elevation changes', 'Panoramic mountain and desert views'], imageAlt: 'Arizona National Golf Club with Saguaro National Park and mountain views', history: 'Arizona National Golf Club opened in 1996, designed by Robert Trent Jones Jr. in the foothills of the Santa Catalina Mountains, abutting Coronado National Forest and near Saguaro National Park. Voted Best Public Golf Course in Tucson, it serves as the home course for the University of Arizona golf program. Managed by Troon Golf.\n\nThe layout meanders up and down saguaro-capped hillsides with significant elevation changes throughout, offering panoramic desert and mountain views on nearly every hole.', signatureHoles: [{ hole: 9, par: 4, yardage: 400, description: 'A strategic par 4 where mid-fairway bunkers force a decision off the tee — sometimes requiring the driver to stay in the bag. Panoramic Catalina Mountain views frame the approach.' }], whatToExpect: 'A mountain-desert experience on manicured fairways with natural Sonoran terrain framing every hole. The layout rewards accuracy over distance with mid-fairway bunkers punishing blind aggression. Views of the Santa Catalinas are constant companions.\n\nPace of play can be slow during peak season (5+ hours reported). Peak rates run $120+; summer rates are significantly discounted.', playingTips: 'Club selection is critical due to elevation changes — shots play shorter uphill and longer downhill.\n\nWatch for mid-fairway traps that punish blind aggression off the tee. Sometimes the smart play is an iron.\n\nDesert air adds distance. Factor altitude into every club selection.\n\nSummer rates offer significant savings if you can handle the Tucson heat.', faqs: [{ question: 'Is it near Saguaro National Park?', answer: 'Yes — adjacent to the park and Coronado National Forest, creating an unspoiled desert setting with abundant saguaro cacti and wildlife.' }, { question: 'Who designed it?', answer: 'Robert Trent Jones Jr., opening in 1996. Managed by Troon Golf.' }, { question: 'Is it the University of Arizona home course?', answer: 'Yes — the U of A golf program plays here.' }]},
    { id: 'tuc-3', name: 'Gallery Golf Club - South Course', slug: 'gallery-south', city: 'Tucson', state: 'Arizona', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Tom Lehman & John Fought', yearBuilt: 2000, holes: 18, par: 71, yardage: 7190, description: 'A Tom Lehman and John Fought design in Marana that hosted the WGC-Accenture Match Play Championship. The South Course plays through pristine high Sonoran Desert terrain with mountain views and championship-caliber conditioning year-round.', highlights: ['Former WGC-Match Play host', 'Tom Lehman & John Fought design', 'Pristine high Sonoran Desert'], imageAlt: 'Gallery Golf Club South Course desert championship hole in Marana', history: 'Gallery Golf Club\\\'s South Course was designed by John Fought (with Tom Lehman collaborating on the North Course) and opened in December 2003 as a private club within the Dove Mountain community near Marana. The South Course hosted the WGC-Accenture Match Play Championship in 2007 and 2008, and later hosted LIV Golf Tucson in 2023.\n\nThe North Course (Lehman/Fought, 1998) complements the South to form a 36-hole facility. The South has been nominated for Golf Digest\\\'s 100 Best. Part of the 63-hole Clubs of Dove Mountain complex.', signatureHoles: [{ hole: 9, par: 5, yardage: 725, description: 'A massive downhill par 5 into the prevailing wind, well-bunkered with a lake in play. At 725 yards, it is one of the longest holes on any championship course. Widely cited as the signature hole.' }, { hole: 7, par: 4, yardage: 314, description: 'A driveable short par 4 that tempts aggressive play but punishes misses. Risk-reward at its best — the green is reachable but well-defended.' }], whatToExpect: 'The front nine starts downhill with panoramic canyon views. Surprisingly player-friendly for a championship venue, with imaginative layouts including par 3s with dual green options and wildly undulating putting surfaces.\n\nConditioning is consistently excellent. The high Sonoran Desert setting provides pristine terrain with mountain views throughout.\n\nPrivate — access limited to members and guests.', playingTips: 'Take advantage of downhill holes on the front nine for extra distance.\n\nWind is a significant factor, particularly on the back nine. Check conditions before each shot.\n\nGreen reading is essential — the undulations are more severe than they appear. Spend time on the practice green.\n\nThe 725-yard 9th is a genuine three-shot hole for everyone. Don\\\'t force heroics.', faqs: [{ question: 'Did it host the WGC Match Play?', answer: 'Yes — the South Course hosted the WGC-Accenture Match Play Championship in 2007 and 2008. LIV Golf Tucson was also held here in 2023.' }, { question: 'How long is the 9th hole?', answer: '725 yards — one of the longest holes on any championship course. A massive downhill par 5 into prevailing wind with a lake in play.' }, { question: 'Can the public play?', answer: 'No. Gallery is a private club. Part of the 63-hole Clubs of Dove Mountain complex.' }]},
    { id: 'tuc-4', name: 'Sewailo Golf Club', slug: 'sewailo-golf-club', city: 'Tucson', state: 'Arizona', type: 'resort', rating: 4.3, greensFee: '$60–$140', architect: 'Notah Begay III', yearBuilt: 2013, holes: 18, par: 72, yardage: 7363, description: 'Designed by Notah Begay III on the Pascua Yaqui tribal land, Sewailo (meaning "flower world") features 92 bunkers, 7 lakes, and a dramatic 7,363-yard desert layout. The course connects to Casino del Sol resort, making it a convenient Tucson golf-and-gaming option.', highlights: ['Notah Begay III design on tribal land', '92 bunkers and 7 lakes', 'Casino del Sol resort connected'], imageAlt: 'Sewailo Golf Club desert water feature and mountain backdrop in Tucson', history: 'Opened 2013 on Pascua Yaqui tribal land by Notah Begay III. Sewailo means flower world in Yaqui. 92 bunkers and 7 lakes.', signatureHoles: [{ hole: 7, par: 4, yardage: 440, description: 'Demanding par 4 with water.' }, { hole: 12, par: 3, yardage: 195, description: 'Par 3 over a lake.' }, { hole: 15, par: 5, yardage: 555, description: 'Risk-reward par 5.' }, { hole: 18, par: 4, yardage: 445, description: 'Strong mountain-backdrop finisher.' }], whatToExpect: 'Desert golf on tribal land with 92 bunkers and 7 lakes. At 7,363 yards, a serious test.', playingTips: 'Avoid the 92 bunkers. Desert air adds distance.', faqs: [{ question: 'Public?', answer: 'Yes. $60-$140.' }, { question: 'Sewailo meaning?', answer: 'Flower world in Yaqui.' }] },
    { id: 'tuc-5', name: 'Tucson National Resort - Catalina Course', slug: 'tucson-national-catalina', city: 'Tucson', state: 'Arizona', type: 'resort', rating: 4.3, greensFee: '$75–$150', architect: 'Bruce Devlin & Robert von Hagge', yearBuilt: 1962, holes: 18, par: 73, yardage: 7262, description: 'A historic desert resort course that hosted the PGA Tour\'s Tucson Open for decades, Tucson National at the Omni resort is one of Arizona\'s most storied layouts. The mature desert landscape and championship pedigree make it a Tucson golf institution.', highlights: ['Former PGA Tour Tucson Open host', 'Historic Omni resort course', 'Mature desert championship layout'], imageAlt: 'Tucson National Catalina Course championship fairway with desert mountains', history: 'The Catalina Course at Tucson National opened originally in 1961 and was redesigned by Robert von Hagge and Bruce Devlin in 1983. It is the historic home of the PGA Tour\\\'s Tucson Open, hosting over 30 Tour events from 1965 through 2006 — Geoff Ogilvy won the final edition in a playoff.\n\nPast Tucson Open champions include a who\\\'s who of golf history. The course also serves as the University of Arizona\\\'s home course for NCAA competition. Now part of the Omni Tucson National Resort, it plays as a par 73 at 7,262 yards.', signatureHoles: [{ hole: 18, par: 4, yardage: 443, description: 'One of the PGA Tour\\\'s historically toughest finishing holes. Water flanks both sides of the fairway with an elevated, well-guarded green. This is where Tucson Open rounds were won and lost for decades.' }], whatToExpect: 'A traditional parkland-style layout — more lush and tree-lined than typical Arizona desert courses. Fairly level terrain with tree-lined fairways, significant bunkering, and strategic water hazards. Rolling fairways of varying widths add variety.\n\nThe par-73 routing creates an unusual scoring dynamic. Championship pedigree from decades of PGA Tour competition is evident in the strategic challenge, particularly on the closing stretch.\n\nResort guests at the Omni have full access.', playingTips: 'This is a thinking player\\\'s course. Doglegs and water demand course management over raw power.\n\nThe finishing stretch (especially 18) is where rounds are made or broken. Save your concentration.\n\nThe course plays longer than expected due to the par-73 routing — don\\\'t be surprised by the extra hole\\\'s worth of difficulty.\n\nMature trees create defined corridors. Accuracy off the tee is paramount.', faqs: [{ question: 'Did it really host the PGA Tour?', answer: 'Yes — over 30 PGA Tour Tucson Open events from 1965 to 2006. Geoff Ogilvy won the final edition. Past champions include many of golf\\\'s biggest names.' }, { question: 'Why is it par 73?', answer: 'The von Hagge/Devlin redesign created a routing with five par 5s, giving the course an unusual par-73 total.' }, { question: 'Is it open to resort guests?', answer: 'Yes — Omni Tucson National Resort guests have full access to both the Catalina and Sonoran courses.' }]},
    { id: 'tuc-6', name: 'Dove Mountain - Saguaro Course at The Ritz-Carlton', slug: 'dove-mountain-saguaro', city: 'Tucson', state: 'Arizona', type: 'resort', rating: 4.5, greensFee: '$100–$225', architect: 'Jack Nicklaus', yearBuilt: 2006, holes: 18, par: 72, yardage: 7208, description: 'Part of the three-course Dove Mountain complex that hosted the WGC-Accenture Match Play, the Saguaro Course is a Jack Nicklaus design at The Ritz-Carlton Marana. The desert layout features wild elevation changes, boulder-strewn terrain, and Tortolita Mountain views.', highlights: ['Jack Nicklaus at The Ritz-Carlton Marana', 'WGC-Match Play host complex', 'Dramatic boulder and mountain terrain'], imageAlt: 'Dove Mountain Saguaro Course desert boulder terrain with Tortolita Mountains', history: 'The Saguaro Course at Dove Mountain (formerly the Ritz-Carlton Golf Club) is a Jack Nicklaus Signature Design that opened around 2008-2009 as one of three nines at the 27-hole Golf Club at Dove Mountain. The facility hosted the WGC-Accenture Match Play Championship for six years (2009-2014), with the Saguaro and Tortolita nines forming the championship 18.\n\nTiger Woods, Phil Mickelson, Rory McIlroy, and other stars competed here during the WGC years. Nicklaus designed the course specifically with match play in mind. The complex is now publicly accessible — no longer exclusive to Ritz-Carlton guests.', signatureHoles: [{ hole: 5, par: 4, yardage: 420, description: 'On the Saguaro nine — played beside a spectacular saguaro cactus forest with generously wide fairways that still demand testing approach shots. The massive saguaros framing the hole create one of the most visually stunning settings in Arizona golf.' }], whatToExpect: 'Three nines (Saguaro, Tortolita, Wild Burro) can be combined in any 18-hole configuration. The Saguaro nine is the flattest, laid out beside spectacular saguaro forests. The Tortolita provides dramatic elevation changes and mountain vistas. Nicklaus himself stated the Wild Burro contains some of the best five holes he ever designed.\n\nClassic Nicklaus design: flashed bunkering, complex green complexes with small effective putting surfaces, and strategic risk-reward decisions. Forgiving fairways but demanding approaches.\n\nNow publicly accessible at resort-level pricing ($100-225).', playingTips: 'Focus on approach shots and putting — the greens are the primary defense. Nicklaus greens here have significant undulation and small effective targets despite appearing larger.\n\nClub up on uphill holes on the Tortolita nine. The course shows beautifully but plays tougher than it looks around the greens.\n\nAsk which 18-hole combination is playing that day. The Saguaro/Tortolita pairing was the WGC championship routing.', faqs: [{ question: 'Did the WGC Match Play really happen here?', answer: 'Yes — six consecutive years (2009-2014). Tiger Woods, Phil Mickelson, Rory McIlroy, and the world\\\'s best competed on the Saguaro/Tortolita championship routing.' }, { question: 'Is it still Ritz-Carlton exclusive?', answer: 'No. The course is now publicly accessible — open to resort guests and daily-fee players.' }, { question: 'How many holes are there?', answer: '27 holes across three Nicklaus-designed nines: Saguaro, Tortolita, and Wild Burro. Any two combine for an 18-hole round.' }]},
    { id: 'tuc-7', name: 'Quarry Pines Golf Club', slug: 'quarry-pines', city: 'Tucson', state: 'Arizona', type: 'public', rating: 4.1, greensFee: '$35–$75', architect: 'Unknown', yearBuilt: 1997, holes: 18, par: 71, yardage: 6601, description: 'Built in a former quarry south of Tucson, Quarry Pines offers one of the best public golf values in southern Arizona. The compact layout uses the quarry\'s dramatic rock walls to frame several memorable holes, creating visual interest that belies its affordable green fees.', highlights: ['Former quarry setting with rock walls', 'Best value public golf in Tucson', 'Compact memorable layout'], imageAlt: 'Quarry Pines Golf Club quarry wall framing green in Tucson', history: 'Quarry Pines Golf Club is Arizona\'s only quarry golf course, built on the edge of a 90-plus acre, 100-foot-deep sand and gravel quarry in Marana near Tucson. Architect Brian Huntley designed the layout, which was later renovated to relocate ten holes into the old quarry, mostly on the back nine.\n\nThe quarry setting creates dramatic elevation changes and rock wall backdrops unlike anything else in southern Arizona golf. The course offers accessible public golf at affordable pricing while delivering a visually stunning experience.\n\nKemperSports was selected to manage the facility in 2024, bringing professional course management to maintain and improve the unique property.', signatureHoles: [{ hole: 10, par: 4, yardage: 380, description: 'The first hole playing into the quarry with 100-foot rock walls creating a dramatic amphitheater setting.' }, { hole: 13, par: 3, yardage: 165, description: 'A scenic par 3 within the quarry where rock walls frame the green and create a unique enclosed atmosphere.' }, { hole: 15, par: 4, yardage: 400, description: 'A challenging par 4 using the quarry elevation changes. The approach plays significantly downhill to a green surrounded by rock formations.' }, { hole: 18, par: 5, yardage: 525, description: 'A finishing par 5 that climbs out of the quarry, providing a dramatic conclusion with views across the Tucson valley.' }], whatToExpect: 'The quarry holes are the star attraction. Playing 100 feet below the surrounding terrain with massive rock walls as backdrops is unlike any other golf experience in Arizona. The non-quarry holes play through more traditional desert terrain.\n\nAt 6,601 yards par 71, the course is not brutally long. The value is exceptional for the visual drama provided.', playingTips: 'The quarry holes play differently from the surface holes due to wind patterns and elevation. Shots within the quarry are sheltered from wind but elevation changes affect distance.\n\nDesert heat in summer is intense. Early morning tee times and adequate hydration are essential from May through September.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Green fees from $35 to $75, making it one of Tucson\'s best values.' }, { question: 'Is it really in a quarry?', answer: 'Yes. Arizona\'s only quarry golf course, built on a 90-plus acre, 100-foot-deep former sand and gravel quarry.' }, { question: 'Who designed it?', answer: 'Brian Huntley designed the original layout with ten holes relocated into the quarry.' }, { question: 'How far from Tucson?', answer: 'Located in Marana just off Interstate 10, easily accessible from anywhere in the Tucson metro area.' }] },
    { id: 'tuc-8', name: 'Omni Tucson National - Sonoran Course', slug: 'tucson-national-sonoran', city: 'Tucson', state: 'Arizona', type: 'resort', rating: 4.2, greensFee: '$65–$130', architect: 'Tom Lehman', yearBuilt: 2004, holes: 18, par: 70, yardage: 6585, description: 'The sister course to the Catalina at Omni Tucson National, the Sonoran Course is a Tom Lehman design that offers a slightly shorter, more strategic desert experience. The layout winds through pristine Sonoran terrain with mountain views and challenging green complexes.', highlights: ['Tom Lehman strategic desert design', 'Part of Omni Tucson National resort', 'Pristine Sonoran terrain'], imageAlt: 'Omni Tucson National Sonoran Course desert fairway with mountain views', history: 'The Sonoran Course at Omni Tucson National was designed by Tom Lehman (2006 Ryder Cup Captain) and opened in December 2005. Lehman replaced the original 27 non-tournament holes designed by Bruce Devlin and Robert von Hagge with this all-new 18-hole desert-style layout, complementing the parkland Catalina Course next door.\n\nThe result is a modern desert-forward design contrasting sharply with the traditional parkland Catalina. At par 70 and 6,585 yards, it offers a more strategic, shorter test with 69 bunkers and significant elevation changes.', signatureHoles: [{ hole: 15, par: 5, yardage: 515, description: 'The signature hole — only 515 yards but plays 100% uphill, making it feel significantly longer. A daunting test of patience and course management. Plan for 2-3 extra clubs on the approach.' }], whatToExpect: 'A desert-style layout contrasting the parkland Catalina next door. Features 2 lakes and 69 strategically placed bunkers over undulating terrain with steep mountain backdrops and Santa Catalina Mountain views throughout.\n\nMore open than many Arizona desert courses — you won\\\'t face constant forced carries over desert wash. The undulating terrain means few flat lies. Par 70 creates a tighter scoring challenge.\n\nResort guests have access to both the Sonoran and Catalina courses.', playingTips: 'Play fall through spring for best conditions — summer heat in Tucson is extreme.\n\nThe undulating terrain means few flat lies. Practice uneven-stance shots.\n\nThe uphill par-5 15th plays 2-3 clubs longer than the yardage. Don\\\'t underestimate it.\n\nThe 69 bunkers are the primary hazard. Keep the ball in the fairway and you\\\'ll score well.', faqs: [{ question: 'How does the Sonoran compare to the Catalina?', answer: 'The Sonoran is a modern desert-style layout (par 70, shorter) while the Catalina is a traditional parkland course (par 73, longer) with PGA Tour history. They complement each other well.' }, { question: 'Who designed it?', answer: 'Tom Lehman, the 2006 Ryder Cup Captain. It opened in 2005 as a replacement for the original non-tournament holes.' }, { question: 'Is it open to the public?', answer: 'Yes — Omni Tucson National resort guests and daily-fee players have access at $65-130.' }]},
    { id: 'tuc-9', name: 'Raven Golf Club at Sabino Springs', slug: 'raven-sabino-springs', city: 'Tucson', state: 'Arizona', type: 'public', rating: 4.1, greensFee: '$40–$90', architect: 'Robert Trent Jones Jr.', yearBuilt: 1994, holes: 18, par: 71, yardage: 6899, description: 'An RTJ Jr. design in the Sabino Canyon area of northeast Tucson, the Raven at Sabino Springs features a target-style desert layout through the Santa Catalina Mountain foothills. The par-71 blends dramatically with the native Sonoran terrain while offering generous fairways and strategic bunker complexes at an accessible daily-fee price point.', highlights: ['RTJ Jr. target-style desert design', 'Santa Catalina Mountain foothill setting', 'Accessible daily-fee pricing in northeast Tucson'], imageAlt: 'Raven Golf Club at Sabino Springs desert fairway with Santa Catalina Mountain views', history: 'Originally opened as The Raven Golf Club at Sabino Springs in the mid-1990s, designed by Robert Trent Jones Jr. on 430 acres of natural Sonoran Desert in the Santa Catalina Mountain foothills adjacent to Coronado National Forest. The course was later rebranded as Arizona National Golf Club.\n\nNamed to Golf Magazine\\\'s "Top 100 Courses You Can Play" and voted best public course in Tucson. The nine natural springs on the property influenced the routing, creating water features throughout. Serves as host for USGA qualifying events.', signatureHoles: [{ hole: 4, par: 3, yardage: 180, description: 'Elevated tee with panoramic valley views stretching toward the Mexican border. Bunkers demand precision on this scenic one-shotter.' }, { hole: 18, par: 4, yardage: 420, description: 'An elevated tee with an intimidating water hazard left and sweeping desert scenery to finish. A strong, memorable closer.' }], whatToExpect: 'A true desert layout winding through mesquite-lined arroyos, rock outcroppings, saguaro forests, and nine natural springs. Bent grass greens are mostly flat with subtle undulations.\n\nBreathtaking mountain-to-valley vistas throughout. The desert penalties are severe for wayward shots, but fairways are generally generous for accurate players.', playingTips: 'Most putts break away from the mountain, even when your eyes disagree. Trust the read.\n\nLay up before water hazards on holes 2 and 8. Hole 15 has a visual illusion where the green appears to slope one direction but breaks away from the mountain.\n\nDesert air adds distance. Choose tees wisely — the penalties for missing fairways are severe.', faqs: [{ question: 'Is this the same as Arizona National?', answer: 'Yes — originally opened as The Raven Golf Club at Sabino Springs, it was later rebranded as Arizona National Golf Club.' }, { question: 'Who designed it?', answer: 'Robert Trent Jones Jr. The course sits on 430 acres with nine natural springs in the Santa Catalina Mountain foothills.' }]},
    { id: 'tuc-10', name: 'Ventana Canyon Golf - Mountain Course', slug: 'ventana-canyon-mountain', city: 'Tucson', state: 'Arizona', type: 'resort', rating: 4.4, greensFee: '$80–$175', architect: 'Tom Fazio', yearBuilt: 1988, holes: 18, par: 72, yardage: 6836, description: 'A Tom Fazio resort design at The Lodge at Ventana Canyon in the Catalina Mountain foothills, the Mountain Course is famous for its signature par-3 3rd hole that plays over a desert canyon to a green backed by towering rock formations. The layout through pristine Sonoran Desert features saguaro-lined fairways and stunning mountain scenery.', highlights: ['Famous par-3 3rd hole over desert canyon', 'Tom Fazio resort design in Catalina foothills', 'Pristine Sonoran Desert saguaro-lined fairways'], imageAlt: 'Ventana Canyon Mountain Course famous par 3 over desert canyon in Tucson', history: 'The Mountain Course at Ventana Canyon opened in 1988, designed by Tom Fazio in the foothills of the Santa Catalina Mountains. Connected to The Lodge at Ventana Canyon, it is best known for the iconic par-3 3rd hole — a shot from a rocky ledge across a saguaro-studded desert canyon to a seemingly impossible green.\n\nThe course has been a cornerstone of Tucson resort golf for over 35 years. LINKS Magazine consistently lists the 3rd among the best short par 3s in North America.', signatureHoles: [{ hole: 3, par: 3, yardage: 107, description: 'One of the most photographed holes in the American Southwest. At the course\\\'s highest point, the tee shot plays across a desert canyon studded with saguaro cactus. The distance is deceptively short (a wedge) but the visual intimidation, canyon drop, and swirling wind make it unforgettable.' }], whatToExpect: 'Classic Fazio desert target golf through pristine Sonoran Desert in the Catalina foothills. More holes play downhill than uphill. The par-3 3rd is the undisputed highlight, but mountain views and desert beauty appear on every hole.\n\nConditioning is consistently strong. Summer rates drop below $100 — great value for Fazio resort quality.', playingTips: 'On the famous 3rd, the short distance is misleading. Wind swirls in the canyon. Pick a wedge and commit.\n\nFirm greens require planning for rollout. Stay below the hole throughout.\n\nDesert air means extra distance. Adjust club selection accordingly.', faqs: [{ question: 'What is the famous hole?', answer: 'No. 3 — a par 3 of only ~107 yards across a saguaro-studded desert canyon from a rocky ledge. Despite the short distance, it is one of the most talked-about holes in the Southwest.' }, { question: 'Is it open to the public?', answer: 'Yes — resort guests and daily-fee players. Connected to The Lodge at Ventana Canyon.' }]},
    { id: 'tuc-11', name: 'Forty Niner Country Club', slug: 'forty-niner-cc', city: 'Tucson', state: 'Arizona', type: 'semi-private', rating: 4.0, greensFee: '$30–$65', architect: 'Red Lawrence', yearBuilt: 1959, holes: 18, par: 72, yardage: 6763, description: 'A Red Lawrence design in south Tucson, Forty Niner Country Club offers semi-private access to a well-maintained desert course with mountain views and an inviting community atmosphere. The mature layout features strategic water hazards, established desert vegetation, and affordable pricing that has kept it a local favorite for over sixty years.', highlights: ['Affordable semi-private desert golf since 1959', 'Mature layout with established desert vegetation', 'Local favorite with community atmosphere'], imageAlt: 'Forty Niner Country Club mature desert fairway in south Tucson', history: 'Forty Niner Country Club opened in 1959, designed by Red Lawrence — one of the pioneering golf course architects of the American Southwest. The semi-private club in south Tucson has been a local favorite for over sixty years, offering affordable desert golf with mountain views and a welcoming community atmosphere.\n\nThe mature layout features established desert vegetation that has grown in over six decades, creating defined corridors and a settled, classic feel uncommon in the newer resort-style courses that dominate the Tucson market.', signatureHoles: [{ hole: 9, par: 4, yardage: 390, description: 'A well-designed par 4 with strategic water that tests course management. The mature desert vegetation frames the hole beautifully — a highlight of the front nine.' }], whatToExpect: 'A mature, established desert course with over 60 years of growth creating defined corridors and a classic feel. Strategic water hazards add challenge without overwhelming. Mountain views throughout.\n\nAt $30-65, this is among the most affordable golf in Tucson. The community atmosphere is welcoming and unpretentious. Semi-private access means public tee times are available.', playingTips: 'The mature vegetation creates tighter corridors than newer desert courses. Accuracy off the tee matters.\n\nStrategic water hazards reward course management. Know where the hazards are and play away from them.\n\nThe affordable pricing makes it ideal for a second round in a Tucson golf trip — less pressure, more enjoyment.', faqs: [{ question: 'How affordable is it?', answer: 'At $30-65, Forty Niner is among the most affordable courses in Tucson. Great value for a mature, well-maintained layout.' }, { question: 'Is it open to the public?', answer: 'Semi-private — public tee times are available alongside member play.' }, { question: 'Who designed it?', answer: 'Red Lawrence, one of the pioneering Southwest golf architects. The course opened in 1959.' }]},
  ],
  'portland-oregon': [
    { id: 'por-1', name: 'Bandon Dunes Golf Resort - Pacific Dunes', slug: 'pacific-dunes', city: 'Portland', state: 'Oregon', type: 'resort', rating: 5.0, greensFee: '$275–$395', architect: 'Tom Doak', yearBuilt: 2001, holes: 18, par: 71, yardage: 6633, description: 'Widely ranked as the #1 public course in America, Pacific Dunes is Tom Doak\'s links masterpiece perched on the bluffs above the Pacific Ocean at Bandon Dunes Resort. The routing — which hugs the cliff edge for multiple holes — recalls the great seaside links of Scotland and Ireland, but in an utterly wild Oregon setting.', highlights: ['#1 public course in America', 'Tom Doak clifftop links masterpiece', 'Oregon Pacific coast bluff-edge routing'], imageAlt: 'Pacific Dunes cliff-edge hole above the Pacific Ocean at Bandon Dunes Resort', history: 'Pacific Dunes was designed by Tom Doak and opened in 2001 as the second course at Bandon Dunes Golf Resort on the southern Oregon coast. Resort founder Mike Keiser gave Doak spectacular oceanfront land with coastal bluffs, native gorse, and rolling dune terrain. Doak routed the course to maximize ocean exposure, with multiple holes playing directly along the cliff edge.\n\nThe course rose quickly to claim the number-one public course ranking in America. Pacific Dunes is often cited as the layout that elevated Bandon Dunes from a remarkable resort to a pilgrimage destination. Unlike the original Bandon Dunes course by David McLay Kidd, Pacific Dunes maintains extended contact with the bluffs, creating a visual and strategic experience that rivals the great seaside links of the British Isles.', signatureHoles: [{ hole: 11, par: 3, yardage: 148, description: 'A postcard par 3 perched on the ocean bluffs with the Pacific crashing below. The green sits on a promontory above the sea, and the wind makes this short iron one of the most consequential shots in golf.' }, { hole: 13, par: 4, yardage: 444, description: 'A stunning par 4 along the cliff edge with the Pacific to the left. The fairway tilts toward the bluffs, and the approach must find a well-bunkered green with ocean views in every direction.' }, { hole: 4, par: 4, yardage: 463, description: 'Plays entirely on the bluffs overlooking the Pacific. The drive navigates fairway bunkers, and the approach plays to a green perched above the coastline.' }, { hole: 6, par: 4, yardage: 288, description: 'A brilliant short par 4 that tempts players to drive the green. The fairway is nearly 90 yards wide, but the tiny green punishes anything less than precise.' }], whatToExpect: 'Pacific Dunes is a walking-only links course on the Oregon coast bluffs. The routing alternates between oceanfront holes with breathtaking Pacific views and interior holes through native gorse and dune terrain. At 6,633 yards, it is not long, but constant wind, firm conditions, and strategic greens create a demanding test.\n\nThe setting is wild and remote. Caddies are available and highly recommended. The walking-only policy adds to the links authenticity.', playingTips: 'Wind is the defining feature. Expect constant ocean breezes of 20-30 mph and plan club selection accordingly. The course rewards ground-game creativity — bump-and-run approaches, low shots, and use of slopes around greens.\n\nA caddie\'s local knowledge is invaluable for reading greens and managing the wind.', faqs: [{ question: 'Is Pacific Dunes really the number-one public course in America?', answer: 'It consistently ranks at or near the top of every major ranking. It is universally considered among the best two or three public courses in America.' }, { question: 'Can I ride a cart at Pacific Dunes?', answer: 'No. All courses at Bandon Dunes are walking only. Caddies are available and pull carts are permitted.' }, { question: 'How do I get to Bandon Dunes?', answer: 'The resort is in Bandon, Oregon, about 5 hours south of Portland. The closest airport is North Bend/Coos Bay (OTH), about 30 minutes away.' }, { question: 'How many courses are at Bandon Dunes Resort?', answer: 'Five full 18-hole courses: Bandon Dunes, Pacific Dunes, Old Macdonald, Bandon Trails, and Sheep Ranch, plus the Bandon Preserve par-3 course.' }] },
    { id: 'por-2', name: 'Bandon Dunes Golf Resort - Bandon Dunes', slug: 'bandon-dunes-course', city: 'Portland', state: 'Oregon', type: 'resort', rating: 4.8, greensFee: '$275–$395', architect: 'David McLay Kidd', yearBuilt: 1999, holes: 18, par: 72, yardage: 6732, description: 'The course that started it all — David McLay Kidd\'s original Bandon Dunes layout put Oregon on the world golf map. The links-style design on the rugged southern Oregon coast features tumbling dune terrain, gorse-lined fairways, and multiple oceanfront holes that define bucket-list golf.', highlights: ['The original course that launched Bandon Dunes', 'David McLay Kidd links design', 'Oceanfront dune terrain on Oregon coast'], imageAlt: 'Bandon Dunes course ocean-side hole through dune grass on Oregon coast', history: 'Bandon Dunes opened on May 19, 1999, as the first course at what would become America\'s greatest golf resort. Chicago entrepreneur Mike Keiser hired David McLay Kidd, a relatively untested 25-year-old Scotsman whose father was the head agronomist at Gleneagles, to design the inaugural course on spectacular dunesland perched 100 feet above the Pacific Ocean.\n\nThe course was an immediate sensation, proving that American golfers were hungry for authentic links golf. Bandon Dunes featured walking-only play, no real estate development, and a wild coastal setting that felt more like Scotland than the Pacific Northwest. Kidd\'s design prompted Keiser to add Pacific Dunes (2001), Bandon Trails (2005), Old Macdonald (2010), and Sheep Ranch (2020).\n\nKidd\'s original layout remains a fan favorite and holds a special place as the design that launched a revolution in American resort golf, proving that a remote coastal location could draw golfers from around the world.', signatureHoles: [{ hole: 16, par: 4, yardage: 363, description: 'A beloved short par 4 along the ocean bluff. Depending on the wind, this hole can be drivable. The approach plays slightly uphill to a green framed by the coastline.' }, { hole: 5, par: 5, yardage: 472, description: 'Known as Hog\'s Back, this reachable par 5 features a narrow elevated fairway ridge with steep falloffs on both sides and a risk-reward second shot.' }, { hole: 12, par: 3, yardage: 205, description: 'A Redan-inspired par 3 that plays into the prevailing wind. The green angles away from the player and the ball must be worked right to left to hold the surface.' }, { hole: 4, par: 4, yardage: 425, description: 'The first hole to reveal the full Pacific Ocean panorama. The fairway runs along the bluffs with breathtaking views.' }], whatToExpect: 'Bandon Dunes is a walking-only links course on the rugged southern Oregon coast, set atop bluffs 100 feet above the Pacific. The routing weaves between oceanfront holes and interior holes through native gorse and dune terrain. At 6,732 yards it is not overwhelmingly long, but ever-present coastal wind and firm conditions make club selection a constant puzzle.\n\nThe course has a wild, natural feel with no cart paths and gorse bushes that punish wayward shots. Caddies are available and recommended.', playingTips: 'Wind is the dominant factor on every shot. The prevailing wind comes from the north-northwest, but ocean breezes swirl throughout the round. Bring low-trajectory punch shots and expect to adjust club selection significantly.\n\nKeep the ball in play off the tee — gorse bushes mean a lost ball. Favor the wide side of fairways. A caddie\'s local knowledge is invaluable for first-time visitors.', faqs: [{ question: 'Is Bandon Dunes walking only?', answer: 'Yes. All courses at Bandon Dunes Golf Resort are walking only. Caddies and pull carts are available.' }, { question: 'How do I get to Bandon Dunes?', answer: 'The resort is in Bandon, Oregon, about 5 hours south of Portland. The closest airport is North Bend/Coos Bay (OTH), roughly 30 minutes away.' }, { question: 'What is the best time of year to visit?', answer: 'June through September offers the warmest and driest weather. May and October offer excellent conditions with fewer crowds.' }, { question: 'How far in advance should I book?', answer: 'Peak season tee times book up months in advance. Booking 3 to 6 months ahead is recommended for summer trips.' }] },
    { id: 'por-3', name: 'Bandon Dunes Golf Resort - Bandon Trails', slug: 'bandon-trails', city: 'Portland', state: 'Oregon', type: 'resort', rating: 4.7, greensFee: '$275–$395', architect: 'Bill Coore & Ben Crenshaw', yearBuilt: 2005, holes: 18, par: 71, yardage: 6765, description: 'The Coore & Crenshaw entry at Bandon Dunes routes through coastal forest, open meadow, and dune land — offering the most varied terrain of any course at the resort. While it lacks the ocean views of Pacific Dunes, many consider it the most strategically interesting layout at Bandon.', highlights: ['Coore & Crenshaw diverse terrain routing', 'Most strategically varied Bandon course', 'Forest, meadow, and dune land'], imageAlt: 'Bandon Trails Coore Crenshaw fairway through coastal forest and dunes', history: 'Bandon Trails opened in 2005 as the third course at Bandon Dunes Golf Resort, designed by Bill Coore and Ben Crenshaw. Unlike the oceanfront courses, Trails was routed through the property\'s interior, integrating three distinct ecosystems: sand dunes, open meadow, and coastal rainforest. Coore and Crenshaw extended the layout westward to incorporate ocean-adjacent dune terrain, giving the course remarkable variety.\n\nThe course begins atop a massive sand dune before descending into sprawling meadows, then climbing into dense coastal forest before returning to the dunes for a dramatic finish. This diversity sets Bandon Trails apart and has earned it a devoted following among golfers who value strategic variety over raw coastal drama.\n\nCoore and Crenshaw returned to make significant renovations, refining holes to improve playability. The course is consistently praised as one of the most strategically interesting designs at the resort, with many repeat visitors calling it their favorite Bandon experience.', signatureHoles: [{ hole: 1, par: 4, yardage: 374, description: 'Widely considered the best opening hole at Bandon Dunes Resort. The tee shot appears intimidating but the generous fairway allows a confident swing to start the round.' }, { hole: 14, par: 4, yardage: 353, description: 'A short par 4 in the dune terrain with sweeping views and multiple strategic options off the tee leading to a well-contoured green.' }, { hole: 16, par: 5, yardage: 530, description: 'A slithering uphill par 5 that is a fan favorite. Visually striking with dune grasses framing the fairway, this hole rewards bold play.' }, { hole: 5, par: 3, yardage: 186, description: 'A beautiful par 3 in the meadow section, playing to a green surrounded by native grasses and bunkers with the coastal forest as backdrop.' }], whatToExpect: 'Bandon Trails offers the most varied terrain of any course at Bandon Dunes Resort. The routing moves through sand dunes, open meadow, and dense coastal rainforest, creating a journey that feels like three courses in one round. While it lacks sustained ocean views, the inland setting provides shelter from coastal wind.\n\nAt 6,765 yards and par 71, Bandon Trails rewards strategic thinking and shot shaping. The green complexes are among the most interesting at the resort.', playingTips: 'Bandon Trails is the most sheltered course at the resort, but wind still affects play on the exposed dune holes. The forest holes create tight corridors requiring accuracy.\n\nThe green complexes reward players who study contours and pick the correct approach angle. Many greens have false fronts and subtle tiers that make distance control critical.', faqs: [{ question: 'Is Bandon Trails less windy than the other courses?', answer: 'Generally yes. The forest and meadow sections provide more shelter. However, the dune holes are still exposed to coastal winds.' }, { question: 'How does Bandon Trails compare to the other Bandon courses?', answer: 'It offers the most diverse terrain and is often considered the most strategically interesting layout. Many repeat visitors rank it among their favorites.' }, { question: 'Is Bandon Trails walking only?', answer: 'Yes. Like all courses at Bandon Dunes Resort, it is walking only with caddies and pull carts available.' }, { question: 'What par is Bandon Trails?', answer: 'Bandon Trails plays as a par 71 at 6,765 yards from the back tees.' }] },
    { id: 'por-4', name: 'Bandon Dunes Golf Resort - Old Macdonald', slug: 'old-macdonald', city: 'Portland', state: 'Oregon', type: 'resort', rating: 4.7, greensFee: '$275–$395', architect: 'Tom Doak & Jim Urbina', yearBuilt: 2010, holes: 18, par: 71, yardage: 6942, description: 'A tribute to the template holes of Charles Blair Macdonald, Old Macdonald is Tom Doak\'s second design at Bandon. The wide, strategic layout features massive greens, deep pot bunkers, and expansive ocean views — recreating Macdonald\'s timeless hole concepts in a Pacific Northwest setting.', highlights: ['C.B. Macdonald template hole tribute', 'Tom Doak\'s second Bandon design', 'Massive greens and strategic width'], imageAlt: 'Old Macdonald wide strategic fairway with Pacific Ocean views at Bandon Dunes', history: 'Old Macdonald opened in 2010 as the fourth course at Bandon Dunes Golf Resort. Tom Doak and Jim Urbina were commissioned to create a tribute to Charles Blair Macdonald, the father of American golf course architecture who brought template hole concepts from the British Isles to the United States in the early 1900s.\n\nDoak and Urbina recreated Macdonald\'s most famous template holes — the Redan, Biarritz, Alps, Eden, Cape, Road, and Punchbowl — using natural dune terrain. The greens are among the largest built in decades, with some exceeding 15,000 square feet.\n\nThe course has become one of the most discussed layouts at the resort. Its enormous greens and wide fairways can be wonderfully strategic or frustratingly vast depending on one\'s appreciation for template architecture.', signatureHoles: [{ hole: 16, par: 4, yardage: 455, description: 'The Alps hole, widely considered the finest modern version of this template. The tee shot plays from an oceanside perch and the blind approach must carry a massive bunker to find a hidden green.' }, { hole: 8, par: 3, yardage: 170, description: 'A superb Biarritz hole with a deep swale through the center of a long narrow green. Finding the correct tier is essential to avoid a three-putt.' }, { hole: 18, par: 4, yardage: 455, description: 'Modeled after the famous Road Hole at St. Andrews. A tee shot down the right side leaves the best angle to a green defended by a deep pot bunker.' }, { hole: 5, par: 3, yardage: 160, description: 'A short par 3 with one of the widest greens in existence. The pin position dramatically changes the challenge.' }], whatToExpect: 'Old Macdonald is a wide-open strategic links course with the largest greens at Bandon Dunes. The layout features template holes inspired by C.B. Macdonald\'s Golden Age designs, each named for its template inspiration. At 6,942 yards and par 71, it rewards creative shotmaking.\n\nThe massive greens are the defining characteristic. Finding the surface is relatively easy; finding the correct quadrant for a reasonable birdie putt is the real challenge.', playingTips: 'Study pin positions carefully before each approach. On these enormous greens, being on the wrong tier can leave a 100-foot putt. Aim for the correct quadrant rather than simply hitting the green.\n\nThe wide fairways are forgiving off the tee. The ground game is rewarded — bump and run approaches work beautifully on many holes.', faqs: [{ question: 'What are template holes?', answer: 'Classic designs originated by C.B. Macdonald in the early 1900s based on famous holes from the British Isles, including the Redan, Biarritz, Alps, Eden, and Cape.' }, { question: 'How big are the greens at Old Macdonald?', answer: 'Some exceed 15,000 square feet, among the largest on any modern course. Three-putts are common when on the wrong tier.' }, { question: 'Is Old Macdonald the hardest course at Bandon?', answer: 'Not necessarily. Wide fairways and large greens can be forgiving, but wind and massive green complexes create a stern test depending on conditions.' }, { question: 'Is Old Macdonald walking only?', answer: 'Yes. Like all Bandon Dunes courses, it is walking only with caddies and pull carts available.' }] },
    { id: 'por-5', name: 'Pumpkin Ridge Golf Club - Ghost Creek', slug: 'pumpkin-ridge-ghost-creek', city: 'Portland', state: 'Oregon', type: 'public', rating: 4.5, greensFee: '$100–$200', architect: 'Bob Cupp', yearBuilt: 1992, holes: 18, par: 71, yardage: 6839, description: 'Host of the 1996 U.S. Amateur (Tiger Woods won) and 2015 U.S. Women\'s Open, Ghost Creek is the public course at Pumpkin Ridge near Portland. The Bob Cupp design winds through dense Pacific Northwest forest with ferns, creeks, and towering Douglas firs creating a lush woodland atmosphere.', highlights: ['Tiger Woods won 1996 U.S. Amateur here', 'U.S. Women\'s Open host', 'Lush Pacific Northwest forest setting'], imageAlt: 'Pumpkin Ridge Ghost Creek fairway through Douglas fir forest near Portland', history: 'Opened 1992 near North Plains, Oregon, designed by Bob Cupp. Tiger Woods won the 1996 U.S. Amateur here. Also hosted 2003 and 2015 U.S. Women\'s Opens.', signatureHoles: [{ hole: 6, par: 4, yardage: 410, description: 'Par 4 through Douglas firs alongside a creek.' }, { hole: 11, par: 3, yardage: 185, description: 'Beautiful forest par 3 with ferns and creek.' }, { hole: 14, par: 4, yardage: 430, description: 'Strong par 4 in Tiger Woods\' Amateur triumph.' }, { hole: 18, par: 4, yardage: 420, description: 'Memorable forest finishing hole.' }], whatToExpect: 'Lush PNW forest golf through Douglas firs, ferns, and creeks. At 6,839 yards par 71, championship quality accessible to the public.', playingTips: 'Forest corridors demand accuracy. Course can be soft, affecting carry distances. Know creek hazard locations.', faqs: [{ question: 'Public?', answer: 'Yes. $100-$200.' }, { question: 'Tiger Woods?', answer: 'Won 1996 U.S. Amateur here, third consecutive Amateur title.' }] },
    { id: 'por-6', name: 'Crosswater Club', slug: 'crosswater-club', city: 'Portland', state: 'Oregon', type: 'resort', rating: 4.6, greensFee: '$125–$225', architect: 'Bob Cupp', yearBuilt: 1995, holes: 18, par: 72, yardage: 7693, description: 'Part of the Sunriver Resort in Central Oregon, Crosswater is a Bob Cupp design that plays through meadow, marshland, and along the Deschutes and Little Deschutes rivers. At 7,693 yards from the tips, it\'s one of the longest resort courses in the Pacific Northwest, with Cascade Mountain views providing a stunning backdrop.', highlights: ['7,693 yards along two rivers', 'Sunriver Resort in Central Oregon', 'Cascade Mountain panoramic views'], imageAlt: 'Crosswater Club river-side fairway with Cascade Mountain backdrop at Sunriver', history: 'Crosswater Club opened in 1995 at Sunriver Resort in Central Oregon, designed by Bob Cupp, who had previously served as senior designer for Jack Nicklaus for 15 years. The course was immediately recognized as a showcase for Central Oregon golf, earning a spot on Golf Digest\'s list of America\'s 100 Greatest Public Courses.\n\nCupp routed the layout through meadows, wetlands, and along both the Deschutes and Little Deschutes rivers, with the Cascade Mountains — including Mount Bachelor, Broken Top, and the Three Sisters — providing a panoramic backdrop. The design is more subtle than dramatic, with low-profile greens edged by graceful chipping areas.\n\nBob Cupp passed away in 2016, but Crosswater remains one of his finest achievements and a centerpiece of the Sunriver Resort experience. The course continues to be recognized among the best resort courses in America.', signatureHoles: [{ hole: 5, par: 4, yardage: 445, description: 'A par 4 along the Deschutes River with Cascade Mountain views. The approach must respect the river running along the hole.' }, { hole: 12, par: 3, yardage: 215, description: 'A long par 3 with the Little Deschutes River as a backdrop. At altitude the thin air helps, but the distance is still demanding.' }, { hole: 15, par: 5, yardage: 580, description: 'A sweeping par 5 through the river meadow with wetlands framing the fairway. Risk-reward decisions at every stage.' }, { hole: 18, par: 4, yardage: 460, description: 'A strong finisher with river and mountain views providing a memorable conclusion to the round.' }], whatToExpect: 'Crosswater is a Central Oregon gem set in river meadows with Cascade Mountain panoramas. The Bob Cupp design is elegant rather than overpowering, with low-profile greens and natural features integrated seamlessly. At 7,693 yards it is long, but the altitude helps.\n\nThe resort setting at Sunriver provides accommodations and activities for non-golfers. The course is accessible to resort guests and public players.', playingTips: 'The Central Oregon altitude (about 4,200 feet) adds distance. Club down from your normal selections. The thin air also means the ball curves less.\n\nMorning dew and riverside conditions can make early rounds play soft. Afternoon winds often pick up. The meadow terrain is walkable but distances between holes may require a cart.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Resort guests and public players welcome. Fees from $125 to $225.' }, { question: 'Who designed it?', answer: 'Bob Cupp, former senior designer for Jack Nicklaus, completed the design in 1995.' }, { question: 'Which rivers run through the course?', answer: 'Both the Deschutes and Little Deschutes rivers cross and border the layout.' }, { question: 'What mountains are visible?', answer: 'Mount Bachelor, Broken Top, and the Three Sisters in the Cascade Range.' }] },
    { id: 'por-7', name: 'Tetherow Golf Club', slug: 'tetherow-golf-club', city: 'Portland', state: 'Oregon', type: 'resort', rating: 4.5, greensFee: '$100–$200', architect: 'David McLay Kidd', yearBuilt: 2008, holes: 18, par: 72, yardage: 7298, description: 'A David McLay Kidd design in Bend with panoramic views of the Cascade volcanoes — Broken Top, South Sister, and Bachelor. The Scottish links-inspired layout on volcanic soil features firm, fast conditions unusual for the Pacific Northwest, with fescue fairways and creative green sites.', highlights: ['Panoramic Cascade volcano views', 'David McLay Kidd Scottish links style', 'Firm fescue conditions on volcanic soil'], imageAlt: 'Tetherow Golf Club links fairway with Cascade volcanoes near Bend Oregon', history: 'Tetherow Golf Club opened in 2008, designed by David McLay Kidd — the Scottish architect who created the original Bandon Dunes course. Set on volcanic terrain near Bend with sweeping views of the Cascade Range (Broken Top, South Sister, Bachelor), the course plays entirely on fescue grass over volcanic soil — conditions unlike anything else in Oregon.\n\nNamed one of Golfweek\\\'s Top Resort Golf Courses in the U.S. (2025) and ranked 15th in Oregon. The design is deliberately "controversial" — Kidd created a penal, links-inspired layout demanding imagination and ground-game creativity that rewards those who adapt but frustrates those who don\\\'t.', signatureHoles: [{ hole: 17, par: 3, yardage: 182, description: '"The Quarry" — a par 3 with a 50-plus-yard-long narrow green framed by massive waste bunkers carved from volcanic rock. The dramatic setting with Cascade volcano views makes it one of the most memorable par 3s in Oregon.' }, { hole: 6, par: 4, yardage: 424, description: 'A split fairway offering genuine risk/reward options off the tee. The aggressive line shortens the approach but brings severe penalties into play.' }], whatToExpect: 'A links-style layout at 7,298 yards on rolling volcanic soil blanketed entirely in fescue grass. Conditions are firm and fast — the ball bounces and runs 20-40 yards on the firm turf. Hidden bunkers, substantial green movement, and constant Central Oregon wind create a demanding test.\n\nForecaddies are included and strongly recommended — blind bunkers and hidden contours punish uninformed play. The Cascade volcano panorama (Broken Top, South Sister, Bachelor) is stunning throughout.\n\nThis course demands a different style of golf than most American courses. Embrace the ground game.', playingTips: 'Forget target golf. Learn to use the ground game — bump-and-run approaches, low shots, and creative use of slopes around greens are essential.\n\nTrust the forecaddie. Blind bunkers and hidden contours punish uninformed play.\n\nFescue fairways and greens play nothing like typical irrigated American courses. Expect the ball to release dramatically on firm turf.\n\nCentral Oregon wind is a constant factor. Club selection must account for both wind and the firm, bouncy conditions.', faqs: [{ question: 'Who designed Tetherow?', answer: 'David McLay Kidd, the Scottish architect famous for the original Bandon Dunes course. Tetherow opened in 2008 on volcanic terrain near Bend.' }, { question: 'What is the fescue like?', answer: 'The entire course — fairways and greens — is fescue on volcanic soil. Conditions are firm and fast with dramatic ball release. It plays nothing like typical irrigated courses.' }, { question: 'Are forecaddies required?', answer: 'Included with your round and strongly recommended. The blind bunkers and hidden contours make local knowledge essential.' }]},
    { id: 'por-8', name: 'Bandon Dunes Golf Resort - Sheep Ranch', slug: 'sheep-ranch', city: 'Portland', state: 'Oregon', type: 'resort', rating: 4.8, greensFee: '$275–$395', architect: 'Bill Coore & Ben Crenshaw', yearBuilt: 2020, holes: 18, par: 72, yardage: 6734, description: 'The newest addition to Bandon Dunes, Sheep Ranch is a Coore & Crenshaw design with the most dramatic ocean exposure of any course at the resort. Nearly every hole offers Pacific Ocean views, and many play directly along the cliff edge. The wide, strategic layout with minimal rough evokes the spirit of early links golf.', highlights: ['Most ocean exposure at Bandon Dunes', 'Coore & Crenshaw 2020 cliff-edge links', 'Nearly every hole has Pacific views'], imageAlt: 'Sheep Ranch cliff-edge fairway with Pacific Ocean at Bandon Dunes Resort', history: 'Sheep Ranch opened June 1, 2020, as the fifth 18-hole course at Bandon Dunes Golf Resort. The property originally hosted a 13-green layout by Tom Doak from 2001 that served as an informal walking course. Mike Keiser later commissioned Bill Coore and Ben Crenshaw to build a full 18-hole course on land that had been a failed wind farm in the 1970s.\n\nCoore and Crenshaw maximized ocean exposure, placing nine greens on soaring cliffs above the Pacific — more coastline than Bandon Dunes and Pacific Dunes combined. The course was designed without a single sand bunker, giving it a pure minimalist character.\n\nSheep Ranch quickly became a favorite for its raw beauty and dramatic ocean views. Wide fairways and no bunkers create a throwback to the earliest forms of links golf where the land itself provides the defense.', signatureHoles: [{ hole: 1, par: 5, yardage: 549, description: 'Widely considered the best opening hole at Bandon Dunes Resort. This downhill par 5 introduces the ocean panorama and sets the tone for a dramatic coastal walk.' }, { hole: 16, par: 3, yardage: 151, description: 'A stunning short par 3 atop Five Mile Point, a cape jutting from the cliffs above the Pacific. The green is shared with hole 3 in one of golf\'s most spectacular settings.' }, { hole: 11, par: 5, yardage: 543, description: 'A sweeping par 5 along the cliff edge with the Pacific on the left throughout. Often cited as the best par 5 at the entire resort.' }, { hole: 5, par: 3, yardage: 198, description: 'A mid-length par 3 playing toward Five Mile Point with ocean views. Exposed to coastal winds making club selection critical.' }], whatToExpect: 'Sheep Ranch delivers the most dramatic ocean exposure at Bandon Dunes. Nearly every hole offers Pacific views and many play directly along cliff edges. The absence of bunkers gives the course a pure minimalist character.\n\nAt 6,734 yards and par 72, wide fairways appear forgiving but constant ocean wind and creative green complexes provide ample challenge.', playingTips: 'Without bunkers, the primary defense is wind and natural contours. Greens reject poorly positioned approaches, so correct angle of attack matters greatly.\n\nCliff-edge holes demand respect — the ocean is an absolute boundary. Play conservatively along the coastline and take chances on inland holes.', faqs: [{ question: 'Does Sheep Ranch really have no bunkers?', answer: 'Correct. It was designed without a single sand bunker. Natural terrain, wind, and green contours provide the defense.' }, { question: 'Is Sheep Ranch the newest course at Bandon?', answer: 'Yes. It opened in June 2020 as the fifth full 18-hole course.' }, { question: 'How does it compare to Pacific Dunes for ocean views?', answer: 'Sheep Ranch has more total coastline than Bandon Dunes and Pacific Dunes combined, with nine greens on oceanside cliffs.' }, { question: 'Is Sheep Ranch walking only?', answer: 'Yes. Like all Bandon Dunes courses, it is walking only with caddies and pull carts available.' }] },
    { id: 'por-9', name: 'Reserve Vineyards & Golf Club - North', slug: 'reserve-vineyards-north', city: 'Aloha', state: 'Oregon', type: 'public', rating: 4.2, greensFee: '$50–$90', architect: 'Bob Cupp', yearBuilt: 1997, holes: 18, par: 72, yardage: 6827, description: 'A Bob Cupp design in the Tualatin Valley west of Portland, the Reserve North Course winds through mature Oregon trees with vineyard views and the Tualatin Mountains as a backdrop. The accessible public layout offers a refined parkland experience with well-maintained bent grass surfaces and strategic bunkering.', highlights: ['Bob Cupp parkland design near Tualatin Valley vineyards', 'Well-maintained bent grass surfaces', 'Accessible public pricing west of Portland'], imageAlt: 'Reserve Vineyards North Course fairway with Tualatin Mountain views near Portland', history: 'Reserve Vineyards\\\\\' North Course was designed by Bob Cupp and opened in 1997 west of Portland in the Tualatin Valley. Cupp spent 15 years as Jack Nicklaus\\\'s senior designer before going independent, winning Golf World\\\'s Designer of the Year in 1992. The facility has hosted Champions Tour senior major "The Tradition" and Peter Jacobsen\\\'s Fred Meyer Challenge.\n\nThe North Course (also called "The Cupp Course") employs a links-style design contrasting with the tree-lined South Course, using undulating native grass mounds, judicious bunkering, and formidable greens with short grass surrounds.', signatureHoles: [{ hole: 17, par: 4, yardage: 459, description: 'The green is part of a spectacular 43,000-square-foot triple green complex shared by the 1st, 8th, and 17th holes — one of the most unusual green complexes in Oregon golf.' }, { hole: 13, par: 4, yardage: 400, description: 'A severe dogleg left where positioning past the 100-yard marker is essential for an open approach to the green.' }], whatToExpect: 'A links-style layout at par 72 stretching to 6,840 yards with a 140 slope. Undulating native grass mounds, firm greens with short-grass surrounds, and strategic bunkering create a feel closer to Oregon\\\'s coastal dunes than the Willamette Valley.\n\nThe 43,000-square-foot triple green shared by holes 1, 8, and 17 is among the largest shared surfaces in the Pacific Northwest.\n\nNote: The North Course is reserved exclusively for private members the first through fifteenth of each month. Public access is available the second half of each month.', playingTips: 'Firm greens with short-grass surrounds make bump-and-run recovery shots viable throughout. Don\\\'t automatically reach for the lob wedge.\n\nHole 4 has a deceptively long carry over marsh — take an extra club.\n\nOn the par-5 12th, a creek runs 75 yards before the green and may be hidden from your second shot. Lay up or commit fully.\n\nThe severe dogleg-left 13th demands a tee shot past the 100-yard marker for a clean approach.', faqs: [{ question: 'Is the North Course public?', answer: 'Semi-private. The North Course is reserved for private members the 1st through 15th of each month. Public access is available the second half of each month.' }, { question: 'What is the triple green?', answer: 'A 43,000-square-foot putting surface shared by holes 1, 8, and 17 — one of the largest shared green complexes in the Pacific Northwest.' }, { question: 'Who designed it?', answer: 'Bob Cupp, who spent 15 years as Jack Nicklaus\\\'s senior designer. Won Golf World Designer of the Year in 1992.' }]},
    { id: 'por-10', name: 'Langdon Farms Golf Club', slug: 'langdon-farms-golf-club', city: 'Aurora', state: 'Oregon', type: 'public', rating: 4.3, greensFee: '$45–$85', architect: 'John Fought & Robert Cupp', yearBuilt: 1995, holes: 18, par: 71, yardage: 6931, description: 'A Fought-Cupp collaboration south of Portland, Langdon Farms is consistently rated among the top public courses in Oregon. The links-influenced layout through open farmland features deep pot bunkers, native fescue, and the Willamette Valley\'s characteristic wind, creating a strategic test that rewards creativity.', highlights: ['Consistently rated top public course in Oregon', 'Links-influenced design with pot bunkers and fescue', 'Fought-Cupp collaboration in Willamette Valley'], imageAlt: 'Langdon Farms Golf Club links-style fairway through Willamette Valley farmland', history: 'Langdon Farms opened in spring 1995, built on the 63-year-old Langdon family farm south of Portland. The land was originally worked by James Edgar Langdon and Marie Beck, German emigrants who arrived in 1887. Designed by John Fought (1977 U.S. Amateur Champion, two-time PGA Tour winner) and Bob Cupp (15 years as Nicklaus\\\'s senior designer, Golf World Designer of the Year 1992).\n\nBrothers Chris and Tom Maletis purchased the course outright in 2003 and continue to run it as a family business. Ranked No. 1 best public course by the Portland Business Journal (2010) and Top 10 in Oregon by Golfweek. Has hosted USGA U.S. Open qualifying.', signatureHoles: [{ hole: 9, par: 4, yardage: 420, description: 'A demanding par 4 where deep pot bunkers guard the approach to a well-contoured green. The links-influenced mounding and fescue rough frame every shot — representative of the course\\\'s character throughout.' }], whatToExpect: 'A links-influenced public layout at 6,931 yards, par 71. Deep pot bunkers, thick rough, short-cropped fairways, and large water hazards define the challenge. The flat agricultural terrain is shaped into rolling mounds and ridges to create visual interest and strategic variety.\n\nSpacious fairways invite aggressive driving, but the greens are well-defended by bunkering. Wind is a regular factor on this open, exposed Willamette Valley layout.\n\nPublic-only policy maintained throughout its history. Located 15 miles south of downtown Portland.', playingTips: 'Deep bunkers are the primary defense — avoid them at all costs, especially around the greens.\n\nThe rough is thick and punishing. Accuracy off the tee pays dividends over distance.\n\nGreens are well-contoured — take time to read them carefully.\n\nWind on this open farmland layout can be a significant factor. Check conditions before exposed shots.', faqs: [{ question: 'Is Langdon Farms public?', answer: 'Yes — public-only since opening in 1995. No membership required. Green fees $45-85.' }, { question: 'Who designed it?', answer: 'John Fought (1977 U.S. Amateur Champion) and Bob Cupp (former Nicklaus senior designer). Fought recently retooled the strategic bunkering.' }, { question: 'Has it hosted events?', answer: 'Yes — USGA U.S. Open qualifying. Ranked No. 1 public course by Portland Business Journal and Top 10 in Oregon by Golfweek.' }]},
    { id: 'por-11', name: 'Waverley Country Club', slug: 'waverley-country-club', city: 'Portland', state: 'Oregon', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'H. Chandler Egan', yearBuilt: 1913, holes: 18, par: 72, yardage: 6618, description: 'Founded in 1896 and redesigned by H. Chandler Egan in 1913, Waverley is Portland\'s most prestigious private club. Located on the banks of the Willamette River with views of Mount Hood, the classic parkland layout features mature Douglas fir corridors, strategic bunkering, and a refined atmosphere steeped in Pacific Northwest golf history.', highlights: ['Portland\'s most prestigious private club since 1896', 'H. Chandler Egan redesign on Willamette River', 'Mount Hood views through Douglas fir corridors'], imageAlt: 'Waverley Country Club historic fairway along Willamette River with Mount Hood views', history: 'Founded in April 1896, Waverley is the second-oldest private golf club west of the Mississippi River. Originally in Portland\\\'s Richmond neighborhood, it relocated in 1897 to the east bank of the Willamette River on land that was formerly the Luelling/Lewelling orchard — where the Bing cherry was developed.\n\nH. Chandler Egan established the current routing between 1912 and his death in 1936. Gil Hanse completed a 2012 restoration using historical photographs to revive Egan\\\'s original design elements. The tournament history is extraordinary: the 1970 U.S. Amateur (Lanny Wadkins), 1981 U.S. Women\\\'s Amateur (Juli Inkster), and the 1993 U.S. Junior Amateur (Tiger Woods, age 15) were all held here.', signatureHoles: [{ hole: 13, par: 4, yardage: 385, description: 'One of several holes routing along the Willamette River\\\'s edge, with Mount Hood framing the backdrop on clear days. Egan\\\'s subtle green complexes reward precision over power.' }], whatToExpect: 'A classic, walkable private course at par 71 and 6,668 yards (slope 134). Old-growth trees, Willamette River views, and Egan\\\'s subtle green complexes reward precision over power. The Hanse restoration stripped away decades of changes to reveal the original strategic intent.\n\nThe compact layout emphasizes ground-game approach shots and careful putting on greens with subtle, deceptive breaks. Mount Hood views on clear days add to the Pacific Northwest atmosphere.\n\nStrictly private — Portland\\\'s most prestigious club.', playingTips: 'Egan\\\'s greens are more complex than they appear. Study the surrounds and use them for recovery shots.\n\nThe river and mature trees define many corridors, placing a premium on shot shaping.\n\nWalking is the best way to experience Waverley — the compact terrain provides better reads on the subtle slopes.', faqs: [{ question: 'What major events has Waverley hosted?', answer: '1970 U.S. Amateur (Lanny Wadkins), 1981 U.S. Women\\\'s Amateur (Juli Inkster), 1993 U.S. Junior Amateur (Tiger Woods at age 15), plus the Blyth Tournament since 1897.' }, { question: 'Who designed the current layout?', answer: 'H. Chandler Egan (1912-1936). Gil Hanse completed a restoration in 2012 using historical photographs to revive Egan\\\'s original design.' }, { question: 'How old is Waverley?', answer: 'Founded 1896 — the second-oldest private golf club west of the Mississippi River.' }]},
  ],
  'palm-springs-california': [
    { id: 'ps-1', name: 'PGA West - Stadium Course', slug: 'pga-west-stadium', city: 'Palm Springs', state: 'California', type: 'resort', rating: 4.7, greensFee: '$125–$275', architect: 'Pete Dye', yearBuilt: 1986, holes: 18, par: 72, yardage: 7300, description: 'One of Pete Dye\'s most famous and fearsome designs, PGA West Stadium was built as the ultimate spectator-friendly desert course. The infamous island-green 17th, deep pot bunkers, and relentless challenge made it a PGA Tour venue and one of the toughest resort courses in the world.', highlights: ['Pete Dye\'s famous island-green 17th', 'American Express PGA Tour venue', 'One of the toughest resort courses in the world'], imageAlt: 'PGA West Stadium Course island green 17th hole in La Quinta', history: 'PGA West Stadium Course was designed by Pete Dye and opened in 1986 in La Quinta, California, purpose-built for spectator golf with stadium mounding around many holes. It debuted hosting the 1986 Skins Game featuring Jack Nicklaus, Arnold Palmer, Fuzzy Zoeller, and Lee Trevino, instantly making the island-green 17th one of the most famous holes in desert golf.\n\nThe course served as a PGA Tour venue and continues in the American Express tournament rotation. Lee Trevino famously called it the hardest course he had ever played. Deep pot bunkers, railroad-tie bulkheads, and forced carries earned it a reputation as one of the most punishing resort layouts in America.\n\nThe 17th hole, nicknamed Alcatraz, is among the most iconic island greens in golf after TPC Sawgrass.', signatureHoles: [{ hole: 17, par: 3, yardage: 168, description: 'Known as Alcatraz, one of golf\'s most famous island greens. Surrounded by water with no bail-out, a precise tee shot is essential.' }, { hole: 16, par: 5, yardage: 571, description: 'San Andreas Fault — a dramatic par 5 featuring a deep imposing bunker complex cutting through the fairway. A risk-reward hole where strategy is critical.' }, { hole: 12, par: 4, yardage: 363, description: 'One of the strongest short par 4s on the course requiring precise positioning to set up an approach to a well-defended green.' }, { hole: 18, par: 4, yardage: 453, description: 'One of the toughest finishing holes in desert golf. Water runs along the left and the green demands a precise approach under pressure.' }], whatToExpect: 'PGA West Stadium is a relentless Pete Dye design with deep pot bunkers, railroad-tie bulkheads, and the famous island-green 17th. Stadium mounding frames many holes. At 7,300 yards from the tips, this is one of the toughest resort courses in America.\n\nThe Coachella Valley desert setting means warm dry conditions most of the year with dramatic mountain backdrops.', playingTips: 'Many hazards look worse than they are — trust your yardage and ignore Dye\'s visual intimidation. The island green at 17 plays shorter than it looks but demands a committed swing.\n\nAvoid the deep pot bunkers at all costs. Some are so deep the only play is sideways. Course management is far more important than power.', faqs: [{ question: 'Can the public play PGA West Stadium?', answer: 'Yes. Green fees range from $125 to $275. Peak rates apply during winter months.' }, { question: 'What is hole 17 like?', answer: 'Nicknamed Alcatraz, it is a 168-yard par 3 to an island green surrounded by water — one of the most famous holes in desert golf.' }, { question: 'Is PGA West on the PGA Tour?', answer: 'The Stadium Course is part of the American Express tournament rotation held each January.' }, { question: 'How tough is it?', answer: 'Lee Trevino once called it the hardest course he ever played. It is widely considered one of the most difficult resort courses in America.' }] },
    { id: 'ps-2', name: 'La Quinta Resort - Mountain Course', slug: 'la-quinta-mountain', city: 'Palm Springs', state: 'California', type: 'resort', rating: 4.6, greensFee: '$100–$225', architect: 'Pete Dye', yearBuilt: 1980, holes: 18, par: 72, yardage: 6758, description: 'Set against the dramatic Santa Rosa Mountains at the historic La Quinta Resort, the Mountain Course is a Pete Dye desert classic and part of the American Express PGA Tour rotation. The intimate desert canyon setting and mountain backdrop create one of the most photogenic rounds in the Coachella Valley.', highlights: ['American Express PGA Tour rotation', 'Dramatic Santa Rosa Mountain backdrop', 'Historic La Quinta Resort setting'], imageAlt: 'La Quinta Mountain Course with Santa Rosa Mountains in Coachella Valley', history: 'The Mountain Course at La Quinta Resort was designed by Pete Dye and opened in 1980, nestled at the base of the Santa Rosa Mountains. Part of the PGA WEST complex — the "Western Home of Golf in America" — the Mountain Course is one of Dye\\\'s most dramatic desert designs.\n\nThe front 13 holes wind through a residential community alongside jagged rock outcroppings, then holes 14-18 climb spectacularly into the mountain foothills with elevation changes and panoramic desert views. The stretch from 14 to 16 is widely considered among the most scenic consecutive holes in the Coachella Valley.', signatureHoles: [{ hole: 16, par: 3, yardage: 167, description: 'An iconic mountain par 3 with virtually no margin for error — a rocky amphitheater with trouble short, long, left, and right. One of the most photographed holes in desert golf.' }, { hole: 2, par: 3, yardage: 205, description: 'A classic Pete Dye par 3 with water flanking the entire left side. The water draws the eye and tempts a bail-out right where bunkers wait.' }], whatToExpect: 'A shorter Pete Dye design (6,758 yards) relying on trademark pot bunkers, rock features, tall native grasses, and tricky elevated greens rather than raw length. The back nine (especially 13-18) transitions into genuinely mountainous terrain with dramatic elevation changes and panoramic Santa Rosa Mountain views.\n\nConditioning is typically excellent. Open to resort guests and public play as part of the PGA WEST complex.', playingTips: 'Don\\\'t let the modest yardage fool you — accuracy matters far more than distance on this Dye design.\n\nThe greens are contoured and punishing. Favor below-the-hole positions throughout.\n\nOn the mountain holes (14-18), trust your yardage over your eyes. Elevation changes distort visual perception.\n\nBring extra balls for the par 3s — Dye\\\'s green complexes have severe penalties for misses.', faqs: [{ question: 'Is this the PGA Tour course?', answer: 'The Mountain Course is part of the PGA WEST complex but the adjacent Stadium Course (also Pete Dye) hosts The American Express PGA Tour event. The Mountain Course is the resort complement.' }, { question: 'Who designed it?', answer: 'Pete Dye, opening in 1980 at the base of the Santa Rosa Mountains. One of his most dramatic desert designs.' }, { question: 'What is the best stretch?', answer: 'Holes 14-16 climbing into the mountain foothills are widely considered among the most scenic consecutive holes in the Coachella Valley.' }]},
    { id: 'ps-3', name: 'Indian Wells Golf Resort - Celebrity Course', slug: 'indian-wells-celebrity', city: 'Palm Springs', state: 'California', type: 'resort', rating: 4.3, greensFee: '$75–$175', architect: 'Clive Clark', yearBuilt: 2006, holes: 18, par: 72, yardage: 7050, description: 'A Clive Clark design in Indian Wells, the Celebrity Course replaced the old Ted Robinson layout with a more modern, strategically engaging desert design. The course offers panoramic mountain views and one of the best resort-value experiences in the Coachella Valley.', highlights: ['Panoramic mountain views', 'Best resort value in Coachella Valley', 'Modern Clive Clark desert design'], imageAlt: 'Indian Wells Celebrity Course with mountain panorama in Coachella Valley', history: 'The Celebrity Course was designed by English architect Clive Clark and opened in November 2006, replacing the original Ted Robinson layout at Indian Wells Golf Resort. It was the first of the resort\\\'s two courses to be rebuilt (the Players Course followed). Both courses have been ranked among the Top 25 golf courses in California.\n\nThe resort is city-owned, giving it a public-access mission despite the upscale presentation. It hosts the annual City of Indian Wells Celebrity Pro-Am.', signatureHoles: [{ hole: 17, par: 3, yardage: 146, description: 'A stunning short iron over a scenic pond fronted by a cascading waterfall, with the San Jacinto Mountains as backdrop. A visual showstopper — one of the most photogenic par 3s in the Coachella Valley.' }, { hole: 5, par: 4, yardage: 400, description: 'A risk/reward par 4 where water and strategic bunkering force a choice between aggressive and conservative lines off the tee.' }], whatToExpect: 'Water is the defining feature — 13 of 18 holes have water hazards via meandering streams, split-level lakes, and waterfalls. The front nine features water mostly along hole edges; the back nine brings it more directly into play.\n\nRolling, undulating fairways with lush landscaping give it a more "Eastern" feel than most desert courses. At 7,050 yards from the tips, it has real teeth but excellent value compared to comparable private-feel desert layouts.\n\nCity-owned with public access — one of the best resort values in the Coachella Valley.', playingTips: 'Club selection around water hazards is critical — know your carry distances cold. Water is on 13 of 18 holes.\n\nThe undulating fairways create uneven lies. Take one extra club on approach shots from awkward stances.\n\nAfternoon valley wind can add 1-2 clubs on exposed holes. Morning tee times offer calmer conditions.\n\nThe greens are well-protected but receptive. Favor the center over chasing pins near water.', faqs: [{ question: 'Is Indian Wells Celebrity Course public?', answer: 'Yes — city-owned with public access. One of the best resort values in the Coachella Valley at $75-175.' }, { question: 'How much water is in play?', answer: '13 of 18 holes feature water hazards — meandering streams, split-level lakes, and waterfalls. It is the defining feature of the course.' }, { question: 'Who designed it?', answer: 'English architect Clive Clark, opening in 2006 to replace the original Ted Robinson layout.' }]},
    { id: 'ps-4', name: 'Desert Willow Golf Resort - Firecliff Course', slug: 'desert-willow-firecliff', city: 'Palm Springs', state: 'California', type: 'public', rating: 4.4, greensFee: '$60–$150', architect: 'Michael Hurdzan & Dana Fry', yearBuilt: 1997, holes: 18, par: 72, yardage: 7056, description: 'A city-owned desert masterpiece in Palm Desert, Firecliff at Desert Willow delivers championship desert golf at municipal pricing. The Hurdzan/Fry design features dramatic elevation changes, native desert landscaping, and the Santa Rosa Mountain backdrop.', highlights: ['Municipal pricing for championship desert golf', 'Hurdzan & Fry desert design', 'Palm Desert city-owned gem'], imageAlt: 'Desert Willow Firecliff desert fairway with Santa Rosa Mountains', history: 'The Firecliff Course at Desert Willow opened in 1997, designed by Michael Hurdzan, Dana Fry, and PGA Tour player John Cook. It is a municipally owned public facility in Palm Desert — one of the finest city-run courses in the country.\n\nEarned 4 out of 5 stars from Golf Digest Places to Play and regularly hosts championship events including the City of Palm Desert Championship and the Golfweek Senior Amateur Championship (March 2026). The course recently underwent renovations including an expanded and upgraded 18th green.\n\nWidely considered one of the best public golf values in the entire Coachella Valley — municipal pricing for championship desert golf.', signatureHoles: [{ hole: 18, par: 4, yardage: 440, description: 'Recently renovated with an expanded green, leveled tees, and fresh sod. A demanding closer with water guarding the green, requiring a precise approach to finish your round.' }, { hole: 5, par: 4, yardage: 429, description: 'Played from an elevated tee revealing a slight dogleg left framed by native desert washes and arroyos. A strategic hole rewarding positioning over power.' }], whatToExpect: 'A rugged, authentic desert layout at 7,056 yards from the tips. Six of the ten par 4s stretch past 400 yards from the blues. Desert washes, native vegetation, and sandy waste areas frame the holes rather than manicured turf, giving it a true Sonoran feel.\n\nFirm, fast conditions are typical. Water impacts the two finishing holes on each nine. Five tee sets make it playable for all skill levels.\n\nAs a city-owned facility, green fees ($60-150) are notably lower than comparable private-resort courses.', playingTips: 'Carry distances over desert washes are the key challenge. Know your landing zones off the tee.\n\nThe course plays longer than the card suggests because firm fairways can kick balls into waste areas.\n\nTake the forward tees seriously if you don\\\'t carry the ball 200+ yards. The desert penalties are severe.\n\nGreens run firm and fast — plan for run-out on approach shots. Below-the-hole is essential.', faqs: [{ question: 'Is Desert Willow really municipal?', answer: 'Yes — owned by the City of Palm Desert. Municipal pricing ($60-150) for championship-quality desert golf. One of the best values in the Coachella Valley.' }, { question: 'Who designed it?', answer: 'Michael Hurdzan, Dana Fry, and PGA Tour player John Cook. The companion Mountain View course (also Hurdzan/Fry) offers a gentler alternative.' }, { question: 'How long is it?', answer: 'Seven of the ten par 4s exceed 400 yards from the blues, and the course stretches to 7,056 yards from the tips. Five tee sets accommodate all skill levels.' }]},
    { id: 'ps-5', name: 'The Vintage Club - Mountain Course', slug: 'vintage-club-mountain', city: 'Palm Springs', state: 'California', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 1979, holes: 18, par: 72, yardage: 7157, description: 'One of the most exclusive private clubs in the desert, The Vintage Club in Indian Wells features two Tom Fazio courses in a gated community of extraordinary wealth. The Mountain Course is the more dramatic of the two, with desert washes, mountain views, and Fazio\'s bold shaping.', highlights: ['Ultra-exclusive Indian Wells private club', 'Tom Fazio desert mountain design', 'Among the most prestigious desert clubs'], imageAlt: 'Vintage Club Mountain Course dramatic desert fairway in Indian Wells', history: 'The Vintage Club opened its Mountain Course in 1979 within a 712-acre ultra-exclusive residential community in Indian Wells, originally designed by George and Tom Fazio. Tom Fazio completed an extensive redesign in 2014. The club also features a Desert Course (1984).\n\nWith no tee times — members simply walk up and play — the Vintage Club is one of the most prestigious private communities in the United States. Membership is reportedly around $300,000 with annual dues of approximately $17,500. The club\\\'s 80,000-square-foot clubhouse was renovated in 2016.\n\nMembership has historically included presidents, billionaires, and entertainment icons.', signatureHoles: [{ hole: 16, par: 4, yardage: 402, description: 'Widely considered the signature hole, featuring dramatic elevation changes set against the Santa Rosa Mountain backdrop. The mountain framing creates one of the most memorable par 4s in desert golf.' }], whatToExpect: 'Dramatic elevation changes, impeccable conditioning, and a layout blending seamlessly into its mountainside setting. The course threads holes into the shadow of the Santa Rosa Mountains with a uniquely natural desert aesthetic.\n\nOnly open during cooler months (roughly October through May). Expect a serene, unhurried atmosphere with very few players on the course at any time.\n\nAmong the most exclusive private clubs in America — access requires membership or member invitation.', playingTips: 'Fazio rewards precision off the tee over raw distance. Course management is paramount.\n\nThe undulating greens demand local knowledge. Ask your host about pin positions and break tendencies.\n\nDesert air and elevation changes affect club selection throughout. Trust your yardage device.', faqs: [{ question: 'How exclusive is The Vintage Club?', answer: 'Among the most exclusive in the US. Membership reportedly ~$300,000 with ~$17,500 annual dues. No tee times — members walk up and play.' }, { question: 'Who designed the Mountain Course?', answer: 'George and Tom Fazio (1979). Tom Fazio completed an extensive redesign in 2014.' }, { question: 'Is it open year-round?', answer: 'No — only during cooler months, roughly October through May.' }]},
    { id: 'ps-6', name: 'Bighorn Golf Club - Canyons Course', slug: 'bighorn-canyons', city: 'Palm Springs', state: 'California', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Arthur Hills', yearBuilt: 1997, holes: 18, par: 72, yardage: 6970, description: 'Perched in the hills above Palm Desert at 1,500 feet elevation, Bighorn\'s Canyons Course offers sweeping Coachella Valley views and a dramatic Arthur Hills layout through boulder-strewn desert terrain. The club formerly hosted the Skins Game, attracting golf\'s biggest names.', highlights: ['Former Skins Game host', 'Sweeping Coachella Valley views', 'Arthur Hills mountain desert design'], imageAlt: 'Bighorn Canyons Course overlooking Coachella Valley from Palm Desert hills', history: 'Bighorn Golf Club opened its Mountains Course (Arthur Hills, 1991) which famously hosted the Skins Game from 1992 to 1995, drawing legends Nicklaus, Palmer, and Trevino. The Canyons Course, designed by Tom Fazio, followed in 1997 as the second 18. The club also hosted the LPGA Samsung World Championship and U.S. Senior Match Play Challenge.\n\nPerched at 1,500 feet elevation in the hills above Palm Desert, both courses offer sweeping Coachella Valley views. Lee Trevino has called Bighorn one of his favorite places. The club is consistently ranked among the top private golf communities in the country.', signatureHoles: [{ hole: 7, par: 4, yardage: 420, description: 'An elevated tee shot offering panoramic desert-and-mountain views dropping into canyon terrain. Classic Fazio design with wide fairways flanked by enormous bunkers. The visual drama of the elevated tees is Bighorn\\\'s hallmark experience.' }], whatToExpect: 'A more open, generous feel than the Mountains Course, with wide inviting fairways flanked by 113 enormous bunkers totaling 2.7 acres of sand. Classic Fazio trademarks throughout: bold shaping, generous corridors, and strategic decisions created by bunker placement rather than hazards.\n\nConditions are immaculate. The sweeping Coachella Valley views from 1,500 feet elevation are among the best in desert golf.\n\nStrictly private — one of the most prestigious desert golf communities.', playingTips: 'The generous fairways encourage aggressive tee shots, but the enormous greenside bunkers punish imprecise approaches severely.\n\nClub selection on downhill holes needs careful attention. Desert air and elevation drops add significant distance.\n\nThe 1,500-foot elevation means the ball flies even farther than at valley-floor courses. Adjust all club selections accordingly.', faqs: [{ question: 'Did Bighorn host the Skins Game?', answer: 'Yes — the Mountains Course (Arthur Hills) hosted the Skins Game from 1992 to 1995 with Nicklaus, Palmer, and Trevino. The Canyons Course (Tom Fazio, 1997) is the second 18.' }, { question: 'Can the public play?', answer: 'No. Bighorn is a strictly private community perched at 1,500 feet elevation in the Palm Desert hills.' }, { question: 'Who designed the Canyons Course?', answer: 'Tom Fazio (1997). The older Mountains Course was designed by Arthur Hills (1991).' }]},
    { id: 'ps-7', name: 'Escena Golf Club', slug: 'escena-golf-club', city: 'Palm Springs', state: 'California', type: 'public', rating: 4.2, greensFee: '$50–$120', architect: 'Jack Nicklaus', yearBuilt: 2006, holes: 18, par: 72, yardage: 7191, description: 'A Jack Nicklaus design in central Palm Springs, Escena offers accessible desert golf with mountain views and wide playing corridors. The well-conditioned layout is one of the best public values in the Coachella Valley, delivering Nicklaus design pedigree at reasonable prices.', highlights: ['Jack Nicklaus design in central Palm Springs', 'Best public value in the Coachella Valley', 'Mountain views and wide corridors'], imageAlt: 'Escena Golf Club Nicklaus fairway with San Jacinto Mountain backdrop', history: 'Escena Golf Club opened in 2006, one of the rare Jack Nicklaus-designed courses open for public play, within a master-planned guard-gated community in central Palm Springs between the airport and the Whitewater Wash.\n\nThe layout features an unusual configuration of five par 5s and five par 3s (rather than the traditional four of each), creating a distinctive scoring rhythm. Unobstructed mountain views from every hole and Nicklaus\\\'s signature strategic design at public-access pricing ($59-199 depending on season) make it one of the best values in the Coachella Valley.', signatureHoles: [{ hole: 18, par: 5, yardage: 540, description: 'A memorable finishing par 5 that players specifically highlight. Part of a back nine offering more variety and challenge than the flatter front. One of five par 5s in the distinctive Nicklaus configuration.' }], whatToExpect: 'Unobstructed San Jacinto and San Gorgonio mountain views from every hole. Well-protected greens with plentiful bunkering and water features. The front nine plays flatter and shorter; the back nine offers more variety and challenge.\n\nWind is the defining factor — the course sits in a natural wind corridor and conditions can change rapidly. The five par 5s and five par 3s create a unique scoring rhythm.\n\nOutstanding value for a Nicklaus design at $59-199 depending on season.', playingTips: 'Wind is the biggest challenge — the course sits in a natural wind corridor. Club up and keep ball flight low when the breeze kicks up.\n\nThe long par 3s demand precise iron play. With five of them, your long-iron game defines your score.\n\nThe front nine is more forgiving — use it to build confidence before the tougher back nine.', faqs: [{ question: 'Is this really a Nicklaus design open to the public?', answer: 'Yes — one of the rare Jack Nicklaus courses available for public play at $59-199 depending on season. Outstanding value.' }, { question: 'What makes the layout unusual?', answer: 'Five par 5s and five par 3s (rather than the traditional four of each) create a distinctive scoring rhythm.' }, { question: 'Is wind a factor?', answer: 'Very much so. Escena sits in a natural wind corridor. Conditions can change rapidly — plan club selection accordingly.' }]},
    { id: 'ps-8', name: 'SilverRock Resort', slug: 'silverrock-resort', city: 'Palm Springs', state: 'California', type: 'public', rating: 4.3, greensFee: '$60–$140', architect: 'Arnold Palmer', yearBuilt: 2005, holes: 18, par: 72, yardage: 7578, description: 'An Arnold Palmer Signature design in La Quinta, SilverRock is a city-owned championship course that formerly hosted the Bob Hope Classic. At 7,578 yards with dramatic Santa Rosa Mountain framing, it delivers a premium desert experience at public pricing.', highlights: ['Arnold Palmer Signature design', 'Former Bob Hope Classic host', 'City-owned championship at 7,578 yards'], imageAlt: 'SilverRock Resort Arnold Palmer fairway with Santa Rosa Mountains in La Quinta', history: 'SilverRock Resort is an Arnold Palmer Signature design that opened in 2005 at a reported cost of $58 million — one of the most expensive public courses ever built. Owned by the City of La Quinta, it co-hosted the PGA Tour\\\'s Bob Hope Classic from 2008 to 2011.\n\nAt 7,578 yards, it is one of the longest public courses in the Coachella Valley. The layout sprawls over 200 acres with massive native bunkers and dramatic water features set against the Santa Rosa Mountain backdrop. The front nine was recently renovated with new bermudagrass.\n\nAs a city-owned municipal course with genuine tour pedigree, SilverRock delivers a premium desert experience at public pricing.', signatureHoles: [{ hole: 17, par: 3, yardage: 187, description: 'The consensus signature hole — plays alongside a canal waterway with water guarding the green. The Santa Rosa Mountains frame the backdrop for one of the most scenic par 3s in the valley.' }], whatToExpect: 'A big, bold Arnold Palmer design with wide fairways but desert washes, beach-sand bunkers, and water features creating strategic decisions. Very few forced carries despite the championship length, making it playable for all skill levels from the appropriate tees.\n\nAt 7,578 yards from the tips with two par 5s exceeding 600 yards, tee selection is critical. The front nine was recently renovated.\n\nCity-owned with public access at $60-140 — remarkable value for a former PGA Tour venue.', playingTips: 'Play the appropriate tees. At 7,578 yards from the tips, this is a monster. The wide fairways are forgiving off the tee.\n\nApproach shots must navigate massive bunker complexes — this is where SilverRock bites.\n\nDesert winds amplify in the afternoon. Morning tee times are strongly advisable.\n\nThe recently renovated front nine plays differently than the back — conditions may vary during the transition.', faqs: [{ question: 'Did SilverRock host PGA Tour events?', answer: 'Yes — co-hosted the Bob Hope Classic from 2008 to 2011. One of the most expensive public courses ever built at $58 million.' }, { question: 'Is it really municipal?', answer: 'Yes — owned by the City of La Quinta. Public access at $60-140, making it remarkable value for a course with tour pedigree.' }, { question: 'How long is it?', answer: '7,578 yards from the tips with two par 5s exceeding 600 yards. Multiple tee sets make it playable for all abilities.' }]},
  ],
  'seattle-washington': [
    { id: 'sea-1', name: 'Chambers Bay', slug: 'chambers-bay', city: 'University Place', state: 'Washington', type: 'public', rating: 4.7, greensFee: '$75–$225', architect: 'Robert Trent Jones Jr.', yearBuilt: 2007, holes: 18, par: 72, yardage: 7585, description: 'Host of the 2015 U.S. Open, Chambers Bay is a links-style municipal course built on a former gravel quarry along Puget Sound. The fescue-covered layout features dramatic elevation changes, panoramic water views, and firm-and-fast conditions rare in the Pacific Northwest.', highlights: ['2015 U.S. Open host venue', 'Links-style on former gravel quarry', 'Puget Sound panoramic views'], imageAlt: 'Chambers Bay links fairway overlooking Puget Sound in University Place Washington', history: 'Chambers Bay opened in 2007, designed by Robert Trent Jones Jr. on the site of a former sand and gravel quarry that had produced aggregates for decades (helping build Tacoma and Seattle). The 930-acre Pierce County park transformation was selected to host the 2010 U.S. Amateur and the 2015 U.S. Open within its first year — the first reclaimed mining site ever used for the national championship.\n\nJordan Spieth won the 2015 U.S. Open at age 21, birdieing the 72nd hole while Dustin Johnson famously three-putted from 12 feet on the final green to lose by one. Hole 18 was designed to play as either par 4 or par 5, giving tournament organizers flexibility.\n\nConcrete remnants of the quarry operations remain visible as architectural features throughout the links landscape.', signatureHoles: [{ hole: 15, par: 3, yardage: 185, description: '"Lone Fir" — defined by the single Douglas fir tree standing behind the green, the only tree on the entire course. Tee boxes can be moved dramatically (123-246 yards), creating two completely different looks. One of the most iconic holes in Pacific Northwest golf.' }, { hole: 18, par: 5, yardage: 600, description: 'Designed to play as either par 4 or par 5 (it alternated daily during the 2015 U.S. Open). The site of Spieth\\\'s clinching birdie and Johnson\\\'s heartbreaking three-putt — one of the most dramatic finishing holes in championship history.' }], whatToExpect: 'A true links experience unlike anything else in the Pacific Northwest. Fescue turf, massive dunes carved from old quarry walls, virtually no trees (except the Lone Fir on 15), firm-and-fast conditions, and panoramic Puget Sound views. Dramatic elevation changes from the quarry terrain create one of the most visually striking courses in America.\n\nExpect bouncing fairways, firm greens, and constant wind off the Sound. Walking is the best way to experience the terrain (carts available). Concrete quarry remnants dot the landscape as architectural features.', playingTips: 'Embrace the ground game — this is a links course where bump-and-run shots are the smart play. Fescue fairways promote running the ball.\n\nWind off Puget Sound is constant. Club selection must account for it on every shot.\n\nStudy the pin sheet carefully. Green complexes have dramatic undulation — being on the wrong tier can mean a 60-foot putt.\n\nThe fescue conditions are unlike typical irrigated American courses. The ball bounces and runs dramatically.', faqs: [{ question: 'Did Chambers Bay really host the U.S. Open?', answer: 'Yes — the 2015 U.S. Open, won by Jordan Spieth at age 21. It was the first reclaimed mining site ever used for the national championship.' }, { question: 'What is the Lone Fir?', answer: 'The single Douglas fir tree behind the 15th green — the only tree on the entire course. It has become the iconic symbol of Chambers Bay.' }, { question: 'Is it a public course?', answer: 'Yes — a Pierce County municipal course at $75-225. One of the most affordable U.S. Open venues for public play.' }, { question: 'Were the greens controversial?', answer: 'During the 2015 U.S. Open, greens drew criticism as they were transitioning from poa annua to fescue. Conditions have since improved significantly.' }]},
    { id: 'sea-2', name: 'Sahalee Country Club', slug: 'sahalee-country-club', city: 'Sammamish', state: 'Washington', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Ted Robinson', yearBuilt: 1969, holes: 18, par: 72, yardage: 6895, description: 'Carved through towering Douglas firs and Western red cedars in the Pacific Northwest forest, Sahalee hosted the 1998 PGA Championship and 2010 U.S. Senior Open. The tree-lined corridors create an intimate, cathedral-like setting demanding accuracy off every tee.', highlights: ['1998 PGA Championship host', '2010 U.S. Senior Open venue', 'Cathedral-like old-growth forest setting'], imageAlt: 'Sahalee Country Club fairway through towering Douglas fir forest near Seattle', history: 'Sahalee Country Club opened in 1969 in Sammamish, Washington, designed by Ted Robinson through towering Douglas fir and Western red cedar trees. The name comes from a Chinook word meaning "high heavenly ground."\n\nSahalee hosted the 1998 PGA Championship where Vijay Singh claimed his first major title, the 2002 WGC-NEC Invitational, the 2010 U.S. Senior Open, and the 2016 KPMG Women\'s PGA Championship.\n\nThe cathedral-like setting among ancient evergreens makes it one of the most beautiful championship venues in America.', signatureHoles: [{ hole: 2, par: 4, yardage: 445, description: 'A demanding par 4 through a corridor of towering Douglas firs.' }, { hole: 11, par: 4, yardage: 420, description: 'A strong par 4 with green guarded by water and bunkers, pivotal in championship play.' }, { hole: 15, par: 5, yardage: 535, description: 'A risk-reward par 5 tempting long hitters. Water and trees punish aggressive misses.' }, { hole: 18, par: 4, yardage: 430, description: 'A demanding finishing hole through the firs that has decided multiple championships.' }], whatToExpect: 'A cathedral of Pacific Northwest golf. Towering Douglas firs and cedars line every fairway, creating narrow corridors that demand accuracy.\n\nThe course is one of the most demanding in the region, with tight fairways, strategic bunkering, and precise green complexes.', playingTips: 'Accuracy is everything. The towering trees create tight corridors where missing the fairway means a recovery or penalty. Use whatever club keeps you in the fairway.\n\nPacific Northwest conditions mean the course can be soft, so carry distances matter.', faqs: [{ question: 'Can the public play?', answer: 'No. Sahalee is a private club.' }, { question: 'What championships has Sahalee hosted?', answer: 'The 1998 PGA Championship (Vijay Singh), 2002 WGC-NEC Invitational, 2010 U.S. Senior Open, and 2016 KPMG Women\'s PGA Championship.' }, { question: 'What does Sahalee mean?', answer: 'It comes from a Chinook word meaning "high heavenly ground."' }] },
    { id: 'sea-3', name: 'The Golf Club at Newcastle - China Creek', slug: 'newcastle-china-creek', city: 'Newcastle', state: 'Washington', type: 'public', rating: 4.5, greensFee: '$80–$165', architect: 'Robert Cupp & Fred Couples', yearBuilt: 1999, holes: 18, par: 72, yardage: 7024, description: 'Co-designed by Seattle native Fred Couples, China Creek sits on a forested ridge between Lake Washington and the Cascades. On clear days, golfers enjoy views of Mount Rainier, the Seattle skyline, and the Olympic Mountains from multiple holes.', highlights: ['Fred Couples co-design', 'Mount Rainier and Seattle skyline views', 'Ridge-top setting between two mountain ranges'], imageAlt: 'Newcastle China Creek course with Mount Rainier and Seattle skyline in distance', history: 'The Golf Club at Newcastle was developed on a forested ridgetop in Newcastle, Washington, on land that was once home to coal mining operations dating back to the 1880s. The ambitious 36-hole complex was designed by renowned architect Robert E. Cupp in consultation with Masters Champion and Seattle native Fred Couples. The Coal Creek course opened first in 1999, followed by the China Creek course shortly after.\n\nThe China Creek course takes its name from the Chinese immigrant workers who mined coal on the property in the 19th century. Cupp integrated the gently rolling terrain throughout the 6,632-yard layout, creating a course that combines characteristics of Pacific Northwest forest golf with dramatic ridgetop views. The collaboration with Fred Couples brought a tour player\'s perspective to the strategic design.\n\nThe entire Newcastle complex sits on 350 acres and includes a magnificent 44,000 square-foot clubhouse. On clear days, the elevated setting provides panoramic views of Mount Rainier, the Seattle skyline, Lake Washington, and the Olympic Mountains, making it one of the most visually spectacular golf facilities in the Pacific Northwest.', signatureHoles: [{ hole: 1, par: 5, yardage: 621, description: 'A dramatic opening par 5 that stretches over 600 yards with sweeping views of the surrounding valleys and mountains. The downhill tee shot sets up a risk-reward second shot opportunity.' }, { hole: 9, par: 3, yardage: 195, description: 'One of the top-rated par 3s at Newcastle, this hole plays from an elevated tee to a well-bunkered green with panoramic views of the Cascade Range as a backdrop.' }, { hole: 15, par: 5, yardage: 475, description: 'The signature hole at Newcastle, this reachable par 5 features a blind tee shot followed by a bold second-shot decision. Bold players who attack the green are rewarded, but water and bunkers punish mistakes.' }, { hole: 18, par: 4, yardage: 435, description: 'A strong finishing hole with views of Mount Rainier and the Seattle skyline. The demanding approach to an elevated green provides a memorable conclusion to the round.' }], whatToExpect: 'China Creek at Newcastle delivers a Pacific Northwest golf experience defined by stunning natural beauty and strategic course design. The layout winds through mature forest with frequent elevation changes that create dramatic tee shots and approach angles. On clear days, the panoramic views of Mount Rainier, the Seattle skyline, and the Olympic Mountains are among the finest in Washington state golf.\n\nThe course is well-conditioned and plays through a mix of open ridgetop holes and tree-lined corridors. The facility includes excellent practice facilities, a world-class clubhouse, and the companion Coal Creek course for those looking to play 36 holes.', playingTips: 'Elevation changes are the defining characteristic of China Creek, so adjust your club selection accordingly. Downhill holes will play shorter than the yardage suggests, while uphill approaches require extra club. The ridgetop location means wind can be a significant factor, particularly on exposed holes.\n\nThe greens are well-maintained and true, but many feature subtle undulations that can be tricky to read. Take time to study the terrain around each green, as putts tend to break toward the valleys below. Book morning tee times for the best chance of clear weather and spectacular views.', faqs: [{ question: 'Is China Creek at Newcastle open to the public?', answer: 'Yes, China Creek is a public course. Tee times can be booked online and are available to all golfers.' }, { question: 'What is the difference between Coal Creek and China Creek?', answer: 'Coal Creek is the more challenging and higher-rated of the two courses, with more dramatic elevation changes. China Creek features a gentler routing with five par 3s and is slightly more accessible for mid-handicap golfers.' }, { question: 'Can you see Mount Rainier from the course?', answer: 'Yes, on clear days Mount Rainier is visible from numerous holes on both courses. The best views are typically available from late spring through early fall when skies are clearest.' }, { question: 'Did Fred Couples design the course?', answer: 'Fred Couples served as design consultant alongside primary architect Robert E. Cupp. Couples, a Seattle native and Masters Champion, provided player perspective on strategy and playability.' }] },
    { id: 'sea-4', name: 'Washington National Golf Club', slug: 'washington-national-golf-club', city: 'Auburn', state: 'Washington', type: 'public', rating: 4.4, greensFee: '$50–$110', architect: 'John Fought', yearBuilt: 2000, holes: 18, par: 72, yardage: 7304, description: 'A John Fought design built on rolling terrain in Auburn, Washington National features wide fairways, bold bunkering, and panoramic views of Mount Rainier. The championship layout consistently ranks among the top public courses in the Pacific Northwest.', highlights: ['Panoramic Mount Rainier views', 'John Fought championship design', 'Top-ranked Pacific Northwest public course'], imageAlt: 'Washington National Golf Club fairway with Mount Rainier backdrop', history: 'Washington National Golf Club opened in 2000, designed by John Fought, the 1977 U.S. Amateur champion who became an acclaimed golf course architect. Fought built the course on rolling terrain in Auburn, south of Seattle, taking advantage of natural elevation changes and panoramic views of Mount Rainier and the Cascade Range.\n\nFought\'s design features an exceptional array of contrasting aesthetics — wide fairways and bold bunkering on some holes, tight tree-lined corridors on others. The championship layout quickly earned recognition as one of the top public courses in Washington state and the Pacific Northwest.\n\nWashington National consistently ranks among the best public golf experiences in the region, offering a genuine championship test at accessible daily-fee pricing.', signatureHoles: [{ hole: 4, par: 4, yardage: 440, description: 'A par 4 with panoramic Mount Rainier views. One of the most photographed holes in Washington state golf.' }, { hole: 9, par: 4, yardage: 430, description: 'A strong front-nine closer with Fought\'s bold bunkering demanding a precise approach to the green.' }, { hole: 14, par: 3, yardage: 200, description: 'A demanding par 3 with Cascade Mountain views. The green is well-defended and wind can affect play.' }, { hole: 18, par: 5, yardage: 555, description: 'A risk-reward finishing par 5 with Mount Rainier framing the background. A birdie finish is possible for those who manage the strategic bunkering.' }], whatToExpect: 'Washington National offers championship golf with stunning Cascade Range and Mount Rainier views on rolling terrain. Fought\'s varied design keeps every hole interesting, mixing open holes with wooded corridors. At 7,304 yards from the tips it is a serious test.\n\nThe course is accessible at public daily-fee pricing, making it one of the best values in Pacific Northwest golf.', playingTips: 'The Pacific Northwest weather means rain is common. Pack rain gear and expect soft conditions in the cooler months. Summer offers dry, firm conditions and the best mountain views.\n\nFought\'s varied hole designs require different strategies. Some holes reward aggressive play while others demand precision. Pay attention to the contrasting styles.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Daily-fee course with green fees from $50 to $110.' }, { question: 'Who designed it?', answer: 'John Fought, the 1977 U.S. Amateur champion turned golf course architect.' }, { question: 'Can you see Mount Rainier?', answer: 'Yes. Panoramic views of Mount Rainier and the Cascade Range are visible from numerous holes on clear days.' }, { question: 'How far from Seattle?', answer: 'Washington National is in Auburn, approximately 30 minutes south of downtown Seattle.' }] },
    { id: 'sea-5', name: 'Aldarra Golf Club', slug: 'aldarra-golf-club', city: 'Fall City', state: 'Washington', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 2001, holes: 18, par: 72, yardage: 7320, description: 'An ultra-exclusive Tom Fazio design in the Cascade foothills east of Seattle, Aldarra features dramatic elevation changes through old-growth forest with Snoqualmie Valley views. The walking-only policy and limited membership create an intimate, unhurried atmosphere.', highlights: ['Ultra-exclusive Tom Fazio design', 'Walking-only policy', 'Old-growth forest in Cascade foothills'], imageAlt: 'Aldarra Golf Club fairway through Cascade foothill forest near Fall City', history: 'Aldarra Golf Club opened in 2001 as Tom Fazio\\\'s first and still only design in Washington State, built on the 525-acre former Boeing family farm in the Cascade foothills east of Seattle. Conceived as a "players club" — walking-only, no real estate development, focused purely on the golf experience.\n\nFazio was initially reluctant but was won over by the rolling terrain. The result is among the top-rated private courses in the Pacific Northwest. Limited membership keeps it uncrowded, and the walking-only policy reflects a commitment to traditional golf values.', signatureHoles: [{ hole: 15, par: 3, yardage: 234, description: 'The marquee hole — requires threading your tee shot between two large trees framing the green, often described as "kicking a field goal." A demanding long iron with no margin for error.' }, { hole: 3, par: 5, yardage: 550, description: 'A strategic three-shot par 5 with a particularly tricky green, especially when the pin sits on the left side. Demands thoughtful course management from tee to green.' }], whatToExpect: 'Immaculate conditioning — among the purest turf in the Pacific Northwest. The routing weaves through meadows and mature trees with occasional Cascade mountain views. Fazio\\\'s greens are bolder than his typical work, with significant contour. Bent grass throughout runs fast.\n\nThe course demands precision over power. Walking-only policy and limited membership create an intimate, unhurried atmosphere unlike typical Pacific Northwest private clubs.', playingTips: 'Green reading is the primary challenge — the bold putting surfaces are Fazio\\\'s main defense.\n\nBent grass fairways and greens run fast. Adjust for the speed.\n\nThe walking-only routing is designed for walkability, but the terrain rolls. Be prepared for some elevation changes on foot.\n\nAt 71.2 rating / 138 slope, the course has teeth despite not being overpowering in length.', faqs: [{ question: 'Why is it walking-only?', answer: 'The founders conceived Aldarra as a pure "players club" focused on the golf experience. No carts, no real estate development — just walking golf on extraordinary terrain.' }, { question: 'Who designed it?', answer: 'Tom Fazio — his first and still only course in Washington State. Built on the former Boeing family farm in the Cascade foothills.' }, { question: 'Can the public play?', answer: 'No. Aldarra is an ultra-exclusive private club with limited membership.' }]},
    { id: 'sea-6', name: 'Trophy Lake Golf & Casting Club', slug: 'trophy-lake-golf-casting', city: 'Port Orchard', state: 'Washington', type: 'public', rating: 4.2, greensFee: '$40–$75', architect: 'John Fought', yearBuilt: 2005, holes: 18, par: 72, yardage: 7206, description: 'A John Fought design on the Kitsap Peninsula, Trophy Lake combines championship golf with a fly-fishing lake and outdoor recreation. The layout rolls through native Pacific Northwest terrain with wetlands, mature evergreens, and Olympic Mountain views.', highlights: ['Unique golf-and-fishing club concept', 'Olympic Mountain views', 'John Fought design on Kitsap Peninsula'], imageAlt: 'Trophy Lake Golf Club fairway with Pacific Northwest forest and Olympic Mountain views', history: 'Trophy Lake Golf & Casting Club opened in 1999, designed by John Fought — a 1977 U.S. Amateur champion later inducted into the Pacific Northwest Golf Hall of Fame. The course was carved through dense Northwest forest on the Kitsap Peninsula and built around a unique fishing-lodge concept.\n\nBeyond championship golf, the facility includes stocked ponds for fly fishing and casting — one of extremely few courses in the country combining golf with angling. The secluded forest setting makes it feel miles from civilization.\n\nRoutinely rated among the best public venues in Washington State with a course rating of 74.9 and slope of 140 from the back tees.', signatureHoles: [{ hole: 9, par: 4, yardage: 430, description: 'Representative of the course\\\'s character — dramatic elevation change through the woodland setting with deep, ornate bunkers guarding the approach. Some bunkers stretch up to 100 yards in length.' }], whatToExpect: 'A secluded woodland layout with over 80 bunkers averaging 4-5 per hole — among the most elaborately bunkered public courses in the region. Wide fairways invite aggressive play but the deep, ornate bunkers punish misses severely.\n\nDramatic elevation changes throughout the dense Pacific Northwest forest. The fishing-lodge-style clubhouse and stocked trophy lake create a unique atmosphere combining outdoor recreation with championship golf.\n\nOlympic Mountain views appear throughout the round.', playingTips: 'Fairways are wide — take driver confidently. But avoid the deep bunkers at all costs; recovery from the deeper ones costs a full stroke.\n\nElevation changes are significant. Club selection on approaches requires careful attention to uphill/downhill shots.\n\nThe secluded setting means little wind protection — be aware of gusts through the tree corridors.', faqs: [{ question: 'What is the fishing component?', answer: 'Trophy Lake includes stocked ponds for fly fishing and casting — one of extremely few golf courses in the US combining championship golf with angling. The name references the stocked trophy lake on property.' }, { question: 'Who designed it?', answer: 'John Fought, the 1977 U.S. Amateur Champion and Pacific Northwest Golf Hall of Famer. The course opened in 1999.' }, { question: 'How difficult is it?', answer: 'Course rating 74.9 / slope 140 from the back tees. Over 80 bunkers across 18 holes make it a legitimate championship test.' }]},
    { id: 'sea-7', name: 'The Home Course', slug: 'the-home-course', city: 'DuPont', state: 'Washington', type: 'public', rating: 4.3, greensFee: '$35–$65', architect: 'Mike Asmundson', yearBuilt: 2007, holes: 18, par: 72, yardage: 7208, description: 'Built as the home of Washington junior golf, The Home Course in DuPont offers championship-caliber golf at accessible pricing. The layout winds through native prairie grasses with Puget Sound and Mount Rainier views, hosting numerous USGA and Washington State Golf Association events.', highlights: ['Home of Washington junior golf', 'USGA qualifying venue', 'Outstanding value with Mount Rainier views'], imageAlt: 'The Home Course prairie-style fairway with Puget Sound and Mount Rainier views', history: 'Opened June 29, 2007, designed by Mike Asmundson. Immediately ranked No. 2 best public course in Washington by Golfweek. Serves as home of Washington junior golf. Hosted the 2014 U.S. Women\'s Amateur Public Links and served as companion course for the 2010 U.S. Amateur at Chambers Bay. The property was formerly an explosives manufacturing site.', signatureHoles: [{ hole: 5, par: 4, yardage: 440, description: 'Links-style par 4 through prairie grasses with Puget Sound views.' }, { hole: 11, par: 3, yardage: 195, description: 'Demanding par 3 with Mount Rainier backdrop on clear days.' }, { hole: 15, par: 5, yardage: 560, description: 'Risk-reward par 5 through open prairie where wind is constant.' }, { hole: 18, par: 4, yardage: 445, description: 'Strong finishing hole demanding two quality shots.' }], whatToExpect: 'Links-style layout through native prairie with Puget Sound and Rainier views. At 7,208 yards it is a serious test. Exceptional value at municipal pricing.\n\nWalking encouraged on ideal terrain.', playingTips: 'Wind is the primary defense on exposed prairie holes. Links design rewards running approach shots and ground game.', faqs: [{ question: 'Can the public play?', answer: 'Yes. $35-$65, one of Washington\'s best values.' }, { question: 'Championships hosted?', answer: '2014 U.S. Women\'s Amateur Public Links, USGA qualifying, 2010 U.S. Amateur companion.' }, { question: 'Designer?', answer: 'Mike Asmundson, 2007.' }, { question: 'Location?', answer: 'DuPont, south of Tacoma.' }] },
    { id: 'sea-8', name: 'Salish Cliffs Golf Club', slug: 'salish-cliffs-golf-club', city: 'Shelton', state: 'Washington', type: 'resort', rating: 4.5, greensFee: '$60–$120', architect: 'Gene Bates', yearBuilt: 2011, holes: 18, par: 72, yardage: 7269, description: 'Part of the Little Creek Casino Resort on the Squaxin Island Tribe reservation, Salish Cliffs winds through dense Pacific Northwest forest with towering evergreens, native ferns, and moss-covered rock outcroppings. The Gene Bates design has earned numerous best-in-state accolades.', highlights: ['Award-winning tribal casino resort course', 'Dense Pacific Northwest forest setting', 'Gene Bates design with moss-covered outcroppings'], imageAlt: 'Salish Cliffs Golf Club fairway through dense Pacific Northwest forest', history: 'Salish Cliffs opened in 2011, designed by Gene Bates and owned by the Squaxin Island Tribe as part of the Little Creek Casino Resort. Carved from the forests of the Kamilche Valley about 20 minutes north of Olympia, it is widely considered one of Bates\\\'s finest designs among his 150+ worldwide.\n\nRanked among Golfweek\\\'s Top 100 Resort Courses. Sixteen of eighteen holes route through thick Pacific Northwest forest, but Bates carved generously wide fairways so corridors never feel claustrophobic. No residential development is planned, preserving the wilderness character.', signatureHoles: [{ hole: 3, par: 3, yardage: 185, description: 'Recognized by Pacific Northwest Golfer Magazine as one of the "Great Holes of the Northwest." A dramatic drop-shot par 3 through the trees — one of the most visually striking one-shotters in the region.' }, { hole: 9, par: 4, yardage: 420, description: 'Shares an expansive 15,000-square-foot double green with the 18th hole, fronted by a sparkling lake. Both finishing holes sharing one massive green is a memorable and unusual design feature.' }], whatToExpect: 'Dense Pacific Northwest forest with towering evergreens, native ferns, and moss-covered rock outcroppings frame every hole. Significant elevation changes — the course climbs and drops through the Kamilche Valley. Bent grass greens are large and sloping.\n\nEach hole feels secluded and private with no housing development. The tribal ownership ensures the wilderness setting will be permanently preserved.\n\nStay-and-play packages through Little Creek Casino Resort offer good value. Year-round play available.', playingTips: 'Take a cart — the elevation changes between holes are substantial and walking is very difficult.\n\nDownhill holes play shorter; uphill holes play much longer. Adjust club selection for the significant elevation changes.\n\nThe large, sloping greens reward players who study pin positions carefully. Being on the wrong tier means a long, difficult putt.\n\nClub selection on the par 3s is critical given the elevation changes throughout.', faqs: [{ question: 'Who owns Salish Cliffs?', answer: 'The Squaxin Island Tribe, as part of the Little Creek Casino Resort. No residential development is planned, preserving the wilderness setting.' }, { question: 'What is the double green?', answer: 'Holes 9 and 18 share an expansive 15,000-square-foot putting surface fronted by a lake — both finishing holes end at the same green.' }, { question: 'Is it open to the public?', answer: 'Yes — resort/public access at $60-120. Stay-and-play packages through Little Creek Casino offer good value.' }]},
    { id: 'sea-9', name: 'The Home Course', slug: 'the-home-course', city: 'DuPont', state: 'Washington', type: 'public', rating: 4.3, greensFee: '$35–$65', architect: 'Mike Asmundson', yearBuilt: 2007, holes: 18, par: 72, yardage: 7208, description: 'Home of the Washington State Golf Association, The Home Course in DuPont delivers championship-caliber public golf south of Seattle. The links-influenced layout through Puget Sound lowland features firm fescue fairways, strategic bunkering, and views of Mount Rainier on clear days at outstanding value.', highlights: ['Home of Washington State Golf Association', 'Links-influenced fescue fairways', 'Mount Rainier views at outstanding value'], imageAlt: 'The Home Course links fairway with Mount Rainier views in DuPont Washington', history: 'The Home Course opened in 2007, designed by Mike Asmundson. Jointly owned by Washington Golf (formerly WSGA) and the Pacific Northwest Golf Association (PNGA), it serves as the home venue for amateur championship golf in Washington State.\n\nImmediately ranked No. 2 Public Course in Washington by Golfweek. Hosted the final U.S. Women\\\'s Amateur Public Links in 2014 along with numerous state, regional, and national championships. The WSGA/PNGA ownership ensures championship maintenance standards year-round.', signatureHoles: [{ hole: 7, par: 3, yardage: 195, description: 'One of several above-average par 3s that reviewers consistently single out. Each demands accurate iron play to well-defended greens — the par 3s are the highlight collection of the course.' }], whatToExpect: 'A links-inspired layout on open terrain with fescue rough, panoramic views of Puget Sound, the Olympic Mountains, and Mount Rainier. Greens run fast and are well-contoured. Fully walkable by design.\n\nGenerous off the tee but demanding on approaches — bunkers surround the greens and must be avoided. Wind is a constant factor on this exposed Puget Sound lowland site.\n\nAt $35-65, one of the best public course values in the Pacific Northwest. The course can stretch to 7,450 yards for competitive play.', playingTips: 'Wind management is essential on this open, exposed terrain. Breezes off Puget Sound are constant.\n\nKeep the ball below the hole on the fast greens. Avoid greenside bunkers at all costs — the short game challenge is the primary defense.\n\nBall-striking and course management are rewarded over raw power. The generous fairways mean the test is in the approach game.', faqs: [{ question: 'What is the WSGA connection?', answer: 'The Home Course is jointly owned by Washington Golf (WSGA) and the Pacific Northwest Golf Association, serving as the home venue for state amateur championships.' }, { question: 'Is it walkable?', answer: 'Yes — the walkable layout is a deliberate design choice reflecting traditional golf values.' }, { question: 'What are the views like?', answer: 'Panoramic views of Puget Sound, the Olympic Mountains, and Mount Rainier on clear days. The links-style open terrain provides expansive sightlines.' }]},
    { id: 'sea-10', name: 'Washington National Golf Club', slug: 'washington-national-gc', city: 'Auburn', state: 'Washington', type: 'public', rating: 4.2, greensFee: '$40–$80', architect: 'John Fought', yearBuilt: 2000, holes: 18, par: 72, yardage: 7304, description: 'A John Fought design south of Seattle in Auburn, Washington National features a dramatic routing through the Green River Valley with views of Mount Rainier and the Cascades. The 7,304-yard championship layout has hosted U.S. Open qualifiers and provides one of the strongest public golf tests in the Seattle metro area.', highlights: ['U.S. Open qualifier host venue', 'Mount Rainier and Cascade views', 'John Fought 7,304-yard championship layout'], imageAlt: 'Washington National Golf Club fairway with Mount Rainier views in Auburn', history: 'Washington National Golf Club opened in 2000, designed by John Fought (1977 U.S. Amateur Champion) in Auburn southeast of Seattle. The course serves as the home venue for the University of Washington men\\\'s and women\\\'s golf teams and has hosted U.S. Open qualifying.\n\nFought created a championship layout at 7,304 yards featuring contrasting aesthetics — rugged natural areas alongside manicured playing surfaces — with Mount Rainier and Cascade views as a backdrop.', signatureHoles: [{ hole: 7, par: 4, yardage: 430, description: 'A strong risk/reward hole where longer hitters can challenge water and go directly at the green, while the conservative route plays safely right. Strategic decision-making off the tee defines the outcome.' }], whatToExpect: 'A championship-length test at 7,304 yards from the Husky tees with bent grass throughout. The layout blends ponds, tree-lined fairways, and doglegs. Forgiving off the tee on most holes but demands accurate approach play.\n\nMount Rainier and Cascade Range views provide a stunning Northwest backdrop. The walkable terrain blends flat and gently rolling sections. Conditions are strong year-round, though Pacific Northwest winters bring softer conditions.\n\nPublic access at quality comparable to many private clubs.', playingTips: 'Choose tees wisely — the championship length is a serious test. Use a GPS or rangefinder; yardage markers can be hard to find on some holes.\n\nOn risk/reward holes, know your carry distances precisely before challenging water.\n\nApproach shot accuracy matters more than driving distance. The greens are well-defended.\n\nIn winter months, expect softer conditions and adjust club selection accordingly.', faqs: [{ question: 'Is this the UW Huskies home course?', answer: 'Yes — Washington National serves as the home venue for the University of Washington men\\\'s and women\\\'s golf teams.' }, { question: 'Has it hosted professional qualifying?', answer: 'Yes — U.S. Open qualifiers have been held here, confirming its championship caliber.' }, { question: 'Who designed it?', answer: 'John Fought, the 1977 U.S. Amateur Champion also known for Pumpkin Ridge and other acclaimed Pacific Northwest designs.' }]},
    { id: 'sea-11', name: 'Sahalee Country Club', slug: 'sahalee-country-club', city: 'Sammamish', state: 'Washington', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Ted Robinson', yearBuilt: 1969, holes: 18, par: 72, yardage: 6928, description: 'Host of the 1998 PGA Championship and the 2010 U.S. Senior Open, Sahalee is the Pacific Northwest\'s most decorated championship venue. The tight, tree-lined layout through towering Douglas fir and western red cedar creates a cathedral-like atmosphere that demands precision on every shot.', highlights: ['1998 PGA Championship and 2010 U.S. Senior Open host', 'Cathedral-like Douglas fir forest setting', 'Pacific Northwest\'s premier championship venue'], imageAlt: 'Sahalee Country Club fairway through towering Douglas fir forest in Sammamish', history: 'Opened 1969, designed by Ted Robinson through towering Douglas fir and cedar. Name means "high heavenly ground" in Chinook. Hosted 1998 PGA Championship (Vijay Singh), 2002 WGC-NEC Invitational, 2010 U.S. Senior Open, and 2016 KPMG Women\'s PGA.', signatureHoles: [{ hole: 2, par: 4, yardage: 445, description: 'Demanding par 4 through firs.' }, { hole: 11, par: 4, yardage: 420, description: 'Strong par 4 with water guarding green.' }, { hole: 15, par: 5, yardage: 535, description: 'Risk-reward par 5.' }, { hole: 18, par: 4, yardage: 430, description: 'Championship-deciding finisher.' }], whatToExpect: 'Cathedral of PNW golf with towering firs creating narrow corridors. One of the region\'s most demanding courses.', playingTips: 'Accuracy is everything. Use whatever club keeps you in the fairway.', faqs: [{ question: 'Public?', answer: 'No. Private.' }, { question: 'Championships?', answer: '1998 PGA, 2002 WGC, 2010 US Senior Open, 2016 KPMG Women\'s PGA.' }] },
  ],
  'boston-massachusetts': [
    { id: 'bos-1', name: 'The Country Club', slug: 'the-country-club-brookline', city: 'Brookline', state: 'Massachusetts', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'William Flynn', yearBuilt: 1893, holes: 18, par: 71, yardage: 7264, description: 'One of the five founding members of the USGA, The Country Club in Brookline is hallowed ground in American golf. Host of the 1913, 1963, and 1988 U.S. Opens, the 1999 Ryder Cup, and the 2022 U.S. Open, its William Flynn composite course is a masterclass in strategic architecture.', highlights: ['Five-time U.S. Open host including 2022', '1999 Ryder Cup venue', 'Founding member of the USGA since 1893'], imageAlt: 'The Country Club in Brookline historic fairway with classic New England setting', history: 'Founded in 1882 as one of America\'s oldest country clubs and a founding USGA member in 1894. Golf established 1893, later redesigned by William Flynn.\n\nFrancis Ouimet\'s 1913 U.S. Open playoff victory here over Vardon and Ray democratized American golf. Also hosted the 1963 and 1988 U.S. Opens, the famous 1999 Ryder Cup comeback, and the 2022 U.S. Open won by Matt Fitzpatrick.', signatureHoles: [{ hole: 4, par: 3, yardage: 200, description: 'Demanding par 3 testing long-iron play.' }, { hole: 11, par: 4, yardage: 450, description: 'Strong par 4 pivotal in U.S. Open play.' }, { hole: 17, par: 4, yardage: 370, description: 'The famous 17th from the 1913 and 1999 matches where history was made.' }, { hole: 18, par: 4, yardage: 435, description: 'Where Fitzpatrick clinched the 2022 U.S. Open.' }], whatToExpect: 'One of the most historically significant courses in world golf. Classic New England terrain with stone walls, mature trees, and Flynn\'s strategic green complexes. At 7,264 yards par 71.', playingTips: 'Flynn\'s green complexes are the primary defense with subtle, deceptive contours. A caddie is essential for the composite layout.', faqs: [{ question: 'Public?', answer: 'No. One of America\'s most exclusive private clubs.' }, { question: 'Francis Ouimet?', answer: 'In 1913, unknown amateur Ouimet defeated Vardon and Ray in a U.S. Open playoff, democratizing American golf.' }, { question: '1999 Ryder Cup?', answer: 'The U.S. team mounted a historic final-day comeback to win.' }] },
    { id: 'bos-2', name: 'Salem Country Club', slug: 'salem-country-club', city: 'Peabody', state: 'Massachusetts', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Donald Ross', yearBuilt: 1926, holes: 18, par: 72, yardage: 6843, description: 'A Donald Ross masterpiece on the North Shore, Salem Country Club hosted the 2017 U.S. Senior Open. The classic Ross design features crowned greens, strategic bunkering, and a parkland setting through mature New England hardwoods that has stood the test of time.', highlights: ['2017 U.S. Senior Open host', 'Classic Donald Ross crowned greens', 'Historic North Shore parkland setting'], imageAlt: 'Salem Country Club Donald Ross fairway through New England hardwoods', history: 'Salem Country Club was established in 1895 and moved to its current Peabody, Massachusetts location where Donald Ross designed the championship course that opened in 1926. Ross created a classic New England parkland layout through mature hardwoods on the North Shore, featuring his trademark crowned greens and strategic bunkering.\n\nThe club has hosted an impressive roster of USGA championships: the 1932 U.S. Women\'s Amateur, the 1954 U.S. Women\'s Open won by Babe Didrikson Zaharias while recovering from cancer treatment, the 1984 U.S. Women\'s Open won by Hollis Stacy, and both the 2001 and 2017 U.S. Senior Opens.\n\nSalem has undergone careful restoration to preserve Ross\'s original design intent while maintaining the course for modern championship play.', signatureHoles: [{ hole: 4, par: 4, yardage: 435, description: 'A long, demanding par 4 consistently ranked among the most difficult holes on the course. The approach must find a crowned Ross green defended by deep bunkers.' }, { hole: 9, par: 4, yardage: 410, description: 'A beautiful finishing hole on the front nine through a corridor of mature hardwoods with a classic Ross green featuring fall-offs on all sides.' }, { hole: 14, par: 3, yardage: 185, description: 'A signature par 3 with a demanding carry to a well-bunkered green. Wind through the trees and the crowned putting surface make this a tricky one-shotter.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finishing par 4 demanding two quality shots to a green complex that has decided many USGA championships.' }], whatToExpect: 'Salem Country Club is a quintessential Donald Ross New England parkland course. Mature hardwood trees frame every hole, and the terrain rolls gently through the North Shore landscape. Ross\'s crowned greens shed approach shots that miss the center, creating challenging up-and-down situations.\n\nAt 6,843 yards with a par of 72, the course relies on precision rather than length. Conditioning is outstanding, and the classic Ross routing provides excellent variety.', playingTips: 'The crowned greens are the key to scoring. Approach shots must land on the correct portion, as misses roll off the edges into collection areas and bunkers. Favor the center of each putting surface.\n\nThe New England hardwoods create tight corridors on many holes. Accuracy off the tee is essential. Play to the wide side of fairways and accept the longer approach.', faqs: [{ question: 'Can the public play Salem Country Club?', answer: 'No. Salem Country Club is a private club with no public access.' }, { question: 'What major championships has Salem hosted?', answer: 'The 1932 U.S. Women\'s Amateur, the 1954 and 1984 U.S. Women\'s Opens, and the 2001 and 2017 U.S. Senior Opens.' }, { question: 'Who won the famous 1954 U.S. Women\'s Open at Salem?', answer: 'Babe Didrikson Zaharias won in one of sport\'s most inspiring victories, competing while recovering from cancer treatment.' }, { question: 'Who designed Salem Country Club?', answer: 'Donald Ross designed the course, which opened in 1926, featuring his trademark crowned greens and strategic bunkering.' }] },
    { id: 'bos-3', name: 'Pinehills Golf Club - Jones Course', slug: 'pinehills-jones', city: 'Plymouth', state: 'Massachusetts', type: 'public', rating: 4.4, greensFee: '$65–$130', architect: 'Rees Jones', yearBuilt: 2001, holes: 18, par: 72, yardage: 7175, description: 'A Rees Jones design through the pine barrens of Plymouth, Pinehills Jones Course delivers championship-caliber public golf south of Boston. The layout carves through pitch pines and scrub oaks with well-crafted bunkering and excellent conditioning.', highlights: ['Championship public golf south of Boston', 'Pine barrens setting in Plymouth', 'Rees Jones design with excellent conditioning'], imageAlt: 'Pinehills Jones Course fairway through Plymouth pine barrens', history: 'Pinehills Jones Course opened in 2001 on 300 acres of glacially carved terrain in Plymouth, Massachusetts. Designed by Rees Jones — "The Open Doctor" known for his U.S. Open renovation work — the layout evokes historic New England golf through pine barrens reminiscent of the region\\\'s oldest courses.\n\nThe Jones Course shares a clubhouse with a companion Nicklaus Design course, making Pinehills one of New England\\\'s premier daily-fee facilities. The glacial terrain creates natural amphitheaters and significant elevation changes through pitch pines and scrub oaks.', signatureHoles: [{ hole: 14, par: 4, yardage: 420, description: 'A demanding par 4 through the pine barrens corridor. The tight, tree-lined fairway demands accuracy while the sandy, firm conditions create a classic New England feel. Representative of the course\\\'s championship character.' }], whatToExpect: 'Classic Rees Jones design: challenging for experts yet enjoyable for all skill levels, with deep respect for the natural landscape. Pine-lined fairways create seclusion on every hole. The glacial terrain produces significant elevation changes and firm, fast conditions on sandy soil.\n\nThe Jones Course is rated the more challenging of the two Pinehills layouts. Five tee sets range from 5,185 to 7,243 yards.\n\nPlymouth\\\'s proximity to Cape Cod makes it a strong addition to any golf trip through southeastern Massachusetts.', playingTips: 'Missing fairways is the cardinal sin — the pine barrens and native areas are extremely penal. Accuracy off the tee matters far more than distance.\n\nThe sandy soil creates firm, fast conditions. Expect extra roll on fairways and firm greens.\n\nThe undulating greens require careful reading. Don\\\'t assume flat putts — the glacial terrain creates subtle slopes throughout.', faqs: [{ question: 'How does the Jones Course compare to the Nicklaus Course?', answer: 'The Jones Course is rated more challenging — tighter corridors through the pines with more demanding approach shots. The Nicklaus Course is slightly more forgiving.' }, { question: 'Is it open to the public?', answer: 'Yes — daily-fee public access. Premium pricing (~$160 at prime time) with better value at twilight.' }, { question: 'Who designed it?', answer: 'Rees Jones ("The Open Doctor"), opening in 2001 on glacially carved terrain in Plymouth.' }]},
    { id: 'bos-4', name: 'George Wright Golf Course', slug: 'george-wright-golf-course', city: 'Boston', state: 'Massachusetts', type: 'public', rating: 4.2, greensFee: '$25–$55', architect: 'Donald Ross', yearBuilt: 1938, holes: 18, par: 70, yardage: 6418, description: 'A hidden Donald Ross gem in Boston\'s Hyde Park neighborhood, George Wright is widely regarded as one of the best municipal courses in America. The restored Ross design features classic crowned greens, strategic bunkering, and excellent value in the heart of the city.', highlights: ['Donald Ross municipal masterpiece', 'Among America\'s best city-owned courses', 'Restored classic design at affordable pricing'], imageAlt: 'George Wright Golf Course Donald Ross municipal layout in Boston Hyde Park', history: 'George Wright Golf Course was originally commissioned to Donald Ross in the 1920s, but the 1929 stock market crash halted the project. Walter Irving Johnson, a former Ross associate, completed the build using Ross\\\'s plans, and the course opened in 1938 as a WPA-era municipal project in Boston\\\'s Hyde Park neighborhood.\n\nBeginning in 2003, architect Mark Mungeam undertook an ongoing restoration to recover Ross\\\'s original design intent — clearing encroaching trees, restoring green contours, and reclaiming bunker lines. The restoration has elevated George Wright into discussions as one of the best municipal courses in America.\n\nNamed for George Wright, a 19th-century baseball pioneer.', signatureHoles: [{ hole: 15, par: 5, yardage: 490, description: 'Frequently cited as the signature hole — a demanding par 5 that epitomizes the course\\\'s character with strategic options and Ross\\\'s characteristic crowned green complex.' }, { hole: 5, par: 4, yardage: 426, description: 'One of the most interesting holes, requiring a well-placed drive and a testing approach to a contoured Ross green. Classic Golden Age design at its best.' }], whatToExpect: 'An urban course with a surprisingly sylvan feel — mature trees line most holes, and a few holes capture Boston skyline views. Ross\\\'s trademark crowned, tilted greens with fallaway edges are the primary defense.\n\nSeveral holes feature blind or semi-blind shots, adding old-school character. At par 70 and 6,418 yards, it is not long but the green complexes make it play harder than the yardage suggests.\n\nThe Mungeam restoration has dramatically improved both conditions and design clarity. Green fees remain municipal-affordable — extraordinary value for Ross architecture.', playingTips: 'Study the greens carefully. Ross\\\'s putting surfaces are deceptively contoured — missing on the wrong side leaves very difficult up-and-downs.\n\nOn blind-shot holes, trust the lines suggested by the terrain and play conservatively until you learn the course.\n\nAt par 70 and under 6,500 yards, the course is playable for all skill levels but punishes sloppy short games.\n\nGeese are a constant presence and unafraid of golfers. Plan accordingly.', faqs: [{ question: 'Is this really a Donald Ross design?', answer: 'Yes — Ross designed it in the 1920s. His associate Walter Irving Johnson completed construction using Ross\\\'s plans when the Depression halted the project. It opened in 1938.' }, { question: 'How affordable is it?', answer: 'Municipal pricing at $25-55. Extraordinary value for a restored Donald Ross design — one of the best deals in American golf.' }, { question: 'What was the restoration?', answer: 'Architect Mark Mungeam has been restoring Ross\\\'s original design intent since 2003 — clearing trees, restoring green contours, and reclaiming bunker lines. The work has elevated it into top-municipal-course discussions.' }]},
    { id: 'bos-5', name: 'Boston Golf Club', slug: 'boston-golf-club', city: 'Hingham', state: 'Massachusetts', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Gil Hanse', yearBuilt: 2005, holes: 18, par: 72, yardage: 6931, description: 'A Gil Hanse design on the South Shore, Boston Golf Club occupies a stunning coastal property with views of Boston Harbor. The modern layout integrates seamlessly with the rocky New England terrain, featuring creative green complexes and strategic bunkering.', highlights: ['Gil Hanse modern design', 'Boston Harbor coastal views', 'Rocky New England terrain integration'], imageAlt: 'Boston Golf Club coastal fairway with Boston Harbor views in Hingham', history: 'Boston Golf Club opened in 2005, designed by Gil Hanse on dramatic coastal topography in Hingham on Boston\\\'s South Shore. Golf Digest compared it to Pine Valley, calling it "a modern-day Pine Valley massaged from dramatic coastal topography." It has received numerous accolades since opening and is regularly ranked among the best modern courses in America.\n\nHanse — who went on to design the 2016 Olympic course in Rio — crafted a layout where firm, fast conditions and strategic ground-game creativity define the experience. At just under 7,000 yards, the course relies on angles, contours, and positioning rather than brute length.', signatureHoles: [{ hole: 12, par: 4, yardage: 410, description: 'One of many holes where Hanse\\\'s philosophy of letting the land dictate the routing is evident. Natural undulation and strategic bunkering reward thoughtful positioning over power. No two holes feel alike on this varied coastal layout.' }], whatToExpect: 'Firm, fast conditions are the hallmark. Tight fairways, well-manicured bunkers, and immaculate tee boxes. The coastal setting provides occasional Boston Harbor views with a wide variety of hole characters.\n\nAt 6,931 yards, the course is not overly long but its defenses are angles, contours, and positioning. Bump-and-run approaches are often the smart play on the firm turf.\n\nStrictly private — widely regarded as one of the top private courses built in the 21st century.', playingTips: 'Course management is everything. Think about where you want to miss, not just where you want to hit.\n\nFirm conditions mean bump-and-run approaches are often smarter than lofted shots.\n\nThe greens have subtle movement rewarding local knowledge. Ask your host for reading advice.\n\nAt under 7,000 yards, this is a course where strategy beats power every time.', faqs: [{ question: 'Why is it compared to Pine Valley?', answer: 'Golf Digest called it "a modern-day Pine Valley massaged from dramatic coastal topography." The strategic depth, firm conditions, and varied hole characters earn the comparison.' }, { question: 'Who designed it?', answer: 'Gil Hanse, who went on to design the 2016 Olympic course in Rio. Boston Golf Club is considered one of his most celebrated original designs.' }, { question: 'Can the public play?', answer: 'No. Strictly private — access requires a member invitation.' }]},
    { id: 'bos-6', name: 'Granite Links Golf Club', slug: 'granite-links-golf-club', city: 'Quincy', state: 'Massachusetts', type: 'public', rating: 4.3, greensFee: '$75–$140', architect: 'John Sanford', yearBuilt: 2003, holes: 27, par: 72, yardage: 6828, description: 'Built atop former granite quarries south of Boston, Granite Links offers 27 holes with spectacular views of the Boston skyline, Blue Hills, and harbor islands. The elevated terrain creates a unique golfing experience with dramatic elevation changes uncommon in coastal Massachusetts.', highlights: ['Built on former granite quarries', 'Boston skyline and harbor views', '27 holes with dramatic elevation changes'], imageAlt: 'Granite Links Golf Club elevated fairway with Boston skyline views', history: 'Granite Links opened in 2003, built atop two former landfill sites and old granite quarries south of Boston. An estimated 900,000 truckloads of material from Boston\\\'s Big Dig project helped shape the terrain — one of the most remarkable land reclamation stories in golf.\n\nDesigned by John Sanford, the 27 holes were built piecemeal over a long period as land became available. The result transformed an environmental liability into a premier public golf destination just seven miles from downtown Boston.\n\nThe elevated terrain creates spectacular panoramic views of the Boston skyline, Blue Hills Reservation, and Harbor Islands simultaneously.', signatureHoles: [{ hole: 7, par: 4, yardage: 400, description: 'On the Granite nine — features dramatic quarry rock walls framing the hole, with elevated tees offering panoramic Boston skyline views. The quarry features create a visual experience unlike any other course in New England.' }], whatToExpect: 'Three nines (Granite, Milton, and Quincy) playable in any 18-hole combination. Plenty of hills and elevation changes create an athletic round with significant uphill and downhill shots. Dramatic quarry rock walls and old quarry faces frame several holes.\n\nThe Boston skyline views are genuinely spectacular — among the best urban panoramas from any golf course in America. The on-site Tavern restaurant also takes advantage of the views.\n\nSome holes have quirky features born from the site\\\'s industrial past.', playingTips: 'The hilly terrain means many uneven lies. Solid ball-striking fundamentals are essential.\n\nWind can be a factor on the exposed, elevated holes. Club selection must account for both wind and elevation changes.\n\nClub up on uphill approaches more than you think — the elevation is deceptive.\n\nLocal knowledge helps with the quirky features from the site\\\'s industrial past.', faqs: [{ question: 'What is the Big Dig connection?', answer: 'An estimated 900,000 truckloads of material from Boston\\\'s Big Dig project helped shape the terrain, transforming former landfills and quarries into a premier golf destination.' }, { question: 'How many holes?', answer: '27 holes across three nines (Granite, Milton, Quincy). Any two combine for an 18-hole round.' }, { question: 'Can you see the Boston skyline?', answer: 'Yes — spectacular panoramic views of the Boston skyline, Blue Hills, and Harbor Islands from the elevated terrain. Among the best urban panoramas from any golf course.' }]},
    { id: 'bos-7', name: 'Myopia Hunt Club', slug: 'myopia-hunt-club', city: 'South Hamilton', state: 'Massachusetts', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Herbert Leeds', yearBuilt: 1894, holes: 18, par: 72, yardage: 6555, description: 'A four-time U.S. Open host from 1898 to 1908, Myopia Hunt Club is one of the most historic courses in America. The Herbert Leeds design on Boston\'s North Shore features devilish green contours, blind shots, and the quirky charm of Golden Age architecture.', highlights: ['Four-time early U.S. Open host 1898–1908', 'Herbert Leeds Golden Age design', 'Devilish green contours and blind shots'], imageAlt: 'Myopia Hunt Club historic fairway on Boston North Shore', history: 'Myopia Hunt Club is one of the most historically significant courses in America, with roots dating to 1894. Herbert Corey Leeds — who both designed the course and competed (he tied for 7th in the 1898 U.S. Open played on his own course) — laid out the original nine in 1894 and expanded to 18 by 1898.\n\nMyopia hosted four U.S. Opens at the turn of the 20th century: 1898, 1901, 1905, and 1908. The 1901 U.S. Open produced a winning score of 331 — still the highest winning total in championship history. Leeds is sometimes called "the Papa of American Golf Architecture."\n\nThe club has deep equestrian and polo roots alongside its golf heritage, originally moving from Winchester to Hamilton in 1891.', signatureHoles: [{ hole: 10, par: 4, yardage: 404, description: 'An Alps-style hole with a completely blind tee shot that epitomizes Myopia\\\'s old-world character. No modern course would dare build this — it is quirky, challenging, and utterly charming.' }, { hole: 4, par: 4, yardage: 380, description: 'One of the most talked-about holes — a dogleg wrapping around a marsh area. The green is so fast and severely sloped that it famously has just one viable pin position. Putting from above the hole can send the ball off the surface entirely.' }], whatToExpect: 'Blind shots, tiny greens, and putting surfaces so fast that balls above the hole can roll off entirely. This is old-school golf with minimal modern softening — a test of creativity, imagination, and course management unlike anything built today.\n\nThe course opens gently then progressively increases in difficulty and quirkiness. At 6,555 yards and par 72, it is not long, but the small greens and devilish contours create one of the most demanding short-game tests in American golf.\n\nStrictly private — a pilgrimage site for golf history enthusiasts.', playingTips: 'Aim for the fat side of every green and always stay below the hole. On Myopia\\\'s tiny, severely contoured greens, above-the-hole putts are genuinely terrifying.\n\nFairway-finder clubs off the tee are often wiser than driver. Positioning beats distance on nearly every hole.\n\nLocal knowledge is invaluable given the blind shots and hidden contours. Listen to your host.\n\nApproach from the correct angle on every hole — the small greens only accept shots from specific sides.', faqs: [{ question: 'How many U.S. Opens did Myopia host?', answer: 'Four — 1898, 1901, 1905, and 1908. The 1901 Open produced a winning score of 331, still the highest in championship history.' }, { question: 'Who designed it?', answer: 'Herbert Corey Leeds, who also competed in the events held on his own course. He is sometimes called "the Papa of American Golf Architecture."' }, { question: 'Can the public play?', answer: 'No. Myopia Hunt Club is strictly private with deep equestrian and polo traditions alongside golf. Access requires a member invitation.' }]},
    { id: 'bos-8', name: 'Red Tail Golf Club', slug: 'red-tail-golf-club', city: 'Devens', state: 'Massachusetts', type: 'semi-private', rating: 4.4, greensFee: '$65–$115', architect: 'Brian Silva', yearBuilt: 2002, holes: 18, par: 72, yardage: 7015, description: 'Built on the former Fort Devens military base, Red Tail is a Brian Silva design that draws on Golden Age principles with modern playability. The layout features chocolate-drop mounds, geometric bunkering, and a natural routing through rolling terrain west of Boston.', highlights: ['Brian Silva Golden Age-inspired design', 'Built on former Fort Devens military base', 'Chocolate-drop mounds and geometric bunkering'], imageAlt: 'Red Tail Golf Club Golden Age style fairway at former Fort Devens', history: 'Opened in 2002 on the former Fort Devens military base. Brian Silva designed a Golden Age-inspired layout with chocolate-drop mounds and geometric bunkering reminiscent of Seth Raynor and Charles Banks. Recognized as one of the best semi-private courses in New England.', signatureHoles: [{ hole: 4, par: 4, yardage: 410, description: 'Strategic par 4 with geometric bunkering and chocolate-drop mounds.' }, { hole: 9, par: 3, yardage: 185, description: 'Golden Age template-inspired par 3 with a demanding green complex.' }, { hole: 14, par: 4, yardage: 430, description: 'Strong par 4 through rolling terrain with strategic bunkering.' }, { hole: 18, par: 5, yardage: 540, description: 'Reachable finishing par 5 with risk-reward options.' }], whatToExpect: 'A treat for architecture enthusiasts. Distinctive chocolate-drop mounds, geometric bunkers, and creative green complexes on rolling former military land. At 7,015 yards it is a championship test.\n\nSemi-private format provides public access to private-club quality design.', playingTips: 'Silva designed for ground game. Running approaches through openings between mounds and bunkers is often more effective than aerial attacks.\n\nGeometric bunkering creates visual cues about intended approach angles.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Semi-private, $65-$115.' }, { question: 'What was Fort Devens?', answer: 'A decommissioned U.S. Army base in north-central Massachusetts.' }, { question: 'Designer?', answer: 'Brian Silva, 2002.' }, { question: 'What are chocolate-drop mounds?', answer: 'Rounded mounds around greens inspired by Golden Age architects like Seth Raynor.' }] },
    { id: 'bos-9', name: 'Pinehills Golf Club - Nicklaus', slug: 'pinehills-nicklaus', city: 'Plymouth', state: 'Massachusetts', type: 'public', rating: 4.2, greensFee: '$55–$100', architect: 'Jack Nicklaus', yearBuilt: 2001, holes: 18, par: 72, yardage: 7175, description: 'A Jack Nicklaus design on the South Shore at Plymouth, Pinehills Nicklaus offers championship-level public golf through pine and cranberry bog terrain. The 7,175-yard layout features Nicklaus\'s bold green complexes, strategic bunkering, and the characteristic sandy terrain of southeastern Massachusetts.', highlights: ['Jack Nicklaus championship public design', 'Pine and cranberry bog terrain on South Shore', '7,175-yard layout at public pricing'], imageAlt: 'Pinehills Nicklaus Course fairway through Plymouth pine forest', history: 'The Nicklaus Course at Pinehills opened in 2002, designed by the Jack Nicklaus Design Group on land roughly an hour south of Boston in Plymouth. Part of a 36-hole complex paired with a Rees Jones design, it is one of New England\\\'s premier daily-fee facilities.\n\nThe routing weaves through mature pine forests, wetlands, and actively maintained 100-year-old cranberry bogs — a landscape unique in American golf. Consistently rated among the top public courses in Massachusetts.', signatureHoles: [{ hole: 4, par: 4, yardage: 420, description: 'The No. 1 handicap hole — a slightly downhill dogleg left where the fairway narrows sharply toward an angled green. Demands precision off the tee and sets the tone for the round.' }], whatToExpect: 'Each hole feels isolated in its own corridor of pines, creating a private-club atmosphere on a public course. The cranberry bog carries are mostly visual intimidation, but stray shots have zero margin.\n\nConditioning is typically strong. The sandy southeastern Massachusetts terrain creates firm, fast conditions. Practice facilities are among the most extensive in the region.\n\nPaired with the Rees Jones Course for a full 36-hole day.', playingTips: 'Club selection off the tee is critical — many holes reward positioning over power, especially where fairways tighten near landing zones.\n\nThe cranberry bog carries look intimidating but are manageable with confident swings. Don\\\'t bail out.\n\nWind picks up on the more exposed holes. Factor it into every club selection.\n\nSandy soil creates firm conditions — expect extra roll on fairways.', faqs: [{ question: 'How does it compare to the Jones Course?', answer: 'The Nicklaus Course is slightly more forgiving with wider corridors. The Jones Course is tighter through the pines. Both are championship caliber.' }, { question: 'What are the cranberry bogs?', answer: 'Actively maintained 100-year-old cranberry bogs are integrated into several holes — a landscape feature unique in American golf.' }, { question: 'Is it open to the public?', answer: 'Yes — daily-fee public access at $55-100.' }]},
    { id: 'bos-10', name: 'Kittansett Club', slug: 'kittansett-club', city: 'Marion', state: 'Massachusetts', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'William Flynn (attributed) / Fred Hood', yearBuilt: 1922, holes: 18, par: 71, yardage: 6596, description: 'A seaside links gem on Buzzards Bay south of Boston, Kittansett is one of the finest private courses in New England. The compact par-71 features spectacular waterfront holes, firm fescue conditions, and a windswept character that rewards creative shotmaking along the rocky Massachusetts coastline.', highlights: ['Spectacular Buzzards Bay seaside links', 'One of the finest private clubs in New England', 'Windswept fescue conditions along rocky coastline'], imageAlt: 'Kittansett Club seaside links fairway along Buzzards Bay', history: 'Kittansett Club sits on a peninsula jutting into Buzzards Bay in Marion, Massachusetts, founded in the early 1920s. The club engaged both Donald Ross and William Flynn; they ultimately went with Flynn\\\'s plans, but founding member Frederic Hood personally led construction and refined the course over two decades, blending American and British design elements.\n\nKittansett hosted the 1953 Walker Cup and the 2022 U.S. Senior Amateur. Ranked among the top courses in Massachusetts, it consistently appears on national top-100 lists as one of the finest Flynn designs in existence.', signatureHoles: [{ hole: 3, par: 4, yardage: 380, description: 'A standout seaside hole in the celebrated stretch from holes 3 through 8 that runs along Buzzards Bay. Constantly shifting wind directions across these waterfront holes create a different challenge every day.' }], whatToExpect: 'A windswept, links-influenced experience with ocean views throughout. Flynn\\\'s out-and-back routing means holes constantly change direction relative to the prevailing Buzzards Bay breeze. The compact par-71 layout (roughly 6,600 yards) uses wind and strategic bunkering as the primary defense.\n\nFirm fescue conditions and a rocky Massachusetts coastline setting create a playing experience closer to the British Isles than typical New England parkland golf.\n\nStrictly private — one of the finest clubs in New England.', playingTips: 'Wind management is the primary skill tested. Club selection can swing two or three clubs depending on conditions off Buzzards Bay.\n\nGround-game approaches are rewarded — Flynn designed many greens to accept running shots.\n\nKeep the ball below the hole. The greens have subtle, wind-exposed slopes that punish anything above the pin.\n\nThe holes 3-8 waterfront stretch is the heart of the course — save your best golf for this stretch.', faqs: [{ question: 'Who designed Kittansett?', answer: 'William Flynn provided the plans, but founding member Frederic Hood personally led construction and refined the course over two decades. It is one of the finest Flynn designs in existence.' }, { question: 'Has it hosted major events?', answer: 'Yes — the 1953 Walker Cup and the 2022 U.S. Senior Amateur, among others.' }, { question: 'Can the public play?', answer: 'No. Kittansett is a strictly private club on a Buzzards Bay peninsula.' }]},
    { id: 'bos-11', name: 'Granite Links Golf Club', slug: 'granite-links-golf-club', city: 'Quincy', state: 'Massachusetts', type: 'public', rating: 4.2, greensFee: '$50–$95', architect: 'John Sanford', yearBuilt: 2003, holes: 27, par: 72, yardage: 6828, description: 'Built on former quarry land south of Boston with panoramic Boston skyline and harbor views, Granite Links offers 27 holes of championship-caliber public golf. The dramatic layout features exposed granite ledge, elevation changes unusual for coastal Massachusetts, and stunning city views from elevated tee boxes.', highlights: ['Panoramic Boston skyline and harbor views', 'Built on former quarry with exposed granite', '27 holes of championship public golf'], imageAlt: 'Granite Links Golf Club elevated fairway with Boston skyline views', history: 'Granite Links opened in 2003, built atop former landfill sites and old granite quarries south of Boston. Roughly 900,000 truckloads of Big Dig material helped shape the terrain — transforming an environmental liability into a premier public golf destination seven miles from downtown.\n\nDesigned by John Sanford with 27 holes across three nines (Granite, Milton, Quincy). The elevated terrain creates spectacular panoramic views of the Boston skyline, Blue Hills, and Harbor Islands.', signatureHoles: [{ hole: 5, par: 4, yardage: 410, description: 'Features dramatic quarry rock walls and exposed granite framing the hole. Elevated tees offer panoramic Boston skyline views — among the best urban panoramas from any golf course.' }], whatToExpect: 'Three nines playable in any 18-hole combination. Dramatic hills, elevation changes, and quarry features create an athletic round. Boston skyline views are genuinely spectacular from the elevated terrain.\n\nSome holes have quirky features from the site\\\'s industrial past — quarry walls, exposed granite ledge, and the landscape shaped by Big Dig material.', playingTips: 'The hilly terrain means many uneven lies. Solid ball-striking is essential.\n\nWind on exposed elevated holes is a factor. Club up on uphill approaches more than you think.\n\nLocal knowledge helps with the quirky quarry-era features.', faqs: [{ question: 'What is the Big Dig connection?', answer: '~900,000 truckloads of Big Dig material shaped the terrain, transforming former quarries and landfills into a premier golf destination.' }, { question: 'How many holes?', answer: '27 holes across three nines. Any two combine for an 18-hole round.' }]},
  ],
  'detroit-michigan': [
    { id: 'det-1', name: 'Oakland Hills Country Club - South', slug: 'oakland-hills-south', city: 'Bloomfield Hills', state: 'Michigan', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'Donald Ross', yearBuilt: 1918, holes: 18, par: 72, yardage: 7395, description: 'Dubbed "The Monster" by Ben Hogan, Oakland Hills South is one of America\'s most storied championship venues. The Donald Ross design has hosted six U.S. Opens, three PGA Championships, and the 2004 Ryder Cup. A Gil Hanse restoration in 2021 returned the course to Ross\'s original vision.', highlights: ['Six-time U.S. Open host', '2004 Ryder Cup venue', 'Gil Hanse 2021 restoration of Donald Ross design'], imageAlt: 'Oakland Hills South Course the Monster fairway in Bloomfield Hills Michigan', history: 'Oakland Hills South Course was designed by Donald Ross and opened in 1918 in Bloomfield Hills, Michigan. Robert Trent Jones Sr. toughened it before the 1951 U.S. Open, where Ben Hogan won and famously declared he had brought "the Monster" to its knees — a nickname that stuck permanently.\n\nThe course has hosted six U.S. Opens (most recently 1996), three PGA Championships, the 2004 Ryder Cup, and the 2025 U.S. Senior Open — 17 major championships overall. In 2019-2021, Gil Hanse led a landmark $12.1 million restoration, removing 137 trees and restoring Ross\\\'s original strategic vision by reopening green entrances and restoring bunkers.\n\nThe Hanse restoration is considered one of the most significant in modern American golf architecture.', signatureHoles: [{ hole: 16, par: 4, yardage: 440, description: 'Historically the most famous hole — Gary Player called his 9-iron approach here the best shot of his career during the 1972 PGA Championship. Part of the demanding 16-17-18 closing stretch that remains Ross\\\'s original design.' }, { hole: 7, par: 3, yardage: 195, description: 'Post-Hanse restoration, the par-3 7th has emerged as potentially the new signature hole with dramatic restored bunkering and reopened sightlines.' }], whatToExpect: 'A classic parkland championship course with elevated, tilting Ross greens, deep bunkers, and demanding approach angles. The Hanse restoration opened up ground-game options lost under decades of tree growth and RTJ Sr.\\\'s modifications — the course now plays firmer and faster, closer to Ross\\\'s original strategic intent.\n\nWider fairways and removed trees give more room off the tee, but green complexes are more exposed and challenging than ever.\n\nStrictly private — one of the most prestigious clubs in American golf.', playingTips: 'Approach shot precision is everything. Ross\\\'s green complexes reward specific angles and severely punish misses to the wrong side.\n\nPost-restoration, the wider fairways are more forgiving off the tee, but don\\\'t be lulled — the green complexes are more exposed and demanding.\n\nCourse management and knowledge of green contours are essential. Ask your host about preferred approach angles.', faqs: [{ question: 'Why is it called The Monster?', answer: 'Ben Hogan dubbed it after winning the 1951 U.S. Open, declaring he had brought "the Monster" to its knees. The nickname stuck permanently.' }, { question: 'How many major championships has it hosted?', answer: '17 — including six U.S. Opens, three PGA Championships, and the 2004 Ryder Cup. The 2025 U.S. Senior Open was the most recent.' }, { question: 'What was the Hanse restoration?', answer: 'A $12.1 million Gil Hanse restoration (2019-2021) that removed 137 trees and restored Ross\\\'s original strategic vision. Considered one of the most significant restorations in modern American golf architecture.' }]},
    { id: 'det-2', name: 'Detroit Golf Club', slug: 'detroit-golf-club', city: 'Detroit', state: 'Michigan', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Donald Ross', yearBuilt: 1916, holes: 18, par: 72, yardage: 7341, description: 'Home of the Rocket Mortgage Classic on the PGA Tour, Detroit Golf Club is a Donald Ross design in the heart of the city. The historic layout features Ross\'s signature crowned greens, mature tree-lined fairways, and a classic parkland setting that has been lovingly maintained for over a century.', highlights: ['Host of PGA Tour Rocket Mortgage Classic', 'Donald Ross design since 1916', 'Classic parkland setting in the heart of Detroit'], imageAlt: 'Detroit Golf Club Donald Ross fairway with PGA Tour tournament setup', history: 'Detroit Golf Club was founded in 1899 and moved to its current Palmer Park location in 1916 when Donald Ross designed both the North and South courses. Early members included Henry Ford.\n\nAfter decades without professional tournament golf in the city, Detroit Golf Club landed the Rocket Mortgage Classic in 2019, the first PGA Tour event ever held in Detroit proper. The tournament uses 17 holes from the North Course and one from the South.\n\nThe Rocket Mortgage Classic has become a popular PGA Tour fixture, bringing economic impact and national attention to Detroit.', signatureHoles: [{ hole: 4, par: 4, yardage: 472, description: 'A long par 4 through a tight tree-lined corridor with deep bunkers guarding both sides of the crowned Ross green.' }, { hole: 9, par: 4, yardage: 455, description: 'A strong front-nine finisher where the fairway narrows between mature trees, often requiring a long iron approach to the crowned green.' }, { hole: 14, par: 5, yardage: 557, description: 'A risk-reward par 5 reachable in two for long hitters, with bunkers and surrounding trees creating a dramatic amphitheater during tournaments.' }, { hole: 18, par: 4, yardage: 478, description: 'A demanding finishing hole with a long approach to a well-defended green, playing as one of the toughest during the Rocket Mortgage Classic.' }], whatToExpect: 'Detroit Golf Club is a classic Donald Ross parkland course in a beautiful urban park setting. Mature trees line every fairway, and Ross\'s crowned greens provide the primary defense. At 7,341 yards from the tips, it is a serious test.\n\nThe course has old-fashioned charm, with wide fairways off the tee narrowing near the greens. Conditioning is excellent, particularly around the Rocket Mortgage Classic.', playingTips: 'Ross\'s crowned greens are the defining feature. Approach shots must land softly on the correct portion, as misses roll off into collection areas. A reliable short game is essential.\n\nMature trees create tight corridors, but fairways are generally generous. Favor accuracy over distance off the tee.', faqs: [{ question: 'Can the public play Detroit Golf Club?', answer: 'No. It is a private club that gains public visibility through hosting the PGA Tour\'s Rocket Mortgage Classic.' }, { question: 'When did the Rocket Mortgage Classic start?', answer: 'The inaugural event was held in 2019, making it the first PGA Tour event ever held in the city of Detroit.' }, { question: 'How old is Detroit Golf Club?', answer: 'Founded in 1899, it is one of Michigan\'s oldest clubs. The Donald Ross courses date to 1916.' }, { question: 'Who were famous early members?', answer: 'Henry Ford was among the early members. The club has served Detroit\'s business and civic leaders for over a century.' }] },
    { id: 'det-3', name: 'Forest Dunes Golf Club - The Loop (Red)', slug: 'forest-dunes-loop-red', city: 'Roscommon', state: 'Michigan', type: 'resort', rating: 4.8, greensFee: '$100–$225', architect: 'Tom Doak', yearBuilt: 2016, holes: 18, par: 72, yardage: 6978, description: 'The first reversible course in America, Tom Doak\'s The Loop at Forest Dunes plays as two completely different 18-hole courses depending on the direction. The Red routing winds clockwise through Michigan pine barrens with creative green complexes and no two rounds ever the same.', highlights: ['First reversible golf course in America', 'Tom Doak innovative design', 'Michigan pine barrens setting'], imageAlt: 'Forest Dunes The Loop Red routing through Michigan pine barrens', history: 'The Loop at Forest Dunes opened in 2016, designed by Tom Doak (Renaissance Golf Design) as the first fully reversible golf course in the modern era. Using 18 greens and 18 distinct fairways, it creates two completely different 18-hole experiences: the Red routing (counter-clockwise on even days) and the Black routing (clockwise on odd days).\n\nWon Golf Digest\\\'s Best New Course award upon opening. Part of a resort complex in Roscommon that also includes the original Forest Dunes course (Weiskopf design). Doak, a Michigan native, brought personal significance to the project.\n\nOn months with 31 days, the resort holds "The Dual" — a 36-hole event playing both directions.', signatureHoles: [{ hole: 9, par: 4, yardage: 400, description: 'On the Red routing — a strategic par 4 through pristine northern Michigan pine corridors. Because the course reverses, this hole becomes a completely different experience on the Black routing. The variety of angles and green complexes means no two rounds ever feel alike.' }], whatToExpect: 'Wide fairways reward strategic positioning rather than raw distance. Enormous greens have dramatic internal contours — being on the correct tier matters more than being on the green at all. Walking-friendly layout through sandy, well-drained pine barrens terrain.\n\nThe Red routing plays counter-clockwise (even days); the Black plays clockwise (odd days). Both are top-tier designs offering genuinely different experiences on the same land.\n\nResort access with stay-and-play packages available in Roscommon, Michigan\\\'s northern Lower Peninsula.', playingTips: 'Think angles, not distance. Doak designed fairways to reward specific sides for approach shots.\n\nThe greens are large but heavily contoured. Being on the correct tier is critical — a 60-foot putt from the wrong section is common.\n\nWalking is encouraged and the terrain is gentle. Enjoy the pine barrens atmosphere.\n\nStudy pin positions carefully before every approach.', faqs: [{ question: 'What does "reversible" mean?', answer: 'The Loop uses 18 greens and 18 fairways to create two completely different courses: Red (counter-clockwise, even days) and Black (clockwise, odd days). Same land, two totally different experiences.' }, { question: 'Which routing is better?', answer: 'The Black is ranked slightly higher, but both are top-tier Tom Doak designs. Many players prefer whichever they play first for the novelty factor.' }, { question: 'Is it open to the public?', answer: 'Yes — resort access with stay-and-play packages. Located in Roscommon in Michigan\\\'s northern Lower Peninsula.' }]},
    { id: 'det-4', name: 'Arcadia Bluffs Golf Club - Bluffs Course', slug: 'arcadia-bluffs-course', city: 'Arcadia', state: 'Michigan', type: 'resort', rating: 4.7, greensFee: '$100–$250', architect: 'Warren Henderson & Rick Smith', yearBuilt: 1999, holes: 18, par: 72, yardage: 7300, description: 'Perched 200 feet above Lake Michigan on dramatic sandy bluffs, Arcadia Bluffs offers Scottish links-style golf with breathtaking Great Lakes views from every hole. The windswept layout features fescue fairways, deep pot bunkers, and one of the most spectacular settings in American golf.', highlights: ['200 feet above Lake Michigan on sandy bluffs', 'Scottish links-style with fescue fairways', 'Breathtaking Great Lakes views from every hole'], imageAlt: 'Arcadia Bluffs clifftop fairway overlooking Lake Michigan', history: 'Arcadia Bluffs Golf Club opened in 1999 on a dramatic property more than 200 feet above Lake Michigan on Michigan\'s western coast. Designed by Warren Henderson in collaboration with instructor Rick Smith, the course was envisioned as a links layout rivaling the great seaside courses of the British Isles.\n\nThe spectacular setting drew immediate comparisons to Irish links courses, with sweeping Lake Michigan views from every hole. Some have dubbed it Whistling Straits East for its lakeside links character. Arcadia Bluffs has been consistently ranked among the best public courses in America.\n\nThe facility expanded in 2019 with the South Course by Dana Fry and Jason Straka, and later added The Dozen, a 12-hole short course. But the original Bluffs Course remains the marquee attraction and one of the most stunning golf experiences in the Midwest.', signatureHoles: [{ hole: 11, par: 5, yardage: 633, description: 'Perhaps the most memorable hole on the course. This massive par 5 features dramatic terrain changes with Lake Michigan views throughout and a green complex rewarding strategic play.' }, { hole: 7, par: 4, yardage: 409, description: 'The number-one handicap hole. A demanding par 4 where wind off Lake Michigan significantly affects both the tee shot and approach.' }, { hole: 12, par: 3, yardage: 188, description: 'A beautiful par 3 with sweeping Lake Michigan views. The green is perched on the bluffs with pot bunkers and wind making club selection a challenge.' }, { hole: 18, par: 4, yardage: 434, description: 'A strong finishing hole playing toward the clubhouse with Lake Michigan as backdrop. The approach must navigate bunkers to find a green with panoramic views.' }], whatToExpect: 'Arcadia Bluffs delivers a Scottish links experience perched more than 200 feet above Lake Michigan. Windswept fescue fairways, deep pot bunkers, and open terrain create a true links feel rare in the Midwest. Lake Michigan views are visible from every hole.\n\nThe course plays 7,300 yards from the back tees at par 72. Wind off Lake Michigan is a constant factor that can dramatically change the character of holes.', playingTips: 'Wind off Lake Michigan is the primary challenge, blowing 20-30 mph and changing direction as the routing loops around the property. Bring your low shots and adjust club selection significantly on exposed holes.\n\nThe fescue rough is penal — keep the ball on the fairway. Pot bunkers are deep. A links ground game with bump-and-run approaches is very effective on firm, fast fairways.', faqs: [{ question: 'Is Arcadia Bluffs open to the public?', answer: 'Yes. Green fees range from approximately $100 to $250 depending on season. Peak season is summer.' }, { question: 'Where is Arcadia Bluffs located?', answer: 'In Arcadia, Michigan, on the western coast about 30 miles south of Traverse City, roughly 4 hours from Detroit.' }, { question: 'How many courses are at Arcadia Bluffs?', answer: 'Three: the original Bluffs Course, the South Course (2019), and The Dozen, a 12-hole short course.' }, { question: 'Is Arcadia Bluffs walking only?', answer: 'The Bluffs Course encourages walking and offers caddies, but riding carts are also available.' }] },
    { id: 'det-5', name: 'Shepherd\'s Hollow Golf Club', slug: 'shepherds-hollow-golf-club', city: 'Clarkston', state: 'Michigan', type: 'public', rating: 4.3, greensFee: '$50–$95', architect: 'Arthur Hills', yearBuilt: 2000, holes: 27, par: 72, yardage: 7204, description: 'A 27-hole Arthur Hills design in Clarkston, Shepherd\'s Hollow is consistently ranked the top public course in metro Detroit. The layout winds through heavily wooded terrain with dramatic elevation changes, ravines, and excellent conditioning that rivals private clubs.', highlights: ['Top-ranked public course in metro Detroit', '27-hole Arthur Hills design', 'Dramatic elevation changes through wooded ravines'], imageAlt: 'Shepherds Hollow Golf Club wooded fairway with ravine in Clarkston Michigan', history: 'Shepherd\\\'s Hollow opened in 2000, designed by Arthur Hills on 350+ rolling, wooded acres about 30 miles north of Detroit in Clarkston. Despite its metro proximity, it has an "Up North" Michigan feel. Recognized by Golf Digest as a Top 100 Public Golf Course in the United States — widely considered the finest inland public course in the Midwest.\n\nThe facility offers 27 holes (three nines) with all holes designed by Hills. Set at 1,106 feet above sea level, the dense hardwood forestation means each hole feels isolated and private.', signatureHoles: [{ hole: 18, par: 4, yardage: 440, description: 'A breathtaking finishing hole through the wooded terrain. Dramatic elevation changes and the heavily wooded corridor demand both length and accuracy for a strong close.' }], whatToExpect: 'Large, frequently tiered greens that are tough to read. Significant undulations and slopes throughout the rolling terrain. Dense hardwoods create defined corridors giving the sensation of northern Michigan golf without the drive.\n\n27 holes across three nines. Conditions are consistently praised as pure — rivaling private clubs in the area. The clubhouse veranda offers post-round relaxation.\n\nPublic access at $50-95 — exceptional value for a Golf Digest Top 100 Public Course.', playingTips: 'Being on the wrong green tier means a difficult two-putt. Study pin positions before every approach.\n\nThe slopes create uneven lies throughout. Solid ball-striking fundamentals are essential.\n\nThe wooded corridors punish wayward drives. Course management off the tee is critical.\n\nPlay the correct tee box — the course stretches to 7,204 yards from the tips.', faqs: [{ question: 'Is it really a top-100 public course?', answer: 'Yes — Golf Digest recognized Shepherd\\\'s Hollow as a Top 100 Public Golf Course. Widely considered the finest inland public course in the Midwest.' }, { question: 'How many holes?', answer: '27 holes across three nines, all designed by Arthur Hills. Holes 10-27 form the preferred 18-hole combination.' }, { question: 'What is the terrain like?', answer: 'Dense hardwoods and rolling hills at 1,106 feet elevation. Each hole feels isolated and private — an "Up North" feel 30 miles from Detroit.' }]},
    { id: 'det-6', name: 'Country Club of Detroit', slug: 'country-club-of-detroit', city: 'Grosse Pointe Farms', state: 'Michigan', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Harry Colt / C.H. Alison', yearBuilt: 1897, holes: 18, par: 72, yardage: 6876, description: 'Redesigned by the legendary English duo of Harry Colt and C.H. Alison in 1916, Country Club of Detroit occupies a historic lakeside property in Grosse Pointe Farms. The course hosted the 2008 U.S. Senior Open and features strategic bunkering, undulating greens, and a genteel parkland setting.', highlights: ['Harry Colt and C.H. Alison redesign', '2008 U.S. Senior Open host', 'Historic lakeside Grosse Pointe setting'], imageAlt: 'Country Club of Detroit Colt-Alison designed fairway in Grosse Pointe Farms', history: 'Country Club of Detroit was founded in 1897, making it one of Michigan\\\'s most historic private clubs. The original course was redesigned by Harry Colt in 1912, with partner C.H. Alison further modifying the design and building additional holes in 1927. In 2011, Tom Doak completed a comprehensive restoration returning the course to its Colt-Alison origins.\n\nThe club hosted the 1954 U.S. Amateur — where a young Arnold Palmer announced himself to the world with his victory — and the 2021 U.S. Senior Amateur. Palmer\\\'s 1954 win here is considered a defining moment in his career.\n\nThe 80,000-square-foot clubhouse reflects the grandeur of the Grosse Pointe Farms setting on Lake St. Clair.', signatureHoles: [{ hole: 13, par: 4, yardage: 415, description: 'A classic Colt-Alison par 4 where the correct angle of approach matters enormously. The restored green complex with characteristic undulations demands intelligent positioning rather than power.' }], whatToExpect: 'A classic, refined private club experience. The Doak restoration stripped away decades of accumulated changes to reveal the strategic genius of Colt and Alison. Firm, fast conditions with greens featuring restored original contours.\n\nThe layout demands intelligent positioning rather than power. Colt\\\'s bunker placements define ideal lines of play — strategic, not penal.\n\nStrictly private — one of the most prestigious clubs in Michigan.', playingTips: 'Study green complexes carefully — Colt created greens where the correct angle of approach matters enormously. Missing on the wrong side leaves nearly impossible recoveries.\n\nThe bunker placements are strategic guideposts. They define the ideal lines of play rather than simply punishing misses.\n\nFirm, fast conditions reward a ground game. Bump-and-run approaches are viable throughout.', faqs: [{ question: 'What is the Arnold Palmer connection?', answer: 'Palmer won the 1954 U.S. Amateur here — a defining moment that announced him to the world of golf.' }, { question: 'Who restored the course?', answer: 'Tom Doak completed a comprehensive 2011 restoration returning the course to its original Colt-Alison design intent. Considered one of the finest restorations in American golf.' }, { question: 'Can the public play?', answer: 'No. Country Club of Detroit is strictly private. Membership is by referral only.' }]},
    { id: 'det-7', name: 'Eagle Eye Golf Club', slug: 'eagle-eye-golf-club', city: 'Bath', state: 'Michigan', type: 'resort', rating: 4.4, greensFee: '$70–$140', architect: 'Chris Lutzke', yearBuilt: 2005, holes: 18, par: 72, yardage: 7354, description: 'Part of the Hawk Hollow complex near Lansing, Eagle Eye is an ambitious design featuring replica holes inspired by famous courses worldwide. The 7,354-yard layout includes tributes to Augusta\'s 12th, Sawgrass\'s 17th, and St. Andrews\' Road Hole, all set in rolling Michigan farmland.', highlights: ['Famous hole replicas from worldwide courses', 'Part of Hawk Hollow resort complex', '7,354-yard championship test'], imageAlt: 'Eagle Eye Golf Club replica hole in rolling Michigan farmland', history: 'Opened 2005. Chris Lutzke design with Pete Dye collaboration. Ranked among Golf Digest\'s 100 Greatest Public. Famous hole replicas. Part of Hawk Hollow Resort near Lansing.', signatureHoles: [{ hole: 1, par: 4, yardage: 449, description: 'Strong opening par 4.' }, { hole: 7, par: 3, yardage: 165, description: 'Island green inspired by Sawgrass 17th.' }, { hole: 12, par: 3, yardage: 155, description: 'Inspired by Augusta 12th.' }, { hole: 17, par: 4, yardage: 445, description: 'Modeled after St. Andrews Road Hole.' }], whatToExpect: 'Links-style course with famous replica holes at 7,354 yards in Michigan farmland. Part of Hawk Hollow complex.', playingTips: 'Replica holes play differently in Michigan conditions. Wind affects exposed holes. Island green demands confidence.', faqs: [{ question: 'Public?', answer: 'Yes. $70-$140.' }, { question: 'Replicas?', answer: 'Augusta 12, Sawgrass 17, St. Andrews Road Hole.' }, { question: 'Designer?', answer: 'Chris Lutzke with Pete Dye.' }, { question: 'Resort?', answer: 'Hawk Hollow Golf Resort.' }] },
    { id: 'det-8', name: 'Fieldstone Golf Club', slug: 'fieldstone-golf-club', city: 'Auburn Hills', state: 'Michigan', type: 'semi-private', rating: 4.2, greensFee: '$45–$85', architect: 'Arthur Hills', yearBuilt: 1997, holes: 18, par: 72, yardage: 7049, description: 'An Arthur Hills design in Auburn Hills, Fieldstone offers a challenging semi-private experience through rolling Oakland County terrain. The layout features elevation changes, strategic water hazards, and bentgrass fairways that provide excellent playing conditions throughout the Michigan golf season.', highlights: ['Arthur Hills design in Oakland County', 'Rolling terrain with strategic water hazards', 'Bentgrass fairways with excellent conditioning'], imageAlt: 'Fieldstone Golf Club rolling fairway in Auburn Hills Michigan', history: 'Fieldstone Golf Club opened in 1998, designed by Arthur Hills as a municipally owned course operated by the city of Auburn Hills. Despite its public status, it has been consistently ranked among the top three public courses in southeast Michigan for over two decades.\n\nHills designed the layout to integrate the area\\\'s diverse natural landscape of wetlands, rolling terrain, and mature hardwoods. The 40-station bent grass driving range with four target greens provides one of the better practice facilities in the area.', signatureHoles: [{ hole: 17, par: 4, yardage: 420, description: 'Part of a well-regarded finishing stretch demanding solid shots to close out a round. Forced carries, strategic bunkering, and the rolling Oakland County terrain create memorable closing holes.' }], whatToExpect: 'A scenic, well-conditioned course with genuine variety — both short and long holes, doglegs in both directions, and a mix of open and tree-lined corridors. Wetlands and rolling terrain give it more visual drama than a typical municipal course.\n\nConditioning is generally strong with fast, consistent bent grass greens and well-maintained bunkers. Forced carries over wetlands appear on several holes.\n\nSemi-private/public at $45-85 — excellent value for an Arthur Hills design in the Detroit metro.', playingTips: 'Accuracy off the tee matters more than length. Forced carries over wetlands punish wild shots.\n\nSeveral holes narrow at the typical landing zone. Fairway-finder clubs are often the smart play.\n\nThe greens are quick — leave yourself below the hole when possible.\n\nThis is a course that rewards middle-of-the-fairway golf.', faqs: [{ question: 'Is it really municipally owned?', answer: 'Yes — owned by the City of Auburn Hills. Semi-private/public access at $45-85, making it an excellent value for an Arthur Hills design.' }, { question: 'How is it ranked?', answer: 'Consistently among the top three public courses in southeast Michigan for over two decades.' }, { question: 'Who designed it?', answer: 'Arthur Hills, opening in 1998. One of his most accessible and affordable designs in the Detroit metro area.' }]},
    { id: 'det-9', name: 'Arcadia Bluffs Golf Club', slug: 'arcadia-bluffs-gc', city: 'Arcadia', state: 'Michigan', type: 'resort', rating: 4.7, greensFee: '$125–$250', architect: 'Warren Henderson & Rick Smith', yearBuilt: 1999, holes: 18, par: 72, yardage: 7300, description: 'Perched on 245-foot bluffs above Lake Michigan on the state\'s western coast, Arcadia Bluffs is one of the most dramatic resort courses in America. The links-style layout features windswept fescue, panoramic lake views from every hole, and a clifftop setting that draws frequent comparisons to the great Irish links.', highlights: ['245-foot bluffs above Lake Michigan', 'Links-style fescue with panoramic lake views', 'Frequently compared to great Irish links courses'], imageAlt: 'Arcadia Bluffs Golf Club clifftop links fairway above Lake Michigan', history: 'Arcadia Bluffs Golf Club opened in 1999 on Michigan\'s western coast, perched more than 245 feet above Lake Michigan. Designed by Warren Henderson in collaboration with well-known instructor Rick Smith, the course was inspired by the great seaside links of Ireland and Scotland, translated to a spectacular Great Lakes setting.\n\nThe course drew immediate acclaim and comparisons to Whistling Straits for its lakeside links character. It has been consistently ranked among the best public-access courses in America. Arcadia Bluffs expanded in 2019 with a second 18-hole layout called the South Course, designed by Dana Fry and Jason Straka.\n\nThe facility later added The Dozen, a 12-hole short course. But the original Bluffs Course remains the premier attraction, offering one of the most visually stunning and wind-challenged golf experiences in the Midwest.', signatureHoles: [{ hole: 11, par: 5, yardage: 633, description: 'The most wild and memorable hole on the course. This massive par 5 features dramatic terrain changes and Lake Michigan views throughout.' }, { hole: 7, par: 4, yardage: 409, description: 'The number-one handicap hole where wind off Lake Michigan significantly affects both tee shot and approach to a well-defended green.' }, { hole: 12, par: 3, yardage: 188, description: 'A beautiful par 3 perched on the bluffs with sweeping Lake Michigan views. Pot bunkers and wind make club selection challenging.' }, { hole: 18, par: 4, yardage: 434, description: 'A strong finishing hole playing toward the clubhouse with Lake Michigan as the panoramic backdrop.' }], whatToExpect: 'Arcadia Bluffs delivers a Scottish links experience 245 feet above Lake Michigan. Windswept fescue fairways, deep pot bunkers, and open terrain create a true links feel. Lake Michigan is visible from every hole and the setting rivals the great coastal courses of the British Isles.\n\nThe course plays 7,300 yards at par 72 from the back tees. Wind off Lake Michigan is a constant factor that dramatically changes the character of holes.', playingTips: 'Wind off Lake Michigan is the primary challenge, blowing 20-30 mph and changing direction as the routing loops around the property. Bring low shots and adjust club selection by two to three clubs on exposed holes.\n\nFescue rough is penal so keep the ball on the fairway. Pot bunkers are deep. Bump-and-run approaches work beautifully on firm, fast fairways.', faqs: [{ question: 'Is Arcadia Bluffs open to the public?', answer: 'Yes. Green fees range from $125 to $250 depending on season.' }, { question: 'Where is Arcadia Bluffs?', answer: 'On Michigan\'s western coast about 30 miles south of Traverse City, roughly 4 hours from Detroit.' }, { question: 'How many courses are there?', answer: 'Three: the Bluffs Course, the South Course (2019), and The Dozen, a 12-hole short course.' }, { question: 'Are carts available?', answer: 'Yes. Walking is encouraged and caddies are offered, but riding carts are also available.' }] },
    { id: 'det-10', name: 'Forest Dunes Golf Club - Weiskopf', slug: 'forest-dunes-weiskopf', city: 'Roscommon', state: 'Michigan', type: 'resort', rating: 4.6, greensFee: '$100–$200', architect: 'Tom Weiskopf', yearBuilt: 2002, holes: 18, par: 72, yardage: 7104, description: 'A Tom Weiskopf design in northern Michigan\'s pine and sand country, Forest Dunes is consistently ranked among the top public courses in America. The flowing layout through towering pines and sandy terrain features wide fairways, creative green complexes, and a peaceful Up North Michigan atmosphere.', highlights: ['Consistently ranked among top public courses in America', 'Tom Weiskopf design through northern Michigan pines', 'Sandy pine barrens terrain and peaceful atmosphere'], imageAlt: 'Forest Dunes Weiskopf Course fairway through northern Michigan pines', history: 'Forest Dunes opened in 2002 in Roscommon, Michigan, designed by Tom Weiskopf through northern Michigan\'s pine and sand country. The course quickly earned recognition as one of the top public courses in America.\n\nThe resort later added The Loop, a reversible course by Tom Doak, making Forest Dunes a must-visit destination for golf architecture enthusiasts.', signatureHoles: [{ hole: 4, par: 4, yardage: 420, description: 'A beautiful par 4 through towering pines with sandy waste areas framing the fairway.' }, { hole: 9, par: 5, yardage: 545, description: 'A risk-reward par 5 through the pine corridor with creative green complex.' }, { hole: 14, par: 3, yardage: 185, description: 'A scenic par 3 in the pine barrens setting.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finishing hole through the pines back to the clubhouse.' }], whatToExpect: 'One of America\'s top public courses through northern Michigan pines and sandy terrain. Wide fairways, creative greens, and peaceful Up North atmosphere.\n\nAt 7,104 yards, the course is a fair test that rewards strategic play.', playingTips: 'Sandy waste areas are playable but can be tricky. The wide fairways are forgiving off the tee, but green complexes demand precise approach play.\n\nThe sandy soil provides firm, fast conditions.', faqs: [{ question: 'Can the public play?', answer: 'Yes. Resort course, $100-$200.' }, { question: 'What is The Loop?', answer: 'A reversible Tom Doak course at Forest Dunes that plays in one direction one day and reverses the next.' }, { question: 'Designer?', answer: 'Tom Weiskopf, opened 2002.' }] },
    { id: 'det-11', name: 'Country Club of Detroit', slug: 'country-club-of-detroit', city: 'Grosse Pointe Farms', state: 'Michigan', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Harry Colt / C.H. Alison', yearBuilt: 1897, holes: 18, par: 72, yardage: 6876, description: 'A Harry Colt and C.H. Alison redesign from the 1920s, the Country Club of Detroit in Grosse Pointe Farms is one of the most prestigious private clubs in Michigan. The classic parkland layout features Colt-Alison strategic bunkering, mature trees, and Lake St. Clair proximity that has attracted championships since the early 20th century.', highlights: ['Harry Colt and C.H. Alison Golden Age redesign', 'One of Michigan\'s most prestigious private clubs', 'Lake St. Clair proximity in Grosse Pointe Farms'], imageAlt: 'Country Club of Detroit Colt-Alison parkland fairway in Grosse Pointe', history: 'Country Club of Detroit was founded in 1897 in Grosse Pointe Farms, redesigned by Harry Colt and C.H. Alison in the 1910s-1920s. Tom Doak completed a comprehensive 2011 restoration to Colt-Alison origins. Hosted the 1954 U.S. Amateur (Arnold Palmer\\\'s breakthrough victory) and the 2021 U.S. Senior Amateur.\n\nThe Colt-Alison strategic bunkering and subtle green contours — revealed by Doak\\\'s restoration — make this one of the finest Golden Age private courses in the Midwest.', signatureHoles: [{ hole: 7, par: 3, yardage: 195, description: 'A Colt-Alison par 3 with strategic bunkering defining the ideal angle of approach. The restored green complex rewards precision with characteristic Golden Age undulations.' }], whatToExpect: 'Classic parkland golf with Colt-Alison strategic bunkering, mature trees, and Lake St. Clair proximity. The Doak restoration returned the course to its Golden Age character — firm, fast, and strategic.\n\nStrictly private — one of Michigan\\\'s most prestigious clubs.', playingTips: 'The correct approach angle to each green matters enormously. Study the bunker positions — they are guideposts, not just hazards.\n\nFirm conditions reward ground-game creativity throughout.', faqs: [{ question: 'What is the Arnold Palmer connection?', answer: 'Palmer won the 1954 U.S. Amateur here — the victory that launched his legendary career.' }, { question: 'Who restored the course?', answer: 'Tom Doak (2011), returning it to Colt-Alison origins.' }]},
  ],
  'minneapolis-minnesota': [
    { id: 'min-1', name: 'Hazeltine National Golf Club', slug: 'hazeltine-national', city: 'Chaska', state: 'Minnesota', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'Robert Trent Jones Sr.', yearBuilt: 1962, holes: 18, par: 72, yardage: 7674, description: 'One of America\'s premier championship venues, Hazeltine has hosted two U.S. Opens, a PGA Championship, the 2016 Ryder Cup, and the 2002 and 2009 PGA Championships. The Robert Trent Jones Sr. design around Lake Hazeltine combines length, water hazards, and strategic bunkering.', highlights: ['2016 Ryder Cup host venue', 'Multiple U.S. Open and PGA Championship host', 'Robert Trent Jones Sr. lakeside design'], imageAlt: 'Hazeltine National Golf Club championship fairway with Lake Hazeltine', history: 'RTJ Sr. design, 1962. Hosted U.S. Open (1970, 1991), PGA (2002, 2009), 2016 Ryder Cup, 2019 Women\'s PGA. Will host 2029 Ryder Cup, first U.S. venue to host twice.', signatureHoles: [{ hole: 7, par: 5, yardage: 600, description: 'Among Ryder Cup\'s longest holes, along Lake Hazeltine.' }, { hole: 10, par: 4, yardage: 400, description: 'Strategic lakeside par 4.' }, { hole: 16, par: 4, yardage: 445, description: 'Critical closing stretch championship hole.' }, { hole: 18, par: 4, yardage: 460, description: 'Dramatic championship finisher.' }], whatToExpect: 'Premier championship venue, 7,674 yards around Lake Hazeltine. Private only.', playingTips: 'Length is primary defense. Large contoured greens need correct positioning.', faqs: [{ question: 'Public?', answer: 'No.' }, { question: 'Events?', answer: 'U.S. Open, PGA, 2016 Ryder Cup. 2029 Ryder Cup coming.' }, { question: 'Designer?', answer: 'RTJ Sr., 1962.' }, { question: '2029?', answer: 'First U.S. venue hosting Ryder Cup twice.' }] },
    { id: 'min-2', name: 'Interlachen Country Club', slug: 'interlachen-country-club', city: 'Edina', state: 'Minnesota', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Willie Watson', yearBuilt: 1911, holes: 18, par: 72, yardage: 6988, description: 'Host of the 1930 U.S. Open where Bobby Jones completed his Grand Slam, Interlachen is one of the most historically significant courses in Minnesota. The lakeside layout in Edina features mature tree-lined fairways, strategic bunkering, and classic Golden Age charm.', highlights: ['Bobby Jones completed Grand Slam here in 1930', '2008 U.S. Women\'s Open host', 'Historic lakeside setting in Edina'], imageAlt: 'Interlachen Country Club historic fairway along the lake in Edina Minnesota', history: 'Interlachen Country Club was founded in 1909 in Edina, Minnesota. Willie Watson designed the original course in 1911, set between two lakes. Donald Ross later contributed renovations.\n\nInterlachen\'s place in golf history was secured in 1930 when Bobby Jones won the U.S. Open here for the third leg of his Grand Slam. Jones clinched the title with a 40-foot birdie putt on the final hole.\n\nThe club has hosted the 2002 Solheim Cup and the 2008 U.S. Women\'s Open won by Inbee Park. It is consistently ranked among America\'s top 100 courses.', signatureHoles: [{ hole: 9, par: 4, yardage: 430, description: 'The hole where Bobby Jones hit his famous "lily pad shot" during the 1930 U.S. Open. A demanding par 4 along the lake.' }, { hole: 3, par: 4, yardage: 415, description: 'A strategic par 4 along the lakeside with water threatening the left side and a well-defended green.' }, { hole: 15, par: 3, yardage: 200, description: 'A beautiful par 3 with a lake backdrop demanding a well-struck long iron.' }, { hole: 18, par: 4, yardage: 450, description: 'Where Bobby Jones sank a 40-foot putt to clinch the 1930 U.S. Open. A demanding finisher climbing toward the clubhouse.' }], whatToExpect: 'Interlachen is a classic Golden Age layout in a stunning lakeside setting winding through mature trees and along Lake Interlachen.\n\nAt 6,988 yards with a par of 72, the course is a fair but demanding test. Wind off the lake can be a factor, and tree-lined fairways demand accuracy.', playingTips: 'On lakeside holes, favor the safe side away from water. Wind off the lake affects club selection significantly.\n\nThe greens have classic Golden Age contours with subtle breaks. Position approach shots to leave uphill putts.', faqs: [{ question: 'Can the public play Interlachen?', answer: 'No. Interlachen is a private club with no public access.' }, { question: 'What is the Bobby Jones connection?', answer: 'Bobby Jones won the 1930 U.S. Open here, the third leg of his Grand Slam.' }, { question: 'What other major events has Interlachen hosted?', answer: 'The 2002 Solheim Cup and the 2008 U.S. Women\'s Open.' }, { question: 'Who designed Interlachen?', answer: 'Willie Watson designed the original course in 1911. Donald Ross later contributed renovations.' }] },
    { id: 'min-3', name: 'The Wilds Golf Club', slug: 'the-wilds-golf-club', city: 'Prior Lake', state: 'Minnesota', type: 'public', rating: 4.4, greensFee: '$55–$110', architect: 'Tom Weiskopf', yearBuilt: 2004, holes: 18, par: 72, yardage: 7025, description: 'A Tom Weiskopf design in Prior Lake, The Wilds is consistently ranked among the best public courses in Minnesota. The layout winds through rolling prairie terrain, hardwood forests, and wetlands with exceptional conditioning and a resort-quality experience at public pricing.', highlights: ['Tom Weiskopf championship design', 'Top-ranked Minnesota public course', 'Prairie, forest, and wetland routing'], imageAlt: 'The Wilds Golf Club rolling prairie fairway in Prior Lake Minnesota', history: 'The Wilds Golf Club opened in 1995, designed by Tom Weiskopf and Jay Morrish in Prior Lake, just south of Minneapolis. The course winds through a landscape of Ponderosa pines, hardwoods, and wetlands with over 150 feet of elevation changes — among the most dramatic in the Twin Cities metro.\n\nBilling itself as "Minnesota\\\'s Crown Jewel," The Wilds operates as an upscale public facility managed by Troon Golf. From the Weiskopf tees, the course carries a slope of 152 and rating of 74.5 — one of the highest in Minnesota.\n\nAcquired by Thompson Golf Group in 2025. The Eagles Nest viewpoint between holes 1 and 2 offers a panoramic overlook worth pausing at.', signatureHoles: [{ hole: 14, par: 4, yardage: 430, description: 'A demanding par 4 showcasing the dramatic 150+ feet of elevation change throughout the course. The rolling prairie terrain and wooded corridors create a hole that demands both length and accuracy.' }], whatToExpect: 'Swift bentgrass fairways, well-conditioned greens, and a mix of prairie openness and forested corridors. Over 150 feet of elevation changes create many downhill and sidehill lies. Water comes into play on roughly half the holes.\n\nThe setting feels far more remote than its location (about 25 minutes from downtown Minneapolis) suggests. Fine dining on-site completes the upscale public experience.\n\nMultiple tee sets accommodate all skill levels, but the 152 slope from the tips is among the highest in Minnesota.', playingTips: 'With a 152 slope, course management is paramount. Don\\\'t try to overpower this course.\n\nThe elevation changes create many uneven lies — solid footwork and ball-striking fundamentals are essential.\n\nWater on roughly half the holes means knowing your carry distances is critical.\n\nChoose tees wisely — the gap between tee boxes is significant and the difficulty scales dramatically.', faqs: [{ question: 'How difficult is The Wilds?', answer: 'The 152 slope from the Weiskopf tees is among the highest for any public course in Minnesota. Course rating 74.5.' }, { question: 'Who designed it?', answer: 'Tom Weiskopf and Jay Morrish, opening in 1995. Managed by Troon Golf, acquired by Thompson Golf Group in 2025.' }, { question: 'How far is it from Minneapolis?', answer: 'About 25 minutes from downtown in Prior Lake. Despite the proximity, the terrain feels far more remote.' }]},
    { id: 'min-4', name: 'TPC Twin Cities', slug: 'tpc-twin-cities', city: 'Blaine', state: 'Minnesota', type: 'semi-private', rating: 4.5, greensFee: '$90–$175', architect: 'Arnold Palmer', yearBuilt: 2000, holes: 18, par: 72, yardage: 7114, description: 'Home of the 3M Open on the PGA Tour, TPC Twin Cities is an Arnold Palmer design in Blaine that offers tour-caliber golf accessible to the public. The layout features rolling terrain, strategic water hazards, and the immaculate conditioning expected of a TPC facility.', highlights: ['Host of PGA Tour 3M Open', 'Arnold Palmer championship design', 'Tour-caliber public access facility'], imageAlt: 'TPC Twin Cities championship fairway during 3M Open in Blaine Minnesota', history: 'TPC Twin Cities opened in 2000 in Blaine, designed by Arnold Palmer with Minnesota native Tom Lehman. Originally hosting the 3M Championship (Champions Tour, 2001-2018), the course stepped up to host the full PGA Tour\\\'s 3M Open beginning in 2019. The event has been extended through 2030.\n\nA 2018 renovation by Steve Wenzloff and Tom Lehman updated the course before the PGA Tour transition. The layout features abundant water along many holes with rolling terrain and the immaculate conditioning expected of a TPC facility. Tony Finau won the 2022 3M Open here.', signatureHoles: [{ hole: 7, par: 4, yardage: 340, description: 'A drivable short par 4 featuring Arnold Palmer\\\'s signature beach bunker — a classic risk-reward temptation. The aggressive play can yield birdie or eagle, but the bunker catches overconfident tee shots.' }, { hole: 18, par: 4, yardage: 450, description: 'A demanding closer that provides exciting conclusions during the 3M Open. Water and strategic bunkering create a genuine championship finishing hole.' }], whatToExpect: 'A 7,164-yard par-72 layout with very large greens that have relatively little undulation. Abundant water hazards throughout. Three par 5s all offer birdie opportunities, making them key scoring holes during tour events.\n\nThe course offers a solid balance of difficult holes and scoring chances. Tour-caliber conditioning year-round as expected from the TPC network.\n\nSemi-private — public access with PGA Tour pedigree at $90-175.', playingTips: 'Driving accuracy matters — water is in play on many holes and rough can be punishing.\n\nThe large greens mean reaching the putting surface is achievable, but wrong-tier positions create long lag putts.\n\nOn the drivable 7th, assess risk honestly — the beach bunker catches aggressive plays.\n\nThe long par 3s (three exceed 200 yards) are among the eight toughest holes. Take enough club.', faqs: [{ question: 'Does the PGA Tour play here?', answer: 'Yes — the 3M Open has been held annually since 2019, extended through 2030. Previously hosted the Champions Tour 3M Championship (2001-2018).' }, { question: 'Who designed it?', answer: 'Arnold Palmer with Minnesota native Tom Lehman. A 2018 Wenzloff/Lehman renovation prepared it for the PGA Tour transition.' }, { question: 'Is it open to the public?', answer: 'Semi-private — public tee times available at $90-175. TPC network standards ensure tour-caliber conditioning.' }]},
    { id: 'min-5', name: 'Giants Ridge Golf & Ski Resort - Quarry', slug: 'giants-ridge-quarry', city: 'Biwabik', state: 'Minnesota', type: 'resort', rating: 4.5, greensFee: '$60–$110', architect: 'Jeff Brauer', yearBuilt: 2003, holes: 18, par: 72, yardage: 7201, description: 'Built on Minnesota\'s Iron Range amid old mining terrain, Giants Ridge Quarry features dramatic elevation changes, exposed mine walls, and views across the Laurentian Divide. The Jeff Brauer design transforms rugged industrial landscape into one of the most unique resort courses in the Midwest.', highlights: ['Built on former Iron Range mining terrain', 'Dramatic elevation changes and exposed mine walls', 'Unique Laurentian Divide setting'], imageAlt: 'Giants Ridge Quarry course carved from Iron Range mining terrain in northern Minnesota', history: 'Opened 2003 on former Iron Range mining operations. Jeff Brauer design ranked No. 1 public course in Minnesota. Golf Digest named it among America\'s Most Important Courses. Second of two courses at Giants Ridge (Legend opened 1997).', signatureHoles: [{ hole: 1, par: 4, yardage: 433, description: 'Demanding opener with bunker and native grasses.' }, { hole: 13, par: 4, yardage: 323, description: 'Short drivable par 4 with quarry features.' }, { hole: 15, par: 3, yardage: 180, description: 'Scenic par 3 with exposed mine wall amphitheater.' }, { hole: 18, par: 5, yardage: 545, description: 'Memorable quarry terrain finisher.' }], whatToExpect: 'Built on former mining operations with dramatic elevation and rugged terrain. 7,201 yards championship test. Combine with Legend for 36-hole getaway.', playingTips: 'Quarry terrain creates dramatic elevation changes. Northern Minnesota weather is unpredictable — pack layers.', faqs: [{ question: 'Public?', answer: 'Yes. $60-$110.' }, { question: 'Top ranked?', answer: 'No. 1 public course in Minnesota (Golfweek).' }, { question: 'Courses?', answer: 'The Quarry (2003) and The Legend (1997), both Brauer.' }, { question: 'Location?', answer: 'Iron Range, 90 minutes north of Duluth.' }] },
    { id: 'min-6', name: 'Spring Hill Golf Club', slug: 'spring-hill-golf-club', city: 'Wayzata', state: 'Minnesota', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Riley Johns', yearBuilt: 2022, holes: 18, par: 72, yardage: 7186, description: 'One of the most buzzed-about new courses in America, Spring Hill is a Riley Johns design that opened in 2022 near Lake Minnetonka. The minimalist layout features dramatic contours, wide strategic corridors, and a ground-game emphasis that has earned immediate national acclaim.', highlights: ['Riley Johns acclaimed 2022 opening', 'Minimalist design with dramatic contours', 'Immediate national top-100 recognition'], imageAlt: 'Spring Hill Golf Club minimalist fairway contours near Lake Minnetonka', history: 'Spring Hill Golf Club opened in 1999 near Lake Minnetonka, designed by Tom Fazio as a pure private golf experience with no housing development on the course. The layout has appeared on Golf Digest\\\'s America\\\'s 100 Greatest list multiple times, reaching No. 69 (2017-2018) and consistently ranking as the No. 2 course in Minnesota behind Hazeltine National.\n\nReviewers compare it to Kinloch and Flint Hills National for its "pure golf" feel — each hole is isolated with no encroaching development. The course experienced severe flooding in fall 2015 (10 inches of rain in October) but recovered to maintain its elite conditioning standard.', signatureHoles: [{ hole: 5, par: 3, yardage: 211, description: 'An uphill par 3 with significant elevation change — described as "fascinating" by reviewers. A demanding one-shotter that requires precise club selection to account for the climb.' }, { hole: 13, par: 5, yardage: 540, description: 'Part of what Golf Digest called a "fantastic collection of par 5s." The strategic design rewards intelligent positioning over raw distance.' }], whatToExpect: 'Excellent variety throughout the routing with a wide range of hole lengths, shapes, and elevations. Tight fairways with meaningful elevation changes. Tricky greens with subtle breaks — rarely a flat lie on this course.\n\nImmaculate conditioning — described as impossible to find a blade of grass out of place. The "pure golf" atmosphere with no housing development creates a sense of total seclusion on every hole.\n\nStrictly private — consistently ranked among the top 2-3 courses in Minnesota.', playingTips: 'Green contours are the main defense — pay close attention to subtle breaks that are easy to misread.\n\nThe course plays longer than the yardage suggests due to elevation changes. Club up on the uphill par 3s.\n\nCourse management matters more than raw power on the tight fairways.\n\nTake any invitation you can get — this is among the most exclusive private clubs in Minnesota.', faqs: [{ question: 'Who designed Spring Hill?', answer: 'Tom Fazio, opening in 1999. The course has appeared on Golf Digest\\\'s America\\\'s 100 Greatest list multiple times, reaching No. 69.' }, { question: 'How does it rank in Minnesota?', answer: 'Consistently No. 2 in the state behind Hazeltine National. Compared to Kinloch and Flint Hills National for its pure golf atmosphere.' }, { question: 'Can the public play?', answer: 'No. Strictly private with no housing development on the course — a pure golf experience.' }]},
    { id: 'min-7', name: 'Windsong Farm Golf Club', slug: 'windsong-farm-golf-club', city: 'Independence', state: 'Minnesota', type: 'semi-private', rating: 4.3, greensFee: '$75–$135', architect: 'Rees Jones', yearBuilt: 2005, holes: 18, par: 72, yardage: 7169, description: 'A Rees Jones design west of Minneapolis, Windsong Farm occupies 345 acres of rolling terrain with sweeping views of Lake Independence. The semi-private layout delivers a private-club experience with generous fairways, strategic bunkering, and superb bentgrass conditioning.', highlights: ['Rees Jones design on 345 acres', 'Lake Independence views', 'Private-club experience at semi-private access'], imageAlt: 'Windsong Farm Golf Club fairway overlooking Lake Independence', history: 'Windsong Farm Golf Club opened in 2005 west of Minneapolis, designed by Rees Jones on 345 acres of rolling terrain with sweeping views of Lake Independence. The semi-private layout delivers a private-club experience with generous fairways, strategic bunkering, and superb bentgrass conditioning.\n\nThe course provides one of the best semi-private experiences in the Twin Cities metro — private-club quality with broader access than fully exclusive clubs.', signatureHoles: [{ hole: 14, par: 4, yardage: 420, description: 'A demanding par 4 showcasing the Lake Independence views and rolling terrain that define the Windsong Farm experience. Strategic bunkering guards the approach to a well-contoured green.' }], whatToExpect: 'A Rees Jones design occupying 345 acres with lake views and rolling terrain. Generous fairways provide forgiveness off the tee, but strategic bunkering and well-defended greens demand precision on approaches.\n\nSuperb bentgrass conditioning throughout. The semi-private format provides broader access than fully private clubs at $75-135.\n\nLake Independence views add scenic beauty to the round.', playingTips: 'The generous fairways are forgiving off the tee — use that confidence to set up better approach angles.\n\nStrategic bunkering guards the preferred sides of greens. Study where NOT to miss before each approach.\n\nBentgrass conditions are typically excellent — expect true, consistent rolls on the greens.', faqs: [{ question: 'Is it open to the public?', answer: 'Semi-private — public tee times available at $75-135. Private-club experience with broader access.' }, { question: 'Who designed it?', answer: 'Rees Jones, opening in 2005 on 345 acres west of Minneapolis.' }, { question: 'What are the views like?', answer: 'Sweeping views of Lake Independence from multiple holes throughout the rolling terrain.' }]},
    { id: 'min-8', name: 'Rush Creek Golf Club', slug: 'rush-creek-golf-club', city: 'Maple Grove', state: 'Minnesota', type: 'public', rating: 4.3, greensFee: '$50–$95', architect: 'Bob Cupp & John Fought', yearBuilt: 1996, holes: 18, par: 72, yardage: 6989, description: 'A Bob Cupp and John Fought design in Maple Grove, Rush Creek has hosted the 2004 U.S. Amateur and multiple USGA qualifying events. The rolling layout through native prairie grasses and wetlands offers championship-caliber public golf northwest of Minneapolis.', highlights: ['2004 U.S. Amateur host', 'Bob Cupp and John Fought design', 'Native prairie and wetland setting'], imageAlt: 'Rush Creek Golf Club prairie fairway in Maple Grove Minnesota', history: 'Rush Creek Golf Club opened in June 1996, designed by Bob Cupp and John Fought in Maple Grove northwest of Minneapolis. The course hosted the 2004 U.S. Amateur Public Links Championship — where Ryan Moore won for the second time — and three LPGA Tour events, establishing serious competitive credentials.\n\nThe Cupp-Fought design philosophy emphasized creating distinct individual holes through varied terrain of native prairie grasses and wetlands. At 7,290 yards from the tips with a 75.7 rating, it is a genuine championship test.', signatureHoles: [{ hole: 9, par: 4, yardage: 430, description: 'A demanding par 4 through the native prairie landscape. The Cupp-Fought design ensures each hole has its own distinct personality — no two holes feel alike throughout the round.' }], whatToExpect: 'A challenging public course with excellent conditioning and strong strategic elements. The design features wide-ranging hole variety — some reward aggression, others demand precision. The native prairie grasses and wetlands create a natural setting.\n\nEach hole has distinct character, a hallmark of the Cupp-Fought collaborative philosophy. At 7,290 yards from the tips, the course is a serious test but multiple tees accommodate all skill levels.\n\nPublic access at $50-95 — strong value for championship-caliber golf.', playingTips: 'Take advantage of the distinct character of each hole. Some reward aggression, others demand precision — read each hole individually.\n\nAt 7,290 yards from the tips, choose appropriate tees honestly.\n\nThe variety of holes means few assumptions carry from one to the next. Study each hole before swinging.\n\nNative prairie areas are penal — keep the ball on maintained turf.', faqs: [{ question: 'Has Rush Creek hosted major events?', answer: 'Yes — the 2004 U.S. Amateur Public Links Championship (won by Ryan Moore) and three LPGA Tour events.' }, { question: 'Who designed it?', answer: 'Bob Cupp and John Fought, opening in 1996. Both are known for creating courses with strong individual hole identity.' }, { question: 'How long is it?', answer: '7,290 yards from the tips with a 75.7 rating. Multiple tees accommodate all skill levels.' }]},
    { id: 'min-9', name: 'The Wilds Golf Club', slug: 'the-wilds-golf-club', city: 'Prior Lake', state: 'Minnesota', type: 'public', rating: 4.2, greensFee: '$45–$90', architect: 'Tom Weiskopf', yearBuilt: 1995, holes: 18, par: 72, yardage: 7025, description: 'A Tom Weiskopf design south of Minneapolis in Prior Lake, The Wilds features a dramatic routing through wetlands, native prairie, and hardwood forest. The 7,025-yard layout earned praise for its natural beauty and strategic challenge, making it one of the top public options in the Twin Cities metro area.', highlights: ['Tom Weiskopf design through wetlands and prairie', 'Top public option in Twin Cities metro', 'Natural beauty and strategic routing in Prior Lake'], imageAlt: 'The Wilds Golf Club prairie and wetland fairway in Prior Lake Minnesota', history: 'The Wilds Golf Club opened in 1995, designed by Tom Weiskopf south of Minneapolis in Prior Lake. The layout features over 150 feet of elevation changes through wetlands, native prairie, and hardwood forest — among the most dramatic terrain in the Twin Cities metro.\n\nFrom the Weiskopf tees, the course carries a 152 slope — one of the highest for any public course in Minnesota. Managed by Troon Golf and billing itself as "Minnesota\\\'s Crown Jewel."', signatureHoles: [{ hole: 7, par: 4, yardage: 420, description: 'A demanding par 4 showcasing the dramatic 150+ feet of elevation changes that define The Wilds. The rolling prairie-to-forest terrain creates a hole demanding both length and accuracy.' }], whatToExpect: 'Swift bentgrass fairways and a mix of prairie openness and forested corridors. Over 150 feet of elevation changes create many dramatic downhill and sidehill lies. Water on roughly half the holes.\n\nThe setting feels far more remote than its location (25 minutes from downtown Minneapolis) suggests. Fine dining on-site completes the upscale public experience.\n\nPublic access at $45-90 with a 152 slope from the tips.', playingTips: 'With a 152 slope, course management is paramount. The elevation changes create many uneven lies.\n\nWater on roughly half the holes means knowing carry distances is critical.\n\nChoose tees wisely — the difficulty scales dramatically between tee boxes.', faqs: [{ question: 'How difficult is it?', answer: '152 slope from the Weiskopf tees — among the highest for any public course in Minnesota.' }, { question: 'Who designed it?', answer: 'Tom Weiskopf, opening in 1995. Managed by Troon Golf.' }]},
    { id: 'min-10', name: 'Windsong Farm Golf Club', slug: 'windsong-farm-golf-club', city: 'Independence', state: 'Minnesota', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Rees Jones', yearBuilt: 2004, holes: 18, par: 72, yardage: 7208, description: 'A Rees Jones design west of Minneapolis in Independence, Windsong Farm is one of the premier private clubs in Minnesota. The 7,208-yard layout through rolling terrain and wetlands features Jones\'s strategic design philosophy with bold bunkering, well-defended greens, and panoramic views of the Minnesota countryside.', highlights: ['Rees Jones premier Minnesota private club', '7,208-yard championship layout', 'Rolling terrain and Minnesota countryside views'], imageAlt: 'Windsong Farm Golf Club Rees Jones fairway through Minnesota countryside', history: 'Windsong Farm Golf Club was designed by Rees Jones west of Minneapolis in Independence, Minnesota, on 345 acres of rolling terrain with panoramic views of Lake Independence. The private club has evolved into Minnesota\\\'s only 36-hole private facility after adding a North Course.\n\nJones\\\'s strategic design philosophy features bold bunkering, well-defended greens, and superb bentgrass conditioning throughout. Consistently ranked among the top private clubs in Minnesota.', signatureHoles: [{ hole: 12, par: 4, yardage: 430, description: 'A strategic par 4 showcasing the rolling terrain and Lake Independence views. Jones\\\'s bold bunkering guards the approach to a well-contoured green that demands precise positioning.' }], whatToExpect: 'A Rees Jones private club on 345 acres of rolling Minnesota countryside with lake views. Strategic bunkering and well-defended greens demand precision. Superb bentgrass conditioning.\n\nNow Minnesota\\\'s only 36-hole private facility. Strictly private — members and guests only.', playingTips: 'Jones\\\'s bunkering defines the ideal lines of play. Study where NOT to miss before each approach.\n\nThe rolling terrain creates many uneven lies. Solid footwork is essential.\n\nBentgrass conditions are typically excellent — expect true, consistent greens.', faqs: [{ question: 'Who designed it?', answer: 'Rees Jones, on 345 acres west of Minneapolis. Now Minnesota\\\'s only 36-hole private facility.' }, { question: 'Can the public play?', answer: 'No — strictly private.' }]},
    { id: 'min-11', name: 'Legends Club', slug: 'legends-club-minnesota', city: 'Prior Lake', state: 'Minnesota', type: 'public', rating: 4.1, greensFee: '$40–$75', architect: 'Gary Player', yearBuilt: 2004, holes: 18, par: 72, yardage: 7014, description: 'A Gary Player design at the Mystic Lake Casino resort, the Legends Club features a challenging public layout through southern Minnesota prairie and wetland terrain. The 7,014-yard course offers casino-resort amenities combined with a well-maintained championship golf experience accessible to the public.', highlights: ['Gary Player design at Mystic Lake Casino resort', 'Prairie and wetland terrain south of Minneapolis', 'Casino-resort amenities with championship golf'], imageAlt: 'Legends Club Gary Player fairway at Mystic Lake resort in Prior Lake', history: 'The Legends Club opened in 2001 on 360 acres of rolling terrain between Prior Lake and Lakeville, associated with the Mystic Lake Casino area and developed by the Shakopee Mdewakanton Sioux Community. Named "National Golf Course of the Year" by the NGCOA in 2007 and consistently ranked among the Top 10 courses in Minnesota.\n\nThe layout features a 30-acre lake at its center, cascading creeks, scenic wetlands, and dramatic topography. Five sets of tees accommodate all skill levels.', signatureHoles: [{ hole: 16, par: 5, yardage: 621, description: 'The longest hole on the course at 621 yards, requiring three precise shots to navigate the lake and wetland features. A genuine three-shot challenge where course management defines the outcome.' }, { hole: 18, par: 4, yardage: 440, description: 'A dramatic finishing hole with water in play. Frequently photographed and praised as a strong, memorable closer.' }], whatToExpect: 'A course carved through natural landscape featuring a 30-acre central lake, cascading creeks, and dramatic topography. White sand bunkers and well-rolling greens are meticulously maintained. Native plants and environmental stewardship are emphasized throughout.\n\nThe course provides generous scoring opportunities but punishes errant shots with wetlands and water features. Casino-resort amenities enhance the experience.\n\nPublic access — green fees approximately $140 including cart, range, and tax.', playingTips: 'Water and wetlands are the primary hazards. Know your carry distances before challenging lake carries.\n\nThe 30-acre central lake influences strategy on multiple holes. Play away from the water when in doubt.\n\nFive tee sets accommodate all skill levels — choose honestly given the wetland penalties.\n\nThe free mobile app offers GPS and scorecard tracking — use it.', faqs: [{ question: 'Is it connected to Mystic Lake Casino?', answer: 'Yes — developed by the Shakopee Mdewakanton Sioux Community in the Mystic Lake area. Casino-resort amenities complement the golf experience.' }, { question: 'How is it ranked?', answer: 'Named NGCOA National Golf Course of the Year (2007). Consistently ranked among the Top 10 courses in Minnesota.' }, { question: 'What does it cost?', answer: 'Approximately $140 including cart, range balls, and tax. Twilight rate around $100.' }]},
  ],
  'philadelphia-pennsylvania': [
    { id: 'phi-1', name: 'Pine Valley Golf Club', slug: 'pine-valley-golf-club', city: 'Pine Valley', state: 'New Jersey', type: 'private', rating: 5.0, greensFee: 'Members Only', architect: 'George Crump & H.S. Colt', yearBuilt: 1918, holes: 18, par: 70, yardage: 7057, description: 'Widely considered the number-one golf course in the world, Pine Valley is a masterwork of penal design set in the New Jersey Pine Barrens just outside Philadelphia. Every hole is an isolated island of manicured turf surrounded by sand, scrub, and forest, creating golf\'s ultimate strategic and visual challenge.', highlights: ['Perennially ranked #1 golf course in the world', 'George Crump\'s singular architectural vision', 'Pine Barrens setting with unmatched shot demands'], imageAlt: 'Pine Valley Golf Club legendary fairway through New Jersey Pine Barrens', history: 'Pine Valley Golf Club was founded in 1913 by George Arthur Crump, a Philadelphia hotelier and passionate amateur golfer. Crump discovered the sandy, rolling terrain in the New Jersey Pine Barrens near Clementon and purchased 184 acres. He enlisted English architect H.S. Colt, who helped with the initial routing, though Crump remained the driving creative force.\n\nCrump devoted his life to the project, living on the property and overseeing every detail. He died in January 1918 before completion, with four holes unfinished. Hugh Wilson of Merion completed the remaining holes. The course opened in 1918 and was immediately recognized as extraordinary.\n\nPine Valley has been ranked number one in the world by virtually every major ranking. The club hosted the 1936 and 1985 Walker Cups and annually holds the Crump Cup, one of golf\'s most prestigious amateur events.', signatureHoles: [{ hole: 2, par: 4, yardage: 367, description: 'A short par 4 epitomizing Pine Valley\'s brilliance. The blind tee shot must carry sandy wasteland to an island fairway, and the approach plays to a green above deep bunkers.' }, { hole: 5, par: 3, yardage: 238, description: 'One of the most feared par 3s in golf. This long one-shotter plays over a pond to a severely contoured green with no bail-out.' }, { hole: 7, par: 5, yardage: 640, description: 'An epic par 5 featuring Hell\'s Half Acre, the largest bunker on the course. This massive sandy wasteland splits the fairway about 280 yards out.' }, { hole: 13, par: 4, yardage: 448, description: 'Widely regarded as the finest hole on the course. This dogleg-left par 4 plays through dense pine forest to a crowned green with severe run-offs.' }], whatToExpect: 'Each hole at Pine Valley is a self-contained experience, an island of immaculate turf surrounded by sandy waste areas, scrub brush, and dense Pine Barrens forest. The routing has no parallel fairways and few holes visible from any other.\n\nThe course is walking only with caddies. Sandy soil ensures excellent drainage year-round. Par 70 at just over 7,000 yards, but difficulty lies in the unforgiving nature of any missed shot rather than length.', playingTips: 'Accuracy off the tee is paramount. Nearly every hole features a defined target area, and missing it means sand, scrub, or forest. Identify the safe side of each fairway rather than overpowering the course.\n\nFavor the center of greens since many surfaces feature crowned contours rejecting edge shots. The par 3s average over 200 yards and require confident iron play.', faqs: [{ question: 'Can the public play Pine Valley?', answer: 'No. Pine Valley is extremely private. Access is only through a member invitation.' }, { question: 'Why is Pine Valley ranked number one?', answer: 'An unmatched combination of strategic design, visual drama, and shot-making demands. The course has remained virtually unchanged since completion.' }, { question: 'What is the Crump Cup?', answer: 'An elite invitational amateur tournament held annually since 1930, named for founder George Crump.' }, { question: 'Is Pine Valley walkable?', answer: 'Walking only with caddies required. The sandy soil provides firm footing and the routing is well-designed for walking.' }] },
    { id: 'phi-2', name: 'Merion Golf Club - East', slug: 'merion-east', city: 'Ardmore', state: 'Pennsylvania', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'Hugh Wilson', yearBuilt: 1912, holes: 18, par: 70, yardage: 6846, description: 'Host of five U.S. Opens including 2013, Merion East is where Bobby Jones completed the original Grand Slam in 1930 and Ben Hogan hit his famous 1-iron on the 18th in 1950. Hugh Wilson\'s compact masterpiece packs extraordinary challenge into just 110 acres on Philadelphia\'s storied Main Line.', highlights: ['Five-time U.S. Open host', 'Bobby Jones Grand Slam and Ben Hogan 1-iron history', 'Hugh Wilson masterpiece on just 110 acres'], imageAlt: 'Merion Golf Club East Course iconic wicker basket flagstick on the Main Line', history: 'Merion Golf Club was founded in 1896 as part of the Merion Cricket Club. In 1910, Hugh Wilson, a young insurance broker and Princeton golf captain, was assigned to design a new course. He traveled to Britain to study the great links, then created the East Course opening in 1912 on just 110 acres in Ardmore on Philadelphia\'s Main Line.\n\nMerion East is where Bobby Jones completed the original Grand Slam by winning the 1930 U.S. Amateur, and where Ben Hogan hit his famous 1-iron on the 72nd hole to force a playoff at the 1950 U.S. Open, just 16 months after his near-fatal car accident. The course has hosted five U.S. Opens (1934, 1950, 1971, 1981, 2013) and more USGA championships than any other club.\n\nThe course is famous for wicker basket flagsticks used instead of traditional flags since the 1930s. The dramatic quarry holes (16, 17, 18) provide one of golf\'s most celebrated closing stretches.', signatureHoles: [{ hole: 11, par: 4, yardage: 367, description: 'One of the most famous short par 4s in golf. Where Ben Hogan hit his legendary 1-iron in the 1950 U.S. Open. A creek crosses the fairway creating a strategic decision off the tee.' }, { hole: 16, par: 4, yardage: 428, description: 'The first of the famous quarry holes. The tee shot plays downhill to a narrow fairway, and the approach must navigate the old quarry to a well-defended green.' }, { hole: 18, par: 4, yardage: 505, description: 'A demanding finishing hole alongside the old quarry. This long par 4 requires two excellent shots, with the green where Bobby Jones clinched the Grand Slam in 1930.' }], whatToExpect: 'A compact masterpiece on 110 acres with only two par 5s and a par of 70. Despite modest yardage at 6,846 yards, the course is extraordinarily demanding with tight fairways, deep bunkers, and small contoured greens marked by signature wicker basket flagsticks.\n\nThe closing stretch through the old quarry (holes 16-18) is among the most dramatic in golf. Walking with a caddie is standard.', playingTips: 'Precision is everything at Merion. The course rewards accurate iron play to small greens. The wicker baskets do not indicate wind direction, so read wind independently.\n\nOn the quarry holes, study hazards carefully before committing to a line. Play conservatively on 16 and 17, then give yourself the best angle into 18.', faqs: [{ question: 'Can the public play Merion?', answer: 'No. Private club, member invitation only.' }, { question: 'What are the wicker basket flagsticks?', answer: 'Merion uses wicker baskets atop flagsticks instead of flags, a tradition since the 1930s. They do not indicate wind direction.' }, { question: 'What happened at the 1950 U.S. Open?', answer: 'Ben Hogan hit a famous 1-iron to the 18th green to force a playoff, which he won, just 16 months after a near-fatal car accident.' }, { question: 'How small is Merion\'s property?', answer: 'The East Course is routed on approximately 110 acres, remarkably compact for a championship venue.' }] },
    { id: 'phi-3', name: 'Aronimink Golf Club', slug: 'aronimink-golf-club', city: 'Newtown Square', state: 'Pennsylvania', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Donald Ross', yearBuilt: 1928, holes: 18, par: 72, yardage: 7237, description: 'A Donald Ross masterpiece that hosted the 2018 BMW Championship, Aronimink is considered one of Ross\'s finest designs. The rolling layout through mature Philadelphia Main Line woodlands features bold strategic bunkering and superb green complexes that reward precision shotmaking.', highlights: ['2018 BMW Championship host', 'Donald Ross masterpiece on the Main Line', 'Bold strategic bunkering and green complexes'], imageAlt: 'Aronimink Golf Club Donald Ross fairway in Newtown Square Pennsylvania', history: 'Aronimink Golf Club was founded in 1896 and moved to its current Newtown Square location on the Philadelphia Main Line where Donald Ross completed his design in 1928. Ross reportedly declared it his masterpiece, stating he intended to make it his finest course. The club\'s name derives from a Lenape word meaning "running waters."\n\nThe course hosted the 1962 PGA Championship won by Gary Player and the 1977 U.S. Amateur. Over the decades, Dick Wilson and later George and Tom Fazio made modifications. In 2016-2017, Gil Hanse and Jim Wagner completed a comprehensive restoration that returned the course to Ross\'s original vision, removing decades of accumulated changes.\n\nThe restored Aronimink hosted the 2018 BMW Championship, where Keegan Bradley won in a playoff. The 2026 PGA Championship is scheduled for Aronimink, bringing another major championship to this storied venue. It is consistently ranked among the top 25 courses in America.', signatureHoles: [{ hole: 5, par: 4, yardage: 475, description: 'A sweeping, demanding par 4 with Ross\'s characteristic bunkering framing the approach. The green complex features bold contours that reward a precise approach shot from the correct angle.' }, { hole: 10, par: 4, yardage: 432, description: 'A strong opening hole on the back nine that plays through a corridor of mature hardwoods. The green is one of the most challenging on the course, with significant slope.' }, { hole: 13, par: 3, yardage: 210, description: 'A long par 3 known as "The Sink at the Mink" for its sunken green setting. One of Ross\'s most distinctive par 3 designs, demanding a precise long iron to a well-protected target.' }, { hole: 18, par: 4, yardage: 465, description: 'A powerful finishing hole that climbs toward the clubhouse. The approach is demanding, playing uphill to a green complex that has decided numerous championships.' }], whatToExpect: 'Aronimink is a Donald Ross masterpiece on the rolling terrain of the Philadelphia Main Line. Following the Hanse restoration, the course features Ross\'s original bold bunkering, challenging green contours, and strategic variety. Mature hardwoods frame every hole, creating a classic parkland atmosphere.\n\nAt 7,237 yards from the tips, Aronimink is a serious championship test. The green complexes are the primary defense, featuring Ross\'s signature contours that create challenging pin positions and demand precise approach play.', playingTips: 'Aronimink\'s greens are the key to scoring. Ross designed bold contours with multiple tiers and fall-off areas that punish misses. Hitting to the correct portion of each green is essential, and leaving approach shots on the low side provides easier putts.\n\nThe restored bunkers are strategically placed to challenge the optimal line on every hole. Understanding where the trouble lies and playing away from it is more important than chasing distance.', faqs: [{ question: 'Can the public play Aronimink?', answer: 'No. Aronimink is a private club. It gains public visibility through hosting major championships like the 2018 BMW Championship and the upcoming 2026 PGA Championship.' }, { question: 'What championships has Aronimink hosted?', answer: 'The 1962 PGA Championship, 1977 U.S. Amateur, 2018 BMW Championship, and the 2026 PGA Championship is scheduled.' }, { question: 'What is the Hanse restoration?', answer: 'In 2016-2017, Gil Hanse and Jim Wagner completed a comprehensive restoration returning the course to Donald Ross\'s original 1928 design intent, removing decades of accumulated changes.' }, { question: 'Why did Donald Ross call it his masterpiece?', answer: 'Ross reportedly declared he intended to make Aronimink his finest course. The rolling Main Line terrain and natural features gave him an ideal canvas for his design philosophy.' }] },
    { id: 'phi-4', name: 'Philadelphia Cricket Club - Wissahickon', slug: 'philly-cricket-wissahickon', city: 'Flourtown', state: 'Pennsylvania', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'A.W. Tillinghast', yearBuilt: 1922, holes: 18, par: 72, yardage: 6748, description: 'An A.W. Tillinghast design in the Wissahickon Valley, Philadelphia Cricket Club hosted the 2005 and 2010 U.S. Senior Opens. The intimate Tillinghast layout features strategic bunkering, creative green sites, and a classic Philadelphia parkland setting through mature hardwoods.', highlights: ['A.W. Tillinghast classic design', 'Two-time U.S. Senior Open host', 'Wissahickon Valley parkland setting'], imageAlt: 'Philadelphia Cricket Club Wissahickon Course Tillinghast fairway', history: 'Philadelphia Cricket Club is America\\\'s oldest country club, established in 1854. The Wissahickon Course was designed by A.W. Tillinghast — a Philadelphia native who considered this his home course for life — and opened in 1922. Originally called the Flourtown Course, renamed Wissahickon in 2002.\n\nA comprehensive Keith Foster and Phil Young restoration completed Memorial Day 2014 returned the course to Tillinghast\\\'s original vision. Ranked No. 98 in Golf Magazine\\\'s Top 100 U.S. courses (2024-25).\n\nThe course hosted the 2005 and 2010 U.S. Senior Opens, the 2016 Constellation Senior Players Championship, and the 2025 Truist Championship (PGA Tour Champions).', signatureHoles: [{ hole: 7, par: 5, yardage: 553, description: 'Features Tillinghast\\\'s famous "Great Hazard" — mass bunkering designed to replicate the impact of a water hazard. A strategic three-shot hole that defines the architect\\\'s philosophy of challenge through angles rather than raw difficulty.' }, { hole: 18, par: 4, yardage: 487, description: 'A brutal finishing hole running along Lorraine Run creek. One of the most demanding closers in the Philadelphia region — where championships are won and lost.' }, { hole: 15, par: 3, yardage: 240, description: 'A Redan-style par 3 requiring a long, shaped shot. Part of a punishing closing stretch (15-18) among the toughest in Philadelphia golf.' }], whatToExpect: 'A big, classic Tillinghast design with U.S. Open-caliber conditions. The front nine feels intimate through a lower section; the back nine opens up with an expansive feel and a punishing 15-18 closing stretch.\n\nGenerous driving areas reward accuracy over power — the course challenges through strategic angles rather than sheer length. Exceptional variety in the par 3s. The 2014 Foster/Young restoration returned the course to Tillinghast\\\'s original strategic brilliance.\n\nStrictly private — one of the most prestigious clubs in Philadelphia.', playingTips: 'Where you place your drive dictates everything on approach shots. Pay close attention to angle of approach.\n\nThe closing holes (15-18) are among the toughest in Philadelphia golf. Save your best golf for the finish.\n\nTillinghast\\\'s green complexes are well-protected with strategic bunkering. Study the pin positions carefully.\n\nThe "Great Hazard" on 7 looks like a water hazard but is pure sand — play it as such.', faqs: [{ question: 'What major events has it hosted?', answer: '2005 and 2010 U.S. Senior Opens, 2016 Senior Players Championship, and 2025 Truist Championship (PGA Tour Champions). Ranked No. 98 in Golf Magazine\\\'s Top 100.' }, { question: 'Who designed it?', answer: 'A.W. Tillinghast (1922), restored by Keith Foster and Phil Young (2014). Tillinghast considered this his home course for life.' }, { question: 'How old is the club?', answer: 'Founded 1854 — America\\\'s oldest country club. The golf course opened in 1922.' }]},
    { id: 'phi-5', name: 'Union League Liberty Hill', slug: 'union-league-liberty-hill', city: 'Lafayette Hill', state: 'Pennsylvania', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Gil Hanse', yearBuilt: 2023, holes: 18, par: 72, yardage: 7206, description: 'Gil Hanse\'s newest Philadelphia-area design, Union League Liberty Hill opened in 2023 on a property overlooking the Schuylkill Valley. The modern layout blends minimalist shaping with classic Philadelphia golf traditions, featuring wide fairways, creative green complexes, and firm-and-fast conditioning.', highlights: ['Gil Hanse 2023 opening', 'Schuylkill Valley overlook', 'Minimalist modern design with firm-and-fast play'], imageAlt: 'Union League Liberty Hill Gil Hanse fairway overlooking Schuylkill Valley', history: 'Union League Liberty Hill traces its origins to the Ace Club, which was built in 2003 on 311 rolling acres in Lafayette Hill, Pennsylvania. The property was originally designed by Gary Player and featured 27 holes of golf. In 2017, the Union League of Philadelphia — one of the oldest and most prestigious private clubs in America, founded in 1862 — acquired the facility as a companion golf property.\n\nThe Union League subsequently commissioned renowned architect Gil Hanse to undertake a comprehensive reimagining of the golf course. Hanse, fresh from his celebrated work at Merion, the Olympic course in Rio, and the Ohoopee Match Club, transformed the property into an 18-hole minimalist design that opened in 2023. The renovation stripped away artificial features to reveal the natural contours of the Schuylkill Valley landscape.\n\nThe result is a modern championship layout that blends firm-and-fast playing conditions with the rich Philadelphia golf tradition. Liberty Hill complements the Union League\'s other golf property, Union League National (formerly Sand Barrens), giving the 160-year-old club two distinct golf experiences for its membership.', signatureHoles: [{ hole: 3, par: 4, yardage: 420, description: 'A sweeping dogleg par 4 that takes full advantage of the Schuylkill Valley views. The tee shot must navigate Hanse\'s characteristic strategic bunkering to set up an approach to a green with subtle contours.' }, { hole: 9, par: 4, yardage: 445, description: 'A strong finishing hole for the front nine that plays along the ridgeline with panoramic views. The approach shot demands precision to a well-defended green complex.' }, { hole: 14, par: 3, yardage: 195, description: 'One of Hanse\'s most visually striking par 3s on the property, playing to a green surrounded by natural terrain movement and strategic bunkering that frames the putting surface beautifully.' }, { hole: 18, par: 4, yardage: 460, description: 'A demanding finishing hole that brings the round to a dramatic close with the Schuylkill Valley as a backdrop. The approach must carry Hanse\'s bunkering to reach a green with championship-caliber pin positions.' }], whatToExpect: 'Union League Liberty Hill is a modern minimalist Gil Hanse design set on 311 acres of rolling terrain overlooking the Schuylkill Valley in Lafayette Hill, Pennsylvania. The par-72 course plays to 7,206 yards from the championship tees with firm-and-fast conditions that encourage ground-game creativity. Wide fairways offer multiple strategic angles, but Hanse\'s green complexes demand precise approach play.\n\nThe conditioning and presentation reflect the Union League\'s commitment to excellence. The clubhouse and practice facilities are first-class, befitting one of America\'s oldest and most prestigious private clubs.', playingTips: 'Hanse\'s design rewards golfers who think their way around the course. The wide fairways can lull players into complacency, but the real challenge lies in positioning. Approaching greens from the correct angle is essential, as Hanse\'s green complexes feature subtle runoffs and collection areas that punish careless approaches.\n\nThe firm-and-fast conditions mean that bump-and-run approaches are often more effective than high-spinning wedge shots. Study the green contours carefully — what appears flat often has subtle movement that affects putts significantly.', faqs: [{ question: 'Can the public play Union League Liberty Hill?', answer: 'No. Union League Liberty Hill is a private club accessible only to members of the Union League of Philadelphia and their guests.' }, { question: 'What was Union League Liberty Hill before the renovation?', answer: 'The property was originally the Ace Club, a 27-hole Gary Player design that opened in 2003. The Union League acquired it in 2017 and commissioned Gil Hanse to redesign it as an 18-hole course, which opened in 2023.' }, { question: 'How many golf courses does the Union League have?', answer: 'The Union League of Philadelphia operates two golf properties: Liberty Hill in Lafayette Hill (Gil Hanse design) and Union League National, formerly Sand Barrens, a 27-hole facility designed by Michael Hurdzan and Dana Fry.' }, { question: 'Who is the architect of Union League Liberty Hill?', answer: 'Gil Hanse redesigned the course, which opened in 2023. Hanse is known for his minimalist approach and has designed courses worldwide, including the Olympic course in Rio de Janeiro.' }] },
    { id: 'phi-6', name: 'Huntingdon Valley Country Club', slug: 'huntingdon-valley-cc', city: 'Huntingdon Valley', state: 'Pennsylvania', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'William Flynn', yearBuilt: 1897, holes: 18, par: 70, yardage: 6664, description: 'A William Flynn redesign on one of the oldest club properties in the Philadelphia area, Huntingdon Valley features a tight, tree-lined parkland layout demanding accuracy. Flynn\'s green complexes are among his most intricate, with subtle contours that test even the best short games.', highlights: ['William Flynn intricate green complexes', 'One of Philadelphia\'s oldest clubs', 'Tight parkland layout demanding precision'], imageAlt: 'Huntingdon Valley Country Club William Flynn fairway through mature trees', history: 'Huntingdon Valley was organized in 1896 and first played on in 1897, making it the first club in the Philadelphia area organized exclusively for golf. The current layout was designed by William Flynn, with the main 18-hole course opening in 1928.\n\nA careful restoration by architect Andrew Green focused on tree removal to restore sightlines, bunker re-edging, tee improvements, and drainage — described as "brushing dust off ancient pottery rather than creating replicas."\n\nRobert Trent Jones himself called the par-3 8th "one of the finest par 3s he had ever played." Ranked among the top private courses in Pennsylvania and top-3 in the Philadelphia area by Golf Digest.', signatureHoles: [{ hole: 13, par: 3, yardage: 175, description: 'Features a lake that Flynn created in 1927 — among the first examples in the U.S. of an architect building a lake specifically to defend a par-3 green. A picturesque and strategically demanding one-shotter.' }, { hole: 8, par: 3, yardage: 190, description: 'Robert Trent Jones himself called this one of the finest par 3s he had ever played. High praise from the legendary architect.' }, { hole: 7, par: 5, yardage: 550, description: 'Each shot gets progressively tighter, with strategic bunkering leading to one of the course\\\'s smallest, firmest greens. Classic Flynn progressive difficulty.' }], whatToExpect: 'The course is routed through a scenic wooded bowl with a stream running through it. The front nine plays counter-clockwise around the top; the back nine loops clockwise at the bottom. Greens are among the firmest in Philadelphia, canting side-to-side rather than predictable back-to-front.\n\nFirm, fast conditions emphasize a traditional ground-game approach. Flynn\\\'s intricate green complexes test even the best short games.\n\nStrictly private — one of the top-3 private courses in the Philadelphia area.', playingTips: 'Forget standard back-to-front green reads — Flynn\\\'s greens require side-to-side thinking. This is the key to scoring here.\n\nFirm conditions reward bump-and-run approaches throughout. Don\\\'t automatically reach for the lob wedge.\n\nStudy green complexes carefully before committing to club selection. The intricate contours are Flynn\\\'s primary defense.', faqs: [{ question: 'What makes Flynn\\\'s greens special here?', answer: 'They cant side-to-side rather than the predictable back-to-front slopes found elsewhere. Firm conditions require a ground-game approach that tests creativity and touch.' }, { question: 'How old is the club?', answer: 'Organized 1896, first played 1897 — the first Philadelphia-area club organized exclusively for golf. Flynn\\\'s current layout opened in 1928.' }, { question: 'Who did the restoration?', answer: 'Andrew Green led a careful restoration focusing on tree removal, bunker re-edging, and drainage — described as brushing dust off ancient pottery.' }]},
    { id: 'phi-7', name: 'Inniscrone Golf Club', slug: 'inniscrone-golf-club', city: 'Avondale', state: 'Pennsylvania', type: 'public', rating: 4.2, greensFee: '$45–$85', architect: 'Jim Blaukovitch', yearBuilt: 2001, holes: 18, par: 72, yardage: 7021, description: 'Named for a village in western Ireland, Inniscrone is a links-inspired public course in Chester County with rolling terrain, fescue rough, and panoramic countryside views. The layout offers championship length and challenge uncommon for public golf in the Philadelphia area.', highlights: ['Links-inspired public course in Chester County', 'Rolling terrain with fescue rough', 'Championship-caliber public golf near Philadelphia'], imageAlt: 'Inniscrone Golf Club links-style fairway in Chester County Pennsylvania', history: 'Inniscrone Golf Club was Gil Hanse\\\'s first solo design project, opening in the late 1990s on rolling terrain about 45 miles west of Philadelphia in Chester County. Hanse — who went on to design the 2016 Olympic Course in Rio and renovate Merion, The Country Club (Brookline), and many other prestigious venues — started his career here.\n\nThe property possessed large natural ground movements that Hanse designed around, pushing holes into formerly open farmland. Named for a village in western Ireland. LINKS Magazine has featured the course for its strategic originality.\n\nNow fully open to the public under London Grove Township ownership — one of the better values in the area for architecturally significant golf.', signatureHoles: [{ hole: 16, par: 4, yardage: 400, description: 'Features a split fairway all the way to the green — described as one of the most unusual and difficult holes in America. Requires a decisive strategic choice off the tee that affects every subsequent shot.' }, { hole: 3, par: 4, yardage: 309, description: 'A classic driveable risk-reward par 4. The short distance tempts aggressive play but the green complex punishes anything less than precise. Vintage Hanse strategic design.' }], whatToExpect: 'A hilly course that starts manageable but gets progressively harder toward the finish. The closing stretch (holes 13-18) is the strongest routing section. Deep rough, masterfully shaped bunkers, and fast undulating greens. Several forced carries and blind shots add old-school character.\n\nThe course plays significantly longer than the scorecard suggests due to elevation changes. Slope rating of 140 confirms the difficulty despite the par-70, 6,630-yard layout.\n\nPublic access — outstanding value for a course by the architect of the Olympic Course.', playingTips: 'Course management is everything. The short par 4s (holes 2-5) look easy but are exceptionally tricky.\n\nTake extra club on uphill approaches — there are many, and the elevation makes the course play much longer than yardage suggests.\n\nAccuracy off the tee matters far more than distance on this hilly terrain.\n\nExpect to use a cart — the terrain is extremely hilly between holes.', faqs: [{ question: 'Is this really Gil Hanse\\\'s first course?', answer: 'Yes — his first solo design project. Hanse went on to design the Olympic Course in Rio and renovate Merion, The Country Club, and many other prestigious venues.' }, { question: 'Is it open to the public?', answer: 'Yes — owned by London Grove Township in Chester County. One of the better public golf values in the Philadelphia area.' }, { question: 'Why is it called Inniscrone?', answer: 'Named for a village in western Ireland, reflecting the links-inspired character of the rolling Chester County terrain.' }]},
    { id: 'phi-8', name: 'Broad Run Golfer\'s Club', slug: 'broad-run-golfers-club', city: 'West Chester', state: 'Pennsylvania', type: 'semi-private', rating: 4.1, greensFee: '$40–$75', architect: 'Rees Jones', yearBuilt: 2001, holes: 18, par: 72, yardage: 6850, description: 'A Rees Jones design in the rolling Chester County countryside, Broad Run offers semi-private access to a layout routed through farmland, mature hardwoods, and natural stream corridors. The well-conditioned course provides a quality experience at accessible pricing.', highlights: ['Rees Jones Chester County design', 'Farmland and hardwood routing', 'Accessible semi-private pricing'], imageAlt: 'Broad Run Golfers Club Rees Jones fairway through Chester County farmland', history: 'Broad Run Golfer\\\'s Club opened in 2000, designed by Rees Jones with Phil Larsen on 372 acres of Chester County\\\'s Brandywine Valley countryside. The land was once known as "Como Farm," named after a small Italian town by its original owner.\n\nEarned 2014 Pennsylvania Course of the Year honors and is consistently rated among the top public courses in southeastern PA. A 4-star Golf Digest course with Princeville Bent fairways and G2 Bent greens.', signatureHoles: [{ hole: 18, par: 4, yardage: 420, description: 'A strong finishing hole using the dramatic elevation changes the course is known for. Demands an accurate approach to close out the round on the rolling Chester County terrain.' }], whatToExpect: 'Dramatic elevation changes throughout with steep inclines around greens. Despite the challenge, Jones kept bunkering relatively light and fairways generous — more forgiving off the tee than his major championship work.\n\nCart-only — the terrain is too steep for comfortable walking. Multi-tiered, undulating greens are the primary defense.\n\nSemi-private access at $40-75 — strong value for a Rees Jones design.', playingTips: 'Club selection is critical due to significant elevation changes. Uphill/downhill adjustments of 1-2 clubs are common on nearly every hole.\n\nFairways are generous — prioritize keeping the ball in play rather than chasing distance.\n\nGreen complexes are multi-tiered and undulating. Precise approach shots define your score.', faqs: [{ question: 'Who designed Broad Run?', answer: 'Rees Jones ("The Open Doctor") with Phil Larsen. One of the few public courses to benefit from Jones\\\'s design expertise. Opened 2000.' }, { question: 'Is it walkable?', answer: 'No — cart-only due to the steep Chester County terrain.' }, { question: 'How is it ranked?', answer: '2014 Pennsylvania Course of the Year. 4-star Golf Digest rating. Consistently among the top public courses in southeastern PA.' }]},
  ],
  'washington-dc': [
    { id: 'dc-1', name: 'Congressional Country Club - Blue', slug: 'congressional-blue', city: 'Bethesda', state: 'Maryland', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Andrew Green (restoration)', yearBuilt: 1924, holes: 18, par: 72, yardage: 7580, description: 'Host of three U.S. Opens and the 2024 U.S. Women\'s Open, Congressional\'s Blue Course is one of the most prominent championship venues near Washington D.C. Andrew Green\'s comprehensive 2020 restoration removed trees, restored sight lines, and returned the course to its bold, strategic origins.', highlights: ['Three-time U.S. Open host venue', 'Andrew Green 2020 comprehensive restoration', 'Premier championship venue near the nation\'s capital'], imageAlt: 'Congressional Country Club Blue Course championship fairway in Bethesda Maryland', history: 'Congressional Country Club was founded in 1924, originally designed by Devereux Emmet, 12 miles northwest of the U.S. Capitol in Bethesda. The Blue Course has hosted three U.S. Opens (1964, 1997, 2011) and the 2024 U.S. Women\\\'s Open.\n\nAndrew Green\\\'s comprehensive 2019-2021 restoration transformed the course from what critics called one of the dullest championship venues into one of the most distinctive and intriguing. Green stripped away decades of accumulated changes, restored ground-game options, and created an unconventional par-71 with three par 3s, three par 4s, and three par 5s on each nine.\n\nThe KPMG Women\\\'s PGA Championship (2022) was the first major on the renovated Blue Course.', signatureHoles: [{ hole: 18, par: 4, yardage: 470, description: 'The iconic finishing hole seen during every U.S. Open broadcast. Water guards the approach — a precise shot over the pond to a well-bunkered green is required. Where championships are decided.' }, { hole: 10, par: 5, yardage: 560, description: 'A sweeping downhill par 5 kicking off the back nine with dramatic terrain. Water comes into play for those going for the green in two. Considered one of the most improved holes in the Green renovation.' }], whatToExpect: 'A unique par-71 where back-to-back holes of the same par only occur once (11th and 12th). Green\\\'s renovation restored ground-game options — you can fly it or run it up on most holes. The back nine changes character significantly with more dramatic elevation and decisive water on holes 10, 11, and 18.\n\nChampionship-caliber conditions throughout. The restoration has been widely praised as one of the most transformative in modern American golf.\n\nStrictly private — one of the most prominent clubs near the nation\\\'s capital.', playingTips: 'The ground game is back in play after the Green renovation. On many holes, bumping from well short of the green is a viable strategy.\n\nThe back nine is the scoring stretch if you play holes 10-13 well. Save your best golf for the finish.\n\nGreen complexes are the primary challenge — pin positions on holes like the 14th are particularly devious.', faqs: [{ question: 'How many U.S. Opens has Congressional hosted?', answer: 'Three — 1964, 1997, and 2011. Also hosted the 2024 U.S. Women\\\'s Open on the renovated Blue Course.' }, { question: 'What was the Green restoration?', answer: 'Andrew Green\\\'s 2019-2021 work transformed the course from one of the dullest championship venues to one of the most distinctive. Restored ground-game options, created unique par-71 configuration.' }, { question: 'Can the public play?', answer: 'No. Congressional is strictly private — one of the most prominent clubs in the Washington D.C. area.' }]},
    { id: 'dc-2', name: 'TPC Potomac at Avenel Farm', slug: 'tpc-potomac', city: 'Potomac', state: 'Maryland', type: 'semi-private', rating: 4.5, greensFee: '$100–$200', architect: 'Ed Ault (renovated)', yearBuilt: 1986, holes: 18, par: 70, yardage: 7105, description: 'Home of the Cognizant Classic on the PGA Tour, TPC Potomac at Avenel Farm offers championship golf in the affluent Potomac corridor. The parkland layout along the Potomac River features well-defended greens, strategic water hazards, and tour-caliber conditioning.', highlights: ['PGA Tour Cognizant Classic host', 'Potomac River parkland setting', 'Tour-caliber conditioning with public access'], imageAlt: 'TPC Potomac at Avenel Farm championship fairway along the Potomac River', history: 'TPC Potomac at Avenel Farm, originally known as TPC Avenel, opened in 1986 on 220 acres of rolling wooded countryside in Montgomery County, Maryland. The course was designed by Edmund Ault and Tom Clark, with PGA Tour player Ed Sneed serving as the player consultant. It was built specifically to host PGA Tour events and quickly became the home of the Kemper Open, later known as the Booz Allen Classic.\n\nThe course hosted PGA Tour events regularly from 1987 through 2006, with winners including Steve Elkington, Tiger Woods, and Stuart Appleby. In 2008, the course underwent a historic renovation under the direction of PGA Tour Design Services, with Davis Love III providing player consultation. The redesign dramatically transformed the layout, creating more strategic options and modernizing the course for contemporary tour play.\n\nRebranded as TPC Potomac at Avenel Farm, the venue returned to the PGA Tour spotlight when it hosted the Wells Fargo Championship in 2022, won by Max Homa. The course continues to host tour events and serves as one of the premier private golf facilities in the Washington D.C. metropolitan area.', signatureHoles: [{ hole: 18, par: 4, yardage: 455, description: 'A demanding finishing hole that plays slightly uphill to a well-defended green. This hole has produced dramatic finishes in PGA Tour events, with water guarding the approach.' }, { hole: 10, par: 4, yardage: 380, description: 'A strategic par 4 with water running along the left side that demands a precise tee shot. The approach plays to a green complex that rewards accuracy over power.' }, { hole: 13, par: 3, yardage: 195, description: 'A picturesque par 3 over water to an island-style green surrounded by bunkers. One of the most visually striking and nerve-testing holes on the course.' }, { hole: 7, par: 5, yardage: 555, description: 'A risk-reward par 5 that offers eagle opportunities for those bold enough to carry the water on their second shot, but severely punishes mistakes.' }], whatToExpect: 'TPC Potomac at Avenel Farm delivers championship-caliber golf in a beautiful parkland setting. The course features impeccable conditioning year-round, with lush fairways winding through mature hardwoods and strategic water hazards testing decision-making on multiple holes. The 2008 renovation created a modern layout that balances challenge with playability.\n\nAs a TPC facility, the service and amenities are first-class. The clubhouse overlooks the 18th green and provides an excellent setting for post-round dining. The course plays to a par of 70, making every shot count.', playingTips: 'Water comes into play on numerous holes at TPC Potomac, so course management is essential. Know your carry distances and err on the side of caution when water is in play, particularly on the par 3s and risk-reward par 5s.\n\nThe greens are fast and true, with subtle slopes that can be deceptive. Pay attention to the grain, which generally follows the drainage toward the Potomac River. The tree-lined fairways reward accuracy off the tee, so consider hitting less than driver on the tighter holes to find the fairway.', faqs: [{ question: 'Can the public play TPC Potomac?', answer: 'TPC Potomac operates as a private club with TPC membership access. It is not generally open to the public, though limited access may be available during certain events or through TPC membership programs.' }, { question: 'What PGA Tour events has TPC Potomac hosted?', answer: 'TPC Potomac has hosted the Wells Fargo Championship, Quicken Loans National, Booz Allen Classic, and Kemper Open over its history, with winners including Tiger Woods, Max Homa, and Steve Elkington.' }, { question: 'Who redesigned TPC Potomac in 2008?', answer: 'The course was redesigned by PGA Tour Design Services with Davis Love III serving as the player consultant, dramatically transforming the layout from the original Ault/Clark design.' }, { question: 'Where is TPC Potomac located?', answer: 'TPC Potomac is located in Potomac, Maryland, in the affluent Montgomery County suburbs northwest of Washington D.C.' }] },
    { id: 'dc-3', name: 'Caves Valley Golf Club', slug: 'caves-valley-golf-club', city: 'Owings Mills', state: 'Maryland', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 1991, holes: 18, par: 72, yardage: 7540, description: 'A Tom Fazio design in the lush Baltimore-Washington corridor, Caves Valley hosted the 2021 BMW Championship. The sweeping parkland layout through rolling terrain features immaculate conditioning, bold Fazio shaping, and a serene valley setting surrounded by mature hardwoods.', highlights: ['2021 BMW Championship host', 'Tom Fazio sweeping parkland design', 'Pristine valley setting near Baltimore and D.C.'], imageAlt: 'Caves Valley Golf Club Tom Fazio fairway through rolling Maryland terrain', history: 'Caves Valley Golf Club was designed by Tom Fazio and opened in 1991 in Maryland\\\'s hunt country northwest of Baltimore. The club hosted the 2021 BMW Championship — where Patrick Cantlay defeated Bryson DeChambeau on the sixth playoff hole in an epic duel — and is set to host again in 2025 after a major 100-day renovation toughened the course.\n\nThe 2021 field averaged nearly 3-under per round, prompting the renovation to add teeth before the 2025 return. Ranked in Golf Digest\\\'s Second 100 Greatest (No. 154).', signatureHoles: [{ hole: 12, par: 3, yardage: 179, description: 'Part of the best stretch on the course (holes 9-14). An elevated green with dramatic bunkering and Maryland countryside views. The mid-iron par 3 demands precision.' }, { hole: 15, par: 4, yardage: 491, description: 'A demanding long par 4 showcasing the rolling terrain and surrounding landscape. Bunkers punish wayward approaches on one of the course\\\'s sternest tests.' }], whatToExpect: 'A par-72 playing 7,540 yards from the championship tees through rolling Maryland hunt country. Fast bentgrass greens, undulating fairways, and strategically placed water hazards. The parkland setting through hardwood forests creates a serene, private atmosphere.\n\nThe 2025 renovation added significant challenge after the PGA Tour pros torched the 2021 layout. Strictly private — member or guest access only.', playingTips: 'Course management is paramount. Rolling fairways create uneven lies throughout — take an extra moment to assess your stance.\n\nThe stretch from holes 9-14 is the heart of the round. Play conservatively if unfamiliar.\n\nGreens are receptive but undulating — missing on the wrong side creates very difficult up-and-downs.', faqs: [{ question: 'Did it host the BMW Championship?', answer: 'Yes — 2021 (Cantlay won in a six-hole playoff vs. DeChambeau) and returning in 2025 after a renovation to toughen the course.' }, { question: 'Who designed it?', answer: 'Tom Fazio, opening in 1991 in Maryland\\\'s hunt country northwest of Baltimore.' }, { question: 'Can the public play?', answer: 'No. Caves Valley is strictly private.' }]},
    { id: 'dc-4', name: 'Whiskey Creek Golf Club', slug: 'whiskey-creek-golf-club', city: 'Ijamsville', state: 'Maryland', type: 'public', rating: 4.3, greensFee: '$55–$100', architect: 'J. Michael Poellot', yearBuilt: 2000, holes: 18, par: 72, yardage: 7001, description: 'A J. Michael Poellot design in Frederick County, Whiskey Creek is consistently rated the best public course in Maryland. The layout rolls through piedmont terrain with scenic views of the Catoctin Mountains, strategic bunkering, and bentgrass fairways in impeccable condition.', highlights: ['Top-rated public course in Maryland', 'Catoctin Mountain views', 'Bentgrass fairways with impeccable conditioning'], imageAlt: 'Whiskey Creek Golf Club fairway with Catoctin Mountain views in Maryland', history: 'Whiskey Creek opened in 2000, designed by J. Michael Poellot with two-time U.S. Open champion Ernie Els as design consultant — one of Els\\\'s first ventures into course design. Located near Frederick, MD at the end of a mile-long drive through forest and field.\n\nThe property features ponds, wetland areas, rocky outcrops, meadows, and pine forest, bordered by a high ridge of hardwoods with panoramic views of the Catoctin and Blue Ridge Mountains. Widely considered the best public course in Maryland.', signatureHoles: [{ hole: 5, par: 4, yardage: 371, description: 'The tee shot from the highest point on the course offers panoramic 30-mile views of the Catoctin and Blue Ridge Mountains. A demanding par 4 despite moderate length due to elevation and wind exposure.' }, { hole: 18, par: 5, yardage: 540, description: 'The iconic closer features old stone house ruins sitting in the middle of the fairway — a truly remarkable and unique finishing hole that demands strategy around the historic ruins while providing an unforgettable visual.' }], whatToExpect: 'A par-72 through dramatically varied terrain where every hole demands a different type of shot. Elevation changes are the primary challenge. The setting feels private and secluded despite being fully public.\n\nThe stone ruins on the 18th are original to the property and were incorporated into the design rather than removed — one of the most unique finishing holes in American public golf.\n\nManaged by KemperSports at $55-100.', playingTips: 'Elevation changes are extreme. Factor significant yardage adjustments, especially on downhill tee shots.\n\nThis is a thinker\\\'s course — club selection and shot shape matter more than raw distance.\n\nThe course plays harder than the scorecard suggests. Take one more club than you think on approach shots.\n\nConditions are typically excellent — trust your yardages once elevation is factored in.', faqs: [{ question: 'Is it really the best public course in Maryland?', answer: 'Widely considered so by Golf Digest, Golf Magazine, and Golfweek. The varied terrain, Catoctin Mountain views, and excellent conditioning set it apart.' }, { question: 'What are the ruins on 18?', answer: 'Original old stone house ruins sitting in the middle of the fairway — incorporated into the design rather than removed. One of the most unique finishing holes in public golf.' }, { question: 'Who co-designed it with Poellot?', answer: 'Ernie Els served as design consultant — one of the two-time U.S. Open champion\\\'s first ventures into course design.' }]},
    { id: 'dc-5', name: 'Robert Trent Jones Golf Club', slug: 'rtj-golf-club', city: 'Gainesville', state: 'Virginia', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Robert Trent Jones Sr.', yearBuilt: 1991, holes: 18, par: 72, yardage: 7340, description: 'Built as a tribute to the legendary architect and host of the 1994, 2000, and 2005 Presidents Cups, Robert Trent Jones Golf Club features a dramatic lakeside layout in Virginia\'s rolling piedmont. The challenging design demands precise shot placement around Lake Manassas.', highlights: ['Three-time Presidents Cup host', 'Lake Manassas dramatic lakeside routing', 'Tribute to legendary architect RTJ Sr.'], imageAlt: 'Robert Trent Jones Golf Club lakeside fairway on Lake Manassas Virginia', history: 'Robert Trent Jones Golf Club was designed by RTJ Sr. and opened in 1991 in Gainesville, Virginia, purpose-built as a world-class competition venue. It hosted the first four Presidents Cups held in the U.S. (1994, 1996, 2000, 2005) — with Gerald Ford chairing the inaugural 1994 match — and the 2024 Solheim Cup.\n\nThe centerpiece is 850-acre Lake Manassas, visible from nearly every hole. Eight holes on the back nine run directly along its banks, transforming the course\\\'s character from inland parkland to dramatic lakeside golf.\n\nThe 1994 Presidents Cup ended in the only tie in the event\\\'s history (before the 2003 tie).', signatureHoles: [{ hole: 11, par: 3, yardage: 215, description: 'One of two par 3s on Lake Manassas (with the 9th) and considered among the most attractive holes in Virginia. The tee shot carries over an inlet to a green perched on the shoreline with water on multiple sides.' }, { hole: 18, par: 4, yardage: 400, description: 'A strong finishing hole along the lake — the stage for many dramatic Presidents Cup and Solheim Cup moments. Water runs the entire left side, demanding accuracy from tee to green.' }], whatToExpect: 'The front nine plays as strong inland parkland. The back nine transforms as it reaches Lake Manassas — eight holes along the banks with stunning views and demanding forced carries over water.\n\nRTJ Sr.\\\'s trademark bold, heroic design: wide fairways narrowing at landing zones, large greens with severe slopes, and risk-reward options on nearly every hole. Ten holes directly interact with the lake.\n\nStrictly private — one of the most prestigious clubs in Virginia.', playingTips: 'The back nine is the marquee stretch. Lake Manassas creates wind exposure not experienced on the front — recalibrate your distances.\n\nHoles 9 and 11 are the signature par 3s over the lake. Pick the right club and commit — no bailout over water.\n\nRTJ Sr. greens are large but heavily contoured. Being on the correct tier matters more than being pin-high.\n\nPick your line off the tee and commit. The course rewards bold, decisive play.', faqs: [{ question: 'How many Presidents Cups has it hosted?', answer: 'Four — 1994, 1996, 2000, and 2005. Also hosted the 2024 Solheim Cup.' }, { question: 'What is Lake Manassas?', answer: 'An 850-acre lake visible from nearly every hole. Eight back-nine holes run directly along its banks, creating dramatic lakeside golf.' }, { question: 'Can the public play?', answer: 'No. RTJ Golf Club is strictly private — purpose-built as a world-class competition venue.' }]},
    { id: 'dc-6', name: 'Queenstown Harbor Golf Links - River', slug: 'queenstown-harbor-river', city: 'Queenstown', state: 'Maryland', type: 'public', rating: 4.2, greensFee: '$50–$100', architect: 'Lindsay Ervin & Roger Baird', yearBuilt: 1991, holes: 18, par: 72, yardage: 6837, description: 'A links-style layout on Maryland\'s Eastern Shore along the Chester River, Queenstown Harbor is an easy drive from D.C. and offers panoramic water views from virtually every hole. The windswept design rewards creative shotmaking and ground-game play.', highlights: ['Chester River links-style layout', 'Water views from nearly every hole', 'Easy Eastern Shore drive from D.C.'], imageAlt: 'Queenstown Harbor River Course links fairway along the Chester River', history: 'Queenstown Harbor\\\'s River Course opened in 1991 on Maryland\\\'s Eastern Shore at the mouth of the Chester River where it flows into the Chesapeake Bay. Designed by Lindsay Ervin and Roger Baird, it is the premier layout of the 36-hole Queenstown Harbor facility.\n\nA significant renovation in 2011 refreshed the bunkers. The course is consistently ranked among the top public courses in Maryland and the D.C. area. Over half the holes offer panoramic Chester River and Chesapeake Bay views.', signatureHoles: [{ hole: 8, par: 4, yardage: 400, description: 'Part of the celebrated riverside stretch where 3-4 holes play directly along the Chester River. Panoramic water views and wind off the river create a links-like experience uncommon for the mid-Atlantic.' }], whatToExpect: 'A mix of protected tree-lined fairways on inland portions and windswept links-style holes along the Chester River. The water views are stunning on the riverside stretch. The facility includes a Toptracer driving range, river cottages, and on-site dining.\n\nLocated on the Eastern Shore within easy reach of D.C., Baltimore, and Annapolis — a top day-trip destination at $50-100.', playingTips: 'Factor in wind on the exposed riverside holes — club selection can shift significantly.\n\nAccurate approach shots matter more than raw distance throughout.\n\nThe renovated bunkers are strategic but fair.', faqs: [{ question: 'Where is Queenstown Harbor?', answer: 'Maryland\\\'s Eastern Shore at the mouth of the Chester River. Easy drive from D.C., Baltimore, and Annapolis.' }, { question: 'How many courses?', answer: '36 holes — the River Course (premier layout) and the Lakes Course.' }]},
    { id: 'dc-7', name: 'Woodmont Country Club - North', slug: 'woodmont-north', city: 'Rockville', state: 'Maryland', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'William Flynn', yearBuilt: 1927, holes: 18, par: 72, yardage: 6925, description: 'A William Flynn design in Rockville, Woodmont\'s North Course has hosted the U.S. Senior Open and U.S. Women\'s Amateur. The classic parkland layout through mature trees features Flynn\'s hallmark strategic bunkering and clever green complexes on rolling Maryland terrain.', highlights: ['William Flynn classic design', 'U.S. Senior Open and U.S. Women\'s Amateur host', 'Rolling Maryland parkland through mature trees'], imageAlt: 'Woodmont Country Club North Course William Flynn fairway in Rockville Maryland', history: 'Woodmont Country Club traces its origins to 1913, with William Flynn designing the North Course at the current Rockville site (opened 1927). Flynn — one of the most celebrated Golden Age architects, also responsible for Shinnecock Hills and Merion — created a classic parkland layout later renovated by Arthur Hills. A second 18 (South Course, Alfred Tull, 1950) makes Woodmont a 36-hole facility.\n\nThe club has hosted the 120th U.S. Women\\\'s Amateur (2020), U.S. Open Final Qualifying over 40 times since 1986, and is selected for the 2025-2026 U.S. Adaptive Opens and 2028 U.S. Junior Amateur — one of the most prolific USGA host sites in the mid-Atlantic.', signatureHoles: [{ hole: 14, par: 4, yardage: 420, description: 'A demanding par 4 showcasing Flynn\\\'s hallmark strategic bunkering and green complexes. The mature tree-lined corridor demands accurate positioning off the tee to set up the best approach angle.' }], whatToExpect: 'A classic tree-lined parkland course with Golden Age Flynn design principles — strategic angles off the tee and well-defended green complexes demanding precise iron play. The Arthur Hills renovation preserved Flynn\\\'s intent while modernizing playability.\n\nStrictly private — one of the most prolific USGA championship host sites in the mid-Atlantic region.', playingTips: 'Flynn greens reward shots approaching from the correct angle. Study pin positions carefully.\n\nCourse management and accuracy off the tee are more valuable than length on this classic parkland layout.\n\nThe green contours funnel balls away from tucked pins — favor the center of greens.', faqs: [{ question: 'What USGA events has it hosted?', answer: '2020 U.S. Women\\\'s Amateur, 40+ U.S. Open Final Qualifyings since 1986, selected for 2025-26 U.S. Adaptive Opens and 2028 U.S. Junior Amateur.' }, { question: 'Who designed it?', answer: 'William Flynn (1927), later renovated by Arthur Hills. Flynn also designed Shinnecock Hills and Merion.' }]},
    { id: 'dc-8', name: 'Renditions Golf Course', slug: 'renditions-golf-course', city: 'Davidsonville', state: 'Maryland', type: 'public', rating: 4.1, greensFee: '$45–$85', architect: 'Lester George', yearBuilt: 1999, holes: 18, par: 71, yardage: 7044, description: 'A unique concept course near Annapolis where each hole is a recreation of a famous major championship hole, from Augusta\'s 12th to St. Andrews\' Road Hole. Renditions offers golf fans a chance to play some of the world\'s most iconic holes in a single round.', highlights: ['18 recreations of famous major championship holes', 'Unique concept course near Annapolis', 'Play Augusta, St. Andrews, and more in one round'], imageAlt: 'Renditions Golf Course replica hole near Annapolis Maryland', history: 'Renditions opened in 1999 near Annapolis, designed by Lester George and Dave Edsall on a unique concept: every one of its 18 holes is a replica of a famous hole from a major championship venue. It bills itself as a "Grand Slam Golf Experience," drawing from Masters, U.S. Open, Open Championship, and PGA Championship courses.\n\nRecognized on GolfPass\\\'s "America\\\'s 10 Best Replica Courses." The opening holes replicate U.S. Open and PGA venues, then shift to Open Championship links-style, then into Augusta-inspired stretches including all three Amen Corner holes.', signatureHoles: [{ hole: 7, par: 3, yardage: 155, description: 'A replica of Augusta National\\\'s famous 12th hole (Golden Bell) — the centerpiece of the recreated Amen Corner stretch (holes 6-8). The par 3 over water captures the beauty and tension of the original.' }, { hole: 13, par: 3, yardage: 135, description: 'A replica of TPC Sawgrass\\\'s iconic 17th hole island green. The island putting surface recreates the most famous par 3 in modern golf — nerve-wracking regardless of how many times you\\\'ve seen it on TV.' }], whatToExpect: 'The course shifts styles dramatically — parkland replicas from U.S. Open venues, links-style holes inspired by Open Championship courses, and Augusta\\\'s azalea-lined corridors including all three Amen Corner holes. Each hole features a historical write-up explaining the original.\n\nThe terrain and landscaping are interpretations adapted to Maryland, but strategic elements and visual character are faithfully recreated.\n\nPublic access at $45-85 near Annapolis — a unique concept experience.', playingTips: 'Treat each hole on its own terms. The course shifts styles dramatically from parkland to links to Augusta corridors.\n\nThe island green (hole 13, TPC Sawgrass replica) plays about the same yardage as the original. Take enough club and aim center.\n\nWind affects the open links-style holes significantly. Adjust club selection.\n\nRead the historical write-ups at each tee — they enhance the experience.', faqs: [{ question: 'Which famous holes are replicated?', answer: 'All three Amen Corner holes (Augusta 11, 12, 13), TPC Sawgrass 17th island green, St. Andrews Road Hole, and replicas from Brookline, Inverness, and other major championship venues.' }, { question: 'Is it a gimmick?', answer: 'The concept is fun but the golf is legitimate. GolfPass named it one of America\\\'s 10 Best Replica Courses. The strategic elements are faithfully recreated.' }, { question: 'Is it open to the public?', answer: 'Yes — public access at $45-85 near Annapolis. About 20 minutes from the city center.' }]},
    { id: 'dc-9', name: 'Whiskey Creek Golf Club', slug: 'whiskey-creek-golf-club', city: 'Ijamsville', state: 'Maryland', type: 'public', rating: 4.3, greensFee: '$50–$95', architect: 'J. Michael Poellot', yearBuilt: 2000, holes: 18, par: 72, yardage: 7001, description: 'A Poellot design in Frederick County northwest of DC, Whiskey Creek has earned multiple best-in-state public course honors. The layout through rolling Maryland farmland and mature hardwoods features natural stone walls, creek crossings, and views of the Catoctin Mountains that evoke classic mid-Atlantic parkland golf.', highlights: ['Multiple best-in-state public course honors', 'Natural stone walls and creek crossings', 'Catoctin Mountain views through Maryland farmland'], imageAlt: 'Whiskey Creek Golf Club fairway with Catoctin Mountain views in Frederick County', history: 'Whiskey Creek opened in 2000, designed by J. Michael Poellot with Ernie Els as consultant, in Frederick County northwest of D.C. The property features rolling Maryland farmland, mature hardwoods, natural stone walls, and creek crossings with Catoctin Mountain views.\n\nMultiple best-in-state public course honors from Golf Digest, Golf Magazine, and Golfweek. The stone ruins on the 18th fairway are original to the property — one of the most unique finishing holes in public golf.', signatureHoles: [{ hole: 18, par: 5, yardage: 540, description: 'Old stone house ruins sit in the middle of the fairway — a truly remarkable closer that demands strategy around the historic ruins while providing an unforgettable visual.' }], whatToExpect: 'Dramatically varied terrain where every hole demands a different shot. Elevation changes are the primary challenge. The setting feels private despite being fully public.\n\nManaged by KemperSports at $50-95.', playingTips: 'Elevation changes are extreme — factor significant yardage adjustments. This is a thinker\\\'s course where club selection matters more than distance.', faqs: [{ question: 'What are the ruins on 18?', answer: 'Original stone house ruins incorporated into the fairway design — one of the most unique finishing holes in American public golf.' }]},
    { id: 'dc-10', name: 'Woodmont Country Club - North', slug: 'woodmont-cc-north', city: 'Rockville', state: 'Maryland', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'William Flynn', yearBuilt: 1928, holes: 18, par: 72, yardage: 6882, description: 'A William Flynn design in Rockville, Woodmont North is one of the finest private courses in the greater Washington DC area. Flynn\'s Golden Age architecture features his trademark strategic bunkering, undulating greens, and naturalistic design through mature parkland that has hosted USGA and PGA events.', highlights: ['William Flynn Golden Age design from 1928', 'Host of USGA and PGA events', 'One of DC area\'s finest private clubs'], imageAlt: 'Woodmont Country Club North Course William Flynn parkland fairway in Rockville', history: 'Woodmont Country Club\\\'s North Course was designed by William Flynn and opened in 1928 in Rockville, Maryland. Flynn — architect of Shinnecock Hills and Merion — created Golden Age architecture with trademark strategic bunkering, undulating greens, and naturalistic design through mature parkland.\n\nThe club has hosted the U.S. Women\\\'s Amateur, over 40 U.S. Open Final Qualifyings, and is selected for the 2028 U.S. Junior Amateur. One of the most prolific USGA host sites in the mid-Atlantic.', signatureHoles: [{ hole: 9, par: 4, yardage: 415, description: 'A classic Flynn par 4 with strategic bunkering defining the ideal approach angle. The mature parkland setting and Golden Age green complex reward precise positioning.' }], whatToExpect: 'Golden Age Flynn architecture with strategic bunkering, undulating greens, and naturalistic parkland design. One of the finest private courses in the greater Washington D.C. area.\n\nStrictly private — extraordinary USGA championship hosting pedigree.', playingTips: 'Flynn\\\'s greens reward specific approach angles. Study the bunkering — it defines the ideal line of play.\n\nAccuracy off the tee matters far more than distance through the mature tree corridors.', faqs: [{ question: 'Who designed it?', answer: 'William Flynn (1928), architect of Shinnecock Hills and Merion. Later renovated by Arthur Hills.' }]},
    { id: 'dc-11', name: 'Raspberry Falls Golf & Hunt Club', slug: 'raspberry-falls-golf', city: 'Leesburg', state: 'Virginia', type: 'public', rating: 4.2, greensFee: '$45–$85', architect: 'Gary Player', yearBuilt: 1996, holes: 18, par: 72, yardage: 7191, description: 'A Gary Player signature design in Loudoun County Virginia, Raspberry Falls features a dramatic layout through rolling horse-country terrain with Blue Ridge Mountain views. The 7,191-yard course winds through a historic estate property with mature trees, stone walls, and a distinctly Virginia countryside atmosphere.', highlights: ['Gary Player signature design in Virginia horse country', 'Blue Ridge Mountain views from rolling terrain', 'Historic estate property with stone walls'], imageAlt: 'Raspberry Falls Golf Club Gary Player fairway through Virginia horse country', history: 'Raspberry Falls is Virginia\\\'s only Gary Player Signature Design course, opened in 1996 in Loudoun County horse country north of Leesburg. Located on rolling terrain with Blue Ridge Mountain views, the course earned 4 stars from Golf Digest.\n\nA recent renovation added revetted, pot-style bunkers reminiscent of Scottish links, giving the layout a unique blend of Virginia parkland and links character. Natural water hazards come into play on seven holes.', signatureHoles: [{ hole: 3, par: 4, yardage: 479, description: 'A long par 4 with significant elevation change — a true Gary Player design test. The rolling Virginia horse country terrain creates a demanding tee shot and approach on one of the course\\\'s most challenging holes.' }], whatToExpect: 'Rolling terrain with considerable elevation changes across open, non-parallel fairways. The revetted pot-style bunkers add a links feel to the Virginia parkland setting. Pastoral scenery throughout — horse farms and Blue Ridge Mountain ridgelines frame the round.\n\nWater hazards on seven holes. The open terrain means wind can be a significant factor on exposed hillside holes.\n\nPublic access at $45-85 — strong value for the only Gary Player Signature course in the Mid-Atlantic.', playingTips: 'Water hazards on nearly half the holes punish wayward drives. Bring extra balls.\n\nThe open terrain exposes shots to wind — club selection on elevated par 3s is critical.\n\nThe revetted bunkers play differently than standard American bunkers. Expect steeper faces requiring more loft to escape.', faqs: [{ question: 'Is this really the only Gary Player course in the area?', answer: 'Yes — the only Gary Player Signature Design course in the entire Mid-Atlantic region.' }, { question: 'What are the revetted bunkers?', answer: 'A recent renovation added Scottish links-style pot bunkers with stacked sod faces — unusual for a Virginia course and adding a distinctive character.' }]},
  ],
  'san-antonio-texas': [
    { id: 'sa-1', name: 'TPC San Antonio - Oaks Course', slug: 'tpc-san-antonio-oaks', city: 'San Antonio', state: 'Texas', type: 'resort', rating: 4.6, greensFee: '$125–$250', architect: 'Greg Norman', yearBuilt: 2010, holes: 18, par: 72, yardage: 7435, description: 'Host of the Valero Texas Open on the PGA Tour, TPC San Antonio\'s Oaks Course is a Greg Norman design at the JW Marriott Hill Country Resort. The championship layout stretches through rolling Texas Hill Country terrain with live oaks, native grasses, and panoramic vistas.', highlights: ['PGA Tour Valero Texas Open host', 'Greg Norman championship design', 'JW Marriott Hill Country resort setting'], imageAlt: 'TPC San Antonio Oaks Course championship fairway in Texas Hill Country', history: 'TPC San Antonio\\\'s Oaks Course opened in 2010, co-designed by Greg Norman with player consultant Sergio Garcia, at the JW Marriott San Antonio Hill Country Resort. The course has hosted the PGA Tour\\\'s Valero Texas Open annually since opening — one of the oldest events on Tour.\n\nThe Norman design departs from modern manicured tournament style, incorporating the natural scrubby Texas landscape with native grasses and rugged Hill Country terrain. Conditions are maintained to PGA Tour standards. The Valero Texas Open is extended through future seasons.', signatureHoles: [{ hole: 13, par: 5, yardage: 560, description: 'An island-style par 5 with dramatic risk-reward options. The aggressive line brings water into play on the second shot for those going for the green in two.' }, { hole: 18, par: 4, yardage: 460, description: 'A punishing par 4 closer that has produced memorable Valero Texas Open moments. Part of a demanding 17-18 finishing stretch of back-to-back par 4s.' }], whatToExpect: 'A championship layout at 7,438 yards playing through dry Texas Hill Country terrain with native grasses and rugged, scrubby landscape. The course plays firm and fast. Wind is a constant factor on the exposed layout.\n\nPGA Tour-standard conditioning throughout. The JW Marriott resort provides full amenities. Resort guest and public access at $125-250.\n\nSergio Garcia\\\'s involvement brought a player\\\'s perspective to the strategic shot values.', playingTips: 'Wind is constant on the exposed Hill Country terrain. Factor it into every club selection.\n\nThe native areas flanking fairways are penal. Course management off the tee is essential — missing fairways costs strokes.\n\nThe closing holes demand precision under pressure. Save your best golf for 17-18.\n\nFirm, fast conditions mean the ball runs. Plan for extra roll on approaches.', faqs: [{ question: 'Does the PGA Tour play here?', answer: 'Yes — the Valero Texas Open has been held annually since the course opened in 2010. One of the oldest events on the PGA Tour.' }, { question: 'Who designed it?', answer: 'Greg Norman with player consultant Sergio Garcia. The design incorporates natural Texas Hill Country terrain rather than a manicured tournament style.' }, { question: 'Is it open to the public?', answer: 'Yes — resort guest and public access at $125-250. Part of the JW Marriott San Antonio Hill Country Resort.' }]},
    { id: 'sa-2', name: 'The Quarry Golf Club', slug: 'the-quarry-san-antonio', city: 'San Antonio', state: 'Texas', type: 'public', rating: 4.3, greensFee: '$45–$90', architect: 'Keith Foster', yearBuilt: 1993, holes: 18, par: 71, yardage: 6740, description: 'Built in an abandoned cement quarry, The Quarry is one of the most visually dramatic public courses in Texas. The back nine descends 100 feet into the quarry floor, surrounded by towering 200-foot limestone walls that create a one-of-a-kind golfing amphitheater.', highlights: ['Built in a 100-foot-deep abandoned quarry', '200-foot limestone walls surround back nine', 'One of the most unique settings in American golf'], imageAlt: 'The Quarry Golf Club San Antonio back nine surrounded by limestone quarry walls', history: 'The Quarry Golf Club opened in 1993-94, designed by Keith Foster on the site of an abandoned Alamo Cement Company limestone quarry that operated for decades before closing in 1983. Within a decade, Foster transformed the industrial relic into one of San Antonio\\\'s most celebrated courses — consistently rated the best public course in the city.\n\nThe back nine descends into the quarry itself, surrounded by massive limestone walls up to 200 feet high with a central lake. The front nine plays as a contrasting links-style layout above ground.', signatureHoles: [{ hole: 13, par: 4, yardage: 323, description: '"Escape from Alcatraz" — a horseshoe dogleg left with sheer limestone cliffs running from tee to green. The fairway wraps around the quarry lake, demanding an accurate tee shot to clear the water and avoid the cliff face. Honored specifically by Golf Digest.' }], whatToExpect: 'Two distinct experiences in one round. The front nine plays as a links-style layout with deep bunkers, sloping greens, and open terrain. The back nine drops into the quarry — surrounded by 200-foot limestone walls, a central lake, and dramatic elevation changes creating a completely different visual atmosphere.\n\nThe quarry walls create an amphitheater effect making the back nine feel like playing inside a geological monument. Par 71, approximately 6,740 yards.\n\nPublic access at $45-90 — one of the most visually unique courses in American golf.', playingTips: 'Wind swirls unpredictably inside the quarry walls on the back nine — even when the flag appears still, wind catches your ball at its apex.\n\nAvoid the bunkers at all costs on the back nine. Precision ball placement matters more than distance inside the quarry.\n\nThe front nine rewards aggressive play; the back nine demands accuracy. Adjust your strategy at the turn.\n\nThe quarry amphitheater is spectacular — enjoy it but stay focused on the golf.', faqs: [{ question: 'Is it really built in a quarry?', answer: 'Yes — an abandoned Alamo Cement Company limestone quarry. The back nine plays inside the quarry surrounded by 200-foot limestone walls with a central lake.' }, { question: 'What is Escape from Alcatraz?', answer: 'Hole 13 — a 323-yard horseshoe dogleg with sheer limestone cliffs from tee to green wrapping around the quarry lake. Honored by Golf Digest.' }, { question: 'How different are the two nines?', answer: 'Completely different experiences. The front nine is links-style above ground; the back nine descends into the quarry amphitheater. Like playing two different courses.' }]},
    { id: 'sa-3', name: 'Briggs Ranch Golf Club', slug: 'briggs-ranch-golf-club', city: 'San Antonio', state: 'Texas', type: 'public', rating: 4.4, greensFee: '$60–$110', architect: 'Tom Lehman & Gary Stephenson', yearBuilt: 2003, holes: 18, par: 72, yardage: 7259, description: 'A Tom Lehman design south of San Antonio, Briggs Ranch emulates the rugged ranch lands of South Texas with native mesquite, dramatic bunkering, and a links-inspired layout. The championship course has hosted numerous state and regional tournaments.', highlights: ['Tom Lehman championship design', 'Links-inspired South Texas ranch setting', 'Host of state and regional tournaments'], imageAlt: 'Briggs Ranch Golf Club links-style fairway in South Texas ranch country', history: 'Briggs Ranch Golf Club was designed by Tom Fazio and opened in 2001 about 20 miles west of downtown San Antonio through rugged South Texas ranchland. The owners\\\'s stated goal was to create 18 signature holes. The Dormie Network acquired the club in 2017.\n\nFazio shaped the course through native mesquite with dramatic bunkering and a links-inspired feel despite the inland Hill Country setting. Greens were recently refurbished with TifEagle bermuda; fairways, tees, and rough are Zoysia grass. Ranked among the top residential courses in the U.S. by Golfweek.', signatureHoles: [{ hole: 15, par: 3, yardage: 206, description: 'Earned a Grade "A" from Golf Today for its architecture — gives nothing away and demands a pure, well-struck shot. A demanding one-shotter that exemplifies the goal of creating 18 signature holes.' }], whatToExpect: 'A private Dormie Network experience through rugged South Texas ranchland. Fazio\\\'s dramatic bunkering and links-inspired design create strategic decisions on every hole. The Zoysia turf plays firm — expect the ball to run.\n\nThe experience is intentionally understated and focused on the course itself. The native mesquite and open ranch terrain provide a wild, natural setting.\n\nPrivate — Dormie Network members and guests only.', playingTips: 'Zoysia turf plays firm — expect extra ball roll throughout. Plan approaches accordingly.\n\nThe dramatic bunkering is both beautiful and penal. Course management around green complexes is essential.\n\nWind on the open ranch terrain is a regular factor. Adjust club selection on every exposed shot.', faqs: [{ question: 'Who designed Briggs Ranch?', answer: 'Tom Fazio, opening in 2001. The Dormie Network acquired the club in 2017.' }, { question: 'Is it open to the public?', answer: 'No — private Dormie Network club. Members and guests only.' }, { question: 'How is it ranked?', answer: 'Among the top residential courses in the U.S. by Golfweek. Greens recently refurbished with TifEagle bermuda.' }]},
    { id: 'sa-4', name: 'La Cantera Golf Club - Palmer Course', slug: 'la-cantera-palmer', city: 'San Antonio', state: 'Texas', type: 'resort', rating: 4.3, greensFee: '$70–$140', architect: 'Arnold Palmer & Tom Lehman', yearBuilt: 2020, holes: 18, par: 72, yardage: 7102, description: 'The reimagined Palmer Course at La Cantera sits atop one of the highest points in San Antonio with sweeping Hill Country views. Arnold Palmer\'s design philosophy of playability and visual drama is evident in the wide fairways, bold bunkering, and scenic vistas stretching for miles.', highlights: ['Arnold Palmer design atop San Antonio high point', 'Sweeping Hill Country panoramic views', 'La Cantera resort complex setting'], imageAlt: 'La Cantera Palmer Course elevated fairway with San Antonio Hill Country views', history: 'The Palmer Course at La Cantera was designed by Arnold Palmer and opened in March 2001 on 225 acres of rugged Texas Hill Country terrain at one of the highest points in San Antonio. The course featured dramatic waterfalls, sweeping panoramic views of both the Hill Country and downtown San Antonio, and played 6-8 strokes harder than the neighboring Resort Course.\n\nThe Palmer Course closed in December 2021 amid redevelopment plans. The La Cantera Resort Course (designed by Jay Morrish and Tom Weiskopf) remains open and operating, managed by Troon Golf at the Signia by Hilton San Antonio.\n\nNote: The Palmer Course is currently closed. Visitors seeking the La Cantera experience should book the Resort Course.', signatureHoles: [{ hole: 7, par: 4, yardage: 420, description: 'One of the dramatic Hill Country holes featuring waterfall features and panoramic views stretching for miles. The elevated routing at one of San Antonio\\\'s highest points created some of the most scenic golf in the city. (Note: Palmer Course currently closed.)' }], whatToExpect: 'Note: The Palmer Course closed in December 2021. The neighboring La Cantera Resort Course (Morrish/Weiskopf design) remains open at the Signia by Hilton, offering Hill Country views and a resort-friendly championship experience managed by Troon Golf.\n\nThe Resort Course plays at a more accessible difficulty level than the former Palmer Course and provides sweeping Hill Country vistas from the elevated terrain.', playingTips: 'For the open Resort Course: Hill Country terrain creates uneven lies and elevation changes throughout. Wind is common on the exposed hilltop routing.\n\nThe resort-friendly layout is more accessible than the former Palmer Course but still offers challenges for skilled players.', faqs: [{ question: 'Is the Palmer Course open?', answer: 'No — the Palmer Course closed in December 2021. The La Cantera Resort Course (Morrish/Weiskopf design) remains open and operating.' }, { question: 'What is still available at La Cantera?', answer: 'The Resort Course, managed by Troon Golf at the Signia by Hilton San Antonio. An 18-hole championship course with Hill Country views.' }]},
    { id: 'sa-5', name: 'San Antonio Country Club', slug: 'san-antonio-country-club', city: 'San Antonio', state: 'Texas', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'A.W. Tillinghast', yearBuilt: 1907, holes: 18, par: 71, yardage: 6848, description: 'The oldest private club in San Antonio, SACC features a classic A.W. Tillinghast design that has been meticulously maintained for over a century. The parkland layout along the banks of the San Antonio River features Tillinghast\'s trademark bunkering and challenging par 3s.', highlights: ['A.W. Tillinghast historic design', 'Oldest private club in San Antonio', 'San Antonio River parkland setting'], imageAlt: 'San Antonio Country Club Tillinghast fairway along the San Antonio River', history: 'San Antonio Country Club was established circa 1904 by nine prominent businessmen, making it one of the oldest private clubs in Texas. A.W. Tillinghast designed the 18-hole layout along the San Antonio River in the Alamo Heights area.\n\nA notable restoration using 1930s aerial photographs recreated Tillinghast\\\'s original design, including his characteristic rectangular greens. The routing features template holes modeled after North Berwick\\\'s Redan and Prestwick\\\'s Alps — classic links concepts adapted to the Texas parkland setting.\n\nTillinghast also designed nearby Brackenridge Park (1916) and Oak Hills CC, giving San Antonio a rare trio of Tillinghast designs.', signatureHoles: [{ hole: 7, par: 3, yardage: 195, description: 'A restored Redan-style hole modeled after the 15th at North Berwick — one of the most photographed holes on the course. Tillinghast\\\'s classic template adapted to the San Antonio River setting.' }], whatToExpect: 'A par-71 classic Tillinghast design at approximately 7,246 yards. Narrow, tree-lined fairways with flat-bottomed rectangular greens — a Tillinghast hallmark. The San Antonio River winds through the property adding both beauty and hazard. Twisted live oaks dominate the landscape.\n\nThe restoration to Tillinghast\\\'s original intent makes this one of the most authentic Golden Age experiences in Texas.\n\nStrictly private — invitation or member sponsorship required.', playingTips: 'The tight, tree-lined holes demand club selection over power. The restored rectangular greens require precise approach angles.\n\nTillinghast\\\'s template holes (Redan, Alps) play as strategic puzzles — study the green contours before committing to your approach.\n\nThe San Antonio River creates both visual beauty and genuine hazard on several holes.', faqs: [{ question: 'Is this a real Tillinghast design?', answer: 'Yes — one of three Tillinghast designs in San Antonio (along with Brackenridge Park and Oak Hills). A restoration using 1930s aerials recreated his original vision.' }, { question: 'How old is it?', answer: 'Established circa 1904 — one of the oldest private clubs in Texas.' }]},
    { id: 'sa-6', name: 'The Club at Sonterra - Canyon', slug: 'sonterra-canyon', city: 'San Antonio', state: 'Texas', type: 'semi-private', rating: 4.2, greensFee: '$60–$100', architect: 'Robert von Hagge & Bruce Devlin', yearBuilt: 1997, holes: 18, par: 72, yardage: 6979, description: 'Located in the Stone Oak area of north San Antonio, Sonterra\'s Canyon Course winds through rugged Hill Country terrain with dramatic canyon carries and mature live oaks. The von Hagge-Devlin design offers strategic challenge with scenic Hill Country beauty.', highlights: ['Dramatic canyon carries over Hill Country terrain', 'Robert von Hagge and Bruce Devlin design', 'Scenic Stone Oak area setting'], imageAlt: 'Sonterra Canyon Course fairway through Hill Country canyon in north San Antonio', history: 'The Club at Sonterra features two 18-hole championship courses designed by Bruce Devlin and Robert von Hagge in the Stone Oak area of north San Antonio. The Canyon Course integrates dramatic Hill Country canyon terrain with natural limestone outcroppings and significant elevation changes.\n\nThe club is considered the premier country club in the Stone Oak area, offering golf, tennis, fitness, and family amenities across 36 holes with contrasting styles — the North Course is more target-oriented with forced carries, while the Canyon/South Course is more naturalistic.', signatureHoles: [{ hole: 12, par: 4, yardage: 420, description: 'A canyon-influenced hole featuring dramatic elevation change and natural limestone outcroppings. The Hill Country terrain creates a visually stunning and strategically demanding par 4.' }], whatToExpect: 'The Canyon Course winds through Hill Country terrain with dramatic elevation changes, canyon carries, and mature live oaks. The contrasting North Course demands accuracy with forced carries over native terrain.\n\n36 holes total provide variety across the Stone Oak community. Well-conditioned fairways and greens with natural Hill Country beauty.\n\nSemi-private with some reciprocal access at $60-100.', playingTips: 'On the Canyon Course, respect the elevation changes — club selection on hillside holes is tricky.\n\nWind on the exposed ridgeline holes can shift club selection significantly.\n\nThe North Course demands carry distance off the tee due to forced carries. Know your distances.', faqs: [{ question: 'How many courses?', answer: 'Two 18-hole courses — the Canyon/South (naturalistic Hill Country terrain) and the North (more target-oriented with forced carries). 36 holes total.' }, { question: 'Who designed them?', answer: 'Bruce Devlin and Robert von Hagge. Both courses sit in the Stone Oak area of north San Antonio.' }]},
    { id: 'sa-7', name: 'Brackenridge Park Golf Course', slug: 'brackenridge-park-golf', city: 'San Antonio', state: 'Texas', type: 'public', rating: 4.0, greensFee: '$20–$40', architect: 'A.W. Tillinghast', yearBuilt: 1916, holes: 18, par: 72, yardage: 6185, description: 'The first public golf course in Texas, Brackenridge Park is an A.W. Tillinghast design along the San Antonio River. This historic municipal course hosted the 1922 Texas Open — the first PGA Tour event played in Texas — and remains a beloved and accessible civic treasure.', highlights: ['First public golf course in Texas', 'A.W. Tillinghast 1916 design', 'Hosted first PGA Tour event in Texas in 1922'], imageAlt: 'Brackenridge Park Golf Course historic Tillinghast layout along San Antonio River', history: 'Brackenridge Park is the oldest 18-hole public golf course in Texas, designed by A.W. Tillinghast and opened in 1916 along the San Antonio River. In 1922, it hosted the inaugural Texas Open — the first PGA Tour event played in Texas — offering a then-remarkable $5,000 first prize. Tommy Armour won that historic event.\n\nThe Texas Open remained at Brackenridge for most years between 1922 and 1959. The Valero Texas Open (still played annually in San Antonio) traces its lineage directly to this course. A restoration returned several holes to Tillinghast\\\'s original design, including reopening riverbed meanders.', signatureHoles: [{ hole: 10, par: 3, yardage: 196, description: 'A par 3 guarded by water and bunkers with a sloped green — reportedly one of Ben Crenshaw\\\'s favorite holes growing up. The combination of water, sand, and Tillinghast\\\'s green contours creates a demanding one-shotter.' }, { hole: 7, par: 4, yardage: 380, description: 'A famously difficult, narrow hole demanding precise tee-shot placement through tight tree corridors. Accuracy is everything on this classic Tillinghast par 4.' }], whatToExpect: 'A short but strategic municipal course where every hole is memorable. The San Antonio River runs through the property with mature trees lining tight fairways. Lacks length but demands accuracy and creativity — a thinking player\\\'s course.\n\nRestored Tillinghast features (rectangular greens, original routing) add genuine historical character. A plaque commemorating the birthplace of the Texas Open stands on the property.\n\nMunicipal pricing at $20-40 — historic Tillinghast golf accessible to everyone.', playingTips: 'Fairway accuracy is essential — the course is notably narrow with adjacent fairways running close together.\n\nGreens are small and require precise approaches. Bring your shot-shaping game rather than distance.\n\nThe river and trees create tight corridors. Accept that driver isn\\\'t always the right play.', faqs: [{ question: 'Is this really the first public course in Texas?', answer: 'Yes — the oldest 18-hole public golf course in Texas, opened in 1916. Designed by A.W. Tillinghast.' }, { question: 'What is the Texas Open connection?', answer: 'Brackenridge hosted the inaugural Texas Open in 1922 — the first PGA Tour event ever played in Texas. The Valero Texas Open traces its lineage directly here.' }, { question: 'How affordable is it?', answer: 'Municipal pricing at $20-40. Historic Tillinghast golf accessible to everyone.' }]},
    { id: 'sa-8', name: 'Boot Ranch', slug: 'boot-ranch-golf-club', city: 'Fredericksburg', state: 'Texas', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Hal Sutton', yearBuilt: 2002, holes: 18, par: 72, yardage: 7179, description: 'A Hal Sutton design in the heart of Texas Hill Country near Fredericksburg, Boot Ranch is an exclusive residential golf community with sweeping views of the Pedernales Valley. The challenging layout winds through native grasslands, live oaks, and natural limestone outcroppings.', highlights: ['Hal Sutton design in Hill Country heartland', 'Sweeping Pedernales Valley views', 'Exclusive residential golf community'], imageAlt: 'Boot Ranch fairway with Pedernales Valley views in Texas Hill Country', history: 'Boot Ranch was designed by PGA legend Hal Sutton (with Jim Lipe) and opened in 2006 north of Fredericksburg in the Texas Hill Country. Sutton carved a par-72 layout measuring 7,155 yards through the property\\\'s ridges, canyons, and Palo Alto Creek.\n\nThe course is the centerpiece of an exclusive residential community, ranked among the top residential courses in the country. Sutton himself said "you can learn everything about the game at Boot Ranch." The back nine (especially holes 13-18) is considered among the finest consecutive-hole stretches in Texas.', signatureHoles: [{ hole: 10, par: 4, yardage: 364, description: 'The standout hole — a late dogleg right split by a creek with Roos Falls, creating a jaw-dropping visual and strategic challenge. The waterfall adds dramatic beauty to a genuinely demanding par 4.' }], whatToExpect: 'Firm, fast greens on a layout following natural Hill Country terrain. Many elevated tees provide sweeping Pedernales Valley views. The back nine is notably stronger than the front. The course demands finesse and accuracy over distance.\n\nSmooth elevation changes, demanding bunkers, and large undulating greens. Bump-and-run shots around the greens are effective on the firm turf.\n\nPrivate — membership or member invitation required. Fredericksburg\\\'s wineries and German heritage dining are nearby.', playingTips: 'This is an accuracy-over-distance layout. The ridges and canyons reward precision and punish wayward shots.\n\nFirm, fast conditions mean bump-and-run approaches are effective. Don\\\'t automatically reach for the lob wedge.\n\nFrom elevated tees, the ball flies and rolls further than expected. Club down accordingly.\n\nSutton also designed a 34-acre short-course practice facility — use it to warm up.', faqs: [{ question: 'Who designed Boot Ranch?', answer: 'Hal Sutton (with Jim Lipe), opening in 2006. Sutton said "you can learn everything about the game at Boot Ranch."' }, { question: 'Where is Fredericksburg?', answer: 'In the heart of Texas Hill Country, about 75 miles west of Austin and 70 miles northwest of San Antonio. Known for German heritage, wineries, and dining.' }, { question: 'Can the public play?', answer: 'No — private residential community. Membership or member invitation required.' }]},
  ],
  'hawaii-hawaii': [
    { id: 'hi-1', name: 'Kapalua Plantation Course', slug: 'kapalua-plantation', city: 'Lahaina', state: 'Hawaii', type: 'resort', rating: 4.8, greensFee: '$250–$400', architect: 'Bill Coore & Ben Crenshaw', yearBuilt: 1991, holes: 18, par: 73, yardage: 7596, description: 'Host of the PGA Tour\'s Sentry Tournament of Champions, Kapalua Plantation is a Coore & Crenshaw design cascading down the slopes of the West Maui Mountains toward the Pacific Ocean. The dramatic elevation drops, sweeping ocean views, and wide fairways create one of the most exhilarating rounds in golf.', highlights: ['PGA Tour Sentry Tournament of Champions host', 'Dramatic West Maui Mountain-to-ocean elevation drops', 'Coore & Crenshaw design with sweeping Pacific views'], imageAlt: 'Kapalua Plantation Course cascading toward the Pacific Ocean on Maui', history: 'Kapalua Plantation Course was the first collaboration between Bill Coore and Ben Crenshaw, opening in 1991 on the slopes of the West Maui Mountains. The par-73, 7,596-yard layout cascades downhill toward the Pacific with enormous elevation drops and views of Molokai and Lanai.\n\nThe course has hosted the PGA Tour\'s season-opening event since 1999, currently The Sentry. The wide fairways and dramatic terrain produce some of the lowest scores on Tour. The 663-yard downhill 18th is one of the most spectacular finishing holes in professional golf.', signatureHoles: [{ hole: 18, par: 5, yardage: 663, description: 'One of the most spectacular finishing holes in golf. This massive downhill par 5 cascades toward the Pacific with views of Molokai. Tour pros regularly reach the green in two.' }, { hole: 5, par: 5, yardage: 526, description: 'A cape-style par 5 wrapping around a deep jungle ravine. Wide fairway with multiple strategic options and stunning coastal views on the approach.' }, { hole: 1, par: 4, yardage: 520, description: 'One of the most intimidating openers on Tour at 520 yards, playing slightly downhill but demanding a powerful, accurate drive.' }, { hole: 8, par: 4, yardage: 385, description: 'A shorter par 4 playing steeply downhill with the ocean as backdrop. Dramatic elevation change makes club selection critical.' }], whatToExpect: 'Kapalua Plantation cascades down the West Maui Mountains with sweeping Pacific views, neighboring island vistas, and lush tropical vegetation. Wide fairways are forgiving off the tee, but severe elevation changes and persistent trade winds of 15-25 mph make distance control the primary challenge.\n\nThe par-73 layout at 7,596 yards is one of the longest on Tour, but downhill holes play much shorter than the card distance.', playingTips: 'Downhill holes play significantly shorter than yardage indicates, so adjust club selection. Trade winds can add or subtract two clubs on approaches. Wide fairways are forgiving, so swing aggressively off the tee. Pay close attention to green contours — many slope severely with the mountain terrain.', faqs: [{ question: 'Can the public play Kapalua Plantation?', answer: 'Yes. Green fees range from $250 to $400 depending on season. Twilight rates offer the best value.' }, { question: 'When is the PGA Tour event at Kapalua?', answer: 'The Sentry is typically held the first week of January, kicking off the PGA Tour season.' }, { question: 'How does elevation affect play?', answer: 'Dramatic elevation changes mean many holes play shorter than yardage indicates. Take less club on downhill approaches.' }, { question: 'Was the course affected by the 2023 Maui wildfires?', answer: 'The Plantation Course was not directly damaged by the August 2023 Lahaina wildfires. It has continued to operate and host the PGA Tour event.' }] },
    { id: 'hi-2', name: 'Mauna Kea Golf Course', slug: 'mauna-kea-golf-course', city: 'Kohala Coast', state: 'Hawaii', type: 'resort', rating: 4.7, greensFee: '$175–$325', architect: 'Robert Trent Jones Sr.', yearBuilt: 1964, holes: 18, par: 72, yardage: 7370, description: 'The course that started the Hawaii golf resort era, Mauna Kea was Robert Trent Jones Sr.\'s masterpiece on the Big Island\'s Kohala Coast. The iconic par-3 3rd hole over a Pacific Ocean cove is among the most photographed holes in the world, and the lava-framed layout remains a must-play.', highlights: ['RTJ Sr. masterpiece that launched Hawaii resort golf', 'Iconic par-3 3rd hole over ocean cove', 'Historic Kohala Coast lava landscape'], imageAlt: 'Mauna Kea Golf Course iconic par 3 over ocean cove on Big Island Kohala Coast', history: 'Mauna Kea Golf Course was designed by Robert Trent Jones Sr. and opened in 1964 on the Kohala Coast of Hawaii\\\'s Big Island — the course that launched the Hawaii resort golf era. Built as part of the Mauna Kea Beach Hotel development by Laurance Rockefeller.\n\nThe iconic par-3 3rd hole over a Pacific Ocean cove is among the most photographed golf holes in the world. RTJ Jr. (the original designer\\\'s son) recently completed a major renovation updating fairways, greens, and bunkers while honoring his father\\\'s original vision.\n\nEight of the original greens were perched atop hills, well-fortified by bunkers, demanding aerial approaches — a signature RTJ Sr. defensive strategy.', signatureHoles: [{ hole: 3, par: 3, yardage: 179, description: 'One of the most famous par 3s in the world — a shot over a Pacific Ocean cove filled with crashing waves and black lava rock. Plays 272 yards from the tips but 179 from the resort tees. Among the most photographed golf holes anywhere on Earth.' }, { hole: 18, par: 4, yardage: 450, description: 'A strong finishing hole with ocean views framing a stout close. Part of the dramatic Kohala Coast setting that makes Mauna Kea unforgettable.' }], whatToExpect: 'A par-72 resort course playing through lava fields, Pacific Ocean coastline, and tropical vegetation on the Big Island\\\'s Kohala Coast. Coastal breezes are constant at 10-20 mph and significantly affect play.\n\nThe renovated layout features modern conditioning while preserving RTJ Sr.\\\'s dramatic hilltop greens fortified by bunkers. The lava rough is essentially out of play — keep it on maintained turf.\n\nResort guests at Mauna Kea Beach Hotel get preferred access and rates at $175-325.', playingTips: 'On the iconic 3rd, play from the resort tees (179 yards) unless you have a reliable long-iron game in wind. The ocean cove is spectacular but the wind makes it treacherous from the tips.\n\nTake extra clubs throughout — coastal breezes of 10-20 mph affect every shot. Morning tee times often offer calmer conditions.\n\nApproach shots must be aerial — the hilltop greens are fortified by bunkers and reject ground-game approaches.\n\nThe lava is out of play. Keep it on the short grass and you\\\'ll score well.', faqs: [{ question: 'Is the 3rd hole as famous as they say?', answer: 'Yes — one of the most photographed par 3s in the world. A shot over a Pacific Ocean cove filled with crashing waves and black lava rock. Plays 179 yards from resort tees.' }, { question: 'Who designed it?', answer: 'Robert Trent Jones Sr. (1964). His son RTJ Jr. recently completed a renovation preserving the original vision. The course launched Hawaii\\\'s resort golf era.' }, { question: 'How much does wind affect play?', answer: 'Significantly. Constant coastal breezes of 10-20 mph affect every shot. Always take extra clubs. Morning rounds offer calmer conditions.' }]},
    { id: 'hi-3', name: 'Mauna Lani South Course', slug: 'mauna-lani-south', city: 'Kohala Coast', state: 'Hawaii', type: 'resort', rating: 4.6, greensFee: '$150–$295', architect: 'Robin Nelson & Rodney Wright', yearBuilt: 1981, holes: 18, par: 72, yardage: 6938, description: 'Set amid ancient lava fields on the Big Island\'s Kohala Coast, Mauna Lani South is famous for its dramatic par-3 15th hole played over the Pacific Ocean and ancient Hawaiian fishponds. The vivid contrast of emerald fairways against black lava rock creates an unforgettable visual experience.', highlights: ['Famous par-3 15th over ocean and fishponds', 'Emerald fairways through ancient lava fields', 'Kohala Coast volcanic landscape'], imageAlt: 'Mauna Lani South Course fairway through ancient black lava fields on Kohala Coast', history: 'Mauna Lani South Course was designed by Robin Nelson and Rodney Wright and opened in 1981 on the Big Island\\\'s Kohala Coast, now part of the Auberge-managed Mauna Lani resort. The entire course was built on solid pahoehoe and a\\\'a lava formations completely devoid of topsoil — all soil had to be imported.\n\nThe iconic par-3 15th over crashing Pacific waves and ancient Hawaiian fishponds is one of the most photographed holes in the world. The vivid contrast of emerald bermuda fairways against prehistoric black lava creates one of golf\\\'s most unforgettable visual experiences.', signatureHoles: [{ hole: 15, par: 3, yardage: 196, description: 'One of the most photographed holes in the world. The tee shot carries entirely over crashing Pacific waves and black lava cliffs. Ancient Hawaiian fishponds dating back centuries border the hole, adding cultural and visual drama to a spectacular par 3.' }, { hole: 13, par: 3, yardage: 175, description: 'Another oceanside par 3 that sets up the climactic coastal stretch. The building anticipation toward the famous 15th begins here.' }], whatToExpect: 'Generous fairways and wide-open views make this the more resort-friendly of Mauna Lani\\\'s two courses. The front nine plays inland through stark lava fields with mountain backdrops; the back nine builds toward the ocean climax at 15.\n\nThe natural lava rough is unforgiving — any ball leaving the fairway onto rock is gone. But the maintained corridors are generous enough for all skill levels.\n\nGolf Digest Top 75 Resort Course. The fishponds at 15 are historic Hawaiian aquaculture sites dating back centuries.', playingTips: 'Wind off the ocean intensifies on the back nine, especially at 15. Club up on the oceanfront par 3s.\n\nAfternoon trade winds are strongest — morning tee times offer calmer conditions.\n\nThe lava rough is absolute death. Keep it on the fairway at all costs, but the fairways are wide enough to accommodate most players.\n\nBring extra balls for the coastal stretch.', faqs: [{ question: 'Is the 15th hole really that dramatic?', answer: 'Yes — a tee shot carrying entirely over crashing Pacific waves and black lava cliffs to a green bordered by ancient Hawaiian fishponds. One of the most photographed holes in the world.' }, { question: 'How was the course built on lava?', answer: 'All topsoil was imported — the entire property was solid lava with zero natural soil. The emerald fairways carved through black rock create the dramatic visual contrast.' }]},
    { id: 'hi-4', name: 'Princeville Makai Golf Club', slug: 'princeville-makai', city: 'Princeville', state: 'Hawaii', type: 'resort', rating: 4.5, greensFee: '$175–$300', architect: 'Robert Trent Jones Jr.', yearBuilt: 1971, holes: 18, par: 72, yardage: 7223, description: 'Perched on dramatic sea cliffs along Kauai\'s North Shore, Princeville Makai offers some of the most breathtaking ocean views in all of golf. Robert Trent Jones Jr.\'s design features holes that play along Anini Beach, Hanalei Bay, and Bali Hai cliffs with the Na Pali Coast as a distant backdrop.', highlights: ['Dramatic Kauai North Shore sea cliff setting', 'Views of Hanalei Bay and Bali Hai', 'Robert Trent Jones Jr. oceanfront design'], imageAlt: 'Princeville Makai Golf Club sea cliff fairway on Kauai North Shore', history: 'Princeville Makai was Robert Trent Jones Jr.\\\'s very first solo design, opening in 1971 on dramatic bluffs overlooking Hanalei Bay on Kauai\\\'s North Shore. RTJ Jr. later returned to renovate his debut course, introducing Seashore Paspalum turf on all fairways and greens.\n\nSix oceanfront holes total, with the routing touching the sea cliffs twice during the round. Views of Hanalei Bay\\\'s famous pipeline surf, the Bali Hai peak, and the distant Na Pali Coast create what many consider the most scenic golf in Hawaii.', signatureHoles: [{ hole: 7, par: 4, yardage: 400, description: 'Plays along the sea cliffs with panoramic views of Hanalei Bay and the Bali Hai peak — one of the most scenic holes in all of Hawaii. The cliff-edge setting and ocean views make this an unforgettable par 4.' }, { hole: 3, par: 3, yardage: 175, description: 'A dramatic ocean-cliff par 3 with one of the most iconic tee shots on Kauai. The Pacific crashes below as you select your club.' }], whatToExpect: 'Six oceanfront holes weaving through native forests, tranquil lakes, and along coastline with Na Pali Coast views in the distance. Seashore Paspalum turf provides exceptional playing surfaces. Significant elevation changes on this bluff-top layout.\n\nKauai\\\'s North Shore gets more rain than the south side — be prepared for passing showers and softer conditions. The views of Hanalei Bay\\\'s pipeline surf from the course are world-famous.\n\nResort access at $175-300.', playingTips: 'Wind is unpredictable along the cliffs. Trust your yardage device but adjust for gusts.\n\nThe multi-level greens require precision on approach shots. Being on the wrong tier means a difficult two-putt.\n\nPlay from appropriate tees — the course has real teeth from the tips at 7,223 yards.\n\nPrepare for passing North Shore showers — they come and go quickly.', faqs: [{ question: 'Was this really RTJ Jr.\\\'s first course?', answer: 'Yes — his very first solo design, opening in 1971. He later returned to renovate it with Paspalum turf.' }, { question: 'How many holes are oceanfront?', answer: 'Six holes total touch the ocean cliffs, with views of Hanalei Bay, Bali Hai, and the Na Pali Coast throughout.' }]},
    { id: 'hi-5', name: 'Nanea Golf Club', slug: 'nanea-golf-club', city: 'Kailua-Kona', state: 'Hawaii', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'David McLay Kidd', yearBuilt: 2003, holes: 18, par: 72, yardage: 7253, description: 'An ultra-exclusive David McLay Kidd design on the Kona Coast, Nanea is consistently ranked as the best golf course in Hawaii. The minimalist layout flows over ancient lava terrain with Pacific Ocean views, volcanic mountain backdrops, and a walking-only policy that emphasizes pure golf.', highlights: ['Ranked #1 golf course in Hawaii', 'David McLay Kidd minimalist lava design', 'Ultra-exclusive walking-only club'], imageAlt: 'Nanea Golf Club minimalist fairway over Kona lava terrain with Pacific Ocean views', history: 'Nanea Golf Club was designed by David McLay Kidd (of Bandon Dunes fame) and opened in 2003 on the Kona Coast, created for founders Charles Schwab and George Roberts. Built on a thick hardened-lava mantle on the slopes of Mount Hualalai above the Pacific, it was the first course in North America to use Paspalum grass from tee to green.\n\nConsistently ranked the No. 1 course in Hawaii and approximately 59th nationally. Walking-only with mandatory caddies. Strictly private and invitation-only — among the most exclusive golf clubs in the world.', signatureHoles: [{ hole: 11, par: 4, yardage: 400, description: 'Part of the oceanfront stretch where fairways wind along black lava formations with sweeping Pacific panoramas. The course\\\'s greatness is in the cumulative routing rather than one standout hole — every hole is a signature hole.' }], whatToExpect: 'A walking-only course with British links sensibility transplanted onto Hawaiian lava fields. Wide fairways with creative bunkering, firm and fast Paspalum conditions, and ground-game options throughout. Caddies are standard.\n\nThe lava fringes every hole, creating dramatic visual contrast with the emerald turf. Pacific Ocean views and volcanic mountain backdrops are constant companions.\n\nUltra-exclusive — membership by invitation only.', playingTips: 'Walking-only in Hawaiian heat requires serious hydration preparation.\n\nFirm, fast Paspalum surfaces reward bump-and-run shots around the greens. Don\\\'t automatically reach for the lob wedge.\n\nWind is a constant factor on the Kona coast. Course management and shot shaping matter more than raw distance.\n\nEnjoy the caddie — their local knowledge is invaluable.', faqs: [{ question: 'Is Nanea really the best course in Hawaii?', answer: 'Yes — consistently ranked No. 1 in Hawaii by Golf Digest and other publications, approximately 59th nationally.' }, { question: 'Why walking-only?', answer: 'The walking-only policy with mandatory caddies reflects a British links ethos — pure golf focused on the course and the walk.' }, { question: 'Can anyone play?', answer: 'No. Membership is by invitation only — one of the most exclusive golf clubs in the world.' }]},
    { id: 'hi-6', name: 'Ko Olina Golf Club', slug: 'ko-olina-golf-club', city: 'Kapolei', state: 'Hawaii', type: 'resort', rating: 4.3, greensFee: '$175–$250', architect: 'Ted Robinson', yearBuilt: 1990, holes: 18, par: 72, yardage: 6867, description: 'A Ted Robinson design on Oahu\'s west coast, Ko Olina features his signature water features with cascading waterfalls, tranquil lakes, and lush tropical landscaping. The resort course at the Four Seasons provides an accessible yet scenic Hawaiian golf experience just 30 minutes from Waikiki.', highlights: ['Ted Robinson tropical water feature design', 'Four Seasons resort setting on Oahu', 'Accessible location near Waikiki'], imageAlt: 'Ko Olina Golf Club tropical fairway with waterfall and palm trees on Oahu', history: 'Ko Olina Golf Club was designed by Ted Robinson — renowned for his water features — and opened in 1990 on Oahu\\\'s sunny leeward (west) coast. The course is Robinson\\\'s showcase, with waterfalls, cascading streams, and shimmering lakes woven throughout the layout.\n\nAssociated with the Four Seasons Resort Oahu at Ko Olina within the upscale Ko Olina resort community (alongside Disney\\\'s Aulani and other luxury properties). Named one of Golf Digest\\\'s Top 75 Resort Courses in the U.S. Just 30 minutes from Waikiki.', signatureHoles: [{ hole: 12, par: 3, yardage: 155, description: 'Robinson\\\'s dramatic waterfall design — the tee shot plays over water to an island-like green framed by cascading falls. The signature visual of the course and one of the most photogenic par 3s in Hawaii.' }], whatToExpect: 'Rolling fairways, multi-tiered greens, and Robinson\\\'s signature water features (waterfalls and streams on the majority of holes). Large landing areas make it playable for a wide range of skill levels despite championship pedigree.\n\nAt 6,867 yards, the moderate length keeps it enjoyable rather than punishing. Oahu\\\'s leeward coast means reliably sunny, dry weather.\n\nResort access at $175-250. One of the most accessible high-quality courses on Oahu for visitors.', playingTips: 'Multi-tier greens are the main defense — being on the wrong level means a difficult two-putt. Study pin positions.\n\nWater comes into play frequently but is mostly avoidable with smart club selection.\n\nAfternoon winds pick up on the west side — morning rounds play calmer.\n\nThe leeward location means reliable sunshine even when the rest of Oahu is cloudy.', faqs: [{ question: 'Is it near Waikiki?', answer: 'About 30 minutes west of Waikiki on Oahu\\\'s leeward coast. Part of the Ko Olina resort community with the Four Seasons and Disney\\\'s Aulani.' }, { question: 'What are the water features like?', answer: 'Ted Robinson\\\'s signature — waterfalls, cascading streams, and lakes on the majority of holes. More ornamental and beautiful than most resort courses.' }]},
    { id: 'hi-7', name: 'Kukui\'ula Golf Course', slug: 'kukuiula-golf-course', city: 'Koloa', state: 'Hawaii', type: 'semi-private', rating: 4.5, greensFee: '$200–$325', architect: 'Tom Weiskopf', yearBuilt: 2007, holes: 18, par: 72, yardage: 7089, description: 'A Tom Weiskopf design on Kauai\'s sunny south shore, Kukui\'ula features a spectacular oceanfront routing through lush tropical vegetation with views of Poipu Beach and the Haupu Mountain Range. The layout includes dramatic cliff-edge holes and pristine resort conditioning.', highlights: ['Tom Weiskopf oceanfront Kauai design', 'Dramatic cliff-edge holes above the Pacific', 'Poipu Beach and Haupu Mountain views'], imageAlt: 'Kukuiula Golf Course cliff-edge fairway above Pacific Ocean on Kauai south shore', history: 'Kukui\\\'ula Golf Course was designed by Tom Weiskopf on 200 acres of Kauai\\\'s sunny south shore (a former sugar plantation) and opened around 2011 as the centerpiece of the Kukui\\\'ula luxury residential community in the Poipu area. Weiskopf considered this one of his finest designs.\n\nGolf Digest has called it one of the best courses in Hawaii. Private for members but accessible to guests staying at the Lodge at Kukui\\\'ula. The south shore is the sunniest and driest part of Kauai, making it a reliable play even when the north shore is rainy.', signatureHoles: [{ hole: 14, par: 4, yardage: 400, description: 'The quintessential Weiskopf par 4 — dramatic ocean views from an elevated cliff-edge position. The strategic design demands a thoughtful approach with the Pacific as a stunning backdrop.' }], whatToExpect: 'A spacious, tropically lush layout winding across Poipu\\\'s landscape. Wide-open fairways suit a variety of skill levels, but the course has teeth when the trade winds blow. Several holes run along or near the coastline with elevated ocean vantage points.\n\nThe south shore microclimate is the driest on Kauai — firm, fast conditions are typical. Weiskopf honored the natural landscape rather than overpowering it.\n\nSemi-private — Lodge guests can access, but book early as tee times are limited.', playingTips: 'Poipu\\\'s trade winds are a significant factor on the exposed cliff-side holes. Adjust club selection for wind on every coastal shot.\n\nWide fairways are forgiving off the tee but approach shots to well-defended greens require accuracy.\n\nSouth shore sun is intense — sun protection and hydration are essential.\n\nBook tee times early — access for non-members is limited.', faqs: [{ question: 'Can non-members play?', answer: 'Yes — guests staying at the Lodge at Kukui\\\'ula can access the course. Book early as tee times for non-members are limited.' }, { question: 'Why the south shore?', answer: 'Poipu has the driest, sunniest microclimate on Kauai. While the north shore gets frequent rain, the south shore offers reliable playing conditions year-round.' }, { question: 'Who designed it?', answer: 'Tom Weiskopf, who considered this one of his finest designs. The course opened around 2011 on a former sugar plantation.' }]},
    { id: 'hi-8', name: 'Hualalai Golf Course', slug: 'hualalai-golf-course', city: 'Kailua-Kona', state: 'Hawaii', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 1996, holes: 18, par: 72, yardage: 7117, description: 'A Jack Nicklaus design at the Four Seasons Hualalai on the Big Island\'s Kona Coast, this course hosted the Champions Tour\'s Mitsubishi Electric Championship for over two decades. The layout traverses ancient lava flows with ocean views, volcanic rock walls, and tropical vegetation.', highlights: ['Jack Nicklaus design at Four Seasons Hualalai', 'Former Champions Tour event host', 'Ancient lava flow and ocean routing'], imageAlt: 'Hualalai Golf Course Jack Nicklaus layout through lava rock at Four Seasons Kona', history: 'Hualalai Golf Course was designed by Jack Nicklaus and opened in 1996 at the Four Seasons Hualalai on the Big Island\\\'s Kona Coast. The course hosts the PGA Champions Tour\\\'s Mitsubishi Electric Championship — the senior tour\\\'s season opener — every January.\n\nSet within the dramatic lava fields of Ka\\\'upulehu, the layout traverses ancient volcanic flows with ocean views and tropical vegetation. The resort also features a second course (Ke\\\'olu by Tom Weiskopf) reserved for club members. The Nicklaus Course is accessible to Four Seasons resort guests.', signatureHoles: [{ hole: 17, par: 3, yardage: 165, description: 'The crown jewel — a short par 3 playing toward the ocean with the green encircled by black lava rock and crashing whitewater. During whale season, concentration becomes difficult. One of Hawaii\\\'s most photogenic holes.' }], whatToExpect: 'Pristine five-star conditioning throughout. Lush green fairways create striking contrast against jet-black lava rock. The course winds from the coast inland through lava fields, then returns to the ocean for the closing stretch.\n\nLava replaces traditional rough — a ball hit into lava is essentially lost. Trade winds affect every shot. The Champions Tour event brings senior legends here every January.\n\nFour Seasons resort guest access. Private for non-guests.', playingTips: 'Bring extra golf balls — lava rough means any ball off the fairway is likely gone.\n\nTrade winds affect ball flight significantly. Always account for the breeze in club selection.\n\nKeep driver in the bag on tighter holes where lava borders both sides. Accuracy over distance throughout.\n\nThe closing stretch returns to the ocean — save your best for 17 and 18.', faqs: [{ question: 'Can the public play Hualalai?', answer: 'Four Seasons resort guests have access. The course is private for non-guests.' }, { question: 'What Champions Tour event is held here?', answer: 'The Mitsubishi Electric Championship — the senior tour\\\'s season opener every January.' }, { question: 'What happens if my ball hits the lava?', answer: 'It\\\'s essentially lost. Centuries-old lava flows replace traditional rough. Bring extra balls.' }]},
  ],
  'monterey-california': [
    { id: 'mon-1', name: 'Pebble Beach Golf Links', slug: 'pebble-beach-golf-links', city: 'Pebble Beach', state: 'California', type: 'resort', rating: 5.0, greensFee: '$575–$625', architect: 'Jack Neville & Douglas Grant', yearBuilt: 1919, holes: 18, par: 72, yardage: 6828, description: 'Arguably the most famous golf course in America, Pebble Beach has hosted six U.S. Opens along the cliffs of the Monterey Peninsula. The iconic oceanfront holes from 4 through 10 and the dramatic finishing stretch at 17 and 18 deliver golf at its most spectacular and storied.', highlights: ['Six-time U.S. Open host', 'Iconic Monterey Peninsula clifftop holes', 'Most famous public-access course in the world'], imageAlt: 'Pebble Beach Golf Links iconic 7th hole along Monterey Peninsula cliffs', history: 'Pebble Beach Golf Links opened on February 22, 1919, on the stunning Monterey Peninsula coastline. The course was commissioned by Samuel F.B. Morse, who hired two accomplished amateur golfers, Jack Neville and Douglas Grant, to design the layout. Neither had any prior course-design experience, yet they routed eight holes directly along the rocky Pacific cliffs, creating one of golf\'s most breathtaking stretches. Neville later said the course was already there and all he had to do was find the holes.\n\nOver the decades, several legendary architects refined the design. H. Chandler Egan made significant changes in 1928 before the U.S. Amateur, and Jack Nicklaus redesigned the par-3 5th hole in 1998. Pebble Beach has hosted six U.S. Opens (1972, 1982, 1992, 2000, 2010, 2019), five U.S. Amateurs, a PGA Championship, and is an annual stop on the PGA Tour as host of the AT&T Pebble Beach Pro-Am. Tiger Woods\' record 15-stroke victory at the 2000 U.S. Open remains one of the most dominant performances in major championship history.\n\nThe course was designated a National Historic Landmark and continues to be the most famous public-access course in the world, welcoming resort guests who pay a premium green fee for the privilege of walking the same fairways as the game\'s greatest champions.', signatureHoles: [{ hole: 7, par: 3, yardage: 106, description: 'The shortest hole on the course and one of the most iconic par 3s in golf. This downhill shot plays to a tiny green perched on a rocky promontory jutting into Carmel Bay, fully exposed to ocean winds that can change a wedge into a mid-iron.' }, { hole: 8, par: 4, yardage: 428, description: 'One of the most visually stunning holes in golf, the approach shot must carry a massive chasm where the Pacific Ocean crashes against the cliffs below. The second shot plays across the abyss to a green set against the rocky coastline, demanding both courage and precision.' }, { hole: 17, par: 3, yardage: 208, description: 'An hourglass-shaped green perched on the edge of Stillwater Cove where Tom Watson famously chipped in from the rough to win the 1982 U.S. Open. The green is narrow and bunkered, with the Pacific Ocean threatening any shot that misses left.' }, { hole: 18, par: 5, yardage: 543, description: 'One of the greatest finishing holes in golf, this par 5 curves left along the rugged shoreline of Carmel Bay. The entire left side is ocean, and Jack Nicklaus hit the flagstick with his tee shot on this hole during the 1972 U.S. Open.' }], whatToExpect: 'Pebble Beach plays along dramatic seaside cliffs on the Monterey Peninsula with panoramic views of Carmel Bay and the Pacific Ocean. The front nine moves inland through Monterey pines before the iconic clifftop stretch begins at the 4th hole. Coastal winds are a constant factor, especially in the afternoon, and marine fog can roll in quickly. The course plays shorter than many championship venues at approximately 6,828 yards, but ocean breezes, small greens, and dramatic elevation changes more than compensate.\n\nWalking is encouraged with a caddie, and the terrain is manageable for most golfers. Expect a five-hour round given the resort pace of play. The views from holes 6 through 10 are among the most spectacular in all of golf.', playingTips: 'Wind management is the key to scoring at Pebble Beach. The ocean breeze typically picks up after noon, so morning tee times offer calmer conditions. Club selection on the clifftop holes requires constant adjustment. On the par-3 7th, trust your caddie since the tiny green demands precision rather than power.\n\nThe greens are generally small and firm, rewarding approach shots that land below the hole. Avoid being long on most holes, as the areas behind the greens often fall away sharply. On the finishing stretch, the ocean running down the left side of 18 punishes any draw, so favor the right side off the tee.', faqs: [{ question: 'Can the public play Pebble Beach Golf Links?', answer: 'Yes. Pebble Beach is a public-access resort course. Green fees are approximately $575-$625, and resort guests at Pebble Beach Resorts properties receive priority booking. Non-guests can book tee times up to 24 months in advance when staying at the resort.' }, { question: 'Is a caddie required at Pebble Beach?', answer: 'Caddies are not required but are highly recommended. A knowledgeable caddie enhances the experience significantly with local insight on wind conditions, green reads, and club selection on the coastal holes.' }, { question: 'What is the best time of year to play Pebble Beach?', answer: 'September and October typically provide the warmest and clearest conditions. Summer months can bring morning fog that usually burns off by midday. Winter rounds are possible but weather can be unpredictable.' }, { question: 'How difficult is Pebble Beach for average golfers?', answer: 'While Pebble Beach is a championship venue, it is very playable from the forward tees at under 5,200 yards. The main challenges are wind, small greens, and the mental pressure of playing alongside ocean cliffs.' }] },
    { id: 'mon-2', name: 'Spyglass Hill Golf Course', slug: 'spyglass-hill', city: 'Pebble Beach', state: 'California', type: 'resort', rating: 4.7, greensFee: '$395–$425', architect: 'Robert Trent Jones Sr.', yearBuilt: 1966, holes: 18, par: 72, yardage: 6960, description: 'Robert Trent Jones Sr.\'s Spyglass Hill begins with five stunning oceanfront holes through the sand dunes before ascending into the Del Monte Forest pines. Often considered the toughest test on the Monterey Peninsula, it combines coastal and forest golf in a single round.', highlights: ['RTJ Sr. design blending ocean and forest', 'Among the toughest courses on the Monterey Peninsula', 'AT&T Pebble Beach Pro-Am rotation course'], imageAlt: 'Spyglass Hill opening dune holes with ocean views on Monterey Peninsula', history: 'Spyglass Hill Golf Course opened in 1966 as the second resort course at Pebble Beach Resorts, designed by Robert Trent Jones Sr. The course was built to complement Pebble Beach Golf Links and was named after a lookout point in Robert Louis Stevenson\'s novel Treasure Island. Nearly every hole carries a name drawn from the classic adventure story, a tribute to Stevenson who lived briefly on the Monterey Peninsula in 1879.\n\nJones created a unique two-part design: the first five holes wind through exposed sand dunes along the Pacific coastline, reminiscent of Scottish links golf, before the course ascends into the dense Del Monte Forest of Monterey pines and cypress trees for the remaining thirteen holes. This dramatic shift in landscape is unlike anything else in American golf.\n\nSpyglass Hill joined the AT&T Pebble Beach Pro-Am rotation and has been a fixture of that event alongside Pebble Beach Golf Links and other Monterey Peninsula courses. With a course rating of 75.5 from the championship tees, it is widely considered the most difficult course in the Pro-Am rotation and one of the toughest resort courses in the country.', signatureHoles: [{ hole: 1, par: 5, yardage: 600, description: 'Named "Treasure Island," the opening par 5 plays through sand dunes toward the Pacific Ocean. One of the most dramatic opening holes in golf, it sets the tone for the oceanside stretch with sweeping coastal views.' }, { hole: 4, par: 4, yardage: 370, description: 'Named "Blind Pew," this short par 4 in the dunes rewards accuracy over power. The green is tucked behind dunes with the ocean as a stunning backdrop, requiring a precise approach to a well-defended target.' }, { hole: 8, par: 4, yardage: 399, description: 'The transition hole where the course moves from open dunes into the Del Monte Forest. A demanding par 4 that marks the dramatic change in character from links-style to tree-lined parkland golf.' }, { hole: 16, par: 4, yardage: 476, description: 'A long, challenging par 4 through the dense forest. At nearly 480 yards, it demands two powerful and accurate shots through a corridor of towering Monterey pines to reach a well-protected green.' }], whatToExpect: 'Spyglass Hill offers a remarkable two-course-in-one experience. The first five holes play through exposed sand dunes along the Pacific coast, with ocean winds, sandy waste areas, and links-style turf. At the 6th tee, the course transforms dramatically as it enters the dense Del Monte Forest, where towering Monterey pines and cypress trees frame tight fairways and elevated greens.\n\nAt 6,960 yards with a course rating of 75.5 and slope of 148 from the tips, Spyglass Hill is a serious test for any golfer. The resort tees offer more manageable yardages, but the course remains demanding due to its varied terrain, firm conditions, and strategic green complexes.', playingTips: 'On the opening dune holes, wind management is critical. Club selection should account for gusts off the Pacific, and keeping the ball low is often advantageous. The dune holes also feature ice plant and sandy waste areas, so staying on the short grass is essential.\n\nOnce in the forest, accuracy becomes paramount. The tree-lined fairways leave little room for wayward drives, and the greens are well-defended by bunkers and elevation changes. Play conservatively on the long par 4s in the forest section, as bogey from the fairway beats double bogey from the trees.', faqs: [{ question: 'Can the public play Spyglass Hill?', answer: 'Yes. Spyglass Hill is a resort course open to guests of Pebble Beach Resorts and the general public. Green fees typically range from $395 to $425.' }, { question: 'Why is it called Spyglass Hill?', answer: 'The course is named after a lookout point in Robert Louis Stevenson\'s Treasure Island. Nearly every hole carries a name from the novel, honoring Stevenson who lived on the Monterey Peninsula in 1879.' }, { question: 'How difficult is Spyglass Hill compared to Pebble Beach?', answer: 'Spyglass Hill is generally considered the tougher test, with a course rating of 75.5 compared to Pebble Beach\'s 75.0. It is often the hardest course in the AT&T Pro-Am rotation.' }, { question: 'What is the best strategy for the dune holes?', answer: 'The first five holes are exposed to ocean winds. Keep the ball low, account for wind in club selection, and aim for the center of fairways and greens. Accuracy matters more than distance on these holes.' }] },
    { id: 'mon-3', name: 'Cypress Point Club', slug: 'cypress-point-club', city: 'Pebble Beach', state: 'California', type: 'private', rating: 5.0, greensFee: 'Members Only', architect: 'Alister MacKenzie', yearBuilt: 1928, holes: 18, par: 72, yardage: 6524, description: 'Alister MacKenzie\'s jewel on the Monterey Peninsula, Cypress Point is considered one of the most beautiful and strategically brilliant courses ever built. The iconic par-3 16th over the Pacific, the lone cypress, and the wind-swept clifftop setting create golf\'s most romantic and revered experience.', highlights: ['Alister MacKenzie architectural masterwork', 'Iconic par-3 16th over the Pacific Ocean', 'Perennially ranked among the world\'s top 3 courses'], imageAlt: 'Cypress Point Club clifftop hole with lone cypress and Pacific Ocean', history: 'Cypress Point Club was conceived by Marion Hollins, a former U.S. Women\'s Amateur champion, and designed by Dr. Alister MacKenzie with Robert Hunter. The course opened in 1928 on a spectacular stretch of the Monterey Peninsula weaving through dunes, Monterey cypress groves, and dramatic rocky coastline. Samuel F.B. Morse formed the club and selected MacKenzie based on Hollins\' recommendation.\n\nMacKenzie considered Cypress Point his finest work. The routing moves from inland meadows through dark cypress forest to exposed oceanside cliffs. The course hosted the Bing Crosby Clambake rotation from 1947 until 1991, when the club withdrew. The 2025 Walker Cup returned elite competition to the course.\n\nAt just 6,524 yards, Cypress Point proves great golf does not require excessive length. MacKenzie\'s genius lay in creating holes offering multiple strategic options, all framed by some of the most breathtaking scenery in the game.', signatureHoles: [{ hole: 15, par: 3, yardage: 137, description: 'A short, enchanting par 3 perched on the rocky coastline with the Pacific crashing below. Ocean winds and a small green surrounded by ice plant make this one of the most memorable short holes anywhere.' }, { hole: 16, par: 3, yardage: 231, description: 'Perhaps the most famous par 3 in all of golf. This heroic one-shotter plays entirely over the Pacific Ocean to a green on a rocky headland. Players can lay up left, but the bold carry over the churning ocean is golf\'s most iconic shot.' }, { hole: 17, par: 4, yardage: 381, description: 'Often overshadowed by the 16th, this stunning par 4 plays along clifftops with ocean on the left. The approach navigates cypress trees to a green perched on the edge of the rocks.' }], whatToExpect: 'Cypress Point journeys through three distinct landscapes: rolling dune land on opening holes, dense Monterey cypress forest in the middle, and dramatic rocky coastline on the famous finishing stretch. At 6,524 yards, the course rewards finesse and imagination far more than power.\n\nOcean winds are constant on coastal holes. The course is walking only with caddies, and the terrain is very manageable. The small membership means you will likely have the course largely to yourself.', playingTips: 'Course management is everything at Cypress Point. The inland holes through cypress forest demand accuracy while the coastal stretch demands courage and restraint. On the 16th, assess the wind honestly before attempting the ocean carry. The bail-out fairway left still allows a chance at par.\n\nMacKenzie\'s greens reward approach shots played to specific quadrants. Favor the wide side of each green, as the coastal greens can be firm and wind-swept.', faqs: [{ question: 'Can the public play Cypress Point Club?', answer: 'No. Cypress Point is one of the most exclusive private clubs in the world. Access is only through a member invitation.' }, { question: 'What makes the 16th hole so famous?', answer: 'The 16th is a 231-yard par 3 playing entirely over the Pacific Ocean to a green on a rocky headland. It is considered the most iconic hole in golf.' }, { question: 'Why did Cypress Point leave the AT&T Pro-Am rotation?', answer: 'Cypress Point withdrew from the tournament rotation in 1991 and was replaced by other Monterey Peninsula courses.' }, { question: 'How does Cypress Point compare to Pebble Beach?', answer: 'Both are among the world\'s greatest courses. Cypress Point is shorter, more intimate, and exclusively private, while Pebble Beach is longer, has hosted more championships, and is open to the public.' }] },
    { id: 'mon-4', name: 'The Links at Spanish Bay', slug: 'spanish-bay-links', city: 'Pebble Beach', state: 'California', type: 'resort', rating: 4.5, greensFee: '$290–$310', architect: 'Robert Trent Jones Jr. / Tom Watson / Sandy Tatum', yearBuilt: 1987, holes: 18, par: 72, yardage: 6821, description: 'A collaboration between Robert Trent Jones Jr., Tom Watson, and Sandy Tatum, Spanish Bay was designed to evoke the links courses of Scotland. The seaside layout on restored sand dunes features fescue fairways, pot bunkers, and a Scottish bagpiper at sunset — a Monterey Peninsula tradition.', highlights: ['Scottish links-style on restored dunes', 'RTJ Jr., Tom Watson, and Sandy Tatum collaboration', 'Bagpiper at sunset tradition'], imageAlt: 'Spanish Bay Links seaside fairway with sand dunes on Monterey Peninsula', history: 'The Links at Spanish Bay opened in 1987, born from an unusual three-way collaboration between architect Robert Trent Jones Jr., five-time Open Championship winner Tom Watson, and former USGA president Sandy Tatum. The trio shared a passion for Scottish links golf and set out to create an authentic links experience on the Monterey Peninsula.\n\nThe course was built on a former sand mining site at the northern end of the 17-Mile Drive. As part of the project, the developers restored native sand dune habitat and replanted coastal vegetation, making it one of the earliest environmentally restorative golf projects in America. The restored dunes now support native species and provide the rolling, windswept terrain that gives the course its Scottish character.\n\nSpanish Bay is perhaps best known for its sunset bagpiper tradition, where a lone piper in full Highland regalia plays along the course at dusk each evening. The course is part of the AT&T Pebble Beach Pro-Am rotation and offers a distinctly different experience from the other Pebble Beach Resorts courses. In 2026, a major redesign by Gil Hanse and Jim Wagner was announced.', signatureHoles: [{ hole: 1, par: 4, yardage: 503, description: 'A lengthy opening par 4 along the coastline that immediately establishes the links character. The fairway rolls through restored dunes with ocean views, demanding a well-placed drive to set up the approach.' }, { hole: 7, par: 3, yardage: 170, description: 'A beautiful par 3 that plays toward the Pacific Ocean. Wind off the bay makes club selection a constant challenge, and the green is framed by pot bunkers in true Scottish style.' }, { hole: 14, par: 4, yardage: 571, description: 'A massive par 4 that plays along the shoreline and is one of the most dramatic holes on the Monterey Peninsula. The Pacific Ocean borders the entire left side, and the wind can make this hole play even longer than its considerable yardage.' }, { hole: 17, par: 4, yardage: 414, description: 'A strong par 4 returning toward the ocean. The approach shot must navigate coastal winds and pot bunkers protecting a green with ocean views as the backdrop.' }], whatToExpect: 'Spanish Bay delivers the closest experience to Scottish links golf available in California. The fescue fairways provide firm, fast conditions that encourage bump-and-run shots. Pot bunkers dot the landscape, and the routing takes full advantage of the coastal setting with ocean views on numerous holes.\n\nAt 6,821 yards from the tips, the yardage is modest, but the ever-present coastal winds make the course play significantly longer. The restored sand dunes create undulating terrain that provides uneven lies and tests creative shotmaking. The evening bagpiper adds a memorable touch to the experience.', playingTips: 'Embrace the ground game at Spanish Bay. The firm fescue fairways reward low running shots, and bump-and-run approaches are often more effective than high pitch shots, especially when the wind is blowing. Bring your links imagination and think creatively about how to use the terrain.\n\nWind is the primary defense. Check conditions before each shot and be prepared to adjust club selection by two or three clubs on exposed holes. The pot bunkers are penal, so aim away from them rather than trying to carry them.', faqs: [{ question: 'Can the public play Spanish Bay?', answer: 'Yes. The Links at Spanish Bay is a resort course open to guests of Pebble Beach Resorts and the general public. Green fees range from $290 to $310.' }, { question: 'What is the bagpiper tradition?', answer: 'Each evening at sunset, a lone Scottish bagpiper in full Highland regalia walks the course playing traditional tunes. It has become one of the most beloved traditions on the Monterey Peninsula.' }, { question: 'Who designed Spanish Bay?', answer: 'The course was a collaboration between architect Robert Trent Jones Jr., five-time Open Championship winner Tom Watson, and former USGA president Sandy Tatum, all united by a love of Scottish links golf.' }, { question: 'How does Spanish Bay differ from Pebble Beach and Spyglass Hill?', answer: 'Spanish Bay is a true links-style course with fescue fairways and pot bunkers, evoking Scotland. Pebble Beach is a clifftop parkland course, and Spyglass Hill blends dunes and forest. Spanish Bay is the most wind-affected and the most affordable of the three.' }] },
    { id: 'mon-5', name: 'Pasadera Country Club', slug: 'pasadera-country-club', city: 'Monterey', state: 'California', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 2000, holes: 18, par: 71, yardage: 6831, description: 'A Jack Nicklaus Signature design in the hills above Monterey, Pasadera offers a more inland Monterey Peninsula experience through oak woodlands and rolling terrain. The intimate private club features challenging green complexes and panoramic views of Monterey Bay.', highlights: ['Jack Nicklaus Signature inland design', 'Oak woodland setting above Monterey', 'Panoramic Monterey Bay views'], imageAlt: 'Pasadera Country Club Jack Nicklaus fairway through Monterey oak woodlands', history: 'Pasadera (now TPC Monterey at Pasadera) was designed by Jack Nicklaus and opened in 2000 — the only Nicklaus Signature course on the Monterey Peninsula. Situated on a mountain ridge about 10 miles inland from Pebble Beach.\n\nThe club has evolved through several names: Pasadera Golf & Country Club, Nicklaus Club Monterey, and most recently TPC Monterey at Pasadera after joining the TPC Network in 2025. Par 71, approximately 6,811 yards through oak woodlands and canyon terrain.', signatureHoles: [{ hole: 14, par: 3, yardage: 185, description: 'The dramatic signature hole — a forced carry over a deep canyon/cliff to the green. One of the most visually intimidating par 3s in the Monterey area. The canyon depth makes it play much more demanding than the yardage suggests.' }], whatToExpect: 'The front nine is relatively flat and open before plunging into severely downhill terrain. The back nine features dramatic, secluded holes winding through oak groves and canyons. Nicklaus credited the natural topography for allowing a course that feels naturally integrated.\n\nNow part of the TPC Network (PGA Tour\\\'s course management brand). Provides a distinct inland alternative to the famous coastal Monterey courses.\n\nPrivate — members and guests.', playingTips: 'The course mixes par 3s, 4s, and 5s in an unconventional sequence. Check the scorecard before each hole.\n\nCanyon carries on several par 3s are longer than they appear. Take enough club.\n\nThe back nine\\\'s elevation changes significantly affect club selection. Trust your yardage device over your eyes.', faqs: [{ question: 'Is this the only Nicklaus course in the Monterey area?', answer: 'Yes — the only Jack Nicklaus Signature design on the Monterey Peninsula. Now part of the TPC Network.' }, { question: 'Why the name changes?', answer: 'Originally Pasadera, then Nicklaus Club Monterey, now TPC Monterey at Pasadera after joining the TPC Network in 2025.' }]},
    { id: 'mon-6', name: 'Bayonet & Black Horse - Bayonet', slug: 'bayonet-golf-course', city: 'Seaside', state: 'California', type: 'public', rating: 4.3, greensFee: '$60–$130', architect: 'Gen. Robert McClure', yearBuilt: 1954, holes: 18, par: 72, yardage: 7104, description: 'Originally built for soldiers at Fort Ord, Bayonet is a military-heritage course now open to the public. The demanding layout through Monterey pines and coastal terrain features narrow fairways and firm conditions, offering a challenging and affordable alternative to Pebble Beach.', highlights: ['Military-heritage course at former Fort Ord', 'Affordable Monterey Peninsula alternative', 'Demanding layout through Monterey pines'], imageAlt: 'Bayonet Golf Course military heritage layout through Monterey pines at Seaside', history: 'Bayonet Golf Course was built in 1954 by General Robert B. McClure on the grounds of Fort Ord, a major U.S. Army training installation. Named for the 7th Infantry "Bayonet Division." After Fort Ord closed in 1994, the course transitioned to public play.\n\nLong considered the most difficult test of golf on the Monterey Peninsula, Bayonet underwent a significant 2008 renovation by Gene Bates that made it somewhat more player-friendly without removing the teeth. Now managed by Troon Golf alongside its sister course Black Horse (1964, named for the 11th Cavalry Regiment).', signatureHoles: [{ hole: 11, par: 4, yardage: 430, description: 'One of the peninsula\\\'s toughest holes — a narrow, tree-lined corridor with steep, penal bunkering. Embodies the course\\\'s reputation as the most difficult public course in the Monterey area.' }, { hole: 18, par: 5, yardage: 600, description: 'A beast of a finisher at 600+ yards from the back tees. Three strong shots required to reach the green — a demanding championship closer.' }], whatToExpect: 'Narrow playing corridors through Monterey pines, steep penal bunkering, and fast tricky greens. The military heritage is embedded in the course\\\'s DNA. At 7,104 yards from the tips, this is genuinely punishing.\n\nPaired with Black Horse for 36 of the best public holes in the Monterey area at a fraction of Pebble Beach-area pricing ($60-130).\n\nHas hosted PGA Tour Monday qualifiers.', playingTips: 'Practice putting — the greens are fast with significant break, often surrounded by greenside bunkers.\n\nPlay from appropriate tees. From the tips at 7,104 yards, this course is genuinely punishing.\n\nFairway accuracy matters more than distance. Bring your best iron play.\n\nThe military-style difficulty is not a gimmick — this is a serious test.', faqs: [{ question: 'What is the Fort Ord connection?', answer: 'Built in 1954 for soldiers at Fort Ord. Named for the 7th Infantry "Bayonet Division." Transitioned to public play after Fort Ord closed in 1994.' }, { question: 'Is it really the toughest on the peninsula?', answer: 'Long considered so. The 2008 renovation softened it slightly but it remains the most demanding public course in the Monterey area.' }, { question: 'How does it compare to Pebble Beach?', answer: 'Different experience entirely — tougher, longer, and a fraction of the cost. Military heritage vs. resort luxury, but the golf is championship caliber.' }]},
    { id: 'mon-7', name: 'Quail Lodge Golf Club', slug: 'quail-lodge-golf-club', city: 'Carmel Valley', state: 'California', type: 'resort', rating: 4.2, greensFee: '$100–$185', architect: 'Robert Muir Graves', yearBuilt: 1963, holes: 18, par: 71, yardage: 6516, description: 'Nestled in sunny Carmel Valley away from the coastal fog, Quail Lodge is a resort course at the boutique Quail Lodge & Golf Club. The Robert Muir Graves design winds through oak-studded valley terrain with Carmel River frontage and mountain views in a serene, uncrowded setting.', highlights: ['Sunny Carmel Valley location', 'Boutique resort golf experience', 'Carmel River frontage and mountain views'], imageAlt: 'Quail Lodge Golf Club valley fairway with mountain views in Carmel Valley', history: 'Quail Lodge Golf Club was originally designed by Robert Muir Graves in 1963-64 as part of the boutique Quail Lodge resort in sunny Carmel Valley. Todd Eckenrode of Origins Golf Design refined the layout in 2015. Par 71, approximately 6,500 yards.\n\nThe Carmel Valley setting offers warmer, sunnier weather than the foggy coast — often 10-15 degrees warmer than Pebble Beach. The resort is also famous for hosting "The Quail, A Motorsports Gathering," one of the world\\\'s most prestigious automotive events during Monterey Car Week.', signatureHoles: [{ hole: 5, par: 3, yardage: 197, description: 'A demanding par 3 with a pond guarding the right side of the green — the most memorable and photogenic hole on the course. The Carmel Valley setting provides warm sunshine as a backdrop.' }], whatToExpect: 'Pristine conditioning and beautifully manicured greens on gently rolling Carmel Valley terrain. Strategically placed bunkers add beauty and difficulty. The sheltered valley setting means less wind and more sunshine than coastal courses.\n\nVery walkable with minor elevation changes. A nine-hole all-grass putting course adds a family-friendly element. Pace of play is typically under 4 hours.\n\nResort guest and public access at $100-185.', playingTips: 'Precision off the tee matters — several holes run alongside residences with OB in play.\n\nGreens are smooth with subtle, tricky breaks. Read carefully.\n\nThe valley setting means less wind than coastal courses, but morning fog can affect early tee times.\n\nEnjoy the sunshine — Carmel Valley is consistently 10-15 degrees warmer than the foggy coast.', faqs: [{ question: 'Why is Carmel Valley warmer?', answer: 'The sheltered inland valley sits behind the coastal mountains, blocking the fog. Often 10-15 degrees warmer than Pebble Beach just a few miles away.' }, { question: 'Is it connected to the car event?', answer: 'Yes — the resort hosts "The Quail, A Motorsports Gathering," one of the world\\\'s most prestigious automotive events during Monterey Car Week.' }]},
    { id: 'mon-8', name: 'Pacific Grove Golf Links', slug: 'pacific-grove-golf-links', city: 'Pacific Grove', state: 'California', type: 'public', rating: 4.1, greensFee: '$25–$55', architect: 'Jack Neville', yearBuilt: 1932, holes: 18, par: 70, yardage: 5732, description: 'Known as the "Poor Man\'s Pebble Beach," Pacific Grove Municipal offers ocean-side golf at a fraction of the cost. The Jack Neville back nine plays along the rugged Pacific coastline with crashing waves, tide pools, and views of Point Pinos Lighthouse — a remarkable value on the Monterey Peninsula.', highlights: ['Ocean-side golf at municipal pricing', 'Jack Neville back nine along Pacific coastline', 'Nicknamed "Poor Man\'s Pebble Beach"'], imageAlt: 'Pacific Grove Golf Links oceanfront hole with Point Pinos Lighthouse', history: 'Pacific Grove Golf Links features two distinct designers across its two nines. H. Chandler Egan designed the original front nine in the early 1930s. In 1932, the City of Pacific Grove reportedly purchased the oceanfront land for the back nine with a single $10 gold coin, and Jack Neville — co-designer of Pebble Beach Golf Links — designed those nine holes along the rocky coastline.\n\nThe beloved nickname "Poor Man\\\'s Pebble Beach" reflects the remarkable value: oceanfront golf by Pebble Beach\\\'s co-designer at roughly $50 vs. $600+. City-owned municipal course, par 70, 5,732 yards.', signatureHoles: [{ hole: 12, par: 4, yardage: 355, description: '"Rocky Shore" — one of seven back-nine holes directly along the Pacific Ocean. The Point Pinos Lighthouse (1855, oldest continuously operating lighthouse on the West Coast) is visible in the background. Ocean and wind define every shot.' }, { hole: 15, par: 4, yardage: 397, description: 'The toughest hole on the back nine — an uphill par 4 demanding an accurate drive and strong approach into the prevailing wind. The ocean backdrop makes it unforgettable despite the difficulty.' }], whatToExpect: 'Two dramatically different nines. The front (Egan) is an inland affair — pleasant but unremarkable. The back nine (Neville) is the revelation: seven consecutive holes along the Pacific with the Point Pinos Lighthouse visible from every hole. The contrast is dramatic.\n\nThe back nine is heavily wind-exposed — expect 1-3 clubs of wind on coastal holes. Ocean-side is OB on most back-nine holes.\n\nAt roughly $50, arguably the greatest oceanfront golf value in the United States.', playingTips: 'The front nine is warmup. Save energy and focus for the spectacular back nine.\n\nOn the back nine, favor the left side off the tee — the ocean (right) is OB on most holes.\n\nMorning tee times have calmer conditions before afternoon winds pick up.\n\nExpect 1-3 clubs of wind adjustment on coastal holes. The wind is constant and real.', faqs: [{ question: 'Why is it called Poor Man\\\'s Pebble Beach?', answer: 'Oceanfront golf co-designed by Jack Neville (who also co-designed Pebble Beach) at roughly $50 vs. $600+. Arguably the greatest oceanfront golf value in the United States.' }, { question: 'Who designed the two nines?', answer: 'H. Chandler Egan designed the front nine (1930s). Jack Neville — co-designer of Pebble Beach — designed the oceanfront back nine (1932).' }, { question: 'What is the lighthouse?', answer: 'Point Pinos Lighthouse (1855) — the oldest continuously operating lighthouse on the West Coast, visible from every back-nine hole.' }]},
  ],
  'naples-florida': [
    { id: 'nap-1', name: 'Calusa Pines Golf Club', slug: 'calusa-pines-golf-club', city: 'Naples', state: 'Florida', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Michael Hurdzan & Dana Fry', yearBuilt: 2001, holes: 18, par: 72, yardage: 7185, description: 'Widely regarded as the finest private course in Southwest Florida, Calusa Pines is a Hurdzan-Fry design carved through an old-growth pine forest. The layout features dramatic elevation changes rare for coastal Florida, pristine conditioning, and a limited membership that ensures an unhurried pace.', highlights: ['Top-ranked private course in Southwest Florida', 'Old-growth pine forest setting', 'Dramatic elevation changes rare for coastal Florida'], imageAlt: 'Calusa Pines Golf Club fairway through old-growth pine forest in Naples', history: 'Calusa Pines opened in 2001, designed by Michael Hurdzan and Dana Fry through an old-growth slash pine forest in Naples. Named among Golf Digest\\\'s Top Ten Best New Private Clubs upon opening. Currently ranked No. 68 on Golf Digest\\\'s 100 Greatest and No. 3 in Florida — considered by many the finest private club in the state.\n\nNo two consecutive holes play in the same direction, and short green-to-tee walks create a walking-friendly flow rare in Southwest Florida. The cathedral-like setting under towering pines with no houses visible gives a sense of isolation from suburban Naples.', signatureHoles: [{ hole: 18, par: 5, yardage: 512, description: 'A risk/reward finish through the pines. The closing hole offers bold options for those going for the green in two but punishes misses with sand and trees. A fitting conclusion to one of Florida\\\'s finest private courses.' }], whatToExpect: 'A cathedral-like setting under towering old-growth pines with no houses visible from any hole. Seamless routing with dynamic par and length variety. Large, well-contoured greens. Walking is encouraged with a strong caddie program.\n\nThe course rewards shot-shaping and strategic play over raw distance. Green complexes have subtle breaks that read differently under the pine canopy shadows.\n\nIntensely private — guest access requires a member invitation.', playingTips: 'Shot-shaping and strategic tee shots matter more than raw distance. Bold lines exist on several holes but sand and trees punish misses.\n\nGreen complexes have subtle breaks that look different under pine canopy shadows. Read carefully.\n\nWalking with a caddie is the best way to experience the course — the routing was designed for it.', faqs: [{ question: 'How is it ranked?', answer: 'No. 68 on Golf Digest\\\'s 100 Greatest, No. 3 in Florida. Named Top Ten Best New Private Clubs when it opened in 2001.' }, { question: 'Are houses visible?', answer: 'No — the old-growth pine forest setting means no houses are visible from any hole. A rare pure-golf experience in Southwest Florida.' }]},
    { id: 'nap-2', name: 'Tiburon Golf Club - Gold Course', slug: 'tiburon-gold', city: 'Naples', state: 'Florida', type: 'resort', rating: 4.5, greensFee: '$100–$225', architect: 'Greg Norman', yearBuilt: 2001, holes: 18, par: 72, yardage: 7288, description: 'Home of the PGA Tour\'s QBE Shootout at the Ritz-Carlton Naples, Tiburon Gold is a Greg Norman design that delivers championship resort golf in a tropical setting. The layout features wide fairways through native Florida vegetation with strategic water hazards and Norman\'s signature bold bunkering.', highlights: ['Host of PGA Tour QBE Shootout', 'Greg Norman design at Ritz-Carlton Naples', 'Championship resort golf in tropical setting'], imageAlt: 'Tiburon Gold Course championship fairway at Ritz-Carlton Naples', history: 'Tiburon\\\'s Gold Course was designed by Greg Norman and opened in 2001 at the Ritz-Carlton Golf Resort in Naples. "Tiburon" is Spanish for "shark" — Norman\\\'s nickname. The Gold Course hosted the QBE Shootout (formerly Shark Shootout) for over 30 consecutive years, founded by Norman in 1989.\n\nThe Gold is the longer and more demanding of Tiburon\\\'s two 18s (the Black Course is the other). The links-influenced layout relies on coquina-shell waste areas, water hazards, and large undulating greens rather than trees for its defense.', signatureHoles: [{ hole: 4, par: 4, yardage: 480, description: 'One of the most demanding holes on the front — a long par 4 requiring precision off the tee and a well-struck approach. The open terrain and wind exposure make it play even longer than the yardage suggests.' }], whatToExpect: 'Wide-open, links-influenced layout with minimal tree interference. Coquina-shell waste areas, water hazards, and large undulating greens define the challenge. Wind is a major factor on exposed holes.\n\nConditioning is resort-level excellent. Caddie service available. Resort guests at the Ritz-Carlton get priority tee times at $100-225.\n\nThe Gold plays longer than the card suggests due to constant wind exposure.', playingTips: 'Club selection into the wind is critical — the open terrain amplifies gusts by 1-2 clubs.\n\nWaste areas are playable but unpredictable. Keep the ball on maintained turf.\n\nGreens are large — being on the correct tier matters more than just finding the putting surface.\n\nThe finishing stretch (17-18) features water carries demanding composure under pressure.', faqs: [{ question: 'What is the QBE Shootout?', answer: 'A PGA Tour event founded by Greg Norman in 1989 that was held at Tiburon\\\'s Gold Course for over 30 consecutive years. One of the longest venue relationships in Tour history.' }, { question: 'Is it open to resort guests?', answer: 'Yes — Ritz-Carlton Naples guests get priority tee times. Also available to daily-fee players at $100-225.' }]},
    { id: 'nap-3', name: 'Lely Resort - Flamingo Island', slug: 'lely-flamingo-island', city: 'Naples', state: 'Florida', type: 'resort', rating: 4.3, greensFee: '$75–$175', architect: 'Robert Trent Jones Sr.', yearBuilt: 1990, holes: 18, par: 72, yardage: 7171, description: 'A Robert Trent Jones Sr. design in Naples, Flamingo Island at Lely Resort features dramatic water hazards, including the iconic island green on the par-3 5th. The resort layout delivers a scenic and challenging round through subtropical landscape with abundant wildlife sightings.', highlights: ['Robert Trent Jones Sr. resort design', 'Iconic island green par 3', 'Abundant subtropical wildlife'], imageAlt: 'Lely Resort Flamingo Island Course with island green and tropical landscaping', history: 'Flamingo Island at Lely Resort was designed by Robert Trent Jones Sr. (with Roger Rulewich) and opened in 1990 — one of the last designs by the legendary architect, who reportedly considered it among the finest courses he ever designed. The only RTJ Sr. design in the Naples area.\n\nTwice rated by Golfweek among America\\\'s best resort courses. Lely Resort also features the Mustang Course (Lee Trevino design). The famous island green on the par-3 5th is one of the most photographed holes in Southwest Florida.', signatureHoles: [{ hole: 5, par: 3, yardage: 200, description: 'The famous island green — entirely surrounded by water and connected to the mainland only by two small bridges. One of the most photographed holes in Southwest Florida. Commit to your number and swing confidently — indecision puts balls in the water.' }], whatToExpect: 'Classic RTJ Sr. design: expansive white sand bunkers outlining hourglass-shaped fairways, large undulating bermuda greens, and strategic water features. Visually dramatic with well-defined playing corridors.\n\nOpen to public play without membership or resort stay — one of the few premium Naples courses accessible to visitors. GPS-equipped carts and driving range included with greens fees.\n\nPeak season rates around $325; off-season significantly less.', playingTips: 'Wind changes club selection by 2-3 clubs on exposed holes. Always factor it in.\n\nOn the island-green 5th, commit to your number and swing with confidence. Indecision causes the most water balls.\n\nRTJ Sr.\\\'s greens reward approaches to the correct quadrant. Pin-seeking from the wrong angle is punished.\n\nInvest time on the practice green — green speeds can vary.', faqs: [{ question: 'Is the island green as dramatic as it sounds?', answer: 'Yes — entirely surrounded by water, connected by two small bridges. One of the most photographed holes in Southwest Florida.' }, { question: 'Is it open to the public?', answer: 'Yes — public play without membership required. One of the few premium Naples courses accessible to all visitors.' }]},
    { id: 'nap-4', name: 'Old Corkscrew Golf Club', slug: 'old-corkscrew-golf-club', city: 'Estero', state: 'Florida', type: 'public', rating: 4.5, greensFee: '$65–$140', architect: 'Jack Nicklaus', yearBuilt: 2007, holes: 18, par: 72, yardage: 7397, description: 'A Jack Nicklaus design that ranks among the best public courses in Florida, Old Corkscrew winds through 390 acres of native cypress, pine, and palmetto in the Audubon-certified Corkscrew corridor. The layout offers a rare natural Florida golf experience away from housing developments.', highlights: ['Jack Nicklaus design ranked among Florida\'s best public courses', 'Audubon-certified 390-acre natural setting', 'No residential development — pure golf'], imageAlt: 'Old Corkscrew Golf Club Jack Nicklaus fairway through native cypress and pine', history: 'Old Corkscrew opened in 2007, a Jack Nicklaus Signature design built on 270 acres of natural Florida landscape with zero residential development bordering the course. Earned Audubon International Silver Signature Sanctuary certification.\n\nRanked the No. 1 golf course in Southwest Florida by Golf Magazine and named to Golf Digest\\\'s Top 40 Courses You Can Play in Florida. One of the highest slope ratings in the state at 153 from the tips.\n\nThe name references Corkscrew Road and the nearby Corkscrew Swamp Sanctuary. The pure-golf setting with no houses in sight is unique in Southwest Florida.', signatureHoles: [{ hole: 9, par: 4, yardage: 423, description: 'The consensus standout — a dogleg rewarding players bold enough to challenge the water along the left side for a shorter approach. Risk-reward at its best, followed by the stellar 10th to create the course\\\'s finest two-hole stretch.' }], whatToExpect: 'A pure golf experience with no houses, roads, or development in sight — just native wetlands, cypress heads, and open prairie. Natural bunkering (rather than manicured white sand) blends with the landscape.\n\nGreens are tricky with subtle slopes that become more challenging as the round progresses. The 437-yard opener sets the tone with a generous fairway but demanding green.\n\nPublic access at $65-140 — the best public course in the Naples/Estero area.', playingTips: 'Play one set of tees forward from where you normally would. This is universally recommended — the 153 slope from the tips is extremely penal.\n\nThis is a shot-maker\\\'s course. Managing your way around it is essential or double bogeys pile up.\n\nGreens slope more than they appear. Trust your reads even when they look wrong.\n\nThe Audubon-certified setting means wildlife everywhere — enjoy it.', faqs: [{ question: 'Is it really the best public course in the area?', answer: 'Yes — ranked No. 1 in Southwest Florida by Golf Magazine and in Golf Digest\\\'s Top 40 Florida public courses. Slope 153 from the tips.' }, { question: 'Are there really no houses?', answer: 'Correct — zero residential development borders the course. Just native wetlands, cypress, and prairie. Unique in Southwest Florida.' }, { question: 'Why play forward tees?', answer: 'Universally recommended by reviewers. The 153 slope from the tips is one of the highest in Florida — extremely penal for anyone but scratch-or-better players.' }]},
    { id: 'nap-5', name: 'The Club at Mediterra - South', slug: 'mediterra-south', city: 'Naples', state: 'Florida', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 2001, holes: 18, par: 72, yardage: 7217, description: 'One of two Tom Fazio courses at the Mediterra community, the South Course is considered among the finest private club experiences in Naples. The layout features Fazio\'s bold shaping through native Southwest Florida preserves with strategic water hazards and immaculate tropical conditioning.', highlights: ['Tom Fazio private club design', 'Native Southwest Florida preserve setting', 'Among Naples\' finest private club experiences'], imageAlt: 'Mediterra South Course Tom Fazio fairway through native Florida preserves', history: 'Mediterra\\\'s South Course was designed by Tom Fazio and opened around 2001 as part of the luxury Mediterra community in North Naples. The community features 36 holes of Fazio golf (North and South courses) with membership capped at 450 golf members to ensure uncrowded play.\n\nThe South Course is considered the more difficult of the two layouts. PlatinumTE Paspalum turf on tees, fairways, and greens plays firm and fast. Native preserve corridors frame holes beautifully and come into play on errant shots.\n\nMediterranean-inspired aesthetics with an Italianate clubhouse and a private Gulf beach club complete the experience.', signatureHoles: [{ hole: 14, par: 4, yardage: 430, description: 'A demanding par 4 through native preserve corridors with deep, well-placed Fazio bunkering. The South Course\\\'s difficulty lies in the approach game — being on the correct side of the fairway for the angle into the green defines the outcome.' }], whatToExpect: 'Tom Fazio design through native preserves and wetlands with firm, fast Paspalum turf. The South Course rewards approach-shot precision more than length. Deep bunkering is both aesthetic and penal.\n\nThe 450-member cap means tee times are readily available — a major selling point. Mediterranean-inspired clubhouse and Gulf beach club.\n\nResidential private — membership tied to home ownership in Mediterra.', playingTips: 'Paspalum greens play firm and fast — factor in more roll on approach shots.\n\nBeing on the correct side of the fairway for approach angle matters more than distance. Position off the tee defines your score.\n\nDeep bunkering is both beautiful and penal. Avoid it when possible.\n\nFirst-timers should lean on a caddie or knowledgeable playing partner — course knowledge matters.', faqs: [{ question: 'How many Fazio courses?', answer: 'Two — North and South. The South is considered more difficult. Together they provide 36 holes of Fazio golf within the Mediterra community.' }, { question: 'What is the membership like?', answer: 'Capped at 450 golf members (tied to home ownership), ensuring uncrowded tee times — a major selling point.' }]},
    { id: 'nap-6', name: 'Naples National Golf Club', slug: 'naples-national-golf-club', city: 'Naples', state: 'Florida', type: 'semi-private', rating: 4.2, greensFee: '$50–$120', architect: 'Gordon Lewis', yearBuilt: 1999, holes: 18, par: 72, yardage: 6862, description: 'A Gordon Lewis design offering semi-private access in the heart of Naples, Naples National features a parkland layout through native Florida vegetation with strategic water hazards. The well-conditioned course provides solid golf value in one of Florida\'s most expensive golf markets.', highlights: ['Semi-private access in Naples', 'Native Florida vegetation routing', 'Solid golf value in premium market'], imageAlt: 'Naples National Golf Club parkland fairway through native Florida vegetation', history: 'Naples National Golf Club opened in the early-to-mid 1990s with distinctive coral rock outcroppings integrated into the layout — an uncommon feature among Naples-area courses. Golf Digest rated it the 7th "Best in State" course for 1995-96 and 1997-98.\n\nKnown for beautiful conditioning and greens considered among the best in the Naples area — fast, true, and in outstanding condition. Water hazards come into play on only four holes, but the coral rock features create distinctive visual and strategic elements throughout.', signatureHoles: [{ hole: 16, par: 4, yardage: 400, description: 'Part of a notable finishing stretch where coral rock outcroppings add both visual drama and strategic challenge. The distinctive rock features give Naples National a unique identity among Southwest Florida courses.' }], whatToExpect: 'Wide, well-maintained fairways through a classic South Florida landscape. Greens are fast, true, and among the best in the Naples area. Water on only four holes makes it more forgiving than many Naples courses, but coral rock features add distinctive challenge.\n\nSemi-private access provides one of the better golf values in Naples\\\'s premium market at $50-120.', playingTips: 'Wide fairways reward aggressive driving. Focus precision on approach shots — the greens are the main defense.\n\nCoral rock features create strategic decisions not found on typical Naples courses. Study them before committing to your line.\n\nGreens are fast and well-contoured. Invest time on the practice green.', faqs: [{ question: 'What are the coral rock features?', answer: 'Distinctive coral rock outcroppings integrated into the layout — uncommon among Naples-area courses and giving it a unique identity.' }, { question: 'Is it open to the public?', answer: 'Semi-private — public access at $50-120. One of the better values in Naples\\\'s premium golf market.' }]},
    { id: 'nap-7', name: 'Hammock Bay Golf & Country Club', slug: 'hammock-bay-golf', city: 'Naples', state: 'Florida', type: 'semi-private', rating: 4.1, greensFee: '$55–$110', architect: 'Peter Jacobsen & Jim Hardy', yearBuilt: 2004, holes: 18, par: 72, yardage: 7054, description: 'A Jacobsen-Hardy design south of Naples near Marco Island, Hammock Bay winds through mangrove preserves and native wetlands with distant views of the Gulf of Mexico. The semi-private layout offers a nature-immersive golfing experience in the Ten Thousand Islands region.', highlights: ['Mangrove and wetland preserve setting', 'Peter Jacobsen and Jim Hardy design', 'Near Marco Island and Ten Thousand Islands'], imageAlt: 'Hammock Bay Golf Club fairway through mangrove preserves near Marco Island', history: 'Hammock Bay opened around 2004, designed by Peter Jacobsen and Jim Hardy near Marco Island within the Hammock Bay community adjacent to Collier-Seminole State Park (over 7,200 acres). The course earned Audubon Gold certification for environmental stewardship.\n\nThe design takes advantage of the highest elevations in Southwest Florida, routing through live oaks, bay, marshes, and mangroves. Access is typically through JW Marriott Marco Island resort packages, making it one of the few premium courses accessible to Marco Island visitors.', signatureHoles: [{ hole: 11, par: 3, yardage: 175, description: 'Widely praised for its beauty, playing over or alongside natural mangrove and marsh terrain. The Audubon-certified setting with Ten Thousand Islands proximity creates a nature-immersive par 3.' }], whatToExpect: 'Live oak-lined fairways winding through bay, marshes, mangroves, and sand bunkers. Roomier off the tee than it looks — the visual intimidation of mangrove carries often overstates the actual distance. The back nine routing through bay and wetland landscapes is especially praised.\n\nAudubon Gold certified. Surrounded by Collier-Seminole State Park. Semi-private access through JW Marriott resort packages at $55-110.', playingTips: 'The course looks more intimidating than it plays — mangrove carries are shorter than they appear. Trust the generous landing areas.\n\nPlay correct tees for your game — the back tees create a genuinely challenging experience.\n\nThe back nine is the highlight — save your best golf and attention for the marsh-edge holes.', faqs: [{ question: 'How do I access Hammock Bay?', answer: 'Typically through JW Marriott Marco Island resort packages. Semi-private access available at $55-110.' }, { question: 'What is the Audubon Gold certification?', answer: 'The highest level of Audubon environmental certification, reflecting exceptional stewardship of the surrounding 7,200+ acres of Collier-Seminole State Park.' }]},
    { id: 'nap-8', name: 'TwinEagles Golf Club - Talon Course', slug: 'twineagles-talon', city: 'Naples', state: 'Florida', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 2010, holes: 18, par: 72, yardage: 7193, description: 'A Jack Nicklaus design in the TwinEagles community north of Naples, the Talon Course features bold bunkering, strategic water hazards, and pristine conditioning through native Florida landscape. The challenging layout hosted LPGA and Champions Tour qualifying events.', highlights: ['Jack Nicklaus private community design', 'Bold bunkering and strategic water hazards', 'Host of LPGA and Champions Tour events'], imageAlt: 'TwinEagles Talon Course Jack Nicklaus fairway in north Naples community', history: 'TwinEagles\\\' Talon Course was designed by Jack Nicklaus and Jack Nicklaus II, originally opening in 1999 with a significant renovation completed in 2021. One of two courses at TwinEagles (the other being the Steve Smyers-designed Eagle Course).\n\nThe Talon hosted the PGA Tour Champions\\\' Chubb Classic (formerly ACE Group Classic) for 11 consecutive years, putting it on the national stage. Loren Roberts clinched the 2006 ACE Group Classic on the demanding 18th hole. Rated 75.9/145 slope from the tips post-renovation.', signatureHoles: [{ hole: 18, par: 4, yardage: 457, description: 'The demanding closer where Loren Roberts clinched the 2006 ACE Group Classic — water in play with a premium on accuracy. Part of a final four-hole stretch considered among the most compelling closers in Southwest Florida.' }], whatToExpect: 'Classic Nicklaus design: length, tough par 3s, strategic bunkering, and elevated greens with firm fast putting surfaces. Wide fairways tighten as you approach the greens — accurate iron play matters more than driving distance.\n\nThe 2021 Nicklaus renovation updated the course to modern standards. Champions Tour professionals have described the finishing stretch as one that "can bite you."\n\nPrivate — members and guests at TwinEagles community.', playingTips: 'The par 3s are the teeth of the course. Club selection is critical on every one-shotter.\n\nOn 18, favor the right side off the tee to avoid the water hazard left.\n\nBail-out areas are typically on the high side of greens throughout. When in doubt, miss high.\n\nThe 145 slope from the tips post-renovation is legitimate. Choose tees honestly.', faqs: [{ question: 'Did it host professional events?', answer: 'Yes — the PGA Tour Champions Chubb Classic (formerly ACE Group Classic) for 11 consecutive years.' }, { question: 'Who renovated it?', answer: 'Jack Nicklaus and Jack Nicklaus II completed a significant renovation in 2021, updating the course to modern standards.' }]},
  ],
  'savannah-georgia': [
    { id: 'sav-1', name: 'The Club at Savannah Harbor', slug: 'savannah-harbor-golf', city: 'Savannah', state: 'Georgia', type: 'resort', rating: 4.4, greensFee: '$90–$175', architect: 'Sam Snead & Bob Cupp', yearBuilt: 1999, holes: 18, par: 72, yardage: 7288, description: 'Located on Hutchinson Island in the Savannah River, this resort course at the Westin Savannah Harbor offers panoramic views of the city\'s historic skyline. The Sam Snead and Bob Cupp design features tidal marsh hazards, live oak-lined fairways, and a unique island setting minutes from downtown.', highlights: ['Historic Savannah skyline views', 'Hutchinson Island tidal marsh setting', 'Westin resort golf minutes from downtown'], imageAlt: 'Club at Savannah Harbor fairway with historic Savannah skyline across the river', history: 'The Club at Savannah Harbor opened in 1999 on Hutchinson Island in the Savannah River, designed by Robert Cupp and Sam Snead — one of Snead\\\'s final course design projects. The course hosted the Liberty Mutual Legends of Golf on the Champions Tour.\n\nThe island setting between Savannah and South Carolina creates a unique layout winding through tidal wetlands and marshland with panoramic views of the historic Savannah skyline across the river. Rated among the "Top 10 Places to Play" in Georgia by Golf Magazine. Managed by Troon Golf at the Westin Savannah Harbor.', signatureHoles: [{ hole: 14, par: 4, yardage: 420, description: 'One of several holes offering dramatic views of the historic Savannah skyline across the river. The tidal wetland setting with the city\\\'s church steeples and historic buildings as backdrop creates one of the most unique visual experiences in resort golf.' }], whatToExpect: 'A course weaving through tidal wetlands with panoramic downtown Savannah skyline views — one of the few courses where a major city\\\'s historic skyline serves as your backdrop. Generous fairways balance resort-friendly playability with genuine championship challenge from the back tees.\n\nHutchinson Island location means Savannah\\\'s historic district is a short ferry ride away. The 22,000-square-foot clubhouse anchors the experience.\n\nResort access at the Westin Savannah Harbor at $90-175.', playingTips: 'Wind off the Savannah River is constant. Check conditions before choosing clubs on every shot.\n\nWetland forced carries look longer than they actually are. Trust the distances.\n\nThe course is fair for all skill levels from appropriate tees. Select honestly.\n\nDynamic pricing is in effect — off-peak rounds offer significant savings.', faqs: [{ question: 'Can you see the Savannah skyline?', answer: 'Yes — panoramic views of the historic Savannah skyline across the river from multiple holes. One of the few courses where a city skyline serves as your backdrop.' }, { question: 'How do you get there?', answer: 'Hutchinson Island in the Savannah River. The historic district is a short ferry ride away.' }, { question: 'Who designed it?', answer: 'Robert Cupp and Sam Snead — one of Snead\\\'s final course design projects. Opened 1999.' }]},
    { id: 'sav-2', name: 'The Landings Club - Marshwood', slug: 'landings-marshwood', city: 'Savannah', state: 'Georgia', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Arnold Palmer', yearBuilt: 1973, holes: 18, par: 72, yardage: 6826, description: 'The original course at The Landings on Skidaway Island, Marshwood is an Arnold Palmer design routed through Lowcountry marsh and maritime forest. The layout features tidal creek hazards, moss-draped live oaks, and scenic views of the Vernon River that define Savannah\'s coastal golf experience.', highlights: ['Arnold Palmer Lowcountry design on Skidaway Island', 'Tidal creek and Vernon River frontage', 'Part of six-course Landings Club community'], imageAlt: 'Landings Marshwood Course Arnold Palmer fairway through Lowcountry marsh and live oaks', history: 'Marshwood is the original course at The Landings on Skidaway Island, designed by Arnold Palmer and Frank Duane and opened in July 1974. Tim Liddy completed a comprehensive 2003 redesign, rebuilding greens, tees, and bunkers while updating drainage and irrigation.\n\nThe Landings now features six championship courses by Palmer, Tom Fazio, Arthur Hills, and Willard Byrd — one of the largest private club complexes in the Southeast. Located 12 miles from historic Savannah on a barrier island with pristine tidal creek ecosystems.', signatureHoles: [{ hole: 15, par: 4, yardage: 400, description: 'One of the marsh-edge holes where the fairway runs adjacent to saltwater creeks, demanding both precision and nerve. The Lowcountry marsh vistas and maritime forest framing create the most dramatic scenery on the course.' }], whatToExpect: 'A blend of parkland corridors through maritime forest with open marsh-vista holes. The Liddy redesign modernized the course while preserving Palmer\\\'s original routing philosophy. Undulating greens, strategic bunkering, and constant interaction with Lowcountry marsh and hardwood forests.\n\nPart of a six-course private club complex on Skidaway Island. Strictly private — members and guests.\n\nArnold Palmer\\\'s personal connection to The Landings was a lifelong relationship.', playingTips: 'Tidal conditions affect wind patterns and the visual intimidation of marsh-side holes. Play away from marsh edges — the penalty for finding wetlands is absolute.\n\nThe redesigned greens have more movement than the originals. Study slopes before putting.\n\nThe maritime forest corridors demand accuracy off the tee on the parkland holes.', faqs: [{ question: 'How many courses does The Landings have?', answer: 'Six championship courses by Palmer, Fazio, Hills, and Byrd — one of the largest private club complexes in the Southeast.' }, { question: 'Who designed Marshwood?', answer: 'Arnold Palmer and Frank Duane (1974). Tim Liddy redesigned it comprehensively in 2003.' }, { question: 'Where is Skidaway Island?', answer: '12 miles from historic Savannah — a barrier island with pristine tidal creek ecosystems.' }]},
    { id: 'sav-3', name: 'Ford Plantation', slug: 'ford-plantation-golf', city: 'Richmond Hill', state: 'Georgia', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Pete Dye', yearBuilt: 1997, holes: 18, par: 72, yardage: 7018, description: 'A Pete Dye design on the historic Ford Plantation estate south of Savannah, this exclusive course winds through Lowcountry landscape along the Ogeechee River. The former winter retreat of Henry Ford features dramatic marsh carries, ancient live oaks, and old-South charm.', highlights: ['Pete Dye design on historic Henry Ford estate', 'Ogeechee River and Lowcountry marsh routing', 'Exclusive old-South plantation club'], imageAlt: 'Ford Plantation Pete Dye fairway through Lowcountry marsh along Ogeechee River', history: 'The Ford Field & River Club (formerly Ford Plantation) spans 1,800 acres along Georgia\\\'s Ogeechee River on land Henry and Clara Ford purchased in the 1930s as their Lowcountry winter retreat. Pete Dye designed the course in the mid-1980s, later returning for a significant redesign that softened his trademark severity. Dye called it his "Finest Southern Links."\n\nThe club has hosted the Georgia Open six times. The front nine plays through Lowcountry parkland with mature oaks; the back nine transitions to open links-style holes along the river and marshland. No tee times required — members play at will.', signatureHoles: [{ hole: 17, par: 3, yardage: 146, description: 'The most photographed hole — a downhill par 3 to an offset, elevated green guarded by deep bunkers. Miss the green and recovery is extremely difficult. Accuracy is everything.' }], whatToExpect: 'The front nine plays through Lowcountry parkland. The back nine projects onto an open isthmus into the Ogeechee River, creating dramatic links-like holes with water and marsh views on all sides. Alligators bask along the banks.\n\nDye\\\'s redesign made it gentler than his typical fare while preserving strategic interest. The 1,800-acre property also offers a deepwater marina, horseback riding, and sporting pursuits.\n\nPrivate — members and guests only.', playingTips: 'Marsh-side holes demand precise club selection, especially in wind. Course management matters more than distance.\n\nWatch for soft lies near marshland edges and drainage areas.\n\nThe back nine\\\'s links character is dramatically different from the parkland front. Adjust your expectations at the turn.', faqs: [{ question: 'What is the Henry Ford connection?', answer: 'Ford purchased roughly 85,000 acres as his Lowcountry winter retreat in the 1930s. The club sits on 1,800 of those acres along the Ogeechee River.' }, { question: 'Who designed it?', answer: 'Pete Dye — who called it his "Finest Southern Links." He returned for a redesign that softened the original layout.' }]},
    { id: 'sav-4', name: 'Harbour Town Golf Links', slug: 'harbour-town-golf-links', city: 'Hilton Head Island', state: 'South Carolina', type: 'resort', rating: 4.8, greensFee: '$200–$400', architect: 'Pete Dye & Jack Nicklaus', yearBuilt: 1969, holes: 18, par: 71, yardage: 7099, description: 'Home of the RBC Heritage on the PGA Tour, Harbour Town is a Pete Dye and Jack Nicklaus collaboration at Sea Pines Resort. The tight, strategic layout along Calibogue Sound features Dye\'s signature railroad-tie bulkheads, small greens, and the iconic lighthouse behind the 18th green.', highlights: ['PGA Tour RBC Heritage host since 1969', 'Pete Dye and Jack Nicklaus collaboration', 'Iconic lighthouse at 18th green on Calibogue Sound'], imageAlt: 'Harbour Town Golf Links 18th green with iconic lighthouse on Calibogue Sound', history: 'Harbour Town Golf Links was designed by Pete Dye with consultation from a young Jack Nicklaus and opened in 1969 at Sea Pines Resort on Hilton Head Island. The first Heritage Classic was won by Arnold Palmer that same year, establishing the PGA Tour event that continues today as the RBC Heritage.\n\nThe course revolutionized design thinking by proving a shorter, strategic layout could challenge the world\'s best players. Harbour Town remains one of the shortest courses on Tour, yet its tight live-oak corridors, small greens, and coastal winds make it one of the most demanding. The red-and-white lighthouse behind the 18th green is one of golf\'s most recognizable landmarks.', signatureHoles: [{ hole: 18, par: 4, yardage: 472, description: 'One of golf\'s most iconic finishing holes. The fairway runs along Calibogue Sound with the approach playing to a green at the base of the famous striped lighthouse.' }, { hole: 17, par: 3, yardage: 192, description: 'A beautiful par 3 over a marshy waste area to a green guarded by Calibogue Sound. Wind off the water makes club selection tricky.' }, { hole: 9, par: 4, yardage: 338, description: 'A short but devious par 4 with a narrow fairway pinched by towering live oaks and a tiny, heavily bunkered green.' }, { hole: 15, par: 5, yardage: 541, description: 'The longest and most difficult hole at 541 yards. A tight, tree-lined par 5 with a well-defended green.' }], whatToExpect: 'Harbour Town is a shotmaker\'s course where accuracy trumps distance. Narrow fairways wind through ancient live oaks draped in Spanish moss, with overhanging branches restricting trajectory. Greens are among the smallest on the PGA Tour.\n\nThe closing holes along Calibogue Sound bring wind and water into play, and the lighthouse at 18 provides a memorable finish.', playingTips: 'Leave the driver in the bag on many holes. Accuracy off the tee matters far more than distance. A 3-wood or hybrid will keep you in play and set up better angles into the small greens.\n\nWind off Calibogue Sound intensifies on the back nine. Take extra club and aim for green centers on holes 17 and 18.', faqs: [{ question: 'Can non-resort guests play Harbour Town?', answer: 'Yes, though Sea Pines Resort guests receive preferred tee times. Green fees range from $200 to $400 depending on season.' }, { question: 'Why is Harbour Town so short compared to other Tour courses?', answer: 'At approximately 7,200 yards for Tour events, tight fairways, small greens, overhanging trees, and coastal winds make it play much harder than the yardage suggests.' }, { question: 'When is the RBC Heritage played?', answer: 'The RBC Heritage is typically held in April, the week after the Masters.' }, { question: 'Can I see the lighthouse up close?', answer: 'Yes. The Harbour Town Lighthouse is open to the public with panoramic views of Calibogue Sound and the 18th hole.' }] },
    { id: 'sav-5', name: 'Palmetto Bluff - May River Golf Club', slug: 'may-river-golf-club', city: 'Bluffton', state: 'South Carolina', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 2004, holes: 18, par: 72, yardage: 7171, description: 'A Jack Nicklaus Signature design at the Montage Palmetto Bluff, May River winds through pristine Lowcountry landscape along the banks of the May River. The layout through live oak canopies, tidal marshes, and native Lowcountry terrain delivers one of the most beautiful rounds in the Southeast.', highlights: ['Jack Nicklaus Signature at Montage Palmetto Bluff', 'May River Lowcountry routing', 'Pristine live oak and tidal marsh setting'], imageAlt: 'May River Golf Club Jack Nicklaus fairway through Lowcountry live oaks at Palmetto Bluff', history: 'May River Golf Club at Montage Palmetto Bluff was designed by Jack Nicklaus as a Signature Course (personally overseeing every aspect) and opened in 2004. Named South Carolina\\\'s "Best New Course" the year it opened. Set within the 20,000-acre Palmetto Bluff community in Bluffton.\n\nThe routing winds through four distinct forest types — upland pine, maritime, live oaks, and hardwood — along the banks of the May River. A Coore & Crenshaw course is being added to the community.\n\nAccess available to Montage Palmetto Bluff resort guests.', signatureHoles: [{ hole: 7, par: 4, yardage: 400, description: 'One of several holes brushing directly along the May River banks, with 300-year-old live oaks creating cathedral-like corridors. The river views and natural beauty make this stretch unforgettable.' }], whatToExpect: 'Wide, inviting fairways past centuries-old live oaks and along the May River. Four distinct forest types give each stretch a unique character. The greens provide the real defense — more complex than they first appear.\n\nAccess through Montage Palmetto Bluff resort. Private for non-guests.', playingTips: 'Generous fairways reward accuracy over power. The greens are the real defense — read carefully.\n\nWind off the May River affects exposed holes. Factor it into every club choice.', faqs: [{ question: 'Can non-members play?', answer: 'Yes — guests at Montage Palmetto Bluff have access.' }, { question: 'Who designed it?', answer: 'Jack Nicklaus Signature Course, opened 2004.' }]},
    { id: 'sav-6', name: 'Colleton River Club - Dye Course', slug: 'colleton-river-dye', city: 'Bluffton', state: 'South Carolina', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Pete Dye', yearBuilt: 1992, holes: 18, par: 72, yardage: 7019, description: 'A Pete Dye design on the banks of the Colleton River near Hilton Head, this private club features dramatic marsh-front holes, Dye\'s trademark visual intimidation, and some of the most scenic river views in the Lowcountry. The layout demands precise shot placement on every approach.', highlights: ['Pete Dye Lowcountry marsh-front design', 'Dramatic Colleton River views', 'Premium Bluffton private club near Hilton Head'], imageAlt: 'Colleton River Dye Course marsh-front fairway overlooking Colleton River', history: 'Colleton River Club\\\'s Dye Course was designed by Pete Dye in 1998, complementing the existing Jack Nicklaus course (1991) to create a 36-hole private community along the Chechessee River and Port Royal Sound near Hilton Head. Consistently ranked among South Carolina\\\'s top private layouts.\n\nDye placed many small bunkers in visually intimidating but sometimes strategically irrelevant positions — a classic Dye mind game. The links-style design with holes raised above the landscape feels like a proper links with firm, fast conditions. Over half the holes feature open water and marsh views.', signatureHoles: [{ hole: 15, par: 4, yardage: 420, description: 'Part of the dramatic holes 12-15 stretch playing directly along tidal marshlands and Port Royal Sound with unobstructed Atlantic Ocean views. The most scenic and demanding sequence on the course.' }], whatToExpect: 'A links-style Dye design with holes raised above the landscape, separated by mounding. Tidal marsh provides a constantly changing backdrop. Firm, fast conditions. Wind off Port Royal Sound is the major variable.\n\nThe club also features an Augusta National-style par-3 course. The Dye Clubhouse wraparound porches overlook the finishing holes with Chechessee River and marsh views.\n\nPrivate — 36-hole community with Nicklaus and Dye courses.', playingTips: 'Wind off Port Royal Sound changes direction and intensity rapidly on exposed holes. Trust your yardages over your eyes — Dye\\\'s visual deception is deliberate.\n\nSmall decorative bunkers can distract from the real hazards. Focus on the actual strategic elements.\n\nThe slope of 145 from the tips confirms this is a stern test.', faqs: [{ question: 'How does the Dye Course compare to the Nicklaus?', answer: 'The Dye is more links-style with firm, fast conditions and visual deception. The Nicklaus is more traditional parkland. Together they create one of the finest 36-hole private communities in the Lowcountry.' }, { question: 'What is the par-3 course?', answer: 'An Augusta National-style par-3 course on the property — a bonus for members alongside the two championship 18s.' }]},
    { id: 'sav-7', name: 'Savannah Golf Club', slug: 'savannah-golf-club', city: 'Savannah', state: 'Georgia', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Donald Ross', yearBuilt: 1930, holes: 18, par: 72, yardage: 6534, description: 'The oldest golf club in Georgia, Savannah Golf Club features a Donald Ross design on a compact property draped with Spanish moss and ancient live oaks. The intimate layout embodies classic Southern golf with Ross\'s crowned greens and traditional parkland charm in the heart of the city.', highlights: ['Oldest golf club in Georgia', 'Donald Ross classic design', 'Spanish moss and live oak Southern charm'], imageAlt: 'Savannah Golf Club Donald Ross fairway under Spanish moss and live oaks', history: 'The Savannah Golf Club holds the distinction of being the oldest golf club in the United States, with roots tracing back to 1794 when Scottish settlers first played golf on the greens of Savannah. The club was formally established and has operated continuously since the late 18th century, making it a cornerstone of American golf history. The current course property was developed in the early 20th century, and the legendary Donald Ross was brought in to design the 18-hole championship layout that members enjoy today.\n\nRoss crafted a classic 6,534-yard, par-72 course that takes full advantage of the serene Lowcountry setting, with fairways winding beneath towering live oaks draped in Spanish moss. The club underwent a significant clubhouse renovation in 2010, ushering in a new era focused on family and modern amenities while preserving the historic character that has defined Savannah Golf Club for over two centuries.', signatureHoles: [{ hole: 5, par: 4, yardage: 410, description: 'A demanding par 4 that plays through a corridor of live oaks, requiring a precise tee shot to set up an approach to one of Ross\'s classic crowned greens that repels anything but an accurate iron shot.' }, { hole: 9, par: 4, yardage: 425, description: 'The finishing hole of the front nine doglegs through moss-draped trees with a challenging approach to an elevated green complex that showcases Ross\'s design philosophy of rewarding precision over power.' }, { hole: 15, par: 3, yardage: 185, description: 'A picturesque par 3 framed by ancient oaks, with a well-bunkered green that demands careful club selection and a high, soft landing shot to hold the putting surface.' }], whatToExpect: 'Savannah Golf Club offers an intimate, historic golf experience unlike any other in America. The compact Donald Ross layout winds through one of the most beautiful settings in Southern golf, with ancient live oaks creating cathedral-like canopies over the fairways. The course plays shorter than modern championship layouts at 6,534 yards, but Ross\'s crowned greens and strategic bunkering demand precision and creativity.\n\nAs a private club, the atmosphere is refined and unhurried. The Lowcountry landscape provides a serene backdrop with abundant wildlife and the distinctive Spanish moss that defines the Savannah aesthetic. The course is walking-friendly and rewards a thoughtful, strategic approach to each hole.', playingTips: 'Club selection around Ross\'s crowned greens is the key to scoring well at Savannah Golf Club. These convex putting surfaces shed approach shots that miss the center, so aim for the middle of greens rather than chasing pins on the edges. A reliable bump-and-run game is valuable for the many shots around the greens where the ball needs to be kept low under overhanging oak branches.\n\nThe course rewards accuracy off the tee more than distance. Focus on hitting fairways to give yourself the best angles into the well-defended greens. The flat Lowcountry terrain means drainage can be an issue after rain, so expect softer conditions in the winter months.', faqs: [{ question: 'Is Savannah Golf Club really the oldest golf club in America?', answer: 'Yes, Savannah Golf Club traces its origins to 1794, making it the oldest golf club in the United States. Scottish settlers brought the game to Savannah, and the club has maintained a continuous presence in the city since the late 18th century.' }, { question: 'Can the public play Savannah Golf Club?', answer: 'No, Savannah Golf Club is a private members-only club. Access requires membership or an invitation from a current member. The club focuses on providing an exclusive, intimate experience for its members and their guests.' }, { question: 'Who designed the current course?', answer: 'The legendary Donald Ross designed the current 18-hole layout. Ross, one of the most celebrated golf course architects in history, created a classic parkland course that takes full advantage of the beautiful Lowcountry setting with his trademark crowned greens and strategic bunkering.' }] },
    { id: 'sav-8', name: 'Crosswinds Golf Club', slug: 'crosswinds-golf-club-savannah', city: 'Savannah', state: 'Georgia', type: 'public', rating: 4.0, greensFee: '$30–$55', architect: 'Mark McCumber', yearBuilt: 2001, holes: 27, par: 72, yardage: 6921, description: 'A Mark McCumber design offering 27 affordable public holes in Savannah, Crosswinds provides solid municipal-quality golf through native Lowcountry terrain with tidal marsh views and mature hardwoods. Three distinct nines allow varied routing combinations for repeat play.', highlights: ['27 holes of affordable public golf', 'Mark McCumber Lowcountry design', 'Three nine-hole rotations for variety'], imageAlt: 'Crosswinds Golf Club public fairway through Lowcountry terrain in Savannah', history: 'Crosswinds Golf Club was designed by Mark McCumber and Michael Beebe, featuring 27 holes — an 18-hole championship course and a lighted 9-hole par-3 course. Consistently ranked among Georgia\\\'s top 20 public courses and regarded as Savannah\\\'s best public golf value.\n\nThe championship course features an unusual five par 3s and five par 5s (rather than the standard four of each), creating a distinctive scoring rhythm. Completed course improvements in October 2024. Conveniently located near the Savannah airport.', signatureHoles: [{ hole: 9, par: 5, yardage: 530, description: 'One of five par 5s offering the best scoring opportunities. The five-par-5, five-par-3 configuration creates a unique rhythm where birdie chances balance against demanding short holes.' }], whatToExpect: 'Well-maintained fairways and greens — frequently praised as the best conditions among Savannah public courses. Mature trees frame the fairways throughout. The par-3 course (60-150 yards) is lighted for evening play.\n\nThree nines allow varied 18-hole combinations for repeat play. Greens play fairly fast with noticeable grain.\n\nPublic at approximately $72 for 18 with cart — strong value near the Savannah airport.', playingTips: 'Greens have significant grain — expect slower putts against it than anticipated. Read carefully.\n\nThe five par 5s are the best scoring opportunities. Position off the tee matters more than distance on tree-lined holes.\n\nConveniently located near the airport — ideal for a round before or after a flight.', faqs: [{ question: 'Is it the best public course in Savannah?', answer: 'Widely regarded as Savannah\\\'s best public golf value. Consistently ranked among Georgia\\\'s top 20 public courses.' }, { question: 'What is the par-3 course?', answer: 'A lighted 9-hole par-3 course (60-150 yards) for evening play — a unique bonus alongside the championship 27 holes.' }]},
    { id: 'sav-9', name: 'Savannah Golf Club', slug: 'savannah-golf-club', city: 'Savannah', state: 'Georgia', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Donald Ross (1920s renovation)', yearBuilt: 1899, holes: 18, par: 72, yardage: 6574, description: 'Established in 1899, Savannah Golf Club is one of the oldest courses in Georgia. The Donald Ross-renovated layout winds through moss-draped live oaks in a serene Lowcountry setting. The classic short course rewards precision and touch around Ross\'s signature crowned greens.', highlights: ['One of Georgia\'s oldest clubs since 1899', 'Donald Ross renovation with crowned greens', 'Moss-draped live oak Lowcountry setting'], imageAlt: 'Savannah Golf Club historic fairway through moss-draped live oaks', history: 'Savannah Golf Club traces its origins to 1794, when Scottish merchants in the port city of Savannah began playing golf, making it the oldest golf club in America. The club was formally reorganized in 1899 on its current property and has been a fixture of Savannah\'s sporting and social life ever since. In the 1920s, the renowned golf course architect Donald Ross was commissioned to renovate the course, bringing his signature design elements to the historic layout.\n\nRoss reshaped the greens with his trademark crowned surfaces, added strategic bunkering, and refined the routing through the property\'s magnificent live oak canopy. The result is a classic 6,574-yard, par-72 course that embodies the charm and tradition of Southern golf. The club has maintained its intimate character through the decades, with a new clubhouse completed in 2010 that modernized facilities while honoring the club\'s extraordinary heritage as America\'s oldest golf institution.', signatureHoles: [{ hole: 7, par: 4, yardage: 395, description: 'A classic Ross par 4 that requires a well-placed drive through the oak-lined corridor. The approach plays to a crowned green with deep bunkers left and right, punishing anything less than a precise iron shot.' }, { hole: 12, par: 3, yardage: 175, description: 'A beautiful mid-length par 3 set beneath a canopy of Spanish moss-draped oaks. The green features Ross\'s classic crowned design with falloff areas on all sides that make par a satisfying achievement.' }, { hole: 18, par: 4, yardage: 420, description: 'A strong finishing par 4 that brings players back toward the historic clubhouse. The tee shot must navigate mature oaks, and the approach plays to an elevated Ross green that provides a fitting conclusion to the round.' }], whatToExpect: 'Playing Savannah Golf Club is a walk through American golf history. The intimate Donald Ross layout winds beneath towering live oaks draped in Spanish moss, creating one of the most atmospheric settings in Southern golf. At 6,574 yards, the course plays shorter than modern designs, but Ross\'s crowned greens and strategic bunkering provide a genuine test of precision and shot-making.\n\nThe private club maintains a relaxed, unhurried pace that complements the historic surroundings. Wildlife including herons, egrets, and songbirds are common companions during a round. The flat Lowcountry terrain makes for an enjoyable walk, and the course rewards thoughtful play over raw power.', playingTips: 'Success at Savannah Golf Club hinges on mastering Ross\'s crowned greens. These convex putting surfaces reject approach shots that land on the edges, so always favor the center of the green regardless of pin position. A strong short game with reliable chipping and pitching is essential for recovering from the collection areas that surround most greens.\n\nKeep the ball in play off the tee. The oak-lined fairways are not excessively narrow but wayward drives that end up behind tree trunks create difficult recovery situations. The course is best enjoyed as a strategic puzzle rather than a power game, so consider leaving the driver in the bag on shorter par 4s where a long iron or hybrid will find the fairway more reliably.', faqs: [{ question: 'How old is Savannah Golf Club?', answer: 'Savannah Golf Club is the oldest golf club in America, with origins dating to 1794. The club was formally reorganized in 1899, and Donald Ross renovated the course in the 1920s.' }, { question: 'Is Savannah Golf Club open to the public?', answer: 'No, it is a private members-only club. Guests may play when accompanied by a member. The club maintains an intimate, exclusive atmosphere focused on its membership.' }, { question: 'What is the course like?', answer: 'The Donald Ross-designed course plays 6,574 yards, par 72 through moss-draped live oaks in a classic Lowcountry setting. Ross\'s crowned greens are the course\'s defining feature, rewarding precise approach shots and creative short-game play.' }, { question: 'What makes the course historically significant?', answer: 'Beyond being America\'s oldest golf club, the course features the design work of Donald Ross, one of golf\'s most celebrated architects. The combination of historic pedigree and Ross\'s timeless design makes it a unique piece of American golf heritage.' }] },
    { id: 'sav-10', name: 'Palmetto Electric - Club at Savannah Harbor', slug: 'club-at-savannah-harbor', city: 'Savannah', state: 'Georgia', type: 'resort', rating: 4.2, greensFee: '$80–$150', architect: 'Bob Cupp & Sam Snead', yearBuilt: 1999, holes: 18, par: 72, yardage: 7288, description: 'A Bob Cupp and Sam Snead co-design on Hutchinson Island overlooking downtown Savannah\'s historic skyline across the Savannah River, The Club at Savannah Harbor delivered resort golf at the Westin Savannah Harbor. The waterfront layout features tidal marsh views, strategic water hazards, and Lowcountry landscape.', highlights: ['Downtown Savannah skyline views across the river', 'Bob Cupp and Sam Snead resort co-design', 'Hutchinson Island waterfront setting'], imageAlt: 'Club at Savannah Harbor fairway with downtown Savannah skyline across the river', history: 'The Club at Savannah Harbor opened in 1999 on Hutchinson Island, designed by Bob Cupp and Sam Snead — one of Snead\\\'s final course design projects. The course hosted the Liberty Mutual Legends of Golf on the Champions Tour.\n\nThe island setting in the Savannah River creates panoramic views of the historic Savannah skyline across the water. Managed by Troon Golf at the Westin Savannah Harbor resort.', signatureHoles: [{ hole: 16, par: 4, yardage: 420, description: 'One of several holes with dramatic views of the historic Savannah skyline across the river. Tidal wetlands and the city\\\'s church steeples as backdrop create a unique visual experience.' }], whatToExpect: 'Tidal wetland routing with panoramic downtown Savannah skyline views. Resort-friendly playability with genuine challenge from the back tees at 7,288 yards. Wind off the river is constant.\n\nResort access at the Westin at $80-150. Historic district a short ferry ride away.', playingTips: 'Wind off the Savannah River is constant. Wetland carries look longer than they are. Select appropriate tees.', faqs: [{ question: 'Can you see the Savannah skyline?', answer: 'Yes — panoramic views of the historic skyline across the river from multiple holes.' }]},
    { id: 'sav-11', name: 'Savannah Quarters Country Club', slug: 'savannah-quarters-cc', city: 'Pooler', state: 'Georgia', type: 'semi-private', rating: 4.1, greensFee: '$45–$80', architect: 'Greg Norman', yearBuilt: 2005, holes: 18, par: 72, yardage: 7061, description: 'A Greg Norman design in Pooler west of Savannah, Savannah Quarters offers semi-private access to a well-maintained championship layout. The 7,061-yard course features typical Norman design elements including strategic water hazards, waste bunkers, and native Lowcountry vegetation on a gently rolling property.', highlights: ['Greg Norman semi-private design', 'Well-maintained championship layout', 'Strategic water and waste bunker features'], imageAlt: 'Savannah Quarters Country Club Greg Norman fairway in Pooler Georgia', history: 'Savannah Quarters is a Greg Norman Signature Design in Pooler west of Savannah, completely redesigned and reconstructed by Norman\\\'s firm into what they call a Lowcountry masterpiece. Managed by Troon Golf and operated by Heritage Golf Group.\n\nThe course threads through classic Lowcountry terrain with elevation changes rare for the Savannah area, wetland carries, and mature oaks. Six sets of tees accommodate all skill levels. Norman designed risk-reward options throughout.', signatureHoles: [{ hole: 4, par: 3, yardage: 185, description: 'Part of the standout holes 3-5 stretch — a demanding par 5 followed by a testing par 3 and another par 5. This three-hole gauntlet defines the round and showcases Norman\\\'s strategic Lowcountry design.' }], whatToExpect: 'A well-conditioned layout with wide fairways rewarding positioning over power. Water comes into play frequently from the Lowcountry marshes. Wind off the marshes alters club selection.\n\nSemi-private — outside play available around $50 for 18 with cart. Full amenities including swim and fitness center.', playingTips: 'Take advantage of six tee boxes — play the right yardage for your game.\n\nCourse management over distance. Norman designed risk-reward options throughout.\n\nKeep the ball below the hole on well-defended greens.', faqs: [{ question: 'Who designed it?', answer: 'Greg Norman Signature Design, completely redesigned and reconstructed into a Lowcountry masterpiece. Managed by Troon Golf.' }, { question: 'Is it open to outside play?', answer: 'Semi-private — outside play available around $50 for 18 with cart, though it primarily operates as a private community club.' }]},
  ],
  'charleston-south-carolina': [
    { id: 'chs-1', name: 'Kiawah Island - Ocean Course', slug: 'kiawah-ocean-course', city: 'Kiawah Island', state: 'South Carolina', type: 'resort', rating: 4.9, greensFee: '$250–$450', architect: 'Pete Dye', yearBuilt: 1991, holes: 18, par: 72, yardage: 7356, description: 'Host of the 1991 "War by the Shore" Ryder Cup and the 2012 and 2021 PGA Championships, Kiawah\'s Ocean Course is Pete Dye\'s windswept masterpiece. Built with every hole offering views of the Atlantic Ocean, it is the most challenging and exposed seaside course in the United States.', highlights: ['2021 PGA Championship and 1991 Ryder Cup host', 'Every hole has Atlantic Ocean views', 'Pete Dye\'s most exposed seaside design'], imageAlt: 'Kiawah Island Ocean Course windswept fairway along the Atlantic Ocean', history: 'The Ocean Course was built at a furious pace by Pete and Alice Dye from 1989 to 1991, opening just in time to host the 1991 Ryder Cup — the famous "War by the Shore" decided on the final putt by Bernhard Langer. The course was originally intended to sit behind the dunes, but Alice Dye suggested raising the fairways so that every hole would have ocean views, a decision that made it the most exposed seaside course in North America with 10 holes directly along the Atlantic.\n\nThe Ocean Course has since hosted the 2012 PGA Championship, won by Rory McIlroy with a record 13-under total, and the 2021 PGA Championship, claimed by Phil Mickelson at age 50 to become the oldest major champion in history. The course was also selected to host the 2031 Ryder Cup. Over its lifetime, Dye has made subtle refinements to tees and bunkering, but the essential design remains a tribute to the wild, windswept links courses of the British Isles.', signatureHoles: [{ hole: 17, par: 3, yardage: 223, description: 'A brutally long par 3 played along the ocean with the wind typically howling off the Atlantic. All carry over sandy waste, the green is shallow and well-bunkered. This hole was pivotal in the 1991 Ryder Cup and remains one of the most feared par 3s in championship golf.' }, { hole: 18, par: 4, yardage: 452, description: 'A dramatic finishing hole that doglegs right along Kiawah\'s coastline. The approach must carry a marshy inlet to reach a green perched near the dunes. The ocean provides a stunning backdrop for what is often a pressure-packed final shot.' }, { hole: 2, par: 5, yardage: 557, description: 'A sweeping par 5 that transitions from the interior to the ocean, offering the first full Atlantic vista. The fairway bends left around sand dunes, and the elevated green complex provides expansive views up and down the coastline.' }, { hole: 13, par: 4, yardage: 404, description: 'A gorgeous par 4 that plays along the marsh with the ocean beyond. The fairway is framed by dunes on the left and wetlands on the right, demanding a precise drive to set up an approach to a well-defended green.' }], whatToExpect: 'The Ocean Course is one of the most exposed and windswept layouts in American golf. Every hole offers views of the Atlantic Ocean, and the course is routed so that the wind direction changes constantly — no two consecutive holes play in the same direction. Expect dramatic elevation changes between dune ridges and low-lying marsh areas, with sandy waste areas, sea grasses, and Dye\'s signature railroad-tie bulkheads throughout.\n\nThis is a genuinely difficult test of golf. The course rating from the championship tees is 77.2 with a slope of 144. Even from the resort tees at around 6,200 yards, the wind makes club selection a constant challenge. Caddie service is mandatory and highly recommended — the local caddies\' knowledge of wind patterns and green reads is invaluable.', playingTips: 'Wind management is the single most important skill at the Ocean Course. Bring your low-trajectory shots and expect to hit knockdown irons throughout the round. The wind typically blows 15-25 mph, and on gusty days it can reach 30-40 mph, changing a wedge shot into a 5-iron.\n\nPlay from appropriate tees — the course is a brute from the tips and most golfers will enjoy it far more from the resort tees. Trust your caddie on club selection and green reads. The greens are firm and fast, so plan to land approach shots short and let them feed onto the putting surfaces. Bring plenty of extra golf balls.', faqs: [{ question: 'How difficult is the Ocean Course?', answer: 'It is widely considered one of the toughest courses in America. The combination of wind, length (7,356 yards from the tips), and exposed seaside terrain makes it extraordinarily challenging. Play from the forward tees and use a caddie to maximize enjoyment.' }, { question: 'Do I need a caddie at the Ocean Course?', answer: 'Caddie service is mandatory during walking-only periods and strongly recommended at all times. The caddies are experienced, know the wind patterns intimately, and can save you multiple strokes per round. Forecaddies are also available for cart riders.' }, { question: 'Can non-resort guests play the Ocean Course?', answer: 'Yes, but resort guests at Kiawah Island Golf Resort receive priority access and better rates. Non-guest green fees are typically $250-$450 depending on season. Advance booking is strongly recommended, especially in spring and fall.' }, { question: 'What is the best season to play the Ocean Course?', answer: 'Spring (April-May) and fall (September-October) offer the most pleasant conditions. Summer is hot and humid, while winter can bring cold winds off the Atlantic. Wind is always a factor regardless of season.' }] },
    { id: 'chs-2', name: 'Yeamans Hall Club', slug: 'yeamans-hall-club', city: 'Hanahan', state: 'South Carolina', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Seth Raynor / Tom Doak (restoration)', yearBuilt: 1925, holes: 18, par: 72, yardage: 6598, description: 'A rare Seth Raynor design in the Charleston Lowcountry, Yeamans Hall was comprehensively restored by Tom Doak in 1998. The intimate layout through live oaks and magnolias features Raynor\'s template holes — Redan, Biarritz, Cape — on a historic plantation property north of Charleston.', highlights: ['Seth Raynor template design restored by Tom Doak', 'Historic Lowcountry plantation property', 'Classic Redan, Biarritz, and Cape holes'], imageAlt: 'Yeamans Hall Club Seth Raynor fairway through Lowcountry live oaks near Charleston', history: 'Yeamans Hall Club was established in 1925 on a 1,100-acre plantation tract about 12 miles north of Charleston in Hanahan, South Carolina. Seth Raynor designed the golf course, bringing his trademark template holes to the Lowcountry landscape. James Gamble Rogers designed the buildings.\n\nRaynor, a protege of Charles Blair Macdonald, created versions of his famous Redan, Biarritz, Cape, and Principal\'s Nose holes adapted to the flat coastal terrain and framed by centuries-old live oaks draped in Spanish moss.\n\nIn 1998, Tom Doak completed a comprehensive restoration returning the course to Raynor\'s original design. The restoration earned widespread acclaim and helped elevate Yeamans Hall into national Top 100 rankings.', signatureHoles: [{ hole: 1, par: 4, yardage: 425, description: 'A dramatic opener featuring Raynor\'s Principal\'s Nose bunker complex in the landing area, forcing an immediate strategic decision. One of the best opening holes in the South.' }, { hole: 5, par: 3, yardage: 195, description: 'Raynor\'s Redan hole, where the green angles away and a deep bunker guards the front left. The ball must be played to the high right and fed down to the pin.' }, { hole: 9, par: 4, yardage: 360, description: 'A short but strategic par 4 with a Biarritz green featuring a deep swale through the center of the putting surface.' }, { hole: 17, par: 3, yardage: 170, description: 'A beautiful par 3 framed by live oaks and marsh in a quintessential Lowcountry setting.' }], whatToExpect: 'Yeamans Hall is a quiet, exclusive retreat where golf takes center stage. The course winds through ancient live oaks draped in Spanish moss and along marsh edges. At 6,598 yards, it challenges with Raynor\'s strategic template designs rather than overpowering length.\n\nDoak\'s restoration sharpened every green complex and bunker. The intimate scale and low-key atmosphere make it one of the most enjoyable experiences in the Charleston area.', playingTips: 'Understanding Raynor\'s template holes is essential. Study the Redan (play to the high side), Biarritz (avoid the swale), and Cape (bite off as much as you dare) before your round.\n\nThe course is short enough that accuracy and green-reading are far more important than distance. The greens have significant movement that can be deceptive on the flat terrain.', faqs: [{ question: 'Can the public play Yeamans Hall?', answer: 'No. Yeamans Hall is an exclusive private club with no public access.' }, { question: 'What are template holes?', answer: 'Seth Raynor designed holes based on famous templates from great British courses. The Redan, Biarritz, Cape, and Principal\'s Nose each have specific strategic characteristics.' }, { question: 'Who restored Yeamans Hall?', answer: 'Tom Doak completed a comprehensive restoration in 1998 that returned the course to Seth Raynor\'s original design intent.' }, { question: 'How old is the property?', answer: 'The 1,100-acre plantation tract has centuries of history. The club was established in 1925, and the ancient live oaks are hundreds of years old.' }] },
    { id: 'chs-3', name: 'Charleston Municipal Golf Course', slug: 'charleston-municipal', city: 'Charleston', state: 'South Carolina', type: 'public', rating: 4.1, greensFee: '$25–$50', architect: 'Seth Raynor', yearBuilt: 1927, holes: 18, par: 72, yardage: 6411, description: 'A remarkably well-preserved Seth Raynor municipal design in downtown Charleston, "The Muni" offers template hole architecture at city-course pricing. The flat Lowcountry layout features Raynor\'s trademark Redan, Punchbowl, and Short holes, making it one of the most architecturally significant public courses in the South.', highlights: ['Seth Raynor municipal course — rare architectural gem', 'Template holes at city-course pricing', 'Downtown Charleston Lowcountry location'], imageAlt: 'Charleston Municipal Golf Course Seth Raynor template hole in downtown Charleston', history: 'Charleston Municipal Golf Course was transformed in a 2019-2020 renovation led by architect Troy Miller into a deliberate homage to Golden Age architect Seth Raynor. Miller\\\'s redesign brought famous template holes — Redan, Punchbowl, Short — typically found only at elite private clubs like nearby Yeamans Hall to an affordable city-owned public course.\n\nThe result turned a modest muni into one of the most architecturally interesting public courses in the country. Golf Digest recognized the renovation. Located just 10 minutes from downtown Charleston at city-course pricing ($25-50).', signatureHoles: [{ hole: 5, par: 3, yardage: 165, description: 'The Redan — modeled on Raynor\\\'s famous template with a green angled away from the player and a backstop feeding balls toward the pin. A world-class green design you can play in blue jeans at municipal pricing.' }, { hole: 6, par: 4, yardage: 380, description: 'The Punchbowl — features a dramatic punchbowl green where shots funnel toward the center. A blind approach over hidden bunkers makes club selection and trajectory critical. Template architecture at its finest.' }], whatToExpect: 'An affordable public course with private-club-quality architecture. Walkable and relatively short, emphasizing angles, ground game, and strategic thinking over power. Bold Raynor-inspired green contours throughout.\n\nOne of the best ways for public-access golfers to experience template hole architecture otherwise locked behind exclusive private gates.\n\nCity-owned at $25-50 — extraordinary value for the architectural significance.', playingTips: 'Study green contours before putting — the template greens have built-in slopes working for or against you.\n\nThe Redan green rewards shots to the high side. On punchbowl greens, use the slopes rather than fighting them.\n\nBump-and-run approaches are often smarter than lofted wedges on these classic green complexes.', faqs: [{ question: 'Are these real Raynor template holes?', answer: 'The 2019-2020 Troy Miller renovation was a deliberate homage to Seth Raynor\\\'s templates — Redan, Punchbowl, Short — bringing private-club architecture to a $25-50 municipal course.' }, { question: 'How close to downtown Charleston?', answer: 'About 10 minutes. One of the most accessible golf experiences in the city.' }]},
    { id: 'chs-4', name: 'Wild Dunes Resort - Links Course', slug: 'wild-dunes-links', city: 'Isle of Palms', state: 'South Carolina', type: 'resort', rating: 4.3, greensFee: '$100–$200', architect: 'Tom Fazio', yearBuilt: 1980, holes: 18, par: 72, yardage: 6722, description: 'A Tom Fazio design on the Isle of Palms near Charleston, Wild Dunes Links features two dramatic oceanfront finishing holes along the Atlantic. The resort layout winds through maritime forest and salt marsh before reaching the beachfront crescendo of holes 17 and 18.', highlights: ['Tom Fazio oceanfront finishing holes', 'Isle of Palms beachside setting', 'Maritime forest and salt marsh routing'], imageAlt: 'Wild Dunes Links Course Tom Fazio oceanfront finishing holes on Isle of Palms', history: 'Wild Dunes Links Course was designed by Tom Fazio and opened in 1980 on the Isle of Palms, a barrier island northeast of Charleston. One of two Fazio courses at the resort (the Harbor Course is the other). The layout moves through maritime forest, tidal marshes, and rolling dune ridges before the dramatic Atlantic Ocean finishing stretch.\n\nHoles 17 and 18 play directly along the Atlantic with the beach as a lateral hazard — consistently cited as two of the most dramatic finishing holes in Lowcountry golf. The barrier island setting gives the course a genuine coastal links character rare on the East Coast.', signatureHoles: [{ hole: 17, par: 4, yardage: 400, description: 'The first of the famous oceanfront finishing pair. Plays directly along the Atlantic Ocean with the beach as a lateral hazard. Wind off the ocean makes club selection a guessing game while the scenery is among the most photographed in South Carolina golf.' }, { hole: 18, par: 4, yardage: 420, description: 'The oceanfront closer completing one of the most dramatic two-hole finishes in Lowcountry golf. Atlantic breezes, beach hazard, and the roar of waves create an unforgettable conclusion to the round.' }], whatToExpect: 'The front nine plays through trees and lagoons. The back nine opens with marsh and ocean views, building to the stunning 17-18 oceanfront finish along the Atlantic. Homes line interior holes but the seaside finale erases any residential feel.\n\nAtlantic breezes are constant, especially on the closing holes. Golf Digest has recognized Wild Dunes for exceptional conditions.\n\nResort access at $100-200. About 30 minutes from downtown Charleston.', playingTips: 'Play the wind on 17 and 18 — ocean gusts can add or subtract two clubs. Par is a great score when the wind is up.\n\nWide interior fairways reward aggressive tee shots, but the ocean holes demand conservative strategy.\n\nBring extra balls for the beach-side holes.', faqs: [{ question: 'What makes the finish special?', answer: 'Holes 17 and 18 play directly along the Atlantic Ocean with the beach as a lateral hazard. Two of the most dramatic finishing holes in Lowcountry golf.' }, { question: 'How far from Charleston?', answer: 'About 30 minutes from downtown Charleston on the Isle of Palms barrier island.' }]},
    { id: 'chs-5', name: 'Daniel Island Club - Ralston Creek', slug: 'daniel-island-ralston-creek', city: 'Charleston', state: 'South Carolina', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Rees Jones', yearBuilt: 2000, holes: 18, par: 72, yardage: 7093, description: 'A Rees Jones design on Daniel Island in Charleston Harbor, Ralston Creek winds through Lowcountry marsh and maritime forest with sweeping views of the Wando River. The private layout features strategic tidal creek hazards and immaculate conditioning in an upscale island community.', highlights: ['Rees Jones Lowcountry marsh design', 'Wando River and Charleston Harbor views', 'Upscale Daniel Island community'], imageAlt: 'Daniel Island Ralston Creek Course fairway along Charleston Harbor marsh', history: 'Daniel Island Club\\\'s Ralston Creek Course was designed by Rees Jones and opened in 2006 as the second of two championship courses on Daniel Island (Tom Fazio\\\'s Beresford Creek opened in 2000). At 7,446 yards from the tips, it winds through Lowcountry marsh and maritime forest with the Wando River shaping the routing.\n\nJones ("The Open Doctor") brought the same strategic rigor he uses on major championship venues. The two courses offer contrasting philosophies — Fazio\\\'s more parkland Beresford Creek versus Jones\\\'s more exposed, links-influenced Ralston Creek. Both are nationally ranked.', signatureHoles: [{ hole: 14, par: 4, yardage: 440, description: 'One of several holes playing along or toward the Wando River, with tidal marsh views and creek hazards creating visual drama and strategic challenge. The links-influenced exposure to wind makes it play differently every day.' }], whatToExpect: 'A long, demanding private layout at nearly 7,450 yards from the tips. Rees Jones\\\'s emphasis on strategic angles off the tee and challenging approaches to well-defended greens. Tidal marsh and the Wando River create natural hazards throughout.\n\nThe club describes choosing between Beresford Creek and Ralston Creek as being like choosing between pecan and peach pie.\n\nPrivate — Daniel Island community about 20 minutes from downtown Charleston.', playingTips: 'Tee shot placement is critical — Jones creates holes where approach angle matters as much as distance.\n\nPlay correct tees. At 7,446 yards from the back, this is a significant test.\n\nWind exposure near the Wando River changes club selection significantly.', faqs: [{ question: 'How does it compare to the Fazio course?', answer: 'The Fazio Beresford Creek is more parkland-style; the Jones Ralston Creek is more exposed and links-influenced. The club calls it like choosing between pecan and peach pie.' }, { question: 'Can the public play?', answer: 'No — private club on Daniel Island, about 20 minutes from downtown Charleston.' }]},
    { id: 'chs-6', name: 'Kiawah Island - Osprey Point', slug: 'kiawah-osprey-point', city: 'Kiawah Island', state: 'South Carolina', type: 'resort', rating: 4.3, greensFee: '$125–$250', architect: 'Tom Fazio', yearBuilt: 1988, holes: 18, par: 72, yardage: 6932, description: 'A Tom Fazio design at Kiawah Island Resort, Osprey Point winds through natural lakes, tidal marshes, and maritime forest teeming with wildlife. Compared to the Ocean Course, Osprey Point offers a more sheltered, nature-immersive experience with abundant alligator and bird sightings.', highlights: ['Tom Fazio nature-immersive Kiawah design', 'Tidal marsh and maritime forest wildlife', 'More sheltered alternative to Ocean Course'], imageAlt: 'Kiawah Osprey Point Tom Fazio fairway through tidal marsh and maritime forest', history: 'Osprey Point opened in 1988 as Tom Fazio\'s contribution to the growing collection of world-class courses at Kiawah Island Golf Resort. Fazio originally conceived the course as a members-only layout, designing it with generous fairways, strategic water features, and a nature-immersive routing through the island\'s interior marshlands, lakes, and maritime forest. The course quickly became a favorite among resort guests for its playability and stunning natural beauty.\n\nIn 2014, Osprey Point underwent a comprehensive renovation under Tom Fazio\'s direction. The project included regrassing all tees, greens, and fairways with Paspalum, a salt-tolerant turf ideal for the coastal environment. Fazio also refined the bunkering and green complexes while maintaining the original character of the layout. The renovation elevated Osprey Point\'s conditioning to match the resort\'s flagship Ocean Course while preserving its reputation as a more welcoming, wildlife-rich alternative to Kiawah\'s more exposed seaside layouts.', signatureHoles: [{ hole: 11, par: 3, yardage: 223, description: 'The signature hole at Osprey Point requires a heroic tee shot over a large water hazard to a diagonally set green framed by ancient live oaks. At 223 yards, it is one of the most demanding and photogenic par 3s on Kiawah Island.' }, { hole: 15, par: 4, yardage: 415, description: 'A beautiful par 4 that plays along the edge of a natural lake with marsh and forest pressing in from both sides. The approach shot must carry water to reach a green tucked against the shoreline, demanding both accuracy and nerve.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finishing hole that plays along one of the course\'s four major lakes. The tee shot must favor the right side to open up the best angle into a well-protected green, providing a dramatic conclusion to the round.' }, { hole: 4, par: 5, yardage: 525, description: 'A risk-reward par 5 where long hitters can reach the green in two if they successfully navigate the water that guards the front of the putting surface. The hole winds through maritime forest with wildlife sightings common along the way.' }], whatToExpect: 'Osprey Point offers one of the most nature-immersive golf experiences at Kiawah Island. The course winds through four large natural lakes, fingers of saltwater marsh, and dense maritime forest that teems with wildlife. Alligator sightings are common along the lakeshores, and the course is home to ospreys, herons, egrets, and numerous other bird species that give the course its name.\n\nCompared to the windswept Ocean Course, Osprey Point provides a more sheltered experience with wider fairways and more forgiving landing areas. The Paspalum turf installed during the 2014 renovation provides excellent playing surfaces year-round. The course plays 6,932 yards from the back tees but offers multiple tee options that make it enjoyable for all skill levels.', playingTips: 'While Osprey Point is more forgiving than the Ocean Course, water comes into play on the majority of holes, so course management is essential. Take extra club on approaches that carry water and aim for the fat part of greens rather than chasing tucked pins near hazards. The Paspalum greens can be slower than bermudagrass, so be aggressive with your putting stroke.\n\nThe sheltered interior routing means wind is less of a factor than on Kiawah\'s coastal courses, but sea breezes can still affect shots on exposed holes. Take time to enjoy the wildlife but maintain awareness around the lakeshores where alligators are frequently spotted. Book morning tee times for the best conditions and to maximize your chances of seeing wildlife active along the course.', faqs: [{ question: 'How does Osprey Point compare to the Ocean Course?', answer: 'Osprey Point is significantly more playable and sheltered than the Ocean Course. It features wider fairways, less wind exposure, and a more forgiving layout. Green fees are also considerably lower, making it an excellent choice for golfers who want a premier Kiawah experience without the extreme challenge of the Ocean Course.' }, { question: 'Can non-resort guests play Osprey Point?', answer: 'Yes, Osprey Point is open to the public as part of Kiawah Island Golf Resort. Resort guests receive preferred tee times and pricing, but outside play is available. Green fees typically range from $125 to $250 depending on the season.' }, { question: 'Is the wildlife really that abundant?', answer: 'Absolutely. Osprey Point is one of the best courses in the Southeast for wildlife viewing. Alligators, ospreys, great blue herons, egrets, and deer are regularly seen during rounds. The course\'s routing through natural lakes and marsh creates ideal habitat for diverse wildlife.' }, { question: 'When was the course last renovated?', answer: 'Tom Fazio oversaw a comprehensive renovation in 2014 that included regrassing all playing surfaces with Paspalum, rebuilding bunkers, and refining green complexes. The renovation significantly improved course conditioning while maintaining the original design character.' }] },
    { id: 'chs-7', name: 'Patriots Point Links', slug: 'patriots-point-links', city: 'Mount Pleasant', state: 'South Carolina', type: 'public', rating: 4.0, greensFee: '$35–$70', architect: 'Willard Byrd', yearBuilt: 1981, holes: 18, par: 72, yardage: 6838, description: 'A Willard Byrd design on Charleston Harbor in Mount Pleasant, Patriots Point offers spectacular views of the USS Yorktown aircraft carrier, Fort Sumter, and the Charleston skyline. The affordable links-style layout along the marsh provides one of the most scenic budget-friendly rounds in the Charleston area.', highlights: ['Views of USS Yorktown and Fort Sumter', 'Charleston Harbor and skyline panorama', 'Affordable links-style public golf'], imageAlt: 'Patriots Point Links fairway with USS Yorktown and Charleston Harbor views', history: 'Patriots Point Links was designed by Willard C. Byrd and built in 1979 on the edge of Charleston Harbor in Mount Pleasant — the closest 18-hole course to downtown Charleston. The course sits adjacent to the Patriots Point Naval and Maritime Museum, home of the USS Yorktown aircraft carrier.\n\nThe harbor setting gives it a genuine links-style feel with ocean breezes constantly altering play. Recent updates involved Annika Sorenstam\\\'s design team. The waterfront finishing stretch (holes 15-18) with panoramic views of downtown Charleston is the defining experience.', signatureHoles: [{ hole: 17, par: 4, yardage: 400, description: 'The most scenic hole — plays along Charleston Harbor with panoramic views of the downtown skyline, Ravenel Bridge, Fort Sumter, and the USS Yorktown aircraft carrier. The harbor serves as dramatic backdrop and very real hazard.' }], whatToExpect: 'Interior holes play through typical Lowcountry terrain, but the experience builds toward the spectacular harbor-side finishing stretch. Wind off Charleston Harbor is a constant companion on the closing holes.\n\nViews of the USS Yorktown flight deck, Fort Sumter, the Ravenel Bridge, and ships entering Charleston Harbor make this one of the most visually distinctive public courses in the Southeast.\n\nPublic at $35-70 — among the most scenic budget-friendly rounds near Charleston.', playingTips: 'Harbor wind is the biggest factor. Club up or down on exposed finishing holes.\n\nThe course plays longer than yardage suggests when wind is in your face.\n\nWarm up your short game — the practice facility allows chips up to 50 yards.\n\nThe interior holes are a warmup. Save your best golf for the spectacular 15-18 finish.', faqs: [{ question: 'Can you really see the USS Yorktown?', answer: 'Yes — the WWII aircraft carrier is directly adjacent to the course. You can see the flight deck from several holes.' }, { question: 'How close to downtown Charleston?', answer: 'The closest 18-hole course to downtown — in Mount Pleasant just across the harbor.' }, { question: 'What does it cost?', answer: 'Public at $35-70. Among the most scenic budget-friendly rounds near Charleston.' }]},
    { id: 'chs-8', name: 'Cassique Golf Club', slug: 'cassique-golf-club', city: 'Kiawah Island', state: 'South Carolina', type: 'semi-private', rating: 4.4, greensFee: '$125–$225', architect: 'Tom Watson', yearBuilt: 2000, holes: 18, par: 72, yardage: 6950, description: 'Tom Watson\'s first solo design in the United States, Cassique at Kiawah Island features a links-inspired routing through native Lowcountry landscape. The layout incorporates salt marsh, tidal creeks, and maritime forest with Watson\'s emphasis on strategic ground-game golf and natural shot options.', highlights: ['Tom Watson\'s first U.S. solo design', 'Links-inspired Lowcountry routing', 'Strategic ground-game emphasis'], imageAlt: 'Cassique Golf Club Tom Watson links-style fairway on Kiawah Island', history: 'Cassique opened in 2000 as five-time Open Championship winner Tom Watson\\\'s first course design in North America, part of the private Kiawah Island Club. Watson channeled a British links feel within the Lowcountry landscape, modeling several holes after favorites from Open Championships in Scotland and England.\n\nWide fairways with firm, fast conditions create genuine links golf. Multiple routing options around holes 4-6 give members different experiences each round. Widely considered by many to be the best course on Kiawah Island, even against the famed Ocean Course.', signatureHoles: [{ hole: 9, par: 4, yardage: 420, description: 'Features one of the most deceptive greens in the Southeast — a severely elevated putting surface with a massive false front that rejects anything short, rolling the ball well back down the hill. A classic Watson strategic challenge.' }], whatToExpect: 'Links-inspired Lowcountry golf with wide fairways and firm, fast conditions. The course weaves through marshes, creeks, and maritime forest. Water on nearly every hole but generous fairway widths reward creative shot-making over brute force.\n\nTom Watson designs are extremely rare — Cassique is a genuine collector\\\'s item in course architecture.\n\nPrivate — access requires Kiawah Island Club membership or member invitation.', playingTips: 'Play the ground game — Watson designed this for bump-and-run approaches, not target golf.\n\nClub selection into elevated greens is critical. The false fronts are severe — take enough club.\n\nWind off the marshes shifts significantly hole to hole. Check conditions before every shot.', faqs: [{ question: 'Is this Tom Watson\\\'s only US design?', answer: 'His first North American design. Watson has designed very few courses worldwide, making Cassique a genuine rarity in course architecture.' }, { question: 'Can the public play?', answer: 'No — private Kiawah Island Club. Access requires membership or member invitation.' }]},
  ],
  'jacksonville-florida': [
    { id: 'jax-1', name: 'TPC Sawgrass - Stadium Course', slug: 'tpc-sawgrass-stadium', city: 'Ponte Vedra Beach', state: 'Florida', type: 'resort', rating: 4.8, greensFee: '$250–$500', architect: 'Pete Dye', yearBuilt: 1980, holes: 18, par: 72, yardage: 7245, description: 'Home of THE PLAYERS Championship — the PGA Tour\'s marquee event — TPC Sawgrass Stadium is Pete Dye\'s most famous creation. The iconic island-green 17th hole is the most recognizable par 3 in golf, and the demanding championship layout through Northeast Florida wetlands tests every facet of the game.', highlights: ['THE PLAYERS Championship host venue', 'Iconic island-green 17th hole', 'Pete Dye\'s most famous design'], imageAlt: 'TPC Sawgrass Stadium Course iconic island green 17th hole at Ponte Vedra Beach', history: 'TPC Sawgrass was born from PGA Tour Commissioner Deane Beman\'s vision to create a permanent home for THE PLAYERS Championship. Working with architect Pete Dye, Beman oversaw construction on a flat, swampy tract in Ponte Vedra Beach, Florida, with the course opening in 1980. Dye pioneered the "stadium course" concept here, building spectator mounds and plateaus adjacent to every hole so fans could watch tournament action up close.\n\nThe course underwent a significant renovation in 2006 under the guidance of Bobby Weed, a former Dye associate, who rebuilt all 18 greens with TifEagle bermudagrass and refined several holes while preserving Dye\'s original intent. Alice Dye, Pete\'s wife, played a crucial role in the design — most famously suggesting the island green concept on the 17th hole. THE PLAYERS Championship has been held here annually since 1982, producing iconic moments from dozens of the game\'s greatest players.', signatureHoles: [{ hole: 17, par: 3, yardage: 137, description: 'The most famous par 3 in golf. The island green is surrounded entirely by water, with only a narrow walkway connecting it to land. Wind swirls unpredictably, making club selection treacherous. Roughly 100,000 balls find the water each year.' }, { hole: 18, par: 4, yardage: 462, description: 'One of the great finishing holes in tournament golf. The tee shot must carry water on the left while avoiding trees on the right. The approach is played to a peninsula green guarded by water on the left and front, creating a dramatic risk-reward finish.' }, { hole: 16, par: 5, yardage: 523, description: 'A reachable par 5 that sets up the famous closing stretch. Water lines the entire left side, and the green is tucked behind a pond, tempting long hitters to go for the green in two while punishing any shot that leaks left.' }, { hole: 12, par: 4, yardage: 358, description: 'A short, drivable par 4 that exemplifies Dye\'s strategic genius. The narrow fairway is flanked by water and sand, and the shallow green demands precise distance control on the approach.' }], whatToExpect: 'TPC Sawgrass is flat Florida terrain transformed into a strategic masterpiece through Dye\'s imaginative use of lakes, mounding, and railroad-tie bulkheads. The course winds through Northeast Florida wetlands with water in play on most holes. Conditioning is always tournament-caliber, with fast TifEagle greens and manicured bermudagrass fairways.\n\nThe closing stretch from holes 16 through 18 is one of the most thrilling in golf, with water threatening on every shot. Wind off the nearby Atlantic can dramatically change how the course plays from morning to afternoon. The caddie program and on-course service reflect the venue\'s status as the PGA Tour\'s flagship facility.', playingTips: 'Course management is everything at TPC Sawgrass. Leave the driver in the bag on several holes where accuracy matters more than distance — particularly on holes 4, 8, and 14. On the 17th, take one extra club and aim for the center of the green; the pin position is irrelevant when water surrounds you on all sides.\n\nThe greens are typically fast and subtly contoured, so focus on leaving approach shots below the hole. Afternoon sea breezes can add two clubs to approach shots on exposed holes, so check the forecast and plan accordingly. Book an early morning tee time for calmer conditions and the best chance at a good score.', faqs: [{ question: 'Can the public play TPC Sawgrass?', answer: 'Yes. TPC Sawgrass is a resort course open to the public. Green fees range from approximately $250 to $500 depending on the season, with peak rates during winter and spring. Guests at the Sawgrass Marriott receive preferred tee times and pricing.' }, { question: 'How hard is TPC Sawgrass for average golfers?', answer: 'The course plays 7,245 yards from the tips with a slope of 155, but multiple tee options make it manageable. From the forward tees at around 5,000 yards, the course is very playable. The real challenge is the mental pressure of water hazards on nearly every hole.' }, { question: 'When is the best time to play TPC Sawgrass?', answer: 'Fall (September through November) offers the best combination of pleasant weather, lower green fees, and availability. The course is closed for several weeks surrounding THE PLAYERS Championship in March. Summer is hot and humid but offers the lowest rates.' }, { question: 'Is the 17th hole really as intimidating as it looks on TV?', answer: 'Yes — and then some. The green plays at around 137 yards, but swirling winds and the all-or-nothing nature of the shot make it uniquely pressurized. The drop area is available if you find the water, but expect to feel your heart rate spike on the tee.' }] },
    { id: 'jax-2', name: 'TPC Sawgrass - Dye\'s Valley Course', slug: 'tpc-sawgrass-dyes-valley', city: 'Ponte Vedra Beach', state: 'Florida', type: 'resort', rating: 4.4, greensFee: '$100–$200', architect: 'Pete Dye & Bobby Weed', yearBuilt: 1987, holes: 18, par: 72, yardage: 6864, description: 'The lesser-known sibling at TPC Sawgrass, Dye\'s Valley Course offers a more intimate Pete Dye experience through Northeast Florida wetlands. Redesigned by Bobby Weed in 2017, the layout features dramatic mounding, native marsh hazards, and a challenging but more playable alternative to the Stadium Course.', highlights: ['Bobby Weed 2017 redesign of Pete Dye original', 'More playable TPC Sawgrass alternative', 'Northeast Florida wetland setting'], imageAlt: 'TPC Sawgrass Dyes Valley Course fairway through Northeast Florida wetlands', history: 'Dye\\\'s Valley Course at TPC Sawgrass opened in 1987, co-designed by Pete Dye and Bobby Weed with 1982 PLAYERS champion Jerry Pate as player consultant. The second course at the PGA Tour\\\'s global headquarters, it was initially designed to host PGA Tour Champions events.\n\nThe layout is carved through wetlands and framed by towering oaks adjacent to the famed Stadium Course. A figure-8 routing on the back nine ensures wind affects each hole differently. The final four holes provide a strong finishing stretch.', signatureHoles: [{ hole: 11, par: 4, yardage: 325, description: 'A drivable par 4 from the back tees, framed by mature oak trees — one of the most scenic holes in Northeast Florida. Risk-reward at its finest.' }, { hole: 13, par: 4, yardage: 409, description: 'A classic Pete Dye dogleg bending around a water hazard with strategic bunkering. Rewards a well-shaped tee shot.' }], whatToExpect: 'Wetlands and towering oaks frame a layout with genuine risk-reward variety — drivable short par 4s (325 yards) alongside reachable par 5s (500 yards). Dye\\\'s signature mounding and bunkering punish wayward shots.\n\nOften overshadowed by the Stadium Course but highly regarded by those who play it. Resort access through TPC Sawgrass Marriott at $100-200.', playingTips: 'Course management is paramount. Play to the wide side of fairways and accept par.\n\nGreens are well-defended — know your approach distances precisely.\n\nWind awareness is essential on the exposed wetland routing. The figure-8 back nine means wind direction changes constantly.', faqs: [{ question: 'How does it compare to the Stadium Course?', answer: 'More intimate and more playable, but still a genuine Pete Dye challenge. Often overshadowed but highly regarded by those who play both.' }, { question: 'Is it open to the public?', answer: 'Resort course — open to TPC Sawgrass Marriott guests at $100-200.' }]},
    { id: 'jax-3', name: 'World Golf Village - King & Bear', slug: 'king-and-bear', city: 'St. Augustine', state: 'Florida', type: 'public', rating: 4.2, greensFee: '$60–$130', architect: 'Arnold Palmer & Jack Nicklaus', yearBuilt: 2000, holes: 18, par: 72, yardage: 7279, description: 'The only course co-designed by Arnold Palmer and Jack Nicklaus, King & Bear at World Golf Village combines both legends\' design philosophies. Each architect designed alternating holes through Northeast Florida pine and wetland, creating a unique collaboration at the home of the World Golf Hall of Fame.', highlights: ['Only Palmer-Nicklaus co-designed course', 'World Golf Hall of Fame location', 'Two legends\' alternating hole designs'], imageAlt: 'King and Bear Golf Course Palmer-Nicklaus collaboration at World Golf Village', history: 'King & Bear opened in 2000 at the World Golf Village adjacent to the World Golf Hall of Fame — the only golf course ever co-designed by Arnold Palmer ("The King") and Jack Nicklaus ("The Golden Bear"). Palmer Course Design and Nicklaus Design collaborated on every hole.\n\nRight-to-left holes reflect Palmer\\\'s natural draw; left-to-right holes mirror Nicklaus\\\'s trademark fade. Each hole contains recognizable characteristics of both designers. Nicklaus Design completed a full bunker renovation in 2017.\n\nPublic access — open to all players at the home of the World Golf Hall of Fame.', signatureHoles: [{ hole: 1, par: 4, yardage: 420, description: 'A strong opening hole immediately showcasing both designers\\\' influence — accuracy off the tee and a thoughtful approach. Sets the tone for a round where two legends\\\' philosophies blend on every hole.' }], whatToExpect: 'A course rewarding strong tee ball striking above all else. Compared to other Nicklaus courses, the greens are relatively friendly and receptive. Five tee sets accommodate all skill levels. Lakes, wetlands, and natural Florida terrain throughout.\n\nThe only Palmer-Nicklaus co-design in existence — a unique piece of golf history. Adjacent to the World Golf Hall of Fame.\n\nPublic at $60-130.', playingTips: 'Arrive early to use the excellent practice facilities. The opening holes demand confidence.\n\nTee shot accuracy is the key to scoring. Find the fairway and the course opens up.\n\nChoose appropriate tees — the course plays very differently from forward vs. back.', faqs: [{ question: 'Is this really the only Palmer-Nicklaus course?', answer: 'Yes — the only course ever co-designed by Arnold Palmer and Jack Nicklaus. A unique piece of golf history.' }, { question: 'Is it connected to the Hall of Fame?', answer: 'Adjacent to the World Golf Hall of Fame at World Golf Village in St. Augustine.' }]},
    { id: 'jax-4', name: 'Ponte Vedra Inn & Club - Ocean Course', slug: 'ponte-vedra-ocean-course', city: 'Ponte Vedra Beach', state: 'Florida', type: 'resort', rating: 4.5, greensFee: '$150–$275', architect: 'Herbert Bertram Strong / Bobby Weed', yearBuilt: 1928, holes: 18, par: 72, yardage: 6811, description: 'A historic oceanfront layout at the Ponte Vedra Inn & Club, the Ocean Course features nine holes along the Atlantic Ocean. Originally built in 1928 and renovated by Bobby Weed, the course offers a classic Florida coastal golf experience with sea breezes, dune vegetation, and crashing waves.', highlights: ['Historic 1928 oceanfront layout', 'Nine holes along the Atlantic Ocean', 'Bobby Weed renovation of classic design'], imageAlt: 'Ponte Vedra Inn Ocean Course fairway along Atlantic Ocean beach', history: 'The Ocean Course at Ponte Vedra Inn & Club was originally constructed in 1928 by Herbert Strong — one of Florida\\\'s most historic layouts along 1.5 miles of Atlantic beachfront. Robert Trent Jones Sr. made mid-century updates, and Bobby Weed Golf Design oversaw significant renovations in 1998 and again around 2021-2022 (earning a restoration award).\n\nHole 9 features what many historians consider golf\\\'s very first island green — predating TPC Sawgrass\\\'s famous 17th by over 50 years. A member of the Florida Historic Golf Trail.', signatureHoles: [{ hole: 9, par: 3, yardage: 144, description: 'What many historians consider golf\\\'s very first island green — predating TPC Sawgrass\\\'s famous 17th by over 50 years. At 144 yards, the short distance doesn\\\'t diminish the intimidation of hitting to a green surrounded by water.' }], whatToExpect: 'A resort-friendly par-72 along 1.5 miles of Atlantic beachfront. Not overly demanding off the tee, but elevated greens and constant ocean breezes add challenge. Nine holes run along the Atlantic with stunning views throughout.\n\nApproaching its centennial (1928). The Bobby Weed renovations have modernized the layout while preserving its historic character.\n\nResort access for Ponte Vedra Inn guests at $150-275.', playingTips: 'Ocean wind is the primary defense. Club accordingly on exposed oceanside holes.\n\nApproach shots to elevated greens require extra attention to distance control.\n\nThe course is not punishingly long — accuracy and smart course management yield good scores.\n\nThe historic island green on 9 requires commitment. Pick your club and swing confidently.', faqs: [{ question: 'Is hole 9 really the first island green?', answer: 'Many historians credit it as golf\\\'s very first island green, built in 1928 — over 50 years before TPC Sawgrass made the concept famous.' }, { question: 'How old is the course?', answer: 'Opened 1928 — approaching its centennial. A member of the Florida Historic Golf Trail.' }]},
    { id: 'jax-5', name: 'Sawgrass Country Club - East', slug: 'sawgrass-country-club-east', city: 'Ponte Vedra Beach', state: 'Florida', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Ed Seay (Arnold Palmer Design)', yearBuilt: 1974, holes: 18, par: 72, yardage: 6918, description: 'Adjacent to TPC Sawgrass, the East Course at Sawgrass Country Club is an Arnold Palmer Design Group layout through Northeast Florida marsh and pine forest. The private club offers a quieter alternative to its famous neighbor with strategic marsh carries and mature tree-lined fairways.', highlights: ['Arnold Palmer Design Group layout', 'Adjacent to TPC Sawgrass', 'Mature pine forest and marsh setting'], imageAlt: 'Sawgrass Country Club East Course through pine forest near Ponte Vedra Beach', history: 'Sawgrass Country Club\\\'s East Course was designed by Ed Seay under Arnold Palmer Course Design Company, opening in 1974. From 1977 to 1981, the East/West combination hosted the Tournament Players Championship (now THE PLAYERS Championship) — the PGA Tour\\\'s flagship event — before the tournament moved to the newly built TPC Sawgrass Stadium Course in 1982.\n\nWinners at Sawgrass CC include Jack Nicklaus (1978), Lee Trevino (1980), and Raymond Floyd (1981). The South nine was added later, creating 27 holes. Robert Walker later renovated the layout.\n\nThe course sits directly adjacent to TPC Sawgrass — neighbors with deep shared history.', signatureHoles: [{ hole: 9, par: 4, yardage: 430, description: 'Part of the East nine that hosted THE PLAYERS Championship from 1977-1981. The layout was notoriously tough — brutal wind conditions produced famously high scores from the world\\\'s best players.' }], whatToExpect: 'A mature, strategic layout through Northeast Florida marsh and pine forest. The Palmer Design pedigree shows in the emphasis on tee shot placement and course management. 27 holes across three nines (East/West/South) allow varied 18-hole rotations.\n\nImproved drainage from the Walker renovation modernized playability while preserving character. Directly adjacent to TPC Sawgrass.\n\nPrivate — membership required.', playingTips: 'Tee shot placement is everything — the course was designed to demand accuracy, as proven by high PGA Tour scores in the late 1970s.\n\nRespect the wind funneling through the flat coastal terrain.\n\nCourse management remains the key to scoring despite the renovation improvements.', faqs: [{ question: 'Did this really host THE PLAYERS?', answer: 'Yes — from 1977 to 1981 before the tournament moved to the adjacent TPC Sawgrass Stadium Course. Winners include Nicklaus, Trevino, and Floyd.' }, { question: 'Is it related to TPC Sawgrass?', answer: 'Direct neighbors with shared history. THE PLAYERS Championship was born at Sawgrass CC before moving next door.' }]},
    { id: 'jax-6', name: 'Amelia Island Club - Long Point', slug: 'amelia-island-long-point', city: 'Amelia Island', state: 'Florida', type: 'resort', rating: 4.3, greensFee: '$100–$185', architect: 'Tom Fazio', yearBuilt: 1987, holes: 18, par: 72, yardage: 6775, description: 'A Tom Fazio design at the Omni Amelia Island resort, Long Point winds through maritime forest and along the Intracoastal Waterway on Florida\'s northernmost barrier island. The resort layout features salt marsh hazards, live oaks, and scenic water views throughout the round.', highlights: ['Tom Fazio resort design on Amelia Island', 'Intracoastal Waterway and marsh views', 'Omni resort setting on barrier island'], imageAlt: 'Amelia Island Long Point Tom Fazio fairway along Intracoastal Waterway', history: 'Long Point was completed in 1987 by Tom Fazio on Amelia Island, a barrier island along Florida\\\'s northernmost coast. A member-owned equity club within the Omni Amelia Island Resort, the layout runs through three distinct environments: maritime forest with live oaks, salt marshes along the Amelia River, and oceanfront dunes along the Atlantic.\n\nThe dramatic four-hole seaside sequence (holes 15-18) crosses A1A to reach the dune-side stretch. The club describes the back-to-back oceanside par 3s (15-16) as playing "like docile pussy cats or wild broncos depending on the wind."', signatureHoles: [{ hole: 15, par: 3, yardage: 170, description: 'The first of back-to-back oceanside par 3s — the crown jewels of the course. They cross A1A to reach the dune-side stretch and can swing wildly in difficulty depending on Atlantic wind conditions.' }], whatToExpect: 'The first 12 holes route through marshland and heavy tree canopy with natural waste bunkers and large undulating greens. Upon crossing A1A around the 13th, the character shifts entirely to a windswept seaside finish — a rare combination of marsh, forest, and true oceanfront in a single 18-hole routing.\n\nPristine conditioning. Abundant wildlife — herons, egrets, and marsh birds throughout.\n\nResort guest access through the Omni on a limited basis.', playingTips: 'Wind management is the key skill on the oceanside holes. Club selection can swing 2-3 clubs depending on conditions.\n\nOn the marsh holes, play to the safe side of fairways — errant shots find waste areas with no recovery.\n\nThe back nine is notably tougher than the front. Save your energy.', faqs: [{ question: 'What makes the finish special?', answer: 'Holes 15-18 play along the Atlantic dunes after crossing A1A. Back-to-back oceanside par 3s (15-16) can swing wildly in difficulty with the wind.' }, { question: 'Can resort guests play?', answer: 'Yes — Omni Amelia Island Resort guests have limited access.' }]},
    { id: 'jax-7', name: 'Marsh Landing Country Club', slug: 'marsh-landing-country-club', city: 'Ponte Vedra Beach', state: 'Florida', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Ed Seay (Arnold Palmer Design)', yearBuilt: 1986, holes: 18, par: 72, yardage: 6841, description: 'An Arnold Palmer Design layout in Ponte Vedra Beach, Marsh Landing features a scenic routing through tidal marsh, lakes, and mature Northeast Florida vegetation. The private community course offers challenging marsh carries and well-defended greens in one of Jacksonville\'s most desirable neighborhoods.', highlights: ['Arnold Palmer Design in Ponte Vedra Beach', 'Tidal marsh and lake-lined routing', 'Premier Ponte Vedra private community'], imageAlt: 'Marsh Landing Country Club fairway through tidal marsh in Ponte Vedra Beach', history: 'Marsh Landing was designed by Ed Seay of Arnold Palmer Course Design and opened in 1986 in Ponte Vedra Beach alongside the Intracoastal Waterway. Seay\\\'s design preserved the natural wetlands and terrain, keeping much of the original landscape intact.\n\nAcquired by Concert Golf Partners in 2022, which has brought renewed investment and restored the club to a higher standard. The natural setting makes it one of the most scenic private clubs in Jacksonville — described by reviewers as "a four-hour ride through a nature preserve."', signatureHoles: [{ hole: 12, par: 3, yardage: 160, description: 'Widely considered the signature hole by members — a striking par 3 with tidal marsh framing the shot. Part of a strong collection of par 3s that reviewers consistently highlight as the course\\\'s greatest strength.' }], whatToExpect: 'A routing through tidal marshlands, hardwood hammocks, and along the Intracoastal Waterway. Expect wading birds, osprey, and possibly dolphins in the waterway. Challenging but not punishing, with wetlands as the primary hazard.\n\nLocated minutes from TPC Sawgrass in the Ponte Vedra golf corridor. Private — renewed under Concert Golf Partners ownership since 2022.', playingTips: 'Accuracy over distance. Many fairways bordered by marsh with no forgiveness — a lost ball is the penalty.\n\nTidal wind off the Intracoastal is constant. Factor it into every club selection.\n\nFocus on approach positioning. The greens can be tricky.', faqs: [{ question: 'Is it near TPC Sawgrass?', answer: 'Yes — minutes from TPC Sawgrass in the heart of Ponte Vedra Beach\\\'s golf corridor.' }, { question: 'Who owns it now?', answer: 'Concert Golf Partners acquired the club in 2022, bringing renewed investment and restored standards.' }]},
    { id: 'jax-8', name: 'Jacksonville Beach Golf Club', slug: 'jacksonville-beach-golf-club', city: 'Jacksonville Beach', state: 'Florida', type: 'public', rating: 4.0, greensFee: '$25–$50', architect: 'Donald Ross (original)', yearBuilt: 1924, holes: 18, par: 72, yardage: 6478, description: 'A Donald Ross-routed municipal course just blocks from the Atlantic Ocean, Jacksonville Beach Golf Club is one of the oldest courses in Northeast Florida. The affordable layout offers a throwback golf experience with Ross-era green complexes, mature trees, and a welcoming community atmosphere.', highlights: ['Donald Ross municipal course since 1924', 'Blocks from the Atlantic Ocean', 'Affordable throwback golf experience'], imageAlt: 'Jacksonville Beach Golf Club Donald Ross municipal layout near the Atlantic', history: 'Jacksonville Beach Golf Club is one of the oldest courses in Northeast Florida, with roots attributed to a Donald Ross routing. Sitting just blocks from the Atlantic Ocean, it began as a private 9-hole layout before the City of Jacksonville Beach took over, expanding to 18 holes as a public municipal course.\n\nA Robert Walker redesign came in 1987 and a comprehensive greens renovation in 2009. Golf Digest has rated it among the top 30 places to play in Florida — remarkable for a municipal course at $25-50.', signatureHoles: [{ hole: 9, par: 4, yardage: 380, description: 'A compact, character-filled par 4 where the Atlantic breeze and mature landscaping create a coastal links feel. The ocean proximity defines the experience — wind turns straightforward holes into genuine tests.' }], whatToExpect: 'A no-frills municipal experience with genuine character. Flat coastal terrain with ocean breeze, mature trees, and compact routing give it more personality than many public tracks. Conditioning has improved significantly since the 2009 greens renovation.\n\nThe Donald Ross heritage (however altered over decades) gives historical cachet rare for a municipal course. Located blocks from the beach — easy to pair with a beach day.\n\nPublic at $25-50 — one of the best values in Northeast Florida.', playingTips: 'Atlantic wind is the great equalizer. Even on calm days, afternoon sea breezes affect club selection by 1-2 clubs.\n\nThe greens are the primary defense. Dial in your short game.\n\nBook tee times in advance, especially weekends — popularity and affordable pricing create demand.\n\nWalking is practical on the flat terrain.', faqs: [{ question: 'Is it really a Donald Ross course?', answer: 'Roots attributed to a Ross routing, though much has been altered over the decades through Walker redesign (1987) and greens renovation (2009). The historical connection adds cachet.' }, { question: 'How close to the beach?', answer: 'Blocks from the Atlantic Ocean. Easy to pair a round with a beach day — a practical bonus for visitors.' }]},
    { id: 'jax-9', name: 'World Golf Village - King & Bear', slug: 'king-and-bear', city: 'St. Augustine', state: 'Florida', type: 'public', rating: 4.3, greensFee: '$60–$120', architect: 'Arnold Palmer & Jack Nicklaus', yearBuilt: 2000, holes: 18, par: 72, yardage: 7279, description: 'The only course co-designed by Arnold Palmer and Jack Nicklaus, the King & Bear at World Golf Village combines the two legends\' design philosophies on a property adjacent to the World Golf Hall of Fame. Palmer\'s aggressive bunkering and Nicklaus\'s strategic water features blend seamlessly through lush North Florida terrain.', highlights: ['Only Palmer-Nicklaus co-design in existence', 'Adjacent to World Golf Hall of Fame', 'Unique blend of two design legends'], imageAlt: 'King and Bear Golf Course Palmer-Nicklaus co-design at World Golf Village', history: 'King & Bear at World Golf Village is the only golf course ever co-designed by Arnold Palmer ("The King") and Jack Nicklaus ("The Golden Bear"). Opened in 2000 adjacent to the World Golf Hall of Fame in St. Augustine.\n\nRight-to-left holes reflect Palmer\\\'s natural draw; left-to-right holes mirror Nicklaus\\\'s trademark fade. Nicklaus Design completed a full bunker renovation in 2017. Public access at $60-120.', signatureHoles: [{ hole: 1, par: 4, yardage: 420, description: 'Immediately showcases both designers\\\' influence — accuracy off the tee and thoughtful approach. Every hole blends recognizable Palmer and Nicklaus characteristics.' }], whatToExpect: 'A course rewarding strong tee ball striking. Five tee sets. Lakes, wetlands, and natural Florida terrain. The only Palmer-Nicklaus co-design in existence — unique golf history.\n\nPublic at $60-120 adjacent to the World Golf Hall of Fame.', playingTips: 'Tee shot accuracy is the key. Find the fairway and the course opens up. Choose appropriate tees.', faqs: [{ question: 'Is this the only Palmer-Nicklaus course?', answer: 'Yes — the only course ever co-designed by the two legends.' }]},
    { id: 'jax-10', name: 'Marsh Landing Country Club', slug: 'marsh-landing-cc', city: 'Ponte Vedra Beach', state: 'Florida', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Ed Seay', yearBuilt: 1986, holes: 18, par: 72, yardage: 6841, description: 'An Ed Seay design in the Ponte Vedra Beach corridor near TPC Sawgrass, Marsh Landing winds through marshland and maritime forest along the Intracoastal Waterway. The private club offers a refined Northeast Florida golf experience with tidal marsh views, natural wildlife, and a serene coastal atmosphere.', highlights: ['Intracoastal Waterway and tidal marsh setting', 'Near TPC Sawgrass in Ponte Vedra corridor', 'Ed Seay design through maritime forest'], imageAlt: 'Marsh Landing Country Club fairway along Intracoastal Waterway in Ponte Vedra Beach', history: 'Marsh Landing was designed by Ed Seay and opened in 1986 in Ponte Vedra Beach along the Intracoastal Waterway. Acquired by Concert Golf Partners in 2022 with renewed investment. Described as "a four-hour ride through a nature preserve" with tidal marshlands, hardwood hammocks, and waterway views.\n\nLocated minutes from TPC Sawgrass in Ponte Vedra\\\'s premier golf corridor. Private club.', signatureHoles: [{ hole: 12, par: 3, yardage: 160, description: 'The signature hole — a par 3 with tidal marsh framing the shot. Part of a strong par-3 collection.' }], whatToExpect: 'Natural wetland routing along the Intracoastal Waterway. Wildlife throughout. Challenging but not punishing.\n\nPrivate — minutes from TPC Sawgrass.', playingTips: 'Accuracy over distance. Marsh borders leave no forgiveness for wayward shots. Tidal wind is constant.', faqs: [{ question: 'Is it near TPC Sawgrass?', answer: 'Yes — minutes away in the Ponte Vedra corridor.' }]},
    { id: 'jax-11', name: 'Amelia National Golf & Country Club', slug: 'amelia-national-golf-cc', city: 'Fernandina Beach', state: 'Florida', type: 'semi-private', rating: 4.2, greensFee: '$55–$100', architect: 'Tom Fazio', yearBuilt: 2005, holes: 18, par: 72, yardage: 7137, description: 'A Tom Fazio design on Amelia Island north of Jacksonville, Amelia National offers semi-private access to championship golf through moss-draped oaks and marshland. The 7,137-yard layout features Fazio\'s trademark bold shaping, strategic water features, and a coastal lowcountry ambiance.', highlights: ['Tom Fazio design on Amelia Island', 'Moss-draped oaks and marshland routing', 'Semi-private access to championship golf'], imageAlt: 'Amelia National Golf Club Tom Fazio fairway through Amelia Island oaks', history: 'Amelia National was designed by Tom Fazio and opened in 2006 as a gated residential golf community near Amelia Island on Florida\\\'s northeast coast. Fazio threaded the layout through mature hardwoods and natural wetlands using the existing coastal-forested terrain.\n\nRated 74.9/138 slope. Regarded as one of the best private courses in the Southeast since opening. A Fazio-led renovation was underway as of 2025 to refresh the original design. Located five minutes from Amelia Island\\\'s historic downtown.', signatureHoles: [{ hole: 5, par: 3, yardage: 175, description: 'One of the most photographed holes — framed by towering oaks and water. The coastal forest setting with Spanish moss creates a distinctly Lowcountry atmosphere.' }], whatToExpect: 'Visually spectacular Fazio layout with generous fairways set against ancient live oaks, Spanish moss, and coastal forest. French Provincial clubhouse anchors the community. The course rewards positioning over brute length.\n\nCoastal breezes off nearby Amelia Island affect club selection on exposed holes. Semi-private access at $55-100.', playingTips: 'Choose the right angle into Fazio\\\'s well-defended greens — positioning matters more than distance.\n\nCoastal breezes affect exposed holes. The 138 slope from the tips is legitimate; play the right tees.', faqs: [{ question: 'Is it on Amelia Island?', answer: 'Near Amelia Island — five minutes from the historic downtown in Fernandina Beach.' }, { question: 'Who designed it?', answer: 'Tom Fazio (2006). A Fazio-led renovation was underway as of 2025.' }]},
  ],
  'kansas-city-missouri': [
    { id: 'kc-1', name: 'Kansas City Country Club', slug: 'kansas-city-country-club', city: 'Mission Hills', state: 'Kansas', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Perry Maxwell', yearBuilt: 1896, holes: 18, par: 72, yardage: 6836, description: 'One of the oldest clubs west of the Mississippi, Kansas City Country Club features a Perry Maxwell design through rolling terrain in Mission Hills. Maxwell\'s bold green contours and strategic bunkering make it one of the finest examples of his work, complemented by mature tree-lined fairways.', highlights: ['Perry Maxwell classic design', 'One of the oldest clubs west of the Mississippi', 'Bold Maxwell green contours in Mission Hills'], imageAlt: 'Kansas City Country Club Perry Maxwell fairway through Mission Hills', history: 'Kansas City Country Club was founded on May 1, 1896, making it one of the oldest country clubs west of the Mississippi River. Perry Maxwell — the legendary Oklahoma-born architect known for Southern Hills and Prairie Dunes — shaped the course with his trademark green complexes and strategic bunkering.\n\nMaxwell\\\'s undulating greens (the famous "Maxwell rolls") reward precise iron play and punish anything slightly offline. The top-ranked private course in Kansas, standing alongside Maxwell\\\'s work at Southern Hills, Prairie Dunes, and his renovations at Augusta National.', signatureHoles: [{ hole: 13, par: 4, yardage: 420, description: 'A demanding par 4 showcasing Maxwell\\\'s trademark rolling, contoured green complexes. The tree-lined corridor on the back nine demands accuracy off the tee followed by a precise approach to a green that funnels balls to specific positions.' }], whatToExpect: 'A classic, mature parkland layout through rolling Mission Hills terrain with tree-lined fairways. At 6,836 yards it won\\\'t overpower with length, but Maxwell\\\'s green complexes and strategic bunkering create a cerebral challenge rewarding shot-shaping and precise approaches over power.\n\nStrictly private — one of Perry Maxwell\\\'s most enduring designs in the affluent Mission Hills neighborhood.', playingTips: 'Study the greens carefully — Maxwell designed surfaces that funnel balls to certain pin positions and reject others.\n\nClub selection into greens is critical as many are elevated or tilted.\n\nMature trees narrow driving corridors. Keep driver in the bag on tighter holes and focus on positioning.', faqs: [{ question: 'Who is Perry Maxwell?', answer: 'The legendary Oklahoma-born architect also responsible for Southern Hills, Prairie Dunes, and renovations at Augusta National. His "Maxwell rolls" green complexes are among the most celebrated in American golf.' }, { question: 'How old is the club?', answer: 'Founded May 1, 1896 — one of the oldest country clubs west of the Mississippi.' }]},
    { id: 'kc-2', name: 'Shadow Glen Golf Club', slug: 'shadow-glen-golf-club', city: 'Olathe', state: 'Kansas', type: 'public', rating: 4.4, greensFee: '$45–$85', architect: 'Jay Morrish & Tom Weiskopf', yearBuilt: 1993, holes: 18, par: 72, yardage: 7047, description: 'A Weiskopf-Morrish design in Olathe, Shadow Glen is consistently ranked the top public course in the Kansas City area. The rolling layout through native tallgrass prairie and mature hardwoods features strategic bunkering, challenging green complexes, and scenic views of the Kansas countryside.', highlights: ['Top-ranked public course in Kansas City area', 'Weiskopf-Morrish prairie design', 'Rolling Kansas countryside setting'], imageAlt: 'Shadow Glen Golf Club fairway through tallgrass prairie in Olathe Kansas', history: 'Shadow Glen was established in 1987 as a nonprofit equity club, designed by Tom Weiskopf, Jay Morrish, and Tom Watson (a Kansas City native who consulted). Golf Digest named it Best New Private Course in 1989, and it made Golf Digest\\\'s Top 100 Greatest Courses in America by 1995.\n\nMembership is capped at 355 resident members with no reserved tee times, ensuring excellent pace of play. The 22,000-square-foot Howard Nearing-designed clubhouse overlooks a 65-acre lake. One of only a handful of courses where two major champions (Watson and Weiskopf) collaborated.', signatureHoles: [{ hole: 13, par: 4, yardage: 420, description: 'Selected by Golf Digest as one of America\\\'s best 18 holes. A demanding par 4 through the rolling Kansas countryside that exemplifies the strategic design philosophy of the Weiskopf-Morrish-Watson collaboration.' }, { hole: 14, par: 4, yardage: 285, description: '"Wild Turkey" — a driveable par 4 named for the wild turkeys Watson encountered while staking out the hole. Risk-reward at its most tempting.' }], whatToExpect: 'A premier private club with traditional, right-sized greens rewarding reading and touch over power putting. Rolling Kansas countryside through native tallgrass prairie and mature hardwoods. The 355-member cap and no-tee-time policy ensure uncrowded play.\n\nConsistently ranked in Kansas\\\'s top 5 since opening. Former Golf Digest Top 100 course.', playingTips: 'The greens are traditional size — accurate iron play is rewarded over distance.\n\nOn the driveable 14th ("Wild Turkey"), wind changes the risk-reward calculation. Lay up with an iron if the wind is against you.\n\nElevation changes throughout affect club distances. Trust your rangefinder.', faqs: [{ question: 'Was this in Golf Digest\\\'s Top 100?', answer: 'Yes — made the Top 100 Greatest Courses in America by 1995. Named Best New Private Course in 1989.' }, { question: 'Who designed it?', answer: 'Tom Weiskopf, Jay Morrish, and Tom Watson (consulting). One of only a handful of courses where two major champions collaborated on design.' }]},
    { id: 'kc-3', name: 'Wolf Creek Golf Links', slug: 'wolf-creek-golf-links-kc', city: 'Olathe', state: 'Kansas', type: 'public', rating: 4.2, greensFee: '$35–$65', architect: 'Jeff Brauer', yearBuilt: 2000, holes: 18, par: 72, yardage: 6978, description: 'A Jeff Brauer links-inspired design in Olathe, Wolf Creek Golf Links offers an affordable championship experience through rolling Kansas terrain. The layout features prairie grasses, strategic mounding, and wind exposure that create a links-like atmosphere uncommon in the Midwest.', highlights: ['Jeff Brauer links-inspired design', 'Affordable championship golf in Olathe', 'Prairie grass and wind-exposed routing'], imageAlt: 'Wolf Creek Golf Links prairie fairway in Olathe Kansas', history: 'Wolf Creek Golf Links opened in Olathe with a links-inspired design across rolling Kansas prairie. The course features prairie grasses, strategic mounding, and significant wind exposure creating a links-like atmosphere uncommon in the Midwest.\n\nWater features on at least six holes create risk-reward decisions throughout. The rolling prairie terrain provides natural elevation changes adding visual drama. Post-2006 renovation improved conditions markedly with new greens, bunkers, and irrigation.', signatureHoles: [{ hole: 3, par: 5, yardage: 589, description: 'A long right-dogleg par 5 where Wolf Creek (the actual waterway) first comes into play. The rolling prairie terrain and water hazard create a genuine three-shot challenge.' }], whatToExpect: 'A links-inspired layout across rolling Kansas prairie with exposure to prevailing Kansas winds. Traditional links elements — mounding, prairie grasses, firm conditions — with the natural creek that gives the club its name.\n\nWind management is the primary skill tested. Kansas wind can add or subtract two clubs on exposed holes.\n\nPublic access at $35-65 — affordable championship golf.', playingTips: 'Wind is the biggest challenge. Kansas wind can swing club selection dramatically on exposed holes.\n\nLinks-style mounding allows bump-and-run approaches — don\\\'t default to aerial play.\n\nWhen the creek comes into play, respect it. Penalty strokes add up quickly.', faqs: [{ question: 'Is it really links-style?', answer: 'Links-inspired — prairie grasses, mounding, firm conditions, and constant wind exposure create a links atmosphere uncommon in the Midwest.' }, { question: 'How affordable is it?', answer: 'Public at $35-65 — strong value for the quality and links character.' }]},
    { id: 'kc-4', name: 'Hallbrook Country Club', slug: 'hallbrook-country-club', city: 'Leawood', state: 'Kansas', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Tom Watson', yearBuilt: 1989, holes: 18, par: 71, yardage: 6840, description: 'Designed by Kansas City native and eight-time major champion Tom Watson, Hallbrook is the only course Watson designed in his hometown. The private layout in Leawood features Watson\'s emphasis on strategic shotmaking with well-defended greens, creative bunkering, and rolling terrain.', highlights: ['Tom Watson\'s only design in his hometown', 'Eight-time major champion architect', 'Strategic shotmaking emphasis in Leawood'], imageAlt: 'Hallbrook Country Club Tom Watson designed fairway in Leawood Kansas', history: 'Hallbrook Country Club was developed by the Hall family as a premier residential community in south Johnson County, Leawood. Tom Fazio designed the golf course with Tom Watson consulting — the eight-time major champion and Kansas City native. The property for the course was chosen first, with residential lots plotted afterward, ensuring the golf came first.\n\nThe course features notable elevation changes uncommon for the KC area, with natural creek systems threading through the layout and heavily wooded hillsides framing multiple holes. Rated 74.1/140 slope — a demanding private layout.', signatureHoles: [{ hole: 8, par: 3, yardage: 195, description: 'One of several par 3s particularly well-regarded for visual drama and green complex difficulty. The Fazio/Watson collaboration shows in the strategic challenge and scenic woodland setting.' }], whatToExpect: 'A demanding private layout accentuated by native Kansas prairie grasses and heavily wooded hillsides. Rolling terrain provides significant elevation changes affecting club selection and visual perception. Creative bunkering and well-defended greens emphasize strategic shotmaking.\n\nThe only Watson-associated design in his hometown. Hosts the annual Watson Challenge tournament.\n\nPrivate — membership in Leawood\\\'s premier residential community.', playingTips: 'The 140 slope from the back tees indicates serious difficulty. Choose tees wisely.\n\nElevation changes affect distances more than expected. Trust your rangefinder over your eyes.\n\nThe greens reward precise iron play and punish short-sided misses. Favor the center.\n\nCreek crossings create genuine risk-reward moments — plan strategy off the tee.', faqs: [{ question: 'Did Tom Watson really design this?', answer: 'Tom Fazio was the architect with Watson consulting — the eight-time major champion\\\'s only design involvement in his hometown of Kansas City.' }, { question: 'What is the Watson Challenge?', answer: 'An annual tournament hosted at the club, reflecting Watson\\\'s close personal connection to Hallbrook.' }]},
    { id: 'kc-5', name: 'Creekmoor Golf Club', slug: 'creekmoor-golf-club', city: 'Raymore', state: 'Missouri', type: 'public', rating: 4.1, greensFee: '$30–$55', architect: 'Jim Colbert', yearBuilt: 1998, holes: 18, par: 72, yardage: 7032, description: 'A Jim Colbert design south of Kansas City, Creekmoor offers championship-caliber public golf through rolling Missouri terrain with creeks, lakes, and mature hardwoods. The affordable layout provides solid golf value with well-maintained conditions throughout the season.', highlights: ['Jim Colbert championship design', 'Affordable public golf south of KC', 'Rolling Missouri terrain with water features'], imageAlt: 'Creekmoor Golf Club rolling fairway in Raymore Missouri', history: 'Creekmoor Golf Club was designed by Jim Colbert — a Kansas City native and 8-time PGA Tour winner — and opened in 1998 as part of the Creekmoor master-planned community south of KC in Raymore. The course features lush zoysia fairways, 65 sand bunkers, and multiple creeks and lakes through rolling Missouri terrain.\n\nConsistently rated among the best public courses in Missouri. Has hosted Missouri Amateur Championship events and Central Links Golf Association tournaments. The par-5 nicknamed the "Beast of Creekmoor" stretches 663 yards — one of the longest holes in the KC metro.', signatureHoles: [{ hole: 15, par: 5, yardage: 663, description: 'The "Beast of Creekmoor" — 663 yards with five significant hazards. One of the longest holes in the Kansas City metro. A genuine three-shot challenge where course management defines the outcome.' }], whatToExpect: 'A links-influenced layout with thick fescue rough punishing missed fairways. Beautiful views of Creekmoor Lake along holes 13, 14, and 16. Two par 3s require full carries over water. Well-maintained bunkers with quality sand.\n\nMultiple tee options from 7,400+ yards down to 3,305. Public at $30-55 — strong KC value.', playingTips: 'Keep it in the fairway — the fescue rough is penal and thick.\n\nCourse management off the tee is essential. Choose appropriate tees from the wide range available.\n\nThe two water-carry par 3s demand committed swings. Pick your club and trust it.', faqs: [{ question: 'Who designed it?', answer: 'Jim Colbert, Kansas City native and 8-time PGA Tour winner. Opened 1998.' }, { question: 'What is the Beast of Creekmoor?', answer: 'A 663-yard par 5 with five hazards — one of the longest holes in the KC metro.' }]},
    { id: 'kc-6', name: 'Tiffany Greens Golf Club', slug: 'tiffany-greens-golf-club', city: 'Kansas City', state: 'Missouri', type: 'semi-private', rating: 4.2, greensFee: '$40–$75', architect: 'Robert Trent Jones Jr.', yearBuilt: 1999, holes: 18, par: 72, yardage: 7049, description: 'A Robert Trent Jones Jr. design in north Kansas City, Tiffany Greens offers a semi-private championship experience on rolling terrain. The layout features dramatic elevation changes, strategic water hazards, and well-defended greens that create a challenging and visually engaging round.', highlights: ['Robert Trent Jones Jr. design', 'Dramatic elevation changes', 'Semi-private championship experience'], imageAlt: 'Tiffany Greens Golf Club RTJ Jr fairway in north Kansas City', history: 'Tiffany Greens opened in 1999, designed by Robert Trent Jones Jr. near KCI Airport in KC\\\'s Northland. The course immediately hosted the Champions Tour TD Waterhouse Championship from 1999-2002, bringing PGA legends to Kansas City. Tom Watson narrowly lost the 2000 event in his hometown.\n\nJim Colbert eagled the opening hole in the first round of the 2000 TD Waterhouse, setting the tone. Six lake-protected greens throughout the layout. RTJ Jr. also designed Chambers Bay (US Open venue) and Poppy Hills.', signatureHoles: [{ hole: 1, par: 5, yardage: 530, description: 'A reachable par 5 where Jim Colbert eagled in the 2000 Champions Tour event. Risk-reward options set the tone immediately — one of six holes with lake-protected greens.' }], whatToExpect: 'Wide zoysia fairways, undulating green surrounds, and strategic bunkering. Six lake-protected greens create risk-reward decisions. Semi-private with daily tee times at $40-75.\n\nVoted No. 1 in KC\\\'s Northland. Champions Tour history gives it competitive pedigree.\n\nRTJ Jr.\\\'s ability to create accessible public golf at championship caliber is on full display.', playingTips: 'Take advantage of generous fairways but respect the six water-guarded greens.\n\nUndulating surrounds mean short-game creativity is rewarded.\n\nClub selection into greens is critical — the water won\\\'t forgive misjudged distances.', faqs: [{ question: 'Did it host professional events?', answer: 'Yes — Champions Tour TD Waterhouse Championship from 1999-2002. Tom Watson narrowly lost the 2000 event in his hometown.' }, { question: 'Who designed it?', answer: 'Robert Trent Jones Jr. — who also designed Chambers Bay (US Open venue).' }]},
    { id: 'kc-7', name: 'Canyon Farms Golf Club', slug: 'canyon-farms-golf-club', city: 'Lenexa', state: 'Kansas', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 2003, holes: 18, par: 72, yardage: 7300, description: 'A Tom Fazio design in Lenexa, Canyon Farms is one of the premier private clubs in the Kansas City area. The layout features Fazio\'s bold shaping through rolling terrain with dramatic canyon features, strategic bunkering, and immaculate conditioning that sets it apart in the region.', highlights: ['Tom Fazio premier KC private club', 'Dramatic canyon terrain features', 'Immaculate conditioning year-round'], imageAlt: 'Canyon Farms Golf Club Tom Fazio fairway through canyon terrain in Lenexa', history: 'Canyon Farms Golf Club is a premier private club in Lenexa, southwest of Kansas City. The layout features dramatic elevation changes through rolling Kansas terrain with canyon-like features, strategic bunkering, and immaculate conditioning.\n\nRated among the top private clubs in Kansas. Greens run around 10.5 on the stimpmeter. The canyon and ravine crossings are the defining design features, creating dramatic downhill tee shots and elevated green complexes.', signatureHoles: [{ hole: 11, par: 4, yardage: 430, description: 'One of several holes featuring dramatic canyon crossings and elevation changes. The canyon terrain creates breathtaking downhill tee shots and elevated green complexes that define the Canyon Farms experience.' }], whatToExpect: 'Immaculate conditioning — fairways, greens, and surrounds maintained to elite standards. Generous fairways with strategic bunkering. Dramatic elevation changes through canyon terrain uncommon for the Kansas landscape.\n\nPar 72, approximately 7,300 yards. Strictly private.', playingTips: 'Elevation changes affect club selection significantly. Trust your yardage device.\n\nDespite generous fairways, position matters for approach angles into well-protected greens.\n\nGreens run around 10.5 — respect the speed and favor below-the-hole positions.', faqs: [{ question: 'How is it ranked?', answer: 'Among the top private clubs in Kansas. Reviewers call it "literally the nicest course" they\\\'ve played.' }, { question: 'What is the canyon terrain like?', answer: 'Dramatic elevation changes with canyon/ravine crossings creating downhill tee shots and elevated greens — uncommon features for Kansas.' }]},
    { id: 'kc-8', name: 'Staley Farms Golf Club', slug: 'staley-farms-golf-club', city: 'Kansas City', state: 'Missouri', type: 'public', rating: 4.1, greensFee: '$30–$60', architect: 'Rick Robbins', yearBuilt: 2001, holes: 18, par: 71, yardage: 6828, description: 'A Rick Robbins design on the former Staley Farms property in north Kansas City, this public course features rolling terrain, native grasses, and scenic views. The affordable layout consistently ranks among the best public golf values in the Kansas City metro area.', highlights: ['Built on historic Staley Farms property', 'Top public golf value in KC metro', 'Rolling terrain with native grasses'], imageAlt: 'Staley Farms Golf Club rolling fairway in north Kansas City Missouri', history: 'Staley Farms Golf Club was built on the historic Staley family property in north Kansas City. John Horace Staley established the farm in the 1870s, and the family held the land for generations. The golf course was designed by Eric Iverson and opened around 2001-2002, following the natural contours of the historic property.\n\nMissouri Golf Tour calls it "one of the best courses in the state, public or private" and "one of the hardest in the city." Now operated by GreatLIFE Kansas City with a membership model offering private club access.', signatureHoles: [{ hole: 14, par: 4, yardage: 420, description: 'Part of a demanding stretch showcasing the dramatic elevation changes and strategic shot-making requirements that make Staley Farms one of the hardest courses in Kansas City.' }], whatToExpect: 'Fast and firm conditions — a true strategic test requiring shot placement over raw distance. Rolling terrain with native grasses and scenic views of the historic property. The course challenges all skill levels and demands strategic play.\n\nGreatLIFE membership provides private club access with a 24-hour fitness center. A rustic clubhouse adds character.', playingTips: 'This is a thinking golfer\\\'s course. Position off the tee matters more than distance.\n\nFast greens require precise speed control. Leave yourself below the hole.\n\nThe historic property\\\'s natural terrain creates many uneven lies — solid ball-striking fundamentals are essential.', faqs: [{ question: 'Is it public or private?', answer: 'Currently operated as a private club through GreatLIFE Kansas City membership model.' }, { question: 'What is the historic connection?', answer: 'Built on the Staley family farm dating to the 1870s. The golf course follows the natural contours of the historic property.' }]},
    { id: 'kc-9', name: 'Creekmoor Golf Club', slug: 'creekmoor-golf-club', city: 'Raymore', state: 'Missouri', type: 'public', rating: 4.2, greensFee: '$40–$75', architect: 'Tom Watson Design', yearBuilt: 2002, holes: 18, par: 71, yardage: 6806, description: 'Co-designed by Kansas City native and World Golf Hall of Famer Tom Watson, Creekmoor in Raymore features links-style elements with fescue-lined fairways and strategic bunkering on rolling terrain south of KC. Watson\'s design philosophy emphasizes ground-game options and firm playing conditions.', highlights: ['Co-designed by Hall of Famer Tom Watson', 'Links-style elements with fescue rough', 'Firm-and-fast playing conditions'], imageAlt: 'Creekmoor Golf Club Tom Watson links-style fairway in Raymore Missouri', history: 'Creekmoor Golf Club in Raymore was designed by Jim Colbert — a Kansas City native and 8-time PGA Tour winner — opening in 1998 as part of the Creekmoor master-planned community. The links-influenced layout features thick fescue rough, zoysia fairways, 65 sand bunkers, and multiple creeks and lakes through rolling Missouri terrain south of KC.\n\nConsistently rated among the best public courses in Missouri. The 663-yard "Beast of Creekmoor" par 5 is one of the longest holes in the KC metro.', signatureHoles: [{ hole: 5, par: 5, yardage: 663, description: 'The "Beast of Creekmoor" — at 663 yards with five significant hazards, it is one of the longest and most challenging holes in the Kansas City area.' }], whatToExpect: 'Links-influenced layout with fescue-lined fairways and firm playing conditions. Creeks and lakes throughout rolling Missouri terrain. Multiple tee options accommodate all skill levels.\n\nPublic at $40-75 — affordable championship golf south of KC.', playingTips: 'The fescue rough is thick and penal. Keep it on the fairway. Course management off the tee is essential.', faqs: [{ question: 'Who designed it?', answer: 'Jim Colbert, Kansas City native and 8-time PGA Tour winner.' }]},
    { id: 'kc-10', name: 'Shoal Creek Golf Club', slug: 'shoal-creek-golf-club-kc', city: 'Kansas City', state: 'Missouri', type: 'public', rating: 4.1, greensFee: '$35–$65', architect: 'Steve Wolfard', yearBuilt: 2001, holes: 18, par: 71, yardage: 6878, description: 'A Steve Wolfard design on the eastern edge of Kansas City, Shoal Creek winds through native Midwestern terrain with creeks, wetlands, and mature oak corridors. The accessible public layout provides a solid golf experience with interesting elevation changes and excellent drainage that keeps the course playable year-round.', highlights: ['Native Midwestern terrain with creek corridors', 'Excellent drainage for year-round play', 'Accessible public pricing in east KC'], imageAlt: 'Shoal Creek Golf Club creek-lined fairway in eastern Kansas City', history: 'Shoal Creek Golf Club opened in 2001, designed by Steve Wolfard as an upscale championship public course in northeast Kansas City (Clay County). Owned by KC Parks and Recreation, operated by KemperSports. Earned 4-star Golf Digest recognition and consistently ranks among Missouri\\\'s best public courses.\n\nThe layout features more elevation change than most KC-area courses, with Penn G-2 bentgrass greens and Zoysia fairways. Shoal Creek itself winds through the property. Open year-round with excellent drainage.', signatureHoles: [{ hole: 14, par: 4, yardage: 420, description: 'One of several holes showcasing the surprising elevation changes, mature trees, and Shoal Creek water features. The variety of challenging holes with natural terrain gives this municipal course a private-club feel.' }], whatToExpect: 'A 6,950-yard par-71 with more elevation change than typical KC courses. Tree-lined fairways, strategic bunkering, and Shoal Creek winding through the property. Conditioning is excellent for a municipal course.\n\nPublic at $35-65. Regularly hosts corporate and charity outings.', playingTips: 'Factor elevation into yardage decisions — the slopes are more significant than expected.\n\nGenerous fairways are offset by well-placed bunkers and water. Course management is key.', faqs: [{ question: 'Is it really municipal?', answer: 'Yes — owned by KC Parks and Recreation. But the conditioning and layout quality rival private clubs. 4-star Golf Digest recognition.' }]},
    { id: 'kc-11', name: 'Hallbrook Country Club', slug: 'hallbrook-country-club', city: 'Leawood', state: 'Kansas', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Tom Watson Design', yearBuilt: 1989, holes: 18, par: 71, yardage: 6840, description: 'Another Tom Watson design in the Kansas City area, Hallbrook Country Club in Leawood is an intimate private club that reflects Watson\'s love of links-style architecture. The layout features firm fairways, subtle green contours, and a walking-friendly design that emphasizes shot-making over sheer distance.', highlights: ['Tom Watson private club design', 'Links-influenced firm-and-fast conditions', 'Walking-friendly intimate layout'], imageAlt: 'Hallbrook Country Club Tom Watson fairway in Leawood Kansas', history: 'Hallbrook Country Club in Leawood was designed by Tom Fazio with Tom Watson consulting — the eight-time major champion\\\'s only design involvement in his hometown of Kansas City. The Hall family developed it as a premier residential community where the golf course property was chosen first.\n\nRated 74.1/140 slope. Features notable elevation changes uncommon for KC, natural creek systems, and heavily wooded hillsides. Hosts the annual Watson Challenge tournament. Private.', signatureHoles: [{ hole: 12, par: 3, yardage: 185, description: 'One of several par 3s well-regarded for visual drama and green complex difficulty. The Fazio/Watson collaboration shows in strategic challenge and scenic woodland setting.' }], whatToExpect: 'Demanding private layout through native prairie grasses and wooded hillsides with significant elevation changes. Creative bunkering and well-defended greens.\n\nThe only Watson-associated design in his hometown. Private membership in Leawood.', playingTips: 'The 140 slope is legitimate. Choose tees wisely. Trust your rangefinder over your eyes on the rolling terrain.', faqs: [{ question: 'Is this Tom Watson\\\'s course?', answer: 'Fazio designed with Watson consulting — the only Watson-associated design in his KC hometown.' }]},
  ],
  'st-louis-missouri': [
    { id: 'stl-1', name: 'Bellerive Country Club', slug: 'bellerive-country-club', city: 'Town and Country', state: 'Missouri', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Robert Trent Jones Sr.', yearBuilt: 1960, holes: 18, par: 72, yardage: 7547, description: 'Host of the 2018 PGA Championship won by Brooks Koepka, Bellerive has also hosted the 1965 U.S. Open and 1992 PGA Championship. Robert Trent Jones Sr.\'s design through rolling Missouri terrain features generous fairways, bold bunkering, and challenging par 4s that test the world\'s best.', highlights: ['2018 PGA Championship host venue', '1965 U.S. Open and 1992 PGA Championship host', 'Robert Trent Jones Sr. championship design'], imageAlt: 'Bellerive Country Club championship fairway in Town and Country Missouri', history: 'Designed by Robert Trent Jones Sr., opened 1960. Hosted the 1965 U.S. Open (Gary Player), 1992 PGA Championship, and 2018 PGA Championship (Brooks Koepka). Rees Jones performed championship preparation. Elite Midwest private club.', signatureHoles: [{ hole: 2, par: 4, yardage: 465, description: 'Demanding par 4 setting the championship tone.' }, { hole: 10, par: 4, yardage: 445, description: 'Strong back-nine start with rolling terrain and defended green.' }, { hole: 15, par: 4, yardage: 470, description: 'One of the toughest holes, pivotal in championship finishes.' }, { hole: 18, par: 4, yardage: 460, description: 'Demanding finisher witnessing dramatic championship conclusions.' }], whatToExpect: 'Major championship venue at 7,547 yards with generous fairways but demanding green complexes. Rolling Missouri terrain. Exceptional conditioning.\n\nPrivate club only.', playingTips: 'Generous fairways reward aggressive driving but approaches to well-defended greens require precision. Par 4s exceeding 440 yards are the toughest holes.', faqs: [{ question: 'Public?', answer: 'No. Exclusive private club.' }, { question: 'Championships?', answer: '1965 U.S. Open, 1992 PGA, 2018 PGA.' }, { question: 'Designer?', answer: 'Robert Trent Jones Sr., 1960.' }, { question: 'Location?', answer: 'Town and Country, a St. Louis suburb.' }] },
    { id: 'stl-2', name: 'Old Warson Country Club', slug: 'old-warson-country-club', city: 'Ladue', state: 'Missouri', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Robert Trent Jones Sr.', yearBuilt: 1954, holes: 18, par: 71, yardage: 7249, description: 'A Robert Trent Jones Sr. design in the affluent Ladue area, Old Warson hosted the 1971 Ryder Cup and has been a perennial top-100 course in America. The classic parkland layout through mature hardwoods features RTJ Sr.\'s trademark large greens, expansive bunkers, and strategic water hazards.', highlights: ['1971 Ryder Cup host venue', 'Perennial top-100 ranked course', 'RTJ Sr. classic parkland design in Ladue'], imageAlt: 'Old Warson Country Club RTJ Sr fairway through Ladue Missouri hardwoods', history: 'Old Warson Country Club opened in 1954, designed by Robert Trent Jones Sr. in the affluent suburb of Ladue west of St. Louis. The course hosted the 1971 Ryder Cup — the last team featuring Arnold Palmer, Jack Nicklaus, and Lee Trevino together — where the U.S. won 18.5 to 13.5. Also hosted the 2009 U.S. Women\\\'s Amateur.\n\nA fixture on Golf Digest\\\'s America\\\'s 100 Greatest Courses from the late 1960s through the 1990s. RTJ Sr.\\\'s trademark large, severely contoured greens make putting the defining challenge.', signatureHoles: [{ hole: 13, par: 3, yardage: 210, description: 'A demanding RTJ Sr. par 3 requiring precise iron play to hold a large, severely contoured green. The par 3s are characteristically demanding in the RTJ tradition — massive surfaces with slopes that create three-putt territory from the wrong position.' }], whatToExpect: 'An undulating, tree-lined par-71 through rolling Ladue terrain. The large, severely contoured greens are the defining feature — being on the wrong tier can mean three-putting or worse. Water on roughly a third of the holes. Immaculate conditioning.\n\nStrictly private — one of the most prestigious clubs in St. Louis.', playingTips: 'Approach shot placement is everything. Being on the wrong tier of these massive greens means three-putt territory.\n\nTree-lined corridors punish wayward drives. Course management off the tee is rewarded.\n\nPay close attention to pin positions — the wrong side of these greens is genuinely penal.', faqs: [{ question: 'Did it really host the Ryder Cup?', answer: 'Yes — the 1971 Ryder Cup, the last team featuring Palmer, Nicklaus, and Trevino together. U.S. won 18.5-13.5.' }, { question: 'Who designed it?', answer: 'Robert Trent Jones Sr. (1954). A perennial top-100 course in America.' }]},
    { id: 'stl-3', name: 'St. Louis Country Club', slug: 'st-louis-country-club', city: 'Clayton', state: 'Missouri', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Charles Blair Macdonald / Seth Raynor', yearBuilt: 1914, holes: 18, par: 71, yardage: 6697, description: 'A Charles Blair Macdonald and Seth Raynor collaboration, St. Louis Country Club is an architectural treasure featuring classic template holes. The layout hosted the 1947 U.S. Open and brings Golden Age design principles to the rolling hills of Clayton with Redan, Biarritz, and Eden holes.', highlights: ['Macdonald-Raynor template hole design', '1947 U.S. Open host', 'Golden Age architectural treasure'], imageAlt: 'St. Louis Country Club Macdonald-Raynor template fairway in Clayton Missouri', history: 'St. Louis Country Club was founded in 1892 with the current 18-hole layout designed by Charles Blair Macdonald and Seth Raynor in 1914 — one of golf\\\'s most celebrated Golden Age collaborations. The course hosted the 1947 U.S. Open, famously won by Lew Worsham over Sam Snead by a single stroke in a dramatic 18-hole playoff.\n\nThe layout features Macdonald and Raynor\\\'s famous template holes: a celebrated Biarritz (225-yard par 3 with distinctive deep center swale), a Reverse Redan (185-yard 16th — unique among M/R designs), and other classic British-inspired designs. Golf Digest ranks it among America\\\'s Second 100 Greatest.', signatureHoles: [{ hole: 2, par: 3, yardage: 225, description: 'A celebrated Biarritz template — a 225-yard par 3 with a long green featuring the distinctive deep swale through the center. One of the most studied examples of the template by golf architecture enthusiasts worldwide.' }, { hole: 16, par: 3, yardage: 185, description: 'A Reverse Redan — unique among Macdonald/Raynor designs which typically feature left-to-right Redans. The reversed orientation makes this a rare architectural curiosity as well as a demanding par 3.' }], whatToExpect: 'A Golden Age par-71 showcasing Macdonald and Raynor\\\'s template philosophy — strategic, thought-provoking holes referencing the great holes of Britain. Precise iron play and ground-game options are rewarded. Green complexes with slopes, shelves, and contours create natural pin positions.\n\nStrictly private — an architectural treasure in Clayton, Missouri.', playingTips: 'Study the template holes before playing. Understanding a Redan green (angled away) or Biarritz swale helps pick the right club and aim point.\n\nThe ground game is encouraged on approaches. Bump-and-run shots are viable and often smarter.\n\nPutting surfaces have old-school contours that break more than they appear.', faqs: [{ question: 'What are template holes?', answer: 'Macdonald and Raynor recreated famous British holes: Biarritz (deep-swale par 3), Redan (angled-away green), Eden, Short, etc. St. Louis CC features some of the finest examples.' }, { question: 'What happened at the 1947 US Open?', answer: 'Lew Worsham beat Sam Snead by one stroke in an 18-hole playoff — Worsham holed a short putt on the 18th after a measurement dispute. One of the most dramatic finishes in Open history.' }]},
    { id: 'stl-4', name: 'Boone Valley Golf Club', slug: 'boone-valley-golf-club', city: 'Augusta', state: 'Missouri', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Hale Irwin', yearBuilt: 2001, holes: 18, par: 71, yardage: 7213, description: 'Designed by St. Louis native and three-time U.S. Open champion Hale Irwin, Boone Valley is carved through scenic Missouri River bluffs near Augusta. The dramatic layout features significant elevation changes, panoramic valley views, and a challenging test that reflects Irwin\'s competitive golf philosophy.', highlights: ['Hale Irwin design on Missouri River bluffs', 'Three-time U.S. Open champion architect', 'Dramatic elevation changes and valley views'], imageAlt: 'Boone Valley Golf Club fairway on Missouri River bluffs near Augusta', history: 'Boone Valley Golf Club sits on scenic Missouri River bluffs near Augusta, about 45 minutes west of St. Louis. Originally designed by P.B. Dye (son of Pete Dye) in 1992. Three-time U.S. Open champion and St. Louis native Hale Irwin later made substantial modifications, particularly to holes 15 and 18, prior to the 2007 U.S. Junior Amateur.\n\nThe club hosted the Boone Valley Classic on the Senior PGA Tour from 1996-2001 — Irwin himself won two of those events. Memorably, Larry Gilbert beat Irwin (the course\\\'s own architect) in a playoff. Water hazards come into play on twelve of eighteen holes.', signatureHoles: [{ hole: 18, par: 4, yardage: 440, description: 'One of the holes redesigned by Hale Irwin before the 2007 U.S. Junior Amateur. The dramatic Missouri River bluff terrain provides elevation changes and sweeping valley views for a memorable closer.' }], whatToExpect: 'A private design with wide fairways but challenging green complexes. Bentgrass throughout. Rating 74.3 / slope 145 from the back tees — a serious test. Water on twelve of eighteen holes demands course management.\n\nThe secluded setting in Missouri wine country provides panoramic river valley views. Open seasonally, roughly mid-February through mid-December.\n\nStrictly private.', playingTips: 'Despite generous fairways, twelve holes with water demand respect. Course management over length.\n\nElevation changes along the bluffs mean frequent uphill/downhill lies. Adjust stance and club selection.\n\nGreens can be quick and tricky. Favor below-the-hole positions.', faqs: [{ question: 'Did Hale Irwin design the whole course?', answer: 'P.B. Dye designed the original (1992). Irwin made substantial modifications, especially to holes 15 and 18, before the 2007 U.S. Junior Amateur.' }, { question: 'What is the Senior Tour connection?', answer: 'The Boone Valley Classic ran 1996-2001. Irwin won twice. Memorably, Larry Gilbert beat Irwin in a playoff at Irwin\\\'s own course.' }]},
    { id: 'stl-5', name: 'Tapawingo National Golf Club', slug: 'tapawingo-national', city: 'St. Louis', state: 'Missouri', type: 'public', rating: 4.3, greensFee: '$50–$95', architect: 'Gary Kern', yearBuilt: 2002, holes: 18, par: 72, yardage: 7136, description: 'Consistently rated the top public course in the St. Louis metro area, Tapawingo National features a rolling layout through wooded terrain with dramatic elevation changes. The championship design delivers a premium golf experience at public pricing with excellent conditioning and scenic Missouri views.', highlights: ['Top-rated public course in St. Louis metro', 'Dramatic elevation changes through woods', 'Premium championship experience at public pricing'], imageAlt: 'Tapawingo National Golf Club rolling fairway through Missouri woods', history: 'Tapawingo National is a 27-hole public facility with three nines — Meramec, Woodlands, and Prairie — in Sunset Hills. The address sits on Gary Player Drive, reflecting the World Golf Hall of Famer\\\'s design involvement. Ranked inside Golf Digest\\\'s top 10 in Missouri (1997) and consistently rated one of the best public courses in the St. Louis metro.\n\nIsolated holes set among rivers, lakes, and hardwood forests mean many holes feel like their own world. Home course for Missouri Baptist University athletics.', signatureHoles: [{ hole: 9, par: 4, yardage: 420, description: 'One of several holes where anything landing short of the green rolls back into the hazard. The heavily wooded setting and dramatic water features create a demanding but scenic par 4.' }], whatToExpect: 'Heavily wooded terrain with significant water features. Each hole has a distinct personality through isolated settings among rivers, lakes, and hardwoods. The 27-hole format allows three different 18-hole combinations.\n\nChallenging but offering opportunities to score. Greens in excellent condition. Expect to lose a few balls — many holes are bordered by thick woods.\n\nPublic at $50-95 — premium public experience.', playingTips: 'Club selection on approaches is critical — several greens are guarded by water punishing anything short.\n\nPlay to centers of greens rather than chasing pins near hazards.\n\nThe 27-hole format provides variety — ask which combination is most interesting today.', faqs: [{ question: 'How many holes?', answer: '27 holes across three nines (Meramec, Woodlands, Prairie). Different 18-hole combinations provide variety.' }, { question: 'Is it the best public in STL?', answer: 'Consistently rated among the top public courses in the St. Louis metro area.' }]},
    { id: 'stl-6', name: 'Gateway National Golf Links', slug: 'gateway-national-golf-links', city: 'Madison', state: 'Illinois', type: 'public', rating: 4.2, greensFee: '$40–$75', architect: 'Keith Foster', yearBuilt: 1998, holes: 18, par: 71, yardage: 7174, description: 'A Keith Foster links-style design across the river in Madison, Illinois, Gateway National offers windswept, treeless golf with views of the St. Louis skyline and Gateway Arch. The layout through reclaimed wetlands features firm-and-fast conditions, fescue rough, and pot bunkers unusual for the region.', highlights: ['Links-style with St. Louis Arch views', 'Keith Foster firm-and-fast design', 'Reclaimed wetlands with fescue and pot bunkers'], imageAlt: 'Gateway National Golf Links with Gateway Arch and St. Louis skyline views', history: 'Gateway National opened in 1998, designed by Keith Foster with Kevin Hargrave on the Illinois side of the Mississippi River in Madison — the only true links-style course in the St. Louis metro area. Features bentgrass fairways and greens, one of the few public courses in the region with that distinction.\n\nPanoramic views of the Gateway Arch and St. Louis skyline from multiple holes make it uniquely photogenic. Located just 10 minutes from the Arch. Claims the title of No. 1 public golf course in St. Louis.', signatureHoles: [{ hole: 10, par: 4, yardage: 280, description: 'A driveable par 4 over a small creek running in front of the green. Many holes offer Gateway Arch and St. Louis skyline views in the background — the course\\\'s most distinctive visual feature.' }], whatToExpect: 'A wide-open, windswept links layout through native grasses — wind is a major factor. Links-style hazards including fescue rough, pot bunkers, and minimal tree cover. The design rewards bump-and-run ground-game options.\n\nBentgrass fairways and greens — rare for public golf in the region. Course rating 74.2, slope 127 from 7,178-yard tips.\n\nPublic at $40-75. 10 minutes from the Gateway Arch.', playingTips: 'Wind management is essential. Club up/down and consider ground-game options — the links design rewards bump-and-run shots.\n\nBentgrass surfaces are typically in very good condition. The firmness favors running approaches.\n\nPlay appropriate tees — 7,178 yards plays long, especially into the wind.', faqs: [{ question: 'Can you really see the Gateway Arch?', answer: 'Yes — panoramic views of the Arch and St. Louis skyline from multiple holes. Located just 10 minutes from the Arch.' }, { question: 'Is it really links-style?', answer: 'Yes — the only true links-style course in the St. Louis metro. Wide open, windswept, fescue rough, pot bunkers, minimal trees. Designed by Keith Foster.' }]},
    { id: 'stl-7', name: 'Persimmon Woods Golf Club', slug: 'persimmon-woods-golf-club', city: 'Weldon Spring', state: 'Missouri', type: 'semi-private', rating: 4.2, greensFee: '$55–$100', architect: 'Jack Nicklaus', yearBuilt: 1998, holes: 18, par: 72, yardage: 7091, description: 'A Jack Nicklaus design in Weldon Spring, Persimmon Woods offers semi-private access to championship golf in St. Charles County. The layout winds through mature hardwood forest with strategic water hazards and Nicklaus\'s signature bold bunkering on rolling Missouri terrain.', highlights: ['Jack Nicklaus semi-private design', 'Mature hardwood forest routing', 'Championship golf in St. Charles County'], imageAlt: 'Persimmon Woods Golf Club Jack Nicklaus fairway through Missouri hardwoods', history: 'Persimmon Woods opened in 1998, designed by Keith Foster on a rolling 192-acre property in Weldon Spring, west of St. Louis. The front nine has a decidedly links-style feel with open, windswept holes, while the back nine transitions into a more wooded, traditional parkland layout — two distinct experiences in one round.\n\nRegularly used as a site for both men\\\'s and women\\\'s U.S. Open qualifying. Rated 74/132 from the back tees at 6,939 yards. Keith Foster\\\'s creative use of terrain is on full display.', signatureHoles: [{ hole: 10, par: 4, yardage: 420, description: 'The transition hole where the course shifts from the links-style front nine to the wooded parkland back nine. The dual personality of the course is itself the signature feature — two experiences in one round.' }], whatToExpect: 'A challenging but playable layout with pristine conditioning. The links front nine plays firmer and faster; the tree-lined back nine demands more aerial precision. Well-groomed fairways and tournament-ready greens.\n\nSemi-private access at $55-100. Features a state-of-the-art practice center and award-winning PGA instruction staff.', playingTips: 'Adjust strategy between halves — the open front nine rewards ground shots, the wooded back nine demands aerial precision.\n\nThe course has enough teeth to host U.S. Open qualifiers. Play within yourself.\n\nSix tee sets accommodate all skill levels — choose honestly.', faqs: [{ question: 'Does it host U.S. Open qualifying?', answer: 'Yes — regularly hosts both men\\\'s and women\\\'s U.S. Open qualifying events.' }, { question: 'Who designed it?', answer: 'Keith Foster, opening in 1998. Foster\\\'s creative terrain usage creates two distinct experiences — links front, parkland back.' }]},
    { id: 'stl-8', name: 'Algonquin Golf Club', slug: 'algonquin-golf-club', city: 'Glendale', state: 'Missouri', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Seth Raynor', yearBuilt: 1899, holes: 18, par: 70, yardage: 6620, description: 'One of the oldest clubs in Missouri, Algonquin features a Seth Raynor redesign from 1921 with classic template holes in a compact parkland setting. The intimate layout through mature St. Louis suburbs delivers Golden Age charm with Raynor\'s Redan, Punchbowl, and Short holes.', highlights: ['Seth Raynor 1921 template hole redesign', 'One of Missouri\'s oldest golf clubs', 'Compact Golden Age charm in Glendale'], imageAlt: 'Algonquin Golf Club Seth Raynor template fairway in Glendale Missouri', history: 'Algonquin Golf Club was founded in 1899, making it one of Missouri\\\'s oldest golf institutions. Tom Bendelow designed the original nine in 1904 with Robert Foulis laying out the initial routing. Seth Raynor — the renowned protege of C.B. Macdonald — redesigned the course around 1921, incorporating his signature template holes inspired by classic British designs.\n\nRaynor built fewer than 50 courses before his death in 1926, making his work highly prized. Algonquin\\\'s template par 3s (Redan, Biarritz, Short) are the holes most prized by architecture enthusiasts.', signatureHoles: [{ hole: 4, par: 3, yardage: 175, description: 'One of Raynor\\\'s classic template par 3s — bold green complexes with distinct contours drawn from the great holes of Scotland and England. These Golden Age designs reward specific shot shapes and punish others.' }], whatToExpect: 'A compact, strategic par-70 rewarding precision and shot-shaping over power. Raynor\\\'s template greens feature deep swales (Biarritz), angled surfaces (Redan), and punchbowl contours. The intimate pre-1930s design has Golden Age charm throughout.\n\nStrictly private — one of Missouri\\\'s oldest clubs in the Glendale suburb of St. Louis.', playingTips: 'Study green complexes — Raynor\\\'s template greens reward specific shot shapes. Position off the tee matters more than distance on this compact layout.\n\nExpect pin positions playing to the architecture\\\'s strategic intent.', faqs: [{ question: 'What are Raynor template holes?', answer: 'Seth Raynor recreated famous British holes — Redan, Biarritz, Short, Eden, Alps. Algonquin features several, making it architecturally significant for a compact suburban club.' }, { question: 'How old is it?', answer: 'Founded 1899 — one of Missouri\\\'s oldest golf institutions. Raynor redesigned it around 1921.' }]},
    { id: 'stl-9', name: 'Gateway National Golf Links', slug: 'gateway-national-golf-links', city: 'Madison', state: 'Illinois', type: 'public', rating: 4.2, greensFee: '$40–$75', architect: 'Keith Foster', yearBuilt: 1998, holes: 18, par: 71, yardage: 7157, description: 'A Keith Foster links-style design on the Illinois side of the Mississippi River, Gateway National offers panoramic views of the St. Louis skyline and Gateway Arch. The windswept layout through wetlands and native grasses delivers an authentic links experience unusual for the Midwest.', highlights: ['Panoramic St. Louis skyline and Arch views', 'Keith Foster links-style design', 'Authentic windswept links feel on Mississippi'], imageAlt: 'Gateway National Golf Links fairway with St. Louis skyline and Gateway Arch views', history: 'Gateway National Golf Links opened in 1998, designed by Keith Foster on the Illinois side of the Mississippi River — the only true links-style course in the St. Louis metro. Bentgrass fairways and greens with panoramic Gateway Arch and St. Louis skyline views.\n\nThe windswept layout through native grasses features fescue rough, pot bunkers, and minimal tree cover. Claims the No. 1 public course title in St. Louis. 10 minutes from the Gateway Arch.', signatureHoles: [{ hole: 10, par: 4, yardage: 280, description: 'A driveable par 4 over a creek with Gateway Arch views in the background. The links design rewards ground-game creativity.' }], whatToExpect: 'Links-style public golf with wind as the primary defense. Bentgrass surfaces in excellent condition. Gateway Arch and skyline views from multiple holes.\n\nPublic at $40-75.', playingTips: 'Wind management is essential. Bump-and-run approaches often smarter than aerial play on this links layout.', faqs: [{ question: 'Is it really links-style?', answer: 'Yes — the only true links course in the STL metro. Keith Foster design with fescue, pot bunkers, and open terrain.' }]},
    { id: 'stl-10', name: 'The Country Club at the Legends', slug: 'cc-at-the-legends', city: 'Eureka', state: 'Missouri', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 2001, holes: 18, par: 72, yardage: 7138, description: 'A Tom Fazio design west of St. Louis in Eureka, The Country Club at the Legends features dramatic Ozark foothill terrain with significant elevation changes and mature hardwood forest. The private layout delivers Fazio\'s trademark visual drama and strategic challenge through one of the most naturally scenic properties in the metro area.', highlights: ['Tom Fazio design in Ozark foothills', 'Dramatic elevation changes and hardwood forest', 'One of metro St. Louis\'s most scenic properties'], imageAlt: 'Country Club at the Legends Tom Fazio fairway through Ozark foothills near Eureka', history: 'The Country Club at the Legends opened in 2001, designed by Tom Fazio on a wooded property in the Ozark foothills west of St. Louis in Eureka. The dramatic elevation changes through mature hardwood forest showcase Fazio\\\'s trademark visual drama.\n\nRanked among the top private courses in Missouri. The Ozark foothill setting distinguishes it from the flatter river-corridor courses closer to downtown.', signatureHoles: [{ hole: 14, par: 4, yardage: 430, description: 'One of several holes carved through mature hardwood forest with dramatic Ozark foothill elevation changes. Fazio\\\'s visual drama is on full display with drops and rises through the rolling terrain.' }], whatToExpect: 'A 7,138-yard par-72 with significant elevation shifts, tight tree-lined corridors, and strategic bunkering. The mature hardwood canopy creates a secluded parkland feel.\n\nStrictly private — one of the premier clubs in the St. Louis metro.', playingTips: 'Accuracy off the tee is paramount — hardwood-lined fairways punish wayward drives.\n\nClub selection must account for the rolling Ozark terrain.', faqs: [{ question: 'Who designed it?', answer: 'Tom Fazio (2001). One of his few private designs in the St. Louis region.' }]},
    { id: 'stl-11', name: 'Bogey Hills Country Club', slug: 'bogey-hills-country-club', city: 'St. Charles', state: 'Missouri', type: 'private', rating: 4.2, greensFee: 'Members Only', architect: 'Robert Trent Jones Sr.', yearBuilt: 1964, holes: 18, par: 71, yardage: 6927, description: 'A Robert Trent Jones Sr. design in St. Charles, Bogey Hills is a well-respected private club with classic RTJ Sr. features including large tiered greens, sweeping bunkers, and strategic water hazards. The mature parkland setting along the Missouri River bluffs provides a serene and challenging golf experience.', highlights: ['Robert Trent Jones Sr. classic design', 'Mature parkland along Missouri River bluffs', 'Well-respected St. Charles area private club'], imageAlt: 'Bogey Hills Country Club RTJ Sr fairway along Missouri River bluffs', history: 'Bogey Hills Country Club was founded in 1962, a family-owned and operated private club in St. Charles. The course features zoysia fairways, bentgrass greens running at about 10 on the stimpmeter, white sand bunkers, and six water hazards.\n\nVoted the No. 1 country club in St. Charles. Described as the best-kept golf secret in St. Louis, with immaculate conditioning and strategic shot values that punch well above its profile. Five sets of tees accommodate all skill levels.', signatureHoles: [{ hole: 13, par: 3, yardage: 175, description: 'Singled out by reviewers as outstanding — excellent views and a demanding tee shot. The combination of water, bunkering, and elevated green creates a memorable par 3.' }], whatToExpect: 'A par-71 playing 6,435 yards (slope 135) with mature trees lining virtually every hole. Classic old-school country club atmosphere. Greens have significant undulation. The difficulty rating is 8.5/10.\n\nPrivate — one of St. Charles\\\'s most respected clubs.', playingTips: 'Stay below the hole on the undulating greens. Course management matters more than power on this tight, tree-lined layout.', faqs: [{ question: 'Is it the best in St. Charles?', answer: 'Voted No. 1 country club in St. Charles. Described as the best-kept golf secret in St. Louis.' }]},
  ],
  'reno-nevada': [
    { id: 'ren-1', name: 'Edgewood Tahoe Golf Course', slug: 'edgewood-tahoe-golf', city: 'Stateline', state: 'Nevada', type: 'resort', rating: 4.7, greensFee: '$175–$350', architect: 'George Fazio', yearBuilt: 1968, holes: 18, par: 72, yardage: 7529, description: 'Host of the American Century Celebrity Championship on the south shore of Lake Tahoe, Edgewood Tahoe is one of the most scenic courses in the West. The George Fazio design plays along the lake with stunning Sierra Nevada mountain views, towering pines, and three holes directly on the shoreline.', highlights: ['American Century Celebrity Championship host', 'Three holes directly on Lake Tahoe shoreline', 'Sierra Nevada mountain panoramic views'], imageAlt: 'Edgewood Tahoe Golf Course fairway along Lake Tahoe shoreline with Sierra Nevada mountains', history: 'Edgewood Tahoe was designed by George Fazio in 1968 and later refined by nephew Tom Fazio, sitting at 6,200 feet on the southeastern shore of Lake Tahoe. Home of the American Century Celebrity Championship (televised annually in July, featuring Charles Barkley, Tony Romo, Steph Curry, and others).\n\nThe only course at Lake Tahoe with holes directly on the shoreline. The 16-17-18 lakefront finishing stretch (par 5 / par 3 / par 5) is considered one of the most spectacular closings in American golf. Ranked No. 1 in GolfPass\\\'s Golfers\\\' Choice 2025.', signatureHoles: [{ hole: 17, par: 3, yardage: 207, description: 'Plays directly along the Lake Tahoe shoreline — iconic from celebrity tournament broadcasts. A bunker guards the front of this demanding par 3 with the crystal-clear lake as backdrop. Part of the spectacular 16-17-18 lakefront finish.' }], whatToExpect: 'A 7,529-yard par-72 resort course at 6,200 feet. At least 11 holes dogleg right (friendly for faders). Three holes directly on the Lake Tahoe shoreline. Hole 15 features a blind tee shot with a mirror at the tee to check the fairway.\n\nThe Lodge at Edgewood Tahoe is a luxury resort adjacent to the first tee. Green fees $250-425 depending on season.\n\nGraded A-minus, ranked 2nd in Nevada.', playingTips: 'Play conservatively around the doglegs — safe angles produce more greens in regulation than aggressive corner-cutting.\n\nThe altitude adds distance to every club. Adjust accordingly.\n\nThe lakefront finishing holes play into prevailing afternoon winds. Club up for the close.\n\nThe mirror on 15\\\'s tee is not decoration — use it to check the blind fairway.', faqs: [{ question: 'What is the Celebrity Championship?', answer: 'The American Century Celebrity Championship, televised annually in July. Barkley, Romo, Steph Curry, and other celebrities compete here.' }, { question: 'Are there really holes on the lake?', answer: 'Yes — three holes directly on the Lake Tahoe shoreline. The only course at Tahoe with this feature. The 16-17-18 lakefront finish is legendary.' }]},
    { id: 'ren-2', name: 'Montreux Golf & Country Club', slug: 'montreux-golf-country-club', city: 'Reno', state: 'Nevada', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 1997, holes: 18, par: 72, yardage: 7472, description: 'A Jack Nicklaus design in the Sierra foothills south of Reno, Montreux hosted the PGA Tour\'s Barracuda Championship for many years. The mountain layout winds through ponderosa pines and aspens at 5,500 feet elevation with dramatic views of the surrounding peaks and Galena Creek.', highlights: ['Former PGA Tour Barracuda Championship host', 'Jack Nicklaus Sierra foothill design', '5,500-foot elevation mountain setting'], imageAlt: 'Montreux Golf Club Jack Nicklaus fairway through Sierra pines south of Reno', history: 'Montreux Golf & Country Club opened in 1997 as the only Jack Nicklaus Signature Design course in Northern Nevada. Built in the foothills of the Sierra Nevada at 5,500 feet elevation south of Reno, the course was carved through ponderosa pines, aspens, and along the banks of Galena Creek. Nicklaus himself has designated Montreux among his top four or five designs worldwide.\n\nThe club became closely associated with the PGA Tour when it began hosting the Reno-Tahoe Open in 1999, an event later rebranded as the Barracuda Championship. The tournament used the unique Modified Stableford scoring format. Montreux hosted the event through 2019, establishing itself as one of the most difficult venues on the PGA Tour schedule.\n\nThe signature stretch known as the Bear Trap encompasses holes 6, 7, and 8, featuring shimmering lakes, breathtaking mountain views, and undulating greens that test even the best professionals.', signatureHoles: [{ hole: 6, par: 4, yardage: 448, description: 'The first hole of the Bear Trap, a demanding par 4 that begins the most challenging three-hole stretch on the course. Water and mountain views frame a hole that requires precision off the tee.' }, { hole: 7, par: 3, yardage: 195, description: 'The centerpiece of the Bear Trap, this scenic par 3 plays over water to a green surrounded by Sierra Nevada mountain views. Club selection is critical at elevation.' }, { hole: 17, par: 4, yardage: 464, description: 'The signature hole at Montreux with a tee box perched high above the fairway offering panoramic mountain views. The dramatic downhill tee shot sets up a demanding approach.' }, { hole: 18, par: 4, yardage: 448, description: 'A strong finishing hole that plays through ponderosa pines with Galena Creek in play. The uphill approach to the final green provides a fitting conclusion.' }], whatToExpect: 'Montreux delivers a premier mountain golf experience at 5,500 feet elevation in the Sierra foothills. The course plays to nearly 7,500 yards from the tips with a par of 72 through towering ponderosa pines and aspens along Galena Creek. Elevation changes are significant, and the mountain setting creates constantly shifting wind conditions.\n\nConditioning is excellent with bentgrass fairways and greens that roll true. The course was rated among the most difficult on the PGA Tour during its years hosting the Barracuda Championship.', playingTips: 'Altitude significantly affects ball flight at 5,500 feet. Expect shots to fly 10-15 percent farther than at sea level, and adjust club selection accordingly. The mountain terrain creates unpredictable wind patterns, so check conditions before each shot.\n\nThe Bear Trap stretch of holes 6 through 8 is where rounds can unravel. Play conservatively through this section, as water and demanding green complexes punish aggressive misses.', faqs: [{ question: 'Can the public play Montreux Golf & Country Club?', answer: 'No. Montreux is a private club with no public access. The course gained wide visibility through hosting the PGA Tour Barracuda Championship from 1999 to 2019.' }, { question: 'What is the Bear Trap at Montreux?', answer: 'The Bear Trap refers to the demanding stretch of holes 6, 7, and 8, featuring lakes, mountain views, and undulating greens named in the tradition of Jack Nicklaus courses.' }, { question: 'Has Montreux hosted PGA Tour events?', answer: 'Yes. Montreux hosted the Reno-Tahoe Open, later renamed the Barracuda Championship, from 1999 through 2019 using the Modified Stableford scoring format.' }, { question: 'What makes Montreux unique among Nicklaus designs?', answer: 'Nicklaus himself has called Montreux one of his top four or five designs. It is the only Nicklaus Signature course in Northern Nevada, set at 5,500 feet elevation.' }] },
    { id: 'ren-3', name: 'Wolf Run Golf Club', slug: 'wolf-run-golf-club', city: 'Reno', state: 'Nevada', type: 'public', rating: 4.3, greensFee: '$45–$90', architect: 'John Fleming & Gene Bates', yearBuilt: 1998, holes: 18, par: 71, yardage: 6940, description: 'One of the top-rated public courses in the Reno area, Wolf Run features a desert-mountain layout with panoramic views of the Sierra Nevada. The Fleming-Bates design winds through sagebrush and native desert terrain with dramatic elevation changes and consistent tournament-quality conditioning.', highlights: ['Top-rated public course in Reno area', 'Panoramic Sierra Nevada mountain views', 'Desert-mountain layout with elevation changes'], imageAlt: 'Wolf Run Golf Club desert fairway with Sierra Nevada mountain views in Reno', history: 'Opened 1998 by John Fleming and Gene Bates on high desert terrain south of Reno at roughly 4,500 feet elevation. Quickly became one of the top-rated public courses in the Reno-Tahoe area with tournament-quality conditioning through native sagebrush landscape.', signatureHoles: [{ hole: 3, par: 4, yardage: 410, description: 'Par 4 with Sierra views from elevated tee through desert terrain.' }, { hole: 8, par: 3, yardage: 185, description: 'Scenic par 3 with elevation change and mountain backdrop.' }, { hole: 15, par: 5, yardage: 540, description: 'Risk-reward par 5 through desert terrain.' }, { hole: 18, par: 4, yardage: 425, description: 'Strong finishing hole with Sierra Nevada backdrop.' }], whatToExpect: 'Top-tier public desert-mountain golf. Par 71, 6,940 yards with Sierra Nevada views and native sagebrush. $45-$90.', playingTips: 'Altitude at 4,500 feet means shots carry farther. Desert wind can be a factor. Stay out of sagebrush as recovery is very difficult.', faqs: [{ question: 'Public?', answer: 'Yes. $45-$90.' }, { question: 'Designer?', answer: 'Fleming & Bates, 1998.' }, { question: 'Altitude effect?', answer: 'At 4,500 feet balls carry farther.' }, { question: 'Best months?', answer: 'May through October.' }] },
    { id: 'ren-4', name: 'ArrowCreek Golf Club - Legend', slug: 'arrowcreek-legend', city: 'Reno', state: 'Nevada', type: 'semi-private', rating: 4.3, greensFee: '$60–$120', architect: 'Arnold Palmer', yearBuilt: 1999, holes: 18, par: 72, yardage: 7130, description: 'An Arnold Palmer design in the Sierra foothills above Reno, ArrowCreek Legend offers sweeping views of the Truckee Meadows and distant mountain ranges. The semi-private layout features desert-mountain terrain with strategic arroyos, native vegetation, and wind exposure at 5,000 feet.', highlights: ['Arnold Palmer Sierra foothill design', 'Sweeping Truckee Meadows views', '5,000-foot elevation desert-mountain golf'], imageAlt: 'ArrowCreek Legend Course Arnold Palmer fairway above Reno with Truckee Meadows views', history: 'ArrowCreek\\\'s Legend Course was designed by Arnold Palmer and opened August 25, 1999, in southwest Reno\\\'s Sierra foothills. A celebrity round featuring Tom Watson, Lee Trevino, Fuzzy Zoeller, and John Daly launched memberships in 1998.\n\nThe club went private in 2002, endured bankruptcy, was rescued by 56 members ("Friends of ArrowCreek") in 2014, and received a $65-million-plus renovation after Lucky Star Golf LLC purchased in 2018. The companion Challenge Course was designed by Fuzzy Zoeller and John Harbottle.', signatureHoles: [{ hole: 17, par: 4, yardage: 294, description: 'A driveable short par 4 tempting players to carry a large bunker fronting the green. High risk-reward with panoramic Truckee Meadows and Sierra Nevada views. The 18th (442 yards with ravine carry and the fastest green on the course) provides a memorable finish.' }], whatToExpect: 'A 7,115-yard par-72 weaving around ravines, dry creeks, and high-desert rock formations. Palmer incorporated forced carries, native desert grasses, and fast greens. The setting feels isolated despite proximity to Reno.\n\nSemi-private at $60-120. Slope 140. The elevation (~5,000+ feet) adds carry distance.', playingTips: 'Solid ball-striking is essential due to forced carries over ravines.\n\nDesert landscape means lost balls vanish quickly in sagebrush. Bring extras.\n\nGreens are notably fast, especially the 18th.\n\nThe elevation adds carry distance — club down accordingly.', faqs: [{ question: 'Who designed it?', answer: 'Arnold Palmer (1999). The companion Challenge Course was designed by Fuzzy Zoeller.' }, { question: 'What was the rescue story?', answer: '56 members ("Friends of ArrowCreek") rescued the club from bankruptcy in 2014. Lucky Star Golf LLC later invested $65M+ in renovation.' }]},
    { id: 'ren-5', name: 'Old Greenwood Golf Course', slug: 'old-greenwood-golf', city: 'Truckee', state: 'California', type: 'resort', rating: 4.5, greensFee: '$100–$200', architect: 'Jack Nicklaus', yearBuilt: 2004, holes: 18, par: 72, yardage: 7518, description: 'A Jack Nicklaus Signature design near Truckee at 5,800 feet elevation, Old Greenwood winds through towering Jeffrey pines with panoramic views of the Sierra Nevada and Martis Valley. The mountain layout at Tahoe Mountain Club offers one of the premier mountain golf experiences near Lake Tahoe.', highlights: ['Jack Nicklaus Signature at 5,800-foot elevation', 'Jeffrey pine forest and Sierra views', 'Premier mountain golf near Lake Tahoe'], imageAlt: 'Old Greenwood Golf Course Jack Nicklaus mountain fairway through Jeffrey pines near Truckee', history: 'Old Greenwood is a Jack Nicklaus Signature Course that opened in 2004 as part of Tahoe Mountain Club near Truckee at 5,800 feet elevation. Named one of Golf Magazine\\\'s "10 Best New Public-Access Courses in the Country."\n\nThe course hosted the PGA Tour\\\'s Barracuda Championship beginning in 2020, significantly raising its national profile. The first Nicklaus Signature Course in the Tahoe region. A sister course, Gray\\\'s Crossing, offers a two-course package.', signatureHoles: [{ hole: 15, par: 4, yardage: 430, description: 'One of several holes with elevated green complexes backed by Sierra mountain vistas. The Jeffrey pine-lined corridor and strategic bunkering create a quintessential mountain golf experience.' }], whatToExpect: 'An 18-hole par-72 stretching to 7,518 yards (slope 140) through Jeffrey pine-lined corridors with Sierra Nevada panoramas. Deep bunkers, water hazards, large greens, and tall pines create a premier mountain golf experience.\n\nPublic play available alongside Tahoe Mountain Club membership. The Golf Academy on-site is one of the best practice facilities in Northern California.\n\n5,800-foot elevation adds ~10% to carry distances.', playingTips: 'The altitude adds roughly 10% to carry distances. Club down accordingly.\n\nLarge greens require attention to pin placement — wrong-tier positions can mean three-putts.\n\nCart-path-only restrictions apply during certain seasons. Be prepared to walk to your ball.\n\nThe Jeffrey pine corridors demand accuracy off the tee.', faqs: [{ question: 'Did the PGA Tour play here?', answer: 'Yes — the Barracuda Championship was hosted here beginning in 2020.' }, { question: 'Is it the only Nicklaus course at Tahoe?', answer: 'The first Nicklaus Signature Course in the Tahoe region. Part of Tahoe Mountain Club with sister course Gray\\\'s Crossing.' }]},
    { id: 'ren-6', name: 'Lakeridge Golf Course', slug: 'lakeridge-golf-course', city: 'Reno', state: 'Nevada', type: 'public', rating: 4.1, greensFee: '$40–$80', architect: 'Robert Trent Jones Jr.', yearBuilt: 1969, holes: 18, par: 71, yardage: 6717, description: 'A Robert Trent Jones Jr. design on a scenic hillside overlooking Reno, Lakeridge offers dramatic elevation changes and mountain views at accessible public pricing. The layout winds through desert terrain with strategic water hazards and wide fairways that provide a solid public golf experience.', highlights: ['RTJ Jr. hillside design overlooking Reno', 'Dramatic elevation changes', 'Accessible public pricing with mountain views'], imageAlt: 'Lakeridge Golf Course hillside fairway overlooking Reno valley' },
    { id: 'ren-7', name: 'The Golf Club at Genoa Lakes - Ranch', slug: 'genoa-lakes-ranch', city: 'Genoa', state: 'Nevada', type: 'public', rating: 4.2, greensFee: '$45–$85', architect: 'Peter Jacobsen & Jim Hardy', yearBuilt: 1997, holes: 18, par: 72, yardage: 7014, description: 'A Jacobsen-Hardy design in Nevada\'s oldest settlement, Genoa Lakes Ranch features panoramic views of the Sierra Nevada and Carson Valley. The layout winds through wetlands along the Carson River with mountain backdrops creating one of the most scenic public golf experiences in northern Nevada.', highlights: ['Sierra Nevada and Carson Valley panoramas', 'Carson River wetland routing', 'Set in Nevada\'s oldest settlement'], imageAlt: 'Genoa Lakes Ranch Course fairway with Sierra Nevada and Carson Valley views' },
    { id: 'ren-8', name: 'Somersett Country Club - Canyon', slug: 'somersett-canyon', city: 'Reno', state: 'Nevada', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Tom Kite', yearBuilt: 2003, holes: 18, par: 72, yardage: 6913, description: 'A Tom Kite design in the Somersett community west of Reno, the Canyon Course features a dramatic routing through desert canyons with panoramic Sierra Nevada views. The U.S. Open champion\'s design emphasizes strategic play and shot variety through elevation changes and native desert terrain.', highlights: ['Tom Kite desert canyon design', 'Panoramic Sierra Nevada mountain views', 'Strategic routing through canyon terrain'], imageAlt: 'Somersett Canyon Course Tom Kite fairway through desert canyon west of Reno' },
    { id: 'ren-9', name: 'Incline Village Championship Course', slug: 'incline-village-championship', city: 'Incline Village', state: 'Nevada', type: 'public', rating: 4.4, greensFee: '$80–$160', architect: 'Robert Trent Jones Sr.', yearBuilt: 1964, holes: 18, par: 72, yardage: 6910, description: 'A Robert Trent Jones Sr. design on the north shore of Lake Tahoe at 6,300 feet elevation, Incline Village Championship features mountain golf at its most scenic. The layout winds through towering ponderosa pines with Sierra Nevada views and Lake Tahoe glimpses from elevated tees throughout the back nine.', highlights: ['Robert Trent Jones Sr. mountain design at 6,300 feet', 'North shore Lake Tahoe location', 'Towering ponderosa pine forest setting'], imageAlt: 'Incline Village Championship Course mountain fairway near Lake Tahoe' },
    { id: 'ren-10', name: 'Lakeridge Golf Course', slug: 'lakeridge-golf-course', city: 'Reno', state: 'Nevada', type: 'public', rating: 4.1, greensFee: '$35–$75', architect: 'Robert Trent Jones Jr.', yearBuilt: 1969, holes: 18, par: 71, yardage: 6717, description: 'An RTJ Jr. design on a hillside south of Reno, Lakeridge delivers panoramic city and mountain views at an accessible price point. The rolling layout features strategic elevation changes, well-placed bunkers, and a fun closing stretch that has made it one of Reno\'s most popular daily-fee options for decades.', highlights: ['Robert Trent Jones Jr. affordable design', 'Panoramic Reno city and mountain views', 'Popular daily-fee course for decades'], imageAlt: 'Lakeridge Golf Course hillside fairway with Reno city and mountain views' },
    { id: 'ren-11', name: 'Genoa Lakes Golf Club - Ranch', slug: 'genoa-lakes-ranch', city: 'Genoa', state: 'Nevada', type: 'public', rating: 4.2, greensFee: '$50–$100', architect: 'Peter Jacobsen & Jim Hardy', yearBuilt: 1993, holes: 18, par: 72, yardage: 7085, description: 'A Jacobsen-Hardy design in Nevada\'s oldest settlement at the base of the Sierra Nevada, Genoa Lakes Ranch features open meadow-style golf with panoramic mountain views. The Carson Valley setting provides a beautiful backdrop with the Eastern Sierra rising dramatically behind the course.', highlights: ['Located in Nevada\'s oldest settlement', 'Panoramic Eastern Sierra mountain views', 'Jacobsen-Hardy meadow-style design'], imageAlt: 'Genoa Lakes Ranch Course fairway with Eastern Sierra Nevada views' },
  ],
  'bend-oregon': [
    { id: 'bnd-1', name: 'Pronghorn Resort - Nicklaus Course', slug: 'pronghorn-nicklaus', city: 'Bend', state: 'Oregon', type: 'resort', rating: 4.7, greensFee: '$150–$275', architect: 'Jack Nicklaus', yearBuilt: 2004, holes: 18, par: 72, yardage: 7379, description: 'A Jack Nicklaus Signature design at Pronghorn Resort in the high desert east of the Cascades, this course offers panoramic views of Broken Top, the Three Sisters, and Mount Bachelor. The championship layout traverses juniper-studded lava terrain with pristine conditioning at 3,400 feet elevation.', highlights: ['Jack Nicklaus Signature high desert design', 'Panoramic Cascade volcano views', 'Juniper and lava terrain at 3,400 feet'], imageAlt: 'Pronghorn Nicklaus Course fairway with Cascade volcanoes at Bend Oregon' },
    { id: 'bnd-2', name: 'Tetherow Golf Club', slug: 'tetherow-golf-club-bend', city: 'Bend', state: 'Oregon', type: 'resort', rating: 4.6, greensFee: '$100–$200', architect: 'David McLay Kidd', yearBuilt: 2008, holes: 18, par: 72, yardage: 7298, description: 'David McLay Kidd\'s Scottish links-inspired design on volcanic soil above Bend features firm, fast fescue conditions with panoramic views of Broken Top, South Sister, and Mount Bachelor. The windswept layout rewards creativity and ground-game play uncommon in the Pacific Northwest.', highlights: ['David McLay Kidd Scottish links style', 'Firm fescue conditions on volcanic soil', 'Panoramic Cascade volcano views from every hole'], imageAlt: 'Tetherow Golf Club links fairway with Cascade volcanoes near Bend Oregon', history: 'Tetherow Golf Club opened in 2008 as the creation of Scottish architect David McLay Kidd, who first gained fame designing the original Bandon Dunes course on the Oregon coast. Kidd brought his links sensibility inland to the high desert above Bend, building on volcanic soil at roughly 3,600 feet elevation with panoramic views of Broken Top, South Sister, and Mount Bachelor.\n\nThe course was the first in Oregon to achieve Audubon Certified Signature Sanctuary status, reflecting its environmentally sensitive design through native fescue grasses and minimal irrigation. Kidd designed the layout to play firm and fast, a stark departure from the soft conditions typical of Pacific Northwest golf.\n\nTetherow quickly earned recognition as one of the top resort courses in the Pacific Northwest and is consistently ranked among the best courses in Oregon.', signatureHoles: [{ hole: 5, par: 4, yardage: 380, description: 'A short par 4 that epitomizes the strategic nature of the course. Multiple angles of approach and firm fescue conditions reward creativity over brute force.' }, { hole: 12, par: 3, yardage: 175, description: 'A visually stunning par 3 with Cascade volcanoes as a backdrop. The green is exposed to wind and surrounded by native fescue.' }, { hole: 17, par: 4, yardage: 440, description: 'One of the most discussed holes on the course. Kidd himself has spoken about the challenge of this hole, which demands precision into a complex green site.' }, { hole: 18, par: 5, yardage: 575, description: 'A sweeping finishing par 5 with panoramic Cascade views. Risk-reward options create exciting finish possibilities.' }], whatToExpect: 'Tetherow is unlike any other course in the Pacific Northwest. The firm, fast fescue conditions on volcanic soil play more like a Scottish links than an American resort course. Creative ground-game shots are often preferred. Wind is a constant factor on the exposed high desert terrain.\n\nThe Cascade volcano views are extraordinary, visible from virtually every hole.', playingTips: 'Embrace the ground game. Tetherow rewards bump-and-run shots, low runners, and creative approaches. The firm fescue fairways allow the ball to release significantly.\n\nWind management is essential. The high desert terrain is exposed and conditions can change rapidly. Take an extra club into the wind and play lower trajectory shots when possible.', faqs: [{ question: 'Can the public play Tetherow?', answer: 'Yes. Tetherow is a resort course open to the public. Green fees typically range from $100 to $200 depending on season.' }, { question: 'Who designed Tetherow?', answer: 'David McLay Kidd, the Scottish architect famous for designing the original Bandon Dunes course.' }, { question: 'What makes Tetherow different?', answer: 'It plays firm and fast on fescue turf over volcanic soil, more like a Scottish links than a typical Pacific Northwest course.' }, { question: 'Is Tetherow walking friendly?', answer: 'Walking is encouraged and caddies are available. Carts are also available for those who prefer to ride.' }] },
    { id: 'bnd-3', name: 'Crosswater Club at Sunriver', slug: 'crosswater-club-sunriver', city: 'Sunriver', state: 'Oregon', type: 'resort', rating: 4.6, greensFee: '$125–$225', architect: 'Bob Cupp', yearBuilt: 1995, holes: 18, par: 72, yardage: 7693, description: 'Part of Sunriver Resort south of Bend, Crosswater is a Bob Cupp design that plays through meadow, marshland, and along the Deschutes and Little Deschutes rivers. At 7,693 yards from the tips, it is one of the longest resort courses in the Pacific Northwest with Cascade Mountain views throughout.', highlights: ['7,693-yard routing along two rivers', 'Sunriver Resort south of Bend', 'Cascade Mountain panoramic backdrop'], imageAlt: 'Crosswater Club riverside fairway with Cascade Mountains at Sunriver near Bend', history: 'Opened 1995, Bob Cupp design at Sunriver Resort along the Deschutes and Little Deschutes rivers. At 7,693 yards, one of the longest resort courses in the PNW. Crown jewel of Sunriver\'s golf collection.', signatureHoles: [{ hole: 5, par: 4, yardage: 440, description: 'Par 4 along the Deschutes River.' }, { hole: 12, par: 3, yardage: 195, description: 'Par 3 with river and Cascade views.' }, { hole: 15, par: 5, yardage: 580, description: 'Long riverside par 5.' }, { hole: 18, par: 4, yardage: 445, description: 'Strong finisher with Cascade backdrop.' }], whatToExpect: 'Premier resort golf along two rivers with Cascade views. 7,693 yards. $125-$225.', playingTips: 'Play appropriate tees. River corridor wind affects play. Meadow areas penalize wayward shots.', faqs: [{ question: 'Public?', answer: 'Resort guests. $125-$225.' }, { question: 'Designer?', answer: 'Bob Cupp, 1995.' }, { question: 'Length?', answer: '7,693 yards.' }, { question: 'Other courses?', answer: 'Meadows and Woodlands also at Sunriver.' }] },
    { id: 'bnd-4', name: 'Brasada Canyons Golf Club', slug: 'brasada-canyons', city: 'Powell Butte', state: 'Oregon', type: 'resort', rating: 4.4, greensFee: '$80–$160', architect: 'Peter Jacobsen & Jim Hardy', yearBuilt: 2007, holes: 18, par: 72, yardage: 7295, description: 'A Jacobsen-Hardy design at Brasada Ranch Resort east of Bend, this high desert course features dramatic canyon drops and panoramic views of eight Cascade peaks. The layout traverses juniper-studded rimrock terrain with 300-foot elevation changes that create some of the most dramatic holes in Oregon.', highlights: ['Views of eight Cascade peaks', '300-foot elevation changes through canyons', 'Jacobsen-Hardy high desert design'], imageAlt: 'Brasada Canyons Golf Club canyon fairway with Cascade peak views near Bend' },
    { id: 'bnd-5', name: 'Awbrey Glen Golf Club', slug: 'awbrey-glen-golf-club', city: 'Bend', state: 'Oregon', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Gene Bunny Mason', yearBuilt: 1993, holes: 18, par: 72, yardage: 7019, description: 'A private club on the west side of Bend, Awbrey Glen winds through ponderosa pine forest with views of the Deschutes River canyon and Cascade peaks. The layout features natural lava rock outcroppings, native vegetation, and a peaceful forested setting that captures the essence of Central Oregon golf.', highlights: ['Ponderosa pine forest setting', 'Deschutes River canyon and Cascade views', 'Natural lava rock outcroppings'], imageAlt: 'Awbrey Glen Golf Club pine forest fairway with Cascade views in Bend' },
    { id: 'bnd-6', name: 'Sunriver Resort - Meadows Course', slug: 'sunriver-meadows', city: 'Sunriver', state: 'Oregon', type: 'resort', rating: 4.2, greensFee: '$60–$120', architect: 'John Fought', yearBuilt: 1999, holes: 18, par: 71, yardage: 7012, description: 'A John Fought redesign at Sunriver Resort, the Meadows Course offers an accessible mountain resort experience through meadow and pine forest terrain. The layout features views of Mount Bachelor and the surrounding Cascades, with strategic water hazards and well-conditioned bent grass surfaces.', highlights: ['John Fought redesign at Sunriver Resort', 'Mount Bachelor and Cascade views', 'Accessible mountain resort golf'], imageAlt: 'Sunriver Meadows Course fairway with Mount Bachelor in Central Oregon' },
    { id: 'bnd-7', name: 'Juniper Golf Club', slug: 'juniper-golf-club-redmond', city: 'Redmond', state: 'Oregon', type: 'public', rating: 4.1, greensFee: '$35–$65', architect: 'Gene Bunny Mason', yearBuilt: 1952, holes: 18, par: 72, yardage: 6568, description: 'A classic high desert public course in Redmond, Juniper Golf Club has served Central Oregon golfers since 1952. The layout through juniper trees and desert terrain offers panoramic Cascade views, affordable pricing, and a welcoming community atmosphere that embodies small-town Oregon golf.', highlights: ['Classic high desert public course since 1952', 'Affordable Central Oregon golf', 'Panoramic Cascade Mountain views'], imageAlt: 'Juniper Golf Club desert fairway with Cascade views in Redmond Oregon' },
    { id: 'bnd-8', name: 'Pronghorn Resort - Fazio Course', slug: 'pronghorn-fazio', city: 'Bend', state: 'Oregon', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 2007, holes: 18, par: 72, yardage: 7464, description: 'The private companion to Pronghorn\'s Nicklaus Course, Tom Fazio\'s design is the longer of the two at 7,464 yards through high desert terrain. The bold Fazio shaping through juniper and lava rock with Cascade volcano views creates one of the most dramatic private club experiences in the Pacific Northwest.', highlights: ['Tom Fazio 7,464-yard high desert design', 'Companion to Nicklaus Course at Pronghorn', 'Bold shaping through juniper and lava rock'], imageAlt: 'Pronghorn Fazio Course Tom Fazio fairway through high desert terrain near Bend' },
    { id: 'bnd-9', name: 'Tetherow Golf Club', slug: 'tetherow-golf-club', city: 'Bend', state: 'Oregon', type: 'resort', rating: 4.5, greensFee: '$100–$195', architect: 'David McLay Kidd', yearBuilt: 2008, holes: 18, par: 72, yardage: 7298, description: 'A David McLay Kidd design on the southwest edge of Bend, Tetherow is a Scottish-influenced links course set against a dramatic Cascade Mountain backdrop. The windswept layout through native juniper and volcanic terrain features firm-and-fast conditions, massive greens, and sweeping Broken Top and South Sister views.', highlights: ['David McLay Kidd Scottish links-style design', 'Firm-and-fast volcanic terrain', 'Sweeping Cascade volcano panoramic views'], imageAlt: 'Tetherow Golf Club links fairway with Broken Top and South Sister Cascade views' },
    { id: 'bnd-10', name: 'Lost Tracks Golf Club', slug: 'lost-tracks-golf-club', city: 'Bend', state: 'Oregon', type: 'public', rating: 4.0, greensFee: '$35–$70', architect: 'Brian Whitcomb', yearBuilt: 1996, holes: 18, par: 72, yardage: 7003, description: 'A Brian Whitcomb design on the south side of Bend, Lost Tracks offers accessible public golf through ponderosa pine forest with Cascade Mountain views. The straightforward layout provides a welcoming experience for all skill levels while the mountain scenery and pine-scented air elevate the round.', highlights: ['Accessible public golf in south Bend', 'Ponderosa pine forest with Cascade views', 'Welcoming layout for all skill levels'], imageAlt: 'Lost Tracks Golf Club ponderosa pine fairway with Cascade views in Bend' },
    { id: 'bnd-11', name: 'Eagle Crest Resort - Ridge Course', slug: 'eagle-crest-ridge', city: 'Redmond', state: 'Oregon', type: 'resort', rating: 4.1, greensFee: '$45–$90', architect: 'John Thronson', yearBuilt: 1992, holes: 18, par: 72, yardage: 6927, description: 'Located at Eagle Crest Resort near Redmond, the Ridge Course features a high desert layout through juniper-studded terrain with expansive views of the Cascade Range. The John Thronson design offers resort-caliber golf with rolling terrain, lava rock features, and Central Oregon\'s characteristic dry, sunny conditions.', highlights: ['High desert resort golf near Redmond', 'Expansive Cascade Range panoramic views', 'Juniper and lava rock terrain features'], imageAlt: 'Eagle Crest Ridge Course high desert fairway with Cascade Range views near Redmond' },
  ],
  'milwaukee-wisconsin': [
    { id: 'mil-1', name: 'Whistling Straits - Straits Course', slug: 'whistling-straits', city: 'Sheboygan', state: 'Wisconsin', type: 'resort', rating: 4.9, greensFee: '$200–$400', architect: 'Pete Dye', yearBuilt: 1998, holes: 18, par: 72, yardage: 7790, description: 'Host of three PGA Championships and the 2021 Ryder Cup, Whistling Straits is Pete Dye\'s links masterpiece along two miles of Lake Michigan shoreline. The windswept layout features over 1,000 bunkers, dramatic bluff-top holes, and a visual spectacle that rivals the great links of the British Isles.', highlights: ['2021 Ryder Cup and three-time PGA Championship host', 'Two miles of Lake Michigan shoreline', 'Over 1,000 bunkers on Pete Dye links masterpiece'], imageAlt: 'Whistling Straits Straits Course clifftop fairway along Lake Michigan', history: 'Whistling Straits was created by Pete Dye for Herb Kohler of the Kohler Company, opening in 1998 on a former military airfield along two miles of Lake Michigan shoreline near Sheboygan, Wisconsin. Dye transformed the flat, unremarkable terrain by moving massive amounts of earth to create dunes, bluffs, and over 1,000 bunkers that give the course its dramatic, links-like appearance inspired by the great seaside courses of Ireland.\n\nThe Straits Course has hosted three PGA Championships — 2004 (won by Vijay Singh in a playoff), 2010 (Martin Kaymer), and 2015 (Jason Day with a record-setting 20-under total) — as well as the memorable 2021 Ryder Cup, where Team USA dominated Team Europe 19-9. The 2010 PGA Championship is also remembered for Dustin Johnson\'s infamous grounding-his-club-in-a-bunker penalty on the 72nd hole. The venue continues to host major amateur events and is considered one of the finest public-access courses in the world.', signatureHoles: [{ hole: 7, par: 3, yardage: 221, description: 'Named "Shipwreck," this dramatic par 3 plays from an elevated tee along the Lake Michigan bluffs to a green perched above the shoreline. The wind off the lake makes club selection extremely difficult, and bunkers surround the putting surface.' }, { hole: 17, par: 4, yardage: 489, description: 'Named "Pinched Nerve," this demanding par 4 runs along the lakefront with bunkers lining both sides. The approach plays to an elevated green with Lake Michigan as the backdrop, creating one of the most dramatic settings in championship golf.' }, { hole: 3, par: 3, yardage: 183, description: 'Named "O\'Man," this par 3 plays slightly downhill to a green nestled among dunes and deep bunkers. The wind off Lake Michigan swirls unpredictably, making what appears to be a mid-iron shot a real test of nerve.' }, { hole: 11, par: 5, yardage: 619, description: 'Named "Sand Box," this monstrous par 5 stretches over 600 yards along the lakeshore. The fairway is lined with bunkers and the wind off Lake Michigan makes reaching the green in two nearly impossible.' }], whatToExpect: 'Whistling Straits feels more like a links course on the Irish coast than anything you would expect in Wisconsin. The terrain along Lake Michigan is wild and rugged, with massive sandy dunes, tall fescue grasses, and over 1,000 bunkers — many of them unmarked waste areas where you must play the ball as it lies. The layout hugs two miles of shoreline, providing breathtaking Lake Michigan views from nearly every hole.\n\nAt 7,790 yards from the championship tees, it is one of the longest courses in the world, though the resort tees bring it down to a more manageable length. Wind off Lake Michigan is a constant companion and can add or subtract several clubs on approach shots.', playingTips: 'Be aware that many of the 1,000-plus bunkers are unmarked waste areas — you are allowed to ground your club in waste areas but not in defined bunkers. Ask your caddie or starter for clarification before you begin. Play from tees that match your handicap; the course is a monster from the tips but very enjoyable from the green or white tees.\n\nThe wind changes direction constantly as the routing loops along the lake, so re-evaluate your club selection on every shot. Bring rain gear even on sunny days — Lake Michigan weather can change rapidly. Caddies are available and highly recommended for their knowledge of the wind and green reads.', faqs: [{ question: 'Can anyone play Whistling Straits?', answer: 'Yes. The Straits Course is open to the public. Green fees are approximately $200-$400 depending on the season, highest from June through September. Kohler resort guests receive preferred tee times and package pricing.' }, { question: 'How many bunkers does Whistling Straits really have?', answer: 'The course has over 1,000 bunkers and waste areas. Many are small pot bunkers hidden in the dunes, and not all are formally marked as hazards. The distinction between bunkers and waste areas has been a point of controversy in major championships.' }, { question: 'What other courses are at the Kohler golf complex?', answer: 'The Irish Course, also designed by Pete Dye, offers a slightly less demanding links experience on the same property. Blackwolf Run, a short drive away, has two additional Pete Dye courses — the River and Meadow Valleys layouts.' }, { question: 'When is the best time to play Whistling Straits?', answer: 'June through September offers the warmest weather, though it is also peak season with the highest rates. Late May and early October can be excellent with fewer crowds and lower prices, though temperatures may be cool. The course is typically closed from November through April.' }] },
    { id: 'mil-2', name: 'Erin Hills', slug: 'erin-hills-golf', city: 'Erin', state: 'Wisconsin', type: 'public', rating: 4.8, greensFee: '$175–$300', architect: 'Dr. Michael Hurdzan, Dana Fry & Ron Whitten', yearBuilt: 2006, holes: 18, par: 72, yardage: 7823, description: 'Host of the 2017 U.S. Open, Erin Hills is a walking-only course routed through glacial kettle terrain with dramatic 100-foot elevation changes and fescue-covered ridgelines. The massive 7,823-yard layout through open meadows and native grasses delivers a links-like experience in the Wisconsin countryside.', highlights: ['2017 U.S. Open host venue', 'Walking-only through glacial kettle terrain', '7,823 yards with fescue ridgelines'], imageAlt: 'Erin Hills fescue-lined fairway through glacial terrain during U.S. Open in Wisconsin', history: 'Erin Hills was designed by Dr. Michael Hurdzan, Dana Fry, and Golf Digest architecture editor Ron Whitten on glacial kettle moraine terrain in the town of Erin, Wisconsin. The course opened in 2006, carved from farmland with dramatic 100-foot elevation changes created by glacial activity thousands of years ago.\n\nThe course hosted the 2011 U.S. Amateur before being selected for the 2017 U.S. Open — the first ever held in Wisconsin. Brooks Koepka won at 16-under par, a record-tying score. Heavy rains softened conditions and sparked debate about whether the setup was too easy.\n\nErin Hills is a walking-only public course operating as a destination resort with on-site lodging. At 7,823 yards from the championship tees, it is one of the longest courses in America with wide fescue-covered ridgelines and a links-like character unique in the Midwest.', signatureHoles: [{ hole: 18, par: 5, yardage: 663, description: 'One of the longest finishing holes in championship golf. This massive par 5 sweeps through a valley of fescue with the clubhouse perched above, creating a dramatic amphitheater finish.' }, { hole: 9, par: 3, yardage: 160, description: 'A beautiful short par 3 set in a natural amphitheater surrounded by fescue-covered ridges. Frequently cited as the most visually stunning hole on the course.' }, { hole: 14, par: 4, yardage: 465, description: 'A demanding par 4 through a valley of native fescue framed by dramatic ridgelines. One of the most photographed holes during the 2017 U.S. Open.' }, { hole: 7, par: 4, yardage: 475, description: 'A long par 4 with sweeping views of the Kettle Moraine terrain and an approach to an elevated green with expansive Wisconsin countryside vistas.' }], whatToExpect: 'Erin Hills is a walking-only course through dramatic glacial terrain with 100-foot elevation changes. Wide fairways are bordered by tall native fescue that punishes wayward shots. At 7,823 yards from the tips, it is one of the longest courses in America, though forward tees bring it to manageable length.\n\nThe open, treeless character creates a links-like feel unusual for the Midwest. Wind is significant on exposed ridgelines. On-site lodging allows a destination-golf experience.', playingTips: 'Play from appropriate tees — the course is an absolute monster from the tips. The fescue rough is thick and penal so accuracy off the tee is paramount. If you miss a fairway, pitch back to safety rather than attempting a hero shot.\n\nGreens are large but subtly contoured. Wind on exposed ridgelines can add two to three clubs. Walking is the only option so prepare for a physically demanding round over hilly terrain.', faqs: [{ question: 'Is Erin Hills open to the public?', answer: 'Yes. Green fees range from $175 to $300. On-site lodging is available for destination golfers.' }, { question: 'Who won the 2017 U.S. Open at Erin Hills?', answer: 'Brooks Koepka won at 16-under par, tying the record for lowest score relative to par in U.S. Open history at the time.' }, { question: 'Is Erin Hills walking only?', answer: 'Yes. Caddies are available and recommended given the hilly terrain and course length.' }, { question: 'How far is Erin Hills from Milwaukee?', answer: 'About 35 miles northwest of Milwaukee, roughly a 45-minute drive.' }] },
    { id: 'mil-3', name: 'Blackwolf Run - River Course', slug: 'blackwolf-run-river', city: 'Kohler', state: 'Wisconsin', type: 'resort', rating: 4.7, greensFee: '$175–$325', architect: 'Pete Dye', yearBuilt: 1988, holes: 18, par: 72, yardage: 6991, description: 'Pete Dye\'s original Kohler course, the River Course at Blackwolf Run winds through dramatic glacial terrain along the Sheboygan River. The layout features Dye\'s trademark visual intimidation with plunging ravines, island fairways, and some of the most dramatic inland holes in Wisconsin.', highlights: ['Pete Dye\'s original Kohler course', 'Dramatic Sheboygan River ravine routing', 'Among the top resort courses in America'], imageAlt: 'Blackwolf Run River Course Pete Dye fairway along Sheboygan River ravine' },
    { id: 'mil-4', name: 'Milwaukee Country Club', slug: 'milwaukee-country-club', city: 'River Hills', state: 'Wisconsin', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Harry Colt / C.H. Alison', yearBuilt: 1894, holes: 18, par: 72, yardage: 6930, description: 'Redesigned by Harry Colt and C.H. Alison in 1929, Milwaukee Country Club is a Golden Age gem in the affluent River Hills area. The classic parkland layout features Colt-Alison strategic bunkering, undulating greens, and mature tree-lined fairways that hosted the 1969 Walker Cup.', highlights: ['Harry Colt and C.H. Alison redesign', '1969 Walker Cup host venue', 'Golden Age parkland gem in River Hills'], imageAlt: 'Milwaukee Country Club Colt-Alison parkland fairway in River Hills Wisconsin', history: 'Milwaukee Country Club traces its origins to 1894 when it was founded as the Milwaukee Golf Club on the city\'s East Side. When the original land lease expired in 1909, the club relocated and eventually settled in the affluent Village of River Hills along the Milwaukee River.\n\nThe defining moment came when Harry Colt and C.H. Alison redesigned the layout in 1929, creating the Golden Age gem that exists today. The Colt-Alison design masterfully uses the Milwaukee River, with the course occupying both upland terrain and the river valley. Their strategic bunkering and undulating green complexes remain hallmarks of the design.\n\nMilwaukee Country Club has hosted the 1969 Walker Cup, the 1988 U.S. Senior Amateur, and the 2008 U.S. Women\'s Amateur Public Links. Renaissance Golf Design completed a restoration that re-established the course near the forefront of classic American designs.', signatureHoles: [{ hole: 4, par: 4, yardage: 430, description: 'A demanding par 4 along the Milwaukee River, requiring a well-placed drive to set up an approach to one of Colt and Alison\'s most cleverly contoured greens.' }, { hole: 12, par: 3, yardage: 190, description: 'A scenic par 3 over the Milwaukee River to a circular green protected by a trio of bunkers. One of the most photographed holes and a classic Colt-Alison one-shotter.' }, { hole: 15, par: 4, yardage: 415, description: 'A strategic par 4 in the river valley demanding precise positioning off the tee. The approach must navigate Colt-Alison bunkering to find the green.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finishing hole climbing back to the clubhouse through the upland section. Deep bunkers guard the approach to a challenging final green.' }], whatToExpect: 'Milwaukee Country Club occupies two distinct landscapes: the uplands above the river and the valley holes along the Milwaukee River. The Colt-Alison design rewards strategic thinking with bunkering that demands careful positioning rather than raw length. The mature tree-lined parkland setting is classic Wisconsin golf.\n\nThe course plays to approximately 6,930 yards from the back tees with a par of 72 and slope of 136. The Renaissance Golf Design restoration enhanced the original Colt-Alison features.', playingTips: 'The Colt-Alison greens are the primary defense. Many feature subtle contours that are difficult to read. Hitting approach shots to the correct quadrant is more important than flag hunting.\n\nThe river valley holes play differently from the upland holes. Wind along the river corridor can be a factor, and position off the tee is paramount on the tighter river holes.', faqs: [{ question: 'Can the public play Milwaukee Country Club?', answer: 'No. Milwaukee Country Club is a private club with no public access.' }, { question: 'Who designed Milwaukee Country Club?', answer: 'Harry Colt and C.H. Alison redesigned the course in 1929. Renaissance Golf Design later completed a restoration enhancing the original Golden Age features.' }, { question: 'What major events has Milwaukee CC hosted?', answer: 'The club hosted the 1969 Walker Cup, the 1988 U.S. Senior Amateur, and the 2008 U.S. Women\'s Amateur Public Links.' }, { question: 'Where is Milwaukee Country Club located?', answer: 'The club is in the Village of River Hills, an affluent suburb north of Milwaukee along the Milwaukee River.' }] },
    { id: 'mil-5', name: 'University Ridge Golf Course', slug: 'university-ridge-golf', city: 'Madison', state: 'Wisconsin', type: 'public', rating: 4.3, greensFee: '$50–$95', architect: 'Robert Trent Jones Jr.', yearBuilt: 1991, holes: 18, par: 72, yardage: 6888, description: 'A Robert Trent Jones Jr. design and home course of the Wisconsin Badgers, University Ridge features rolling terrain through prairie and oak savanna. The public layout hosts the Steve Stricker-hosted AmFam Championship on the Champions Tour and offers championship golf at accessible university pricing.', highlights: ['Home of Wisconsin Badgers golf', 'Champions Tour AmFam Championship host', 'RTJ Jr. prairie and oak savanna design'], imageAlt: 'University Ridge Golf Course prairie fairway home of Wisconsin Badgers golf' },
    { id: 'mil-6', name: 'SentryWorld Golf Course', slug: 'sentryworld-golf-course', city: 'Stevens Point', state: 'Wisconsin', type: 'public', rating: 4.5, greensFee: '$60–$120', architect: 'Robert Trent Jones Jr.', yearBuilt: 1982, holes: 18, par: 72, yardage: 6951, description: 'Host of the 2023 U.S. Senior Open, SentryWorld is a Robert Trent Jones Jr. design in Stevens Point that has long been considered the best public course in Wisconsin. The famous par-3 16th, the "Flower Hole," features 33,000 individually planted flowers creating the most photographed hole in the Midwest.', highlights: ['2023 U.S. Senior Open host', 'Famous "Flower Hole" par 3 with 33,000 flowers', 'Widely regarded as Wisconsin\'s best public course'], imageAlt: 'SentryWorld famous Flower Hole par 3 with 33000 flowers in Stevens Point Wisconsin' },
    { id: 'mil-7', name: 'Brown Deer Park Golf Course', slug: 'brown-deer-park-golf', city: 'Milwaukee', state: 'Wisconsin', type: 'public', rating: 4.1, greensFee: '$30–$60', architect: 'George Hansen', yearBuilt: 1929, holes: 18, par: 71, yardage: 6759, description: 'A historic Milwaukee county course that hosted the PGA Tour\'s Greater Milwaukee Open for over 30 years, Brown Deer Park offers championship golf at municipal pricing. The Andy North redesign features strategic bunkering, mature tree-lined fairways, and a classic parkland character.', highlights: ['Former PGA Tour Greater Milwaukee Open host', 'Championship golf at municipal pricing', 'Andy North redesign with parkland character'], imageAlt: 'Brown Deer Park Golf Course parkland fairway in Milwaukee county' },
    { id: 'mil-8', name: 'Blue Mound Golf & Country Club', slug: 'blue-mound-golf-cc', city: 'Wauwatosa', state: 'Wisconsin', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Seth Raynor', yearBuilt: 1926, holes: 18, par: 72, yardage: 6838, description: 'A Seth Raynor design in Wauwatosa, Blue Mound is one of the finest private clubs in Wisconsin. The classic template-hole layout features Raynor\'s signature Redan, Alps, and Biarritz holes on gently rolling terrain, creating one of the purest expressions of Raynor\'s architectural philosophy in the Midwest.', highlights: ['Seth Raynor template hole design', 'Redan, Alps, and Biarritz signature holes', 'One of Wisconsin\'s finest private clubs'], imageAlt: 'Blue Mound Golf Club Seth Raynor template fairway in Wauwatosa Wisconsin' },
    { id: 'mil-9', name: 'The Bog Golf Club', slug: 'the-bog-golf-club', city: 'Saukville', state: 'Wisconsin', type: 'public', rating: 4.3, greensFee: '$60–$100', architect: 'Arnold Palmer', yearBuilt: 1995, holes: 18, par: 72, yardage: 7200, description: 'An Arnold Palmer signature design north of Milwaukee, The Bog features a dramatic layout through marshland, wetlands, and mature hardwood forests. The challenging par-72 regularly hosts state amateur events and offers one of the most distinctive public golf experiences in southeastern Wisconsin.', highlights: ['Arnold Palmer signature design', 'Dramatic marshland and wetland routing', 'Regular host of state amateur events'], imageAlt: 'The Bog Golf Club Arnold Palmer marshland fairway in Saukville Wisconsin' },
    { id: 'mil-10', name: 'The Bull at Pinehurst Farms', slug: 'the-bull-pinehurst-farms', city: 'Sheboygan Falls', state: 'Wisconsin', type: 'public', rating: 4.4, greensFee: '$65–$120', architect: 'Jack Nicklaus', yearBuilt: 2003, holes: 18, par: 72, yardage: 7339, description: 'A Jack Nicklaus signature design in Sheboygan County, The Bull at Pinehurst Farms provides a championship-level public golf experience near the famed Kohler courses. The 7,339-yard layout through rolling farmland and wetlands offers Nicklaus\'s trademark strategic challenge with wide fairways and bold green complexes.', highlights: ['Jack Nicklaus signature design near Kohler', '7,339-yard championship layout', 'Excellent complement to Whistling Straits area golf'], imageAlt: 'The Bull at Pinehurst Farms Nicklaus fairway through Wisconsin farmland' },
    { id: 'mil-11', name: 'Ozaukee Country Club', slug: 'ozaukee-country-club', city: 'Mequon', state: 'Wisconsin', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Langford & Moreau', yearBuilt: 1922, holes: 18, par: 71, yardage: 6742, description: 'A Langford & Moreau Golden Age design in Mequon, Ozaukee Country Club features the architects\' hallmark dramatic green complexes and strategic bunkering. The mature parkland layout along the Milwaukee River has been sensitively restored to honor the original vision of two of Chicago\'s most celebrated pre-war architects.', highlights: ['Langford & Moreau Golden Age design', 'Dramatic green complexes along Milwaukee River', 'Sensitively restored classic architecture'], imageAlt: 'Ozaukee Country Club Golden Age parkland fairway in Mequon Wisconsin' },
  ],
  'indianapolis-indiana': [
    { id: 'ind-1', name: 'Crooked Stick Golf Club', slug: 'crooked-stick-golf-club', city: 'Carmel', state: 'Indiana', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Pete Dye', yearBuilt: 1964, holes: 18, par: 72, yardage: 7516, description: 'Host of the 1991 PGA Championship won by John Daly and the 2012 BMW Championship, Crooked Stick is Pete Dye\'s longtime home club and one of his most personal designs. The layout through rolling central Indiana terrain features Dye\'s bold shaping, strategic water hazards, and railroad-tie bulkheads.', highlights: ['1991 PGA Championship and 2012 BMW Championship host', 'Pete Dye\'s personal home club', 'Bold Dye shaping through rolling Indiana terrain'], imageAlt: 'Crooked Stick Golf Club Pete Dye championship fairway in Carmel Indiana' },
    { id: 'ind-2', name: 'Pete Dye Golf Club', slug: 'pete-dye-golf-club', city: 'Bridgeport', state: 'Indiana', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Pete Dye', yearBuilt: 2003, holes: 18, par: 72, yardage: 7349, description: 'Built on a former coal mine, Pete Dye Golf Club is one of the architect\'s most ambitious and dramatic designs. The reclaimed terrain features 100-foot elevation changes, dramatic ravines, and bold shaping that transforms industrial wasteland into one of the most visually striking courses in America.', highlights: ['Built on reclaimed coal mine terrain', '100-foot elevation changes and dramatic ravines', 'Among Pete Dye\'s most ambitious designs'], imageAlt: 'Pete Dye Golf Club dramatic reclaimed terrain fairway in Bridgeport Indiana' },
    { id: 'ind-3', name: 'The Fort Golf Resort', slug: 'the-fort-golf-resort', city: 'Indianapolis', state: 'Indiana', type: 'public', rating: 4.3, greensFee: '$50–$90', architect: 'Pete Dye', yearBuilt: 1997, holes: 18, par: 72, yardage: 7148, description: 'A Pete Dye public design at Fort Harrison State Park, The Fort offers championship golf through a historic military property. The layout winds through mature hardwoods on the former Army garrison with strategic water hazards, bold bunkering, and Dye\'s trademark visual challenge at accessible pricing.', highlights: ['Pete Dye public course at Fort Harrison State Park', 'Historic military property setting', 'Championship golf at accessible pricing'], imageAlt: 'The Fort Golf Resort Pete Dye fairway through Fort Harrison State Park' },
    { id: 'ind-4', name: 'Wolf Run Golf Club', slug: 'wolf-run-golf-club-zionsville', city: 'Zionsville', state: 'Indiana', type: 'semi-private', rating: 4.2, greensFee: '$45–$80', architect: 'Steve Burns', yearBuilt: 1992, holes: 18, par: 72, yardage: 6905, description: 'A Steve Burns design north of Indianapolis in Zionsville, Wolf Run offers semi-private access to a challenging layout through wooded ravines and natural creek corridors. The course features well-defended greens, strategic water hazards, and mature hardwood forest that creates an intimate, parkland atmosphere.', highlights: ['Wooded ravine and creek corridor routing', 'Semi-private access north of Indianapolis', 'Intimate parkland atmosphere in Zionsville'], imageAlt: 'Wolf Run Golf Club wooded fairway through ravines in Zionsville Indiana' },
    { id: 'ind-5', name: 'Victoria National Golf Club', slug: 'victoria-national-golf-club', city: 'Newburgh', state: 'Indiana', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 1998, holes: 18, par: 72, yardage: 7209, description: 'A Tom Fazio design in southern Indiana, Victoria National is consistently ranked as the best course in the state. The stunning layout winds through ravines, ridges, and hardwood forest along a former Ohio River flood plain with bold Fazio shaping and tournament-quality conditioning.', highlights: ['Consistently ranked #1 course in Indiana', 'Tom Fazio design through dramatic ravines', 'Former Ohio River flood plain terrain'], imageAlt: 'Victoria National Golf Club Tom Fazio fairway through Indiana ravines and ridges' },
    { id: 'ind-6', name: 'Brickyard Crossing Golf Club', slug: 'brickyard-crossing', city: 'Indianapolis', state: 'Indiana', type: 'public', rating: 4.2, greensFee: '$50–$95', architect: 'Pete Dye', yearBuilt: 1993, holes: 18, par: 72, yardage: 6981, description: 'A Pete Dye design where four holes play inside the Indianapolis Motor Speedway oval, Brickyard Crossing is one of the most unique public courses in America. The layout combines the famous racing venue setting with Dye\'s strategic design through White River wetlands and mature Indiana hardwoods.', highlights: ['Four holes inside the Indianapolis Motor Speedway', 'Pete Dye design at America\'s most famous racetrack', 'Unique combination of golf and motorsports heritage'], imageAlt: 'Brickyard Crossing fairway inside Indianapolis Motor Speedway oval', history: 'Golf at the Indianapolis Motor Speedway dates to the 1920s when a course was first built on the property. The layout was expanded to 27 holes in 1965. In 1992, legendary architect Pete Dye redesigned the facility, and the renamed Brickyard Crossing opened in 1993.\n\nDye\'s redesign created one of the most unique golf experiences in America, with four holes playing inside the century-old Indianapolis Motor Speedway oval. The remaining 14 holes wind through White River wetlands and mature Indiana hardwoods outside the track.\n\nThe course is part of the Pete Dye Golf Trail in Indiana, showcasing some of the architect\'s finest public works in his home state. It has hosted numerous celebrity and charity events drawing on the fame of both the Speedway and Dye\'s design reputation.', signatureHoles: [{ hole: 7, par: 3, yardage: 192, description: 'The most famous hole at Brickyard Crossing and named to Indiana\'s Signature 18. This par 3 plays inside the Motor Speedway oval with views of the iconic pagoda.' }, { hole: 8, par: 4, yardage: 415, description: 'A challenging par 4 inside the Speedway oval where the famous Yard of Bricks start-finish line is visible. The setting is utterly unique in American golf.' }, { hole: 14, par: 3, yardage: 165, description: 'A beautiful par 3 outside the track over White River wetlands. Classic Pete Dye with railroad ties and a well-defended green.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finishing hole through mature hardwoods. Dye\'s strategic bunkering demands one final quality drive and approach.' }], whatToExpect: 'Brickyard Crossing offers a golf experience unlike any other. Four holes play inside the legendary Indianapolis Motor Speedway oval, where you can see the pagoda, the Yard of Bricks, and the grandstands. The remaining holes wind through scenic White River wetlands and Indiana hardwoods.\n\nThe Pete Dye design plays to 6,981 yards from the back tees with typical Dye features including railroad ties, island-style greens, and strategic bunkering.', playingTips: 'The four infield holes play flatter and more open than the outside holes through trees and wetlands. Wind can be a bigger factor inside the open Speedway oval.\n\nPete Dye\'s trademark features are present throughout. Avoid the hazards at all costs as recovery from Dye\'s penal features is extremely difficult. Play to the center of greens rather than attacking pins near edges.', faqs: [{ question: 'Can the public play Brickyard Crossing?', answer: 'Yes. Brickyard Crossing is a public course with green fees typically ranging from $50 to $95.' }, { question: 'Which holes are inside the Indianapolis Motor Speedway?', answer: 'Holes 7, 8, 9, and 10 play inside the famous oval, offering views of the pagoda, grandstands, and Yard of Bricks.' }, { question: 'Who designed Brickyard Crossing?', answer: 'Pete Dye redesigned the course in 1992. Golf at the Speedway dates to the 1920s.' }, { question: 'Is Brickyard Crossing part of the Pete Dye Golf Trail?', answer: 'Yes. It is one of several Pete Dye-designed courses on the Pete Dye Golf Trail in Indiana.' }] },
    { id: 'ind-7', name: 'Prairie View Golf Club', slug: 'prairie-view-golf-club', city: 'Carmel', state: 'Indiana', type: 'public', rating: 4.1, greensFee: '$35–$65', architect: 'Robert Trent Jones Jr.', yearBuilt: 1997, holes: 18, par: 72, yardage: 7067, description: 'A Robert Trent Jones Jr. design in Carmel, Prairie View offers championship-caliber public golf through rolling central Indiana terrain. The layout features prairie grasses, strategic wetland hazards, and RTJ Jr.\'s bold bunkering style on a property that provides a surprisingly varied topographic experience.', highlights: ['Robert Trent Jones Jr. championship design', 'Rolling prairie and wetland terrain', 'Championship golf at public pricing in Carmel'], imageAlt: 'Prairie View Golf Club RTJ Jr fairway through Indiana prairie in Carmel' },
    { id: 'ind-8', name: 'Kampen Course at Birck Boilermaker', slug: 'kampen-course-purdue', city: 'West Lafayette', state: 'Indiana', type: 'public', rating: 4.3, greensFee: '$40–$75', architect: 'Pete Dye', yearBuilt: 1997, holes: 18, par: 72, yardage: 7432, description: 'A Pete Dye design at Purdue University, the Kampen Course is one of the most challenging college courses in America. The 7,432-yard layout through rolling terrain features Dye\'s signature railroad ties, dramatic bunkering, and challenging forced carries that provide a stern test for even elite players.', highlights: ['Pete Dye championship design at Purdue University', '7,432-yard stern test for elite players', 'Among America\'s toughest university courses'], imageAlt: 'Kampen Course at Purdue University Pete Dye fairway in West Lafayette Indiana' },
    { id: 'ind-9', name: 'French Lick Resort - Pete Dye Course', slug: 'french-lick-pete-dye', city: 'French Lick', state: 'Indiana', type: 'resort', rating: 4.7, greensFee: '$150–$275', architect: 'Pete Dye', yearBuilt: 2009, holes: 18, par: 72, yardage: 8102, description: 'Perched atop a ridge in southern Indiana, the Pete Dye Course at French Lick Resort is one of the most ambitious resort courses in America. The 8,102-yard monster features dramatic 200-foot elevation changes, exposed limestone cliffs, and panoramic Hoosier National Forest views from nearly every hole.', highlights: ['8,102 yards — one of the longest courses in America', '200-foot elevation changes atop a southern Indiana ridge', 'Panoramic Hoosier National Forest views'], imageAlt: 'French Lick Pete Dye Course dramatic ridge fairway with Hoosier Forest views', history: 'The Pete Dye Course at French Lick Resort opened April 24, 2009, at a reported cost of $28 million. Pete Dye built it atop a ridge in southern Indiana\'s Hoosier National Forest, creating one of the most dramatic resort courses in America. It was named Best New Course in America for 2009.\n\nAt 8,102 yards from the championship tees, it is one of the longest in the country with five par 4s exceeding 500 yards from the back. Dye moved massive earth to create 200-foot elevation changes and expose limestone cliffs. Panoramic 40-mile views are visible from nearly every hole.\n\nThe course hosted the 2015 Senior PGA Championship and other professional events. French Lick Resort also features the historic Donald Ross Course (1917) and the Sand Creek short course.', signatureHoles: [{ hole: 3, par: 5, yardage: 641, description: 'The number-one handicap hole stretching 641 yards with dramatic elevation changes and exposed limestone on the hillside.' }, { hole: 18, par: 5, yardage: 657, description: 'A spectacular closing par 5 with panoramic views of Hoosier National Forest sweeping downhill toward the clubhouse.' }, { hole: 11, par: 4, yardage: 519, description: 'One of the most visually impressive holes with an elevated tee providing sweeping views of the valley below.' }, { hole: 4, par: 3, yardage: 251, description: 'A dramatic long par 3 to a green surrounded by Pete Dye\'s signature bunkers with panoramic forest views.' }], whatToExpect: 'The Pete Dye Course is a massive layout perched atop a ridge with 200-foot elevation changes and 40-mile views. At 8,102 yards from championship tees it is one of the longest in America, though five tee sets starting at 5,151 yards make it playable for all levels.\n\nExpect Pete Dye\'s signature elements — railroad ties, dramatic bunkering, visual intimidation. The exposed ridgetop means wind is a factor.', playingTips: 'Play from appropriate tees — the back tees are for elite players only. From forward tees the course is dramatically more enjoyable. Elevation changes mean many downhill holes play shorter than the yardage suggests.\n\nPay attention to Dye\'s visual tricks. Many hazards appear closer than they are. Trust the yardage not your eyes.', faqs: [{ question: 'Is the Pete Dye Course really 8,102 yards?', answer: 'Yes from the championship gold tees. Five sets of tees are available starting at 5,151 yards.' }, { question: 'What other courses are at French Lick?', answer: 'The historic Donald Ross Course (1917) and the Sand Creek short course.' }, { question: 'When is the best time to play?', answer: 'Open April through November. Late spring and early fall offer the best conditions.' }, { question: 'How far is French Lick from major cities?', answer: 'About 2 hours south of Indianapolis, 2 hours northwest of Louisville.' }] },
    { id: 'ind-10', name: 'French Lick Resort - Donald Ross Course', slug: 'french-lick-donald-ross', city: 'French Lick', state: 'Indiana', type: 'resort', rating: 4.4, greensFee: '$75–$150', architect: 'Donald Ross (restored by Lee Schmidt & Brian Curley)', yearBuilt: 1917, holes: 18, par: 70, yardage: 6706, description: 'Originally designed by Donald Ross in 1917 and beautifully restored in 2006, this classic layout hosted the 1924 PGA Championship. The rolling terrain, crowned greens, and strategic bunkering showcase Ross at his strategic best in a historic resort setting.', highlights: ['Host of the 1924 PGA Championship', 'Donald Ross design beautifully restored in 2006', 'Historic resort golf dating to 1917'], imageAlt: 'French Lick Donald Ross Course restored fairway at historic resort', history: 'The Donald Ross Course at French Lick was originally designed in 1917 by Donald Ross, who reportedly rode the property on horseback to lay out the holes. Originally known as the Hill Course, it became part of the French Lick Springs Hotel resort. Just seven years after opening, the course hosted the 1924 PGA Championship, won by the legendary Walter Hagen.\n\nThe course fell into disrepair over the decades and closed in 2005 for a comprehensive restoration by Lee Schmidt and Brian Curley. The restored course reopened in November 2006, faithfully honoring Ross\'s original design philosophy with crowned greens, strategic bunkering, and rolling terrain while adding modern irrigation and infrastructure.\n\nThe Donald Ross Course offers a dramatically different experience from the Pete Dye Course at the same resort. Where the Dye layout is a massive modern monster, the Ross course is a classic, strategic design at a manageable 6,706 yards and par 70, showcasing the timeless principles that made Ross the most prolific architect of golf\'s Golden Age.', signatureHoles: [{ hole: 5, par: 4, yardage: 410, description: 'A classic Ross par 4 with a crowned green that rejects anything not precisely struck. The approach must find the correct portion of the putting surface to avoid a difficult two-putt.' }, { hole: 14, par: 3, yardage: 175, description: 'A beautiful par 3 with Ross\'s trademark green complex featuring subtle contours and strategic bunkering that rewards accurate iron play.' }, { hole: 18, par: 4, yardage: 430, description: 'A strong finishing hole that requires two solid shots. The approach plays to a Ross green defended by bunkers and crowned slopes.' }, { hole: 9, par: 4, yardage: 390, description: 'The closing hole of the front nine features rolling terrain and a green complex showcasing Ross\'s genius for subtle, strategic design.' }], whatToExpect: 'The Donald Ross Course offers classic Golden Age golf in a historic resort setting. At 6,706 yards and par 70, it is far more approachable than the Pete Dye monster on the same property. Ross\'s crowned greens, strategic bunkering, and rolling terrain reward thoughtful play and precise iron work.\n\nThe beautifully restored layout feels authentic to its 1917 origins while providing modern playing conditions. The pace of play tends to be more relaxed than on the Dye course.', playingTips: 'The crowned greens are the primary defense. Approach shots that miss the correct quadrant will roll off the putting surface, leaving difficult up-and-downs. Study the green contours before each approach and favor positions below the hole.\n\nThis is a strategic course that rewards accuracy over power. Take one less club off the tee if it means hitting the fairway, and focus on approach shot positioning.', faqs: [{ question: 'What is the difference between the Ross and Dye courses at French Lick?', answer: 'The Ross course is a classic 1917 design at 6,706 yards and par 70, offering strategic Golden Age golf. The Dye course is a modern 8,102-yard monster with dramatic elevation changes. They are completely different experiences.' }, { question: 'Who won the 1924 PGA Championship at French Lick?', answer: 'Walter Hagen won the 1924 PGA Championship, the seventh edition of the championship, played at what was then known as the French Lick Springs Golf Club.' }, { question: 'When was the Ross course restored?', answer: 'The course closed in 2005 and was restored by Lee Schmidt and Brian Curley, reopening in November 2006.' }, { question: 'Is the Donald Ross Course a good value?', answer: 'Yes. Green fees range from $75 to $150, significantly less than the Pete Dye Course. Many consider it one of the better values in Midwest resort golf.' }] },
    { id: 'ind-11', name: 'Purgatory Golf Club', slug: 'purgatory-golf-club', city: 'Noblesville', state: 'Indiana', type: 'public', rating: 4.2, greensFee: '$55–$95', architect: 'Ron Kern', yearBuilt: 1999, holes: 18, par: 72, yardage: 7072, description: 'A Ron Kern design in Noblesville north of Indianapolis, Purgatory winds through wetlands, prairie grasses, and mature hardwood forest. The public course offers a challenging and varied 18-hole experience with strong conditioning and one of the most interesting routings in the Indianapolis metro area.', highlights: ['Varied routing through wetlands and prairie', 'Strong public course north of Indianapolis', 'Challenging 7,072-yard championship layout'], imageAlt: 'Purgatory Golf Club wetland and prairie fairway in Noblesville Indiana' },
    { id: 'ind-12', name: 'Broadmoor Country Club', slug: 'broadmoor-cc-indianapolis', city: 'Indianapolis', state: 'Indiana', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'William H. Diddel', yearBuilt: 1924, holes: 18, par: 72, yardage: 6800, description: 'One of Indianapolis\'s most respected private clubs, Broadmoor was designed by noted Indiana architect William Diddel in 1924. The mature parkland layout features tree-lined fairways, subtle green complexes, and a classic Midwestern character that has been carefully preserved through multiple sensitive renovations.', highlights: ['William Diddel classic 1924 design', 'One of Indianapolis\'s most respected private clubs', 'Classic Midwestern parkland character'], imageAlt: 'Broadmoor Country Club tree-lined parkland fairway in Indianapolis' },
  ],
  'columbus-ohio': [
    { id: 'col-1', name: 'Muirfield Village Golf Club', slug: 'muirfield-village', city: 'Dublin', state: 'Ohio', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 1974, holes: 18, par: 72, yardage: 7456, description: 'Founded by Jack Nicklaus and host of the Memorial Tournament since 1976, Muirfield Village is one of the most immaculately conditioned courses in the world. Nicklaus\'s design through rolling central Ohio terrain features dramatic green complexes, strategic water hazards, and a routing that creates natural amphitheaters for spectators.', highlights: ['Memorial Tournament PGA Tour host since 1976', 'Jack Nicklaus founded and designed', 'Among the most immaculate conditioning in golf'], imageAlt: 'Muirfield Village Golf Club championship fairway during Memorial Tournament in Dublin Ohio' },
    { id: 'col-2', name: 'The Ohio State University Golf Club - Scarlet', slug: 'osu-scarlet-course', city: 'Columbus', state: 'Ohio', type: 'semi-private', rating: 4.5, greensFee: '$50–$100', architect: 'Alister MacKenzie', yearBuilt: 1938, holes: 18, par: 72, yardage: 7455, description: 'One of only two Alister MacKenzie designs in the Midwest (the other being Augusta National), the OSU Scarlet Course is a masterwork of strategic architecture. The undulating greens, bold bunkering, and strategic width reflect MacKenzie\'s genius and have been carefully restored to honor the original design.', highlights: ['Rare Alister MacKenzie design in the Midwest', 'Augusta National\'s architectural sibling', 'Carefully restored strategic architecture'], imageAlt: 'Ohio State Scarlet Course Alister MacKenzie fairway at Ohio State University Columbus', history: 'The Ohio State University Golf Club Scarlet Course traces its origins to 1931 when Alister MacKenzie, the legendary architect of Augusta National and Cypress Point, was commissioned to design 36 holes for the university. MacKenzie completed his plans, but the Great Depression delayed construction significantly. The Scarlet Course and nine holes of its shorter sibling, the Gray Course, were not completed until 1938, several years after MacKenzie\'s death in 1934.\n\nThe Scarlet Course stands as one of MacKenzie\'s few designs in the Midwest and shares architectural DNA with Augusta National, featuring the same philosophy of strategic width, bold bunkering, and imaginatively contoured greens. The course served as the home of Ohio State\'s legendary golf program, which has produced champions including Jack Nicklaus, who played collegiate golf at Ohio State.\n\nIn 2006, Jack Nicklaus and his Nicklaus Design firm undertook a comprehensive renovation of the Scarlet Course, restoring MacKenzie\'s original design intent while modernizing the layout for championship play. The renovation was completed in 2014 and the course has since hosted Nationwide Tour events, reinforcing its status as one of the finest university golf courses in America.', signatureHoles: [{ hole: 8, par: 3, yardage: 202, description: 'One of the finest redesigned holes on the property, this par 3 features a dramatically contoured green surrounded by deep MacKenzie-style bunkers. The hole demands a precise tee shot to a well-defended putting surface.' }, { hole: 4, par: 4, yardage: 430, description: 'A demanding par 4 with one of the most challenging greens on the course. The approach must be precisely placed, as the putting surface features severe contours that make recovery from poor position extremely difficult.' }, { hole: 11, par: 4, yardage: 440, description: 'Part of the outstanding stretch of holes 10 through 12 that many consider the best run on the course. This par 4 features a creek crossing and a green complex that rewards strategic positioning off the tee.' }, { hole: 12, par: 5, yardage: 562, description: 'A dramatic par 5 where the creek comes into play, creating risk-reward decisions on the second shot. The green is one of MacKenzie\'s most creative, with multiple pin positions that drastically change the character of the hole.' }], whatToExpect: 'The OSU Scarlet Course delivers a world-class architectural experience at university-course pricing. MacKenzie\'s strategic design philosophy is evident throughout, with wide fairways that offer multiple angles of attack and greens that reward precise iron play. The Nicklaus renovation has brought the course to championship condition while honoring the original design.\n\nThe course is the home of Ohio State\'s men\'s and women\'s golf teams, and the atmosphere carries the spirit of Buckeye athletics. Conditions are typically excellent, and the layout provides a demanding test at over 7,400 yards from the back tees while remaining playable from the forward tees.', playingTips: 'The key to scoring on the Scarlet Course is understanding MacKenzie\'s green complexes. Many greens feature false fronts, subtle tiers, and dramatic contours that punish poorly placed approach shots. Study the pin positions and aim for the correct quadrant of the green rather than firing at every pin.\n\nThe course plays through relatively flat terrain with Olentangy Creek creating strategic hazards on several holes. Club selection should account for the Midwest conditions, which can vary dramatically between seasons. Play to your strengths off the tee, as the wide fairways forgive slight misses while the greens demand precision.', faqs: [{ question: 'Can the public play the OSU Scarlet Course?', answer: 'Yes, the Scarlet Course is open to the public as a semi-private facility. Ohio State affiliates and alumni may receive preferred rates and booking windows.' }, { question: 'Did Alister MacKenzie design the Scarlet Course?', answer: 'MacKenzie designed the original plans in 1931, but the course was not completed until 1938, four years after his death. Jack Nicklaus led a major renovation completed in 2014 to restore MacKenzie\'s original vision.' }, { question: 'What is the connection to Augusta National?', answer: 'Both Augusta National and the OSU Scarlet Course were designed by Alister MacKenzie during the same era, sharing architectural philosophies of strategic width, bold bunkering, and creative green contours.' }, { question: 'Did Jack Nicklaus play at Ohio State?', answer: 'Yes, Jack Nicklaus played his collegiate golf at Ohio State and later led the renovation of the Scarlet Course through Nicklaus Design, bringing personal knowledge of the layout to the restoration project.' }] },
    { id: 'col-3', name: 'Scioto Country Club', slug: 'scioto-country-club', city: 'Columbus', state: 'Ohio', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Donald Ross', yearBuilt: 1916, holes: 18, par: 71, yardage: 6965, description: 'Where Jack Nicklaus learned to play golf, Scioto Country Club is a Donald Ross design that hosted the 1926 U.S. Open, 1931 Ryder Cup, and 1950 PGA Championship. The historic layout through mature Columbus parkland remains one of Ross\'s most celebrated designs with classic crowned greens and strategic bunkering.', highlights: ['Where Jack Nicklaus learned the game', 'Host of 1926 U.S. Open and 1931 Ryder Cup', 'Donald Ross classic through Columbus parkland'], imageAlt: 'Scioto Country Club Donald Ross parkland fairway where Nicklaus learned golf', history: 'Donald Ross design, 1916. Hosted 1926 U.S. Open (Bobby Jones), 1931 Ryder Cup, 1950 PGA, 2016 Senior Open. Jack Nicklaus\'s home course growing up, taught by Jack Grout.', signatureHoles: [{ hole: 1, par: 4, yardage: 445, description: 'Opening par 4 through mature parkland.' }, { hole: 7, par: 3, yardage: 190, description: 'Ross crowned green par 3.' }, { hole: 15, par: 4, yardage: 425, description: 'Strategic championship par 4.' }, { hole: 18, par: 4, yardage: 440, description: 'Strong championship finisher.' }], whatToExpect: 'Classic Ross parkland at 6,965 yards par 71. Crowned greens and strategic bunkering. Nicklaus connection is unmatched. Private only.', playingTips: 'Ross crowned greens shed balls missing center. Aim middle. Position over distance in the mature parkland.', faqs: [{ question: 'Public?', answer: 'No.' }, { question: 'Nicklaus?', answer: 'Learned golf here under Jack Grout.' }, { question: 'Championships?', answer: '1926 Open, 1931 Ryder Cup, 1950 PGA, 2016 Senior Open.' }, { question: 'Designer?', answer: 'Donald Ross, 1916.' }] },
    { id: 'col-4', name: 'New Albany Links Golf Club', slug: 'new-albany-links', city: 'New Albany', state: 'Ohio', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Barry Serafin', yearBuilt: 1990, holes: 18, par: 72, yardage: 7197, description: 'A links-inspired private club in the affluent New Albany community east of Columbus, New Albany Links features an open, treeless layout with fescue rough, pot bunkers, and constant wind exposure. The design evokes Scottish links golf in the heart of Ohio farmland with firm-and-fast playing conditions.', highlights: ['Links-inspired design in Ohio farmland', 'Fescue rough and pot bunkers', 'Firm-and-fast Scottish-style conditions'], imageAlt: 'New Albany Links golf club links-style fairway with fescue rough in Ohio', history: 'New Albany Links Golf Club was established in 1990 as part of the planned New Albany community east of Columbus, Ohio. Designed by Barry Serafin to evoke Scottish links golf on open Ohio farmland, it set itself apart from the tree-lined parkland courses typical of the region.\n\nThe club is in the same community as The Golf Club by Pete Dye and New Albany Country Club by Jack Nicklaus, creating one of the most remarkable golf concentrations in the Midwest.\n\nThe layout features an open, treeless design with fescue rough, pot bunkers, and firm playing surfaces replicating links conditions at 7,197 yards from the back tees.', signatureHoles: [{ hole: 3, par: 4, yardage: 420, description: 'A classic links par 4 with fescue-lined fairways and pot bunkers guarding the approach. Wind exposure makes club selection critical.' }, { hole: 8, par: 3, yardage: 185, description: 'A demanding par 3 with deep pot bunkers protecting the green in an exposed setting where wind is always a factor.' }, { hole: 14, par: 5, yardage: 545, description: 'A risk-reward par 5 where long hitters can reach in two but must navigate fescue and strategic bunkering.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finishing par 4 demanding two quality shots with pot bunkers and fescue framing the final approach.' }], whatToExpect: 'New Albany Links offers a genuine links experience in Ohio. The open, treeless layout features constant wind exposure, fescue rough, and pot bunkers creating a Scottish atmosphere with firm-and-fast conditions.\n\nTees range from approximately 4,800 to 7,000 yards accommodating all skill levels.', playingTips: 'Embrace the ground game. Bump-and-run approaches are often more effective than aerial attacks on the firm surfaces.\n\nWind is the primary defense. Take extra club into the wind and play knockdown shots. The pot bunkers are deep and penal, so course management is rewarded.', faqs: [{ question: 'Can the public play New Albany Links?', answer: 'No. New Albany Links is a private club requiring membership.' }, { question: 'What style of course is New Albany Links?', answer: 'Links-inspired with an open treeless layout, fescue rough, pot bunkers, and firm conditions evoking Scottish links golf.' }, { question: 'How does it compare to other New Albany courses?', answer: 'The community also hosts The Golf Club by Pete Dye and New Albany Country Club by Jack Nicklaus.' }, { question: 'What is the best time to play?', answer: 'Late spring through early fall offers the best conditions.' }] },
    { id: 'col-5', name: 'Longaberger Golf Club', slug: 'longaberger-golf-club', city: 'Nashport', state: 'Ohio', type: 'public', rating: 4.4, greensFee: '$55–$100', architect: 'Arthur Hills', yearBuilt: 1999, holes: 18, par: 72, yardage: 7248, description: 'An Arthur Hills design in the Muskingum Valley east of Columbus, Longaberger is widely considered one of the finest public courses in Ohio. The dramatic layout features 200 feet of elevation change through rolling Appalachian foothills with panoramic valley views and immaculate conditioning.', highlights: ['Among Ohio\'s finest public courses', '200 feet of elevation change', 'Arthur Hills design in Appalachian foothills'], imageAlt: 'Longaberger Golf Club Arthur Hills fairway through Ohio Appalachian foothills' },
    { id: 'col-6', name: 'The Golf Club', slug: 'the-golf-club-new-albany', city: 'New Albany', state: 'Ohio', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Pete Dye', yearBuilt: 1967, holes: 18, par: 72, yardage: 7095, description: 'One of Pete Dye\'s earliest and most influential designs, The Golf Club in New Albany helped launch the modern era of American golf architecture. The layout through rolling Ohio farmland features Dye\'s first use of railroad ties, pot bunkers, and the bold shaping that would define his career.', highlights: ['Seminal Pete Dye design that launched modern architecture', 'First use of railroad ties and pot bunkers', '1992 Solheim Cup host venue'], imageAlt: 'The Golf Club Pete Dye fairway through rolling Ohio farmland in New Albany' },
    { id: 'col-7', name: 'Wedgewood Golf & Country Club', slug: 'wedgewood-golf-cc', city: 'Powell', state: 'Ohio', type: 'semi-private', rating: 4.1, greensFee: '$35–$65', architect: 'Jack Kidwell & Michael Hurdzan', yearBuilt: 1966, holes: 18, par: 72, yardage: 6936, description: 'A Kidwell-Hurdzan design north of Columbus in Powell, Wedgewood offers semi-private access to a mature parkland layout through rolling Delaware County terrain. The well-established course features tree-lined fairways, strategic water hazards, and a classic Ohio parkland character.', highlights: ['Kidwell-Hurdzan mature parkland design', 'Semi-private access north of Columbus', 'Classic Ohio parkland golf in Powell'], imageAlt: 'Wedgewood Golf Club mature parkland fairway in Powell Ohio' },
    { id: 'col-8', name: 'Camargo Club', slug: 'camargo-club', city: 'Indian Hill', state: 'Ohio', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Seth Raynor', yearBuilt: 1925, holes: 18, par: 70, yardage: 6577, description: 'One of Seth Raynor\'s greatest achievements, Camargo Club in Indian Hill near Cincinnati is consistently ranked among the top 50 courses in America. The intimate layout on just 127 acres features Raynor\'s template holes at their finest — Redan, Biarritz, Short, and Eden — in a serene woodland setting.', highlights: ['Seth Raynor masterwork on just 127 acres', 'Consistently ranked top 50 in America', 'Finest expression of Raynor template holes'], imageAlt: 'Camargo Club Seth Raynor template hole through woodland in Indian Hill Ohio' },
    { id: 'col-9', name: 'Canterbury Golf Club', slug: 'canterbury-golf-club', city: 'Beachwood', state: 'Ohio', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Jack Way', yearBuilt: 1922, holes: 18, par: 72, yardage: 6852, description: 'Canterbury Golf Club in Beachwood has hosted two U.S. Senior Opens, the 1973 PGA Championship, and multiple U.S. Amateur events. The classic Jack Way design through rolling Cleveland-area terrain has been refined by Keith Foster, maintaining its championship pedigree while modernizing strategic elements.', highlights: ['Host of 1973 PGA Championship', 'Multiple U.S. Senior Open and Amateur venue', 'Keith Foster restoration of classic design'], imageAlt: 'Canterbury Golf Club championship fairway through mature Ohio parkland' },
    { id: 'col-10', name: 'Firestone Country Club - South', slug: 'firestone-south-course', city: 'Akron', state: 'Ohio', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Bert Way / Robert Trent Jones Sr.', yearBuilt: 1929, holes: 18, par: 70, yardage: 7298, description: 'Famous for its "Monster" moniker, Firestone South hosted the WGC-Bridgestone Invitational for decades and three PGA Championships. Robert Trent Jones Sr. transformed the original layout into one of America\'s most demanding tests, anchored by the legendary 625-yard par-5 16th hole.', highlights: ['Hosted WGC-Bridgestone Invitational for decades', 'Legendary 625-yard 16th hole', 'Three-time PGA Championship venue'], imageAlt: 'Firestone Country Club South Course Monster fairway in Akron Ohio' },
    { id: 'col-11', name: 'EagleSticks Golf Club', slug: 'eaglesticks-golf-club', city: 'Zanesville', state: 'Ohio', type: 'public', rating: 4.2, greensFee: '$40–$70', architect: 'Michael Hurdzan & Dana Fry', yearBuilt: 1992, holes: 18, par: 70, yardage: 6408, description: 'A Hurdzan-Fry design in the rolling hills east of Columbus, EagleSticks offers a creative and affordable public golf experience. The short but strategic par-70 layout features dramatic elevation changes, creative green complexes, and Appalachian foothill views that reward precision over power.', highlights: ['Hurdzan-Fry strategic par-70 design', 'Dramatic Appalachian foothill elevation changes', 'Outstanding public value east of Columbus'], imageAlt: 'EagleSticks Golf Club rolling fairway through Appalachian foothills near Zanesville', history: 'EagleSticks Golf Club opened in 1990, designed by Ohio native Dr. Michael Hurdzan on the former McClelland horse farm near Zanesville. It was a runner-up for Golf Digest\'s Best New Public Course in 1991 and rated the number one public course in Ohio by Golf Digest in 1997.\n\nOften described as Augusta National in miniature, EagleSticks packs tremendous variety into a compact par-70 layout of just 6,408 yards. Hurdzan used the natural Appalachian foothill terrain to create dramatic elevation changes and creative green complexes.\n\nThe club specializes in stay-and-play experiences and is located near sister course Virtues Golf Club, giving visitors two of Ohio\'s finest public courses in a single trip.', signatureHoles: [{ hole: 3, par: 4, yardage: 345, description: 'A short, drivable par 4 with dramatic elevation change exemplifying Hurdzan\'s strategic design philosophy.' }, { hole: 8, par: 3, yardage: 175, description: 'A beautiful downhill par 3 with panoramic Appalachian foothill views. The elevation drop makes club selection tricky.' }, { hole: 14, par: 4, yardage: 390, description: 'A strategic par 4 requiring careful tee shot positioning with one of Hurdzan\'s most creative green complexes.' }, { hole: 18, par: 4, yardage: 410, description: 'A demanding finishing hole climbing back toward the clubhouse with an elevated green.' }], whatToExpect: 'EagleSticks delivers creative affordable public golf through rolling Appalachian foothill terrain. The par-70 layout is short at 6,408 yards but strategic design and elevation changes make it more demanding than the yardage suggests.\n\nStay-and-play packages with nearby Virtues Golf Club make it an excellent golf trip destination in southeast Ohio.', playingTips: 'Accuracy trumps distance. The layout does not demand long drives but punishes wayward shots. Focus on position over power.\n\nPay attention to elevation changes for club selection. Downhill holes play shorter while uphill approaches may need an extra club or two.', faqs: [{ question: 'Can the public play EagleSticks?', answer: 'Yes. Green fees typically range from $40 to $70 with stay-and-play packages available.' }, { question: 'Who designed EagleSticks?', answer: 'Dr. Michael Hurdzan. It was rated the number one public course in Ohio by Golf Digest in 1997.' }, { question: 'Is there a sister course nearby?', answer: 'Yes. Virtues Golf Club is nearby and combined stay-and-play packages are available.' }, { question: 'How difficult is EagleSticks?', answer: 'The par-70 layout plays 6,408 yards, rewarding precision and shot-shaping over raw power.' }] },
    { id: 'col-12', name: 'Kinsale Golf & Fitness Club', slug: 'kinsale-golf-fitness-club', city: 'Powell', state: 'Ohio', type: 'public', rating: 4.1, greensFee: '$35–$60', architect: 'Barry Serafin', yearBuilt: 2001, holes: 18, par: 72, yardage: 6927, description: 'A Barry Serafin design in Powell just north of Columbus, Kinsale delivers a links-inspired experience with open fescue-lined fairways, pot bunkers, and firm playing surfaces. The accessible public layout provides an alternative to traditional tree-lined Ohio parkland golf at an affordable price point.', highlights: ['Links-inspired design with pot bunkers and fescue', 'Accessible public pricing north of Columbus', 'Barry Serafin open-style layout'], imageAlt: 'Kinsale Golf Club links-style fairway with fescue rough in Powell Ohio' },
  ],
  'san-jose-california': [
    { id: 'sjo-1', name: 'CordeValle Golf Club', slug: 'cordevalle-golf-club', city: 'San Martin', state: 'California', type: 'resort', rating: 4.7, greensFee: '$200–$350', architect: 'Robert Trent Jones Jr.', yearBuilt: 2000, holes: 18, par: 72, yardage: 7360, description: 'Host of the 2016 U.S. Women\'s Open at the Rosewood CordeValle resort, this RTJ Jr. design occupies a stunning valley floor in the foothills of the Santa Cruz Mountains south of San Jose. The championship layout features dramatic elevation changes, native oak corridors, and impeccable conditioning that earned it top resort accolades.', highlights: ['2016 U.S. Women\'s Open host venue', 'RTJ Jr. design at Rosewood luxury resort', 'Santa Cruz Mountain foothill valley setting'], imageAlt: 'CordeValle Golf Club championship fairway in Santa Cruz Mountain foothills' },
    { id: 'sjo-2', name: 'Cinnabar Hills Golf Club', slug: 'cinnabar-hills-golf-club', city: 'San Jose', state: 'California', type: 'public', rating: 4.3, greensFee: '$55–$100', architect: 'John Harbottle III', yearBuilt: 1998, holes: 27, par: 72, yardage: 6861, description: 'A 27-hole John Harbottle III design in the rolling hills of south San Jose, Cinnabar Hills consistently ranks among the best public courses in the Bay Area. The three distinct nines wind through oak-studded hillsides with panoramic Silicon Valley views and excellent conditioning for a daily-fee facility.', highlights: ['27 holes consistently ranked best public in Bay Area', 'Panoramic Silicon Valley views', 'John Harbottle III hillside design'], imageAlt: 'Cinnabar Hills Golf Club rolling fairway with Silicon Valley views', history: 'Cinnabar Hills Golf Club opened in August 1998 as San Jose\'s first new public course in 30 years. Designed by John Harbottle III, the 27-hole facility was built on rolling hillside terrain in southern San Jose with panoramic Silicon Valley views.\n\nThree distinct nines -- Lake, Mountain, and Canyon -- provide six different 18-hole combinations. Each nine has its own character through oak-studded hillsides with dramatic elevation changes.\n\nThe clubhouse houses the Lee Brandenburg Historical Golf Museum, the only such museum at a public golf facility, with an extensive collection of golf memorabilia dating back centuries.', signatureHoles: [{ hole: 5, par: 4, yardage: 385, description: 'A scenic Lake nine par 4 playing downhill with water guarding the approach and panoramic Silicon Valley views from the tee.' }, { hole: 4, par: 3, yardage: 175, description: 'A dramatic Canyon nine par 3 dropping from an elevated tee to a green nestled in a natural canyon amphitheater.' }, { hole: 7, par: 5, yardage: 530, description: 'A risk-reward Mountain nine par 5 winding through oaks with significant elevation change.' }, { hole: 9, par: 4, yardage: 420, description: 'The Lake nine finisher with a demanding approach over water to an amphitheater green.' }], whatToExpect: 'Cinnabar Hills offers 27 holes through rolling hillside terrain with six 18-hole combinations available. The facility includes a practice range, dining, and the Brandenburg Historical Golf Museum.\n\nConditioning is strong for a daily-fee facility with green fees from $55 to $100.', playingTips: 'Elevation changes significantly affect club selection on all three nines. Downhill holes play shorter and uphill approaches need extra club. Rolling terrain creates uneven lies demanding solid ball-striking.\n\nThe greens have more slope than they appear, especially on the Mountain nine where contours follow the natural hillside.', faqs: [{ question: 'Can the public play Cinnabar Hills?', answer: 'Yes. Green fees typically range from $55 to $100.' }, { question: 'How many holes does Cinnabar Hills have?', answer: '27 holes in three nines: Lake, Mountain, and Canyon, providing six 18-hole combinations.' }, { question: 'What is the Brandenburg Museum?', answer: 'A historical golf museum in the clubhouse with an extensive collection of memorabilia, the only such museum at a public facility.' }, { question: 'Who designed Cinnabar Hills?', answer: 'John Harbottle III. It opened in 1998 as San Jose\'s first new public course in 30 years.' }] },
    { id: 'sjo-3', name: 'San Jose Country Club', slug: 'san-jose-country-club', city: 'San Jose', state: 'California', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Robert Muir Graves', yearBuilt: 1912, holes: 18, par: 72, yardage: 6708, description: 'One of the oldest clubs in the South Bay, San Jose Country Club features a Robert Muir Graves redesign through mature valley oaks and manicured parkland. The private club offers a classic California golf experience with tree-lined fairways, strategic bunkering, and mountain views from elevated tees.', highlights: ['One of South Bay\'s oldest private clubs since 1912', 'Robert Muir Graves redesign', 'Classic California parkland with mountain views'], imageAlt: 'San Jose Country Club mature parkland fairway with mountain views' },
    { id: 'sjo-4', name: 'Coyote Creek Golf Club - Tournament', slug: 'coyote-creek-tournament', city: 'Morgan Hill', state: 'California', type: 'public', rating: 4.2, greensFee: '$50–$90', architect: 'Jack Nicklaus', yearBuilt: 2000, holes: 18, par: 72, yardage: 7067, description: 'A Jack Nicklaus design south of San Jose in Morgan Hill, the Tournament Course at Coyote Creek offers championship-level public golf through the Coyote Valley. The 7,067-yard layout features Nicklaus\'s trademark strategic bunkering, bold green complexes, and views of the surrounding Santa Cruz Mountains and Diablo Range.', highlights: ['Jack Nicklaus championship public design', 'Coyote Valley and mountain range views', 'Championship golf at public pricing'], imageAlt: 'Coyote Creek Tournament Course Nicklaus fairway in Morgan Hill' },
    { id: 'sjo-5', name: 'The Ranch Golf Club', slug: 'the-ranch-golf-club-sj', city: 'San Jose', state: 'California', type: 'public', rating: 4.1, greensFee: '$40–$75', architect: 'Forrest Richardson', yearBuilt: 2004, holes: 18, par: 71, yardage: 6598, description: 'A Forrest Richardson design in the eastern San Jose foothills, The Ranch offers a scenic hillside golf experience with views stretching across the Silicon Valley floor. The accessible par-71 layout features rolling terrain, strategic bunkers, and native California grasslands that keep the course playable and enjoyable for all levels.', highlights: ['Scenic eastern foothills with Silicon Valley views', 'Accessible hillside layout for all levels', 'Forrest Richardson design through native grasslands'], imageAlt: 'The Ranch Golf Club hillside fairway overlooking Silicon Valley in San Jose' },
    { id: 'sjo-6', name: 'Silver Creek Valley Country Club', slug: 'silver-creek-valley-cc', city: 'San Jose', state: 'California', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Ted Robinson Sr.', yearBuilt: 1993, holes: 18, par: 72, yardage: 6856, description: 'A Ted Robinson Sr. design in a master-planned community in south San Jose, Silver Creek Valley features a dramatic canyon routing with waterfalls, lakes, and hillside views. The private club offers a lush, resort-style atmosphere unusual for a residential community with impeccable year-round conditioning.', highlights: ['Ted Robinson Sr. canyon design with waterfalls', 'Lush resort-style residential club', 'Dramatic hillside and canyon views'], imageAlt: 'Silver Creek Valley Country Club canyon fairway with waterfall in San Jose' },
    { id: 'sjo-7', name: 'San Jose Municipal Golf Course', slug: 'san-jose-municipal-gc', city: 'San Jose', state: 'California', type: 'public', rating: 3.9, greensFee: '$25–$50', architect: 'Robert Muir Graves', yearBuilt: 1968, holes: 18, par: 72, yardage: 6633, description: 'A solid Robert Muir Graves municipal course in central San Jose, the muni offers an affordable gateway to golf in the heart of Silicon Valley. The flat but well-maintained layout features mature trees, strategic water hazards, and consistent conditioning that keeps it a popular after-work option for local tech professionals.', highlights: ['Affordable municipal golf in central San Jose', 'Popular with Silicon Valley professionals', 'Robert Muir Graves mature parkland design'], imageAlt: 'San Jose Municipal Golf Course tree-lined fairway in central San Jose' },
    { id: 'sjo-8', name: 'Pasatiempo Golf Club', slug: 'pasatiempo-golf-club', city: 'Santa Cruz', state: 'California', type: 'semi-private', rating: 4.7, greensFee: '$150–$295', architect: 'Alister MacKenzie', yearBuilt: 1929, holes: 18, par: 70, yardage: 6472, description: 'Alister MacKenzie\'s personal favorite among his American designs, Pasatiempo in Santa Cruz is a Golden Age masterpiece set on dramatic coastal terrain overlooking Monterey Bay. MacKenzie lived adjacent to the 6th hole, and the strategic par-70 features his trademark bold bunkering, creative green complexes, and a natural routing through barrancas and ridgelines.', highlights: ['Alister MacKenzie\'s personal favorite design', 'Golden Age masterpiece overlooking Monterey Bay', 'MacKenzie lived adjacent to the course'], imageAlt: 'Pasatiempo Golf Club Alister MacKenzie fairway overlooking Monterey Bay' },
  ],
  'memphis-tennessee': [
    { id: 'mem-1', name: 'TPC Southwind', slug: 'tpc-southwind', city: 'Memphis', state: 'Tennessee', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Ron Prichard (redesign)', yearBuilt: 1988, holes: 18, par: 70, yardage: 7244, description: 'Host of the FedEx St. Jude Championship, the first event in the PGA Tour\'s FedExCup Playoffs, TPC Southwind is a championship layout that has tested the world\'s best players for decades. The tight, tree-lined par-70 through mature Memphis hardwoods demands precision and course management from tee to green.', highlights: ['FedEx St. Jude Championship PGA Tour host', 'First event in FedExCup Playoffs', 'Tight par-70 through mature Memphis hardwoods'], imageAlt: 'TPC Southwind championship fairway during FedEx St. Jude Championship in Memphis', history: 'TPC Southwind opened in 1988 in southeast Memphis and has hosted a PGA Tour event continuously since, first as the St. Jude Classic and now as the FedEx St. Jude Championship, the first event in the FedExCup Playoffs featuring the top 70 players in the world.\n\nRon Prichard led a significant redesign that tightened the course and enhanced its championship character. The par-70 layout winds through mature Memphis hardwoods with water on numerous holes. The WGC-FedEx St. Jude Invitational was held here from 2019 to 2021.\n\nThe closing stretch from holes 11 through 18 is one of the most demanding on Tour, producing memorable finishes including Will Zalatoris\'s three-hole playoff victory in 2022.', signatureHoles: [{ hole: 11, par: 3, yardage: 162, description: 'A short par 3 reminiscent of TPC Sawgrass\'s island green with a pot bunker front and water surrounding the green.' }, { hole: 12, par: 4, yardage: 406, description: 'A demanding dogleg par 4 following the island-green 11th, together creating a pivotal FedExCup Playoffs stretch.' }, { hole: 14, par: 4, yardage: 465, description: 'The number one handicap hole demanding two quality shots through trees with water threatening the approach.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finishing hole that has decided numerous tournaments with water left and deep bunkers guarding the green.' }], whatToExpect: 'TPC Southwind is a tight par-70 through mature Memphis hardwoods with water on over half the holes. At 7,244 yards it rewards accuracy over distance. The closing stretch is among the most challenging on the PGA Tour.\n\nNow a private club with immaculate conditioning maintained year-round.', playingTips: 'Accuracy off the tee is essential on tight tree-lined fairways. Many Tour players hit less than driver to find the short grass.\n\nThe back nine is where tournaments are won and lost. Water is in play on the majority of back nine holes requiring focus and composure.', faqs: [{ question: 'Can the public play TPC Southwind?', answer: 'No. It is now a private club. The public can attend the annual FedEx St. Jude Championship.' }, { question: 'What PGA Tour event is held here?', answer: 'The FedEx St. Jude Championship, the first FedExCup Playoffs event featuring the top 70 players.' }, { question: 'What is the most famous hole?', answer: 'The 162-yard par-3 11th, an island-style green reminiscent of TPC Sawgrass\'s famous 17th.' }, { question: 'How difficult is it?', answer: 'The par-70 at 7,244 yards demands extreme accuracy with water on numerous holes and tight tree-lined fairways.' }] },
    { id: 'mem-2', name: 'Memphis Country Club', slug: 'memphis-country-club', city: 'Memphis', state: 'Tennessee', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Donald Ross / Rees Jones (renovation)', yearBuilt: 1905, holes: 18, par: 72, yardage: 6850, description: 'Founded in 1905, Memphis Country Club is one of the most historic private clubs in the Mid-South. The Donald Ross-influenced layout has been sensitively updated by Rees Jones, preserving classic crowned greens and strategic bunkering while modernizing the course for contemporary play through towering oaks and magnolias.', highlights: ['One of the Mid-South\'s most historic clubs since 1905', 'Donald Ross legacy with Rees Jones updates', 'Towering oaks and magnolias parkland setting'], imageAlt: 'Memphis Country Club historic parkland fairway through oaks and magnolias' },
    { id: 'mem-3', name: 'Mirimichi Golf Course', slug: 'mirimichi-golf-course', city: 'Millington', state: 'Tennessee', type: 'public', rating: 4.2, greensFee: '$35–$65', architect: 'John Floyd', yearBuilt: 1962, holes: 18, par: 72, yardage: 7061, description: 'Justin Timberlake\'s childhood course north of Memphis, Mirimichi underwent a complete eco-friendly renovation and became one of the most environmentally sustainable golf courses in America. The John Floyd design through rolling North Memphis terrain features native plantings, organic maintenance, and a commitment to environmental stewardship.', highlights: ['Justin Timberlake\'s childhood course', 'One of America\'s most eco-friendly golf courses', 'John Floyd design with organic maintenance'], imageAlt: 'Mirimichi Golf Course eco-friendly fairway north of Memphis' },
    { id: 'mem-4', name: 'Colonial Country Club', slug: 'colonial-cc-memphis', city: 'Cordova', state: 'Tennessee', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Joe Lee', yearBuilt: 1972, holes: 18, par: 72, yardage: 7102, description: 'A Joe Lee design in the Cordova suburb east of Memphis, Colonial Country Club is one of the most respected private clubs in the Mid-South. The mature parkland layout through hardwood forest features strategic water hazards, undulating greens, and excellent year-round conditioning.', highlights: ['Respected Mid-South private club', 'Joe Lee mature parkland design', 'Hardwood forest setting in Cordova'], imageAlt: 'Colonial Country Club parkland fairway through Memphis hardwood forest' },
    { id: 'mem-5', name: 'Links at Whitehaven', slug: 'links-at-whitehaven', city: 'Memphis', state: 'Tennessee', type: 'public', rating: 4.0, greensFee: '$25–$50', architect: 'Gary Roger Baird', yearBuilt: 2001, holes: 18, par: 72, yardage: 7049, description: 'A Gary Roger Baird design on the south side of Memphis, the Links at Whitehaven is a solid public option featuring links-style elements with open fairways, native grasses, and strategic mounding. The 7,049-yard layout offers a surprising amount of challenge and character at an accessible price point.', highlights: ['Links-style elements unusual for Memphis', 'Affordable 7,049-yard championship layout', 'Gary Roger Baird public design'], imageAlt: 'Links at Whitehaven links-style fairway on south side of Memphis' },
    { id: 'mem-6', name: 'Spring Creek Ranch', slug: 'spring-creek-ranch-memphis', city: 'Collierville', state: 'Tennessee', type: 'semi-private', rating: 4.2, greensFee: '$45–$80', architect: 'Rick Robbins', yearBuilt: 2005, holes: 18, par: 72, yardage: 7069, description: 'A Rick Robbins design in the affluent Collierville suburb east of Memphis, Spring Creek Ranch offers semi-private access to a well-conditioned championship layout. The course winds through rolling terrain with strategic water features, mature trees, and a tranquil countryside atmosphere removed from the bustle of downtown Memphis.', highlights: ['Rick Robbins semi-private championship design', 'Rolling Collierville countryside setting', 'Well-conditioned layout with strategic water features'], imageAlt: 'Spring Creek Ranch fairway through rolling Collierville countryside near Memphis' },
    { id: 'mem-7', name: 'Tunica National Golf & Tennis', slug: 'tunica-national-golf', city: 'Tunica', state: 'Mississippi', type: 'public', rating: 4.1, greensFee: '$35–$70', architect: 'Mark McCumber', yearBuilt: 2000, holes: 18, par: 72, yardage: 7210, description: 'A Mark McCumber design in the Mississippi Delta casino region south of Memphis, Tunica National offers championship-caliber golf through Delta terrain with strategic water hazards and native vegetation. The 7,210-yard layout is a popular day trip for Memphis golfers seeking a challenging and well-maintained public experience.', highlights: ['Mark McCumber championship design in Mississippi Delta', 'Popular Memphis-area day trip course', '7,210-yard layout through Delta terrain'], imageAlt: 'Tunica National Golf Course fairway through Mississippi Delta near Memphis' },
    { id: 'mem-8', name: 'Windyke Country Club', slug: 'windyke-country-club', city: 'Memphis', state: 'Tennessee', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Joe Lee', yearBuilt: 1981, holes: 18, par: 72, yardage: 7044, description: 'A Joe Lee design in the eastern Memphis suburbs, Windyke Country Club is a well-respected private club that has hosted the Memphis City Amateur and other regional events. The mature parkland layout through rolling terrain features strategic water hazards, tree-lined fairways, and consistent conditioning.', highlights: ['Well-respected Memphis private club', 'Joe Lee mature parkland design', 'Host of Memphis City Amateur and regional events'], imageAlt: 'Windyke Country Club parkland fairway in eastern Memphis suburbs' },
  ],
  'louisville-kentucky': [
    { id: 'lou-1', name: 'Valhalla Golf Club', slug: 'valhalla-golf-club', city: 'Louisville', state: 'Kentucky', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 1986, holes: 18, par: 72, yardage: 7458, description: 'Host of three PGA Championships (1996, 2000, 2014), the 2008 Ryder Cup, and the 2024 PGA Championship, Valhalla is Louisville\'s most celebrated course and one of the premier championship venues in America. Nicklaus\'s design through rolling Kentucky terrain features dramatic creek crossings, bold bunkering, and a thrilling risk-reward finish.', highlights: ['Four-time PGA Championship and Ryder Cup host', 'Jack Nicklaus premier championship design', 'Dramatic Floyds Fork creek crossings'], imageAlt: 'Valhalla Golf Club championship fairway during PGA Championship in Louisville' },
    { id: 'lou-2', name: 'Louisville Country Club', slug: 'louisville-country-club', city: 'Louisville', state: 'Kentucky', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Seth Raynor', yearBuilt: 1895, holes: 18, par: 70, yardage: 6534, description: 'One of the oldest clubs in the South, Louisville Country Club features a Seth Raynor redesign from 1924 with classic template holes on a compact but strategic layout. The intimate par-70 through mature Kentucky hardwoods delivers Golden Age charm with Raynor\'s trademark Redan, Biarritz, and Punchbowl greens.', highlights: ['Seth Raynor 1924 template hole redesign', 'One of the oldest clubs in the South since 1895', 'Classic Golden Age charm on compact layout'], imageAlt: 'Louisville Country Club Seth Raynor template fairway through Kentucky hardwoods' },
    { id: 'lou-3', name: 'Persimmon Ridge Golf Club', slug: 'persimmon-ridge-golf-club', city: 'Louisville', state: 'Kentucky', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Arthur Hills', yearBuilt: 1990, holes: 18, par: 72, yardage: 7086, description: 'An Arthur Hills design in eastern Jefferson County, Persimmon Ridge hosted the Senior PGA Championship in 1994. The layout winds through rolling Kentucky Bluegrass terrain with mature hardwood forests, dramatic ravines, and strategic water features that provide a stern championship test.', highlights: ['1994 Senior PGA Championship host', 'Arthur Hills design through Kentucky Bluegrass', 'Rolling ravines and mature hardwood forests'], imageAlt: 'Persimmon Ridge Golf Club Arthur Hills fairway through Kentucky ravines' },
    { id: 'lou-4', name: 'Chariot Run Golf Club', slug: 'chariot-run-golf-club', city: 'Laconia', state: 'Indiana', type: 'public', rating: 4.3, greensFee: '$45–$80', architect: 'Rees Jones', yearBuilt: 1997, holes: 18, par: 71, yardage: 7031, description: 'A Rees Jones design at Horseshoe Southern Indiana casino resort across the river from Louisville, Chariot Run winds through dramatic wooded ravines and rolling terrain with Ohio River Valley views. The public course offers championship-caliber golf at accessible pricing and is a favorite for Louisville-area golfers.', highlights: ['Rees Jones design at Horseshoe casino resort', 'Dramatic wooded ravines and Ohio River Valley views', 'Championship golf across the river from Louisville'], imageAlt: 'Chariot Run Golf Club Rees Jones fairway through Indiana ravines near Louisville' },
    { id: 'lou-5', name: 'Nevel Meade Golf Course', slug: 'nevel-meade-golf-course', city: 'Prospect', state: 'Kentucky', type: 'public', rating: 4.1, greensFee: '$30–$60', architect: 'Steve Smyers', yearBuilt: 1996, holes: 18, par: 72, yardage: 6901, description: 'A Steve Smyers design in Prospect northeast of Louisville, Nevel Meade offers an excellent public golf experience through rolling Kentucky horse country. The layout features strategic bunkering, natural elevation changes, and views of the surrounding Bluegrass landscape at a price point that makes it one of Louisville\'s best public values.', highlights: ['Steve Smyers design in Kentucky horse country', 'Bluegrass landscape and rolling terrain', 'Outstanding public value northeast of Louisville'], imageAlt: 'Nevel Meade Golf Course fairway through Kentucky horse country near Louisville' },
    { id: 'lou-6', name: 'Big Spring Country Club', slug: 'big-spring-country-club', city: 'Louisville', state: 'Kentucky', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Perry Maxwell', yearBuilt: 1928, holes: 18, par: 72, yardage: 6785, description: 'A Perry Maxwell design in eastern Louisville, Big Spring is one of the architect\'s lesser-known but most delightful works. Maxwell\'s signature tilted, undulating greens and strategic bunkering create fascinating short-game challenges on a mature parkland layout through stately Kentucky hardwoods.', highlights: ['Perry Maxwell Golden Age design from 1928', 'Signature tilted undulating green complexes', 'Mature Kentucky hardwood parkland'], imageAlt: 'Big Spring Country Club Perry Maxwell fairway through Louisville parkland' },
    { id: 'lou-7', name: 'Hurstbourne Country Club', slug: 'hurstbourne-country-club', city: 'Louisville', state: 'Kentucky', type: 'private', rating: 4.2, greensFee: 'Members Only', architect: 'Jack Ridge', yearBuilt: 1970, holes: 18, par: 72, yardage: 6961, description: 'One of Louisville\'s largest and most active private clubs, Hurstbourne features a well-maintained layout through rolling eastern Jefferson County terrain. The mature parkland course offers a classic Kentucky golf experience with tree-lined fairways, strategic bunkers, and a strong tournament hosting history.', highlights: ['One of Louisville\'s most active private clubs', 'Mature parkland in eastern Jefferson County', 'Strong tournament hosting tradition'], imageAlt: 'Hurstbourne Country Club parkland fairway in eastern Louisville' },
    { id: 'lou-8', name: 'Quail Chase Golf Course', slug: 'quail-chase-golf-course', city: 'Louisville', state: 'Kentucky', type: 'public', rating: 4.0, greensFee: '$25–$50', architect: 'Fuzzy Zoeller & Clyde Johnston', yearBuilt: 1991, holes: 27, par: 72, yardage: 6695, description: 'Co-designed by Louisville native and Masters champion Fuzzy Zoeller, Quail Chase offers 27 holes of solid public golf south of the city. The three distinct nines wind through rolling Kentucky terrain with strategic water hazards and native hardwood corridors at some of the most accessible pricing in the Louisville area.', highlights: ['Co-designed by Masters champion Fuzzy Zoeller', '27 holes with three distinct nines', 'Most accessible pricing in Louisville area'], imageAlt: 'Quail Chase Golf Course Fuzzy Zoeller public fairway in south Louisville' },
  ],
  'salt-lake-city-utah': [
    { id: 'slc-1', name: 'Promontory Club - Pete Dye Course', slug: 'promontory-pete-dye', city: 'Park City', state: 'Utah', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Pete Dye', yearBuilt: 2008, holes: 18, par: 72, yardage: 7691, description: 'A Pete Dye design at the exclusive Promontory community near Park City, this mountain course at 6,300 feet elevation features Dye\'s bold shaping through sagebrush meadows and aspen groves with panoramic views of the Wasatch Mountains and Jordanelle Reservoir. The 7,691-yard beast is one of the longest mountain courses in America.', highlights: ['7,691 yards — among America\'s longest mountain courses', 'Pete Dye design at 6,300-foot elevation', 'Wasatch Mountain and Jordanelle Reservoir views'], imageAlt: 'Promontory Club Pete Dye Course mountain fairway with Wasatch views near Park City' },
    { id: 'slc-2', name: 'Bonneville Golf Course', slug: 'bonneville-golf-course', city: 'Salt Lake City', state: 'Utah', type: 'public', rating: 4.2, greensFee: '$30–$50', architect: 'William F. Bell', yearBuilt: 1929, holes: 18, par: 72, yardage: 6824, description: 'Salt Lake City\'s best-loved municipal course, Bonneville sits at the mouth of Emigration Canyon with stunning views of the Wasatch Front. The classic William Bell design has served the community since 1929 with a challenging hillside routing, mature trees, and one of the most scenic backdrops of any municipal course in the West.', highlights: ['Salt Lake City\'s premier municipal course since 1929', 'Stunning Wasatch Front mountain views', 'Historic William Bell hillside design'], imageAlt: 'Bonneville Golf Course fairway with Wasatch Front mountain views in Salt Lake City', history: 'Bonneville Golf Course first opened in 1929 as one of Salt Lake City\'s earliest public courses. The original nine was designed by Willie Bell on hilly terrain at the mouth of Emigration Canyon on the east bench with stunning Wasatch Front views.\n\nWilliam P. and William F. Bell redesigned the course in the 1950s and added an upper nine in 1957, creating the current 18-hole layout. The hilly terrain and ravine create dramatic elevation changes unusual for a municipal course.\n\nBonneville remains one of Utah\'s most-played courses and has hosted numerous state amateur championships throughout its nearly century-long history.', signatureHoles: [{ hole: 1, par: 4, yardage: 395, description: 'The opening hole sets the tone on the hilly lower nine with immediate Wasatch Front views.' }, { hole: 8, par: 3, yardage: 180, description: 'A scenic par 3 with the ravine and mature trees framing the green.' }, { hole: 10, par: 4, yardage: 415, description: 'The upper nine opener climbs into the foothills with dramatic elevation gain and panoramic Salt Lake Valley views.' }, { hole: 18, par: 4, yardage: 400, description: 'The finishing hole descends toward the clubhouse with the Wasatch Range as a backdrop.' }], whatToExpect: 'Bonneville is renowned for hilly terrain and challenging greens on the east bench. The lower nine plays through the original routing while the upper nine climbs into the foothills with expansive valley and mountain views.\n\nGreen fees are $30 to $50 with Wasatch Front views among the best of any public course in the West.', playingTips: 'The hilly terrain creates many uneven lies. The upper nine is particularly steep requiring sidehill and uphill shots.\n\nAt roughly 4,300 feet elevation, the ball carries farther than at sea level. Adjust club selection especially on downhill holes.', faqs: [{ question: 'Can the public play Bonneville?', answer: 'Yes. Green fees range from $30 to $50.' }, { question: 'How old is Bonneville?', answer: 'The original nine opened in 1929 with the upper nine added in 1957.' }, { question: 'Who designed it?', answer: 'Willie Bell designed the original nine. William P. and William F. Bell redesigned and expanded it in the 1950s.' }, { question: 'Is Bonneville hilly?', answer: 'Yes. It is known for challenging hillside terrain with significant elevation changes on both nines.' }] },
    { id: 'slc-3', name: 'Thanksgiving Point Golf Club', slug: 'thanksgiving-point-golf', city: 'Lehi', state: 'Utah', type: 'public', rating: 4.3, greensFee: '$55–$95', architect: 'Johnny Miller', yearBuilt: 1997, holes: 18, par: 72, yardage: 7714, description: 'Designed by U.S. Open champion Johnny Miller in his home state, Thanksgiving Point is one of the longest public courses in America at 7,714 yards. The dramatic layout between Utah Lake and the Wasatch Mountains features massive fairways, sweeping views, and Miller\'s strategic design philosophy emphasizing precise iron play.', highlights: ['7,714 yards — one of America\'s longest public courses', 'Johnny Miller design in his home state', 'Sweeping Utah Lake and Wasatch Mountain views'], imageAlt: 'Thanksgiving Point Golf Club expansive fairway with Wasatch Mountain backdrop' },
    { id: 'slc-4', name: 'Alpine Country Club', slug: 'alpine-country-club', city: 'Highland', state: 'Utah', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'William H. Neff', yearBuilt: 1959, holes: 18, par: 72, yardage: 6895, description: 'Nestled at the base of Mount Timpanogos in the Point of the Mountain area, Alpine Country Club is one of Utah\'s most scenic and respected private clubs. The mountainside layout features dramatic elevation changes, stunning Timpanogos views, and mature pine and aspen corridors that create a serene mountain golf atmosphere.', highlights: ['Mount Timpanogos base with dramatic mountain views', 'One of Utah\'s most respected private clubs', 'Mountainside elevation changes through pine and aspen'], imageAlt: 'Alpine Country Club mountainside fairway with Mount Timpanogos views' },
    { id: 'slc-5', name: 'Soldier Hollow Golf Club - Gold', slug: 'soldier-hollow-gold', city: 'Midway', state: 'Utah', type: 'public', rating: 4.2, greensFee: '$40–$75', architect: 'Gene Bates', yearBuilt: 2004, holes: 18, par: 72, yardage: 7598, description: 'Built on the site of the 2002 Winter Olympics cross-country venue in the Heber Valley, Soldier Hollow Gold is a Gene Bates design at 5,600 feet elevation with sweeping mountain views. The 7,598-yard championship layout through open meadows and sagebrush offers a links-like mountain experience at outstanding public value.', highlights: ['2002 Winter Olympics venue site', 'Links-like mountain golf at 5,600 feet', '7,598-yard championship layout at public pricing'], imageAlt: 'Soldier Hollow Gold Course mountain meadow fairway in Heber Valley' },
    { id: 'slc-6', name: 'Hobble Creek Golf Course', slug: 'hobble-creek-golf-course', city: 'Springville', state: 'Utah', type: 'public', rating: 4.0, greensFee: '$25–$45', architect: 'William H. Neff', yearBuilt: 1967, holes: 18, par: 71, yardage: 6328, description: 'A William Neff design tucked into a narrow canyon in Springville south of Salt Lake City, Hobble Creek is widely considered one of the most scenic affordable courses in Utah. The canyon routing features creek crossings, mature cottonwood trees, and dramatic mountain walls that create a secluded and memorable golf experience.', highlights: ['Scenic canyon routing in Springville', 'Creek crossings and cottonwood-lined fairways', 'Among Utah\'s most affordable scenic courses'], imageAlt: 'Hobble Creek Golf Course canyon fairway with mountain walls in Springville' },
    { id: 'slc-7', name: 'Entrada at Snow Canyon', slug: 'entrada-snow-canyon', city: 'St. George', state: 'Utah', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Johnny Miller', yearBuilt: 1998, holes: 18, par: 72, yardage: 7331, description: 'A Johnny Miller design adjacent to Snow Canyon State Park in southern Utah, Entrada features a dramatic red rock desert landscape unlike any other course in America. The layout winds through red sandstone formations, black lava rock, and native desert vegetation with views of the Pine Valley Mountains creating a visual spectacle on every hole.', highlights: ['Dramatic red rock desert landscape', 'Adjacent to Snow Canyon State Park', 'Johnny Miller design through sandstone and lava formations'], imageAlt: 'Entrada at Snow Canyon red rock desert fairway in St. George Utah' },
    { id: 'slc-8', name: 'Riverside Country Club', slug: 'riverside-cc-provo', city: 'Provo', state: 'Utah', type: 'private', rating: 4.2, greensFee: 'Members Only', architect: 'William H. Neff', yearBuilt: 1958, holes: 18, par: 72, yardage: 6803, description: 'A William Neff design along the Provo River at the base of the Wasatch Mountains, Riverside Country Club is one of the most scenic private clubs in Utah Valley. The mature parkland layout features cottonwood-lined fairways, strategic river crossings, and panoramic views of the Timpanogos massif that elevate every round.', highlights: ['Provo River setting at base of Wasatch Mountains', 'Panoramic Mount Timpanogos views', 'Cottonwood-lined mature parkland design'], imageAlt: 'Riverside Country Club parkland fairway along Provo River with Wasatch views' },
  ],
  'richmond-virginia': [
    { id: 'ric-1', name: 'The Country Club of Virginia - James River', slug: 'ccv-james-river', city: 'Richmond', state: 'Virginia', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'William Flynn', yearBuilt: 1928, holes: 18, par: 72, yardage: 6808, description: 'A William Flynn masterpiece along the James River, the CCV James River Course is consistently ranked among the finest private courses in Virginia. Flynn\'s Golden Age architecture features strategic bunkering, natural topography, and a classic routing through mature hardwoods on a historic estate overlooking the river valley.', highlights: ['William Flynn Golden Age masterpiece', 'James River valley estate setting', 'Consistently ranked among Virginia\'s finest'], imageAlt: 'Country Club of Virginia James River Course Flynn fairway along James River' },
    { id: 'ric-2', name: 'Kinloch Golf Club', slug: 'kinloch-golf-club', city: 'Manakin-Sabot', state: 'Virginia', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Lester George & Vinny Giles', yearBuilt: 2001, holes: 18, par: 72, yardage: 7150, description: 'Kinloch Golf Club west of Richmond is consistently ranked as the top course in Virginia and a top-100 course nationally. The George-Giles design through rolling Piedmont terrain features wide fairways, deep bunkers, and bold green complexes that reward creative shotmaking on a stunning property along the James River bluffs.', highlights: ['Consistently ranked #1 course in Virginia', 'Top-100 nationally ranked private club', 'George-Giles design on James River bluffs'], imageAlt: 'Kinloch Golf Club championship fairway through Virginia Piedmont terrain' },
    { id: 'ric-3', name: 'Independence Golf Club', slug: 'independence-golf-club', city: 'Midlothian', state: 'Virginia', type: 'public', rating: 4.2, greensFee: '$40–$75', architect: 'Tom Fazio', yearBuilt: 2001, holes: 18, par: 72, yardage: 7076, description: 'A Tom Fazio public design in Midlothian south of Richmond, Independence is widely considered the best public course in the Richmond area. Fazio\'s layout through rolling Virginia terrain features strategic bunkering, dramatic water features, and mature hardwood forests that deliver a private-club experience at public pricing.', highlights: ['Tom Fazio public design — best public in Richmond area', 'Private-club experience at public pricing', 'Rolling Virginia terrain with mature hardwoods'], imageAlt: 'Independence Golf Club Tom Fazio public fairway in Midlothian Virginia', history: 'Independence Golf Club opened in 2001 as the centerpiece of the Founders Bridge development in Midlothian south of Richmond. The Tom Fazio design was immediately recognized as the best public course in the Richmond area.\n\nIn 2013, architect Lester George led major renovations earning Golf Digest Top 10 recognition. The course has hosted the State Open of Virginia and other prestigious amateur competitions.\n\nThe facility features 18 championship holes plus excellent practice facilities at daily-fee pricing.', signatureHoles: [{ hole: 4, par: 3, yardage: 190, description: 'A demanding par 3 with water guarding the approach and deep bunkers protecting the green.' }, { hole: 9, par: 5, yardage: 535, description: 'A risk-reward par 5 closing the front nine, reachable for long hitters with water threatening aggressive play.' }, { hole: 14, par: 4, yardage: 420, description: 'A strategic par 4 through mature Virginia hardwoods where tee shot positioning determines approach quality.' }, { hole: 18, par: 4, yardage: 440, description: 'A strong finishing hole demanding two quality shots with water and bunkering creating drama on the final approach.' }], whatToExpect: 'Independence delivers a private-club experience at public pricing through rolling Virginia terrain with strategic bunkering, water features, and mature hardwoods. Conditioning is excellent for a public facility.\n\nThe course plays to 7,076 yards from the tips with multiple tee options.', playingTips: 'Position off the tee is critical on dogleg holes. The Fazio-George design rewards strategic play over raw power.\n\nThe greens have subtle deceptive contours. Favor the center on approach shots to avoid short-siding yourself.', faqs: [{ question: 'Can the public play Independence?', answer: 'Yes. Green fees range from $40 to $75.' }, { question: 'Who designed it?', answer: 'Tom Fazio in 2001, with a major Lester George renovation in 2013.' }, { question: 'Has it hosted tournaments?', answer: 'Yes, including the State Open of Virginia.' }, { question: 'How challenging is it?', answer: 'At 7,076 yards from the tips with multiple tee options for all levels.' }] },
    { id: 'ric-4', name: 'Hermitage Country Club', slug: 'hermitage-country-club', city: 'Richmond', state: 'Virginia', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'A.W. Tillinghast', yearBuilt: 1900, holes: 18, par: 71, yardage: 6683, description: 'A historic Tillinghast design in Richmond\'s West End, Hermitage Country Club is one of the most storied private clubs in Virginia. The compact but strategic par-71 features Tillinghast\'s trademark dramatic bunkering and challenging green complexes on a mature parkland property that has hosted state and regional championships.', highlights: ['Historic A.W. Tillinghast design', 'One of Virginia\'s most storied private clubs', 'Host of state and regional championships'], imageAlt: 'Hermitage Country Club Tillinghast parkland fairway in Richmond' },
    { id: 'ric-5', name: 'The Federal Club', slug: 'the-federal-club', city: 'Glen Allen', state: 'Virginia', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Lester George', yearBuilt: 2008, holes: 18, par: 72, yardage: 7046, description: 'A modern Lester George design north of Richmond in Glen Allen, The Federal Club features a rolling layout through Virginia hardwood forest with natural creek corridors and a links-influenced open feel on several holes. George\'s strategic design rewards thoughtful play with multiple routing options from tee to green.', highlights: ['Modern Lester George design north of Richmond', 'Virginia hardwood forest and creek corridors', 'Strategic design with multiple routing options'], imageAlt: 'The Federal Club Lester George fairway through Virginia hardwoods in Glen Allen' },
    { id: 'ric-6', name: 'Royal New Kent Golf Club', slug: 'royal-new-kent-gc', city: 'Providence Forge', state: 'Virginia', type: 'public', rating: 4.3, greensFee: '$50–$90', architect: 'Mike Strantz', yearBuilt: 1997, holes: 18, par: 72, yardage: 7291, description: 'A Mike Strantz design east of Richmond modeled after the great links of Ireland, Royal New Kent is one of the most unique public courses in Virginia. The dramatic layout features massive dunes, deep pot bunkers, elevated greens, and a windswept character that creates an authentic links experience in the Virginia Tidewater region.', highlights: ['Mike Strantz Irish links-inspired design', 'Massive dunes and deep pot bunkers', 'Authentic links experience in Virginia Tidewater'], imageAlt: 'Royal New Kent Golf Club links-style dunes and pot bunkers near Richmond' },
    { id: 'ric-7', name: 'Stonehouse Golf Club', slug: 'stonehouse-golf-club', city: 'Toano', state: 'Virginia', type: 'public', rating: 4.2, greensFee: '$40–$75', architect: 'Mike Strantz', yearBuilt: 1996, holes: 18, par: 71, yardage: 6867, description: 'The sibling course to Royal New Kent, Stonehouse is another Mike Strantz creation east of Richmond that draws inspiration from Scottish links and English heathland courses. The dramatic routing features massive elevation changes for Coastal Virginia, bold bunkering, and Strantz\'s characteristic visual drama.', highlights: ['Mike Strantz companion to Royal New Kent', 'Scottish links and English heathland inspiration', 'Dramatic elevation changes for Coastal Virginia'], imageAlt: 'Stonehouse Golf Club Mike Strantz dramatic fairway near Williamsburg' },
    { id: 'ric-8', name: 'Magnolia Green Golf Club', slug: 'magnolia-green-golf-club', city: 'Moseley', state: 'Virginia', type: 'public', rating: 4.0, greensFee: '$35–$65', architect: 'Nicklaus Design', yearBuilt: 2010, holes: 18, par: 72, yardage: 7038, description: 'A Nicklaus Design layout in the Magnolia Green community south of Richmond, this public course offers a modern championship experience through rolling Virginia piedmont terrain. The well-conditioned 7,038-yard layout features strategic water hazards, native vegetation, and a welcoming atmosphere for all skill levels.', highlights: ['Nicklaus Design modern championship layout', 'Well-conditioned public course south of Richmond', 'Strategic water hazards through Virginia piedmont'], imageAlt: 'Magnolia Green Golf Club Nicklaus Design fairway south of Richmond' },
  ],
  'pittsburgh-pennsylvania': [
    { id: 'pit-1', name: 'Oakmont Country Club', slug: 'oakmont-country-club', city: 'Oakmont', state: 'Pennsylvania', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'Henry Fownes', yearBuilt: 1903, holes: 18, par: 71, yardage: 7255, description: 'Host of nine U.S. Opens and five PGA Championships, Oakmont is one of the most demanding and historic courses in golf. The Henry Fownes design features over 200 bunkers, the famous Church Pews bunker complex, lightning-fast greens, and a relentless par-71 that has humbled the greatest players in history.', highlights: ['Nine-time U.S. Open host — most of any course', 'Over 200 bunkers including the iconic Church Pews', 'One of the most demanding courses in golf history'], imageAlt: 'Oakmont Country Club Church Pews bunker and championship fairway', history: 'Founded in 1903 by Pittsburgh steel magnate Henry C. Fownes on 191 acres along the Allegheny River. His son William, the 1910 U.S. Amateur champion, continued toughening the course for decades.\n\nOakmont has hosted nine U.S. Opens (1927, 1935, 1953, 1962, 1973, 1983, 1994, 2007, 2016) plus 2025, more than any other course. The 1962 Open produced Jack Nicklaus\'s first major over Arnold Palmer. Gil Hanse restored the course by removing thousands of trees to honor Fownes\'s original open vision.', signatureHoles: [{ hole: 1, par: 4, yardage: 488, description: 'One of the toughest opening holes in golf. Ranked first in scoring resistance at the 2016 U.S. Open.' }, { hole: 3, par: 4, yardage: 428, description: 'Home of the famous Church Pews bunker complex with grass-covered ridges between the 3rd and 4th fairways.' }, { hole: 12, par: 5, yardage: 667, description: 'One of the longest holes in championship golf, demanding three excellent shots.' }], whatToExpect: 'Over 200 bunkers, lightning-fast greens, and narrow fairways on rolling terrain along the Allegheny River. Par 71, over 7,200 yards. Walking with caddies is standard.', playingTips: 'Avoiding bunkers is paramount since recovery rarely results in par. Greens are among the fastest in golf. Leave approaches below the hole and accept that par is a good score on most holes.', faqs: [{ question: 'Can the public play Oakmont?', answer: 'No. Private club, member invitation only.' }, { question: 'What are the Church Pews?', answer: 'A massive bunker complex between the 3rd and 4th holes with grass ridges resembling church pews.' }, { question: 'How many U.S. Opens?', answer: 'Nine completed plus 2025, more than any other course.' }] },
    { id: 'pit-2', name: 'Laurel Valley Golf Club', slug: 'laurel-valley-golf-club', city: 'Ligonier', state: 'Pennsylvania', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Dick Wilson', yearBuilt: 1959, holes: 18, par: 71, yardage: 7305, description: 'A Dick Wilson design in the Laurel Highlands east of Pittsburgh, Laurel Valley hosted the 1965 PGA Championship and 1975 Ryder Cup, with Arnold Palmer serving as head professional. The mountainside layout through towering hardwoods features Wilson\'s signature dramatic bunkering and challenging green complexes.', highlights: ['1965 PGA Championship and 1975 Ryder Cup host', 'Arnold Palmer served as head professional', 'Dick Wilson mountain design through Laurel Highlands'], imageAlt: 'Laurel Valley Golf Club mountain fairway through Laurel Highlands hardwoods', history: 'Laurel Valley Golf Club was established in 1959 in the picturesque Laurel Highlands of western Pennsylvania, near the town of Ligonier. The course was designed by Dick Wilson, considered by many to be his consummate design, with Paul Erath assisting. The club was founded by a group of prominent Pittsburgh businessmen, and Arnold Palmer, a Latrobe native from just down the road, served as the club\'s first head professional.\n\nLaurel Valley quickly established itself as one of America\'s premier championship venues, hosting the 1965 PGA Championship won by Dave Marr, and the 1975 Ryder Cup where the United States defeated Great Britain and Ireland. Arnold Palmer\'s association with the club added immense prestige, and he and Ed Seay later contributed to course modifications that kept the layout at the forefront of championship golf.\n\nThe club has hosted numerous other significant events including the 1989 U.S. Senior Open and the 2010 Senior Players Championship. Set on a mountainside surrounded by towering hardwood forests, Laurel Valley offers a dramatic and secluded golf experience that has earned it consistent placement among the top 50 courses in America.', signatureHoles: [{ hole: 15, par: 4, yardage: 455, description: 'One of the most celebrated holes on the course, this demanding par 4 features a narrow, tree-lined fairway with water threatening the approach. The strategic decisions required make it a favorite among members and visiting professionals alike.' }, { hole: 7, par: 3, yardage: 205, description: 'A beautiful and testing par 3 that has been a pivotal hole in championship play at Laurel Valley. The green is well-defended by Wilson\'s dramatic bunkering, demanding a precise tee shot.' }, { hole: 14, par: 4, yardage: 425, description: 'A magnificent par 4 through the mountain forest that exemplifies Dick Wilson\'s ability to create holes that are both visually stunning and strategically demanding.' }, { hole: 10, par: 4, yardage: 415, description: 'The opening hole of the back nine plays through a narrow corridor of hardwood trees, demanding accuracy off the tee and a well-judged approach to a challenging green.' }], whatToExpect: 'Laurel Valley Golf Club offers one of the most exclusive and distinguished golf experiences in the eastern United States. The mountainside setting among towering hardwoods creates a cathedral-like atmosphere, with the course winding through the natural terrain of the Laurel Highlands. Dick Wilson\'s design features narrow, tree-lined fairways, strategic bunkering, and demanding green complexes that test every aspect of the game.\n\nThe club maintains an air of understated elegance befitting its history and the legacy of Arnold Palmer. Conditioning is impeccable, and the relatively private membership ensures a peaceful, unhurried pace of play.', playingTips: 'Accuracy is the premium skill at Laurel Valley. The narrow, tree-lined fairways leave little margin for error off the tee, and Dick Wilson\'s bunkering severely penalizes wayward approach shots. Consider taking less than driver on the tighter holes to ensure you find the fairway.\n\nThe mountain setting means elevation changes affect club selection on many holes, and the Laurel Highlands climate can produce cool temperatures and morning mist even in summer. The greens are firm and quick, with subtle breaks influenced by the mountainous terrain. Patience and course management will be rewarded over aggressive play.', faqs: [{ question: 'Can the public play Laurel Valley Golf Club?', answer: 'No, Laurel Valley is an extremely private club. Access is limited to members and their invited guests.' }, { question: 'What is Arnold Palmer\'s connection to Laurel Valley?', answer: 'Arnold Palmer served as the club\'s first head professional when it opened in 1959. He grew up just down the road in Latrobe, Pennsylvania, and maintained a lifelong association with the club.' }, { question: 'What major championships has Laurel Valley hosted?', answer: 'Laurel Valley hosted the 1965 PGA Championship, 1975 Ryder Cup, 1989 U.S. Senior Open, and 2010 Senior Players Championship, among other significant events.' }, { question: 'Where is Laurel Valley located?', answer: 'Laurel Valley is located in Ligonier Township in Westmoreland County, Pennsylvania, in the Laurel Highlands about 50 miles east of Pittsburgh.' }] },
    { id: 'pit-3', name: 'Fox Chapel Golf Club', slug: 'fox-chapel-golf-club', city: 'Pittsburgh', state: 'Pennsylvania', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Seth Raynor', yearBuilt: 1923, holes: 18, par: 70, yardage: 6587, description: 'A Seth Raynor gem in the affluent Fox Chapel borough of Pittsburgh, this intimate private club features Raynor\'s classic template holes including Redan, Biarritz, and Eden on a rolling wooded property. The compact par-70 rewards precision and shotmaking in a serene woodland setting along the Allegheny River.', highlights: ['Seth Raynor template hole design', 'Intimate woodland setting along Allegheny River', 'Classic Golden Age private club in Fox Chapel'], imageAlt: 'Fox Chapel Golf Club Seth Raynor template fairway in Pittsburgh', history: 'Fox Chapel Golf Club was commissioned in 1923 with Seth Raynor and Charles Banks as architects. Raynor designed template holes adapted to the rolling wooded terrain in Fox Chapel borough northeast of Pittsburgh along the Allegheny River.\n\nThe club has hosted the 1965 U.S. Senior Amateur, 1985 U.S. Women\'s Amateur, 2002 Curtis Cup, and 2024 U.S. Senior Women\'s Open.\n\nRaynor\'s reputation has experienced a major revival, and Fox Chapel stands as one of his finest surviving works with classic Redan, Biarritz, and Eden template holes faithfully preserved.', signatureHoles: [{ hole: 3, par: 3, yardage: 180, description: 'A classic Redan par 3 with the green angling away and a front-left bunker requiring a fade or running shot.' }, { hole: 8, par: 4, yardage: 380, description: 'A strategic woodland par 4 with a Raynor green complex rewarding accurate approaches.' }, { hole: 14, par: 3, yardage: 200, description: 'The Biarritz template with a long narrow green and distinctive center swale. One of the best-preserved Biarritz holes in existence.' }, { hole: 18, par: 4, yardage: 415, description: 'A demanding finishing hole back toward the clubhouse through mature woodland.' }], whatToExpect: 'Fox Chapel is an intimate Golden Age course through serene woodland along the Allegheny River. The par-70 plays just 6,587 yards but Raynor template holes provide tremendous strategic interest.\n\nThe club emphasizes walking golf with excellent conditioning.', playingTips: 'Understanding Raynor\'s templates is key. Each green has specific character from famous Scottish and English holes. Study slopes before putting.\n\nThe compact yardage is deceptive. Play position golf rather than attacking every pin.', faqs: [{ question: 'Can the public play Fox Chapel?', answer: 'No. It is a private club.' }, { question: 'Who designed it?', answer: 'Seth Raynor with Charles Banks, commissioned in 1923.' }, { question: 'What USGA events has it hosted?', answer: 'The 1965 U.S. Senior Amateur, 1985 U.S. Women\'s Amateur, 2002 Curtis Cup, and 2024 U.S. Senior Women\'s Open.' }, { question: 'What are template holes?', answer: 'Greens modeled after famous Scottish and English holes including Redan, Biarritz, and Eden templates.' }] },
    { id: 'pit-4', name: 'Quicksilver Golf Club', slug: 'quicksilver-golf-club', city: 'Midway', state: 'Pennsylvania', type: 'public', rating: 4.2, greensFee: '$40–$75', architect: 'Arnold Palmer Design', yearBuilt: 2004, holes: 18, par: 72, yardage: 7120, description: 'An Arnold Palmer design west of Pittsburgh, Quicksilver has hosted the Champions Tour\'s Constellation Energy Senior Players Championship. The rolling layout through western Pennsylvania ridges features Palmer\'s aggressive, challenging style with strategic water hazards and panoramic mountain views.', highlights: ['Champions Tour host venue', 'Arnold Palmer design through western PA ridges', 'Panoramic mountain views at public pricing'], imageAlt: 'Quicksilver Golf Club Arnold Palmer fairway through western Pennsylvania hills' },
    { id: 'pit-5', name: 'Olde Stonewall Golf Club', slug: 'olde-stonewall-golf-club', city: 'Ellwood City', state: 'Pennsylvania', type: 'public', rating: 4.4, greensFee: '$55–$100', architect: 'Michael Hurdzan & Dana Fry', yearBuilt: 2002, holes: 18, par: 70, yardage: 6514, description: 'A Hurdzan-Fry design north of Pittsburgh, Olde Stonewall is consistently ranked the top public course in the Pittsburgh area. The dramatic layout on 250 acres of Connoquenessing Creek valley features 200 feet of elevation change, natural stone outcroppings, waterfall features, and stunning fall foliage.', highlights: ['Top-ranked public course in Pittsburgh area', '200 feet of elevation change and natural stone', 'Stunning Connoquenessing Creek valley setting'], imageAlt: 'Olde Stonewall Golf Club dramatic valley fairway with stone outcroppings' },
    { id: 'pit-6', name: 'Pittsburgh Field Club', slug: 'pittsburgh-field-club', city: 'Pittsburgh', state: 'Pennsylvania', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Donald Ross / Ron Prichard (restoration)', yearBuilt: 1903, holes: 18, par: 72, yardage: 6658, description: 'One of Pittsburgh\'s oldest private clubs with a Donald Ross layout beautifully restored by Ron Prichard, Pittsburgh Field Club winds through the rolling hills of Fox Chapel. The restored Ross design features his characteristic crowned greens, strategic bunkering, and a classic parkland character preserved through careful renovation.', highlights: ['Donald Ross design restored by Ron Prichard', 'One of Pittsburgh\'s oldest private clubs since 1903', 'Classic parkland character in Fox Chapel hills'], imageAlt: 'Pittsburgh Field Club restored Donald Ross fairway in Fox Chapel' },
    { id: 'pit-7', name: 'Nemacolin Woodlands - Mystic Rock', slug: 'nemacolin-mystic-rock', city: 'Farmington', state: 'Pennsylvania', type: 'resort', rating: 4.4, greensFee: '$100–$200', architect: 'Pete Dye', yearBuilt: 1995, holes: 18, par: 72, yardage: 7514, description: 'A Pete Dye design at the Nemacolin resort in the Laurel Highlands, Mystic Rock is a championship mountain course that hosted the PGA Tour\'s 84 Lumber Classic. The dramatic 7,514-yard layout through dense Appalachian forest features Dye\'s bold design elements with significant elevation changes and stunning mountain scenery.', highlights: ['Former PGA Tour 84 Lumber Classic host', 'Pete Dye mountain design at 7,514 yards', 'Nemacolin luxury resort in Laurel Highlands'], imageAlt: 'Nemacolin Mystic Rock Pete Dye mountain fairway in Laurel Highlands' },
    { id: 'pit-8', name: 'Allegheny Country Club', slug: 'allegheny-country-club', city: 'Sewickley', state: 'Pennsylvania', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Robert White / William Flynn', yearBuilt: 1904, holes: 18, par: 72, yardage: 6849, description: 'A historic private club in Sewickley with a William Flynn redesign, Allegheny Country Club has hosted the U.S. Senior Open and U.S. Women\'s Amateur. The classic parkland layout through rolling terrain along the Ohio River features Flynn\'s strategic bunkering and naturalistic design philosophy.', highlights: ['U.S. Senior Open and U.S. Women\'s Amateur host', 'William Flynn parkland redesign', 'Historic Sewickley club along Ohio River'], imageAlt: 'Allegheny Country Club William Flynn parkland fairway in Sewickley' },
  ],
  'baltimore-maryland': [
    { id: 'bal-1', name: 'Baltimore Country Club - Five Farms East', slug: 'bcc-five-farms-east', city: 'Timonium', state: 'Maryland', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'A.W. Tillinghast', yearBuilt: 1926, holes: 18, par: 70, yardage: 6678, description: 'An A.W. Tillinghast masterpiece in the hunt country north of Baltimore, Five Farms East hosted the 1988 U.S. Women\'s Open and the 2021 BMW Championship. Tillinghast\'s dramatic bunkering, bold green contours, and strategic routing through mature parkland make this one of the finest Golden Age courses in the mid-Atlantic.', highlights: ['2021 BMW Championship and 1988 U.S. Women\'s Open host', 'A.W. Tillinghast Golden Age masterpiece', 'One of the finest private clubs in the mid-Atlantic'], imageAlt: 'Baltimore Country Club Five Farms East Tillinghast championship fairway' },
    { id: 'bal-2', name: 'Caves Valley Golf Club', slug: 'caves-valley-golf-club', city: 'Owings Mills', state: 'Maryland', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 1991, holes: 18, par: 72, yardage: 7233, description: 'A Tom Fazio design in the rolling hills of Owings Mills, Caves Valley hosted the 2021 BMW Championship and the 2002 Senior Players Championship. The sweeping layout through mature hardwood forest and dramatic valleys features Fazio\'s trademark bold shaping and immaculate conditioning.', highlights: ['2021 BMW Championship host venue', 'Tom Fazio design through rolling Maryland hills', 'Dramatic valleys and mature hardwood forest'], imageAlt: 'Caves Valley Golf Club Tom Fazio fairway through Maryland hills and valleys', history: 'Caves Valley opened in 1991 as a Tom Fazio design on 962 acres of rolling hunt country in Owings Mills, Maryland. The 2021 BMW Championship brought the FedExCup Playoffs here, where Patrick Cantlay won in a playoff. A major renovation preceded the 2025 BMW Championship return.\n\nFazio redesigned several holes in 1997. The course spans 7,233 yards with a slope of 144.', signatureHoles: [{ hole: 5, par: 4, yardage: 450, description: 'A demanding valley par 4 through mature hardwoods to one of Fazio\'s most dramatic green sites.' }, { hole: 11, par: 3, yardage: 195, description: 'A scenic par 3 over water set against the Maryland hillside.' }, { hole: 15, par: 5, yardage: 575, description: 'A risk-reward par 5 through the valley with water threatening the aggressive second shot.' }, { hole: 18, par: 4, yardage: 445, description: 'A strong finishing hole climbing toward the clubhouse with Fazio bunkering guarding the green.' }], whatToExpect: 'Caves Valley features bold Fazio shaping through dramatic Maryland hunt country on a 962-acre property with rolling fairways, water hazards, and mature hardwoods.\n\nConditioning is immaculate, maintained to PGA Tour standards year-round.', playingTips: 'Rolling terrain creates uneven lies throughout. The greens are fast and well-contoured requiring precise approach shots.\n\nAfter renovation the course plays significantly tougher than the 2021 BMW Championship suggested.', faqs: [{ question: 'Can the public play Caves Valley?', answer: 'No. It is a private club.' }, { question: 'What PGA Tour events has it hosted?', answer: 'The 2021 and 2025 BMW Championship events.' }, { question: 'Who designed it?', answer: 'Tom Fazio, opened 1991 with redesigns in 1997 and 2025.' }, { question: 'How large is the property?', answer: '962 acres of rolling hills, pastures, and woods in Owings Mills.' }] },
    { id: 'bal-3', name: 'Bulle Rock Golf Course', slug: 'bulle-rock-golf-course', city: 'Havre de Grace', state: 'Maryland', type: 'public', rating: 4.4, greensFee: '$60–$120', architect: 'Pete Dye', yearBuilt: 1998, holes: 18, par: 72, yardage: 7375, description: 'A Pete Dye design in Havre de Grace northeast of Baltimore, Bulle Rock hosted the LPGA Championship from 2005 to 2009 and is consistently ranked the top public course in Maryland. The 7,375-yard championship layout features Dye\'s trademark railroad ties, island greens, and bold hazards that create one of the most memorable public experiences on the East Coast.', highlights: ['Former LPGA Championship host (2005-2009)', 'Consistently ranked #1 public course in Maryland', 'Pete Dye championship design at 7,375 yards'], imageAlt: 'Bulle Rock Golf Course Pete Dye championship fairway in Havre de Grace' },
    { id: 'bal-4', name: 'Prospect Bay Country Club', slug: 'prospect-bay-cc', city: 'Grasonville', state: 'Maryland', type: 'semi-private', rating: 4.1, greensFee: '$40–$75', architect: 'P.B. Dye', yearBuilt: 1989, holes: 18, par: 72, yardage: 6811, description: 'A P.B. Dye design on Maryland\'s Eastern Shore near the Chesapeake Bay, Prospect Bay offers semi-private access to a challenging layout through tidewater terrain. The waterfront property features tidal marsh views, Chesapeake Bay breezes, and Dye family design DNA with strategic bunkering and water hazards.', highlights: ['P.B. Dye design on Maryland\'s Eastern Shore', 'Chesapeake Bay and tidal marsh views', 'Semi-private access to challenging tidewater golf'], imageAlt: 'Prospect Bay Country Club tidewater fairway with Chesapeake Bay views' },
    { id: 'bal-5', name: 'Cattail Creek Country Club', slug: 'cattail-creek-cc', city: 'Glenwood', state: 'Maryland', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Brian Ault', yearBuilt: 1991, holes: 18, par: 72, yardage: 6889, description: 'A Brian Ault design between Baltimore and Washington in Howard County, Cattail Creek is a well-respected private club with a challenging layout through rolling Maryland farmland. The mature parkland setting features strategic creek crossings, well-defended greens, and a classic mid-Atlantic character.', highlights: ['Well-respected Howard County private club', 'Strategic creek crossings through Maryland farmland', 'Classic mid-Atlantic parkland character'], imageAlt: 'Cattail Creek Country Club parkland fairway in Howard County Maryland' },
    { id: 'bal-6', name: 'Greystone Golf Course', slug: 'greystone-golf-course-md', city: 'White Hall', state: 'Maryland', type: 'public', rating: 4.1, greensFee: '$35–$65', architect: 'Joe Lee', yearBuilt: 1992, holes: 18, par: 72, yardage: 6917, description: 'A Joe Lee design in Baltimore County\'s horse country, Greystone offers quality public golf through rolling terrain with scenic views of the Gunpowder Falls valley. The layout features stone walls, creek crossings, and a pastoral Maryland countryside atmosphere at an accessible price that makes it a favorite of Baltimore-area golfers.', highlights: ['Joe Lee design in Baltimore County horse country', 'Gunpowder Falls valley views and stone walls', 'Quality public golf at accessible pricing'], imageAlt: 'Greystone Golf Course rolling fairway through Maryland horse country' },
    { id: 'bal-7', name: 'Maryland Golf & Country Club', slug: 'maryland-golf-cc', city: 'Bel Air', state: 'Maryland', type: 'public', rating: 4.0, greensFee: '$30–$55', architect: 'Russell Roberts', yearBuilt: 1964, holes: 18, par: 71, yardage: 6600, description: 'A mature Russell Roberts design in Harford County north of Baltimore, Maryland Golf & Country Club offers a well-maintained public experience through rolling woodland terrain. The classic par-71 features tree-lined fairways, strategic creek crossings, and a friendly atmosphere that has served the Baltimore-area community for over six decades.', highlights: ['Well-maintained public course in Harford County', 'Mature woodland setting north of Baltimore', 'Community-focused golf for over six decades'], imageAlt: 'Maryland Golf and Country Club woodland fairway in Bel Air' },
    { id: 'bal-8', name: 'Elkridge Club', slug: 'elkridge-club', city: 'Baltimore', state: 'Maryland', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Donald Ross', yearBuilt: 1922, holes: 18, par: 72, yardage: 6590, description: 'A Donald Ross design in north Baltimore, Elkridge Club is one of the most historic private clubs in Maryland. The classic Ross layout on a compact property features his trademark crowned greens, strategic cross-hazards, and a mature parkland character that has been carefully preserved through sensitive modern renovations.', highlights: ['Donald Ross classic design from 1922', 'One of Maryland\'s most historic private clubs', 'Carefully preserved Golden Age character'], imageAlt: 'Elkridge Club Donald Ross parkland fairway in north Baltimore' },
  ],
  'new-orleans-louisiana': [
    { id: 'nol-1', name: 'TPC Louisiana', slug: 'tpc-louisiana', city: 'Avondale', state: 'Louisiana', type: 'semi-private', rating: 4.4, greensFee: '$100–$175', architect: 'Pete Dye', yearBuilt: 2004, holes: 18, par: 72, yardage: 7425, description: 'Host of the Zurich Classic of New Orleans on the PGA Tour, TPC Louisiana is a Pete Dye design through the bayou landscape west of the city. The 7,425-yard layout features Dye\'s trademark forced carries over wetlands, dramatic bunkering, and a swampy Louisiana terrain that creates a unique championship golf setting.', highlights: ['PGA Tour Zurich Classic host venue', 'Pete Dye bayou and wetland design', 'Unique Louisiana swamp and marsh setting'], imageAlt: 'TPC Louisiana Pete Dye bayou fairway during Zurich Classic' },
    { id: 'nol-2', name: 'English Turn Golf & Country Club', slug: 'english-turn-golf-cc', city: 'New Orleans', state: 'Louisiana', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 1989, holes: 18, par: 72, yardage: 7078, description: 'A Jack Nicklaus design on a historic Mississippi River bend south of downtown New Orleans, English Turn hosted the PGA Tour from 1989 to 2005. The championship layout through live oaks and bayou landscape features Nicklaus\'s bold shaping and strategic water hazards in a uniquely Louisiana setting.', highlights: ['Former PGA Tour venue (1989-2005)', 'Jack Nicklaus design on historic Mississippi River bend', 'Live oaks and bayou landscape setting'], imageAlt: 'English Turn Golf Club Nicklaus fairway through live oaks and bayou near New Orleans' },
    { id: 'nol-3', name: 'Audubon Park Golf Course', slug: 'audubon-park-golf-course', city: 'New Orleans', state: 'Louisiana', type: 'public', rating: 4.0, greensFee: '$20–$40', architect: 'Denis Griffiths (renovation)', yearBuilt: 1898, holes: 18, par: 62, yardage: 4220, description: 'Nestled in the heart of Uptown New Orleans within iconic Audubon Park, this charming short course offers a uniquely New Orleans golf experience beneath canopies of centuries-old live oaks draped in Spanish moss. The par-62 layout is accessible for all levels and provides a quintessentially atmospheric round in one of the city\'s most beloved green spaces.', highlights: ['Historic Audubon Park setting since 1898', 'Centuries-old live oaks draped in Spanish moss', 'Charming short course in the heart of Uptown'], imageAlt: 'Audubon Park Golf Course fairway beneath live oaks and Spanish moss' },
    { id: 'nol-4', name: 'Lakewood Golf Club', slug: 'lakewood-golf-club-nola', city: 'New Orleans', state: 'Louisiana', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Seth Raynor', yearBuilt: 1925, holes: 18, par: 72, yardage: 6744, description: 'A Seth Raynor design in the Algiers Point neighborhood across the Mississippi from downtown, Lakewood Golf Club is one of the finest private clubs in Louisiana. Raynor\'s template holes including Redan and Biarritz are rendered through live oaks and Bayou Fatma, creating a unique blend of Golden Age architecture and Southern Louisiana landscape.', highlights: ['Seth Raynor template hole design from 1925', 'One of Louisiana\'s finest private clubs', 'Live oaks and bayou Golden Age routing'], imageAlt: 'Lakewood Golf Club Seth Raynor template fairway through New Orleans live oaks' },
    { id: 'nol-5', name: 'Bayou Oaks at City Park - Championship', slug: 'bayou-oaks-championship', city: 'New Orleans', state: 'Louisiana', type: 'public', rating: 4.1, greensFee: '$35–$65', architect: 'Rees Jones', yearBuilt: 2017, holes: 18, par: 72, yardage: 7056, description: 'A modern Rees Jones design at New Orleans City Park, Bayou Oaks Championship replaced flood-damaged courses with a championship-caliber public facility. The 7,056-yard layout winds through the park\'s mature live oaks and bayous, offering the city\'s best public golf experience alongside City Park\'s cultural attractions.', highlights: ['Modern Rees Jones championship public design', 'New Orleans City Park setting with live oaks', 'Best public golf experience in the city'], imageAlt: 'Bayou Oaks Championship Course Rees Jones fairway through City Park live oaks' },
    { id: 'nol-6', name: 'Chateau Country Club', slug: 'chateau-country-club', city: 'Kenner', state: 'Louisiana', type: 'semi-private', rating: 4.0, greensFee: '$30–$55', architect: 'Ron Garl', yearBuilt: 1972, holes: 18, par: 72, yardage: 6858, description: 'A Ron Garl design near the New Orleans airport in Kenner, Chateau Country Club offers semi-private access to a solid championship layout through flat Louisiana terrain with strategic water hazards and mature plantings. The accessible pricing and convenient location make it a practical option for visiting golfers.', highlights: ['Convenient location near New Orleans airport', 'Semi-private access at accessible pricing', 'Ron Garl championship layout'], imageAlt: 'Chateau Country Club fairway through mature Louisiana landscape near Kenner' },
    { id: 'nol-7', name: 'Money Hill Golf & Country Club', slug: 'money-hill-golf-cc', city: 'Abita Springs', state: 'Louisiana', type: 'private', rating: 4.2, greensFee: 'Members Only', architect: 'Ron Garl', yearBuilt: 2001, holes: 18, par: 72, yardage: 7058, description: 'A Ron Garl design on the Northshore in Abita Springs across Lake Pontchartrain from New Orleans, Money Hill is a well-regarded private club through rolling piney-woods terrain. The 7,058-yard layout features mature longleaf pine corridors, strategic water features, and gentle elevation changes unusual for the Louisiana landscape.', highlights: ['Rolling piney-woods terrain on the Northshore', 'Mature longleaf pine corridors', 'Gentle elevation changes unusual for Louisiana'], imageAlt: 'Money Hill Golf Club piney-woods fairway in Abita Springs Louisiana' },
    { id: 'nol-8', name: 'Eastover Country Club', slug: 'eastover-country-club', city: 'New Orleans', state: 'Louisiana', type: 'private', rating: 4.1, greensFee: 'Members Only', architect: 'Joe Lee', yearBuilt: 1963, holes: 18, par: 72, yardage: 6802, description: 'A Joe Lee design in New Orleans East, Eastover Country Club is a well-established private club with a mature parkland layout through live oaks and bayou landscape. The classic Lee design features water on numerous holes, well-defended greens, and the characteristic flat Louisiana terrain enhanced by strategic mounding and mature plantings.', highlights: ['Joe Lee mature parkland design', 'Live oaks and bayou landscape setting', 'Well-established New Orleans East private club'], imageAlt: 'Eastover Country Club live oak-lined fairway in New Orleans East' },
  ],
  'birmingham-alabama': [
    { id: 'bhm-1', name: 'Shoal Creek Golf Club', slug: 'shoal-creek-golf-club-al', city: 'Shoal Creek', state: 'Alabama', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Jack Nicklaus', yearBuilt: 1977, holes: 18, par: 72, yardage: 7145, description: 'Host of two PGA Championships (1984, 1990) and the 1986 U.S. Amateur, Shoal Creek is one of the most important courses in Southern golf. Jack Nicklaus\'s design through the wooded ridges of central Alabama features dramatic elevation changes, pristine conditioning, and a championship pedigree that few private clubs can match.', highlights: ['Two-time PGA Championship host (1984, 1990)', '1986 U.S. Amateur host venue', 'Jack Nicklaus design through Alabama ridges'], imageAlt: 'Shoal Creek Golf Club championship fairway through Alabama wooded ridges' },
    { id: 'bhm-2', name: 'Country Club of Birmingham - West', slug: 'cc-birmingham-west', city: 'Birmingham', state: 'Alabama', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Donald Ross', yearBuilt: 1927, holes: 18, par: 72, yardage: 6825, description: 'A Donald Ross design in the heart of Birmingham, the Country Club of Birmingham\'s West Course is one of the most celebrated private courses in Alabama. Ross\'s strategic layout through Red Mountain terrain features his signature crowned greens, classic bunkering, and a mature parkland character that captures Golden Age golf at its finest.', highlights: ['Donald Ross Golden Age design from 1927', 'Red Mountain terrain through Birmingham parkland', 'One of Alabama\'s most celebrated private clubs'], imageAlt: 'Country Club of Birmingham West Course Donald Ross fairway through Red Mountain' },
    { id: 'bhm-3', name: 'Greystone Golf & Country Club - Legacy', slug: 'greystone-legacy-course', city: 'Birmingham', state: 'Alabama', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Bob Cupp & Hubert Green', yearBuilt: 1991, holes: 18, par: 72, yardage: 7131, description: 'A Bob Cupp and Hubert Green co-design in Hoover south of Birmingham, the Legacy Course at Greystone hosted the LPGA\'s Bruno\'s Memorial Classic and multiple state championships. The challenging layout through wooded ridges and valleys features dramatic elevation changes and excellent conditioning year-round.', highlights: ['Former LPGA Bruno\'s Memorial Classic host', 'Bob Cupp and Hubert Green collaboration', 'Dramatic elevation changes through wooded ridges'], imageAlt: 'Greystone Legacy Course fairway through Birmingham wooded ridges and valleys' },
    { id: 'bhm-4', name: 'FarmLinks at Pursell Farms', slug: 'farmlinks-pursell-farms', city: 'Sylacauga', state: 'Alabama', type: 'resort', rating: 4.3, greensFee: '$80–$150', architect: 'Hurdzan/Fry', yearBuilt: 2002, holes: 18, par: 72, yardage: 7444, description: 'A Hurdzan-Fry design at Pursell Farms resort south of Birmingham, FarmLinks was originally built as an agronomic testing facility, making it one of the most uniquely maintained courses in America. The 7,444-yard layout through rolling Alabama farmland and woodland features innovative turf varieties and outstanding conditioning.', highlights: ['Built as agronomic testing facility — unique maintenance', 'Hurdzan-Fry 7,444-yard resort design', 'Rolling Alabama farmland and woodland setting'], imageAlt: 'FarmLinks at Pursell Farms resort fairway through Alabama farmland' },
    { id: 'bhm-5', name: 'Oxmoor Valley - Ridge Course', slug: 'oxmoor-valley-ridge', city: 'Birmingham', state: 'Alabama', type: 'public', rating: 4.2, greensFee: '$40–$70', architect: 'Robert Trent Jones Sr.', yearBuilt: 1992, holes: 18, par: 72, yardage: 7055, description: 'Part of the Robert Trent Jones Golf Trail, Oxmoor Valley\'s Ridge Course is a challenging RTJ Sr. design through the Appalachian foothill ridges west of Birmingham. The dramatic routing features 200-foot elevation changes, panoramic valley views, and bold RTJ Sr. bunkering that make it one of the most scenic and challenging Trail courses.', highlights: ['Robert Trent Jones Golf Trail course', '200-foot elevation changes through Appalachian ridges', 'Panoramic valley views west of Birmingham'], imageAlt: 'Oxmoor Valley Ridge Course RTJ Trail fairway through Birmingham ridges' },
    { id: 'bhm-6', name: 'Ross Bridge Golf Resort & Spa', slug: 'ross-bridge-golf-resort', city: 'Hoover', state: 'Alabama', type: 'resort', rating: 4.3, greensFee: '$60–$120', architect: 'Robert Trent Jones Sr.', yearBuilt: 2005, holes: 18, par: 72, yardage: 8191, description: 'At 8,191 yards from the tips, Ross Bridge is one of the longest courses in the world and a dramatic addition to the Robert Trent Jones Golf Trail. The layout through the Shannon Valley in Hoover features stunning lake views, bold RTJ Sr. shaping, and a resort experience at the Renaissance Ross Bridge Hotel.', highlights: ['8,191 yards — one of the longest courses in the world', 'Robert Trent Jones Golf Trail flagship', 'Renaissance resort with stunning Shannon Valley views'], imageAlt: 'Ross Bridge Golf Resort dramatic valley fairway on RTJ Trail in Hoover Alabama' },
    { id: 'bhm-7', name: 'Highlands Course at RTJ Capitol Hill', slug: 'rtj-capitol-hill-highlands', city: 'Prattville', state: 'Alabama', type: 'public', rating: 4.3, greensFee: '$45–$80', architect: 'Robert Trent Jones Sr.', yearBuilt: 1999, holes: 18, par: 72, yardage: 7630, description: 'Part of the RTJ Trail\'s Capitol Hill complex south of Birmingham in Prattville, the Highlands Course is the most dramatic of the three courses on the property. The 7,630-yard layout features bold elevation changes, sweeping views from hilltop tees, and RTJ Sr.\'s ambitious shaping that creates one of the most visually striking public courses in the Southeast.', highlights: ['RTJ Golf Trail Capitol Hill complex', 'Sweeping hilltop views and bold elevation changes', '7,630-yard dramatic public championship layout'], imageAlt: 'RTJ Capitol Hill Highlands Course hilltop fairway near Birmingham' },
    { id: 'bhm-8', name: 'Mountain Brook Club', slug: 'mountain-brook-club', city: 'Birmingham', state: 'Alabama', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Donald Ross', yearBuilt: 1929, holes: 18, par: 72, yardage: 6700, description: 'A Donald Ross design in the exclusive Mountain Brook community, this private club is one of the most respected in Alabama. Ross\'s layout through rolling terrain features his characteristic crowned greens, strategic cross-hazards, and a lush parkland setting that captures the elegance of Golden Age Southern golf.', highlights: ['Donald Ross Golden Age design from 1929', 'Exclusive Mountain Brook community setting', 'One of Alabama\'s most respected private clubs'], imageAlt: 'Mountain Brook Club Donald Ross parkland fairway in Birmingham' },
  ],
  'oklahoma-city-oklahoma': [
    { id: 'okc-1', name: 'Oak Tree National', slug: 'oak-tree-national', city: 'Edmond', state: 'Oklahoma', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Pete Dye', yearBuilt: 1976, holes: 18, par: 71, yardage: 7015, description: 'Host of the 1988 PGA Championship and 2014 U.S. Senior Open, Oak Tree National is Pete Dye\'s Oklahoma masterpiece. The challenging par-71 through mature oaks and rolling terrain features Dye\'s bold shaping, strategic water hazards, and intimidating forced carries that have tested the game\'s best players.', highlights: ['1988 PGA Championship and 2014 U.S. Senior Open host', 'Pete Dye Oklahoma masterpiece', 'Mature oak corridors with bold Dye shaping'], imageAlt: 'Oak Tree National Pete Dye championship fairway through Oklahoma oaks' },
    { id: 'okc-2', name: 'The Golf Club of Oklahoma', slug: 'golf-club-of-oklahoma', city: 'Broken Arrow', state: 'Oklahoma', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 2003, holes: 18, par: 72, yardage: 7400, description: 'A Tom Fazio design near Tulsa, The Golf Club of Oklahoma is widely considered the finest course in the state. The 7,400-yard layout through rolling Osage Hills terrain features Fazio\'s trademark bold shaping, pristine conditioning, and dramatic water features on a stunning property that rivals any private club in the Southwest.', highlights: ['Widely considered the finest course in Oklahoma', 'Tom Fazio 7,400-yard championship design', 'Stunning Osage Hills terrain and conditioning'], imageAlt: 'Golf Club of Oklahoma Tom Fazio fairway through rolling Osage Hills', history: 'The Golf Club of Oklahoma was fashioned by Tom Fazio in 1982 on a stunning property nine miles south of Broken Arrow near Tulsa. Several fairways are routed around sparkling lakes through rolling Osage Hills terrain with mature Oklahoma hardwoods.\n\nThe club quickly established itself as the finest course in the state, a reputation maintained for four decades. The 7,400-yard layout showcases Fazio\'s bold shaping and visual drama.\n\nPristine conditioning rivals any private club in the Southwest, consistently earning top state and regional rankings.', signatureHoles: [{ hole: 4, par: 4, yardage: 440, description: 'A demanding par 4 with water and Fazio bunkering protecting the green. Rolling terrain adds complexity.' }, { hole: 8, par: 3, yardage: 195, description: 'A scenic par 3 over water to a green framed by Osage Hills.' }, { hole: 13, par: 5, yardage: 555, description: 'A strategic par 5 with risk-reward decisions and water threatening the aggressive second shot.' }, { hole: 18, par: 4, yardage: 445, description: 'A strong finishing hole with dramatic Fazio bunkering framing the final approach.' }], whatToExpect: 'The finest private golf in Oklahoma through stunning Osage Hills terrain. Fazio\'s bold shaping creates dramatic visual impact while strategic design rewards thoughtful play.\n\nConditioning is exceptional year-round.', playingTips: 'Rolling terrain creates uneven lies throughout. Water comes into play on several holes so plan strategy accordingly.\n\nThe course rewards precision over power despite the 7,400-yard length.', faqs: [{ question: 'Can the public play here?', answer: 'No. It is a private club.' }, { question: 'Who designed it?', answer: 'Tom Fazio, opened in 1982 south of Broken Arrow.' }, { question: 'Is it the best in Oklahoma?', answer: 'Widely considered the finest course in the state.' }, { question: 'How long is the course?', answer: '7,400 yards from the championship tees.' }] },
    { id: 'okc-3', name: 'Karsten Creek Golf Club', slug: 'karsten-creek-golf-club', city: 'Stillwater', state: 'Oklahoma', type: 'semi-private', rating: 4.5, greensFee: '$100–$175', architect: 'Tom Fazio', yearBuilt: 1994, holes: 18, par: 72, yardage: 7095, description: 'Home of Oklahoma State University\'s legendary golf program and host of multiple NCAA Championships, Karsten Creek is a Tom Fazio design that has produced countless PGA Tour professionals. The layout around Lake Louise features dramatic lakeside holes, bold bunkering, and one of the finest collegiate golf facilities in America.', highlights: ['Home of Oklahoma State Cowboys golf', 'Multiple NCAA Championship host venue', 'Tom Fazio design around Lake Louise'], imageAlt: 'Karsten Creek Golf Club lakeside fairway home of Oklahoma State golf' },
    { id: 'okc-4', name: 'Gaillardia Country Club', slug: 'gaillardia-country-club', city: 'Oklahoma City', state: 'Oklahoma', type: 'private', rating: 4.4, greensFee: 'Members Only', architect: 'Arthur Hills', yearBuilt: 2000, holes: 18, par: 72, yardage: 7212, description: 'An Arthur Hills design in northwest Oklahoma City, Gaillardia is one of the premier private clubs in the metro area. The 7,212-yard layout through rolling terrain features Hills\'s strategic bunkering, dramatic water features, and excellent conditioning that have made it a popular choice for state and regional tournaments.', highlights: ['Arthur Hills premier OKC private club', 'Strategic 7,212-yard championship design', 'Popular state and regional tournament venue'], imageAlt: 'Gaillardia Country Club Arthur Hills championship fairway in Oklahoma City' },
    { id: 'okc-5', name: 'Jimmie Austin OU Golf Club', slug: 'jimmie-austin-ou-golf', city: 'Norman', state: 'Oklahoma', type: 'semi-private', rating: 4.2, greensFee: '$45–$80', architect: 'Bob Cupp', yearBuilt: 1951, holes: 18, par: 72, yardage: 7141, description: 'Home of the University of Oklahoma golf program, Jimmie Austin has hosted multiple NCAA Regional events. The Bob Cupp renovation transformed the original 1951 layout into a modern championship test through rolling terrain with strategic bunkering, native grass areas, and views of Lake Thunderbird in the distance.', highlights: ['Home of University of Oklahoma Sooners golf', 'Bob Cupp renovation of classic layout', 'NCAA Regional event host venue'], imageAlt: 'Jimmie Austin OU Golf Club Sooners fairway through Norman Oklahoma' },
    { id: 'okc-6', name: 'Dornick Hills Golf & Country Club', slug: 'dornick-hills-golf-cc', city: 'Ardmore', state: 'Oklahoma', type: 'semi-private', rating: 4.1, greensFee: '$35–$60', architect: 'Perry Maxwell', yearBuilt: 1920, holes: 18, par: 70, yardage: 6445, description: 'A Perry Maxwell design in Ardmore where the famed architect grew up, Dornick Hills is a historic Oklahoma gem with Maxwell\'s signature tilted greens and dramatic terrain. The compact par-70 through rolling hills and native oaks is where Maxwell first developed the bold architectural ideas he later brought to Augusta National and Colonial.', highlights: ['Perry Maxwell\'s hometown course — birthplace of his design ideas', 'Maxwell\'s signature tilted greens and bold terrain', 'Historic Oklahoma golf gem since 1920'], imageAlt: 'Dornick Hills Golf Club Perry Maxwell historic fairway through Ardmore Oklahoma' },
    { id: 'okc-7', name: 'The Trails Golf Club', slug: 'the-trails-golf-club', city: 'Norman', state: 'Oklahoma', type: 'public', rating: 4.0, greensFee: '$25–$50', architect: 'Randy Heckenkemper', yearBuilt: 1990, holes: 18, par: 72, yardage: 7032, description: 'A Randy Heckenkemper design in Norman south of Oklahoma City, The Trails is a solid public course that winds through cross-timbers terrain with native oaks, creek corridors, and rolling Oklahoma hills. The affordable 7,032-yard layout offers a legitimate championship test at one of the best price points in the metro area.', highlights: ['Affordable championship public golf in Norman', 'Cross-timbers terrain with native oaks', '7,032-yard layout at outstanding value'], imageAlt: 'The Trails Golf Club cross-timbers fairway in Norman Oklahoma' },
    { id: 'okc-8', name: 'Oklahoma City Golf & Country Club', slug: 'okc-golf-country-club', city: 'Oklahoma City', state: 'Oklahoma', type: 'private', rating: 4.3, greensFee: 'Members Only', architect: 'Perry Maxwell', yearBuilt: 1928, holes: 18, par: 72, yardage: 6915, description: 'A Perry Maxwell design in the Nichols Hills area of Oklahoma City, Oklahoma City Golf & Country Club is one of the most prestigious private clubs in the state. Maxwell\'s bold green complexes and strategic bunkering through mature parkland create a challenging and refined golf experience with his signature undulating putting surfaces.', highlights: ['Perry Maxwell design in prestigious Nichols Hills', 'One of Oklahoma\'s most prestigious private clubs', 'Maxwell\'s bold undulating green complexes'], imageAlt: 'Oklahoma City Golf and Country Club Perry Maxwell fairway in Nichols Hills' },
  ],

  'toronto-ontario': [
    { id: 'tor-1', name: 'St. George\'s Golf and Country Club', slug: 'st-georges-golf-cc', city: 'Toronto', state: 'Ontario', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'Stanley Thompson / Ron Garl', yearBuilt: 1929, holes: 18, par: 70, yardage: 6830, description: 'One of Canada\'s supreme golf courses, St. George\'s was originally designed by Stanley Thompson in 1929 on rugged Etobicoke ravine land. Ron Garl\'s sensitive renovation preserved Thompson\'s dramatic routing through deep ravines and mature hardwoods while modernizing the bunkering and greens. A par-70 that plays with championship ferocity, St. George\'s has hosted multiple Canadian Opens and remains the gold standard for Toronto-area private golf.', highlights: ['Multiple Canadian Open host course', 'Stanley Thompson original on dramatic Etobicoke ravines', 'Ron Garl renovation preserves Golden Age character'], imageAlt: 'St Georges Golf and Country Club ravine fairway through mature Toronto hardwoods' },
    { id: 'tor-2', name: 'Beacon Hall Golf Club', slug: 'beacon-hall-golf-club', city: 'Aurora', state: 'Ontario', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Bob Cupp', yearBuilt: 1990, holes: 18, par: 72, yardage: 7006, description: 'Consistently ranked among Canada\'s finest private clubs, Beacon Hall is a Bob Cupp design carved from rolling Aurora countryside north of Toronto. The course is celebrated for its dramatic bunkering, sweeping elevation changes, and meticulous conditioning. Beacon Hall regularly appears on national best-courses lists and is a fixture in Golf Digest\'s Canada rankings.', highlights: ['Consistently ranked Top 5 in Canada', 'Bob Cupp design on dramatic rolling terrain', 'Meticulous conditioning rivalling any club in the country'], imageAlt: 'Beacon Hall Golf Club dramatic bunkering and rolling fairway north of Toronto in Aurora Ontario', history: 'Beacon Hall Golf Club opened in 1988 as a private equity club in Aurora, Ontario, approximately 30 miles north of downtown Toronto. The course was a design collaboration between Bob Cupp and Tom McBroom, combining their talents to create what would become one of the most celebrated golf courses in Canada. The rolling countryside terrain provided an exceptional canvas for the designers.\n\nThe club was conceived as an intimate private facility with a deliberately limited membership of only 260 shareholders, ensuring open access to the first tee and an unhurried pace of play. Cupp and McBroom crafted two distinct groups of nine holes: the front nine features more of a links-style character on open terrain, while the back nine winds through forested, more parkland-style corridors with dramatic elevation changes.\n\nSince opening, Beacon Hall has consistently ranked among the top five courses in Canada and is regularly featured in Golf Digest\'s Canadian rankings. The club\'s commitment to meticulous conditioning and the quality of the original design have kept it at the forefront of Canadian golf for over three decades.', signatureHoles: [{ hole: 16, par: 3, yardage: 210, description: 'Widely regarded as the signature hole, this demanding par 3 plays to a green defended by dramatic bunkering and a significant elevation change. It is one of the most photographed holes in Canadian golf.' }, { hole: 9, par: 4, yardage: 420, description: 'A strong finishing hole for the front nine that exemplifies the links-style character of the outward half, with strategic bunkering and an exposed green that plays differently depending on wind conditions.' }, { hole: 13, par: 5, yardage: 540, description: 'A risk-reward par 5 on the forested back nine that offers eagle opportunities for those willing to navigate the strategic hazards, but punishes aggressive play with difficult recovery positions.' }, { hole: 17, par: 4, yardage: 376, description: 'A shorter but strategically rich par 4 that demands precise positioning off the tee to set up the best angle into a well-defended green surrounded by Cupp\'s dramatic bunkering.' }], whatToExpect: 'Beacon Hall delivers one of the finest private golf experiences in Canada. The course features two distinctly different nines: an open, links-influenced front nine that plays across rolling terrain with expansive views, and a wooded, parkland-style back nine with significant elevation changes and tighter shot corridors. Both halves showcase the designers\' creative bunkering and inventive green complexes.\n\nWith only 260 members, the club maintains an exclusive and unhurried atmosphere. Conditioning is among the best in the country, and the natural beauty of the Aurora countryside provides a serene backdrop for the round.', playingTips: 'The two contrasting nines at Beacon Hall require different strategies. On the open front nine, wind management and course knowledge are key, as the exposed terrain amplifies the effect of breezes. The back nine demands accuracy through the forest corridors, where position off the tee is more important than distance.\n\nThe greens are well-manicured and can be fast, with subtle breaks that follow the natural terrain. Pay attention to the dramatic bunkering throughout the course, as Cupp\'s bunker placement is both aesthetic and strategic, penalizing shots that miss on the wrong side.', faqs: [{ question: 'Can the public play Beacon Hall?', answer: 'No, Beacon Hall is a private equity club limited to 260 shareholder members and their guests. There is no public access.' }, { question: 'Who designed Beacon Hall?', answer: 'Beacon Hall was a design collaboration between Bob Cupp and Tom McBroom, who created two distinct nines that offer contrasting but equally compelling golf experiences.' }, { question: 'Where is Beacon Hall located?', answer: 'Beacon Hall is located in Aurora, Ontario, approximately 30 miles north of downtown Toronto in the rolling countryside of York Region.' }, { question: 'How does Beacon Hall rank in Canada?', answer: 'Beacon Hall is consistently ranked among the top five courses in Canada by Golf Digest and other major ranking organizations, and it is considered one of the finest private clubs in the country.' }] },
    { id: 'tor-3', name: 'Hamilton Golf and Country Club - South Course', slug: 'hamilton-golf-cc-south', city: 'Ancaster', state: 'Ontario', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Harry S. Colt', yearBuilt: 1916, holes: 18, par: 72, yardage: 6815, description: 'Designed by Harry Colt in 1916, the South Course at Hamilton Golf and Country Club is one of the most important Golden Age layouts in Canada. Colt\'s masterful routing through the Niagara Escarpment uses natural terrain with understated genius — dramatic elevation changes, flowing green contours, and strategic bunkering that rewards thoughtful play over brute force. Hamilton hosted the Canadian Open numerous times and remains one of Canada\'s premier championship venues.', highlights: ['Harry Colt Golden Age masterpiece from 1916', 'Multiple Canadian Open host on the Niagara Escarpment', 'One of North America\'s most important Golden Age designs'], imageAlt: 'Harry Colt Golden Age fairway on the Niagara Escarpment at Hamilton Golf and Country Club South Course' },
    { id: 'tor-4', name: 'Weston Golf and Country Club', slug: 'weston-golf-cc', city: 'Toronto', state: 'Ontario', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Willie Park Jr.', yearBuilt: 1915, holes: 18, par: 70, yardage: 6295, description: 'One of Toronto\'s oldest private clubs, Weston Golf and Country Club was designed by two-time Open Championship winner Willie Park Jr. in 1915. The compact par-70 through mature hardwoods in the Humber River valley retains its Golden Age character with subtle green contours, natural terrain movement, and the strategic puzzle that Park specialized in.', highlights: ['Designed by two-time Open Champion Willie Park Jr.', 'Historic Humber River valley setting in Toronto', 'Classic compact par-70 with Golden Age character'], imageAlt: 'Willie Park Jr. Golden Age fairway through mature hardwoods at Weston Golf and Country Club Toronto' },
    { id: 'tor-5', name: 'Lambton Golf and Country Club', slug: 'lambton-golf-cc', city: 'Toronto', state: 'Ontario', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'George Lyon / Robbie Robinson', yearBuilt: 1902, holes: 18, par: 72, yardage: 6740, description: 'Founded in 1902 and deeply connected to Canadian golf legend George Lyon — the 1904 Olympic gold medalist who helped lay out the original course — Lambton Golf and Country Club is one of Canada\'s most historic clubs. The Humber River valley setting provides dramatic ravine holes, and a thoughtful renovation by Robbie Robinson modernized the layout while honoring its remarkable heritage.', highlights: ['Founded 1902 with connections to Olympic champion George Lyon', 'Dramatic Humber River ravine setting in west Toronto', 'One of Canada\'s most historic and storied clubs'], imageAlt: 'Humber River ravine hole at historic Lambton Golf and Country Club in Toronto' },
    { id: 'tor-6', name: 'National Golf Club of Canada', slug: 'national-golf-club-canada', city: 'Woodbridge', state: 'Ontario', type: 'private', rating: 4.9, greensFee: 'Members Only', architect: 'Tom Fazio', yearBuilt: 1974, holes: 18, par: 72, yardage: 7060, description: 'Widely considered the finest golf course in Canada, the National Golf Club of Canada is a Tom Fazio design set on rolling Woodbridge farmland northwest of Toronto. The course blends dramatic shaping, strategic bunkering, and immaculate conditioning in a private setting of extraordinary refinement. The National is the benchmark for Canadian golf and regularly appears on global top-100 lists.', highlights: ['Widely ranked the finest golf course in Canada', 'Tom Fazio design on rolling Woodbridge farmland', 'Global top-100 course with extraordinary conditioning'], imageAlt: 'National Golf Club of Canada Tom Fazio fairway on rolling Woodbridge farmland northwest of Toronto' },
    { id: 'tor-7', name: 'The Carrying Place Club', slug: 'carrying-place-club', city: 'Bolton', state: 'Ontario', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Robbie Robinson', yearBuilt: 1924, holes: 18, par: 72, yardage: 6750, description: 'Set in the Humber River valley near Bolton, The Carrying Place Club is a Robbie Robinson design on exceptional natural terrain. The course winds through mature forests and open meadows with elevation changes that produce dramatic, memorable holes. A beloved private club with a loyal membership and character that is quintessentially Canadian.', highlights: ['Robbie Robinson design on Humber River valley terrain', 'Dramatic elevation changes through forests and meadows', 'Beloved classic private club northwest of Toronto'], imageAlt: 'Carrying Place Club fairway through mature Ontario forest in Humber River valley near Bolton', history: 'The Carrying Place Club traces its origins to 1924 when the original nine-hole course was established in the Humber River valley near Bolton, Ontario, northwest of Toronto. The club takes its name from the historic portage routes used by Indigenous peoples and early explorers to carry canoes between waterways in the region, reflecting the deep Canadian heritage of the property.\n\nIn 1972, the course was expanded to 18 holes with new holes seamlessly integrated by C.E. "Robbie" Robinson, one of Canada\'s most respected golf course architects who had apprenticed under the legendary Stanley Thompson. Robinson\'s design maximized the exceptional natural terrain of the Humber River valley, using the dramatic elevation changes, mature forests, and open meadows to create holes of remarkable variety and beauty.\n\nMore recently, Canadian architect Doug Carrick, who himself apprenticed under Robinson, has led improvements to the course, maintaining the design lineage while modernizing the layout for contemporary play. The Carrying Place Club remains a beloved private institution with a loyal membership that cherishes its quintessentially Canadian character.', signatureHoles: [{ hole: 10, par: 4, yardage: 410, description: 'The opening hole of Robinson\'s expanded back nine features a dramatic tee shot from an elevated position overlooking the Humber River valley, with the fairway sweeping through mature forest below.' }, { hole: 15, par: 4, yardage: 425, description: 'A challenging par 4 that plays through a corridor of mature hardwoods with significant elevation change. The approach shot demands precision to find a well-protected green.' }, { hole: 5, par: 3, yardage: 185, description: 'A picturesque par 3 that plays across a natural ravine to a green framed by towering forest. The setting is quintessentially Ontario and the hole is as beautiful as it is testing.' }, { hole: 18, par: 4, yardage: 430, description: 'A strong finishing hole that plays back toward the clubhouse with the Humber River valley providing a dramatic backdrop. A well-placed drive sets up an approach to one of Robinson\'s best green complexes.' }], whatToExpect: 'The Carrying Place Club offers a classic private club experience in a stunning natural setting. The course winds through the Humber River valley, alternating between forested corridors and open meadows with significant elevation changes throughout. The character of the course is deeply rooted in the Canadian landscape, with mature hardwoods, wildflowers, and natural water features creating a serene and beautiful atmosphere.\n\nThe club has a warm and welcoming atmosphere typical of the best Canadian private clubs, with a loyal membership that takes pride in the course and its history. Conditioning is excellent, and the natural terrain ensures no two holes feel the same.', playingTips: 'The elevation changes at Carrying Place significantly affect club selection. Take time to assess the slope on each shot, as uphill and downhill lies are common throughout the round. The course rewards accuracy over distance, particularly on the tighter back nine holes through the forest.\n\nThe greens reflect Robinson\'s understanding of natural terrain, with subtle contours that can be deceptive. Pay attention to the surrounding landscape for clues about break direction, as putts generally follow the natural drainage of the Humber River valley. Bring your course management skills, as strategic play is rewarded over aggressive shot-making.', faqs: [{ question: 'Can the public play The Carrying Place Club?', answer: 'No, The Carrying Place Club is a private club. Access is limited to members and their invited guests.' }, { question: 'What does the name "Carrying Place" refer to?', answer: 'The name references the historic portage routes used by Indigenous peoples and early explorers to carry canoes between waterways in the region, a significant feature of early Canadian transportation.' }, { question: 'Who designed The Carrying Place Club?', answer: 'The original nine holes date to 1924, and Robbie Robinson expanded the course to 18 holes in 1972. Robinson apprenticed under Stanley Thompson and was one of Canada\'s most respected post-war architects.' }, { question: 'Where is The Carrying Place Club?', answer: 'The club is located in the Humber River valley near Bolton, Ontario, approximately 30 miles northwest of downtown Toronto.' }] },
    { id: 'tor-8', name: 'Toronto Golf Club', slug: 'toronto-golf-club', city: 'Mississauga', state: 'Ontario', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Harry S. Colt', yearBuilt: 1876, holes: 18, par: 70, yardage: 6340, description: 'The Toronto Golf Club is one of the oldest golf clubs in North America, founded in 1876. The current layout was designed by Harry Colt in 1912 and weaves through mature hardwoods on the Credit River valley with the understated precision that defines Colt\'s best work. The compact par-70 rewards shot placement over power, with green complexes of subtle complexity that reveal new nuances with every visit.', highlights: ['Founded 1876 — one of North America\'s oldest golf clubs', 'Harry Colt 1912 design on the Credit River valley', 'Classic par-70 with Colt\'s signature subtle precision'], imageAlt: 'Harry Colt fairway through Credit River valley hardwoods at historic Toronto Golf Club in Mississauga' },
  ],

  'vancouver-bc': [
    { id: 'van-1', name: 'Shaughnessy Golf and Country Club', slug: 'shaughnessy-golf-cc', city: 'Vancouver', state: 'British Columbia', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'A.V. Macan', yearBuilt: 1912, holes: 18, par: 72, yardage: 6785, description: 'The most prestigious private club in British Columbia, Shaughnessy Golf and Country Club was designed by the great A.V. Macan and has been refined over more than a century. The layout winds through towering Douglas firs on the south slope of Little Mountain, with strategic bunkering and demanding green complexes. Shaughnessy has hosted the Canadian Open multiple times and remains a benchmark for Vancouver golf excellence.', highlights: ['Most prestigious private club in British Columbia', 'A.V. Macan design through towering Douglas firs', 'Multiple Canadian Open host venue'], imageAlt: 'Shaughnessy Golf and Country Club fairway through towering Douglas firs in Vancouver', history: 'Founded 1911 on Musqueam territory along the Fraser River. A.V. Macan designed the layout through Douglas firs. Hosted Canadian Open in 1948, 1966, 2005, 2011. BC\'s most prestigious private club.', signatureHoles: [{ hole: 5, par: 4, yardage: 420, description: 'Par 4 through firs with Macan bunkering.' }, { hole: 10, par: 4, yardage: 400, description: 'Dogleg through fir-lined corridors.' }, { hole: 14, par: 3, yardage: 185, description: 'Scenic par 3 framed by Douglas firs.' }, { hole: 18, par: 4, yardage: 435, description: 'Finishing hole through forest to clubhouse.' }], whatToExpect: 'Finest private golf in BC through Douglas fir forest. 6,785 yards, par 72.', playingTips: 'Tree-lined corridors demand accuracy. Macan greens have deceptive contours.', faqs: [{ question: 'Public?', answer: 'No.' }, { question: 'Canadian Open?', answer: '1948, 1966, 2005, 2011.' }, { question: 'Designer?', answer: 'A.V. Macan.' }, { question: 'Founded?', answer: '1911.' }] },
    { id: 'van-2', name: 'University Golf Club', slug: 'university-golf-club-vancouver', city: 'Vancouver', state: 'British Columbia', type: 'public', rating: 4.3, greensFee: '$70–$120', architect: 'Stan Leonard (renovation)', yearBuilt: 1929, holes: 18, par: 72, yardage: 6584, description: 'Located on the UBC Endowment Lands in Vancouver, the University Golf Club is one of the most popular and historically rich public courses in British Columbia. Canadian golf legend Stan Leonard oversaw a significant renovation. The mature layout winds through second-growth forest with a variety of terrain and an welcoming atmosphere that has made it a Vancouver institution for nearly a century.', highlights: ['Historic 1929 layout on UBC Endowment Lands', 'Stan Leonard renovation by Canadian golf legend', 'Vancouver institution with nearly 100 years of history'], imageAlt: 'University Golf Club Vancouver fairway through second-growth forest on UBC Endowment Lands' },
    { id: 'van-3', name: 'Quilchena Golf and Country Club', slug: 'quilchena-golf-cc', city: 'Richmond', state: 'British Columbia', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Norman Mackenzie', yearBuilt: 1913, holes: 18, par: 71, yardage: 6420, description: 'One of British Columbia\'s oldest private clubs, Quilchena Golf and Country Club was founded in 1913 on the flat delta terrain of Richmond. Norman Mackenzie\'s design has been refined over decades and offers a charming parkland experience with mature trees, strategic water hazards, and an intimate private club atmosphere that reflects its deep community roots.', highlights: ['Founded 1913 — one of BC\'s oldest private clubs', 'Norman Mackenzie parkland design in Richmond', 'Intimate traditional private club atmosphere'], imageAlt: 'Quilchena Golf and Country Club parkland fairway through mature trees in Richmond BC' },
    { id: 'van-4', name: 'Furry Creek Golf and Country Club', slug: 'furry-creek-golf-cc', city: 'Furry Creek', state: 'British Columbia', type: 'public', rating: 4.4, greensFee: '$80–$150', architect: 'Robert Muir Graves', yearBuilt: 1993, holes: 18, par: 72, yardage: 6499, description: 'Dramatically positioned along Howe Sound between Vancouver and Whistler, Furry Creek is one of the most visually spectacular golf courses in Canada. Robert Muir Graves routed the layout along sheer mountain slopes above the fjord, with jaw-dropping ocean and mountain views on nearly every hole. The drive along the Sea-to-Sky Highway to reach Furry Creek is itself a stunning experience.', highlights: ['Jaw-dropping Howe Sound fjord and mountain views', 'Robert Muir Graves routing on dramatic mountain slopes', 'Among the most scenic golf settings in all of Canada'], imageAlt: 'Furry Creek Golf Club mountain hole above Howe Sound fjord on Sea-to-Sky Highway BC' },
    { id: 'van-5', name: 'Northview Golf and Country Club - Ridge Course', slug: 'northview-ridge-course', city: 'Surrey', state: 'British Columbia', type: 'public', rating: 4.4, greensFee: '$60–$110', architect: 'Arnold Palmer / Ed Seay', yearBuilt: 1994, holes: 18, par: 72, yardage: 7044, description: 'The Ridge Course at Northview Golf and Country Club in Surrey is an Arnold Palmer design and a former host of the PGA Tour\'s Air Canada Championship. The championship layout stretches to 7,044 yards across rolling Fraser Valley terrain, offering a legitimate tournament test with excellent public access. Northview\'s two courses — the Ridge and the Canal — provide an outstanding golf destination south of Vancouver.', highlights: ['Arnold Palmer design — former Air Canada Championship host', '7,044-yard championship layout with public access', 'Former PGA Tour venue in the Fraser Valley'], imageAlt: 'Northview Golf Ridge Course Arnold Palmer design championship fairway in Surrey BC Fraser Valley' },
    { id: 'van-6', name: 'Nicklaus North Golf Course', slug: 'nicklaus-north-golf-course', city: 'Whistler', state: 'British Columbia', type: 'public', rating: 4.6, greensFee: '$100–$200', architect: 'Jack Nicklaus', yearBuilt: 1995, holes: 18, par: 71, yardage: 6908, description: 'Designed by Jack Nicklaus along the shores of Green Lake in Whistler, Nicklaus North is one of the most celebrated resort courses in Canada. The layout weaves through boreal forest and meadows with dramatic mountain backdrops and several holes playing directly along the lake. Consistently ranked among Canada\'s top public courses, it pairs world-class mountain scenery with Nicklaus\'s strategic design intelligence.', highlights: ['Jack Nicklaus design along Green Lake in Whistler', 'Consistently ranked among Canada\'s top public courses', 'Dramatic Coast Mountains backdrop on every hole'], imageAlt: 'Nicklaus North Golf Course fairway along Green Lake with Coast Mountains in Whistler BC' },
    { id: 'van-7', name: 'Morgan Creek Golf Course', slug: 'morgan-creek-golf-course', city: 'Surrey', state: 'British Columbia', type: 'semi-private', rating: 4.2, greensFee: '$55–$95', architect: 'Les Furber', yearBuilt: 1995, holes: 18, par: 72, yardage: 6896, description: 'A Les Furber design in South Surrey, Morgan Creek Golf Course is a well-regarded semi-private layout with excellent conditioning and a challenging routing through natural wetlands and mature trees. The 6,896-yard course plays longer than its yardage suggests, with strategic water hazards on multiple holes and green complexes that reward precise approach play.', highlights: ['Les Furber championship design in South Surrey', 'Strategic wetlands and mature tree corridors', 'Well-conditioned semi-private layout at strong value'], imageAlt: 'Morgan Creek Golf Course Les Furber fairway through wetlands and mature trees in South Surrey BC' },
  ],

  'banff-alberta': [
    { id: 'ban-1', name: 'Fairmont Banff Springs Golf Course', slug: 'fairmont-banff-springs', city: 'Banff', state: 'Alberta', type: 'resort', rating: 4.9, greensFee: '$200–$320', architect: 'Stanley Thompson', yearBuilt: 1928, holes: 27, par: 71, yardage: 6938, description: 'Widely considered one of the greatest golf courses ever built, the Fairmont Banff Springs Golf Course is Stanley Thompson\'s crowning achievement. Carved through the Canadian Rockies at 4,500 feet elevation, the course frames glacier-capped peaks, the Bow and Spray Rivers, and the iconic Banff Springs Hotel on nearly every hole. Thompson routed 27 holes through this UNESCO World Heritage Site terrain, creating a golf experience with no equal on earth. The Rundle Nine and Sulphur Nine complete a resort golf destination that golfers travel from around the world to experience.', highlights: ['Stanley Thompson\'s greatest work — consistently world Top 25', 'UNESCO World Heritage Site setting in the Canadian Rockies', 'Glacier peaks, Bow River, and Banff Springs Hotel views throughout'], imageAlt: 'Fairmont Banff Springs Golf Course Stanley Thompson fairway framing glacier peaks and the Bow River in the Canadian Rockies' },
    { id: 'ban-2', name: 'Silvertip Golf Resort', slug: 'silvertip-golf-resort', city: 'Canmore', state: 'Alberta', type: 'resort', rating: 4.5, greensFee: '$130–$220', architect: 'Les Furber', yearBuilt: 1998, holes: 18, par: 72, yardage: 7300, description: 'Perched dramatically above the Bow Valley in Canmore, Silvertip Golf Resort is a Les Furber design with some of the most breathtaking mountain scenery of any golf course in the world. The 7,300-yard layout climbs and descends through Rocky Mountain terrain, offering constant panoramic views of the Three Sisters and surrounding peaks. Every hole plays into a cinematic Canadian Rockies backdrop.', highlights: ['Dramatic Bow Valley and Three Sisters panoramas', 'Les Furber mountain routing at 7,300 yards', 'One of Canada\'s most visually spectacular resort courses'], imageAlt: 'Silvertip Golf Resort Canmore fairway with Three Sisters mountain peaks above the Bow Valley in Alberta', history: 'Silvertip Golf Resort opened in 1998 in Canmore, Alberta, perched dramatically on the slopes above the Bow Valley in the Canadian Rocky Mountains. The course was designed by Les Furber, a renowned Canadian golf course architect who had previously worked with Robert Trent Jones Sr. and whose firm, Golf Design Services, has been based in Canmore since 1980. Furber\'s intimate knowledge of mountain terrain made him the ideal architect for this ambitious project.\n\nThe course was developed as the centerpiece of the Silvertip residential community, a luxury development on the mountainside above the town of Canmore. Furber crafted a switchback routing that climbs and descends through the Rocky Mountain terrain, using over 600 feet of elevation change to create one of the most dramatic golf experiences in the world. The course has been designated as an Audubon Cooperative Sanctuary since 2008, reflecting its commitment to environmental stewardship.\n\nSilvertip has consistently been ranked among the top resort courses in Canada, with its jaw-dropping mountain scenery drawing golfers from around the world. The panoramic views of the Three Sisters, Ha Ling Peak, Mount Rundle, and the Bow Valley are visible from virtually every hole, making it one of the most visually spectacular golf courses on the planet.', signatureHoles: [{ hole: 11, par: 3, yardage: 180, description: 'A breathtaking par 3 that plays from a dramatically elevated tee to a green far below, with the entire Bow Valley and surrounding mountain peaks spread out as a backdrop. One of the most photographed holes in Canadian golf.' }, { hole: 18, par: 4, yardage: 440, description: 'A spectacular finishing hole that plays downhill back toward the clubhouse with panoramic views of the Three Sisters and the Bow Valley. The dramatic elevation drop makes this hole play shorter than its yardage.' }, { hole: 1, par: 5, yardage: 565, description: 'The opening hole begins the mountain journey, playing through a valley with towering peaks on both sides. An accessible start that introduces the dramatic terrain to come.' }, { hole: 6, par: 4, yardage: 420, description: 'A challenging par 4 at the highest point of the course, where the panoramic views are at their most spectacular. The thin mountain air and exposure to wind add to the challenge.' }], whatToExpect: 'Silvertip Golf Resort delivers true mountain golf at its most dramatic. The course climbs and descends through Rocky Mountain terrain with over 600 feet of elevation change, creating a roller-coaster-like experience with jaw-dropping views around every corner. Every hole plays against a backdrop of the Three Sisters, Ha Ling Peak, and the surrounding Canadian Rockies.\n\nThe altitude and mountain conditions create a unique playing experience. The ball flies significantly farther in the thin mountain air, and temperatures can vary dramatically from the valley floor to the highest holes on the course. The switchback routing means you will experience uphill and downhill holes throughout the round.', playingTips: 'Adjust your club selection for the altitude and elevation changes at Silvertip. The thin mountain air at approximately 4,500 feet adds roughly 10 percent to carry distances, and the dramatic elevation changes on individual holes can add or subtract even more. Downhill holes play much shorter than the card suggests.\n\nBring warm layers even in summer, as temperatures at the higher elevations of the course can be significantly cooler. The mountain terrain creates uneven lies throughout, so practice hitting from slopes before your round. Take a cart if you are not accustomed to mountain walking, as the elevation changes are significant.', faqs: [{ question: 'Is Silvertip Golf Resort open to the public?', answer: 'Yes, Silvertip is a resort course open to the public. Tee times can be booked online and are available to all golfers during the season.' }, { question: 'When is the golf season at Silvertip?', answer: 'The season typically runs from mid-May through early October, depending on weather conditions. Peak season is July and August.' }, { question: 'How does altitude affect play at Silvertip?', answer: 'At approximately 4,500 feet elevation, the ball carries about 10 percent farther than at sea level. Combined with the dramatic elevation changes on individual holes, club selection requires significant adjustment.' }, { question: 'Is walking possible at Silvertip?', answer: 'While walking is technically permitted, the extreme elevation changes make walking very challenging. Most golfers opt for a cart, and carts are included in the green fee.' }] },
    { id: 'ban-3', name: 'Stewart Creek Golf and Country Club', slug: 'stewart-creek-golf-cc', city: 'Canmore', state: 'Alberta', type: 'semi-private', rating: 4.5, greensFee: '$120–$200', architect: 'Gary Browning', yearBuilt: 2000, holes: 18, par: 72, yardage: 7010, description: 'Designed by Gary Browning on the site of a historic coal mining operation in the Three Sisters Mountain Village near Canmore, Stewart Creek Golf and Country Club is a semi-private gem with exceptional mountain character. Old mine shafts, wagon roads, and industrial artifacts are incorporated into the design, creating a unique course personality that blends natural drama with historical narrative against the towering Rocky Mountain backdrop.', highlights: ['Historic coal mine artifacts woven into course design', 'Gary Browning routing on Three Sisters Mountain Village terrain', 'One of Canada\'s most distinctive and character-rich layouts'], imageAlt: 'Stewart Creek Golf Club mountain fairway with historic mine site elements near Canmore Alberta' },
    { id: 'ban-4', name: 'Kananaskis Country Golf Course - Mount Lorette', slug: 'kananaskis-mount-lorette', city: 'Kananaskis', state: 'Alberta', type: 'public', rating: 4.6, greensFee: '$90–$140', architect: 'Robert Trent Jones Sr.', yearBuilt: 1983, holes: 18, par: 72, yardage: 7102, description: 'Commissioned by the Government of Alberta and designed by Robert Trent Jones Sr. for the 1988 G8 Summit at Kananaskis, the Mount Lorette Course is a world-class public layout set in the heart of the Rockies. Jones routed the 7,102-yard championship layout along the Kananaskis River with the Kananaskis Range providing a constant backdrop. The course hosted the Presidents Cup qualifier and offers one of the best public golf values in Canada.', highlights: ['Robert Trent Jones Sr. design built for the 1988 G8 Summit', '7,102-yard championship layout on the Kananaskis River', 'Extraordinary Rocky Mountain scenery at public course pricing'], imageAlt: 'Kananaskis Country Golf Course Mount Lorette Robert Trent Jones Sr. fairway along Kananaskis River Alberta Rockies' },
    { id: 'ban-5', name: 'Kananaskis Country Golf Course - Mount Kidd', slug: 'kananaskis-mount-kidd', city: 'Kananaskis', state: 'Alberta', type: 'public', rating: 4.5, greensFee: '$90–$140', architect: 'Robert Trent Jones Sr.', yearBuilt: 1983, holes: 18, par: 72, yardage: 7083, description: 'The companion course to Mount Lorette at Kananaskis Country, the Mount Kidd Course was also designed by Robert Trent Jones Sr. and plays through the valley with views of the namesake peak. At 7,083 yards with the mountain air reducing effective distance, Mount Kidd offers a slightly different routing that rewards long driving and precise approach play. Together, the two Kananaskis courses constitute one of the finest public golf destinations in North America.', highlights: ['Robert Trent Jones Sr. companion course to Mount Lorette', 'Named for the dramatic Mount Kidd backdrop', 'Part of North America\'s finest public mountain golf destination'], imageAlt: 'Kananaskis Country Golf Course Mount Kidd RTJ fairway with Rocky Mountain peak backdrop in Alberta' },
  ],

  'calgary-alberta': [
    { id: 'cal-1', name: 'Glencoe Golf and Country Club', slug: 'glencoe-golf-cc', city: 'Calgary', state: 'Alberta', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Stanley Thompson', yearBuilt: 1929, holes: 18, par: 72, yardage: 6730, description: 'Designed by Stanley Thompson in 1929, Glencoe Golf and Country Club is Calgary\'s most prestigious private golf club and a masterwork of the Golden Age. Thompson\'s routing through the Elbow River valley uses the natural terrain with dramatic elegance — elevation changes, ravine crossings, and creek corridors create a course of enduring strategic interest. Glencoe is consistently ranked among the top 10 courses in Canada and represents Thompson\'s characteristic blending of beauty and challenge.', highlights: ['Stanley Thompson Golden Age masterpiece from 1929', 'Dramatic Elbow River valley routing in Calgary', 'Consistently ranked Top 10 in Canada'], imageAlt: 'Glencoe Golf and Country Club Stanley Thompson fairway through Elbow River valley in Calgary Alberta' },
    { id: 'cal-2', name: 'Calgary Golf and Country Club', slug: 'calgary-golf-cc', city: 'Calgary', state: 'Alberta', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Donald Ross / renovated', yearBuilt: 1908, holes: 18, par: 72, yardage: 6680, description: 'Calgary\'s oldest private golf club, founded in 1897 with the current course dating to 1908, Calgary Golf and Country Club has a Donald Ross connection in its design heritage. The Bow River valley setting creates natural drama, and the club has hosted numerous provincial and national championships over its more than 100-year history. A beloved institution at the heart of Alberta golf.', highlights: ['Calgary\'s oldest private club — founded 1897', 'Bow River valley setting with over a century of history', 'Host of numerous provincial and national championships'], imageAlt: 'Calgary Golf and Country Club Bow River valley historic fairway in Calgary Alberta', history: 'Founded in 1897 when Calgary golfers formed The Calgary Golf Club on vacant CPR land, it is the oldest playable private course in Alberta. The current site along the Elbow River in Windsor Park dates to 1908. Willie Park Jr. designed green complexes and Stanley Thompson also contributed.\n\nThe club has hosted numerous provincial and national championships over more than 125 years.', signatureHoles: [{ hole: 4, par: 4, yardage: 400, description: 'A strategic par 4 along the Elbow River with a Willie Park Jr. green complex.' }, { hole: 9, par: 3, yardage: 175, description: 'A scenic par 3 with river valley backdrop and subtle Golden Age green contours.' }, { hole: 14, par: 4, yardage: 415, description: 'A demanding par 4 through tight routing where tee position is critical.' }, { hole: 18, par: 4, yardage: 420, description: 'A classic finishing hole back to the historic clubhouse along the river valley.' }], whatToExpect: 'Historic private golf on a tight superbly routed property along the Elbow River. The 6,680-yard course features Willie Park Jr. green complexes.\n\nClub atmosphere reflects over 125 years of Calgary golf tradition.', playingTips: 'Tight routing demands accuracy off the tee. The course is not long but river and mature trees punish wayward shots.\n\nGreens retain Golden Age character with subtle deceptive contours.', faqs: [{ question: 'Can the public play?', answer: 'No. Private club.' }, { question: 'How old is it?', answer: 'Founded 1897, oldest playable private course in Alberta.' }, { question: 'Who designed it?', answer: 'Willie Park Jr. green complexes with Stanley Thompson contributions.' }, { question: 'Where is it?', answer: 'Windsor Park neighborhood along the Elbow River in Calgary.' }] },
    { id: 'cal-3', name: 'Priddis Greens Golf and Country Club', slug: 'priddis-greens-golf-cc', city: 'Priddis', state: 'Alberta', type: 'semi-private', rating: 4.6, greensFee: '$90–$140', architect: 'Tom McBroom', yearBuilt: 1994, holes: 36, par: 72, yardage: 7050, description: 'Located in the foothills southwest of Calgary, Priddis Greens Golf and Country Club is a Tom McBroom design with extraordinary Rocky Mountain panoramas. The 36-hole facility offers two championship layouts — the East and West courses — set on rolling foothill terrain with the Rockies as an ever-present backdrop. McBroom\'s routing maximizes the natural terrain movement and view corridors, creating one of Calgary\'s most popular golf destinations.', highlights: ['Tom McBroom design with sweeping Rocky Mountain panoramas', '36-hole facility on rolling Alberta foothills', 'Calgary\'s top destination for mountain-view golf'], imageAlt: 'Priddis Greens Golf Club Tom McBroom fairway with Rocky Mountain backdrop southwest of Calgary Alberta' },
    { id: 'cal-4', name: 'Valley Ridge Golf Club', slug: 'valley-ridge-golf-club', city: 'Calgary', state: 'Alberta', type: 'public', rating: 4.3, greensFee: '$65–$110', architect: 'Bob Cupp', yearBuilt: 1992, holes: 18, par: 71, yardage: 6505, description: 'A Bob Cupp design in the northwest Calgary community of Valley Ridge, Valley Ridge Golf Club is a popular public layout with dramatic Bow River valley views and one of the most accessible quality golf experiences in the city. Cupp\'s routing through the valley terrain creates elevation changes and scenic vistas that punch well above the price point, making Valley Ridge a favorite for Calgary golfers seeking quality public golf.', highlights: ['Bob Cupp design in northwest Calgary\'s Valley Ridge community', 'Dramatic Bow River valley views and elevation changes', 'Top-quality public golf at accessible Calgary pricing'], imageAlt: 'Valley Ridge Golf Club Bob Cupp fairway with Bow River valley views in northwest Calgary Alberta' },
    { id: 'cal-5', name: 'D\'Arcy Ranch Golf Club', slug: 'darcy-ranch-golf-club', city: 'Okotoks', state: 'Alberta', type: 'public', rating: 4.3, greensFee: '$55–$95', architect: 'Les Furber', yearBuilt: 1993, holes: 18, par: 72, yardage: 7088, description: 'Located south of Calgary in the foothills town of Okotoks, D\'Arcy Ranch Golf Club is a Les Furber design on former ranchland with dramatic Sheep River views and Rocky Mountain vistas. The 7,088-yard layout plays long and challenging, with natural water hazards, links-influenced bunkering, and the Alberta prairie wind creating a demanding but rewarding golf experience. D\'Arcy Ranch is considered one of the best public course values in the Calgary area.', highlights: ['Les Furber design on historic Okotoks ranchland south of Calgary', '7,088-yard layout with Sheep River and Rocky Mountain views', 'Best public course value in the greater Calgary area'], imageAlt: 'D\'Arcy Ranch Golf Club Les Furber fairway with Rocky Mountain vista and Sheep River corridor in Okotoks Alberta' },
    { id: 'cal-6', name: 'Country Hills Golf Club - Tower Course', slug: 'country-hills-tower-course', city: 'Calgary', state: 'Alberta', type: 'semi-private', rating: 4.2, greensFee: '$70–$110', architect: 'Tom McBroom', yearBuilt: 1999, holes: 18, par: 72, yardage: 7100, description: 'The Tower Course at Country Hills Golf Club in northwest Calgary is a Tom McBroom design stretching to 7,100 yards with sweeping Rockies panoramas. The layout plays through rolling terrain with strategic bunkering, water features, and excellent conditioning across a pair of courses that make Country Hills one of Calgary\'s busiest and most highly regarded semi-private destinations.', highlights: ['Tom McBroom design at 7,100 yards in northwest Calgary', 'Sweeping Rocky Mountain panoramas throughout', 'Part of a premier semi-private 36-hole destination'], imageAlt: 'Country Hills Golf Club Tower Course Tom McBroom fairway with Rocky Mountain backdrop in northwest Calgary' },
  ],

  'victoria-bc': [
    { id: 'vic-1', name: 'Victoria Golf Club', slug: 'victoria-golf-club', city: 'Victoria', state: 'British Columbia', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Traditional layout', yearBuilt: 1893, holes: 18, par: 70, yardage: 6112, description: 'Founded in 1893, Victoria Golf Club is one of the oldest golf clubs in North America and the oldest in western Canada. The cliffside links layout on the Strait of Juan de Fuca is a remarkable piece of golf heritage — firm, fast, and wind-swept, with ocean views throughout and sea air that makes every round memorable. The course has evolved organically over more than 130 years while maintaining the natural character of its spectacular seaside setting.', highlights: ['Founded 1893 — oldest golf club in western Canada', 'Oceanside cliffs above the Strait of Juan de Fuca', 'One of North America\'s most historic and atmospheric courses'], imageAlt: 'Victoria Golf Club oceanside cliffside hole above Strait of Juan de Fuca in Victoria BC' },
    { id: 'vic-2', name: 'Cordova Bay Golf Course', slug: 'cordova-bay-golf-course', city: 'Victoria', state: 'British Columbia', type: 'public', rating: 4.3, greensFee: '$55–$90', architect: 'Bill Robinson', yearBuilt: 1991, holes: 18, par: 72, yardage: 6905, description: 'Designed by Bill Robinson on rolling terrain overlooking Cordova Bay on the Saanich Peninsula, Cordova Bay Golf Course is consistently rated among the best public courses in British Columbia. The layout winds through mature Garry oaks and sea meadows with ocean glimpses throughout. Robinson\'s design is both challenging and scenic, rewarding thoughtful play with some of the most pleasant golf settings in the Victoria area.', highlights: ['Consistently rated Top 5 public course in British Columbia', 'Bill Robinson design overlooking Cordova Bay', 'Scenic Garry oak and sea meadow setting'], imageAlt: 'Cordova Bay Golf Course Bill Robinson fairway through Garry oaks overlooking the bay in Victoria BC' },
    { id: 'vic-3', name: 'Bear Mountain Golf and Country Club - Mountain Course', slug: 'bear-mountain-mountain-course', city: 'Victoria', state: 'British Columbia', type: 'resort', rating: 4.5, greensFee: '$100–$180', architect: 'Jack Nicklaus / Steve Nicklaus', yearBuilt: 2003, holes: 18, par: 72, yardage: 6939, description: 'The Mountain Course at Bear Mountain Golf and Country Club is a Jack Nicklaus and Steve Nicklaus design set in the highlands west of Victoria. The dramatic elevation changes, rock outcroppings, and panoramic views of the Olympic Mountains and the Strait of Juan de Fuca create a visually stunning resort experience. Bear Mountain hosted the World Cup of Golf in 2003 and remains the premier resort golf destination in the Victoria area.', highlights: ['Jack Nicklaus & Steve Nicklaus design above Victoria', 'World Cup of Golf 2003 host venue', 'Olympic Mountains and Strait of Juan de Fuca panoramas'], imageAlt: 'Bear Mountain Golf Club Mountain Course Jack Nicklaus design with Olympic Mountain views near Victoria BC' },
    { id: 'vic-4', name: 'Olympic View Golf Club', slug: 'olympic-view-golf-club', city: 'Victoria', state: 'British Columbia', type: 'public', rating: 4.2, greensFee: '$60–$100', architect: 'Bill Robinson', yearBuilt: 1988, holes: 18, par: 72, yardage: 6529, description: 'Olympic View Golf Club is a Bill Robinson design in the western highlands of Victoria, named for its views of the Olympic Mountains across the Strait of Juan de Fuca. The layout plays through natural terrain with mature fir forests, rock outcroppings, and twelve water features that require careful course management. A popular and well-maintained public option for Victoria golfers.', highlights: ['Named for Olympic Mountains views across the Strait', 'Bill Robinson design through natural fir forest terrain', 'Twelve water features requiring strategic course management'], imageAlt: 'Olympic View Golf Club Bill Robinson fairway with Olympic Mountain views in Victoria BC' },
    { id: 'vic-5', name: 'Gorge Vale Golf Club', slug: 'gorge-vale-golf-club', city: 'Victoria', state: 'British Columbia', type: 'semi-private', rating: 4.1, greensFee: '$45–$80', architect: 'Traditional layout', yearBuilt: 1922, holes: 18, par: 71, yardage: 6124, description: 'Founded in 1922, Gorge Vale Golf Club is a traditional parkland layout set along the Gorge waterway in Victoria. The mature course through Garry oak meadows and Douglas fir forest has the comfortable character of a well-loved classic — rolling terrain, natural hazards, and the kind of intimate golf atmosphere that keeps members returning for generations. An excellent semi-private option for Victoria golfers seeking quality golf at accessible pricing.', highlights: ['Historic 1922 traditional layout along the Gorge waterway', 'Charming Garry oak and Douglas fir parkland setting', 'Beloved Victoria semi-private institution for over 100 years'], imageAlt: 'Gorge Vale Golf Club traditional fairway through Garry oak meadow along the Gorge in Victoria BC' },
  ],

  'montreal-quebec': [
    { id: 'mtl-1', name: 'Royal Montreal Golf Club - Blue Course', slug: 'royal-montreal-blue-course', city: 'Ile Bizard', state: 'Quebec', type: 'private', rating: 4.8, greensFee: 'Members Only', architect: 'Dick Wilson (renovation)', yearBuilt: 1873, holes: 18, par: 70, yardage: 6722, description: 'The oldest golf club in North America, the Royal Montreal Golf Club was founded in 1873 and received its Royal designation from King Edward VII in 1884. The Blue Course — redesigned by Dick Wilson and Joe Lee — is the club\'s championship layout on Ile Bizard and has hosted the Canadian Open multiple times. The par-70 design rewards precision over power, with Wilson\'s strategic bunkering and demanding green complexes set along Lake of Two Mountains.', highlights: ['Oldest golf club in North America — established 1873', 'Royal designation granted by King Edward VII in 1884', 'Multiple Canadian Open host with Dick Wilson championship design'], imageAlt: 'Royal Montreal Golf Club Blue Course Dick Wilson fairway on Ile Bizard with Lake of Two Mountains' },
    { id: 'mtl-2', name: 'Elm Ridge Golf and Country Club', slug: 'elm-ridge-golf-cc', city: 'Ile Bizard', state: 'Quebec', type: 'private', rating: 4.7, greensFee: 'Members Only', architect: 'Stanley Thompson', yearBuilt: 1924, holes: 18, par: 72, yardage: 6870, description: 'A Stanley Thompson masterpiece on Ile Bizard, Elm Ridge Golf and Country Club is one of Quebec\'s finest private clubs. Thompson\'s 1924 design uses the rolling island terrain with his characteristic boldness — dramatic bunkering, elevated green complexes, and routing that creates memorable sequences of holes. Elm Ridge is one of the hidden gems of Canadian golf architecture, less known than Thompson\'s mountain courses but equally impressive in its own parkland idiom.', highlights: ['Stanley Thompson 1924 design — one of his finest parkland works', 'Rolling Ile Bizard island terrain with dramatic bunkering', 'One of Quebec\'s top-ranked private clubs'], imageAlt: 'Elm Ridge Golf and Country Club Stanley Thompson parkland fairway on Ile Bizard Quebec' },
    { id: 'mtl-3', name: 'Whitlock Golf and Country Club', slug: 'whitlock-golf-cc', city: 'Hudson', state: 'Quebec', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Stanley Thompson / Herbert Strong', yearBuilt: 1921, holes: 18, par: 72, yardage: 6650, description: 'Set in the charming village of Hudson on the shores of Lake of Two Mountains, Whitlock Golf and Country Club is a classic Quebec parkland layout with a distinguished history. The original design elements by Herbert Strong were complemented by Stanley Thompson\'s touch in subsequent refinements. The rolling terrain through mature hardwoods and lakeside corridors makes Whitlock one of the most picturesque private clubs in the Montreal area.', highlights: ['Historic 1921 layout in charming Hudson village', 'Lakeside corridors along Lake of Two Mountains', 'One of the Montreal area\'s most picturesque private clubs'], imageAlt: 'Whitlock Golf and Country Club historic parkland fairway near Lake of Two Mountains in Hudson Quebec' },
    { id: 'mtl-4', name: 'Royal Montreal Golf Club - Red Course', slug: 'royal-montreal-red-course', city: 'Ile Bizard', state: 'Quebec', type: 'private', rating: 4.5, greensFee: 'Members Only', architect: 'Howard Watson', yearBuilt: 1959, holes: 18, par: 71, yardage: 6494, description: 'The Red Course at Royal Montreal Golf Club offers a slightly shorter but no less enjoyable companion to the championship Blue Course. Howard Watson\'s design plays across the rolling Ile Bizard terrain with the same stunning Lake of Two Mountains views. The par-71 layout is a favorite for member play and provides a contrast in character to the longer Blue Course — more intimate, more varied in texture, and equally demanding on approach shots.', highlights: ['Companion course to the celebrated Blue Course at Royal Montreal', 'Howard Watson design with Lake of Two Mountains views', 'Member-favorite par-71 on rolling Ile Bizard terrain'], imageAlt: 'Royal Montreal Golf Club Red Course fairway with Lake of Two Mountains views on Ile Bizard Quebec' },
  ],

  'muskoka-ontario': [
    { id: 'musk-1', name: 'Taboo Muskoka Golf Resort', slug: 'taboo-muskoka-golf-resort', city: 'Gravenhurst', state: 'Ontario', type: 'resort', rating: 4.5, greensFee: '$120–$200', architect: 'Thomas McBroom', yearBuilt: 2000, holes: 18, par: 72, yardage: 7022, description: 'Designed by Thomas McBroom on the shores of Lake Muskoka in Gravenhurst, Taboo Muskoka Golf Resort is one of Ontario\'s premier resort golf experiences. The 7,022-yard layout weaves through the iconic Muskoka landscape of granite outcroppings, boreal forest, and lakeside corridors. McBroom\'s routing is consistently praised for its integration of natural features and its genuine championship challenge in one of Canada\'s most beloved vacation regions.', highlights: ['Thomas McBroom design on Lake Muskoka shores', 'Iconic Muskoka granite and boreal forest setting', 'Premier resort golf destination in cottage country Ontario'], imageAlt: 'Taboo Muskoka Golf Resort Thomas McBroom fairway through granite outcroppings along Lake Muskoka Ontario' },
    { id: 'musk-2', name: 'Deerhurst Highlands', slug: 'deerhurst-highlands-golf', city: 'Huntsville', state: 'Ontario', type: 'resort', rating: 4.4, greensFee: '$100–$180', architect: 'Robert Trent Jones Jr.', yearBuilt: 1990, holes: 18, par: 72, yardage: 7011, description: 'The Highlands Course at Deerhurst Resort in Huntsville is a Robert Trent Jones Jr. design on dramatic Muskoka terrain. The layout climbs and descends through rocky ridges and forest with spectacular views of Peninsula Lake and the surrounding cottage country. Deerhurst hosted the G8 Summit in 2010, and the golf course draws visitors from across North America seeking the combination of championship golf and Muskoka natural beauty.', highlights: ['Robert Trent Jones Jr. design — G8 Summit 2010 venue', 'Dramatic Muskoka ridges with Peninsula Lake views', 'Premier cottage country resort golf destination'], imageAlt: 'Deerhurst Highlands Golf Course Robert Trent Jones Jr. fairway with Peninsula Lake views in Huntsville Ontario' },
    { id: 'musk-3', name: 'The Rock Golf Course', slug: 'the-rock-golf-course', city: 'Minett', state: 'Ontario', type: 'resort', rating: 4.5, greensFee: '$110–$190', architect: 'Nick Faldo', yearBuilt: 2003, holes: 18, par: 71, yardage: 6869, description: 'Nick Faldo\'s only Canadian design, The Rock Golf Course at JW Marriott The Rosseau Muskoka is a dramatic layout through granite Shield terrain on Lake Rosseau. Faldo routed the course to maximize the Muskoka rock features — exposed granite, natural lakes, and boreal forest create a series of visually stunning holes. The par-71 requires precise shot-making through tight tree corridors and over rocky outcroppings.', highlights: ['Nick Faldo\'s only golf course design in Canada', 'Dramatic exposed granite and Lake Rosseau setting', 'JW Marriott Rosseau Muskoka resort destination'], imageAlt: 'The Rock Golf Course Nick Faldo design through granite Shield terrain on Lake Rosseau in Muskoka Ontario' },
    { id: 'musk-4', name: 'Bigwin Island Golf Club', slug: 'bigwin-island-golf-club', city: 'Lake of Bays', state: 'Ontario', type: 'private', rating: 4.6, greensFee: 'Members Only', architect: 'Robbie Robinson (restored)', yearBuilt: 1922, holes: 18, par: 71, yardage: 6602, description: 'Built on an island in Lake of Bays in 1922, Bigwin Island Golf Club has one of the most romantic stories in Canadian golf. The course was closed for decades before being painstakingly restored in the early 2000s by a group of passionate members. Robbie Robinson\'s original design captures classic Muskoka terrain — granite, forest, and lakeside corridors — with a restoration that has earned national acclaim and placed Bigwin among Canada\'s most distinctive and beloved clubs.', highlights: ['Historic 1922 island course restored after decades of closure', 'Passionate restoration celebrated throughout Canadian golf', 'Accessible only by boat — ultimate Muskoka golf experience'], imageAlt: 'Bigwin Island Golf Club restored 1922 fairway on Lake of Bays island in Muskoka Ontario' },
    { id: 'musk-5', name: 'Limberlost Links', slug: 'limberlost-links', city: 'Huntsville', state: 'Ontario', type: 'public', rating: 4.3, greensFee: '$75–$130', architect: 'Thomas McBroom', yearBuilt: 2010, holes: 18, par: 72, yardage: 6840, description: 'Thomas McBroom\'s Limberlost Links in Huntsville is a course designed to capture the natural spirit of Muskoka rather than impose upon it. The layout plays through a landscape of granite, forest, and wetlands with McBroom\'s characteristic respect for natural terrain. Limberlost offers an authentic Muskoka experience at public pricing and has quickly earned a loyal following in cottage country Ontario.', highlights: ['Thomas McBroom design celebrating authentic Muskoka landscape', 'Granite, forest, and wetland terrain routing', 'Accessible public course in the heart of cottage country'], imageAlt: 'Limberlost Links Thomas McBroom fairway through granite and boreal forest near Huntsville Muskoka Ontario' },
  ],

  'prince-edward-island': [
    { id: 'pei-1', name: 'Links at Crowbush Cove', slug: 'links-at-crowbush-cove', city: 'Morell', state: 'Prince Edward Island', type: 'public', rating: 4.8, greensFee: '$75–$130', architect: 'Thomas McBroom', yearBuilt: 1994, holes: 18, par: 72, yardage: 6903, description: 'Consistently ranked as Canada\'s finest public golf course, the Links at Crowbush Cove is Thomas McBroom\'s masterpiece on PEI\'s Gulf of St. Lawrence shoreline. The layout plays along dramatic sand dunes, through windswept marram grass, and along the redcliff coastline in a true links tradition. McBroom captured the natural terrain with minimal manipulation, creating a course that feels inevitable — as if golf has been played here for centuries. Crow Bush Cove is the destination that defines golf tourism in Atlantic Canada.', highlights: ['Consistently ranked Canada\'s finest public golf course', 'Thomas McBroom links masterpiece on Gulf of St. Lawrence', 'Dramatic sand dunes, marram grass, and redcliff coastline'], imageAlt: 'Links at Crowbush Cove Thomas McBroom links fairway along Gulf of St. Lawrence dunes in PEI' },
    { id: 'pei-2', name: 'Dundarave Golf Course', slug: 'dundarave-golf-course', city: 'Cardigan', state: 'Prince Edward Island', type: 'public', rating: 4.5, greensFee: '$65–$110', architect: 'Thomas McBroom', yearBuilt: 1999, holes: 18, par: 72, yardage: 7089, description: 'Thomas McBroom\'s second PEI design at Brudenell River Provincial Park, Dundarave is a more inland layout that plays through rolling PEI farmland and hardwood forests along the Cardigan River. The 7,089-yard course is a genuine championship test — longer and more demanding than Crowbush Cove, with McBroom\'s strategic bunkering and green complexes requiring precision from every distance.', highlights: ['Thomas McBroom design at Brudenell River Provincial Park', '7,089-yard championship layout through PEI farmland', 'Companion course to the acclaimed Brudenell River layout'], imageAlt: 'Dundarave Golf Course Thomas McBroom fairway through rolling PEI farmland at Brudenell River Park' },
    { id: 'pei-3', name: 'Brudenell River Golf Course - River Course', slug: 'brudenell-river-course', city: 'Cardigan', state: 'Prince Edward Island', type: 'public', rating: 4.4, greensFee: '$60–$100', architect: 'Rob Heaslip', yearBuilt: 1969, holes: 18, par: 72, yardage: 6593, description: 'The original championship layout at Brudenell River Provincial Park, the River Course at Brudenell is a classic PEI design by Rob Heaslip that plays along the Brudenell River through mature hardwoods and open meadows. The tree-lined corridors, natural terrain, and riverside holes create an intimate and memorable golf experience. As part of the Rodd Golf PEI package, Brudenell River is accessible to visitors exploring the province\'s extraordinary golf trail.', highlights: ['Classic 1969 Rob Heaslip design along the Brudenell River', 'Mature hardwood corridors and riverside holes', 'Part of the celebrated PEI Golf Trail destination'], imageAlt: 'Brudenell River Golf Course Rob Heaslip fairway along river through hardwoods at Brudenell River Provincial Park PEI' },
    { id: 'pei-4', name: 'Mill River Provincial Golf Course', slug: 'mill-river-golf-course', city: 'Woodstock', state: 'Prince Edward Island', type: 'public', rating: 4.1, greensFee: '$45–$80', architect: 'Traditional layout', yearBuilt: 1971, holes: 18, par: 72, yardage: 6728, description: 'Set in western PEI\'s Mill River Provincial Park, Mill River Golf Course is a traditional parkland layout through mature hardwoods along the Mill River. A longtime favorite of PEI golfers and visitors alike, the course offers excellent conditioning, pleasant terrain variety, and the relaxed atmosphere of a provincial park golf experience. Mill River is an affordable and enjoyable component of the PEI Golf Trail.', highlights: ['Traditional 1971 parkland layout in Mill River Provincial Park', 'Mature hardwoods along the Mill River in western PEI', 'Affordable and well-maintained part of the PEI Golf Trail'], imageAlt: 'Mill River Provincial Golf Course parkland fairway through hardwoods along Mill River in western PEI' },
  ],

  'cape-breton-nova-scotia': [
    { id: 'cb-1', name: 'Cabot Cliffs', slug: 'cabot-cliffs', city: 'Inverness', state: 'Nova Scotia', type: 'resort', rating: 5.0, greensFee: '$300–$500', architect: 'Bill Coore & Ben Crenshaw', yearBuilt: 2015, holes: 18, par: 72, yardage: 6829, description: 'Widely regarded as one of the greatest golf courses ever built, Cabot Cliffs by Bill Coore and Ben Crenshaw sits on the dramatic cliffs of Cape Breton\'s Ceilidh Trail overlooking the Gulf of St. Lawrence. Consistently ranked in the top 5 courses in the world, the layout uses 280 feet of elevation change, genuine clifftop drama, and some of the most spectacular holes ever conceived to create a golf experience without peer in North America. Cabot Cliffs is a bucket-list destination that belongs in the same conversation as Pebble Beach, Cypress Point, and Royal County Down.', highlights: ['Consistently ranked Top 5 in the world', 'Bill Coore & Ben Crenshaw design on dramatic Cape Breton cliffs', '280-foot elevation change above the Gulf of St. Lawrence'], imageAlt: 'Cabot Cliffs Bill Coore Ben Crenshaw clifftop hole above Gulf of St. Lawrence on Cape Breton Nova Scotia' },
    { id: 'cb-2', name: 'Cabot Links', slug: 'cabot-links', city: 'Inverness', state: 'Nova Scotia', type: 'resort', rating: 4.9, greensFee: '$250–$400', architect: 'Rod Whitman', yearBuilt: 2012, holes: 18, par: 70, yardage: 6427, description: 'The first true oceanside links course in Canada, Cabot Links was designed by Rod Whitman on the former Inverness coal mine site with the Atlantic Ocean directly in play on several holes. Ranked consistently in the world top 10, the par-70 layout hugs the Gulf of St. Lawrence waterfront through the village of Inverness, with broad fairways, firm turf, and the relentless Cape Breton wind creating a completely authentic links experience. Together with Cabot Cliffs, it forms the most celebrated golf destination in the Americas.', highlights: ['First true oceanside links course in Canada — Rod Whitman design', 'Consistently world Top 10 — Gulf of St. Lawrence in play', 'Part of the world\'s most celebrated new golf destination'], imageAlt: 'Cabot Links Rod Whitman oceanside links fairway along Gulf of St. Lawrence in Inverness Cape Breton Nova Scotia', history: 'Cabot Links was born from the vision of Toronto entrepreneur Ben Cowan-Dewar, who discovered the dramatic coastline of Inverness, Nova Scotia, and saw the potential for a world-class links course on the site of a former coal mining town. Partnering with Mike Keiser, the visionary behind Bandon Dunes, Cowan-Dewar enlisted Canadian architect Rod Whitman to design what would become the first true oceanside links course in Canada. Construction began in 2008 and continued through the global financial crisis, with the course opening for play in 2012.\n\nThe site had been used for coal mining since the 19th century, and the town of Inverness had seen decades of economic decline after the mines closed. Cabot Links transformed the community, bringing international attention and tourism dollars to this remote corner of Cape Breton. Every hole on the course boasts water views, either of the Gulf of St. Lawrence or MacIsaac\'s Pond, the tidal inlet that runs through the property.\n\nSince opening, Cabot Links has been ranked among the top courses in the world, regularly appearing in Golf Digest and GOLF Magazine global rankings. Together with its sister course Cabot Cliffs, it has established Cape Breton as one of the premier golf destinations on the planet.', signatureHoles: [{ hole: 6, par: 4, yardage: 434, description: 'A sweeping dogleg par 4 that plays directly along the Gulf of St. Lawrence shoreline, with the beach running the entire length of the left side. One of the most visually stunning holes in Canadian golf.' }, { hole: 14, par: 3, yardage: 102, description: 'A deceptively short par 3 inspired by the famous 7th at Pebble Beach, playing downhill toward the ocean. Club selection is everything as the Cape Breton wind can turn this tiny hole into a monster.' }, { hole: 16, par: 4, yardage: 388, description: 'A dramatic par 4 along the coastline where the approach must carry over rugged terrain to a well-defended green with ocean views in every direction.' }, { hole: 2, par: 3, yardage: 226, description: 'A long and exposed par 3 playing directly toward the Gulf of St. Lawrence. The prevailing wind typically adds significant challenge to this already demanding tee shot.' }], whatToExpect: 'Cabot Links delivers an authentic links experience unlike anything else in North America. The course plays firm and fast, with wide fairways that encourage creative shotmaking and ground game approaches. Expect constant wind off the Gulf of St. Lawrence that will test your ability to control trajectory and distance. The greens are large and subtly contoured, rewarding those who study the slopes carefully.\n\nThe resort setting is world-class, with on-site lodging, dining, and the ability to walk from your room to the first tee. The walking-only policy enhances the links experience, and caddies are available and recommended for first-time visitors.', playingTips: 'Wind management is the key to scoring at Cabot Links. Keep the ball below the wind whenever possible and embrace the bump-and-run approach that links golf demands. The fairways are generous, so prioritize keeping the ball in play over maximizing distance off the tee.\n\nStudy the green contours before putting, as many greens slope toward the ocean in subtle ways. A caddie is invaluable for reading both the wind and the greens. Bring layers, as conditions can change rapidly on the Cape Breton coast, and be prepared for temperatures that can drop significantly even in summer.', faqs: [{ question: 'Can the public play Cabot Links?', answer: 'Yes, Cabot Links is a resort course open to the public. Guests staying at the resort receive priority booking, but outside visitors can also reserve tee times.' }, { question: 'Is walking required at Cabot Links?', answer: 'Yes, Cabot Links is a walking-only course. Pull carts are available and caddie services can be arranged in advance.' }, { question: 'When is the best time to play Cabot Links?', answer: 'The golf season runs from late May through October. July and August offer the warmest weather, while September and October provide stunning fall foliage and fewer crowds.' }, { question: 'How does Cabot Links compare to Cabot Cliffs?', answer: 'Cabot Links is a more traditional links experience, playing closer to sea level along the coastline. Cabot Cliffs is more dramatic with clifftop holes and significant elevation changes. Most visitors play both courses during their stay.' }] },
    { id: 'cb-3', name: 'Highland Links Cape Breton', slug: 'highland-links-cape-breton', city: 'Ingonish Beach', state: 'Nova Scotia', type: 'public', rating: 4.7, greensFee: '$60–$100', architect: 'Stanley Thompson', yearBuilt: 1939, holes: 18, par: 72, yardage: 6592, description: 'Stanley Thompson\'s mountain links masterpiece in Cape Breton Highlands National Park is one of the most extraordinary golf experiences in North America. Commissioned by the Canadian government for the National Parks system, Highland Links plays along the Atlantic Ocean and through forested highlands with the Clyburn River in an 18-hole journey of dramatic variety. Thompson declared this his favorite design, and many golf historians agree it belongs alongside Banff Springs as his finest work. As a Parks Canada facility, it remains accessible at extraordinary public pricing.', highlights: ['Stanley Thompson\'s self-declared favorite design', 'National Parks setting — Atlantic Ocean and Highland forest', 'Extraordinary public access at Parks Canada pricing'], imageAlt: 'Highland Links Cape Breton Stanley Thompson oceanside National Park fairway through forested highlands in Ingonish NS', history: 'Highland Links was commissioned by the Canadian government as part of the development of Cape Breton Highlands National Park in the late 1930s. The legendary Stanley Thompson, already renowned for his work at Banff Springs and Jasper Park Lodge, was hired to design a course that would showcase the extraordinary natural beauty of the Cape Breton Highlands. Construction began in 1937, initially as a nine-hole course, with Thompson convincing his employers that a full eighteen holes was essential to do justice to the landscape.\n\nThe course opened for play in 1939 and Thompson himself declared it his favorite design, a remarkable statement given his illustrious portfolio. The layout traverses an astonishing variety of terrain, from oceanside holes along the Atlantic to forested highland passages with the Clyburn River weaving through the property. Each hole is named after a Scottish word or phrase, reflecting the strong Scottish heritage of Cape Breton.\n\nAs a Parks Canada facility, Highland Links has remained remarkably accessible and affordable for nearly a century. The course has undergone sensitive restoration work to preserve Thompson\'s original design intent, and it is consistently ranked among the top public courses in the world.', signatureHoles: [{ hole: 6, par: 5, yardage: 537, description: 'Named "Mucklemouth Meg," this dramatic par 5 plays along the Clyburn River through a narrow valley framed by highland mountains. Stanley Thompson considered the stretch from holes 4 through 8 among his finest work.' }, { hole: 15, par: 5, yardage: 540, description: 'Called "Tattie Bogle" (Scarecrow), this par 5 features a dramatic blind tee shot over a hill followed by a sweeping downhill approach through forested terrain to a green nestled in a natural amphitheater.' }, { hole: 2, par: 4, yardage: 447, description: 'Named "Tam O\'Shanter," this challenging par 4 features one of the most photographed tee shots at Highland Links, playing from an elevated tee across rugged terrain to a fairway framed by the Atlantic Ocean.' }, { hole: 9, par: 4, yardage: 405, description: 'Called "Corbie\'s Nest" (Crow\'s Nest), this turning-point hole plays from the highland terrain back toward the ocean, offering panoramic views of the Atlantic and surrounding mountains.' }], whatToExpect: 'Highland Links is unlike any other golf experience in North America. The course takes you on an extraordinary journey through wildly varied terrain, from oceanside links holes to forested mountain passages along the Clyburn River. Expect to encounter wildlife, breathtaking natural beauty, and hole designs that feel perfectly integrated into the landscape.\n\nThe pace of play tends to be relaxed, and walking is encouraged to fully appreciate the setting within Cape Breton Highlands National Park. The course can play significantly longer than its yardage suggests due to elevation changes and the wind that sweeps in from the Atlantic.', playingTips: 'Course management is essential at Highland Links. The terrain is so varied that you will face every type of shot over the course of eighteen holes. Pay close attention to the wind direction, which can shift dramatically as you move between the ocean, river valley, and highland holes.\n\nThe greens are large and undulating, with subtle breaks that can be difficult to read. Trust your caddie if you hire one, as local knowledge is invaluable. Bring rain gear regardless of the forecast, as weather in Cape Breton can change quickly. The back nine is particularly demanding, so conserve energy and stay patient.', faqs: [{ question: 'Is Highland Links open to the public?', answer: 'Yes, Highland Links is a Parks Canada facility and is fully open to the public at very affordable green fees, making it one of the greatest golf values in the world.' }, { question: 'Do I need a national park pass to play?', answer: 'Yes, in addition to green fees you will need a Cape Breton Highlands National Park entry pass, which can be purchased at the park gates or online through Parks Canada.' }, { question: 'What is the best time to visit Highland Links?', answer: 'The season runs from late May through October. Late June through September offers the best weather, while fall brings spectacular foliage across the highlands.' }, { question: 'Why are the holes named in Scottish?', answer: 'Each hole is named after a Scottish word or phrase, reflecting the deep Scottish heritage of Cape Breton. Names like "Mucklemouth Meg" and "Tattie Bogle" add to the unique character of the course.' }] },
  ],
};

export function getCoursesByCity(citySlug: string): GolfCourse[] {
  return allCourses[citySlug] || [];
}

export function getPublicCourses(citySlug: string): GolfCourse[] {
  return getCoursesByCity(citySlug).filter(c => c.type === 'public' || c.type === 'semi-private');
}

export function getPrivateCourses(citySlug: string): GolfCourse[] {
  return getCoursesByCity(citySlug).filter(c => c.type === 'private');
}

export function getResortCourses(citySlug: string): GolfCourse[] {
  return getCoursesByCity(citySlug).filter(c => c.type === 'resort');
}
